def _run_remote_python_json(
    core_cfg: Dict[str, Any],
    script: str,
    *,
    logger: logging.Logger,
    label: str,
    meta: Optional[Dict[str, Any]] = None,
    command_desc: Optional[str] = None,
    timeout: float = 120.0,
) -> Dict[str, Any]:
    cfg = _normalize_core_config(core_cfg, include_password=True)
    if meta is not None and command_desc:
        meta['grpc_command'] = command_desc
        try:
            g.last_core_grpc_command = command_desc  # type: ignore[attr-defined]
        except Exception:
            pass
    try:
        client = _open_ssh_client(cfg)
    except Exception as exc:
        logger.warning('[core.remote] SSH connection failed for %s: %s', label, exc)
        raise
    try:
        interpreter_candidates = _candidate_remote_python_interpreters(cfg)
        if not interpreter_candidates:
            interpreter_candidates = ['core-python', 'python3', 'python']
        venv_bin = str(cfg.get('venv_bin') or '').strip()
        activate_path = None
        if venv_bin:
            vb = venv_bin.rstrip('/\\')
            vb_base = posixpath.basename(vb)
            bin_dir = posixpath.dirname(vb) if vb_base.startswith('python') else vb
            if bin_dir:
                activate_path = posixpath.join(bin_dir, 'activate')
        last_error: Optional[str] = None
        last_stdout_text: str = ''
        last_stderr_text: str = ''
        last_interpreter: str = ''
        for interpreter in interpreter_candidates:
            command = _compose_remote_python_command(interpreter, script, activate_path)
            logger.info('[core.remote] (%s) executing via %s', label, interpreter)
            exit_code, stdout, stderr = _exec_ssh_command(client, command, timeout=timeout)
            stdout_text = (stdout or '').strip()
            stderr_text = (stderr or '').strip()
            last_stdout_text = stdout_text
            last_stderr_text = stderr_text
            last_interpreter = interpreter
            if stderr_text:
                logger.debug('[core.remote] (%s) stderr (%s): %s', label, interpreter, stderr_text)
            if exit_code != 0:
                last_error = f"interpreter={interpreter} exit={exit_code} stdout={_summarize_for_log(stdout_text)} stderr={_summarize_for_log(stderr_text)}"
                continue
            if not stdout_text:
                last_error = f"interpreter={interpreter} empty stdout"
                continue
            try:
                return json.loads(stdout_text)
            except json.JSONDecodeError as exc:
                logger.warning('[core.remote] (%s) invalid JSON via %s: %s', label, interpreter, exc)
                logger.debug('[core.remote] (%s) raw stdout: %s', label, stdout_text)
                last_error = f'json decode error: {exc}'
                continue
        detail = f' ({last_error})' if last_error else ''
        # Include a small amount of last output to aid troubleshooting (passwords are not logged).
        out_detail = ''
        if last_stdout_text or last_stderr_text:
            out_detail = (
                f" last_interpreter={last_interpreter}"
                f" last_stdout={_summarize_for_log(last_stdout_text)}"
                f" last_stderr={_summarize_for_log(last_stderr_text)}"
            )
        raise RuntimeError(f'Remote execution failed for {label}{detail}{out_detail}')
    finally:
        try:
            client.close()
        except Exception:
            pass


def _sftp_ensure_dir(sftp: Any, directory: str) -> None:
    directory = posixpath.normpath(directory)
    if not directory or directory == '/':
        return
    parts: list[str] = []
    current = directory
    while current not in ('', '/'):
        parts.append(current)
        current = posixpath.dirname(current)
    for path in reversed(parts):
        try:
            sftp.stat(path)
        except Exception:
            try:
                sftp.mkdir(path)
            except Exception:
                pass


def _upload_file_to_core_host(core_cfg: Dict[str, Any], local_path: str, *, remote_dir: str = '/tmp/scenarioforge/uploads') -> str:
    if not os.path.exists(local_path):
        raise FileNotFoundError(local_path)
    cfg = _normalize_core_config(core_cfg, include_password=True)
    client = _open_ssh_client(cfg)
    sftp = None
    try:
        sftp = client.open_sftp()
        _sftp_ensure_dir(sftp, remote_dir)
        unique = f"{uuid.uuid4().hex}_{os.path.basename(local_path)}"
        remote_path = posixpath.normpath(posixpath.join(remote_dir, unique))
        sftp.put(local_path, remote_path)
        return remote_path
    finally:
        try:
            if sftp:
                sftp.close()
        except Exception:
            pass
        try:
            client.close()
        except Exception:
            pass


def _remove_remote_file(core_cfg: Dict[str, Any], remote_path: str) -> None:
    if not remote_path:
        return
    cfg = _normalize_core_config(core_cfg, include_password=True)
    try:
        client = _open_ssh_client(cfg)
    except Exception:
        return
    try:
        sftp = client.open_sftp()
    except Exception:
        try:
            client.close()
        except Exception:
            pass
        return
    try:
        try:
            sftp.remove(remote_path)
        except FileNotFoundError:
            pass
    finally:
        try:
            sftp.close()
        except Exception:
            pass
        try:
            client.close()
        except Exception:
            pass


def _download_remote_file(core_cfg: Dict[str, Any], remote_path: str, local_path: str) -> None:
    cfg = _normalize_core_config(core_cfg, include_password=True)
    client = _open_ssh_client(cfg)
    sftp = None
    try:
        sftp = client.open_sftp()
        os.makedirs(os.path.dirname(local_path), exist_ok=True)
        sftp.get(remote_path, local_path)
    finally:
        try:
            if sftp:
                sftp.close()
        except Exception:
            pass
        try:
            client.close()
        except Exception:
            pass


def _collect_remote_core_daemon_pids(
    client: Any,
    *,
    log_handle: Optional[TextIO] = None,
    log_prefix: str = '[remote] ',
    stage: str = 'probe',
) -> List[int]:
    # Use `timeout` to avoid SSH reads hanging indefinitely if the remote shell blocks.
    command = "sh -c 'timeout 5s pgrep -x core-daemon 2>/dev/null || true'"
    try:
        stdin, stdout, stderr = client.exec_command(command, timeout=8.0)
    except Exception:
        return []
    try:
        stdout_data = stdout.read()
        stderr_data = stderr.read()
    finally:
        _close_ssh_command_streams(stdin, stdout, stderr)
    try:
        exit_code = stdout.channel.recv_exit_status() if hasattr(stdout, 'channel') else 0
    except Exception:
        exit_code = 0
    try:
        if log_handle is not None:
            out_preview = (
                stdout_data.decode('utf-8', 'ignore')
                if isinstance(stdout_data, (bytes, bytearray))
                else str(stdout_data or '')
            ).strip()
            err_preview = (
                stderr_data.decode('utf-8', 'ignore')
                if isinstance(stderr_data, (bytes, bytearray))
                else str(stderr_data or '')
            ).strip()
            # Keep logs readable.
            if len(out_preview) > 300:
                out_preview = out_preview[:300] + '…'
            if len(err_preview) > 300:
                err_preview = err_preview[:300] + '…'
            log_handle.write(
                f"{log_prefix}{stage}: {command} -> exit={exit_code} stdout={out_preview} stderr={err_preview}\n"
            )
            _write_sse_marker(
                log_handle,
                'phase',
                {
                    'stage': stage,
                    'kind': 'ssh',
                    'command': command,
                    'exit': exit_code,
                    'stdout': out_preview,
                    'stderr': err_preview,
                },
            )
    except Exception:
        pass
    if exit_code not in (0, 1):
        return []
    text = ''
    if isinstance(stdout_data, bytes):
        text = stdout_data.decode('utf-8', 'ignore')
    else:
        text = str(stdout_data or '')
    pids: List[int] = []
    for token in text.strip().split():
        try:
            pids.append(int(token))
        except Exception:
            continue
    return pids


def _start_remote_core_daemon(client: Any, sudo_password: str | None, logger: logging.Logger) -> tuple[int, str, str]:
    # Avoid hanging on an interactive sudo prompt: if no password is available,
    # use -n so sudo fails fast instead of blocking forever.
    if sudo_password:
        # Wrap in `timeout` so systemctl can't block forever.
        sudo_cmd = "sudo -S -p '' sh -c 'timeout 20s systemctl start core-daemon'"
    else:
        sudo_cmd = "sudo -n sh -c 'timeout 20s systemctl start core-daemon'"
    stdin = stdout = stderr = None
    try:
        stdin, stdout, stderr = client.exec_command(sudo_cmd, timeout=20.0, get_pty=True)
        if sudo_password:
            try:
                stdin.write(str(sudo_password) + '\n')
                stdin.flush()
            except Exception:
                pass
        stdout_data = stdout.read()
        stderr_data = stderr.read()
        exit_code = stdout.channel.recv_exit_status() if hasattr(stdout, 'channel') else 0
        out_text = stdout_data.decode('utf-8', 'ignore') if isinstance(stdout_data, bytes) else str(stdout_data or '')
        err_text = stderr_data.decode('utf-8', 'ignore') if isinstance(stderr_data, bytes) else str(stderr_data or '')
        logger.info('[core] auto-start daemon executed: exit=%d stdout=%s stderr=%s', exit_code, out_text.strip(), err_text.strip())
        return exit_code, out_text, err_text
    finally:
        _close_ssh_command_streams(stdin, stdout, stderr)


def _stop_remote_core_daemon_conflict(
    client: Any,
    *,
    sudo_password: str | None,
    pids: List[int],
    logger: logging.Logger,
) -> Dict[str, Any]:
    """Stop duplicate core-daemon processes.

    Preferred strategy:
    - Discover systemd MainPID for core-daemon.
    - If MainPID is among duplicates, keep it and terminate only extras.
    - Otherwise fall back to a full stop/kill/start recovery.
    """

    if not pids:
        return {'status': 'noop', 'detail': 'no pids provided'}
    if not sudo_password:
        raise RuntimeError('Stopping core-daemon requires sudo; provide an SSH password.')

    def _sudo(cmd: str, *, timeout: float = 30.0) -> tuple[int, str, str]:
        wrapped = f"sudo -S -p '' sh -c {shlex.quote(cmd)}"
        stdin = stdout = stderr = None
        try:
            stdin, stdout, stderr = client.exec_command(wrapped, timeout=timeout, get_pty=True)
            try:
                stdin.write(str(sudo_password) + '\n')
                stdin.flush()
            except Exception:
                pass
            out = stdout.read() if stdout else b''
            err = stderr.read() if stderr else b''
            try:
                exit_code = stdout.channel.recv_exit_status() if (stdout and hasattr(stdout, 'channel')) else 0
            except Exception:
                exit_code = 0
            out_text = out.decode('utf-8', 'ignore') if isinstance(out, (bytes, bytearray)) else str(out or '')
            err_text = err.decode('utf-8', 'ignore') if isinstance(err, (bytes, bytearray)) else str(err or '')
            return exit_code, out_text, err_text
        finally:
            _close_ssh_command_streams(stdin, stdout, stderr)

    unique_pids = sorted({int(pid) for pid in pids if str(pid).strip().isdigit() and int(pid) > 0})
    if not unique_pids:
        return {'status': 'noop', 'detail': 'no valid pids provided'}

    main_pid: Optional[int] = None
    code, out, err = _sudo('timeout 8s systemctl show -p MainPID --value core-daemon 2>/dev/null || true', timeout=15.0)
    try:
        for token in str(out or '').strip().split():
            value = int(token)
            if value > 0:
                main_pid = value
                break
    except Exception:
        main_pid = None

    preserve_main_pid = bool(main_pid and main_pid in unique_pids and len(unique_pids) > 1)
    if preserve_main_pid:
        kill_targets = [pid for pid in unique_pids if pid != main_pid]
    else:
        kill_targets = list(unique_pids)

    target_args = ' '.join(str(pid) for pid in kill_targets)
    if not target_args:
        return {
            'status': 'noop',
            'detail': 'no duplicate targets to stop',
            'pids': unique_pids,
            'main_pid': main_pid,
            'preserved_main_pid': preserve_main_pid,
        }

    steps: List[Dict[str, Any]] = []
    steps.append({
        'step': 'systemctl_mainpid',
        'command': 'timeout 8s systemctl show -p MainPID --value core-daemon 2>/dev/null || true',
        'exit': code,
        'stdout': (out or '').strip(),
        'stderr': (err or '').strip(),
    })

    command_plan: List[tuple[str, str]] = []
    if not preserve_main_pid:
        command_plan.append(('systemctl_stop', 'timeout 15s systemctl stop core-daemon || true'))
    command_plan.extend([
        ('kill_term', f'kill -TERM {target_args} 2>/dev/null || true'),
        ('sleep', 'sleep 1'),
        ('kill_kill', f'kill -KILL {target_args} 2>/dev/null || true'),
    ])
    if not preserve_main_pid:
        command_plan.append(('systemctl_start', 'timeout 20s systemctl start core-daemon || true'))

    for label, cmd in command_plan:
        code, out, err = _sudo(cmd, timeout=35.0)
        steps.append({'step': label, 'command': cmd, 'exit': code, 'stdout': (out or '').strip(), 'stderr': (err or '').strip()})
        try:
            logger.info('[core] stop duplicate daemons: %s exit=%s', label, code)
        except Exception:
            pass
    return {
        'status': 'attempted',
        'pids': unique_pids,
        'main_pid': main_pid,
        'preserved_main_pid': preserve_main_pid,
        'kill_targets': kill_targets,
        'steps': steps,
    }


def _local_custom_services_dir() -> str:
    repo_root = _get_repo_root()
    return os.path.join(repo_root, 'on_core_machine', 'custom_services')


def _local_custom_service_files() -> list[str]:
    base = _local_custom_services_dir()
    try:
        if not os.path.isdir(base):
            return []
    except Exception:
        return []
    out: list[str] = []
    try:
        for name in os.listdir(base):
            if not name.endswith('.py'):
                continue
            if name.startswith('.'):
                continue
            ap = os.path.join(base, name)
            if os.path.isfile(ap):
                out.append(ap)
    except Exception:
        return []
    out.sort(key=lambda p: os.path.basename(p).lower())
    return out


def _local_custom_service_names() -> list[str]:
    names: set[str] = set()
    for path in _local_custom_service_files():
        module_name = os.path.splitext(os.path.basename(path))[0]
        found = False
        try:
            with open(path, 'r', encoding='utf-8') as handle:
                tree = ast.parse(handle.read(), filename=path)
            for node in tree.body:
                if not isinstance(node, ast.ClassDef):
                    continue
                for stmt in node.body:
                    target_names: list[str] = []
                    value_node: Any = None
                    if isinstance(stmt, ast.AnnAssign):
                        value_node = stmt.value
                        if isinstance(stmt.target, ast.Name):
                            target_names.append(stmt.target.id)
                    elif isinstance(stmt, ast.Assign):
                        value_node = stmt.value
                        for target in stmt.targets:
                            if isinstance(target, ast.Name):
                                target_names.append(target.id)
                    if 'name' not in target_names:
                        continue
                    if isinstance(value_node, ast.Constant) and isinstance(value_node.value, str):
                        service_name = value_node.value.strip()
                        if service_name:
                            names.add(service_name)
                            found = True
        except Exception:
            found = False
        if not found and module_name:
            names.add(module_name)
    return sorted(names, key=str.lower)


def _install_custom_services_to_core_vm(
    ssh_client: Any,
    *,
    sudo_password: str | None,
    logger: logging.Logger,
    core_cfg: Optional[Dict[str, Any]] = None,
) -> dict:
    """Copy repo-provided CORE custom services to the remote CORE VM.

    - Uploads python service modules under on_core_machine/custom_services.
    - Installs them into the remote core.services package directory.
    - Restarts (or starts) core-daemon.
    - Verifies the modules import successfully.
    """

    local_files = _local_custom_service_files()
    if not local_files:
        raise RuntimeError(f'No custom services found under {_local_custom_services_dir()}')
    module_names = [os.path.splitext(os.path.basename(p))[0] for p in local_files]

    def _exec(cmd: str, *, timeout: float = 25.0) -> tuple[int, str, str]:
        stdin = stdout = stderr = None
        try:
            stdin, stdout, stderr = ssh_client.exec_command(cmd, timeout=timeout, get_pty=True)
            out = stdout.read() if stdout else b''
            err = stderr.read() if stderr else b''
            try:
                exit_code = stdout.channel.recv_exit_status() if (stdout and hasattr(stdout, 'channel')) else 0
            except Exception:
                exit_code = 0
            out_text = out.decode('utf-8', 'ignore') if isinstance(out, (bytes, bytearray)) else str(out or '')
            err_text = err.decode('utf-8', 'ignore') if isinstance(err, (bytes, bytearray)) else str(err or '')
            return exit_code, out_text, err_text
        finally:
            _close_ssh_command_streams(stdin, stdout, stderr)

    def _sudo(cmd: str, *, timeout: float = 45.0) -> tuple[int, str, str]:
        if not sudo_password:
            # Installing into site-packages requires root on typical CORE installs.
            raise RuntimeError('Installing custom services requires sudo; provide an SSH password in Step 2.')
        wrapped = f"sudo -S -p '' sh -c {shlex.quote(cmd)}"
        stdin = stdout = stderr = None
        try:
            stdin, stdout, stderr = ssh_client.exec_command(wrapped, timeout=timeout, get_pty=True)
            try:
                stdin.write(str(sudo_password) + '\n')
                stdin.flush()
            except Exception:
                pass
            out = stdout.read() if stdout else b''
            err = stderr.read() if stderr else b''
            try:
                exit_code = stdout.channel.recv_exit_status() if (stdout and hasattr(stdout, 'channel')) else 0
            except Exception:
                exit_code = 0
            out_text = out.decode('utf-8', 'ignore') if isinstance(out, (bytes, bytearray)) else str(out or '')
            err_text = err.decode('utf-8', 'ignore') if isinstance(err, (bytes, bytearray)) else str(err or '')
            return exit_code, out_text, err_text
        finally:
            _close_ssh_command_streams(stdin, stdout, stderr)

    def _remote_python_candidates() -> list[str]:
        candidates: list[str] = []
        try:
            if core_cfg:
                for cand in _candidate_remote_python_interpreters(core_cfg):
                    c = str(cand or '').strip()
                    if c and c not in candidates:
                        candidates.append(c)
        except Exception:
            pass
        for c in ('core-python', '/opt/core/venv/bin/python', 'python3', 'python'):
            if c not in candidates:
                candidates.append(c)
        return candidates

    def _remote_file_size(sftp: Any, remote_path: str) -> Optional[int]:
        try:
            st = sftp.stat(remote_path)
            return int(getattr(st, 'st_size'))
        except Exception:
            return None

    def _sftp_put_compat(sftp: Any, local_path: str, remote_path: str) -> None:
        try:
            sftp.put(local_path, remote_path, confirm=False)
        except TypeError:
            sftp.put(local_path, remote_path)

    def _sftp_stream_upload(sftp: Any, local_path: str, remote_path: str) -> None:
        opener = getattr(sftp, 'open', None) or getattr(sftp, 'file', None)
        if not callable(opener):
            _sftp_put_compat(sftp, local_path, remote_path)
            return
        remote_fh = opener(remote_path, 'wb')
        try:
            with open(local_path, 'rb') as local_fh:
                shutil.copyfileobj(local_fh, remote_fh)
            flush = getattr(remote_fh, 'flush', None)
            if callable(flush):
                flush()
        finally:
            try:
                remote_fh.close()
            except Exception:
                pass

    def _upload_custom_service_file_via_command(local_path: str, remote_path: str) -> None:
        expected_size = os.path.getsize(local_path)
        with open(local_path, 'rb') as handle:
            payload_b64 = base64.b64encode(handle.read()).decode('ascii')

        remote_path_literal = json.dumps(remote_path)
        upload_script = textwrap.dedent(
            f"""
            import base64
            import os
            import sys

            path = {remote_path_literal}
            expected_size = {int(expected_size)}
            tmp_path = f"{{path}}.tmp-{{os.getpid()}}"

            try:
                encoded = sys.stdin.read()
                if isinstance(encoded, bytes):
                    encoded = encoded.decode("ascii")
                payload = base64.b64decode(str(encoded or "").encode("ascii"), validate=True)
                if len(payload) != expected_size:
                    raise RuntimeError(f"decoded size {{len(payload)}} != expected {{expected_size}}")

                parent = os.path.dirname(path)
                if parent:
                    os.makedirs(parent, exist_ok=True)

                with open(tmp_path, "wb") as handle:
                    handle.write(payload)
                    handle.flush()
                    try:
                        os.fsync(handle.fileno())
                    except OSError:
                        pass

                actual_size = os.path.getsize(tmp_path)
                if actual_size != expected_size:
                    raise RuntimeError(f"remote temp size {{actual_size}} != expected {{expected_size}}")
                os.replace(tmp_path, path)
                print(actual_size)
            except Exception as exc:
                try:
                    if os.path.exists(tmp_path):
                        os.unlink(tmp_path)
                except Exception:
                    pass
                print(exc, file=sys.stderr)
                sys.exit(1)
            """
        )
        upload_script_b64 = base64.b64encode(upload_script.encode('utf-8')).decode('ascii')
        loader = (
            "import base64; "
            f"exec(compile(base64.b64decode('{upload_script_b64}').decode('utf-8'), "
            "'<coretg-custom-service-upload>', 'exec'))"
        )

        failures: list[str] = []
        for interpreter in _remote_python_candidates():
            cmd = f"{shlex.quote(interpreter)} -c {shlex.quote(loader)}"
            stdin = stdout = stderr = None
            try:
                stdin, stdout, stderr = ssh_client.exec_command(cmd, timeout=30.0, get_pty=False)
                if stdin:
                    try:
                        stdin.write(payload_b64)
                    except TypeError:
                        stdin.write(payload_b64.encode('ascii'))
                    try:
                        stdin.flush()
                    except Exception:
                        pass
                    try:
                        stdin.close()
                    except Exception:
                        pass
                    stdin = None
                out = stdout.read() if stdout else b''
                err = stderr.read() if stderr else b''
                try:
                    exit_code = stdout.channel.recv_exit_status() if (stdout and hasattr(stdout, 'channel')) else 0
                except Exception:
                    exit_code = 0
                out_text = out.decode('utf-8', 'ignore') if isinstance(out, (bytes, bytearray)) else str(out or '')
                err_text = err.decode('utf-8', 'ignore') if isinstance(err, (bytes, bytearray)) else str(err or '')
                if exit_code == 0:
                    last_line = out_text.strip().splitlines()[-1].strip() if out_text.strip() else ''
                    try:
                        actual_size = int(last_line)
                    except (TypeError, ValueError):
                        actual_size = expected_size if not last_line else -1
                    if actual_size == expected_size:
                        return
                    failures.append(
                        f"{interpreter}: exit=0 but reported size {last_line or 'n/a'} != {expected_size}"
                    )
                else:
                    detail = (err_text or out_text or f'exit={exit_code}').strip()
                    failures.append(
                        f"{interpreter}: exit={exit_code} detail={_summarize_for_log(detail, limit=160)}"
                    )
            except Exception as exc:
                failures.append(f"{interpreter}: {exc}")
            finally:
                _close_ssh_command_streams(stdin, stdout, stderr)

        detail = '; '.join(failures[-4:]) if failures else 'no remote python candidates'
        raise RuntimeError(f'command-channel fallback failed: {detail}')

    def _upload_custom_service_file(sftp: Any, local_path: str, remote_path: str) -> None:
        expected_size = os.path.getsize(local_path)
        errors: list[str] = []
        for attempt in range(1, 4):
            try:
                if attempt == 1:
                    _sftp_put_compat(sftp, local_path, remote_path)
                else:
                    _sftp_stream_upload(sftp, local_path, remote_path)
                actual_size = _remote_file_size(sftp, remote_path)
                if actual_size is None or actual_size == expected_size:
                    return
                errors.append(f'attempt {attempt}: remote size {actual_size} != local size {expected_size}')
            except Exception as exc:
                errors.append(f'attempt {attempt}: {exc}')
            try:
                time.sleep(0.15 * attempt)
            except Exception:
                pass
        try:
            _upload_custom_service_file_via_command(local_path, remote_path)
            return
        except Exception as exc:
            errors.append(str(exc))
        detail = '; '.join(errors[-4:]) if errors else 'unknown upload failure'
        raise RuntimeError(
            f'Failed uploading custom service {os.path.basename(local_path)} to {remote_path}: {detail}'
        )

    # Discover the remote core.services directory (where CORE loads service modules).
    candidates = _remote_python_candidates()

    services_dirs: list[str] = []
    core_conf_custom_services_dirs: list[str] = []
    core_conf_custom_services_lines: list[str] = []
    core_conf_custom_services_configured = False
    managed_custom_services_dir = '/opt/core/custom_services'
    core_conf_readable: Optional[bool] = None
    core_conf_path: Optional[str] = None

    def _parse_core_conf_custom_services_dirs(raw_text: str) -> list[str]:
        out: list[str] = []
        if not raw_text:
            return out
        try:
            lines = str(raw_text or '').splitlines()
        except Exception:
            return out
        for line in lines:
            txt = str(line or '').strip()
            if not txt:
                continue
            if txt.startswith('__CORECONF_'):
                continue
            if '=' in txt:
                _lhs, rhs = txt.split('=', 1)
            else:
                rhs = txt
            rhs = rhs.strip().strip('"').strip("'")
            if not rhs:
                continue
            cleaned = rhs.strip()
            if cleaned.startswith('[') and cleaned.endswith(']'):
                cleaned = cleaned[1:-1].strip()
            parts = [p.strip().strip('"').strip("'") for p in re.split(r'[,;:]', cleaned)]
            for p in parts:
                if not p:
                    continue
                p = os.path.expandvars(p)
                base_name = os.path.basename(p.rstrip('/'))
                if base_name.lower() == 'core.conf' or p.lower().endswith('.conf'):
                    continue
                if p.startswith('~'):
                    # Use shell expansion on remote at install-time; keep here for de-dupe readability.
                    pass
                if p not in out:
                    out.append(p)
        return out
    probe_details: list[str] = []
    last_code: Optional[int] = None
    last_err = ''
    for interp in candidates:
        probe = f"timeout 15s {shlex.quote(interp)} -c \"import os, core.services; print(os.path.dirname(core.services.__file__))\""
        code, out, err = _exec(f"sh -c {shlex.quote(probe)}", timeout=20.0)
        last_code = code
        out_text = (out or '').strip()
        err_text = (err or '').strip()
        probe_details.append(
            f"{interp}:exit={code},stdout={_summarize_for_log(out_text, limit=120)},stderr={_summarize_for_log(err_text, limit=120)}"
        )
        if code == 0 and out_text:
            cand_dir = out_text.splitlines()[-1].strip()
            if cand_dir and cand_dir not in services_dirs:
                services_dirs.append(cand_dir)
        if err_text or out_text:
            last_err = err_text or out_text

    # Also include custom service directories configured in core.conf.
    # Prefer /opt/core/etc/core.conf (CORE install layout), then fallback to /etc/core/core.conf.
    try:
        conf_probe_cmd = (
            "conf=''; "
            "if [ -r /opt/core/etc/core.conf ]; then conf='/opt/core/etc/core.conf'; "
            "elif [ -r /etc/core/core.conf ]; then conf='/etc/core/core.conf'; fi; "
            "if [ -n \"$conf\" ]; then "
            "echo '__CORECONF_PATH__='$conf; "
            "echo '__CORECONF_READABLE__=1'; "
            "grep -Ei '^[[:space:]]*(custom_services|custom_services_dir|custom_service_dir|custom_services_dirs)[[:space:]]*=' \"$conf\" || true; "
            "else echo '__CORECONF_READABLE__=0'; "
            "fi"
        )
        conf_code, conf_out, conf_err = _exec(f"sh -c {shlex.quote(conf_probe_cmd)}", timeout=12.0)
        for raw_line in str(conf_out or '').splitlines():
            normalized = str(raw_line or '').strip()
            if normalized.startswith('__CORECONF_PATH__='):
                path_val = normalized.split('=', 1)[1].strip()
                core_conf_path = path_val or None
                continue
            if normalized == '__CORECONF_READABLE__=1':
                core_conf_readable = True
                continue
            if normalized == '__CORECONF_READABLE__=0':
                core_conf_readable = False
                continue
            if normalized and normalized not in core_conf_custom_services_lines:
                core_conf_custom_services_lines.append(normalized)
        if core_conf_readable is None:
            if core_conf_custom_services_lines:
                core_conf_readable = True
            elif conf_code == 0:
                core_conf_readable = False
        conf_dirs = _parse_core_conf_custom_services_dirs(conf_out or '')
        for conf_dir in conf_dirs:
            if conf_dir and conf_dir not in core_conf_custom_services_dirs:
                core_conf_custom_services_dirs.append(conf_dir)
        for conf_dir in conf_dirs:
            if conf_dir and conf_dir not in services_dirs:
                services_dirs.append(conf_dir)
        if conf_code != 0 and (conf_err or conf_out):
            logger.debug('[core] core.conf custom_services probe non-fatal: %s', (conf_err or conf_out).strip())
    except Exception:
        pass

    if core_conf_path and not core_conf_custom_services_dirs:
        try:
            line = f'custom_services_dir = {managed_custom_services_dir}'
            configure_cmd = (
                f"mkdir -p {shlex.quote(managed_custom_services_dir)} && "
                f"printf '\n{line}\n' >> {shlex.quote(core_conf_path)}"
            )
            code, out, err = _sudo(configure_cmd, timeout=30.0)
            if code != 0:
                raise RuntimeError((err or out or '').strip() or f'exit={code}')
            core_conf_custom_services_configured = True
            core_conf_custom_services_dirs.append(managed_custom_services_dir)
            core_conf_custom_services_lines.append(line)
            if managed_custom_services_dir not in services_dirs:
                services_dirs.append(managed_custom_services_dir)
            logger.info('[core] Added core.conf custom_services_dir: %s', managed_custom_services_dir)
        except Exception as exc:
            logger.warning('[core] Failed configuring core.conf custom_services_dir: %s', exc)

    # Also include the active core-daemon runtime services path when available.
    try:
        daemon_probe = (
            "pid=$(pgrep -x core-daemon 2>/dev/null | head -n1 || true); "
            "if [ -n \"$pid\" ]; then "
            "cwd=$(readlink -f /proc/$pid/cwd 2>/dev/null || true); "
            "if [ -n \"$cwd\" ] && [ -d \"$cwd/core/services\" ]; then echo \"$cwd/core/services\"; fi; "
            "fi"
        )
        d_code, d_out, d_err = _exec(f"sh -c {shlex.quote(daemon_probe)}", timeout=10.0)
        d_path = str(d_out or '').strip().splitlines()[-1].strip() if str(d_out or '').strip() else ''
        if d_path and d_path not in services_dirs:
            services_dirs.append(d_path)
        if d_code != 0 and (d_err or d_out):
            logger.debug('[core] daemon services-path probe non-fatal: %s', (d_err or d_out).strip())
    except Exception:
        pass

    if not services_dirs:
        raise RuntimeError(
            "Failed to locate remote core.services directory "
            f"(probe exit={last_code if last_code is not None else 'n/a'}): "
            f"{_summarize_for_log(last_err, limit=240)} | probes={'; '.join(probe_details[-6:])}"
        )

    logger.info('[core] Installing custom services into %s', ', '.join(services_dirs))

    # Upload files to a temp directory first.
    tmp_dir = '/tmp/coretg_custom_services'
    _exec(f"sh -c {shlex.quote(f'mkdir -p {tmp_dir}')}", timeout=15.0)
    sftp = None
    try:
        sftp = ssh_client.open_sftp()
        for lp in local_files:
            rp = f"{tmp_dir}/{os.path.basename(lp)}"
            _upload_custom_service_file(sftp, lp, rp)
    finally:
        try:
            if sftp:
                sftp.close()
        except Exception:
            pass

    # Install into all discovered core.services directories.
    install_failures: list[str] = []
    for services_dir in services_dirs:
        install_cmd = f"mkdir -p {shlex.quote(services_dir)} && install -m 0644 {tmp_dir}/*.py {shlex.quote(services_dir)}/"
        code, out, err = _sudo(install_cmd, timeout=45.0)
        if code != 0:
            install_failures.append(f"{services_dir}: exit={code} detail={(err or out or '').strip()}")
    if install_failures:
        raise RuntimeError('Failed installing custom services: ' + ' | '.join(install_failures))

    # Restart (or start) core-daemon.
    restart_cmd = "systemctl restart core-daemon || systemctl start core-daemon"
    code, out, err = _sudo(restart_cmd, timeout=45.0)
    if code != 0:
        raise RuntimeError(f'Failed restarting core-daemon after install (exit={code}): {(err or out or "").strip()}')

    # Verify CORE discovers these services (not just that files exist).
    # We import the installed modules, extract CoreService subclasses and their `name`s,
    # then ensure those names are present in the discoverable scan of `core.services`.
    module_list_literal = json.dumps(module_names)
    verify_script = textwrap.dedent(
        f"""
        import importlib
        import inspect
        import json
        import pkgutil
        import sys

        import core.services

        try:
            from core.services.base import CoreService  # type: ignore
        except Exception:  # pragma: no cover - remote execution
            from core.services.coreservices import CoreService  # type: ignore

        custom_modules = json.loads({module_list_literal!r})

        def service_names_from_module(mod):
            names = []
            for _name, obj in inspect.getmembers(mod, inspect.isclass):
                try:
                    is_service = issubclass(obj, CoreService) and obj is not CoreService
                except Exception:
                    continue
                if not is_service:
                    continue
                svc_name = getattr(obj, 'name', None)
                if isinstance(svc_name, str) and svc_name.strip():
                    names.append(svc_name.strip())
            # keep deterministic output
            return sorted(set(names))

        module_service_names = {{}}
        missing_modules = []
        modules_without_services = []
        custom_names = set()

        for mod_name in custom_modules:
            fq = f"core.services.{{mod_name}}"
            try:
                mod = importlib.import_module(fq)
            except Exception as exc:
                missing_modules.append({{'module': mod_name, 'error': repr(exc)}})
                continue
            names = service_names_from_module(mod)
            module_service_names[mod_name] = names
            if not names:
                modules_without_services.append(mod_name)
            custom_names.update(names)

        # Discoverable scan across core.services.
        all_names = set()
        prefix = core.services.__name__ + '.'
        for m in pkgutil.walk_packages(core.services.__path__, prefix):
            name = getattr(m, 'name', None)
            if not name:
                continue
            try:
                mod = importlib.import_module(name)
            except Exception:
                continue
            for svc_name in service_names_from_module(mod):
                all_names.add(svc_name)

        custom_names_missing_from_scan = sorted([n for n in custom_names if n not in all_names])

        result = {{
            'custom_modules': custom_modules,
            'module_service_names': module_service_names,
            'custom_service_names': sorted(custom_names),
            'missing_modules': missing_modules,
            'modules_without_services': modules_without_services,
            'all_service_names_count': len(all_names),
            'custom_names_missing_from_scan': custom_names_missing_from_scan,
        }}
        print('::SERVICESCHECK::' + json.dumps(result, sort_keys=True))

        if missing_modules or modules_without_services or custom_names_missing_from_scan:
            sys.exit(4)
        """
    ).strip()

    verify_b64 = base64.b64encode(verify_script.encode('utf-8')).decode('ascii')
    verify_exec = (
        "import base64; "
        f"exec(compile(base64.b64decode('{verify_b64}').decode('utf-8'), '<coretg-services-verify>', 'exec'))"
    )
    candidates: list[str] = []
    try:
        if core_cfg:
            candidates = _candidate_remote_python_interpreters(core_cfg)
    except Exception:
        candidates = []
    for c in ('core-python', '/opt/core/venv/bin/python', 'python3', 'python'):
        if c not in candidates:
            candidates.append(c)

    code = 1
    out = ''
    err = ''
    marker = '::SERVICESCHECK::'
    payload_line = ''
    probe_errors: list[str] = []
    for interp in candidates:
        verify_cmd = f"timeout 35s {shlex.quote(interp)} -c {shlex.quote(verify_exec)}"
        code, out, err = _exec(f"sh -c {shlex.quote(verify_cmd)}", timeout=40.0)
        for line in (out or '').splitlines():
            if marker in line:
                payload_line = line.strip()
                break
        if payload_line:
            break
        probe_errors.append(
            f"{interp}:exit={code},stdout={_summarize_for_log((out or '').strip(), limit=120)},stderr={_summarize_for_log((err or '').strip(), limit=120)}"
        )
    if not payload_line:
        detail = '; '.join(probe_errors[-6:])
        raise RuntimeError(
            "Custom services verification did not produce expected output "
            f"(exit={code}): {(err or out or '').strip()} | probes={detail}"
        )
    try:
        verify_payload = json.loads(payload_line.split(marker, 1)[1])
    except Exception as exc:
        raise RuntimeError(f'Custom services verification output could not be parsed: {exc}: {payload_line}')
    if code != 0:
        raise RuntimeError(f'Custom services failed CORE discovery verification: {json.dumps(verify_payload, indent=2)}')

    return {
        'services_dir': services_dirs[0] if services_dirs else None,
        'services_dirs': services_dirs,
        'core_conf_path': core_conf_path,
        'core_conf_readable': core_conf_readable,
        'core_conf_custom_services_configured': core_conf_custom_services_configured,
        'core_conf_custom_services_dirs': core_conf_custom_services_dirs,
        'core_conf_custom_services_lines': core_conf_custom_services_lines,
        'modules': module_names,
        'service_names': verify_payload.get('custom_service_names') if isinstance(verify_payload, dict) else None,
        'module_service_names': verify_payload.get('module_service_names') if isinstance(verify_payload, dict) else None,
    }


def _remote_core_service_names(
    ssh_client: Any,
    *,
    timeout: float = 25.0,
    core_cfg: Optional[Dict[str, Any]] = None,
    require_custom_services_dir: bool = False,
) -> set[str]:
    """Best-effort discovery of CORE service names available on a remote host."""
    require_custom_literal = 'True' if require_custom_services_dir else 'False'
    script = textwrap.dedent(
        r"""
        import importlib
        import importlib.util
        import inspect
        import json
        import os
        import pkgutil
        import re

        require_custom_services_dir = __REQUIRE_CUSTOM_SERVICES_DIR__

        try:
            import core.services
            from core.services.base import CoreService  # type: ignore
        except Exception:
            import core.services
            from core.services.coreservices import CoreService  # type: ignore

        def service_names_from_module(mod):
            found = set()
            for _name, obj in inspect.getmembers(mod, inspect.isclass):
                try:
                    ok = issubclass(obj, CoreService) and obj is not CoreService
                except Exception:
                    continue
                if not ok:
                    continue
                svc = getattr(obj, 'name', None)
                if isinstance(svc, str) and svc.strip():
                    found.add(svc.strip())
            return found

        def parse_custom_dirs(raw_text):
            dirs = []
            for line in str(raw_text or '').splitlines():
                text = line.strip()
                if not text or text.startswith('#'):
                    continue
                if not re.match(r'^(custom_services|custom_services_dir|custom_service_dir|custom_services_dirs)\s*=', text, re.I):
                    continue
                rhs = text.split('=', 1)[1].strip().strip('"').strip("'")
                if rhs.startswith('[') and rhs.endswith(']'):
                    rhs = rhs[1:-1].strip()
                for part in re.split(r'[,;:]', rhs):
                    value = part.strip().strip('"').strip("'")
                    if value and value not in dirs:
                        dirs.append(value)
            return dirs

        package_names = set()
        prefix = core.services.__name__ + '.'
        for m in pkgutil.walk_packages(core.services.__path__, prefix):
            n = getattr(m, 'name', None)
            if not n:
                continue
            try:
                mod = importlib.import_module(n)
            except Exception:
                continue
            package_names.update(service_names_from_module(mod))

        conf_path = None
        custom_dirs = []
        for candidate in ('/opt/core/etc/core.conf', '/etc/core/core.conf'):
            try:
                if os.path.isfile(candidate):
                    conf_path = candidate
                    with open(candidate, 'r', encoding='utf-8', errors='ignore') as handle:
                        custom_dirs = parse_custom_dirs(handle.read())
                    break
            except Exception:
                continue

        custom_dir_names = set()
        custom_dir_errors = []
        for raw_dir in custom_dirs:
            directory = os.path.expandvars(os.path.expanduser(str(raw_dir or '').strip()))
            if not directory or not os.path.isdir(directory):
                custom_dir_errors.append({'dir': raw_dir, 'error': 'not found'})
                continue
            try:
                filenames = sorted([name for name in os.listdir(directory) if name.endswith('.py') and not name.startswith('.')])
            except Exception as exc:
                custom_dir_errors.append({'dir': raw_dir, 'error': repr(exc)})
                continue
            for index, filename in enumerate(filenames):
                path = os.path.join(directory, filename)
                module_name = '_coretg_custom_service_%s_%s' % (index, re.sub(r'\W+', '_', filename))
                try:
                    spec = importlib.util.spec_from_file_location(module_name, path)
                    if spec is None or spec.loader is None:
                        raise RuntimeError('spec unavailable')
                    mod = importlib.util.module_from_spec(spec)
                    spec.loader.exec_module(mod)
                    custom_dir_names.update(service_names_from_module(mod))
                except Exception as exc:
                    custom_dir_errors.append({'file': path, 'error': repr(exc)})

        names = custom_dir_names if require_custom_services_dir else (package_names | custom_dir_names)
        payload = {
            'names': sorted(names),
            'package_service_names': sorted(package_names),
            'custom_service_names': sorted(custom_dir_names),
            'custom_services_dir_required': require_custom_services_dir,
            'core_conf_path': conf_path,
            'core_conf_custom_services_dirs': custom_dirs,
            'custom_dir_errors': custom_dir_errors,
        }
        print('::SERVICENAMES::' + json.dumps(payload, sort_keys=True))
        """
    ).strip().replace('__REQUIRE_CUSTOM_SERVICES_DIR__', require_custom_literal)
    script_b64 = base64.b64encode(script.encode('utf-8')).decode('ascii')
    exec_b64 = (
        "import base64; "
        f"exec(compile(base64.b64decode('{script_b64}').decode('utf-8'), '<coretg-services-list>', 'exec'))"
    )
    candidates: list[str] = []
    try:
        if core_cfg:
            candidates = _candidate_remote_python_interpreters(core_cfg)
    except Exception:
        candidates = []
    for c in ('core-python', '/opt/core/venv/bin/python', 'python3', 'python'):
        if c not in candidates:
            candidates.append(c)

    out_text = ''
    for interp in candidates:
        cmd = f"timeout {int(max(5, timeout))}s {shlex.quote(interp)} -c {shlex.quote(exec_b64)}"
        stdin = stdout = stderr = None
        try:
            stdin, stdout, stderr = ssh_client.exec_command(f"sh -c {shlex.quote(cmd)}", timeout=timeout, get_pty=True)
            out = stdout.read() if stdout else b''
            err = stderr.read() if stderr else b''
            rc = stdout.channel.recv_exit_status() if (stdout and hasattr(stdout, 'channel')) else 0
            out_text = out.decode('utf-8', 'ignore') if isinstance(out, (bytes, bytearray)) else str(out or '')
            _err_text = err.decode('utf-8', 'ignore') if isinstance(err, (bytes, bytearray)) else str(err or '')
            if rc == 0 and '::SERVICENAMES::' in out_text:
                break
        except Exception:
            continue
        finally:
            _close_ssh_command_streams(stdin, stdout, stderr)
    marker = '::SERVICENAMES::'
    payload = ''
    for line in (out_text or '').splitlines():
        if marker in line:
            payload = line.split(marker, 1)[1].strip()
    if not payload:
        return set()
    try:
        decoded = json.loads(payload)
    except Exception:
        return set()
    if isinstance(decoded, dict):
        arr = decoded.get('names') or []
    else:
        arr = decoded
    return {str(x).strip() for x in (arr or []) if str(x).strip()}


def _ensure_remote_core_daemon_ready(
    client: Any,
    *,
    core_cfg: Dict[str, Any],
    auto_start_allowed: bool,
    sudo_password: str | None,
    prefer_managed_service: bool = False,
    logger: logging.Logger,
    log_handle: Optional[TextIO] = None,
    log_prefix: str = '[remote] ',
) -> int:
    """Verify that exactly one core-daemon process is running, auto-starting if permitted."""

    def _parse_pid_tokens(text: str) -> List[int]:
        pids: List[int] = []
        for token in str(text or '').strip().split():
            try:
                value = int(token)
            except Exception:
                continue
            if value > 0:
                pids.append(value)
        return pids

    def _run_ready_probe(label: str, command: str, *, timeout: float = 15.0) -> tuple[int, str, str]:
        code, out, err = _exec_ssh_command(client, command, timeout=timeout)
        if log_handle:
            try:
                log_handle.write(
                    f"{log_prefix}{label}: {command} -> exit={code} stdout={(out or '').strip()} stderr={(err or '').strip()}\n"
                )
            except Exception:
                pass
        return code, out, err

    def _probe_managed_daemon_identity(pid: int, stage: str) -> tuple[Optional[int], str, Optional[str]]:
        main_pid: Optional[int] = None
        service_state = ''
        owner: Optional[str] = None

        try:
            _code, out_mainpid, _err = _run_ready_probe(
                f'{stage}.systemctl.mainpid',
                'sh -c "timeout 8s systemctl show -p MainPID --value core-daemon 2>/dev/null || true"',
            )
            for token in str(out_mainpid or '').strip().split():
                try:
                    value = int(token)
                except Exception:
                    continue
                if value > 0:
                    main_pid = value
                    break
        except Exception:
            main_pid = None

        try:
            _code, out_active, _err = _run_ready_probe(
                f'{stage}.systemctl.is-active',
                'sh -c "timeout 8s systemctl is-active core-daemon 2>/dev/null || true"',
            )
            service_state = str(out_active or '').strip().lower()
        except Exception:
            service_state = ''

        try:
            _code, out_owner, _err = _run_ready_probe(
                f'{stage}.ps.owner',
                f"sh -c \"timeout 8s ps -o user= -p {int(pid)} 2>/dev/null || true\"",
            )
            owner = str(out_owner or '').strip() or None
        except Exception:
            owner = None

        return main_pid, service_state, owner

    def _ensure_managed_single_daemon(pid: int, stage: str) -> int:
        if not prefer_managed_service:
            return pid

        main_pid, service_state, owner = _probe_managed_daemon_identity(pid, stage)
        owner_l = str(owner or '').strip().lower()
        service_known = service_state in {'active', 'inactive', 'failed', 'activating', 'deactivating'}
        managed = (
            service_state == 'active'
            and (main_pid is None or main_pid == pid)
            and (not owner_l or owner_l == 'root')
        )
        if managed:
            return pid

        # If we cannot determine systemd state and the owner is not explicitly suspicious,
        # avoid breaking non-systemd/manual environments.
        if not service_known and owner_l in {'', 'root'}:
            return pid

        reasons: List[str] = []
        if service_state and service_state != 'active':
            reasons.append(f'systemctl state={service_state}')
        if main_pid is not None and main_pid != pid:
            reasons.append(f'systemctl MainPID={main_pid}')
        if owner_l and owner_l != 'root':
            reasons.append(f'owner={owner_l}')
        reason_text = ', '.join(reasons) or 'unmanaged core-daemon'

        if not sudo_password:
            raise CoreDaemonMissingError(
                f'core-daemon PID {pid} is not the managed system service ({reason_text}); provide an SSH password so Execute can replace it with the system service.',
                can_auto_start=False,
                start_command=CORE_DAEMON_START_COMMAND,
            )

        if log_handle:
            try:
                log_handle.write(
                    f"{log_prefix}{stage}: replacing unmanaged core-daemon PID {pid} ({reason_text}) with the system service\n"
                )
            except Exception:
                pass

        try:
            _stop_remote_core_daemon_conflict(
                client,
                sudo_password=sudo_password,
                pids=[pid],
                logger=logger,
            )
        except Exception as exc:
            raise CoreDaemonMissingError(
                f'Failed replacing unmanaged core-daemon PID {pid} with the system service: {exc}',
                can_auto_start=False,
                start_command=CORE_DAEMON_START_COMMAND,
            ) from exc

        replacement_pids = _collect_remote_core_daemon_pids(
            client,
            log_handle=log_handle,
            log_prefix=log_prefix,
            stage=f'{stage}.managed-recheck.pgrep',
        )
        _log_daemon_probe(f'{stage}.managed-recheck', 0, replacement_pids)
        if len(replacement_pids) > 1:
            raise CoreDaemonConflictError(
                'Multiple core-daemon processes are running on the CORE VM.',
                pids=replacement_pids,
            )
        if len(replacement_pids) != 1:
            raise CoreDaemonMissingError(
                'core-daemon replacement did not stabilize within the expected time.',
                can_auto_start=False,
                start_command=CORE_DAEMON_START_COMMAND,
            )

        replacement_pid = replacement_pids[0]
        rep_main_pid, rep_service_state, rep_owner = _probe_managed_daemon_identity(
            replacement_pid,
            f'{stage}.managed-recheck',
        )
        rep_owner_l = str(rep_owner or '').strip().lower()
        if (
            rep_service_state == 'active'
            and (rep_main_pid is None or rep_main_pid == replacement_pid)
            and (not rep_owner_l or rep_owner_l == 'root')
        ):
            return replacement_pid

        rep_reasons: List[str] = []
        if rep_service_state and rep_service_state != 'active':
            rep_reasons.append(f'systemctl state={rep_service_state}')
        if rep_main_pid is not None and rep_main_pid != replacement_pid:
            rep_reasons.append(f'systemctl MainPID={rep_main_pid}')
        if rep_owner_l and rep_owner_l != 'root':
            rep_reasons.append(f'owner={rep_owner_l}')
        rep_reason_text = ', '.join(rep_reasons) or 'unmanaged core-daemon'
        raise CoreDaemonMissingError(
            f'core-daemon replacement completed, but the active daemon is still not a managed root-owned service ({rep_reason_text}).',
            can_auto_start=False,
            start_command=CORE_DAEMON_START_COMMAND,
        )

    def _fallback_detect_existing_daemon() -> tuple[Optional[int], bool]:
        observed: set[int] = set()
        sudo_wrapper_pids: set[int] = set()
        daemon_active = False
        daemon_port_listening = False
        port_value = core_cfg.get('port') or CORE_PORT
        try:
            grpc_port = int(str(port_value).strip())
        except Exception:
            grpc_port = int(CORE_PORT)

        def _run_probe(label: str, command: str) -> tuple[int, str, str]:
            code, out, err = _exec_ssh_command(client, command, timeout=15.0)
            if log_handle:
                try:
                    log_handle.write(
                        f"{log_prefix}{label}: {command} -> exit={code} stdout={(out or '').strip()} stderr={(err or '').strip()}\n"
                    )
                except Exception:
                    pass
            return code, out, err

        try:
            _code, out_mainpid, _err = _run_probe(
                'fallback.systemctl.mainpid',
                'sh -c "timeout 8s systemctl show -p MainPID --value core-daemon 2>/dev/null || true"',
            )
            observed.update(_parse_pid_tokens(out_mainpid))
        except Exception:
            pass

        try:
            _code, out_pidof, _err = _run_probe(
                'fallback.pidof',
                "sh -c 'timeout 5s pidof core-daemon 2>/dev/null || true'",
            )
            observed.update(_parse_pid_tokens(out_pidof))
        except Exception:
            pass

        try:
            _code, out_pgrep_full, _err = _run_probe(
                'fallback.pgrep.full',
                "sh -c 'timeout 5s pgrep -fa core-daemon 2>/dev/null || true'",
            )
            for line in str(out_pgrep_full or '').splitlines():
                text = line.strip()
                if not text:
                    continue
                parts = text.split(None, 1)
                if not parts or not parts[0].isdigit():
                    continue
                lower = text.lower()
                if 'pgrep -fa core-daemon' in lower:
                    continue
                cmd = parts[1].strip().lower() if len(parts) > 1 else ''
                pid_value = int(parts[0])
                if cmd.startswith('sudo ') or '/sudo ' in cmd:
                    sudo_wrapper_pids.add(pid_value)
                    continue
                if re.search(r'(^|\s|/)core-daemon(\s|$)', cmd):
                    observed.add(pid_value)
        except Exception:
            pass

        try:
            code_active, out_active, _err = _run_probe(
                'fallback.systemctl.is-active',
                'sh -c "timeout 8s systemctl is-active core-daemon 2>/dev/null || true"',
            )
            daemon_active = str(out_active or '').strip() == 'active'
        except Exception:
            pass

        try:
            _code, out_ss, _err = _run_probe(
                'fallback.port.listen',
                f"sh -c \"timeout 5s ss -ltn 2>/dev/null | awk '\\$4 ~ /:{grpc_port}$/ {{print}}' || true\"",
            )
            daemon_port_listening = bool(str(out_ss or '').strip())
        except Exception:
            pass

        pids = sorted(observed)
        wrapper_pids = sorted(sudo_wrapper_pids)
        if len(pids) > 1:
            raise CoreDaemonConflictError(
                'Multiple core-daemon processes are running on the CORE VM.',
                pids=pids,
            )
        if len(pids) == 0 and len(wrapper_pids) > 1:
            raise CoreDaemonConflictError(
                'Multiple core-daemon processes are running on the CORE VM.',
                pids=wrapper_pids,
            )
        if len(pids) == 1:
            return pids[0], (daemon_active or daemon_port_listening)
        if len(wrapper_pids) == 1:
            return wrapper_pids[0], True
        return None, (daemon_active or daemon_port_listening)

    def _log_daemon_probe(stage: str, attempt_idx: int, pids: List[int]) -> None:
        if not log_handle:
            return
        if pids:
            pid_text = ', '.join(str(pid) for pid in pids)
            summary = f'PID(s) {pid_text}'
        else:
            summary = 'no process found'
        try:
            log_handle.write(f"{log_prefix}{stage} probe {attempt_idx + 1}: {summary}\n")
            _write_sse_marker(
                log_handle,
                'phase',
                {
                    'stage': f'core-daemon.{stage}.probe',
                    'attempt': attempt_idx + 1,
                    'pids': pids,
                    'summary': summary,
                },
            )
        except Exception:
            pass

    def _attempt_conflict_auto_heal(conflict_pids: List[int], stage: str) -> Optional[int]:
        unique = sorted({int(pid) for pid in conflict_pids if str(pid).strip().isdigit() and int(pid) > 0})
        if len(unique) <= 1:
            return unique[0] if unique else None
        if not sudo_password:
            raise CoreDaemonConflictError(
                'Multiple core-daemon processes are running on the CORE VM.',
                pids=unique,
            )
        if log_handle:
            try:
                log_handle.write(
                    f"{log_prefix}{stage}: detected duplicate core-daemon PIDs ({', '.join(str(pid) for pid in unique)}); attempting automatic cleanup\n"
                )
            except Exception:
                pass
        try:
            repair_result = _stop_remote_core_daemon_conflict(
                client,
                sudo_password=sudo_password,
                pids=unique,
                logger=logger,
            )
        except Exception as exc:
            raise CoreDaemonConflictError(
                f'Multiple core-daemon processes are running on the CORE VM, and automatic cleanup failed: {exc}',
                pids=unique,
            ) from exc
        if log_handle:
            try:
                log_handle.write(
                    f"{log_prefix}{stage}: automatic cleanup status={repair_result.get('status')} preserved_main_pid={repair_result.get('preserved_main_pid')} kill_targets={repair_result.get('kill_targets')}\n"
                )
            except Exception:
                pass
        try:
            time.sleep(1.0)
        except Exception:
            pass
        healed_pids = _collect_remote_core_daemon_pids(
            client,
            log_handle=log_handle,
            log_prefix=log_prefix,
            stage=f'{stage}.post-heal.pgrep',
        )
        _log_daemon_probe(f'{stage}.post-heal', 0, healed_pids)
        if len(healed_pids) > 1:
            raise CoreDaemonConflictError(
                'Multiple core-daemon processes are still running on the CORE VM after automatic cleanup.',
                pids=healed_pids,
            )
        if len(healed_pids) == 1:
            if log_handle:
                try:
                    _write_sse_marker(
                        log_handle,
                        'phase',
                        {
                            'stage': 'core-daemon.ready',
                            'pid': healed_pids[0],
                            'source': f'{stage}.auto-heal',
                        },
                    )
                except Exception:
                    pass
            return healed_pids[0]
        return None

    def _poll_for_single_daemon(max_attempts: int, delay: float, stage: str) -> Optional[int]:
        last_pids: List[int] = []
        for attempt in range(max(1, max_attempts)):
            if log_handle:
                try:
                    log_handle.write(f"{log_prefix}{stage}: checking for core-daemon (attempt {attempt + 1}/{max(1, max_attempts)})\n")
                    _write_sse_marker(
                        log_handle,
                        'phase',
                        {
                            'stage': f'core-daemon.{stage}.poll',
                            'attempt': attempt + 1,
                            'max_attempts': max(1, max_attempts),
                        },
                    )
                except Exception:
                    pass
            poll_pids = _collect_remote_core_daemon_pids(
                client,
                log_handle=log_handle,
                log_prefix=log_prefix,
                stage=f"{stage}.pgrep",
            )
            _log_daemon_probe(stage, attempt, poll_pids)
            last_pids = poll_pids
            if len(poll_pids) > 1:
                healed = _attempt_conflict_auto_heal(poll_pids, stage)
                if healed is not None:
                    return healed
                poll_pids = _collect_remote_core_daemon_pids(
                    client,
                    log_handle=log_handle,
                    log_prefix=log_prefix,
                    stage=f'{stage}.recheck.pgrep',
                )
                _log_daemon_probe(f'{stage}.recheck', attempt, poll_pids)
                last_pids = poll_pids
                if len(poll_pids) > 1:
                    raise CoreDaemonConflictError(
                        'Multiple core-daemon processes are running on the CORE VM.',
                        pids=poll_pids,
                    )
            if len(poll_pids) == 1:
                ready_pid = _ensure_managed_single_daemon(poll_pids[0], stage)
                if log_handle:
                    try:
                        _write_sse_marker(
                            log_handle,
                            'phase',
                            {
                                'stage': 'core-daemon.ready',
                                'pid': ready_pid,
                                'source': stage,
                            },
                        )
                    except Exception:
                        pass
                return ready_pid
            if attempt < max_attempts - 1:
                try:
                    time.sleep(delay)
                except Exception:
                    pass
        return None

    pid = _poll_for_single_daemon(max_attempts=1, delay=0.5, stage='initial')
    if pid is not None:
        if log_handle:
            try:
                log_handle.write(f"{log_prefix}core-daemon already running (PID {pid})\n")
            except Exception:
                pass
        return pid

    try:
        fallback_pid, daemon_active = _fallback_detect_existing_daemon()
    except CoreDaemonConflictError as exc:
        healed = _attempt_conflict_auto_heal(exc.pids, 'fallback')
        if healed is not None:
            return healed
        fallback_pid, daemon_active = _fallback_detect_existing_daemon()
    if fallback_pid is not None:
        fallback_pid = _ensure_managed_single_daemon(fallback_pid, 'fallback')
        if log_handle:
            try:
                log_handle.write(f"{log_prefix}core-daemon detected via fallback probe (PID {fallback_pid})\n")
            except Exception:
                pass
        return fallback_pid

    if daemon_active:
        raise CoreDaemonMissingError(
            'core-daemon appears active on the CORE VM, but PID discovery was inconclusive; refusing auto-start to avoid duplicate daemons.',
            can_auto_start=False,
            start_command=CORE_DAEMON_START_COMMAND,
        )

    if not auto_start_allowed:
        raise CoreDaemonMissingError(
            'core-daemon is not running on the CORE VM.',
            can_auto_start=True,
            start_command=CORE_DAEMON_START_COMMAND,
        )
    exit_code = -1
    stdout_text = ''
    stderr_text = ''
    try:
        try:
            logger.info('[core] Auto-starting core-daemon via `%s`', CORE_DAEMON_START_COMMAND)
        except Exception:
            pass
        if log_handle:
            try:
                log_handle.write(
                    f"{log_prefix}core-daemon not detected; attempting auto-start with command: {CORE_DAEMON_START_COMMAND}\n"
                )
                if not sudo_password:
                    log_handle.write(
                        f"{log_prefix}NOTE: No SSH sudo password provided; using non-interactive sudo (-n). If sudo requires a password, auto-start will fail quickly instead of hanging.\n"
                    )
            except Exception:
                pass
        try:
            logger.info('[core] auto-starting core-daemon via `%s`', CORE_DAEMON_START_COMMAND)
        except Exception:
            pass
        exit_code, stdout_text, stderr_text = _start_remote_core_daemon(client, sudo_password, logger)
        # If sudo cannot run non-interactively, fail fast with a clear message.
        if exit_code != 0 and not sudo_password:
            err_lower = (stderr_text or '').lower()
            if 'password' in err_lower or 'sudo' in err_lower:
                raise CoreDaemonMissingError(
                    'core-daemon auto-start failed: sudo requires a password (none provided).',
                    can_auto_start=False,
                    start_command=CORE_DAEMON_START_COMMAND,
                )
        if log_handle:
            try:
                log_handle.write(
                    f"{log_prefix}core-daemon auto-start command '{CORE_DAEMON_START_COMMAND}' exit={exit_code} stdout={stdout_text.strip()} stderr={stderr_text.strip()}\n"
                )
                _write_sse_marker(
                    log_handle,
                    'phase',
                    {
                        'stage': 'core-daemon.start',
                        'kind': 'ssh',
                        'command': CORE_DAEMON_START_COMMAND,
                        'exit': exit_code,
                        'stdout': (stdout_text or '').strip()[:1500],
                        'stderr': (stderr_text or '').strip()[:1500],
                    },
                )
            except Exception:
                pass
    except Exception as exc:
        raise CoreDaemonMissingError(
            f'core-daemon auto-start failed: {exc}',
            can_auto_start=False,
            start_command=CORE_DAEMON_START_COMMAND,
        ) from exc
    try:
        status_cmd = 'sh -c "timeout 10s systemctl is-active core-daemon"'
        status_code, status_out, status_err = _exec_ssh_command(client, status_cmd, timeout=15.0)
        if log_handle:
            try:
                log_handle.write(
                    f"{log_prefix}{status_cmd} -> exit={status_code} stdout={status_out.strip()} stderr={status_err.strip()}\n"
                )
                _write_sse_marker(
                    log_handle,
                    'phase',
                    {
                        'stage': 'core-daemon.systemctl.is-active',
                        'kind': 'ssh',
                        'command': status_cmd,
                        'exit': status_code,
                        'stdout': (status_out or '').strip()[:1500],
                        'stderr': (status_err or '').strip()[:1500],
                    },
                )
            except Exception:
                pass
        # Capture a small amount of extra detail for operator visibility.
        if log_handle:
            try:
                status_detail_cmd = "sh -c \"timeout 15s systemctl status core-daemon --no-pager -l | tail -n 40\""
                detail_code, detail_out, detail_err = _exec_ssh_command(client, status_detail_cmd, timeout=20.0)
                out_clean = (detail_out or '').rstrip()
                err_clean = (detail_err or '').rstrip()
                log_handle.write(
                    f"{log_prefix}{status_detail_cmd} -> exit={detail_code}\n"
                )
                if out_clean:
                    log_handle.write(f"{log_prefix}systemctl status (tail)\n{out_clean}\n")
                if err_clean:
                    log_handle.write(f"{log_prefix}systemctl status stderr\n{err_clean}\n")
                _write_sse_marker(
                    log_handle,
                    'phase',
                    {
                        'stage': 'core-daemon.systemctl.status',
                        'kind': 'ssh',
                        'command': status_detail_cmd,
                        'exit': detail_code,
                        'stdout': out_clean[:2500] if out_clean else '',
                        'stderr': err_clean[:1500] if err_clean else '',
                    },
                )
            except Exception:
                pass
        if exit_code != 0 and log_handle:
            try:
                journal_cmd = "sh -c \"timeout 15s journalctl -u core-daemon -n 40 --no-pager || true\""
                j_code, j_out, j_err = _exec_ssh_command(client, journal_cmd, timeout=20.0)
                out_clean = (j_out or '').rstrip()
                err_clean = (j_err or '').rstrip()
                log_handle.write(f"{log_prefix}{journal_cmd} -> exit={j_code}\n")
                if out_clean:
                    log_handle.write(f"{log_prefix}journalctl (tail)\n{out_clean}\n")
                if err_clean:
                    log_handle.write(f"{log_prefix}journalctl stderr\n{err_clean}\n")
                _write_sse_marker(
                    log_handle,
                    'phase',
                    {
                        'stage': 'core-daemon.journalctl',
                        'kind': 'ssh',
                        'command': journal_cmd,
                        'exit': j_code,
                        'stdout': out_clean[:2500] if out_clean else '',
                        'stderr': err_clean[:1500] if err_clean else '',
                    },
                )
            except Exception:
                pass
    except Exception:
        pass
    pid = _poll_for_single_daemon(max_attempts=10, delay=0.5, stage='post-start')
    if pid is not None:
        return pid
    raise CoreDaemonMissingError(
        'core-daemon auto-start did not stabilize within the expected time.',
        can_auto_start=False,
        start_command=CORE_DAEMON_START_COMMAND,
    )


def _check_remote_daemon_before_setup(
    client: Any,
    *,
    core_cfg: Dict[str, Any],
    auto_start_allowed: bool,
    log_handle: Optional[TextIO],
    log_prefix: str,
) -> int:
    logger = getattr(app, 'logger', logging.getLogger(__name__))
    pid = _ensure_remote_core_daemon_ready(
        client=client,
        core_cfg=core_cfg,
        auto_start_allowed=auto_start_allowed,
        sudo_password=core_cfg.get('ssh_password'),
        prefer_managed_service=True,
        logger=logger,
        log_handle=log_handle,
        log_prefix=log_prefix,
    )
    if log_handle:
        try:
            log_handle.write(f"{log_prefix}core-daemon PID {pid} confirmed before run setup\n")
        except Exception:
            pass
    return pid

def _execute_remote_core_session_action(
    core_cfg: Dict[str, Any],
    action: str,
    session_id: int,
    *,
    logger: logging.Logger,
    meta: Optional[Dict[str, Any]] = None,
) -> Dict[str, Any]:
    cfg = _normalize_core_config(core_cfg, include_password=True)
    ssh_user = (cfg.get('ssh_username') or '').strip() or '<unknown>'
    ssh_host = cfg.get('ssh_host') or cfg.get('host') or 'localhost'
    remote_target_host = _remote_core_target_host(cfg)
    address = f"{remote_target_host}:{cfg.get('port') or CORE_PORT}"
    script = _remote_core_session_action_script(address, action, session_id)
    command_desc = (
        f"remote ssh {ssh_user}@{ssh_host} -> CoreGrpcClient.{action}_session {address} (session={session_id})"
    )
    payload = _run_remote_python_json(
        cfg,
        script,
        logger=logger,
        label=f'core.{action}_session',
        meta=meta,
        command_desc=command_desc,
        timeout=120.0,
    )
    error_text = payload.get('error')
    if error_text:
        tb = payload.get('traceback')
        if tb:
            logger.debug('[core.%s_session] traceback: %s', action, tb)
        raise RuntimeError(error_text)
    return payload


def _list_active_core_sessions_via_remote_python(
    core_cfg: Dict[str, Any],
    *,
    errors: Optional[List[str]] = None,
    meta: Optional[Dict[str, Any]] = None,
    logger: Optional[logging.Logger] = None,
) -> list[dict]:
    cfg = _normalize_core_config(core_cfg, include_password=True)
    log = logger or getattr(app, 'logger', logging.getLogger(__name__))
    ssh_user = (cfg.get('ssh_username') or '').strip() or '<unknown>'
    ssh_host = cfg.get('ssh_host') or cfg.get('host') or 'localhost'
    target_host = _remote_core_target_host(cfg)
    try:
        target_port = int(cfg.get('port') or CORE_PORT)
    except Exception:
        target_port = CORE_PORT
    if meta is not None:
        meta['grpc_command'] = (
            f"remote ssh {ssh_user}@{ssh_host} -> CoreGrpcClient.get_sessions {target_host}:{target_port}"
        )
    address = f"{target_host}:{target_port}"
    script = _remote_core_sessions_script(address)
    command_desc = meta['grpc_command'] if meta and 'grpc_command' in meta else f'get_sessions {address}'
    try:
        payload = _run_remote_python_json(
            cfg,
            script,
            logger=log,
            label='core.get_sessions',
            meta=meta,
            command_desc=command_desc,
            timeout=120.0,
        )
    except Exception as exc:
        msg = f'Remote CORE session fetch failed: {exc}'
        log.warning('[core.grpc] %s', msg)
        if errors is not None:
            errors.append(msg)
        return []
    error_text = payload.get('error')
    if error_text:
        log.warning('[core.grpc] remote CORE session fetch error: %s', error_text)
        if errors is not None:
            errors.append(f'Remote CORE session fetch failed: {error_text}')
        tb = payload.get('traceback')
        if tb:
            log.debug('[core.grpc] remote traceback: %s', tb)
        return []
    sessions = payload.get('sessions') or []
    log.info('[core.grpc] remote returned %d session(s)', len(sessions))
    return sessions


def _exec_ssh_python_probe(client: Any, command: str, *, timeout: float) -> Tuple[int, str, str]:
    stdin, stdout, stderr = client.exec_command(command, timeout=timeout)
    try:
        stdout_data = stdout.read()
        stderr_data = stderr.read()
    finally:
        _close_ssh_command_streams(stdin, stdout, stderr)
    exit_code = stdout.channel.recv_exit_status() if hasattr(stdout, 'channel') else 0
    if isinstance(stdout_data, bytes):
        stdout_text = stdout_data.decode('utf-8', 'ignore')
    else:
        stdout_text = str(stdout_data)
    if isinstance(stderr_data, bytes):
        stderr_text = stderr_data.decode('utf-8', 'ignore')
    else:
        stderr_text = str(stderr_data)
    return exit_code, stdout_text, stderr_text


def _ensure_core_daemon_listening(core_cfg: Dict[str, Any], *, timeout: float = 5.0) -> None:
    cfg = _require_core_ssh_credentials(core_cfg)
    _ensure_paramiko_available()
    daemon_host = _remote_core_target_host(cfg)
    if daemon_host in {'0.0.0.0', '::', '::0', '[::]'}:
        daemon_host = '127.0.0.1'
    daemon_port = int(cfg.get('port') or CORE_PORT)
    ssh_host = str(cfg.get('ssh_host') or cfg.get('host') or 'localhost')
    ssh_port = int(cfg.get('ssh_port') or 22)
    username = str(cfg.get('ssh_username') or '').strip()
    password = cfg.get('ssh_password') or ''
    logger = getattr(app, 'logger', logging.getLogger(__name__))
    client = paramiko.SSHClient()  # type: ignore[assignment]
    client.set_missing_host_key_policy(paramiko.AutoAddPolicy())  # type: ignore[attr-defined]
    try:
        client.connect(
            hostname=ssh_host,
            port=ssh_port,
            username=username,
            password=password,
            look_for_keys=False,
            allow_agent=False,
            timeout=max(timeout, 5.0),
            banner_timeout=max(timeout, 5.0),
            auth_timeout=max(timeout, 5.0),
        )
        probe_errors: List[str] = []
        interpreter_candidates = _candidate_remote_python_interpreters(cfg)
        if not interpreter_candidates:
            interpreter_candidates = ['python3', 'python']
        for interpreter in interpreter_candidates:
            command = _build_python_probe_command(daemon_host, daemon_port, timeout, interpreter=interpreter)
            exit_code, stdout_text, stderr_text = _exec_ssh_python_probe(client, command, timeout=timeout + 2.0)
            stdout_clean = stdout_text.strip()
            stderr_clean = stderr_text.strip()
            combined = ' '.join(part for part in (stdout_clean, stderr_clean) if part).strip()
            if exit_code == 0 and 'OK' in stdout_clean:
                logger.info('[core] Verified core-daemon listening at %s:%s via %s', daemon_host, daemon_port, interpreter)
                return
            if not combined:
                combined = f'exit status {exit_code}'
            probe_errors.append(f'{interpreter}: {combined}')
            lower = combined.lower()
            if _is_core_daemon_socket_probe_failure(combined):
                raise RuntimeError(
                    f'core-daemon is not accepting gRPC connections on {daemon_host}:{daemon_port}. '
                    f'The Python probe ran via {interpreter}, but the daemon socket returned: {combined}. '
                    'Test Venv only verifies that the CORE Python modules import; Save & Validate also requires '
                    'a running core-daemon listening on the configured gRPC host/port. '
                    'Check the configured gRPC port and run `systemctl status core-daemon` on the CORE host.'
                )
            if 'not found' in lower or 'command not found' in lower:
                continue
        error_detail = _summarize_core_daemon_probe_errors(probe_errors)
        raise RuntimeError(f'core-daemon did not respond on {daemon_host}:{daemon_port} ({error_detail})')
    finally:
        try:
            client.close()
        except Exception:
            pass


def _run_core_connection_advanced_checks(
    cfg: Dict[str, Any],
    *,
    adv_fix_docker_daemon: bool = False,
    adv_run_core_cleanup: bool = False,
    adv_check_core_version: bool = False,
    adv_restart_core_daemon: bool = False,
    adv_start_core_daemon: bool = False,
    adv_auto_kill_sessions: bool = False,
) -> Dict[str, Dict[str, Any]]:
    """Run optional advanced checks against the CORE VM.

    These checks mirror the ones available in the Execute Scenario modal.
    Returns a dict keyed by adv_* flag names with shape:
      { enabled: bool, ok: bool|None, message: str }

    Notes:
    - This function is best-effort: when a check is enabled, it will attempt the action
      and report failure in its own result without raising (except for totally unexpected errors).
    - Some checks require sudo (SSH password). If missing, the check is marked failed.
    """

    results: Dict[str, Dict[str, Any]] = {}

    def _set(key: str, *, enabled: bool, ok: Optional[bool], message: str) -> None:
        results[key] = {
            'enabled': bool(enabled),
            'ok': ok,
            'message': str(message or '').strip(),
        }

    enabled_any = any(
        bool(v)
        for v in (
            adv_fix_docker_daemon,
            adv_run_core_cleanup,
            adv_check_core_version,
            adv_restart_core_daemon,
            adv_start_core_daemon,
            adv_auto_kill_sessions,
        )
    )
    if not enabled_any:
        # Keep keys present but disabled for stable UI.
        _set('adv_check_core_version', enabled=False, ok=None, message='')
        _set('adv_fix_docker_daemon', enabled=False, ok=None, message='')
        _set('adv_run_core_cleanup', enabled=False, ok=None, message='')
        _set('adv_restart_core_daemon', enabled=False, ok=None, message='')
        _set('adv_start_core_daemon', enabled=False, ok=None, message='')
        _set('adv_auto_kill_sessions', enabled=False, ok=None, message='')
        return results

    logger = getattr(app, 'logger', logging.getLogger(__name__))
    cfg = _normalize_core_config(cfg, include_password=True)
    if paramiko is None:
        # Can't run these without SSH.
        for key, enabled in (
            ('adv_check_core_version', adv_check_core_version),
            ('adv_fix_docker_daemon', adv_fix_docker_daemon),
            ('adv_run_core_cleanup', adv_run_core_cleanup),
            ('adv_restart_core_daemon', adv_restart_core_daemon),
            ('adv_start_core_daemon', adv_start_core_daemon),
            ('adv_auto_kill_sessions', adv_auto_kill_sessions),
        ):
            if enabled:
                _set(key, enabled=True, ok=False, message='Paramiko unavailable; cannot run this check.')
            else:
                _set(key, enabled=False, ok=None, message='')
        return results

    def _check_core_version(client: Any, required: str = '9.2.1') -> str:
        candidates = [
            "sh -c 'timeout 6s core-daemon --version 2>/dev/null || true'",
            "sh -c 'timeout 6s core-daemon -v 2>/dev/null || true'",
            "sh -c 'timeout 6s dpkg-query -W -f=\"${Version}\" core-daemon 2>/dev/null || true'",
            "sh -c 'timeout 6s rpm -q --qf \"%{VERSION}-%{RELEASE}\" core-daemon 2>/dev/null || true'",
            "sh -c 'timeout 6s core --version 2>/dev/null || true'",
        ]
        raw = ''
        for cmd in candidates:
            try:
                _code, out, err = _exec_ssh_command(client, cmd, timeout=12.0)
            except Exception:
                continue
            text = (out or '').strip() or (err or '').strip()
            if text:
                raw = text
                break
        if not raw:
            raise RuntimeError('Unable to determine CORE version on remote host')
        found = None
        try:
            m = re.search(r"(\d+\.\d+\.\d+)", raw)
            if m:
                found = m.group(1)
        except Exception:
            found = None
        if not found:
            raise RuntimeError(f'Unable to parse CORE version from: {raw}')
        if found != required:
            raise RuntimeError(f'CORE version mismatch: expected {required}, found {found}')
        return found

    def _sudo_exec(client: Any, cmd: str, *, timeout: float = 45.0) -> tuple[int, str, str]:
        sudo_password = cfg.get('ssh_password')
        # Wrap in timeout to avoid hanging.
        wrapped = f"sh -c 'timeout {int(max(5, timeout))}s {cmd}'"
        if sudo_password:
            sudo_cmd = f"sudo -S -p '' {wrapped}"
        else:
            sudo_cmd = f"sudo -n {wrapped}"
        stdin = stdout = stderr = None
        try:
            stdin, stdout, stderr = client.exec_command(sudo_cmd, timeout=timeout + 5.0, get_pty=True)
            if sudo_password:
                try:
                    stdin.write(str(sudo_password) + '\n')
                    stdin.flush()
                except Exception:
                    pass
            stdout_data = stdout.read() if stdout else b''
            stderr_data = stderr.read() if stderr else b''
            try:
                exit_code = stdout.channel.recv_exit_status() if (stdout and hasattr(stdout, 'channel')) else 0
            except Exception:
                exit_code = 0
            out_text = stdout_data.decode('utf-8', 'ignore') if isinstance(stdout_data, (bytes, bytearray)) else str(stdout_data or '')
            err_text = stderr_data.decode('utf-8', 'ignore') if isinstance(stderr_data, (bytes, bytearray)) else str(stderr_data or '')
            return exit_code, out_text, err_text
        finally:
            _close_ssh_command_streams(stdin, stdout, stderr)

    def _maybe_fix_docker_daemon(client: Any) -> None:
        desired = {'bridge': 'none', 'iptables': False}
        existing: dict[str, Any] = {}
        try:
            _code, out, _err = _exec_ssh_command(client, "sh -c 'timeout 5s cat /etc/docker/daemon.json 2>/dev/null || true'", timeout=10.0)
            text = (out or '').strip()
            if text:
                try:
                    existing = json.loads(text)
                except Exception:
                    existing = {}
        except Exception:
            existing = {}
        merged = dict(existing) if isinstance(existing, dict) else {}
        merged.update(desired)
        payload = json.dumps(merged, indent=2, sort_keys=True) + "\n"

        tmp_local = None
        remote_tmp = None
        try:
            import tempfile

            with tempfile.NamedTemporaryFile('w', delete=False, encoding='utf-8') as tf:
                tf.write(payload)
                tmp_local = tf.name
            remote_tmp = _upload_file_to_core_host(cfg, tmp_local, remote_dir='/tmp/scenarioforge/uploads')

            exit_code, _out, err = _sudo_exec(client, 'install -d -m 0755 /etc/docker', timeout=20.0)
            if exit_code != 0:
                err_lower = (err or '').lower()
                if (not cfg.get('ssh_password')) and ('password' in err_lower or 'sudo' in err_lower):
                    raise RuntimeError('Fix docker daemon failed: sudo requires a password (none provided).')
                raise RuntimeError('Fix docker daemon failed: could not create /etc/docker')
            exit_code, _out, err = _sudo_exec(client, f"install -m 0644 {shlex.quote(remote_tmp)} /etc/docker/daemon.json", timeout=25.0)
            if exit_code != 0:
                err_lower = (err or '').lower()
                if (not cfg.get('ssh_password')) and ('password' in err_lower or 'sudo' in err_lower):
                    raise RuntimeError('Fix docker daemon failed: sudo requires a password (none provided).')
                raise RuntimeError('Fix docker daemon failed: could not write /etc/docker/daemon.json')

            rc, _o, _e = _sudo_exec(client, 'systemctl restart docker || service docker restart || true', timeout=40.0)
            if rc != 0:
                raise RuntimeError('Fix docker daemon failed: docker restart did not succeed')
        finally:
            try:
                if tmp_local and os.path.exists(tmp_local):
                    os.remove(tmp_local)
            except Exception:
                pass
            try:
                if remote_tmp:
                    _remove_remote_file(cfg, remote_tmp)
            except Exception:
                pass

    def _maybe_core_cleanup(client: Any) -> None:
        # Prefer system-provided core-cleanup if available; otherwise do safe stale /tmp/pycore.* purge.
        try:
            _code, out, _err = _exec_ssh_command(client, "sh -c 'command -v core-cleanup >/dev/null 2>&1; echo $?'", timeout=10.0)
            has_core_cleanup = (out or '').strip() == '0'
        except Exception:
            has_core_cleanup = False
        if has_core_cleanup:
            exit_code, _out, err = _sudo_exec(client, 'core-cleanup', timeout=70.0)
            if exit_code != 0:
                err_lower = (err or '').lower()
                if (not cfg.get('ssh_password')) and ('password' in err_lower or 'sudo' in err_lower):
                    raise RuntimeError('core-cleanup failed: sudo requires a password (none provided).')
                raise RuntimeError('core-cleanup failed')
            return

        # Fallback: remove stale pycore directories not in active session ids.
        try:
            target_host = str(cfg.get('host') or CORE_HOST)
            target_port = int(cfg.get('port') or CORE_PORT)
        except Exception:
            target_host = str(cfg.get('host') or CORE_HOST)
            target_port = CORE_PORT
        try:
            sessions = _list_active_core_sessions(target_host, int(target_port), cfg, errors=[], meta={})
        except Exception:
            sessions = []
        active_ids: set[int] = set()
        for entry in sessions:
            try:
                sid = entry.get('id')
                if sid is None:
                    continue
                active_ids.add(int(str(sid).strip()))
            except Exception:
                continue
        active_json = json.dumps(sorted(active_ids))
        cleanup_cmd = (
            "python3 - <<'PY'\n"
            "import os, json, glob, shutil, time\n"
            "active=set(json.loads(os.environ.get('ACTIVE_IDS','[]')))\n"
            "removed=[]\nkept=[]\nnow=time.time()\n"
            "for p in glob.glob('/tmp/pycore.*'):\n"
            "  base=os.path.basename(p)\n"
            "  try: sid=int(base.split('.')[-1])\n"
            "  except Exception: kept.append(p); continue\n"
            "  if sid in active: kept.append(p); continue\n"
            "  try: age=now-os.stat(p).st_mtime\n"
            "  except Exception: age=999\n"
            "  if age < 30: kept.append(p); continue\n"
            "  try: shutil.rmtree(p); removed.append(p)\n"
            "  except Exception: kept.append(p)\n"
            "print(json.dumps({'removed':removed,'kept':kept,'active_session_ids':sorted(active)}))\n"
            "PY"
        )
        shell_cmd = f"ACTIVE_IDS={shlex.quote(active_json)} {cleanup_cmd}"
        _exec_ssh_command(client, f"sh -c {shlex.quote(shell_cmd)}", timeout=30.0)

    def _maybe_restart_core_daemon(client: Any) -> None:
        pre_pids = _collect_remote_core_daemon_pids(client)
        if len(pre_pids) > 1:
            raise RuntimeError(
                'Multiple core-daemon processes are already running: '
                + ', '.join(str(pid) for pid in pre_pids)
                + '. Stop duplicates before restarting.'
            )
        exit_code, _out, err = _sudo_exec(client, 'systemctl restart core-daemon', timeout=35.0)
        if exit_code != 0:
            err_lower = (err or '').lower()
            if (not cfg.get('ssh_password')) and ('password' in err_lower or 'sudo' in err_lower):
                raise RuntimeError('Restart core-daemon failed: sudo requires a password (none provided).')
            raise RuntimeError('Restart core-daemon failed')
        post_pids = _collect_remote_core_daemon_pids(client)
        if len(post_pids) > 1:
            raise RuntimeError(
                'Restart left multiple core-daemon processes running: '
                + ', '.join(str(pid) for pid in post_pids)
                + '. Stop duplicates and retry.'
            )

    def _maybe_start_core_daemon(client: Any) -> str:
        """Try starting core-daemon if not running. Returns status message."""
        running_pids = _collect_remote_core_daemon_pids(client)
        if len(running_pids) > 1:
            raise RuntimeError(
                'Multiple core-daemon processes are already running: '
                + ', '.join(str(pid) for pid in running_pids)
                + '. Stop duplicates before starting.'
            )
        if len(running_pids) == 1:
            return f'already running (PID {running_pids[0]})'

        # Fallback check via systemctl in case PID discovery is unavailable.
        exit_code, out, _err = _sudo_exec(client, 'systemctl is-active core-daemon', timeout=15.0)
        if exit_code == 0 and (out or '').strip().lower() == 'active':
            return 'already running'
        
        # Try to start it
        exit_code, _out, err = _sudo_exec(client, 'systemctl start core-daemon', timeout=35.0)
        if exit_code != 0:
            err_lower = (err or '').lower()
            if (not cfg.get('ssh_password')) and ('password' in err_lower or 'sudo' in err_lower):
                raise RuntimeError('Start core-daemon failed: sudo requires a password (none provided).')
            raise RuntimeError(f'Start core-daemon failed: {err or "unknown error"}')
        
        # Verify it started
        exit_code, out, _err = _sudo_exec(client, 'systemctl is-active core-daemon', timeout=15.0)
        if exit_code == 0 and (out or '').strip().lower() == 'active':
            post_pids = _collect_remote_core_daemon_pids(client)
            if len(post_pids) > 1:
                raise RuntimeError(
                    'Start left multiple core-daemon processes running: '
                    + ', '.join(str(pid) for pid in post_pids)
                    + '. Stop duplicates and retry.'
                )
            if len(post_pids) == 1:
                return f'started successfully (PID {post_pids[0]})'
            return 'started successfully'
        return 'start attempted, status unclear'

    def _maybe_kill_active_sessions() -> tuple[list[int], list[str]]:
        deleted: list[int] = []
        errors: list[str] = []
        try:
            target_host = str(cfg.get('host') or CORE_HOST)
            target_port = int(cfg.get('port') or CORE_PORT)
        except Exception:
            target_host = str(cfg.get('host') or CORE_HOST)
            target_port = CORE_PORT
        try:
            sessions = _list_active_core_sessions(target_host, int(target_port), cfg, errors=[], meta={})
        except Exception as exc:
            errors.append(f"Failed listing active CORE sessions: {exc}")
            return deleted, errors
        ids: list[int] = []
        for entry in sessions:
            sid = entry.get('id')
            if sid in (None, ''):
                continue
            try:
                ids.append(int(str(sid).strip()))
            except Exception:
                continue
        seen: set[int] = set()
        ordered: list[int] = []
        for sid in ids:
            if sid in seen:
                continue
            seen.add(sid)
            ordered.append(sid)
        for sid in ordered:
            try:
                _execute_remote_core_session_action(cfg, 'delete', sid, logger=logger)
                deleted.append(sid)
            except Exception as exc:
                errors.append(f"Failed deleting session {sid}: {exc}")
        return deleted, errors

    _ensure_paramiko_available()
    client = paramiko.SSHClient()  # type: ignore[assignment]
    client.set_missing_host_key_policy(paramiko.AutoAddPolicy())  # type: ignore[attr-defined]
    try:
        client.connect(
            hostname=str(cfg.get('ssh_host') or cfg.get('host') or 'localhost'),
            port=int(cfg.get('ssh_port') or 22),
            username=str(cfg.get('ssh_username') or ''),
            password=cfg.get('ssh_password') or '',
            look_for_keys=False,
            allow_agent=False,
            timeout=15.0,
            banner_timeout=15.0,
            auth_timeout=15.0,
        )

        if adv_start_core_daemon:
            try:
                status_msg = _maybe_start_core_daemon(client)
                _set('adv_start_core_daemon', enabled=True, ok=True, message=status_msg)
            except Exception as exc:
                _set('adv_start_core_daemon', enabled=True, ok=False, message=str(exc))
        else:
            _set('adv_start_core_daemon', enabled=False, ok=None, message='')

        if adv_check_core_version:
            try:
                ver = _check_core_version(client, '9.2.1')
                _set('adv_check_core_version', enabled=True, ok=True, message=f'found {ver}')
            except Exception as exc:
                _set('adv_check_core_version', enabled=True, ok=False, message=str(exc))
        else:
            _set('adv_check_core_version', enabled=False, ok=None, message='')

        if adv_fix_docker_daemon:
            try:
                _maybe_fix_docker_daemon(client)
                _set('adv_fix_docker_daemon', enabled=True, ok=True, message='applied /etc/docker/daemon.json and restarted docker')
            except Exception as exc:
                _set('adv_fix_docker_daemon', enabled=True, ok=False, message=str(exc))
        else:
            _set('adv_fix_docker_daemon', enabled=False, ok=None, message='')

        if adv_run_core_cleanup:
            try:
                _maybe_core_cleanup(client)
                _set('adv_run_core_cleanup', enabled=True, ok=True, message='completed')
            except Exception as exc:
                _set('adv_run_core_cleanup', enabled=True, ok=False, message=str(exc))
        else:
            _set('adv_run_core_cleanup', enabled=False, ok=None, message='')

        if adv_restart_core_daemon:
            try:
                _maybe_restart_core_daemon(client)
                _set('adv_restart_core_daemon', enabled=True, ok=True, message='requested')
            except Exception as exc:
                _set('adv_restart_core_daemon', enabled=True, ok=False, message=str(exc))
        else:
            _set('adv_restart_core_daemon', enabled=False, ok=None, message='')

    finally:
        try:
            client.close()
        except Exception:
            pass

    # Auto-kill sessions is done via gRPC calls (remote python) and does not require an open SSHClient.
    if adv_auto_kill_sessions:
        try:
            deleted, errs = _maybe_kill_active_sessions()
            if errs:
                _set('adv_auto_kill_sessions', enabled=True, ok=False, message='; '.join(errs)[:500])
            else:
                detail = f"deleted {len(deleted)} session(s)" if deleted else 'no sessions deleted'
                _set('adv_auto_kill_sessions', enabled=True, ok=True, message=detail)
        except Exception as exc:
            _set('adv_auto_kill_sessions', enabled=True, ok=False, message=str(exc))
    else:
        _set('adv_auto_kill_sessions', enabled=False, ok=None, message='')

    return results


def _normalize_hitl_attachment(raw_value: Any) -> str:
    if isinstance(raw_value, str):
        candidate = raw_value.strip()
        if candidate in _HITL_ATTACHMENT_ALLOWED:
            return candidate
        normalized = candidate.lower().replace('-', '_').replace(' ', '_')
        if normalized in _HITL_ATTACHMENT_ALLOWED:
            return normalized
        synonyms = {
            "router": "existing_router",
            "existing": "existing_router",
            "existingrouter": "existing_router",
            "existing_router": "existing_router",
            "existing-switch": "existing_switch",
            "existing switch": "existing_switch",
            "existing_switch": "existing_switch",
            "switch": "existing_switch",
            "newrouter": "new_router",
            "new_router": "new_router",
            "new router": "new_router",
            "router_new": "new_router",
            "proxmox_vm": "proxmox_vm",
            "proxmoxvm": "proxmox_vm",
            "proxmox-vm": "proxmox_vm",
            "proxmox vm": "proxmox_vm",
            "vm": "proxmox_vm",
            "external_vm": "proxmox_vm",
            "externalvm": "proxmox_vm",
        }
        if normalized in synonyms:
            return synonyms[normalized]
    return _DEFAULT_HITL_ATTACHMENT


def _normalize_hitl_interface_name(raw_value: Any) -> str:
    """Strip any legacy hitl- prefix so CORE sees the raw device name."""
    if isinstance(raw_value, str):
        candidate = raw_value.strip()
    elif raw_value is None:
        candidate = ''
    else:
        candidate = str(raw_value).strip()
    if not candidate:
        return ''
    prefix = 'hitl-'
    if candidate.lower().startswith(prefix):
        return candidate[len(prefix):]
    return candidate


def _slugify_hitl_name(raw_value: Any, fallback: str) -> str:
    value = ''
    if isinstance(raw_value, str):
        value = raw_value.strip().lower()
    elif raw_value is not None:
        value = str(raw_value).strip().lower()
    if not value:
        value = fallback.lower()
    cleaned = []
    for ch in value:
        if ch.isalnum():
            cleaned.append(ch)
        elif ch in {'-', '_'}:
            cleaned.append(ch)
        else:
            cleaned.append('-')
    slug = ''.join(cleaned).strip('-_')
    if not slug:
        slug = fallback.lower().strip('-_') or 'iface'
    return slug[:48]


def _stable_hitl_preview_router_id(scenario_key: str, slug: str, idx: int) -> int:
    key = f"hitl-router|{scenario_key or '__default__'}|{slug}|{idx}"
    digest = hashlib.sha256(key.encode('utf-8', 'replace')).hexdigest()
    return 700_000 + (int(digest[:10], 16) % 200_000)


def _build_hitl_preview_router(
    scenario_key: str,
    iface: Dict[str, Any],
    slug: str,
    ordinal: int,
    ip_info: Dict[str, Any],
) -> Dict[str, Any]:
    node_id = _stable_hitl_preview_router_id(scenario_key, slug, ordinal)
    new_router_ip = ip_info.get('new_router_ip4')
    link_network = ip_info.get('network_cidr') or ip_info.get('network')
    prefix_len = ip_info.get('prefix_len')
    new_router_ip_cidr = None
    if new_router_ip:
        if prefix_len and '/' not in str(new_router_ip):
            new_router_ip_cidr = f"{new_router_ip}/{prefix_len}"
        else:
            new_router_ip_cidr = str(new_router_ip)
    r2r_interfaces: Dict[str, Any] = {}
    metadata = {
        'hitl_preview': True,
        'hitl_interface_name': iface.get('name'),
        'hitl_attachment': iface.get('attachment'),
        'hitl_slug': slug,
        'link_network': link_network,
        'rj45_ip4': ip_info.get('rj45_ip4'),
        'existing_router_ip4': ip_info.get('existing_router_ip4'),
        'new_router_ip4': new_router_ip,
        'prefix_len': ip_info.get('prefix_len'),
        'netmask': ip_info.get('netmask'),
    }
    preview_router = {
        'node_id': node_id,
        'name': f"hitl-router-{slug}",
        'role': 'router',
        'kind': 'router',
        'ip4': new_router_ip_cidr,
        'r2r_interfaces': r2r_interfaces,
        'vulnerabilities': [],
        'is_base_bridge': False,
        'metadata': metadata,
    }
    return preview_router


def _sanitize_hitl_config(hitl_config: Any, scenario_name: Optional[str], xml_basename: Optional[str]) -> Dict[str, Any]:
    def _normalize_list(value: Any) -> List[str]:
        if isinstance(value, list):
            return [str(v).strip() for v in value if str(v).strip()]
        if isinstance(value, str):
            return [part.strip() for part in value.split(',') if part.strip()]
        return []

    cfg = hitl_config if isinstance(hitl_config, dict) else {}
    enabled = bool(cfg.get('enabled'))
    raw_interfaces = cfg.get('interfaces')

    if isinstance(raw_interfaces, list):
        iterable = raw_interfaces
    elif isinstance(raw_interfaces, str) and raw_interfaces.strip():
        iterable = [{'name': raw_interfaces.strip()}]
    elif isinstance(raw_interfaces, dict) and raw_interfaces.get('name'):
        iterable = [raw_interfaces]
    else:
        iterable = []

    sanitized: List[Dict[str, Any]] = []
    for entry in iterable:
        if entry is None:
            continue
        if isinstance(entry, str):
            name = _normalize_hitl_interface_name(entry)
            if name:
                sanitized.append({'name': name, 'attachment': _DEFAULT_HITL_ATTACHMENT})
            continue
        if not isinstance(entry, dict):
            continue
        clone = dict(entry)
        name_candidate = clone.get('name') or clone.get('interface') or clone.get('iface')
        if not isinstance(name_candidate, str):
            name_candidate = str(name_candidate or '').strip()
        else:
            name_candidate = name_candidate.strip()
        normalized_name = _normalize_hitl_interface_name(name_candidate)
        if not normalized_name:
            continue
        clone['name'] = normalized_name
        alias_candidate = clone.get('alias') or clone.get('description') or clone.get('display') or clone.get('summary')
        if isinstance(alias_candidate, str) and alias_candidate.strip():
            clone['alias'] = alias_candidate.strip()
        if 'display' in clone and not clone.get('description'):
            disp_val = clone.get('display')
            if isinstance(disp_val, str) and disp_val.strip():
                clone['description'] = disp_val.strip()
        clone['attachment'] = _normalize_hitl_attachment(clone.get('attachment'))
        if 'ipv4' in clone:
            clone['ipv4'] = _normalize_list(clone.get('ipv4'))
        if 'ipv6' in clone:
            clone['ipv6'] = _normalize_list(clone.get('ipv6'))
        sanitized.append(clone)

    scenario_key = ''
    candidate = cfg.get('scenario_key')
    if isinstance(candidate, str) and candidate.strip():
        scenario_key = candidate.strip()
    elif isinstance(scenario_name, str) and scenario_name.strip():
        scenario_key = scenario_name.strip()
    elif isinstance(xml_basename, str) and xml_basename.strip():
        scenario_key = xml_basename.strip()
    else:
        scenario_key = '__default__'

    sanitized_cfg = {
        'enabled': enabled,
        'interfaces': sanitized,
        'scenario_key': scenario_key,
    }
    core_cfg = _extract_optional_core_config(cfg.get('core'), include_password=False)
    if core_cfg:
        sanitized_cfg['core'] = core_cfg
    _enrich_hitl_interfaces_with_ips(sanitized_cfg)
    return sanitized_cfg


def _enrich_hitl_interfaces_with_ips(hitl_cfg: Dict[str, Any]) -> None:
    interfaces = hitl_cfg.get('interfaces') or []
    scenario_key = hitl_cfg.get('scenario_key') or '__default__'
    preview_routers: List[Dict[str, Any]] = []
    used_hitl_link_networks: set[str] = set()
    total_interfaces = len(interfaces)

    def _ipv4_list_contains_ip(values: Any, ip: str) -> bool:
        if not ip or not isinstance(values, list):
            return False
        for raw_value in values:
            text = str(raw_value or '').strip()
            if not text:
                continue
            if text.split('/', 1)[0].strip() == ip:
                return True
        return False

    for idx, iface in enumerate(list(interfaces)):
        if not isinstance(iface, dict):
            continue
        attachment = _normalize_hitl_attachment(iface.get('attachment'))
        iface['attachment'] = attachment
        slug = _slugify_hitl_name(iface.get('name'), f"iface-{idx+1}")
        iface['slug'] = slug
        iface['ordinal'] = idx
        iface['interface_count'] = total_interfaces
        ip_info: Optional[Dict[str, Any]] = None
        if attachment in {'new_router', 'existing_router'}:
            ip_info = preferred_hitl_link_ips(iface, used_hitl_link_networks)
            if not ip_info:
                ip_info = predict_hitl_link_ips_unique(scenario_key, iface.get('name'), idx, used_hitl_link_networks)
        if attachment in {'new_router', 'existing_router'} and ip_info:
            iface['link_network'] = ip_info.get('network')
            iface['link_network_cidr'] = ip_info.get('network_cidr') or ip_info.get('network')
            iface['prefix_len'] = ip_info.get('prefix_len')
            iface['netmask'] = ip_info.get('netmask')
            iface['existing_router_ip4'] = ip_info.get('existing_router_ip4')
            iface['new_router_ip4'] = ip_info.get('new_router_ip4')
            iface['rj45_ip4'] = ip_info.get('rj45_ip4')
            ipv4_current = iface.get('ipv4') if isinstance(iface.get('ipv4'), list) else []
            rj45_ip = iface.get('rj45_ip4')
            # Keep any user-provided (real) interface IPs first; append predicted RJ45 IP as a fallback.
            # This makes downstream "first valid ipv4" selection match what users typically expect
            # (their actual interface IP), while still retaining the predicted link IP.
            if rj45_ip:
                if not ipv4_current:
                    iface['ipv4'] = [rj45_ip]
                else:
                    if not _ipv4_list_contains_ip(ipv4_current, rj45_ip):
                        iface['ipv4'] = list(ipv4_current) + [rj45_ip]
                    else:
                        iface['ipv4'] = ipv4_current
        if attachment != 'new_router':
            continue
        if not ip_info:
            continue
        preview_router = _build_hitl_preview_router(scenario_key, iface, slug, idx, ip_info)
        preview_metadata = preview_router.setdefault('metadata', {})
        preview_metadata['scenario_key'] = scenario_key
        preview_metadata['ordinal'] = idx
        preview_metadata['interface_count'] = total_interfaces
        iface['preview_router'] = preview_router
        preview_routers.append(preview_router)
    if preview_routers:
        hitl_cfg['preview_routers'] = preview_routers


def _deterministic_hitl_peer_index(
    scenario_key: str,
    iface_name: str,
    ordinal: int,
    total_ifaces: int,
    candidate_count: int,
) -> Optional[int]:
    if candidate_count <= 0:
        return None
    total = total_ifaces if total_ifaces and total_ifaces > 0 else candidate_count
    seed = f"{scenario_key or '__default__'}|{iface_name or ordinal}|{ordinal}|{total}"
    try:
        base_digest = hashlib.sha256(seed.encode('utf-8', 'replace')).digest()
        counter_bytes = (0).to_bytes(8, 'little', signed=False)
        digest = hashlib.sha256(base_digest + counter_bytes).digest()
        value = int.from_bytes(digest[:8], 'big') / float(1 << 64)
        index = int(value * candidate_count) % candidate_count
        return index
    except Exception:
        return 0


def _wire_hitl_preview_routers(full_preview: Dict[str, Any], hitl_cfg: Dict[str, Any]) -> None:
    routers_list = full_preview.get('routers')
    if not isinstance(routers_list, list) or not routers_list:
        return
    interfaces = hitl_cfg.get('interfaces') or []
    preview_interfaces = [iface for iface in interfaces if isinstance(iface, dict) and iface.get('preview_router')]
    if not preview_interfaces:
        return
    base_routers = [router for router in routers_list if not (router.get('metadata', {}) or {}).get('hitl_preview')]
    if not base_routers:
        return
    scenario_key = hitl_cfg.get('scenario_key') or '__default__'
    total_ifaces = len(preview_interfaces)
    edges_list = full_preview.setdefault('r2r_edges_preview', [])
    existing_edge_pairs: set[tuple[int, int]] = set()
    normalized_edges: List[tuple[int, int]] = []
    for edge in list(edges_list):
        try:
            a, b = edge
            pair = tuple(sorted((int(a), int(b))))
            normalized_edges.append(pair)
            existing_edge_pairs.add(pair)
        except Exception:
            continue
    if normalized_edges:
        edges_list[:] = normalized_edges
    else:
        edges_list.clear()
    links_list = full_preview.setdefault('r2r_links_preview', [])
    existing_edge_id = max(
        (
            detail.get('edge_id', 0)
            for detail in links_list
            if isinstance(detail, dict) and isinstance(detail.get('edge_id'), int)
        ),
        default=0,
    )
    next_edge_id = existing_edge_id + 1
    degree_map = full_preview.get('r2r_degree_preview')
    if not isinstance(degree_map, dict):
        degree_map = {}
        full_preview['r2r_degree_preview'] = degree_map
    else:
        normalized_degree_map: Dict[Any, Any] = {}
        for key, value in degree_map.items():
            try:
                normalized_degree_map[int(key)] = value
            except Exception:
                normalized_degree_map[str(key)] = value
        degree_map = normalized_degree_map
        full_preview['r2r_degree_preview'] = degree_map
    policy_preview = full_preview.get('r2r_policy_preview')
    policy_degree = None
    if isinstance(policy_preview, dict):
        policy_degree = policy_preview.setdefault('degree_sequence', {})
    router_lookup = {router.get('node_id'): router for router in routers_list if isinstance(router, dict)}
    for iface in preview_interfaces:
        preview_router = iface.get('preview_router')
        if not isinstance(preview_router, dict):
            continue
        metadata = preview_router.setdefault('metadata', {})
        if metadata.get('hitl_peer_wired'):
            continue
        new_router_id = preview_router.get('node_id')
        if new_router_id is None:
            continue
        candidate_count = len(base_routers)
        if candidate_count <= 0:
            continue
        iface_name = iface.get('name') or metadata.get('hitl_interface_name') or iface.get('slug') or f"iface-{iface.get('ordinal', 0)}"
        ordinal = iface.get('ordinal') if isinstance(iface.get('ordinal'), int) else metadata.get('ordinal') or 0
        total_count = iface.get('interface_count') if isinstance(iface.get('interface_count'), int) else metadata.get('interface_count') or total_ifaces
        peer_index = _deterministic_hitl_peer_index(
            scenario_key,
            str(iface_name),
            int(ordinal),
            int(total_count or total_ifaces or 1),
            candidate_count,
        ) or 0
        peer_router = base_routers[peer_index % candidate_count]
        peer_id = peer_router.get('node_id')
        if peer_id is None:
            continue
        prefix_len = iface.get('prefix_len') or metadata.get('prefix_len')
        new_ip = iface.get('new_router_ip4') or metadata.get('new_router_ip4')
        existing_ip = iface.get('existing_router_ip4') or metadata.get('existing_router_ip4')
        subnet = (
            iface.get('link_network_cidr')
            or metadata.get('link_network')
            or iface.get('link_network')
        )
        if subnet and prefix_len and '/' not in str(subnet):
            subnet = f"{subnet}/{prefix_len}"

        def _fmt_ip(ip: Any) -> Optional[str]:
            if not ip:
                return None
            ip_str = str(ip)
            if '/' in ip_str:
                return ip_str
            if prefix_len:
                return f"{ip_str}/{prefix_len}"
            return ip_str

        new_ip_cidr = _fmt_ip(new_ip)
        existing_ip_cidr = _fmt_ip(existing_ip)
        preview_iface_map = preview_router.setdefault('r2r_interfaces', {})
        peer_iface_map = peer_router.setdefault('r2r_interfaces', {})
        if new_ip_cidr:
            preview_iface_map[str(peer_id)] = new_ip_cidr
        else:
            preview_iface_map.setdefault(str(peer_id), '')
        if existing_ip_cidr:
            peer_iface_map[str(new_router_id)] = existing_ip_cidr
        else:
            peer_iface_map.setdefault(str(new_router_id), '')
        metadata['peer_router_node_id'] = peer_id
        metadata['peer_router_name'] = peer_router.get('name')
        metadata['hitl_peer_wired'] = True
        iface['peer_router_node_id'] = peer_id
        iface['target_router_id'] = peer_id
        layout_positions = full_preview.get('layout_positions')
        if isinstance(layout_positions, dict):
            routers_positions = layout_positions.setdefault('routers', {})
            if isinstance(routers_positions, dict):
                peer_pos = routers_positions.get(str(peer_id)) or routers_positions.get(peer_id)
                offset_x = 90 + 15 * (int(metadata.get('ordinal') or 0))
                offset_y = 60 + 10 * (int(metadata.get('ordinal') or 0))
                if isinstance(peer_pos, dict):
                    base_x = peer_pos.get('x', 0)
                    base_y = peer_pos.get('y', 0)
                else:
                    base_x = 200 + 120 * (int(metadata.get('ordinal') or 0))
                    base_y = 200 + 90 * (int(metadata.get('ordinal') or 0))
                routers_positions[str(new_router_id)] = {
                    'x': int(base_x) + offset_x,
                    'y': int(base_y) + offset_y,
                }
        edge_pair = tuple(sorted((int(peer_id), int(new_router_id))))
        try:
            peer_degree_key: Any = int(peer_id)
        except Exception:
            peer_degree_key = str(peer_id)
        try:
            new_degree_key: Any = int(new_router_id)
        except Exception:
            new_degree_key = str(new_router_id)
        if edge_pair not in existing_edge_pairs:
            existing_edge_pairs.add(edge_pair)
            edges_list.append(edge_pair)
            link_detail = {
                'edge_id': next_edge_id,
                'routers': [
                    {'id': peer_id, 'ip': existing_ip_cidr},
                    {'id': new_router_id, 'ip': new_ip_cidr},
                ],
                'subnet': subnet,
                'hitl_preview': True,
            }
            links_list.append(link_detail)
            if subnet:
                subnets_list = full_preview.setdefault('r2r_subnets', [])
                if subnet not in subnets_list:
                    subnets_list.append(subnet)
            degree_map[peer_degree_key] = degree_map.get(peer_degree_key, 0) + 1
            degree_map[new_degree_key] = degree_map.get(new_degree_key, 0) + 1
            next_edge_id += 1
            metadata['peer_router_node_id'] = peer_id
            iface['peer_router_node_id'] = peer_id
        else:
            degree_map.setdefault(peer_degree_key, degree_map.get(peer_degree_key, 0))
            degree_map.setdefault(new_degree_key, degree_map.get(new_degree_key, 0))
        if policy_degree is not None:
            policy_degree[str(peer_degree_key)] = degree_map.get(peer_degree_key, 0)
            policy_degree[str(new_degree_key)] = degree_map.get(new_degree_key, 0)
    if degree_map:
        values = [int(v) for v in degree_map.values() if isinstance(v, int)]
        if values:
            full_preview['r2r_stats_preview'] = {
                'min': min(values),
                'max': max(values),
                'avg': round(sum(values) / len(values), 2),
            }


def _augment_hitl_existing_router_interfaces(full_preview: Dict[str, Any], hitl_cfg: Dict[str, Any]) -> None:
    if not isinstance(full_preview, dict) or not isinstance(hitl_cfg, dict):
        return
    routers_list = full_preview.get('routers')
    if not isinstance(routers_list, list) or not routers_list:
        return
    interfaces = hitl_cfg.get('interfaces') or []
    existing_router_ifaces = [
        iface for iface in interfaces
        if isinstance(iface, dict) and _normalize_hitl_attachment(iface.get('attachment')) == 'existing_router'
    ]
    if not existing_router_ifaces:
        return
    base_router_entries = [
        router for router in routers_list
        if isinstance(router, dict) and not (router.get('metadata', {}) or {}).get('hitl_preview')
    ]
    if not base_router_entries:
        return
    scenario_key = hitl_cfg.get('scenario_key') or '__default__'
    total_ifaces = len(existing_router_ifaces)
    router_lookup: Dict[Any, Dict[str, Any]] = {}
    for router in routers_list:
        if not isinstance(router, dict):
            continue
        node_id = router.get('node_id')
        if node_id is not None:
            router_lookup[node_id] = router
    links_list = full_preview.setdefault('r2r_links_preview', [])
    existing_edge_id = max(
        (
            detail.get('edge_id', 0)
            for detail in links_list
            if isinstance(detail, dict) and isinstance(detail.get('edge_id'), int)
        ),
        default=0,
    )
    next_edge_id = existing_edge_id + 1
    existing_link_keys: set[tuple[Any, Any]] = set()
    for link in list(links_list):
        if not isinstance(link, dict):
            continue
        routers = link.get('routers')
        if not isinstance(routers, list) or len(routers) < 2:
            continue
        ra = routers[0].get('id') if isinstance(routers[0], dict) else None
        rb = routers[1].get('id') if isinstance(routers[1], dict) else None
        if ra is None or rb is None:
            continue
        existing_link_keys.add((ra, rb))
        existing_link_keys.add((rb, ra))
    global_overlay = full_preview.setdefault('hitl_existing_router_interfaces', [])
    overlay_keys = {
        (entry.get('router_id'), entry.get('slug'))
        for entry in global_overlay
        if isinstance(entry, dict)
    }

    def _compose_ip_with_prefix(ip_val: Any, prefix_len: Any) -> Optional[str]:
        if not ip_val:
            return None
        ip_str = str(ip_val)
        if '/' in ip_str:
            return ip_str
        if prefix_len:
            try:
                return f"{ip_str}/{int(prefix_len)}"
            except Exception:
                return f"{ip_str}/{prefix_len}"
        return ip_str

    for iface in existing_router_ifaces:
        slug = iface.get('slug')
        if not isinstance(slug, str) or not slug:
            slug = _slugify_hitl_name(iface.get('name'), f"iface-{(iface.get('ordinal') or 0) + 1}")
            iface['slug'] = slug
        ordinal = iface.get('ordinal') if isinstance(iface.get('ordinal'), int) else existing_router_ifaces.index(iface)
        total_count = iface.get('interface_count') if isinstance(iface.get('interface_count'), int) else total_ifaces
        target_router_id = iface.get('target_router_id') if iface.get('target_router_id') in router_lookup else None
        if target_router_id is None:
            if not base_router_entries:
                continue
            iface_name = iface.get('name') or slug or f"iface-{ordinal}"
            peer_index = _deterministic_hitl_peer_index(
                scenario_key,
                str(iface_name),
                int(ordinal or 0),
                int(total_count or total_ifaces or 1),
                len(base_router_entries),
            ) or 0
            chosen_router = base_router_entries[peer_index % len(base_router_entries)]
            target_router_id = chosen_router.get('node_id')
        if target_router_id is None or target_router_id not in router_lookup:
            continue
        iface['target_router_id'] = target_router_id
        iface['peer_router_node_id'] = target_router_id
        router_entry = router_lookup[target_router_id]
        prefix_len = iface.get('prefix_len')
        existing_ip_cidr = _compose_ip_with_prefix(iface.get('existing_router_ip4'), prefix_len)
        rj45_ip_cidr = _compose_ip_with_prefix(iface.get('rj45_ip4'), prefix_len)
        iface['existing_router_ip4_cidr'] = existing_ip_cidr
        iface['rj45_ip4_cidr'] = rj45_ip_cidr
        peer_key = slug
        iface['hitl_peer_key'] = peer_key
        router_iface_map = router_entry.setdefault('r2r_interfaces', {})
        if existing_ip_cidr:
            router_iface_map[peer_key] = existing_ip_cidr
        else:
            router_iface_map.setdefault(peer_key, '')
        router_metadata = router_entry.setdefault('metadata', {})
        router_overlay_list = router_metadata.setdefault('hitl_existing_router_interfaces', [])
        router_overlay_keys = {entry.get('slug') for entry in router_overlay_list if isinstance(entry, dict)}
        overlay_entry = {
            'slug': slug,
            'interface_name': iface.get('name'),
            'router_id': target_router_id,
            'router_name': router_entry.get('name'),
            'ip': existing_ip_cidr,
            'rj45_ip': rj45_ip_cidr,
            'network': iface.get('link_network_cidr') or iface.get('link_network'),
            'hitl_preview': True,
            'hitl_attachment': 'existing_router',
            'hitl_peer_key': peer_key,
            'scenario_key': scenario_key,
        }
        if slug not in router_overlay_keys:
            router_overlay_list.append(dict(overlay_entry))
        global_key = (target_router_id, slug)
        if global_key not in overlay_keys:
            global_overlay.append(dict(overlay_entry))
            overlay_keys.add(global_key)
        link_key = (target_router_id, peer_key)
        if link_key not in existing_link_keys:
            link_detail = {
                'edge_id': next_edge_id,
                'routers': [
                    {'id': target_router_id, 'ip': existing_ip_cidr},
                    {'id': peer_key, 'ip': rj45_ip_cidr},
                ],
                'subnet': iface.get('link_network_cidr') or iface.get('link_network'),
                'hitl_preview': True,
                'hitl_attachment': 'existing_router',
                'hitl_interface_slug': slug,
            }
            links_list.append(link_detail)
            existing_link_keys.add(link_key)
            existing_link_keys.add((peer_key, target_router_id))
            next_edge_id += 1


def _merge_hitl_preview_with_full_preview(full_preview: Dict[str, Any], hitl_cfg: Dict[str, Any]) -> None:
    if not isinstance(full_preview, dict) or not isinstance(hitl_cfg, dict):
        return
    preview_routers = hitl_cfg.get('preview_routers') or []
    routers_list = full_preview.get('routers')
    if not isinstance(routers_list, list):
        routers_list = []
        full_preview['routers'] = routers_list
    existing_ids = set()
    for entry in routers_list:
        if isinstance(entry, dict):
            node_id = entry.get('node_id')
            if node_id is not None:
                existing_ids.add(node_id)
    appended_ids: List[Any] = []
    for router in preview_routers:
        if not isinstance(router, dict):
            continue
        node_id = router.get('node_id')
        if node_id in existing_ids:
            continue
        routers_list.append(router)
        existing_ids.add(node_id)
        appended_ids.append(node_id)
    if appended_ids:
        # Keep routers sorted by node_id for deterministic previews
        try:
            def _router_sort_key(entry: Any) -> tuple[int, int]:
                if not isinstance(entry, dict):
                    return (1, 0)
                node_id = entry.get('node_id')
                if isinstance(node_id, int):
                    return (0, node_id)
                sort_val = 0
                if node_id is not None:
                    try:
                        sort_val = int(str(node_id))
                    except Exception:
                        digest = hashlib.sha256(str(node_id).encode('utf-8', 'replace')).hexdigest()
                        sort_val = int(digest[:8], 16)
                return (0, sort_val)

            routers_list.sort(key=_router_sort_key)
        except Exception:
            pass
        hitl_router_ids = full_preview.get('hitl_router_ids')
        if not isinstance(hitl_router_ids, list):
            hitl_router_ids = []
            full_preview['hitl_router_ids'] = hitl_router_ids
        for node_id in appended_ids:
            hitl_router_ids.append(node_id)
        try:
            seen = set()
            deduped = []
            for nid in hitl_router_ids:
                if nid in seen:
                    continue
                seen.add(nid)
                deduped.append(nid)
            full_preview['hitl_router_ids'] = deduped
            hitl_router_ids = deduped
        except Exception:
            pass
        full_preview['hitl_router_count'] = len([nid for nid in hitl_router_ids if nid is not None])
    _wire_hitl_preview_routers(full_preview, hitl_cfg)
    _augment_hitl_existing_router_interfaces(full_preview, hitl_cfg)


def _hitl_core_validation_ok(core_cfg: Any) -> bool:
    if not isinstance(core_cfg, dict):
        return False
    try:
        if _coerce_bool(core_cfg.get('validated')):
            return True
    except Exception:
        pass
    try:
        status = str(core_cfg.get('last_tested_status') or '').strip().lower()
        if status == 'success':
            return True
    except Exception:
        pass
    return False


def _lookup_hitl_validation_hint(scenario_norm: str) -> Optional[Dict[str, Any]]:
    if not scenario_norm:
        return None
    try:
        hv_map = _load_scenario_hitl_validation_from_disk()
    except Exception:
        hv_map = None
    if not isinstance(hv_map, dict):
        return None
    hint = hv_map.get(scenario_norm)
    if isinstance(hint, dict):
        return hint
    try:
        key = _scenario_match_key(scenario_norm)
    except Exception:
        key = ''
    if not key:
        return None
    for k, v in hv_map.items():
        try:
            if _scenario_match_key(k) == key and isinstance(v, dict):
                return v
        except Exception:
            continue
    return None


def _hitl_config_ready_for_preview(hitl_cfg: Dict[str, Any], scenario_name: Optional[str]) -> bool:
    if not isinstance(hitl_cfg, dict):
        return False
    if not bool(hitl_cfg.get('enabled')):
        return False
    interfaces = hitl_cfg.get('interfaces') if isinstance(hitl_cfg.get('interfaces'), list) else []
    usable_ifaces = [it for it in interfaces if isinstance(it, dict) and str(it.get('name') or '').strip()]
    if not usable_ifaces:
        return False

    if _hitl_core_validation_ok(hitl_cfg.get('core')):
        return True

    scenario_norm = _normalize_scenario_label(scenario_name or hitl_cfg.get('scenario_key') or '')
    if not scenario_norm:
        return False

    hint = _lookup_hitl_validation_hint(scenario_norm)
    if isinstance(hint, dict):
        if _hitl_core_validation_ok(hint.get('core')):
            return True

    return False


def _strip_hitl_overlay_from_full_preview(full_preview: Dict[str, Any]) -> None:
    if not isinstance(full_preview, dict):
        return

    removed_router_ids: set[str] = set()
    routers = full_preview.get('routers')
    if isinstance(routers, list):
        kept = []
        for router in routers:
            if not isinstance(router, dict):
                continue
            md = router.get('metadata') if isinstance(router.get('metadata'), dict) else {}
            is_hitl_router = bool(md.get('hitl_preview'))
            node_id = router.get('node_id')
            node_id_key = str(node_id) if node_id is not None else ''
            if is_hitl_router:
                if node_id_key:
                    removed_router_ids.add(node_id_key)
                continue

            iface_map = router.get('r2r_interfaces') if isinstance(router.get('r2r_interfaces'), dict) else None
            if isinstance(iface_map, dict):
                cleaned_iface_map: Dict[str, Any] = {}
                for key, value in iface_map.items():
                    key_str = str(key)
                    if key_str in removed_router_ids:
                        continue
                    if not key_str.isdigit():
                        continue
                    cleaned_iface_map[key_str] = value
                router['r2r_interfaces'] = cleaned_iface_map
            kept.append(router)
        full_preview['routers'] = kept

    links = full_preview.get('r2r_links_preview')
    if isinstance(links, list):
        kept_links = []
        for link in links:
            if not isinstance(link, dict):
                continue
            if bool(link.get('hitl_preview')):
                continue
            endpoints = link.get('routers') if isinstance(link.get('routers'), list) else []
            drop = False
            for endpoint in endpoints:
                if not isinstance(endpoint, dict):
                    continue
                rid = endpoint.get('id')
                rid_key = str(rid) if rid is not None else ''
                if rid_key in removed_router_ids:
                    drop = True
                    break
                if rid is not None and (not str(rid).isdigit()):
                    drop = True
                    break
            if drop:
                continue
            kept_links.append(link)
        full_preview['r2r_links_preview'] = kept_links

    edges = full_preview.get('r2r_edges_preview')
    if isinstance(edges, list):
        kept_edges = []
        for edge in edges:
            if not isinstance(edge, (list, tuple)) or len(edge) < 2:
                continue
            a = str(edge[0])
            b = str(edge[1])
            if a in removed_router_ids or b in removed_router_ids:
                continue
            if not a.isdigit() or not b.isdigit():
                continue
            kept_edges.append([int(a), int(b)])
        full_preview['r2r_edges_preview'] = kept_edges

    full_preview['hitl_enabled'] = False
    full_preview['hitl_interfaces'] = []
    full_preview.pop('hitl_core', None)
    full_preview['hitl_router_ids'] = []
    full_preview['hitl_router_count'] = 0
    full_preview['hitl_existing_router_interfaces'] = []


def _apply_hitl_config_to_full_preview(full_preview: Dict[str, Any], hitl_cfg: Dict[str, Any], scenario_name: Optional[str]) -> None:
    if not isinstance(full_preview, dict):
        return
    if not isinstance(hitl_cfg, dict):
        full_preview['hitl_enabled'] = False
        full_preview['hitl_interfaces'] = []
        return

    if not _hitl_config_ready_for_preview(hitl_cfg, scenario_name):
        _strip_hitl_overlay_from_full_preview(full_preview)
        full_preview['hitl_scenario_key'] = hitl_cfg.get('scenario_key')
        return

    full_preview['hitl_interfaces'] = hitl_cfg.get('interfaces', [])
    full_preview['hitl_enabled'] = bool(hitl_cfg.get('enabled'))
    full_preview['hitl_scenario_key'] = hitl_cfg.get('scenario_key')
    if hitl_cfg.get('core'):
        core_for_preview = _extract_optional_core_config(hitl_cfg.get('core'), include_password=False)
        full_preview['hitl_core'] = core_for_preview if isinstance(core_for_preview, dict) else hitl_cfg.get('core')
    _merge_hitl_preview_with_full_preview(full_preview, hitl_cfg)

"""Flask web backend for ScenarioForge.

Augmented to guarantee the in-repo version of scenarioforge is imported
instead of any globally installed distribution so new planning modules
like planning.full_preview are always available.
"""

# Ensure repository root (parent directory) precedes any site-packages version & purge shadowed installs
try:
    _THIS_DIR = os.path.abspath(os.path.dirname(__file__))
    _REPO_ROOT = os.path.abspath(os.path.join(_THIS_DIR, '..'))
    if _REPO_ROOT not in sys.path:
        sys.path.insert(0, _REPO_ROOT)
    # Purge any pre-imported site-packages version of scenarioforge so we always load in-repo
    import sys as _sys
    for k in list(_sys.modules.keys()):
        if k == 'scenarioforge' or k.startswith('scenarioforge.'):
            del _sys.modules[k]
except Exception:
    pass

try:
    from scenarioforge.parsers.hitl import parse_hitl_info
except ModuleNotFoundError as exc:
    raise RuntimeError(
        "scenarioforge package is not available from this context. "
        "Run webapp commands from the repository root so the in-repo package is importable."
    ) from exc

from scenarioforge.utils.hitl import collect_hitl_preview_ip_reservations, preferred_hitl_link_ips, predict_hitl_link_ips, predict_hitl_link_ips_unique

# Proactively ensure the in-repo planning.full_preview module is available even if an
# older site-packages installation of scenarioforge (without that module) is first on sys.path.
def _ensure_full_preview_module():  # safe no-op if already present
    try:
        import importlib, sys as _sys
        try:
            # Fast path: module already importable
            import scenarioforge.planning.full_preview  # type: ignore
            try:
                app.logger.debug('[full_preview] already importable (fast path)')
            except Exception:
                pass
            return True
        except ModuleNotFoundError:
            # Force reload planning package from repo root then load file directly
            repo_root = _REPO_ROOT
            planning_dir = os.path.join(repo_root, 'scenarioforge', 'planning')
            candidate = os.path.join(planning_dir, 'full_preview.py')
            if not os.path.exists(candidate):
                try:
                    app.logger.error('[full_preview] candidate missing at %s', candidate)
                except Exception:
                    pass
                return False
            import importlib.util
            spec = importlib.util.spec_from_file_location('scenarioforge.planning.full_preview', candidate)
            if not spec or not spec.loader:
                try:
                    app.logger.error('[full_preview] spec/loader missing for %s', candidate)
                except Exception:
                    pass
                return False
            module = importlib.util.module_from_spec(spec)
            _sys.modules['scenarioforge.planning.full_preview'] = module
            try:
                spec.loader.exec_module(module)  # type: ignore
            except Exception:
                try:
                    import traceback, io as _io
                    buf = _io.StringIO(); traceback.print_exc(file=buf)
                    app.logger.error('[full_preview] exec_module failed: %s', buf.getvalue())
                except Exception:
                    pass
                return False
            # Attach as attribute of planning package for attribute-based access patterns
            try:
                import scenarioforge.planning as planning_pkg  # type: ignore
                setattr(planning_pkg, 'full_preview', module)
            except Exception:
                pass
            try:
                app.logger.info('[full_preview] dynamically loaded from %s', candidate)
            except Exception:
                pass
            return True
    except Exception:
        return False

# Attempt early so later endpoints succeed
try:
    if not _ensure_full_preview_module():
        # Will try again lazily in the endpoint if needed
        pass
except Exception:
    pass

app = Flask(__name__)
app.secret_key = os.environ.get('FLASK_SECRET', 'scenarioforge-web')

# Used for cache-busting and debugging when users have an old tab open.
_WEBUI_BUILD_ID = os.environ.get('CORETG_WEBUI_BUILD_ID') or uuid.uuid4().hex
_log_level_name = os.environ.get('WEBAPP_LOG_LEVEL', 'INFO').strip().upper()
try:
    app.logger.setLevel(getattr(logging, _log_level_name, logging.INFO))
except Exception:
    pass


@app.after_request
def _disable_html_cache(response):
    """Avoid cached inline JS/HTML causing stale UI behavior.

    The UI template contains large inline scripts, so browser caching can keep old
    behavior (eg showing XHR upload=4.3KiB) even after backend changes.
    """
    try:
        ct = (response.headers.get('Content-Type') or '').lower()
        if 'text/html' in ct:
            response.headers['Cache-Control'] = 'no-store'
            response.headers['Pragma'] = 'no-cache'
            response.headers['Expires'] = '0'
    except Exception:
        pass
    return response
class _SkipWebuiLogTailFilter(logging.Filter):
    def filter(self, record: logging.LogRecord) -> bool:
        try:
            msg = record.getMessage()
        except Exception:
            msg = ''
        return '/api/webui/log_tail' not in msg

try:
    logging.getLogger('werkzeug').addFilter(_SkipWebuiLogTailFilter())
except Exception:
    pass
try:
    port = str(os.environ.get('CORETG_PORT') or '').strip() or '9090'
except Exception:
    port = '9090'
try:
    logs_dir = os.path.abspath(os.path.join(_outputs_dir(), 'logs'))
except Exception:
    logs_dir = os.path.abspath(os.path.join(os.getcwd(), 'outputs', 'logs'))
try:
    os.makedirs(logs_dir, exist_ok=True)
except Exception:
    pass
try:
    log_path = os.path.join(logs_dir, f'webui-{port}.log')
    has_handler = False
    for h in list(app.logger.handlers):
        try:
            if isinstance(h, logging.FileHandler) and getattr(h, 'baseFilename', None) == log_path:
                has_handler = True
                break
        except Exception:
            continue
    if not has_handler:
        fh = logging.FileHandler(log_path)
        fh.setLevel(getattr(logging, _log_level_name, logging.INFO))
        fh.setFormatter(logging.Formatter('%(asctime)s %(levelname)s %(name)s: %(message)s'))
        app.logger.addHandler(fh)
        try:
            root = logging.getLogger()
            if fh not in root.handlers:
                root.addHandler(fh)
        except Exception:
            pass
except Exception:
    pass

def _enumerate_host_interfaces(include_down: bool = False) -> List[Dict[str, Any]]:
    """Return host network interfaces available for Hardware-in-the-Loop selection."""
    results: List[Dict[str, Any]] = []
    logger = getattr(app, 'logger', logging.getLogger(__name__))
    if HITL_DISABLE_HOST_ENUM:
        if logger.isEnabledFor(logging.DEBUG):
            logger.debug('[hitl] host interface enumeration skipped (HITL_DISABLE_HOST_ENUM=1)')
        return results
    if psutil is None:
        logger.warning('[hitl] psutil not available; host interface enumeration skipped')
        try:
            logger.warning('[hitl] psutil import failed under interpreter: %s', sys.executable)
            logger.debug('[hitl] sys.path=%s', sys.path)
            logger.debug('[hitl] PATH=%s', os.environ.get('PATH'))
            logger.debug('[hitl] PYTHONPATH=%s', os.environ.get('PYTHONPATH'))
        except Exception:
            pass
        return results
    try:
        logger.debug('[hitl] enumerating host interfaces (include_down=%s)', include_down)
        stats = psutil.net_if_stats()
        addrs = psutil.net_if_addrs()
    except Exception as exc:
        logger.error('[hitl] interface enumeration failed while retrieving stats: %s', exc, exc_info=True)
        return results

    link_families = set()
    for attr in ('AF_LINK',):
        fam = getattr(psutil, attr, None)
        if fam is not None:
            link_families.add(fam)
    for attr in ('AF_PACKET', 'AF_LINK'):
        fam = getattr(socket, attr, None)
        if fam is not None:
            link_families.add(fam)

    total_seen = 0
    skipped_down = 0
    skipped_loopback = 0
    skipped_other = 0
    def _is_non_physical(ifname: str) -> Optional[str]:
        name_normalized = ifname.lower()
        if name_normalized in NON_PHYSICAL_INTERFACE_NAMES:
            return 'exact'
        for prefix in NON_PHYSICAL_INTERFACE_PREFIXES:
            if name_normalized.startswith(prefix):
                return f'prefix:{prefix}'
        for needle in NON_PHYSICAL_INTERFACE_SUBSTRINGS:
            if needle in name_normalized:
                return f'substr:{needle}'
        # Treat typical virtual adapters that expose no MAC and no IPv4 address as non-physical
        return None

    for name, addr_list in addrs.items():
        total_seen += 1
        stat = stats.get(name)
        is_up = bool(getattr(stat, 'isup', False)) if stat else False
        if not include_down and not is_up:
            skipped_down += 1
            logger.debug('[hitl] skipping interface %s: interface is down', name)
            continue

        ipv4: List[str] = []
        ipv6: List[str] = []
        mac_addr: Optional[str] = None
        is_loopback = False

        for addr in addr_list:
            fam = addr.family
            if fam == socket.AF_INET:
                if addr.address:
                    ipv4.append(addr.address)
                    if addr.address.startswith('127.'):
                        is_loopback = True
            elif fam == getattr(socket, 'AF_INET6', None):
                if addr.address:
                    address = addr.address.split('%')[0]
                    ipv6.append(address)
                    if address == '::1':
                        is_loopback = True
            elif fam in link_families:
                if addr.address and addr.address != '00:00:00:00:00:00':
                    mac_addr = addr.address

        name_lc = name.lower()
        if name_lc.startswith('lo') or name == 'lo0':
            is_loopback = True

        if is_loopback:
            skipped_loopback += 1
            logger.debug('[hitl] skipping interface %s: loopback detected', name)
            continue

        non_physical_reason = _is_non_physical(name)
        if non_physical_reason is not None:
            skipped_other += 1
            logger.debug('[hitl] skipping interface %s: marked non-physical (%s)', name, non_physical_reason)
            continue

        entry: Dict[str, Any] = {
            'name': name,
            'display': name,
            'mac': mac_addr,
            'ipv4': ipv4,
            'ipv6': ipv6,
            'mtu': getattr(stat, 'mtu', None) if stat else None,
            'speed': getattr(stat, 'speed', None) if stat else None,
            'is_up': is_up,
        }
        flags = getattr(stat, 'flags', None)
        if isinstance(flags, str):
            entry['flags'] = [flag for flag in flags.replace(',', ' ').split() if flag]
        elif isinstance(flags, (list, tuple, set)):
            entry['flags'] = list(flags)

        results.append(entry)
        logger.debug('[hitl] captured interface %s: mac=%s ipv4=%s ipv6=%s is_up=%s',
                     name, mac_addr, ','.join(ipv4) or '-', ','.join(ipv6) or '-', is_up)

    logger.debug(
        '[hitl] host interface enumeration complete: total_seen=%d exported=%d skipped_down=%d skipped_loopback=%d skipped_other=%d',
        total_seen,
        len(results),
        skipped_down,
        skipped_loopback,
        skipped_other,
    )


def _normalize_mac_value(value: Any) -> str:
    if not value:
        return ''
    text = str(value).strip().lower()
    return ''.join(ch for ch in text if ch.isalnum())


def _enumerate_core_vm_interfaces_via_ssh(
    *,
    ssh_host: str,
    ssh_port: int,
    username: str,
    password: str,
    prox_interfaces: Optional[List[Dict[str, Any]]] = None,
    include_down: bool = False,
    vm_context: Optional[Dict[str, Any]] = None,
    timeout: float = 10.0,
) -> List[Dict[str, Any]]:
    logger = getattr(app, 'logger', logging.getLogger(__name__))
    logger.info(f"[hitl-debug] entering _enumerate_core_vm_interfaces_via_ssh")
    logger.info(f"[hitl-debug] prox_interfaces type: {type(prox_interfaces)}")
    if prox_interfaces:
        logger.info(f"[hitl-debug] prox_interfaces len: {len(prox_interfaces)}")

    _ensure_paramiko_available()
    client = paramiko.SSHClient()  # type: ignore[assignment]
    client.set_missing_host_key_policy(paramiko.AutoAddPolicy())  # type: ignore[attr-defined]
    try:
        client.connect(
            hostname=ssh_host,
            port=int(ssh_port),
            username=username,
            password=password,
            look_for_keys=False,
            allow_agent=False,
            timeout=timeout,
            banner_timeout=timeout,
            auth_timeout=timeout,
        )
    except Exception as exc:  # pragma: no cover - network dependent
        raise _SSHTunnelError(f'Failed to establish SSH session to {ssh_host}:{ssh_port}: {exc}') from exc
    try:
        physical_ifaces: Optional[set[str]] = None
        phys_cmd = 'for I in $(ls -1 /sys/class/net 2>/dev/null); do if [ -e "/sys/class/net/$I/device" ]; then printf "%s\n" "$I"; fi; done'
        try:
            _, phys_stdout, _ = client.exec_command(phys_cmd, timeout=timeout)
            phys_data = phys_stdout.read()
            phys_status = phys_stdout.channel.recv_exit_status() if hasattr(phys_stdout, 'channel') else 0
            if phys_status == 0:
                if isinstance(phys_data, bytes):
                    phys_text = phys_data.decode('utf-8', 'ignore')
                else:
                    phys_text = str(phys_data)
                physical_list = [line.strip() for line in phys_text.splitlines() if line.strip()]
                if physical_list:
                    physical_ifaces = {name for name in physical_list if name and not name.lower().startswith('lo')}
        except Exception:  # pragma: no cover - best effort only
            app.logger.debug('[hitl] unable to enumerate physical interface set from CORE VM', exc_info=True)

        command = 'LANG=C ip -json address show'
        try:
            stdin, stdout, stderr = client.exec_command(command, timeout=timeout)
            stdout_data = stdout.read()
            stderr_data = stderr.read()
            exit_status = stdout.channel.recv_exit_status() if hasattr(stdout, 'channel') else 0
        except Exception as exc:  # pragma: no cover - remote command failure
            raise RuntimeError(f'Failed to execute "{command}" on CORE VM: {exc}') from exc
        if isinstance(stdout_data, bytes):
            stdout_text = stdout_data.decode('utf-8', 'ignore')
        else:
            stdout_text = str(stdout_data)
        if exit_status != 0:
            err_text = stderr_data.decode('utf-8', 'ignore') if isinstance(stderr_data, bytes) else str(stderr_data)
            raise RuntimeError(f'CORE VM rejected interface query ({exit_status}): {err_text.strip() or "unknown error"}')
        try:
            parsed = json.loads(stdout_text.strip() or '[]')
        except json.JSONDecodeError as exc:
            raise RuntimeError('Unable to parse interface data from CORE VM (ip -json output invalid)') from exc
        if not isinstance(parsed, list):
            raise RuntimeError('Unexpected interface payload from CORE VM')

        prox_context = vm_context if isinstance(vm_context, dict) else {}
        prox_map: Dict[str, Dict[str, Any]] = {}
        if prox_interfaces and isinstance(prox_interfaces, list):
            logger.info(f"[hitl-debug] Enumerate SSH with {len(prox_interfaces)} prox interfaces")
            if len(prox_interfaces) > 0:
                 logger.info(f"[hitl-debug] First prox interface sample: {prox_interfaces[0]}")
            for entry in prox_interfaces:
                if not isinstance(entry, dict):
                    continue
                mac_norm = _normalize_mac_value(entry.get('macaddr') or entry.get('mac') or entry.get('hwaddr'))
                if not mac_norm:
                    continue
                prox_info: Dict[str, Any] = {
                    'id': entry.get('id') or entry.get('interface_id') or entry.get('name') or entry.get('label'),
                    'macaddr': entry.get('macaddr') or entry.get('mac') or entry.get('hwaddr'),
                    'bridge': entry.get('bridge'),
                    'model': entry.get('model'),
                    'raw': entry,
                }
                prox_info.update({
                    'vm_key': prox_context.get('vm_key'),
                    'vm_name': prox_context.get('vm_name'),
                    'vm_node': prox_context.get('vm_node'),
                    'vmid': prox_context.get('vmid'),
                })
                prox_map[mac_norm] = prox_info

        results: List[Dict[str, Any]] = []
        for item in parsed:
            if not isinstance(item, dict):
                continue
            ifname = item.get('ifname') or item.get('name')
            if not ifname:
                continue
            name_lc = str(ifname).lower()
            if name_lc.startswith('lo'):
                continue
            if physical_ifaces is not None:
                base_name = str(ifname).split('@', 1)[0]
                base_name = base_name.split(':', 1)[0]
                root_name = base_name.split('.', 1)[0]
                if base_name not in physical_ifaces and root_name not in physical_ifaces:
                    continue
            flags = item.get('flags') if isinstance(item.get('flags'), list) else []
            operstate = str(item.get('operstate') or '').strip().upper()
            is_up = operstate == 'UP' or 'UP' in [str(flag).upper() for flag in flags]
            if not include_down and not is_up:
                continue
            mac_addr = item.get('address') or item.get('mac')
            mac_norm = _normalize_mac_value(mac_addr)
            addr_info = item.get('addr_info') if isinstance(item.get('addr_info'), list) else []
            ipv4: List[str] = []
            ipv6: List[str] = []
            for addr in addr_info:
                if not isinstance(addr, dict):
                    continue
                family = str(addr.get('family') or '').lower()
                value = addr.get('local') or addr.get('address')
                if not value:
                    continue
                if family == 'inet':
                    ipv4.append(str(value))
                elif family == 'inet6':
                    ipv6.append(str(value).split('%')[0])
            entry: Dict[str, Any] = {
                'name': ifname,
                'display': ifname,
                'mac': mac_addr,
                'ipv4': ipv4,
                'ipv6': ipv6,
                'ifindex': item.get('ifindex'),
                'mtu': item.get('mtu'),
                'speed': item.get('link_speed') or None,
                'is_up': is_up,
                'flags': flags,
            }
            prox_entry = prox_map.get(mac_norm)
            if prox_entry:
                entry['proxmox'] = prox_entry
                bridge_val = prox_entry.get('bridge')
                if bridge_val:
                    entry['bridge'] = bridge_val
            results.append(entry)

        results.sort(key=lambda rec: rec.get('name') or '')
        logger.info('[hitl] enumerated %d interfaces via CORE VM SSH (host=%s)', len(results), ssh_host)
        return results
    finally:
        try:
            client.close()
        except Exception:
            logger.debug('SSH client close failed after interface enumeration', exc_info=True)


def _enumerate_core_vm_interfaces_from_secret(
    secret_id: str,
    *,
    prox_interfaces: Optional[List[Dict[str, Any]]] = None,
    include_down: bool = False,
    vm_context: Optional[Dict[str, Any]] = None,
) -> List[Dict[str, Any]]:
    if not secret_id:
        raise ValueError('CORE credential identifier is required')
    record = _load_core_credentials(secret_id)
    if not record:
        raise ValueError('Stored CORE credentials not found')
    password = record.get('ssh_password_plain') or record.get('password_plain') or ''
    if not password:
        raise ValueError('Stored CORE credentials are missing password material')
    username = str(record.get('ssh_username') or '').strip()
    if not username:
        raise ValueError('Stored CORE credentials are missing SSH username')
    ssh_host = str(record.get('ssh_host') or record.get('host') or '').strip()
    if not ssh_host:
        raise ValueError('Stored CORE credentials are missing SSH host')
    try:
        ssh_port = int(record.get('ssh_port') or 22)
    except Exception:
        ssh_port = 22
    vm_meta = vm_context if isinstance(vm_context, dict) else {
        'vm_key': record.get('vm_key'),
        'vm_name': record.get('vm_name'),
        'vm_node': record.get('vm_node'),
        'vmid': record.get('vmid'),
    }
    return _enumerate_core_vm_interfaces_via_ssh(
        ssh_host=ssh_host,
        ssh_port=ssh_port,
        username=username,
        password=password,
        prox_interfaces=prox_interfaces,
        include_down=include_down,
        vm_context=vm_meta,
    )

    results.sort(key=lambda item: item['name'])
    return results


_PROXMOX_INTERFACE_ID_RE = re.compile(r"^net\d+$", re.IGNORECASE)

def _hitl_slot_selector_index(value: Any) -> Optional[int]:
    try:
        text = str(value or '').strip().lower()
    except Exception:
        return None
    if not text:
        return None
    match = _PROXMOX_INTERFACE_ID_RE.fullmatch(text)
    if not match:
        return None
    try:
        return int(text[3:])
    except Exception:
        return None


def _ordered_core_vm_interfaces_for_hitl_resolution(live_interfaces: Any) -> List[Dict[str, Any]]:
    ordered: List[Dict[str, Any]] = []
    for live_iface in live_interfaces or []:
        if not isinstance(live_iface, dict):
            continue
        live_name = _normalize_hitl_interface_name(
            live_iface.get('name') or live_iface.get('ifname') or live_iface.get('interface')
        )
        if not live_name:
            continue
        entry = dict(live_iface)
        entry['_resolved_name'] = live_name
        try:
            ifindex_raw = live_iface.get('ifindex')
            entry['_ifindex_sort'] = int(ifindex_raw) if ifindex_raw not in (None, '') else None
        except Exception:
            entry['_ifindex_sort'] = None
        ordered.append(entry)

    ordered.sort(
        key=lambda rec: (
            rec.get('_ifindex_sort') is None,
            rec.get('_ifindex_sort') if rec.get('_ifindex_sort') is not None else 10**9,
            str(rec.get('_resolved_name') or '').lower(),
        )
    )
    return ordered


def _validate_hitl_interface_names_for_execute(
    hitl_cfg: Any,
    core_cfg: Any,
) -> Tuple[Dict[str, Any], List[str], List[Dict[str, Any]]]:
    """Resolve SSH-discoverable HITL selectors and ensure final names exist on the CORE VM before execute."""
    cfg = dict(hitl_cfg) if isinstance(hitl_cfg, dict) else {}
    raw_interfaces = cfg.get('interfaces') if isinstance(cfg.get('interfaces'), list) else []
    interfaces: List[Dict[str, Any]] = []
    configured_entries: List[Tuple[int, str, str, Optional[int]]] = []
    for iface in raw_interfaces:
        if not isinstance(iface, dict):
            continue
        entry = dict(iface)
        interfaces.append(entry)
        name = _normalize_hitl_interface_name(entry.get('name'))
        prox_target = entry.get('proxmox_target') if isinstance(entry.get('proxmox_target'), dict) else {}
        selector_raw = str(prox_target.get('interface_id') or '').strip()
        if not selector_raw and _hitl_slot_selector_index(name) is not None:
            selector_raw = name
        selector_index = _hitl_slot_selector_index(selector_raw)
        if not name and selector_index is None:
            continue
        configured_entries.append((len(interfaces) - 1, name, selector_raw, selector_index))
    cfg['interfaces'] = interfaces
    if not configured_entries:
        return cfg, [], []

    core_state = core_cfg if isinstance(core_cfg, dict) else {}
    ssh_host = str(core_state.get('ssh_host') or core_state.get('host') or '').strip()
    ssh_username = str(core_state.get('ssh_username') or '').strip()
    ssh_password = core_state.get('ssh_password')
    ssh_password_text = str(ssh_password).strip() if ssh_password not in (None, '') else ''
    secret_id = str(core_state.get('core_secret_id') or '').strip()
    ssh_port_raw = core_state.get('ssh_port') or 22
    try:
        ssh_port = int(ssh_port_raw)
    except Exception:
        ssh_port = 22

    if not secret_id and not (ssh_host and ssh_username and ssh_password_text):
        return (
            cfg,
            [
                (
                    'Validate CORE VM SSH access and refresh CORE VM interfaces before execute '
                    'so configured HITL interface names can be verified.'
                )
            ],
            [],
        )

    vm_context = {
        'vm_key': core_state.get('vm_key'),
        'vm_name': core_state.get('vm_name'),
        'vm_node': core_state.get('vm_node'),
        'vmid': core_state.get('vmid'),
    }
    try:
        if secret_id:
            live_interfaces = _enumerate_core_vm_interfaces_from_secret(
                secret_id,
                include_down=True,
                vm_context=vm_context,
            )
        else:
            live_interfaces = _enumerate_core_vm_interfaces_via_ssh(
                ssh_host=ssh_host,
                ssh_port=ssh_port,
                username=ssh_username,
                password=ssh_password_text,
                include_down=True,
                vm_context=vm_context,
            )
    except Exception as exc:
        return (
            cfg,
            [
                (
                    'Failed to verify configured HITL interface names against the CORE VM: '
                    f'{exc}'
                )
            ],
            [],
        )

    ordered_live_interfaces = _ordered_core_vm_interfaces_for_hitl_resolution(live_interfaces)
    live_name_set: Set[str] = {
        str(entry.get('_resolved_name') or '').lower()
        for entry in ordered_live_interfaces
        if str(entry.get('_resolved_name') or '').strip()
    }
    changes: List[Dict[str, Any]] = []

    errors: List[str] = []
    for iface_idx, configured_name, selector_text, slot_index in configured_entries:
        final_name = configured_name
        if slot_index is not None:
            if slot_index >= len(ordered_live_interfaces):
                available_names = ', '.join(
                    str(entry.get('_resolved_name') or '').strip()
                    for entry in ordered_live_interfaces
                    if str(entry.get('_resolved_name') or '').strip()
                )
                available_suffix = f' Available interfaces: {available_names}.' if available_names else ''
                errors.append(
                    'HITL interface selector '
                    f'{selector_text or configured_name} did not match any CORE VM interface discovered over SSH.'
                    f'{available_suffix}'
                )
                continue
            resolved_name = str(ordered_live_interfaces[slot_index].get('_resolved_name') or '').strip()
            if not resolved_name:
                errors.append(
                    'HITL interface selector '
                    f'{selector_text or configured_name} resolved to an empty CORE VM interface name.'
                )
                continue
            if not final_name or _hitl_slot_selector_index(final_name) is not None:
                interfaces[iface_idx]['name'] = resolved_name
                changes.append({
                    'index': iface_idx,
                    'from': final_name or selector_text,
                    'to': resolved_name,
                    'selector': selector_text or final_name,
                })
                final_name = resolved_name
            elif final_name.lower() != resolved_name.lower():
                errors.append(
                    'HITL interface '
                    f'{final_name} does not match selector {selector_text} resolved to {resolved_name}. '
                    'Update the configured name or selector before execute.'
                )
                continue
        if final_name.lower() in live_name_set:
            interfaces[iface_idx]['name'] = final_name
            continue
        errors.append(
            'HITL interface '
            f'{final_name} was not found on the CORE VM. '
            'Refresh CORE VM interfaces and update the configured interface name before execute.'
        )

    return cfg, errors, changes

# ----------------------- Basic Path Helpers (restored) -----------------------
def _get_repo_root() -> str:
    """Return absolute repository root (directory containing this webapp folder)."""
    try:
        return _REPO_ROOT
    except Exception:
        return os.path.abspath(os.path.join(os.path.dirname(__file__), '..'))

def _outputs_dir() -> str:
    d = os.path.join(_get_repo_root(), 'outputs')
    os.makedirs(d, exist_ok=True)
    return d

def _uploads_dir() -> str:
    d = os.path.join(_get_repo_root(), 'uploads')
    os.makedirs(d, exist_ok=True)
    return d

def _reports_dir() -> str:
    d = os.path.join(_get_repo_root(), 'reports')
    os.makedirs(d, exist_ok=True)
    return d


def _abs_path_or_original(path_value: Any, *, base_dir: str | None = None) -> str:
    try:
        raw = str(path_value or '').strip()
    except Exception:
        return ''
    if not raw:
        return ''
    try:
        expanded = os.path.expandvars(os.path.expanduser(raw))
    except Exception:
        expanded = raw
    try:
        if os.path.isabs(expanded):
            return os.path.abspath(expanded)
        if base_dir:
            return os.path.abspath(os.path.join(base_dir, expanded))
        return os.path.abspath(expanded)
    except Exception:
        return raw


def _existing_xml_path_or_none(path_value: Any) -> str | None:
    p = _abs_path_or_original(path_value)
    if not p:
        return None
    try:
        if (not str(p).lower().endswith('.xml')) or (not os.path.exists(p)):
            return None
    except Exception:
        return None
    return p


def _looks_like_path_field(field_name: str) -> bool:
    try:
        key = str(field_name or '').strip().lower()
    except Exception:
        return False
    if not key:
        return False
    return (
        ('path' in key)
        or key.endswith('_dir')
        or key.endswith('_file')
        or key.endswith('_filepath')
        or key in {'file', 'run_dir', 'outputs_manifest'}
    )


def _canonicalize_flow_assignment_paths(assignment: dict[str, Any]) -> dict[str, Any]:
    if not isinstance(assignment, dict):
        return assignment
    out = dict(assignment)
    for key in ('artifacts_dir', 'run_dir', 'outputs_manifest'):
        if key in out:
            out[key] = _abs_path_or_original(out.get(key))
    base_dir = (
        str(out.get('run_dir') or '').strip()
        or str(out.get('artifacts_dir') or '').strip()
        or ''
    )
    if not base_dir:
        try:
            manifest = str(out.get('outputs_manifest') or '').strip()
            if manifest:
                base_dir = os.path.dirname(manifest)
        except Exception:
            base_dir = ''

    def _split_inject_spec_global(raw: str) -> tuple[str, str]:
        text = str(raw or '').strip()
        if not text:
            return '', ''
        for sep in ('->', '=>'):
            if sep in text:
                left, right = text.split(sep, 1)
                return left.strip(), right.strip()
        return text, ''

    def _looks_like_artifact_key(text: str) -> bool:
        s = str(text or '').strip()
        if not s:
            return False
        low = s.lower()
        # Common Flow artifact key shapes
        if low.startswith(('file(', 'directory(', 'flag(', 'credential(', 'knowledge(')):
            return True
        if low.endswith('(path)'):
            return True
        return False

    def _looks_like_fs_path(text: str) -> bool:
        s = str(text or '').strip()
        if not s:
            return False
        if _looks_like_artifact_key(s):
            return False
        if s.startswith('upload:'):
            return True
        if s.startswith(('/', './', '../', '~')):
            return True
        if '/' in s or '\\' in s:
            return True
        return False

    inject_files = out.get('inject_files') if isinstance(out.get('inject_files'), list) else None
    if inject_files is not None:
        resolved_outputs = out.get('resolved_outputs') if isinstance(out.get('resolved_outputs'), dict) else {}
        fixed_injects: list[Any] = []
        for item in inject_files:
            if not isinstance(item, str):
                fixed_injects.append(item)
                continue
            src, dest = _split_inject_spec_global(item)
            if _looks_like_artifact_key(src):
                try:
                    resolved_src = resolved_outputs.get(src) if isinstance(resolved_outputs, dict) else None
                    if isinstance(resolved_src, str) and resolved_src.strip() and _looks_like_fs_path(resolved_src):
                        fixed_src = _abs_path_or_original(resolved_src, base_dir=base_dir or None)
                        fixed_injects.append(f"{fixed_src} -> {dest}" if dest else fixed_src)
                        continue
                except Exception:
                    pass
            if _looks_like_fs_path(src):
                fixed_src = _abs_path_or_original(src, base_dir=base_dir or None)
                fixed_injects.append(f"{fixed_src} -> {dest}" if dest else fixed_src)
            else:
                fixed_injects.append(str(item))
        out['inject_files'] = fixed_injects

    detail = out.get('inject_files_detail') if isinstance(out.get('inject_files_detail'), list) else None
    if detail is not None:
        fixed_detail: list[Any] = []
        for item in detail:
            if not isinstance(item, dict):
                fixed_detail.append(item)
                continue
            item2 = dict(item)
            if 'path' in item2:
                item2['path'] = _abs_path_or_original(item2.get('path'), base_dir=base_dir or None)
            if 'resolved' in item2:
                item2['resolved'] = _abs_path_or_original(item2.get('resolved'), base_dir=base_dir or None)
            fixed_detail.append(item2)
        out['inject_files_detail'] = fixed_detail

    ro = out.get('resolved_outputs') if isinstance(out.get('resolved_outputs'), dict) else None
    if ro is not None:
        fixed_ro: dict[str, Any] = {}
        for key, value in ro.items():
            if isinstance(value, str) and _looks_like_path_field(str(key)):
                fixed_ro[key] = _abs_path_or_original(value, base_dir=base_dir or None)
            else:
                fixed_ro[key] = value
        out['resolved_outputs'] = fixed_ro

    ro_detail = out.get('resolved_outputs_detail') if isinstance(out.get('resolved_outputs_detail'), list) else None
    if ro_detail is not None:
        fixed_ro_detail: list[Any] = []
        for item in ro_detail:
            if not isinstance(item, dict):
                fixed_ro_detail.append(item)
                continue
            item2 = dict(item)
            field = str(item2.get('field') or '').strip()
            if isinstance(item2.get('resolved'), str) and _looks_like_path_field(field):
                item2['resolved'] = _abs_path_or_original(item2.get('resolved'), base_dir=base_dir or None)
            fixed_ro_detail.append(item2)
        out['resolved_outputs_detail'] = fixed_ro_detail

    return out


def _canonicalize_flow_state_paths(flow_state: dict[str, Any], *, xml_path: str | None = None) -> dict[str, Any]:
    if not isinstance(flow_state, dict):
        return flow_state
    out = dict(flow_state)
    xml_abs = _abs_path_or_original(xml_path) if xml_path else ''
    xml_dir = os.path.dirname(xml_abs) if xml_abs else ''

    for key in ('source_preview_plan_path', 'preview_plan_path', 'base_preview_plan_path', 'xml_path'):
        if key in out:
            out[key] = _abs_path_or_original(out.get(key), base_dir=xml_dir or None)

    assigns = out.get('flag_assignments') if isinstance(out.get('flag_assignments'), list) else None
    if assigns is not None:
        out['flag_assignments'] = [
            _canonicalize_flow_assignment_paths(a) if isinstance(a, dict) else a
            for a in assigns
        ]

    try:
        out['allow_node_duplicates'] = bool(_coerce_bool(out.get('allow_node_duplicates') or out.get('allow_duplicates')))
    except Exception:
        out['allow_node_duplicates'] = False
    try:
        out['include_all_topology_vulns'] = bool(_coerce_bool(out.get('include_all_topology_vulns')))
    except Exception:
        out['include_all_topology_vulns'] = False
    try:
        out['include_all_topology_pivots'] = bool(_coerce_bool(out.get('include_all_topology_pivots')))
    except Exception:
        out['include_all_topology_pivots'] = False

    # Keep FlowState chain fields consistent for readers that rely on chain_ids.
    try:
        chain_ids = out.get('chain_ids') if isinstance(out.get('chain_ids'), list) else []
        chain_ids_norm = [str(x or '').strip() for x in (chain_ids or []) if str(x or '').strip()]

        if not chain_ids_norm:
            chain_entries = out.get('chain') if isinstance(out.get('chain'), list) else []
            derived = []
            for entry in chain_entries:
                if isinstance(entry, dict):
                    nid = str(entry.get('id') or entry.get('node_id') or '').strip()
                    if nid:
                        derived.append(nid)
                else:
                    nid = str(entry or '').strip()
                    if nid:
                        derived.append(nid)
            chain_ids_norm = derived

        if chain_ids_norm:
            out['chain_ids'] = chain_ids_norm
            out['length'] = len(chain_ids_norm)
    except Exception:
        pass
    return out


def _flow_state_chain_ids(flow_state: dict[str, Any] | None) -> list[str]:
    if not isinstance(flow_state, dict):
        return []
    try:
        chain_ids = flow_state.get('chain_ids') if isinstance(flow_state.get('chain_ids'), list) else []
        normalized = [str(x or '').strip() for x in (chain_ids or []) if str(x or '').strip()]
        if normalized:
            return normalized
    except Exception:
        pass
    try:
        chain_entries = flow_state.get('chain') if isinstance(flow_state.get('chain'), list) else []
        derived: list[str] = []
        for entry in chain_entries:
            if isinstance(entry, dict):
                nid = str(entry.get('id') or entry.get('node_id') or '').strip()
            else:
                nid = str(entry or '').strip()
            if nid:
                derived.append(nid)
        return derived
    except Exception:
        return []


def _flow_state_chain_nodes(flow_state: dict[str, Any] | None) -> list[dict[str, Any]]:
    if not isinstance(flow_state, dict):
        return []

    chain_entries = flow_state.get('chain') if isinstance(flow_state.get('chain'), list) else []
    chain_ids = _flow_state_chain_ids(flow_state)
    if not chain_ids:
        try:
            assigns = flow_state.get('flag_assignments') if isinstance(flow_state.get('flag_assignments'), list) else []
            chain_ids = [
                str(item.get('node_id') or '').strip()
                for item in (assigns or [])
                if isinstance(item, dict) and str(item.get('node_id') or '').strip()
            ]
        except Exception:
            chain_ids = []

    out: list[dict[str, Any]] = []
    for idx, cid in enumerate(chain_ids):
        entry = chain_entries[idx] if idx < len(chain_entries) else None
        node: dict[str, Any] = dict(entry) if isinstance(entry, dict) else {}
        if not str(node.get('id') or node.get('node_id') or '').strip():
            node['id'] = cid
        if not str(node.get('name') or '').strip():
            node['name'] = cid
        out.append(node)

    if out:
        return out

    for entry in chain_entries:
        if isinstance(entry, dict):
            node_id = str(entry.get('id') or entry.get('node_id') or '').strip()
            if not node_id:
                continue
            node = dict(entry)
            if not str(node.get('name') or '').strip():
                node['name'] = node_id
            out.append(node)
            continue
        node_id = str(entry or '').strip()
        if node_id:
            out.append({'id': node_id, 'name': node_id})
    return out


def _refresh_loaded_flow_state_assignments(
    flow_state: dict[str, Any] | None,
    *,
    scenario_label: str | None,
) -> dict[str, Any] | None:
    if not isinstance(flow_state, dict):
        return flow_state

    assignments = flow_state.get('flag_assignments') if isinstance(flow_state.get('flag_assignments'), list) else None
    if not assignments:
        return flow_state

    chain_nodes = _flow_state_chain_nodes(flow_state)
    if not chain_nodes:
        return flow_state

    label = str(scenario_label or flow_state.get('scenario') or '').strip()
    try:
        enriched = _flow_enrich_saved_flag_assignments(assignments, chain_nodes, scenario_label=label)
    except Exception:
        return flow_state
    if not isinstance(enriched, list) or not enriched:
        return flow_state

    out = dict(flow_state)
    out['flag_assignments'] = enriched
    try:
        first_hints = _flow_first_hints_from_assignments(enriched)
        if first_hints:
            out['first_hint'] = first_hints[0]
            out['first_hints'] = list(first_hints)
    except Exception:
        pass
    return out


def _flow_state_allows_node_duplicates(flow_state: dict[str, Any] | None) -> bool:
    if not isinstance(flow_state, dict):
        return False
    try:
        return bool(_coerce_bool(flow_state.get('allow_node_duplicates') or flow_state.get('allow_duplicates')))
    except Exception:
        return False


def _flow_state_has_disallowed_duplicate_nodes(flow_state: dict[str, Any] | None) -> bool:
    if not isinstance(flow_state, dict):
        return False
    if _flow_state_allows_node_duplicates(flow_state):
        return False
    chain_ids = _flow_state_chain_ids(flow_state)
    return bool(chain_ids) and len(set(chain_ids)) != len(chain_ids)


def _flow_state_scrub_disallowed_duplicates(flow_state: dict[str, Any] | None) -> dict[str, Any] | None:
    if not isinstance(flow_state, dict):
        return flow_state
    if not _flow_state_has_disallowed_duplicate_nodes(flow_state):
        return flow_state
    out = dict(flow_state)
    out['allow_node_duplicates'] = False
    out['chain_ids'] = []
    out['chain'] = []
    out['flag_assignments'] = []
    out['length'] = 0
    out['flags_enabled'] = False
    out['flow_valid'] = False
    msg = 'saved flow chain reused nodes while duplicates are disabled'
    errors = out.get('flow_errors') if isinstance(out.get('flow_errors'), list) else []
    if msg not in errors:
        errors = list(errors) + [msg]
    out['flow_errors'] = errors
    return out


def _backfill_flow_state_inject_files_from_catalog(flow_state: dict[str, Any]) -> dict[str, Any]:
    """Ensure FlowState flag_assignments include inject_files from generator manifests.

    The UI chain tables are sourced from generator catalogs (manifest injects). Persisted
    FlowState may omit inject_files (or leave it empty). We backfill before writing XML
    so CLI execution sees the intended allowlist.
    """
    if not isinstance(flow_state, dict):
        return flow_state
    assigns = flow_state.get('flag_assignments') if isinstance(flow_state.get('flag_assignments'), list) else None
    if not isinstance(assigns, list) or not assigns:
        return flow_state

    gen_injects: dict[str, list[str]] = {}
    gen_candidate_paths: dict[str, list[str]] = {}
    try:
        gens, _errs = _flag_generators_from_enabled_sources()
    except Exception:
        gens = []
    try:
        node_gens, _errs2 = _flag_node_generators_from_enabled_sources()
    except Exception:
        node_gens = []
    for g in list(gens or []) + list(node_gens or []):
        if not isinstance(g, dict):
            continue
        gid = str(g.get('id') or '').strip()
        inj = g.get('inject_files') if isinstance(g.get('inject_files'), list) else None
        if not gid or not isinstance(inj, list):
            continue
        cleaned = [str(x or '').strip() for x in inj if str(x or '').strip()]
        if cleaned:
            gen_injects[gid] = cleaned
        candidates = _normalize_inject_candidate_paths(g.get('inject_candidate_paths'))
        if candidates:
            gen_candidate_paths[gid] = candidates

    def _default_vuln_injects(entry: dict[str, Any]) -> list[str]:
        try:
            vulns = entry.get('vulnerabilities') if isinstance(entry.get('vulnerabilities'), list) else []
            if any(str(v or '').strip() for v in (vulns or [])):
                return ['flag.txt -> /tmp']
        except Exception:
            pass
        return []

    def _merge_vuln_injects(existing: Any, catalog_injects: list[str], fallback: list[str]) -> list[str]:
        current = [str(x or '').strip() for x in (existing or [])] if isinstance(existing, list) else []
        current = [x for x in current if x]
        explicit_catalog = [str(x or '').strip() for x in (catalog_injects or []) if str(x or '').strip()]
        fallback_tokens = {str(x or '').strip() for x in (fallback or []) if str(x or '').strip()}

        if explicit_catalog:
            current = [item for item in current if item not in fallback_tokens]
            if not current:
                current = list(explicit_catalog)

        if not current and fallback:
            current = [str(x or '').strip() for x in fallback if str(x or '').strip()]

        out: list[str] = []
        seen: set[str] = set()
        for item in current:
            if item in seen:
                continue
            seen.add(item)
            out.append(item)
        return out

    out = dict(flow_state)
    out_assigns: list[Any] = []
    for a in assigns:
        if not isinstance(a, dict):
            out_assigns.append(a)
            continue
        a2 = dict(a)
        existing = a2.get('inject_files') if isinstance(a2.get('inject_files'), list) else []
        gid = str(a2.get('id') or a2.get('generator_id') or '').strip()
        fallback = _default_vuln_injects(a2)
        merged_injects = _merge_vuln_injects(existing, gen_injects.get(gid, []), fallback)
        if merged_injects:
            a2['inject_files'] = merged_injects
        if gid and not _normalize_inject_candidate_paths(a2.get('inject_candidate_paths')):
            candidates = gen_candidate_paths.get(gid, [])
            if candidates:
                a2['inject_candidate_paths'] = list(candidates)
        out_assigns.append(a2)
    out['flag_assignments'] = out_assigns
    return out


def _canonicalize_plan_payload_paths(plan_payload: dict[str, Any], *, xml_path: str | None = None) -> dict[str, Any]:
    if not isinstance(plan_payload, dict):
        return plan_payload
    out = dict(plan_payload)
    xml_abs = _abs_path_or_original(xml_path) if xml_path else ''

    meta = out.get('metadata') if isinstance(out.get('metadata'), dict) else {}
    meta2 = dict(meta)
    meta_xml = _abs_path_or_original(meta2.get('xml_path') or '', base_dir=os.path.dirname(xml_abs) if xml_abs else None)
    if not meta_xml and xml_abs:
        meta_xml = xml_abs
    if meta_xml:
        meta2['xml_path'] = meta_xml
    flow_meta = meta2.get('flow') if isinstance(meta2.get('flow'), dict) else None
    if isinstance(flow_meta, dict):
        meta2['flow'] = _canonicalize_flow_state_paths(flow_meta, xml_path=meta_xml or xml_abs)
    out['metadata'] = meta2
    return out

