def _flow_read_flag_value_from_artifacts_dir(artifacts_dir: str) -> str:
    """Read a realized flag value from a generator artifacts directory.

    Only reads from directories under /tmp/vulns to avoid arbitrary file access.
    Returns empty string when not found.
    """
    try:
        d = str(artifacts_dir or '').strip()
        if not d:
            return ''
        base_dir = os.path.abspath(os.path.join('/tmp', 'vulns'))
        dd = os.path.abspath(d)
        if os.path.commonpath([dd, base_dir]) != base_dir:
            return ''
        if not os.path.isdir(dd):
            return ''
        flag_txt = os.path.join(dd, 'flag.txt')
        if os.path.isfile(flag_txt):
            with open(flag_txt, 'r', encoding='utf-8', errors='ignore') as f:
                val = (f.read() or '').strip()
                return val[:4096] if val else ''

        outs_path = os.path.join(dd, 'outputs.json')
        if os.path.isfile(outs_path):
            try:
                with open(outs_path, 'r', encoding='utf-8') as f:
                    m = json.load(f) or {}
                outs = m.get('outputs') if isinstance(m, dict) else None
                if isinstance(outs, dict):
                    v = outs.get('Flag(flag_id)') or outs.get('flag')
                    if isinstance(v, str) and v.strip():
                        vv = v.strip()
                        return vv[:4096]
            except Exception:
                return ''
    except Exception:
        return ''
    return ''


def _flow_read_outputs_map_from_artifacts_dir(artifacts_dir: str) -> dict[str, Any]:
    """Read realized output values from a generator artifacts directory.

    Only reads from directories under /tmp/vulns to avoid arbitrary file access.
    Returns an empty dict when not found.

    Expected shape (best-effort): outputs.json contains {"outputs": {k: v, ...}}.
    """
    try:
        d = str(artifacts_dir or '').strip()
        if not d:
            return {}
        base_dir = os.path.abspath(os.path.join('/tmp', 'vulns'))
        dd = os.path.abspath(d)
        if os.path.commonpath([dd, base_dir]) != base_dir:
            return {}
        if not os.path.isdir(dd):
            return {}
        outs_path = os.path.join(dd, 'outputs.json')
        if not os.path.isfile(outs_path):
            return {}
        with open(outs_path, 'r', encoding='utf-8') as f:
            m = json.load(f) or {}
        outs = m.get('outputs') if isinstance(m, dict) else None
        return outs if isinstance(outs, dict) else {}
    except Exception:
        return {}


def _first_valid_ipv4(value: Any) -> str:
    """Return a best-effort IPv4 address string (no CIDR), or '' if not found."""
    try:
        import ipaddress

        def _norm_one(v: Any) -> str:
            s = str(v or '').strip()
            if not s:
                return ''
            if '/' in s:
                s = s.split('/', 1)[0].strip()
            try:
                ip = ipaddress.ip_address(s)
            except Exception:
                return ''
            return s if ip.version == 4 else ''

        if isinstance(value, list):
            for item in value:
                out = _norm_one(item)
                if out:
                    return out
            return ''
        return _norm_one(value)
    except Exception:
        return ''


def _preview_host_ip4_any(host: dict[str, Any] | None) -> str:
    """Best-effort: return primary IPv4 from a preview host payload."""
    if not isinstance(host, dict):
        return ''
    try:
        ip4 = host.get('ip4')
        if isinstance(ip4, str) and _first_valid_ipv4(ip4):
            return _first_valid_ipv4(ip4)
    except Exception:
        pass
    for key in ('ipv4', 'ip', 'ip_addr', 'address'):
        try:
            v = host.get(key)
        except Exception:
            v = None
        ip_str = _first_valid_ipv4(v)
        if ip_str:
            return ip_str
    try:
        for key in ('ips', 'addresses', 'ip4s', 'ipv4s'):
            v = host.get(key)
            ip_str = _first_valid_ipv4(v)
            if ip_str:
                return ip_str
    except Exception:
        pass
    try:
        ifaces = host.get('interfaces')
        if isinstance(ifaces, list):
            for iface in ifaces:
                if not isinstance(iface, dict):
                    continue
                for key in ('ip4', 'ipv4', 'ip', 'ip_addr', 'address'):
                    ip_str = _first_valid_ipv4(iface.get(key))
                    if ip_str:
                        return ip_str
    except Exception:
        pass
    return ''


def _flow_compute_flag_assignments(
    preview: dict,
    chain_nodes: list[dict[str, Any]],
    scenario_label: str,
    *,
    initial_facts_override: dict[str, list[str]] | None = None,
    goal_facts_override: dict[str, list[str]] | None = None,
    seed_override: int | None = None,
    disallow_generator_reuse: bool = False,
    dependency_level: int | None = None,
    pivot_context: Any | None = None,
) -> list[dict[str, Any]]:
    """Return a per-position list of flag assignments aligned to chain_ids.

    Each item includes node_id plus the fields used for metadata.flow_flag.
    Deterministic-ish: shuffles eligible flags based on preview.seed.
    """
    if not isinstance(preview, dict) or not isinstance(chain_nodes, list) or not chain_nodes:
        return []

    chain_ids: list[str] = [str(n.get('id') or '').strip() for n in chain_nodes if isinstance(n, dict) and str(n.get('id') or '').strip()]
    if not chain_ids:
        return []

    vuln_ids: set[str] = set()
    vuln_names_by_id: dict[str, list[str]] = {}
    try:
        hosts = preview.get('hosts') if isinstance(preview, dict) else None
        if isinstance(hosts, list):
            for h in hosts:
                if not isinstance(h, dict):
                    continue
                hid = str(h.get('node_id') or '').strip()
                if not hid:
                    continue
                vulns = h.get('vulnerabilities') if isinstance(h.get('vulnerabilities'), list) else []
                if vulns:
                    vuln_ids.add(hid)
                try:
                    names: list[str] = []
                    for v in (vulns or []):
                        if isinstance(v, str):
                            s = v.strip()
                            if s:
                                names.append(s)
                            continue
                        if isinstance(v, dict):
                            for key in ('name', 'title', 'id', 'vuln', 'cve', 'cve_id', 'slug'):
                                val = v.get(key)
                                if isinstance(val, str) and val.strip():
                                    names.append(val.strip())
                                    break
                    if names:
                        uniq = []
                        seen = set()
                        for n in names:
                            if n and n not in seen:
                                seen.add(n)
                                uniq.append(n)
                        vuln_names_by_id[hid] = uniq
                except Exception:
                    pass
    except Exception:
        vuln_ids = set()
    def _extract_vuln_names(obj: dict[str, Any]) -> list[str]:
        names: list[str] = []
        try:
            raw = obj.get('vulnerabilities')
            if isinstance(raw, list):
                for v in raw:
                    if isinstance(v, str):
                        s = v.strip()
                        if s:
                            names.append(s)
                        continue
                    if isinstance(v, dict):
                        for key in ('name', 'title', 'id', 'vuln', 'cve', 'cve_id', 'slug'):
                            val = v.get(key)
                            if isinstance(val, str) and val.strip():
                                names.append(val.strip())
                                break
        except Exception:
            pass
        return names
    try:
        for n in (chain_nodes or []):
            if not isinstance(n, dict):
                continue
            nid = str(n.get('id') or '').strip()
            if not nid:
                continue
            names = _extract_vuln_names(n)
            if names:
                vuln_ids.add(nid)
                if nid not in vuln_names_by_id:
                    uniq = []
                    seen = set()
                    for nm in names:
                        if nm and nm not in seen:
                            seen.add(nm)
                            uniq.append(nm)
                    vuln_names_by_id[nid] = uniq
    except Exception:
        pass

    # Use generator-catalog entries:
    # - flag-generators: artifact/flag generation
    # - flag-node-generators: node/docker-compose generation (Docker-role only)
    try:
        generators, _errors = _flag_generators_from_enabled_sources()
    except Exception:
        generators = []

    try:
        node_generators, _errors2 = _flag_node_generators_from_enabled_sources()
    except Exception:
        node_generators = []

    eligible_gens: list[dict[str, Any]] = []
    for g in (generators or []):
        if not isinstance(g, dict):
            continue
        gid = str(g.get('id') or '').strip()
        if not gid:
            continue
        g2 = dict(g)
        g2['_flow_kind'] = 'flag-generator'
        g2['_flow_catalog'] = 'flag_generators'
        eligible_gens.append(g2)

    for g in (node_generators or []):
        if not isinstance(g, dict):
            continue
        gid = str(g.get('id') or '').strip()
        if not gid:
            continue
        g2 = dict(g)
        g2['_flow_kind'] = 'flag-node-generator'
        g2['_flow_catalog'] = 'flag_node_generators'
        eligible_gens.append(g2)

    if not eligible_gens:
        return []

    # Deterministic randomness for generator selection using flow_seed.
    try:
        import random as _random
        seed_val = _get_flow_seed(preview, seed_override)
        rnd = _random.Random(seed_val ^ 0xC0FFEE)
    except Exception:
        rnd = None


    # Map ids -> names/ips for THIS/NEXT substitution.
    id_to_name: dict[str, str] = {}
    id_to_ip: dict[str, str] = {}
    id_to_ip: dict[str, str] = {}
    for n in chain_nodes:
        try:
            nid = str(n.get('id') or '').strip()
            nm = str(n.get('name') or '').strip()
            if nid:
                id_to_name[nid] = nm or nid
                ip = ''
                try:
                    ip = _first_valid_ipv4(n.get('ip4') or n.get('ipv4') or n.get('ip') or '')
                except Exception:
                    ip = ''
                if ip:
                    id_to_ip[nid] = ip
        except Exception:
            pass

    id_to_node: dict[str, dict[str, Any]] = {}
    for n in chain_nodes:
        if not isinstance(n, dict):
            continue
        nid = str(n.get('id') or '').strip()
        if nid:
            id_to_node[nid] = n

    # Prefer v3 plugin contracts for chaining semantics (requires/produces).
    try:
        plugins_by_id = _flow_enabled_plugin_contracts_by_id()
    except Exception:
        plugins_by_id = {}

    def _render_hint(tpl: str, *, this_id: str, next_id: str) -> str:
        try:
            raw_tpl = str(tpl or '').strip() or 'Next: {{NEXT_NODE_NAME}}'
            text = raw_tpl
            next_id_val = str(next_id or '').strip()
            next_name_val = (id_to_name.get(next_id_val) or '').strip() if next_id_val else ''
            next_ip_val = str(id_to_ip.get(next_id_val) or '').strip() if next_id_val else ''
            if not next_id_val:
                return "You've completed this sequence of challenges!"
            if not next_name_val:
                next_name_val = next_id_val
            if ('{{NEXT_NODE_NAME}}' in raw_tpl) and ('{{NEXT_NODE_IP}}' not in raw_tpl) and next_ip_val:
                next_name_val = f"{next_name_val} ({next_ip_val})"
            repl = {
                '{{SCENARIO}}': str(scenario_label or ''),
                '{{THIS_NODE_ID}}': this_id,
                '{{THIS_NODE_NAME}}': id_to_name.get(this_id) or this_id,
                '{{NEXT_NODE_ID}}': next_id_val,
                '{{NEXT_NODE_NAME}}': next_name_val,
                '{{NEXT_NODE_IP}}': next_ip_val,
            }
            for k, v in repl.items():
                text = text.replace(k, str(v))
            return _flow_strip_ids_from_hint(text)
        except Exception:
            return ''

    out: list[dict[str, Any]] = []

    def _artifact_requires_of(gen: dict[str, Any]) -> set[str]:
        required: set[str] = set()
        try:
            pid = str(gen.get('id') or '').strip()
            plugin = plugins_by_id.get(pid)
            if isinstance(plugin, dict) and isinstance(plugin.get('requires'), list):
                for x in (plugin.get('requires') or []):
                    xx = str(x).strip()
                    if xx:
                        required.add(xx)
        except Exception:
            pass
        # Synthesized inputs (e.g., seed/node_name) are *fields*, not chain artifacts.
        # Filter them out even if a plugin contract mistakenly lists them in `requires`.
        try:
            required = {x for x in required if x not in _flow_synthesized_inputs()}
        except Exception:
            pass
        return required

    def _required_input_fields_of(gen: dict[str, Any]) -> set[str]:
        """Return required input field names for a generator.

        Optional inputs (required=False) are intentionally excluded.
        """
        required: set[str] = set()
        try:
            inputs = gen.get('inputs')
            if isinstance(inputs, list):
                for inp in inputs:
                    if not isinstance(inp, dict):
                        continue
                    name = str(inp.get('name') or '').strip()
                    if not name:
                        continue
                    if inp.get('required') is False:
                        continue
                    required.add(name)
        except Exception:
            pass
        return required

    def _all_input_fields_of(gen: dict[str, Any]) -> set[str]:
        fields: set[str] = set()
        try:
            inputs = gen.get('inputs')
            if isinstance(inputs, list):
                for inp in inputs:
                    if not isinstance(inp, dict):
                        continue
                    name = str(inp.get('name') or '').strip()
                    if name:
                        fields.add(name)
        except Exception:
            pass
        return fields

    def _required_inputs_of(gen: dict[str, Any]) -> set[str]:
        # Effective union: artifact dependencies + required runtime input fields.
        # If a plugin-level "requires" token is also present as an *optional* input
        # field (required=False), treat it as optional and exclude it.
        try:
            req_fields = _required_input_fields_of(gen)
            opt_fields = _all_input_fields_of(gen) - set(req_fields)
            req_artifacts = _artifact_requires_of(gen)
            if opt_fields:
                req_artifacts = {r for r in req_artifacts if r not in opt_fields}
            return req_artifacts | set(req_fields)
        except Exception:
            return set()

    def _artifact_produces_of(gen: dict[str, Any]) -> set[str]:
        provides: set[str] = set()
        try:
            pid = str(gen.get('id') or '').strip()
            plugin = plugins_by_id.get(pid)
            if isinstance(plugin, dict) and isinstance(plugin.get('produces'), list):
                for item in (plugin.get('produces') or []):
                    if not isinstance(item, dict):
                        continue
                    a = str(item.get('artifact') or '').strip()
                    if a:
                        provides.add(a)
        except Exception:
            pass
        return provides

    def _output_fields_of(gen: dict[str, Any]) -> set[str]:
        out_fields: set[str] = set()
        try:
            outputs = gen.get('outputs')
            if isinstance(outputs, list):
                for outp in outputs:
                    if not isinstance(outp, dict):
                        continue
                    nm = str(outp.get('name') or '').strip()
                    if nm:
                        out_fields.add(nm)
        except Exception:
            pass
        try:
            out_fields |= _artifact_produces_of(gen)
        except Exception:
            pass
        return out_fields

    def _provides_of(gen: dict[str, Any]) -> set[str]:
        provides: set[str] = set()

        # Plugin-level produces (artifact dependencies).
        try:
            provides |= _artifact_produces_of(gen)
        except Exception:
            pass

        try:
            prov = gen.get('provides')
            if isinstance(prov, list):
                for x in prov:
                    s = str(x).strip()
                    if s:
                        provides.add(s)
        except Exception:
            pass
        try:
            provides |= _output_fields_of(gen)
        except Exception:
            pass
        return provides

    # Inputs we can always synthesize deterministically at preview time.
    # Keep this in sync with _flow_default_generator_config() and common generator conventions.
    initial_facts: set[str] = set(_flow_synthesized_inputs())
    try:
        init_override = _flow_normalize_fact_override(initial_facts_override)
        if init_override:
            initial_facts |= set(init_override.get('artifacts') or [])
            initial_facts |= set(init_override.get('fields') or [])
    except Exception:
        pass

    goal_facts: set[str] = set()
    try:
        goal_override = _flow_normalize_fact_override(goal_facts_override)
        if goal_override:
            goal_facts |= set(goal_override.get('artifacts') or [])
            goal_facts |= set(goal_override.get('fields') or [])
    except Exception:
        pass

    state_known: set[str] = set(initial_facts)
    chain_produced: set[str] = set()
    previous_produced: set[str] = set()
    deployed: set[str] = set()

    dependency_level_norm = _flow_normalize_dependency_level(dependency_level)
    dependent_slot_total = max(0, len(chain_ids) - 1)
    desired_dependent_slots = int(round((max(0, dependency_level_norm - 1) / 4.0) * dependent_slot_total))

    def _slot_should_depend(idx: int) -> bool:
        if idx <= 0 or dependent_slot_total <= 0 or desired_dependent_slots <= 0:
            return False
        if dependency_level_norm >= 5:
            return True
        try:
            import math as _math
            prev_quota = _math.ceil(((idx - 1) * desired_dependent_slots) / dependent_slot_total)
            curr_quota = _math.ceil((idx * desired_dependent_slots) / dependent_slot_total)
            return curr_quota > prev_quota
        except Exception:
            return False

    provides_cache: dict[str, set[str]] = {}
    requires_cache: dict[str, set[str]] = {}

    def _provides_cached(gen: dict[str, Any]) -> set[str]:
        try:
            gid = str(gen.get('id') or '').strip()
        except Exception:
            gid = ''
        if gid and gid in provides_cache:
            return provides_cache[gid]
        try:
            p = set(_provides_of(gen))
        except Exception:
            p = set()
        if gid:
            provides_cache[gid] = p
        return p

    def _requires_cached(gen: dict[str, Any]) -> set[str]:
        try:
            gid = str(gen.get('id') or '').strip()
        except Exception:
            gid = ''
        if gid and gid in requires_cache:
            return requires_cache[gid]
        try:
            r = set(_required_inputs_of(gen))
        except Exception:
            r = set()
        if gid:
            requires_cache[gid] = r
        return r

    pool_by_pos: list[list[dict[str, Any]]] = []
    for cid in chain_ids:
        node = id_to_node.get(str(cid)) or {}
        is_vuln_node = _flow_node_is_vuln(node) or (str(cid) in vuln_ids)
        is_docker_node = _flow_node_is_docker_role(node)
        def _eligible_for_node(g: dict[str, Any]) -> bool:
            k = str(g.get('_flow_kind') or '').strip() or 'flag-generator'
            if k == 'flag-node-generator':
                return bool(is_docker_node and (not is_vuln_node))
            return bool(is_vuln_node)
        pool_by_pos.append([g for g in eligible_gens if _eligible_for_node(g)])

    remaining_union_by_idx: list[set[str]] = []
    try:
        running: set[str] = set()
        for i in range(len(pool_by_pos) - 1, -1, -1):
            pool = pool_by_pos[i] if i < len(pool_by_pos) else []
            for g in pool:
                running |= _provides_cached(g)
            remaining_union_by_idx.append(set(running))
        remaining_union_by_idx = list(reversed(remaining_union_by_idx))
    except Exception:
        remaining_union_by_idx = [set() for _ in range(len(pool_by_pos))]

    remaining_requires_by_idx: list[set[str]] = []
    try:
        running_requires: set[str] = set()
        for i in range(len(pool_by_pos) - 1, -1, -1):
            pool = pool_by_pos[i] if i < len(pool_by_pos) else []
            for g in pool:
                running_requires |= (_requires_cached(g) - set(initial_facts))
            remaining_requires_by_idx.append(set(running_requires))
        remaining_requires_by_idx = list(reversed(remaining_requires_by_idx))
    except Exception:
        remaining_requires_by_idx = [set() for _ in range(len(pool_by_pos))]

    def _candidate_list(idx: int, state: set[str], deployed_ids: set[str]) -> list[dict[str, Any]]:
        pool = pool_by_pos[idx] if idx < len(pool_by_pos) else []
        if not pool:
            return []
        candidates = [
            g for g in pool
            if _requires_cached(g).issubset(state) and str(g.get('id') or '').strip() not in deployed_ids
        ]
        if (not candidates) and (not disallow_generator_reuse):
            candidates = [g for g in pool if _requires_cached(g).issubset(state)]
        if not candidates:
            if disallow_generator_reuse:
                return []
            # Best-effort fallback: allow assignment even if requires are not yet met.
            # Validation will surface missing dependencies, but we avoid empty assignments.
            candidates = list(pool)
        return candidates

    def _score_order(cands: list[dict[str, Any]], state: set[str]) -> list[dict[str, Any]]:
        scored: list[tuple[dict[str, Any], int]] = []
        for g in cands:
            provides = _provides_cached(g)
            new_facts = set(provides) - set(state)
            goal_new = (set(goal_facts) - set(state)) & set(provides)
            score = max(1, len(new_facts) + (3 * len(goal_new)))
            scored.append((g, score))
        if rnd is not None:
            try:
                rnd.shuffle(scored)
            except Exception:
                pass
        scored.sort(key=lambda x: x[1], reverse=True)
        return [g for g, _ in scored]

    def _prefer_by_dependency_target(candidates: list[dict[str, Any]], idx: int) -> list[dict[str, Any]]:
        if not candidates:
            return []
        if idx <= 0:
            if _slot_should_depend(idx + 1):
                try:
                    future_required = remaining_requires_by_idx[idx + 1] if (idx + 1) < len(remaining_requires_by_idx) else set()
                except Exception:
                    future_required = set()
                unlocking = [g for g in candidates if (_provides_cached(g) & future_required)]
                if unlocking:
                    return unlocking
            return candidates

        wants_dependency = _slot_should_depend(idx)
        if wants_dependency:
            previous_dependent = [g for g in candidates if (_requires_cached(g) & previous_produced)]
            if previous_dependent:
                return previous_dependent
            chain_dependent = [g for g in candidates if (_requires_cached(g) & chain_produced)]
            if chain_dependent:
                return chain_dependent
            return candidates

        independent = [g for g in candidates if not (_requires_cached(g) & chain_produced)]
        return independent or candidates

    def _dependency_score(g: dict[str, Any], state: set[str], idx: int) -> int:
        provides = _provides_cached(g)
        requires = _requires_cached(g)
        score = max(1, len(set(provides) - set(state)))
        score += 3 * len((set(goal_facts) - set(state)) & set(provides))
        if _slot_should_depend(idx):
            score += 100 * len(requires & previous_produced)
            score += 40 * len(requires & chain_produced)
        elif requires & chain_produced:
            score -= 20 * len(requires & chain_produced)
        if _slot_should_depend(idx + 1):
            try:
                future_required = remaining_requires_by_idx[idx + 1] if (idx + 1) < len(remaining_requires_by_idx) else set()
            except Exception:
                future_required = set()
            score += 25 * len(provides & future_required)
        return score

    def _choose_candidate(candidates: list[dict[str, Any]], state: set[str], idx: int) -> dict[str, Any]:
        preferred = _prefer_by_dependency_target(candidates, idx)
        scored = [(g, _dependency_score(g, state, idx)) for g in (preferred or candidates)]
        if rnd is not None:
            try:
                rnd.shuffle(scored)
            except Exception:
                pass
        scored.sort(key=lambda item: item[1], reverse=True)
        return scored[0][0]

    chosen_gens: list[dict[str, Any]] | None = None
    if goal_facts:
        memo: set[tuple[int, frozenset[str], frozenset[str]]] = set()
        try:
            import time as _time
            _deadline = _time.monotonic() + 30.0
        except Exception:
            _deadline = None

        def _dfs(idx: int, state: set[str], deployed_ids: set[str]) -> list[dict[str, Any]] | None:
            if _deadline is not None:
                try:
                    if _time.monotonic() >= _deadline:
                        return None
                except Exception:
                    pass
            key = (idx, frozenset(state), frozenset(deployed_ids))
            if key in memo:
                return None
            if idx >= len(chain_ids):
                return [] if set(goal_facts).issubset(state) else None
            remaining_goal = set(goal_facts) - set(state)
            if remaining_goal:
                possible = set(state)
                try:
                    possible |= remaining_union_by_idx[idx]
                except Exception:
                    pass
                if not remaining_goal.issubset(possible):
                    memo.add(key)
                    return None
            candidates = _candidate_list(idx, state, deployed_ids)
            if not candidates:
                memo.add(key)
                return None
            ordered = _score_order(candidates, state)
            for g in ordered:
                provides = _provides_cached(g)
                gid = str(g.get('id') or '').strip()
                next_state = set(state) | set(provides)
                next_deployed = set(deployed_ids)
                if gid:
                    next_deployed.add(gid)
                tail = _dfs(idx + 1, next_state, next_deployed)
                if tail is not None:
                    return [g] + tail
            memo.add(key)
            return None

        try:
            chosen = _dfs(0, set(state_known), set(deployed))
            if chosen and len(chosen) == len(chain_ids):
                chosen_gens = chosen
        except Exception:
            chosen_gens = None

    for i, cid in enumerate(chain_ids):
        pool = pool_by_pos[i] if i < len(pool_by_pos) else []
        if not pool:
            return []

        if chosen_gens is not None:
            gen = chosen_gens[i]
        else:
            candidates = [
                g for g in pool
                if _requires_cached(g).issubset(state_known) and str(g.get('id') or '').strip() not in deployed
            ]
            if (not candidates) and (not disallow_generator_reuse):
                candidates = [g for g in pool if _requires_cached(g).issubset(state_known)]
            if not candidates:
                if disallow_generator_reuse:
                    return []
                # Best-effort fallback: allow assignment even if requires are not yet met.
                # Validation will surface missing dependencies, but we avoid empty assignments.
                candidates = list(pool)

            remaining_goal = set(goal_facts) - set(state_known)
            if remaining_goal:
                if i == (len(chain_ids) - 1):
                    goal_candidates = [g for g in candidates if remaining_goal & _provides_cached(g)]
                    if goal_candidates:
                        candidates = goal_candidates
                else:
                    try:
                        remaining_union: set[str] = set()
                        for j in range(i + 1, len(chain_ids)):
                            for g in (pool_by_pos[j] if j < len(pool_by_pos) else []):
                                remaining_union |= _provides_cached(g)
                        filtered: list[dict[str, Any]] = []
                        for g in candidates:
                            future_possible = set(state_known) | _provides_cached(g) | remaining_union
                            if remaining_goal.issubset(future_possible):
                                filtered.append(g)
                        if filtered:
                            candidates = filtered
                    except Exception:
                        pass

            gen = _choose_candidate(candidates, state_known, i)

        try:
            supplied_names_for_start = set(_flow_first_step_chain_supplied_input_names(gen))
            required_for_start = set(_required_inputs_of(gen)) - set(initial_facts) - supplied_names_for_start
            supply_on_start = bool(not required_for_start)
        except Exception:
            supply_on_start = bool(i == 0)

        # Update outputs for the next hop.
        try:
            produced = _provides_cached(gen)
            state_known |= set(produced)
            previous_produced = set(produced)
            chain_produced |= set(produced)
        except Exception:
            pass
        try:
            gid = str(gen.get('id') or '').strip()
            if gid:
                deployed.add(gid)
        except Exception:
            pass

        next_id = chain_ids[i + 1] if (i + 1) < len(chain_ids) else ''
        hint_level_templates = _flow_hint_level_templates_from_generator(gen)
        rendered_hint_levels = _flow_render_hint_level_templates(
            hint_level_templates,
            scenario_label=scenario_label,
            id_to_name=id_to_name,
            id_to_ip=id_to_ip,
            this_id=str(cid),
            next_id=str(next_id),
        )
        hint_templates = [str(x or '').strip() for x in (hint_level_templates.get('low') or []) if str(x or '').strip()]
        hint_tpl = hint_templates[0] if hint_templates else 'Next: {{NEXT_NODE_NAME}}'
        rendered_hints = [str(x or '').strip() for x in (rendered_hint_levels.get('low') or []) if str(x or '').strip()]
        if not rendered_hints:
            rendered_hints = [
                _render_hint(t, this_id=str(cid), next_id=str(next_id))
                for t in (hint_templates or [])
            ]

        requires_artifacts = sorted(list(_artifact_requires_of(gen)))
        produces_artifacts = sorted(list(_artifact_produces_of(gen)))
        input_fields_required = sorted(list(_required_input_fields_of(gen)))
        input_fields_all = sorted(list(_all_input_fields_of(gen)))
        input_fields_optional = sorted([x for x in input_fields_all if x and x not in set(input_fields_required)])
        output_fields = sorted(list(_output_fields_of(gen)))

        # Preview-level input overrides are optional; these are primarily relevant
        # for UI preview and are filtered to known inputs + synthesized fields.
        raw_overrides = preview.get('config_overrides')
        if not isinstance(raw_overrides, dict):
            raw_overrides = preview.get('inputs_overrides')
        if not isinstance(raw_overrides, dict):
            raw_overrides = preview.get('input_overrides')

        allowed_override_keys: set[str] = set(input_fields_all)
        try:
            allowed_override_keys |= set(_flow_synthesized_inputs())
        except Exception:
            pass

        config_overrides: dict[str, Any] = {}
        if isinstance(raw_overrides, dict):
            for k, v in raw_overrides.items():
                kk = str(k or '').strip()
                if not kk:
                    continue
                if allowed_override_keys and kk not in allowed_override_keys:
                    continue
                # Preserve explicit clears (None/empty) as an override.
                config_overrides[kk] = v

        # If an artifact "requires" token also appears as an optional input field,
        # treat it as optional (do not block chaining/validation on it).
        try:
            optional_field_set = set(input_fields_optional)
            requires_artifacts = sorted([x for x in requires_artifacts if x and x not in optional_field_set])
        except Exception:
            pass

        vuln_names = list(vuln_names_by_id.get(str(cid), []) or [])
        inject_files = [str(x or '').strip() for x in (gen.get('inject_files') or [])] if isinstance(gen.get('inject_files'), list) else []
        inject_files = [x for x in inject_files if x]
        if vuln_names and not inject_files:
            inject_files.append('flag.txt -> /tmp')
        inject_candidate_paths = _normalize_inject_candidate_paths(gen.get('inject_candidate_paths'))

        assignment_out = {
            'node_id': str(cid),
            'id': str(gen.get('id') or ''),
            'name': str(gen.get('name') or ''),
            'description': str(gen.get('description') or ''),
            'type': str(gen.get('_flow_kind') or 'flag-generator'),
            'flag_generator': str(gen.get('_source_name') or '').strip() or 'unknown',
            'generator_catalog': str(gen.get('_flow_catalog') or 'flag_generators'),
            'language': str(gen.get('language') or ''),
            'vulnerabilities': vuln_names,
            'description_hints': list(gen.get('description_hints') or []) if isinstance(gen.get('description_hints'), list) else [],
            'inject_files': inject_files,
            'inject_candidate_paths': inject_candidate_paths,
            # Effective union (used for chaining feasibility / ordering validation).
            'inputs': sorted(list(_required_inputs_of(gen))),
            'outputs': sorted(list(_provides_of(gen))),

            # Split-out views for UI transparency.
            'requires': requires_artifacts,
            'produces': produces_artifacts,
            'input_fields': input_fields_all,
            'input_fields_required': input_fields_required,
            'input_fields_optional': input_fields_optional,
            'output_fields': output_fields,
            'hint_level_templates': hint_level_templates,
            'hint_levels': rendered_hint_levels,
            'hint_template': hint_tpl,
            'hint_templates': hint_templates,
            'hint': rendered_hints[0] if rendered_hints else _render_hint(hint_tpl, this_id=str(cid), next_id=str(next_id)),
            'hints': rendered_hints,
            'next_node_id': str(next_id),
            'next_node_name': str(id_to_name.get(str(next_id)) or ''),
        }
        assignment_out = _flow_apply_first_step_chain_supplied_inputs(
            assignment_out,
            gen,
            scenario_label=scenario_label,
            position=i,
            supply_on_start=supply_on_start,
        )
        out.append(assignment_out)
    return _flow_apply_pivot_context_to_assignments(
        out,
        chain_nodes,
        preview=preview,
        pivot_context=pivot_context,
        scenario_label=scenario_label,
    )


def _flow_synthesized_inputs() -> set[str]:
    """Inputs we can always synthesize deterministically at preview time.

    Keep this in sync with _flow_compute_flag_assignments() and _flow_default_generator_config().
    """
    return {
        'seed',
        'seed_ts',
        'secret',
        'env_name',
        'challenge',
        'flag_prefix',
        'flag_seed',
        'username_prefix',
        'key_len',
        'node_name',
        # Optional per-node context injected by Flow (may not be declared by a generator).
        # These are safe to ignore in "dropped" input reporting.
        'Knowledge(ip)',
        'Hostname(host)',
        'host_ip',
        'target_ip',
        'ip4',
        'ipv4',
    }


def _flow_looks_like_fact_ref(raw: Any) -> bool:
    text = str(raw or '').strip()
    if not text or '(' not in text or not text.endswith(')'):
        return False
    head, _tail = text.split('(', 1)
    return bool(head.strip())


def _flow_truthy_flag(value: Any) -> bool:
    if isinstance(value, bool):
        return value
    if isinstance(value, (int, float)):
        return bool(value)
    if isinstance(value, str):
        return value.strip().lower() in {'1', 'true', 't', 'yes', 'y', 'on'}
    return False


def _flow_input_supply_when_first(input_item: dict[str, Any]) -> bool:
    if not isinstance(input_item, dict):
        return False
    flow_meta = input_item.get('flow') if isinstance(input_item.get('flow'), dict) else {}
    return bool(
        _flow_truthy_flag(input_item.get('flow_supply_when_first'))
        or _flow_truthy_flag(input_item.get('chain_supplied_when_first'))
        or _flow_truthy_flag(input_item.get('flow_required_when_first'))
        or _flow_truthy_flag(flow_meta.get('supply_when_first'))
        or _flow_truthy_flag(flow_meta.get('required_when_first'))
    )


def _flow_credential_like_input_name(name: str) -> bool:
    lowered = str(name or '').lower().strip()
    compact = re.sub(r'[^a-z0-9]+', '', lowered)
    if not compact:
        return False
    if lowered.startswith('credential(') or compact in {'credential', 'credentials', 'creds'}:
        return True
    if 'credential' in compact or 'creds' in compact:
        return True
    user_like = compact in {'user', 'username', 'login', 'loginuser', 'sshuser', 'sshusername'} or compact.endswith('username')
    pass_like = compact in {'password', 'pass', 'passwd', 'passphrase', 'sshpassword'} or compact.endswith('password') or compact.endswith('passphrase')
    return bool(user_like or pass_like)


def _flow_first_step_chain_supplied_input_names(gen_or_assignment: dict[str, Any] | None) -> list[str]:
    """Return inputs explicitly marked for first-step Flow supply."""
    if not isinstance(gen_or_assignment, dict):
        return []

    input_defs = gen_or_assignment.get('inputs')
    if not isinstance(input_defs, list):
        input_defs = gen_or_assignment.get('input_defs')
    names_from_defs: list[str] = []
    if isinstance(input_defs, list):
        for item in input_defs:
            if not isinstance(item, dict):
                continue
            name = str(item.get('name') or '').strip()
            if not name or not _flow_input_supply_when_first(item):
                continue
            names_from_defs.append(name)
    names_explicit_from_defs = bool(names_from_defs)

    if not names_from_defs:
        existing = gen_or_assignment.get('chain_supplied_inputs')
        if isinstance(existing, list):
            names_from_defs = [
                str(x or '').strip()
                for x in existing
                if str(x or '').strip() and _flow_credential_like_input_name(str(x or '').strip())
            ]

    if not names_from_defs:
        return []

    try:
        synthesized = set(_flow_synthesized_inputs())
    except Exception:
        synthesized = set()

    if names_explicit_from_defs:
        names: list[str] = []
        for name in names_from_defs:
            if name and name not in synthesized and name not in names:
                names.append(name)
        return names

    def _norm(value: str) -> str:
        return re.sub(r'[^a-z0-9]+', '', str(value or '').lower())

    direct: list[str] = []
    user_like: list[str] = []
    pass_like: list[str] = []
    for name in names_from_defs:
        if not name or name in synthesized:
            continue
        lowered = name.lower().strip()
        compact = _norm(name)
        if lowered.startswith('credential(') or compact in {'credential', 'credentials', 'creds'} or 'credential' in compact or 'creds' in compact:
            direct.append(name)
            continue
        if compact in {'user', 'username', 'login', 'loginuser', 'sshuser', 'sshusername'} or compact.endswith('username'):
            user_like.append(name)
            continue
        if compact in {'password', 'pass', 'passwd', 'passphrase', 'sshpassword'} or compact.endswith('password') or compact.endswith('passphrase'):
            pass_like.append(name)

    names: list[str] = []
    for name in direct:
        if name not in names:
            names.append(name)
    if pass_like and user_like:
        for name in user_like + pass_like:
            if name not in names:
                names.append(name)
    return names


def _flow_enabled_generator_defs_by_id() -> dict[str, dict[str, Any]]:
    by_id: dict[str, dict[str, Any]] = {}
    try:
        gens, _ = _flag_generators_from_enabled_sources()
        for gen in (gens or []):
            if not isinstance(gen, dict):
                continue
            gen_id = str(gen.get('id') or '').strip()
            if gen_id and gen_id not in by_id:
                by_id[gen_id] = gen
    except Exception:
        pass
    try:
        node_gens, _ = _flag_node_generators_from_enabled_sources()
        for gen in (node_gens or []):
            if not isinstance(gen, dict):
                continue
            gen_id = str(gen.get('id') or '').strip()
            if gen_id and gen_id not in by_id:
                by_id[gen_id] = gen
    except Exception:
        pass
    return by_id


def _flow_assignment_fact_names(assignment: dict[str, Any], keys: tuple[str, ...]) -> set[str]:
    facts: set[str] = set()
    if not isinstance(assignment, dict):
        return facts
    for key in keys:
        raw = assignment.get(key)
        if not isinstance(raw, list):
            continue
        for item in raw:
            if isinstance(item, dict):
                for nested_key in ('artifact', 'name', 'field'):
                    nested_value = str(item.get(nested_key) or '').strip()
                    if nested_value:
                        facts.add(nested_value)
                        break
                continue
            text = str(item or '').strip()
            if text:
                facts.add(text)
    return facts


def _flow_parallel_start_assignment_indexes(
    flag_assignments: list[dict[str, Any]] | Any,
    *,
    initial_facts: set[str] | None = None,
    gen_defs_by_id: dict[str, dict[str, Any]] | None = None,
) -> set[int]:
    if not isinstance(flag_assignments, list) or not flag_assignments:
        return set()
    try:
        available_initial = set(_flow_synthesized_inputs())
    except Exception:
        available_initial = set()
    if isinstance(initial_facts, set):
        available_initial |= set(initial_facts)

    starts: set[int] = set()
    provided_so_far: set[str] = set()
    for index, assignment in enumerate(flag_assignments or []):
        if not isinstance(assignment, dict):
            continue
        gen_def = None
        try:
            gen_id = str(assignment.get('id') or assignment.get('generator_id') or '').strip()
            if gen_id and isinstance(gen_defs_by_id, dict):
                gen_def = gen_defs_by_id.get(gen_id)
        except Exception:
            gen_def = None
        explicit_supplied_names = {
            str(x or '').strip()
            for x in (assignment.get('chain_supplied_inputs') or [])
            if str(x or '').strip()
        } if isinstance(assignment.get('chain_supplied_inputs'), list) else set()
        supplied_names = set(_flow_first_step_chain_supplied_input_names(gen_def if isinstance(gen_def, dict) else assignment)) | explicit_supplied_names
        required = _flow_assignment_fact_names(assignment, ('requires', 'input_fields_required', 'inputs'))
        required = {name for name in required if name and name not in available_initial and name not in supplied_names}
        if explicit_supplied_names:
            if required.issubset(provided_so_far):
                starts.add(index)
        elif not (required & provided_so_far):
            starts.add(index)
        provided_so_far |= _flow_assignment_fact_names(assignment, ('produces', 'output_fields', 'outputs'))
    return starts


def _flow_chain_supplied_credential_pair(*, scenario_label: str, node_id: str, gen_id: str) -> tuple[str, str]:
    seed_text = f"{scenario_label}|{node_id}|{gen_id}|first-step-credential"
    digest = hashlib.sha256(seed_text.encode('utf-8', errors='ignore')).hexdigest()
    return f"user_{digest[:6]}", f"pass_{digest[6:18]}"


def _flow_chain_supplied_value_for_input(
    name: str,
    *,
    scenario_label: str,
    node_id: str,
    gen_id: str,
    username: str,
    password: str,
    input_type: Any = 'string',
) -> Any:
    lowered = str(name or '').lower().strip()
    compact = re.sub(r'[^a-z0-9]+', '', lowered)
    if lowered.startswith('credential('):
        inner = lowered.split('(', 1)[1].rstrip(')')
        if 'password' in inner or 'pass' in inner:
            if 'user' in inner or 'login' in inner:
                return f"{username}:{password}"
            return password
        if 'user' in inner or 'login' in inner:
            return username
        return f"{username}:{password}"
    if compact in {'user', 'username', 'login', 'loginuser', 'sshuser', 'sshusername'} or compact.endswith('username'):
        return username
    if compact in {'password', 'pass', 'passwd', 'passphrase', 'sshpassword'} or compact.endswith('password') or compact.endswith('passphrase'):
        return password
    seed_text = f"{scenario_label}|{node_id}|{gen_id}|{name}|first-step-input"
    digest = hashlib.sha256(seed_text.encode('utf-8', errors='ignore')).hexdigest()
    input_type_text = str(input_type or 'string').strip().lower()
    if 'apikey' in compact or compact.endswith('api_key') or compact.startswith('apikey'):
        return f"api_{digest[:20]}"
    if 'token' in compact:
        return f"tok_{digest[:20]}"
    if 'secret' in compact:
        return f"secret_{digest[:16]}"
    if 'key' in compact:
        return f"key_{digest[:16]}"
    if 'code' in compact:
        return f"code_{digest[:10]}"
    if input_type_text in {'int', 'integer'}:
        return 100000 + (int(digest[:8], 16) % 900000)
    if input_type_text in {'float', 'number', 'numeric'}:
        return round(10 + ((int(digest[:8], 16) % 900000) / 1000), 3)
    if input_type_text in {'boolean', 'bool'}:
        return bool(int(digest[:2], 16) % 2)
    if input_type_text in {'json', 'object', 'dict', 'map'}:
        return {'value': f"value_{digest[:16]}"}
    if input_type_text in {'file', 'filepath', 'file_path', 'path', 'pathname'}:
        return f"/tmp/flow_{digest[:12]}.txt"
    if input_type_text in {'string_list', 'strings'} or input_type_text.endswith('[]'):
        return [f"value_{digest[:16]}"]
    if input_type_text in {'file_list', 'files'}:
        return [f"/tmp/flow_{digest[:12]}.txt"]
    return f"value_{digest[:16]}"


def _flow_chain_supplied_input_hint(values: dict[str, Any], *, sequence_label: str = 'Sequence 1') -> str:
    if not isinstance(values, dict) or not values:
        return ''
    display_parts: list[str] = []
    for key in sorted(values.keys()):
        value = values.get(key)
        if value is None:
            continue
        value_text = str(value).strip()
        if not value_text:
            continue
        key_text = str(key or '').strip()
        if ':' in value_text and key_text.lower().startswith('credential('):
            user_part, pass_part = value_text.split(':', 1)
            display_value = f"{user_part} / {pass_part}"
        elif isinstance(value, (dict, list)):
            try:
                display_value = json.dumps(value, sort_keys=True)
            except Exception:
                display_value = value_text
        else:
            display_value = value_text
        display_parts.append(f"{key_text}={display_value}" if key_text else display_value)
    if not display_parts:
        return ''
    joined = '; '.join(display_parts)
    label = 'input' if len(display_parts) == 1 else 'inputs'
    prefix = str(sequence_label or 'Sequence 1').strip() or 'Sequence 1'
    return f"{prefix} required supplied {label}: {joined}."


def _flow_clear_chain_supplied_inputs(assignment: dict[str, Any]) -> dict[str, Any]:
    if not isinstance(assignment, dict):
        return assignment
    names = [str(x or '').strip() for x in (assignment.get('chain_supplied_inputs') or []) if str(x or '').strip()] if isinstance(assignment.get('chain_supplied_inputs'), list) else []
    values = assignment.get('chain_supplied_input_values') if isinstance(assignment.get('chain_supplied_input_values'), dict) else {}
    hints = [str(x or '').strip() for x in (assignment.get('chain_supplied_input_hints') or []) if str(x or '').strip()] if isinstance(assignment.get('chain_supplied_input_hints'), list) else []

    if hints:
        try:
            current_hints = [str(x or '').strip() for x in (assignment.get('hints') or []) if str(x or '').strip()] if isinstance(assignment.get('hints'), list) else []
            current_hints = [hint for hint in current_hints if hint not in set(hints)]
            if current_hints:
                assignment['hints'] = current_hints
                if str(assignment.get('hint') or '').strip() in set(hints):
                    assignment['hint'] = current_hints[0]
            elif isinstance(assignment.get('hints'), list):
                assignment.pop('hints', None)
                if str(assignment.get('hint') or '').strip() in set(hints):
                    assignment.pop('hint', None)
        except Exception:
            pass

    for map_key in ('config_overrides', 'resolved_inputs'):
        try:
            current = assignment.get(map_key)
            if not isinstance(current, dict):
                continue
            updated = dict(current)
            for name in names:
                if name in updated and str(updated.get(name) or '') == str((values or {}).get(name) or ''):
                    updated.pop(name, None)
            if updated:
                assignment[map_key] = updated
            else:
                assignment.pop(map_key, None)
        except Exception:
            pass

    try:
        original_optional = [str(x or '').strip() for x in (assignment.get('chain_supplied_original_optional_inputs') or []) if str(x or '').strip()] if isinstance(assignment.get('chain_supplied_original_optional_inputs'), list) else []
        if original_optional:
            required = [str(x or '').strip() for x in (assignment.get('input_fields_required') or []) if str(x or '').strip()] if isinstance(assignment.get('input_fields_required'), list) else []
            optional = [str(x or '').strip() for x in (assignment.get('input_fields_optional') or []) if str(x or '').strip()] if isinstance(assignment.get('input_fields_optional'), list) else []
            required = [name for name in required if name not in set(original_optional)]
            for name in original_optional:
                if name and name not in optional:
                    optional.append(name)
            assignment['input_fields_required'] = sorted(required)
            assignment['input_fields_optional'] = sorted(optional)
    except Exception:
        pass

    for key in ('chain_supplied_inputs', 'chain_supplied_input_values', 'chain_supplied_input_hints', 'chain_supplied_original_optional_inputs', 'chain_supplied_sequence_index', 'chain_supplied_requirement_label', 'chain_supplied_required_title', 'chain_supplied_parallel_start'):
        assignment.pop(key, None)
    return assignment


def _flow_apply_first_step_chain_supplied_inputs(
    assignment: dict[str, Any],
    gen_def: dict[str, Any] | None = None,
    *,
    scenario_label: str,
    position: int = 0,
    supply_on_start: bool | None = None,
) -> dict[str, Any]:
    if not isinstance(assignment, dict):
        return assignment
    try:
        position_int = int(position or 0)
    except Exception:
        position_int = 0
    is_start = bool(supply_on_start) if supply_on_start is not None else (position_int == 0)
    if not is_start:
        return _flow_clear_chain_supplied_inputs(assignment)

    source = gen_def if isinstance(gen_def, dict) else assignment
    names = _flow_first_step_chain_supplied_input_names(source)
    if not names and source is not assignment:
        names = _flow_first_step_chain_supplied_input_names(assignment)
    if not names:
        return _flow_clear_chain_supplied_inputs(assignment)

    node_id = str(assignment.get('node_id') or '').strip()
    gen_id = str(assignment.get('id') or assignment.get('generator_id') or '').strip()
    username, password = _flow_chain_supplied_credential_pair(
        scenario_label=str(scenario_label or ''),
        node_id=node_id,
        gen_id=gen_id,
    )

    existing_config = assignment.get('config_overrides') if isinstance(assignment.get('config_overrides'), dict) else {}
    existing_inputs = assignment.get('resolved_inputs') if isinstance(assignment.get('resolved_inputs'), dict) else {}
    config_overrides = dict(existing_config or {})
    resolved_inputs = dict(existing_inputs or {})
    supplied_values: dict[str, Any] = {}
    input_meta_by_name: dict[str, dict[str, Any]] = {}
    try:
        raw_input_defs = source.get('inputs') if isinstance(source.get('inputs'), list) else source.get('input_defs')
        if isinstance(raw_input_defs, list):
            for item in raw_input_defs:
                if not isinstance(item, dict):
                    continue
                input_name = str(item.get('name') or '').strip()
                if input_name:
                    input_meta_by_name[input_name] = item
    except Exception:
        input_meta_by_name = {}
    for name in names:
        current = config_overrides.get(name)
        if current is None or (isinstance(current, str) and not current.strip()):
            current = resolved_inputs.get(name)
        if current is None or (isinstance(current, str) and not current.strip()):
            input_meta = input_meta_by_name.get(name) if isinstance(input_meta_by_name.get(name), dict) else {}
            current = _flow_chain_supplied_value_for_input(
                name,
                scenario_label=str(scenario_label or ''),
                node_id=node_id,
                gen_id=gen_id,
                username=username,
                password=password,
                input_type=(input_meta or {}).get('type'),
            )
        config_overrides[name] = current
        resolved_inputs[name] = current
        supplied_values[name] = current

    assignment['config_overrides'] = config_overrides
    assignment['resolved_inputs'] = resolved_inputs
    assignment['chain_supplied_inputs'] = list(names)
    assignment['chain_supplied_input_values'] = dict(supplied_values)
    sequence_number = max(1, position_int + 1)
    assignment['chain_supplied_sequence_index'] = sequence_number
    assignment['chain_supplied_requirement_label'] = f"Seq {sequence_number} required"
    assignment['chain_supplied_required_title'] = f"Required by sequence {sequence_number}"
    assignment['chain_supplied_parallel_start'] = bool(position_int > 0)

    try:
        input_fields = [str(x or '').strip() for x in (assignment.get('input_fields') or []) if str(x or '').strip()] if isinstance(assignment.get('input_fields'), list) else []
        required = [str(x or '').strip() for x in (assignment.get('input_fields_required') or []) if str(x or '').strip()] if isinstance(assignment.get('input_fields_required'), list) else []
        optional = [str(x or '').strip() for x in (assignment.get('input_fields_optional') or []) if str(x or '').strip()] if isinstance(assignment.get('input_fields_optional'), list) else []
        original_optional = [name for name in names if name in optional]
        for name in names:
            if name not in input_fields:
                input_fields.append(name)
            if name not in required:
                required.append(name)
        optional = [name for name in optional if name not in set(names)]
        assignment['input_fields'] = sorted(input_fields)
        assignment['input_fields_required'] = sorted(required)
        assignment['input_fields_optional'] = sorted(optional)
        if original_optional:
            assignment['chain_supplied_original_optional_inputs'] = sorted(original_optional)
    except Exception:
        pass

    try:
        input_defs = assignment.get('input_defs') if isinstance(assignment.get('input_defs'), list) else None
        if input_defs is None and isinstance(gen_def, dict) and isinstance(gen_def.get('inputs'), list):
            input_defs = list(gen_def.get('inputs') or [])
        if isinstance(input_defs, list):
            updated_defs: list[Any] = []
            for item in input_defs:
                if not isinstance(item, dict):
                    updated_defs.append(item)
                    continue
                item2 = dict(item)
                if str(item2.get('name') or '').strip() in set(names):
                    item2['required'] = True
                updated_defs.append(item2)
            assignment['input_defs'] = updated_defs
    except Exception:
        pass

    try:
        inputs_effective = [str(x or '').strip() for x in (assignment.get('inputs') or []) if str(x or '').strip()] if isinstance(assignment.get('inputs'), list) else []
        requires_effective = [str(x or '').strip() for x in (assignment.get('requires') or []) if str(x or '').strip()] if isinstance(assignment.get('requires'), list) else []
        for name in names:
            if name not in inputs_effective:
                inputs_effective.append(name)
            if _flow_looks_like_fact_ref(name) and name not in requires_effective:
                requires_effective.append(name)
        assignment['inputs'] = sorted(inputs_effective)
        assignment['requires'] = sorted(requires_effective)
    except Exception:
        pass

    hint_text = _flow_chain_supplied_input_hint(supplied_values, sequence_label=f"Sequence {sequence_number}")
    if hint_text:
        try:
            previous_hints = [str(x or '').strip() for x in (assignment.get('chain_supplied_input_hints') or []) if str(x or '').strip()] if isinstance(assignment.get('chain_supplied_input_hints'), list) else []
            current_hints = [str(x or '').strip() for x in (assignment.get('hints') or []) if str(x or '').strip()] if isinstance(assignment.get('hints'), list) else []
            if previous_hints:
                current_hints = [hint for hint in current_hints if hint not in set(previous_hints)]
            if hint_text not in current_hints:
                current_hints.append(hint_text)
            assignment['hints'] = current_hints
            if not str(assignment.get('hint') or '').strip() and current_hints:
                assignment['hint'] = current_hints[0]
            assignment['chain_supplied_input_hints'] = [hint_text]
        except Exception:
            pass
    return assignment


def _flow_apply_first_step_chain_supplied_inputs_to_assignments(
    flag_assignments: list[dict[str, Any]],
    chain_nodes: list[dict[str, Any]],
    *,
    scenario_label: str,
    gen_defs_by_id: dict[str, dict[str, Any]] | None = None,
) -> list[dict[str, Any]]:
    if not isinstance(flag_assignments, list):
        return flag_assignments
    try:
        start_positions = _flow_parallel_start_assignment_indexes(flag_assignments, gen_defs_by_id=gen_defs_by_id)
    except Exception:
        start_positions = {0} if flag_assignments else set()
    out: list[dict[str, Any]] = []
    for index, assignment in enumerate(flag_assignments or []):
        if not isinstance(assignment, dict):
            out.append(assignment)
            continue
        gen_def = None
        try:
            gen_id = str(assignment.get('id') or assignment.get('generator_id') or '').strip()
            if gen_id and isinstance(gen_defs_by_id, dict):
                gen_def = gen_defs_by_id.get(gen_id)
        except Exception:
            gen_def = None
        out.append(_flow_apply_first_step_chain_supplied_inputs(
            assignment,
            gen_def if isinstance(gen_def, dict) else None,
            scenario_label=scenario_label,
            position=index,
            supply_on_start=(index in start_positions),
        ))
    return out


def _flow_split_top_level_list(value: Any) -> list[str]:
    """Return strings from a list or comma text, ignoring commas inside facts."""
    if value is None:
        return []
    if isinstance(value, (list, tuple, set)):
        out: list[str] = []
        for item in value:
            if isinstance(item, dict):
                for key in ('artifact', 'name', 'field', 'value'):
                    text = str(item.get(key) or '').strip()
                    if text:
                        out.append(text)
                        break
                continue
            out.extend(_flow_split_top_level_list(item))
        return list(dict.fromkeys([item for item in out if item]))
    text = str(value or '').strip()
    if not text:
        return []
    parts: list[str] = []
    buf: list[str] = []
    depth = 0
    for ch in text.replace(';', ',').replace('\n', ','):
        if ch == '(':
            depth += 1
        elif ch == ')' and depth > 0:
            depth -= 1
        if ch == ',' and depth == 0:
            part = ''.join(buf).strip()
            if part:
                parts.append(part)
            buf = []
            continue
        buf.append(ch)
    part = ''.join(buf).strip()
    if part:
        parts.append(part)
    return list(dict.fromkeys(parts))


def _flow_append_unique_values(record: dict[str, Any], key: str, values: Any) -> None:
    if not isinstance(record, dict):
        return
    additions = _flow_split_top_level_list(values)
    if not additions:
        return
    existing = _flow_split_top_level_list(record.get(key))
    merged = list(dict.fromkeys([*existing, *additions]))
    record[key] = merged


def _flow_pivot_provider_label(value: Any) -> str:
    provider = str(value or '').strip().lower().replace('_', '-') or 'random'
    aliases = {
        'auto': 'random',
        'random': 'random',
        'vuln': 'vulnerability',
        'flag-node': 'flag-node-generator',
        'flagnode': 'flag-node-generator',
        'flag-nodegen': 'flag-node-generator',
        'ssh': 'ssh-fallback',
        'ssh-server': 'ssh-fallback',
        'fallback-ssh': 'ssh-fallback',
    }
    provider = aliases.get(provider, provider)
    labels = {
        'random': 'Random',
        'auto': 'Random',
        'vulnerability': 'Vulnerability',
        'flag-node-generator': 'Flag-Node-Generator',
        'ssh-fallback': 'Docker SSH',
        'manual': 'Manual',
        'none': 'Manual',
    }
    return labels.get(provider, provider or 'Random')


def _flow_pivot_context_sources(pivot_context: Any, preview: Any) -> list[dict[str, Any]]:
    sources: list[dict[str, Any]] = []

    def _add(value: Any) -> None:
        if isinstance(value, dict) and value not in sources:
            sources.append(value)

    _add(pivot_context)
    _add(preview)
    if isinstance(pivot_context, dict):
        _add(pivot_context.get('full_preview'))
        plan = pivot_context.get('plan')
        _add(plan)
        if isinstance(plan, dict):
            _add(plan.get('breakdowns'))
            _add(plan.get('pivoting_plan'))
        meta = pivot_context.get('metadata')
        _add(meta)
        if isinstance(meta, dict):
            _add(meta.get('generation_meta'))
            _add(meta.get('flow'))
    return sources


def _flow_node_lookup_for_pivot(
    preview: Any,
    chain_nodes: list[dict[str, Any]],
) -> tuple[list[dict[str, Any]], dict[str, dict[str, Any]]]:
    nodes: list[dict[str, Any]] = []
    try:
        if isinstance(preview, dict):
            graph_nodes, _links, _adj = _build_topology_graph_from_preview_plan(preview)
            if isinstance(graph_nodes, list):
                nodes.extend([dict(n) for n in graph_nodes if isinstance(n, dict)])
    except Exception:
        nodes = []
    try:
        existing_ids = {str(n.get('id') or '').strip() for n in nodes if isinstance(n, dict)}
        for node in (chain_nodes or []):
            if not isinstance(node, dict):
                continue
            node_id = str(node.get('id') or '').strip()
            if not node_id:
                continue
            if node_id in existing_ids:
                for existing in nodes:
                    if str(existing.get('id') or '').strip() == node_id:
                        existing.update({k: v for k, v in node.items() if v not in (None, '', [])})
                        break
            else:
                nodes.append(dict(node))
                existing_ids.add(node_id)
    except Exception:
        pass

    by_key: dict[str, dict[str, Any]] = {}
    for node in nodes:
        if not isinstance(node, dict):
            continue
        for raw_key in (
            node.get('id'),
            node.get('node_id'),
            node.get('name'),
            node.get('label'),
        ):
            key = str(raw_key or '').strip()
            if key:
                by_key.setdefault(key.lower(), node)
    return nodes, by_key


def _flow_pivot_node_name(node: dict[str, Any] | None) -> str:
    if not isinstance(node, dict):
        return ''
    return str(node.get('name') or node.get('label') or node.get('id') or node.get('node_id') or '').strip()


def _flow_pivot_node_id(node: dict[str, Any] | None) -> str:
    if not isinstance(node, dict):
        return ''
    return str(node.get('id') or node.get('node_id') or node.get('name') or '').strip()


def _flow_pivot_fact_subject(value: Any) -> str:
    text = str(value or '').strip()
    if not text or '(' not in text or not text.endswith(')'):
        return ''
    prefix = text.split('(', 1)[0].strip().lower()
    if prefix not in {'pivot', 'shell'}:
        return ''
    return text[text.find('(') + 1:-1].strip().lower()


def _flow_pivot_source_name_candidates(value: Any) -> set[str]:
    text = str(value or '').strip().lower()
    if not text:
        return set()
    names: set[str] = set()

    def _add(raw: str) -> None:
        candidate = str(raw or '').strip().lower()
        if not candidate:
            return
        names.add(candidate)
        base = candidate.split(' @ ', 1)[0].strip() if ' @ ' in candidate else candidate
        if base and base != candidate:
            names.add(base)
        if base.isdigit():
            names.add(f'docker-{base}')
        if base.startswith('docker-'):
            suffix = base.split('docker-', 1)[1].strip()
            if suffix.isdigit():
                names.add(suffix)

    _add(text)
    return {name for name in names if name}


def _flow_pivot_aliases_for_values(*values: Any) -> set[str]:
    aliases: set[str] = set()
    for value in values:
        aliases |= _flow_pivot_source_name_candidates(value)
    return aliases


def _flow_pivot_aliases_for_node(node: dict[str, Any] | None) -> set[str]:
    if not isinstance(node, dict):
        return set()
    return _flow_pivot_aliases_for_values(
        node.get('id'),
        node.get('node_id'),
        node.get('name'),
        node.get('label'),
    )


def _flow_pivot_aliases_for_assignment(assignment: dict[str, Any] | None) -> set[str]:
    if not isinstance(assignment, dict):
        return set()
    return _flow_pivot_aliases_for_values(
        assignment.get('node_id'),
        assignment.get('node_name'),
        assignment.get('name'),
        assignment.get('label'),
    )


def _flow_chain_pivot_aliases(chain_nodes: list[dict[str, Any]] | Any) -> set[str]:
    aliases: set[str] = set()
    if not isinstance(chain_nodes, list):
        return aliases
    for node in chain_nodes:
        aliases |= _flow_pivot_aliases_for_node(node if isinstance(node, dict) else None)
    return aliases


def _flow_prune_unavailable_or_self_pivot_facts(
    values: Any,
    chain_nodes: list[dict[str, Any]],
    *,
    current_node: dict[str, Any] | None = None,
    current_assignment: dict[str, Any] | None = None,
) -> list[str]:
    if not isinstance(values, (list, tuple, set)):
        return []
    chain_aliases = _flow_chain_pivot_aliases(chain_nodes)
    current_aliases = _flow_pivot_aliases_for_node(current_node) | _flow_pivot_aliases_for_assignment(current_assignment)
    out: list[str] = []
    for raw in values:
        value = str(raw or '').strip()
        if not value:
            continue
        subject = _flow_pivot_fact_subject(value)
        if subject:
            source_aliases = _flow_pivot_source_name_candidates(subject)
            if source_aliases and not (source_aliases & chain_aliases):
                continue
            if source_aliases and (source_aliases & current_aliases):
                continue
        if value not in out:
            out.append(value)
    return out


def _flow_pivot_match_nodes(
    nodes: list[dict[str, Any]],
    *,
    node_selector: Any = '',
    role_selector: Any = '',
) -> list[dict[str, Any]]:
    node_tokens = _flow_split_top_level_list(node_selector)
    role_tokens = [item.lower() for item in _flow_split_top_level_list(role_selector)]
    if not node_tokens and not role_tokens:
        return []
    out: list[dict[str, Any]] = []
    for node in nodes or []:
        if not isinstance(node, dict):
            continue
        node_values = [
            str(node.get('id') or '').strip(),
            str(node.get('node_id') or '').strip(),
            str(node.get('name') or '').strip(),
            str(node.get('label') or '').strip(),
            str(node.get('role') or '').strip(),
            str(node.get('type') or '').strip(),
        ]
        lowered_values = [value.lower() for value in node_values if value]
        if node_tokens:
            matched = False
            for token in node_tokens:
                token_low = token.lower()
                if token_low in lowered_values:
                    matched = True
                    break
                if any(fnmatch.fnmatchcase(value, token_low) for value in lowered_values):
                    matched = True
                    break
            if not matched:
                continue
        if role_tokens:
            role_value = str(node.get('role') or node.get('type') or '').strip().lower()
            if role_value not in role_tokens:
                continue
        out.append(node)
    return out


def _flow_pivot_provider_for_node(node: dict[str, Any]) -> str:
    if _flow_node_is_vuln(node):
        return 'vulnerability'
    if _flow_node_is_docker_role(node):
        return 'ssh-fallback'
    return 'manual'


def _flow_pivot_requested_provider(value: Any) -> str:
    provider = str(value or 'random').strip().lower().replace('_', '-') or 'random'
    aliases = {
        'auto': 'random',
        'vuln': 'vulnerability',
        'flag-node': 'flag-node-generator',
        'flagnode': 'flag-node-generator',
        'flag-nodegen': 'flag-node-generator',
        'ssh': 'ssh-fallback',
        'ssh-server': 'ssh-fallback',
        'fallback-ssh': 'ssh-fallback',
    }
    return aliases.get(provider, provider)


def _flow_infer_pivot_sources(
    nodes: list[dict[str, Any]],
    *,
    provider: str,
    excluded_ids: set[str] | None = None,
) -> list[dict[str, Any]]:
    excluded = set(excluded_ids or set())
    candidates: list[tuple[int, str, dict[str, Any]]] = []
    provider = _flow_pivot_requested_provider(provider)
    for node in nodes or []:
        if not isinstance(node, dict):
            continue
        node_id = _flow_pivot_node_id(node)
        if not node_id or node_id in excluded:
            continue
        is_docker = _flow_node_is_docker_role(node)
        is_vuln = _flow_node_is_vuln(node)
        if provider == 'vulnerability' and not is_vuln:
            continue
        if provider in {'flag-node-generator', 'ssh-fallback'} and not (is_docker and not is_vuln):
            continue
        if provider in {'random', 'auto'} and not (is_vuln or is_docker):
            continue
        effective = _flow_pivot_provider_for_node(node)
        if provider == 'flag-node-generator' and is_docker and not is_vuln:
            effective = 'flag-node-generator'
        priority_order = {'vulnerability': 0, 'flag-node-generator': 1, 'ssh-fallback': 2, 'manual': 9}
        candidates.append((priority_order.get(effective, 5), _flow_pivot_node_name(node).lower(), node))
    candidates.sort(key=lambda item: (item[0], item[1]))
    return [candidates[0][2]] if candidates else []


def _flow_pivot_rules_for_chain(
    preview: Any,
    chain_nodes: list[dict[str, Any]],
    *,
    pivot_context: Any | None = None,
) -> list[dict[str, Any]]:
    nodes, by_key = _flow_node_lookup_for_pivot(preview, chain_nodes)
    if not nodes:
        return []

    rules: list[dict[str, Any]] = []

    def _node_for_name(name: Any) -> dict[str, Any] | None:
        text = str(name or '').strip()
        if not text:
            return None
        return by_key.get(text.lower())

    def _add_rule(
        *,
        name: str,
        source_node: dict[str, Any],
        target_node: dict[str, Any],
        provider: Any,
        produces: Any = None,
        target_requires: Any = None,
        target_ports: Any = None,
        target_protocols: Any = None,
        exposure: Any = 'pivot-only',
    ) -> None:
        source_name = _flow_pivot_node_name(source_node)
        target_name = _flow_pivot_node_name(target_node)
        source_id = _flow_pivot_node_id(source_node)
        target_id = _flow_pivot_node_id(target_node)
        if not source_name or not target_name or not source_id or not target_id or source_id == target_id:
            return
        prod = _flow_split_top_level_list(produces) or [f'Shell({source_name})', f'Pivot({source_name})']
        req = _flow_split_top_level_list(target_requires) or [f'Pivot({source_name})']
        rule = {
            'name': str(name or 'Pivot').strip() or 'Pivot',
            'source_id': source_id,
            'source_name': source_name,
            'target_id': target_id,
            'target_name': target_name,
            'target_ip': _first_valid_ipv4(target_node.get('ip4') or target_node.get('ipv4') or target_node.get('ip') or ''),
            'provider': _flow_pivot_requested_provider(provider),
            'provider_label': _flow_pivot_provider_label(provider),
            'produces': prod,
            'target_requires': req,
            'target_ports': _flow_split_top_level_list(target_ports),
            'target_protocols': _flow_split_top_level_list(target_protocols),
            'exposure': str(exposure or 'pivot-only').strip() or 'pivot-only',
        }
        key = (rule['source_id'], rule['target_id'], tuple(rule['produces']), tuple(rule['target_requires']))
        for existing in rules:
            existing_key = (
                existing.get('source_id'),
                existing.get('target_id'),
                tuple(existing.get('produces') or []),
                tuple(existing.get('target_requires') or []),
            )
            if existing_key == key:
                return
        rules.append(rule)

    def _candidate_pivot_dicts(source: Any) -> list[dict[str, Any]]:
        if not isinstance(source, dict):
            return []
        candidates: list[dict[str, Any]] = []

        def _add_candidate(value: Any) -> None:
            if not isinstance(value, dict):
                return
            if value in candidates:
                return
            has_pivot_shape = any(
                isinstance(value.get(key), list)
                for key in ('rules', 'raw_items_serialized')
            ) or isinstance(value.get('pivoting'), dict) or isinstance(value.get('pivoting_plan'), dict)
            if has_pivot_shape:
                candidates.append(value)

        _add_candidate(source)
        _add_candidate(source.get('pivoting'))
        _add_candidate(source.get('pivoting_plan'))
        breakdowns = source.get('breakdowns') if isinstance(source.get('breakdowns'), dict) else None
        if isinstance(breakdowns, dict):
            _add_candidate(breakdowns.get('pivoting'))
        return candidates

    def _fact_name_from_pivot_fact(value: Any) -> str:
        text = str(value or '').strip()
        if not text:
            return ''
        low = text.lower()
        if low.startswith('pivot(') and text.endswith(')'):
            return text[text.find('(') + 1:-1].strip()
        return ''

    for source in _flow_pivot_context_sources(pivot_context, preview):
        for pivot_meta in _candidate_pivot_dicts(source):
            for raw_rule in (pivot_meta.get('rules') or []):
                if not isinstance(raw_rule, dict):
                    continue
                target_node = _node_for_name(raw_rule.get('target_node'))
                if not isinstance(target_node, dict):
                    continue
                pivot_nodes = raw_rule.get('pivot_nodes') if isinstance(raw_rule.get('pivot_nodes'), list) else []
                for pivot_name in pivot_nodes:
                    source_node = _node_for_name(pivot_name)
                    if not isinstance(source_node, dict):
                        continue
                    _add_rule(
                        name=str(raw_rule.get('name') or 'Pivot'),
                        source_node=source_node,
                        target_node=target_node,
                        provider=raw_rule.get('access_provider') or raw_rule.get('provider') or raw_rule.get('requested_access_provider'),
                        produces=raw_rule.get('produces'),
                        target_requires=raw_rule.get('target_requires'),
                        target_ports=raw_rule.get('target_ports'),
                        target_protocols=raw_rule.get('target_protocols'),
                        exposure=raw_rule.get('exposure'),
                    )

    if rules:
        return rules

    produces_by_fact: dict[str, list[dict[str, Any]]] = {}
    for node in nodes or []:
        if not isinstance(node, dict):
            continue
        produces = _flow_split_top_level_list(
            node.get('PivotProduces')
            or node.get('pivot_produces')
            or node.get('produces_pivot')
            or node.get('pivot_outputs')
        )
        for fact in produces:
            produces_by_fact.setdefault(fact, []).append(node)

    for target_node in nodes or []:
        if not isinstance(target_node, dict):
            continue
        target_requires = _flow_split_top_level_list(
            target_node.get('PivotRequires')
            or target_node.get('pivot_requires')
            or target_node.get('requires_pivot')
            or target_node.get('pivot_inputs')
        )
        if not target_requires:
            continue
        provider = (
            target_node.get('PivotAccessProvider')
            or target_node.get('pivot_access_provider')
            or target_node.get('access_provider')
            or target_node.get('provider')
            or 'random'
        )
        for required_fact in target_requires:
            source_nodes = list(produces_by_fact.get(required_fact) or [])
            if not source_nodes:
                pivot_name = _fact_name_from_pivot_fact(required_fact)
                source_node = _node_for_name(pivot_name)
                if isinstance(source_node, dict):
                    source_nodes = [source_node]
            for source_node in source_nodes:
                source_produces = _flow_split_top_level_list(
                    source_node.get('PivotProduces')
                    or source_node.get('pivot_produces')
                    or source_node.get('produces_pivot')
                    or source_node.get('pivot_outputs')
                )
                _add_rule(
                    name='Pivot',
                    source_node=source_node,
                    target_node=target_node,
                    provider=provider,
                    produces=source_produces,
                    target_requires=target_requires,
                    target_ports=target_node.get('SegmentationPorts') or target_node.get('segmentation_ports'),
                    target_protocols=target_node.get('SegmentationProtocols') or target_node.get('segmentation_protocols'),
                    exposure=target_node.get('SegmentationExposure') or target_node.get('segmentation_exposure') or 'pivot-only',
                )

    if rules:
        return rules

    pivot_items: list[dict[str, Any]] = []
    for source in _flow_pivot_context_sources(pivot_context, preview):
        for candidate in _candidate_pivot_dicts(source):
            raw_items = candidate.get('raw_items_serialized') if isinstance(candidate.get('raw_items_serialized'), list) else []
            for item in raw_items:
                if isinstance(item, dict):
                    pivot_items.append(item)

    seen_item_keys: set[str] = set()
    for item in pivot_items:
        item_key = json.dumps(item, sort_keys=True, default=str)
        if item_key in seen_item_keys:
            continue
        seen_item_keys.add(item_key)
        provider = _flow_pivot_requested_provider(item.get('access_provider') or item.get('pivot_provider') or item.get('provider') or 'random')
        explicit_targets = _flow_pivot_match_nodes(
            nodes,
            node_selector=item.get('target_node') or item.get('target'),
            role_selector=item.get('target_role'),
        )
        explicit_target_ids = {_flow_pivot_node_id(node) for node in explicit_targets if isinstance(node, dict)}
        source_nodes = _flow_pivot_match_nodes(
            nodes,
            node_selector=item.get('pivot_node') or item.get('source_node') or item.get('source'),
            role_selector=item.get('pivot_role') or item.get('source_role'),
        )
        if not source_nodes:
            source_nodes = _flow_infer_pivot_sources(nodes, provider=provider, excluded_ids=explicit_target_ids)
        if not source_nodes:
            continue
        source_ids = {_flow_pivot_node_id(node) for node in source_nodes if isinstance(node, dict)}
        target_nodes = explicit_targets
        if not target_nodes:
            target_nodes = [
                node for node in nodes
                if isinstance(node, dict)
                and _flow_node_is_docker_role(node)
                and _flow_pivot_node_id(node) not in source_ids
            ]
        for source_node in source_nodes:
            for target_node in target_nodes:
                _add_rule(
                    name=str(item.get('selected') or item.get('name') or 'Pivot'),
                    source_node=source_node,
                    target_node=target_node,
                    provider=provider,
                    produces=item.get('produces'),
                    target_requires=item.get('target_requires') or item.get('requires_target'),
                    target_ports=item.get('target_ports') or item.get('ports'),
                    target_protocols=item.get('target_protocols') or item.get('protocols'),
                    exposure=item.get('exposure') or item.get('target_exposure') or 'pivot-only',
                )
    return rules


def _flow_expand_chain_for_topology_requirements(
    nodes: list[dict[str, Any]],
    chain_nodes: list[dict[str, Any]],
    preview: Any | None = None,
    *,
    include_all_topology_vulns: bool = False,
    include_all_topology_pivots: bool = False,
    pivot_context: Any | None = None,
) -> tuple[list[dict[str, Any]], dict[str, Any]]:
    """Append topology-required Flow nodes without truncating the user's chain.

    The caller still performs normal assignment and dependency ordering after this,
    so this helper only guarantees that requested topology nodes are present once.
    """
    requested_vulns = bool(include_all_topology_vulns)
    requested_pivots = bool(include_all_topology_pivots)
    info: dict[str, Any] = {
        'requested': {
            'include_all_topology_vulns': requested_vulns,
            'include_all_topology_pivots': requested_pivots,
        },
        'added_node_ids': [],
        'added_vuln_node_ids': [],
        'added_pivot_node_ids': [],
        'effective_length': len(chain_nodes or []),
    }
    if not requested_vulns and not requested_pivots:
        return list(chain_nodes or []), info

    all_nodes = [node for node in (nodes or []) if isinstance(node, dict)]
    if not all_nodes:
        try:
            built_nodes, _links, _adj = _build_topology_graph_from_preview_plan(preview) if isinstance(preview, dict) else ([], [], {})
            all_nodes = [node for node in (built_nodes or []) if isinstance(node, dict)]
        except Exception:
            all_nodes = []

    id_to_node: dict[str, dict[str, Any]] = {}
    key_to_id: dict[str, str] = {}

    def _index_node(node: dict[str, Any]) -> None:
        node_id = _flow_pivot_node_id(node)
        if not node_id:
            return
        if node_id not in id_to_node:
            id_to_node[node_id] = node
        for raw in (
            node_id,
            node.get('id'),
            node.get('node_id'),
            node.get('name'),
            node.get('label'),
            node.get('hostname'),
        ):
            key = str(raw or '').strip().lower()
            if key and key not in key_to_id:
                key_to_id[key] = node_id

    for node in all_nodes:
        _index_node(node)
    for node in (chain_nodes or []):
        if isinstance(node, dict):
            _index_node(node)

    expanded = list(chain_nodes or [])
    present_ids = {
        _flow_pivot_node_id(node)
        for node in expanded
        if isinstance(node, dict) and _flow_pivot_node_id(node)
    }
    added_ids: list[str] = []
    added_vuln_ids: list[str] = []
    added_pivot_ids: list[str] = []

    def _resolve_id(raw: Any) -> str:
        text = str(raw or '').strip()
        if not text:
            return ''
        if text in id_to_node:
            return text
        return key_to_id.get(text.lower(), '')

    def _append_node(node_id: str, bucket: list[str]) -> None:
        resolved_id = _resolve_id(node_id)
        if not resolved_id or resolved_id in present_ids:
            return
        node = id_to_node.get(resolved_id)
        if not isinstance(node, dict):
            return
        expanded.append(node)
        present_ids.add(resolved_id)
        added_ids.append(resolved_id)
        if resolved_id not in bucket:
            bucket.append(resolved_id)

    if requested_vulns:
        for node in all_nodes:
            node_id = _flow_pivot_node_id(node)
            if node_id and _flow_node_is_vuln(node):
                _append_node(node_id, added_vuln_ids)

    if requested_pivots:
        try:
            pivot_rules = _flow_pivot_rules_for_chain(preview, expanded, pivot_context=pivot_context)
        except Exception:
            pivot_rules = []
        for rule in pivot_rules or []:
            if not isinstance(rule, dict):
                continue
            _append_node(str(rule.get('source_id') or ''), added_pivot_ids)
            _append_node(str(rule.get('target_id') or ''), added_pivot_ids)
        for rule in pivot_rules or []:
            if not isinstance(rule, dict):
                continue
            source_id = _resolve_id(rule.get('source_id'))
            target_id = _resolve_id(rule.get('target_id'))
            if not source_id or not target_id or source_id == target_id:
                continue
            try:
                source_index = next(
                    idx for idx, node in enumerate(expanded)
                    if isinstance(node, dict) and _flow_pivot_node_id(node) == source_id
                )
                target_index = next(
                    idx for idx, node in enumerate(expanded)
                    if isinstance(node, dict) and _flow_pivot_node_id(node) == target_id
                )
            except StopIteration:
                continue
            if source_index > target_index:
                source_node = expanded.pop(source_index)
                expanded.insert(target_index, source_node)

    info['added_node_ids'] = added_ids
    info['added_vuln_node_ids'] = added_vuln_ids
    info['added_pivot_node_ids'] = added_pivot_ids
    info['effective_length'] = len(expanded)
    return expanded, info


def _flow_add_assignment_hint(assignment: dict[str, Any], hint_text: str) -> None:
    text = _flow_strip_ids_from_hint(str(hint_text or '').strip())
    if not isinstance(assignment, dict) or not text:
        return
    for key in ('pivot_hints', 'hints'):
        existing = [str(x or '').strip() for x in (assignment.get(key) or []) if str(x or '').strip()] if isinstance(assignment.get(key), list) else []
        if text not in existing:
            existing.append(text)
        assignment[key] = existing
    levels = assignment.get('hint_levels') if isinstance(assignment.get('hint_levels'), dict) else {}
    levels = dict(levels or {})
    low_values = [str(x or '').strip() for x in (levels.get('low') or []) if str(x or '').strip()] if isinstance(levels.get('low'), list) else []
    if text not in low_values:
        low_values.append(text)
    levels['low'] = low_values
    assignment['hint_levels'] = levels
    if not str(assignment.get('hint') or '').strip():
        assignment['hint'] = text


def _flow_apply_pivot_context_to_assignments(
    flag_assignments: list[dict[str, Any]],
    chain_nodes: list[dict[str, Any]],
    *,
    preview: Any = None,
    pivot_context: Any | None = None,
    scenario_label: str = '',
) -> list[dict[str, Any]]:
    if not isinstance(flag_assignments, list) or not flag_assignments:
        return flag_assignments
    if not isinstance(chain_nodes, list) or not chain_nodes:
        return flag_assignments

    try:
        rules = _flow_pivot_rules_for_chain(preview, chain_nodes, pivot_context=pivot_context)
    except Exception:
        rules = []

    node_by_id: dict[str, dict[str, Any]] = {}
    # Build a comprehensive lookup of all chain node identifiers so we can
    # detect when a pivot SOURCE node is absent from the chain entirely.
    _chain_all_ids: set[str] = set()
    for node in chain_nodes:
        if not isinstance(node, dict):
            continue
        node_id = _flow_pivot_node_id(node)
        if node_id:
            node_by_id[node_id] = node
        for _alias in _flow_pivot_aliases_for_node(node):
            if _alias:
                node_by_id.setdefault(_alias, node)
                _chain_all_ids.add(_alias)

    def _pivot_fact_subject(value: Any) -> str:
        text = str(value or '').strip()
        if not text or '(' not in text or not text.endswith(')'):
            return ''
        prefix = text.split('(', 1)[0].strip().lower()
        if prefix not in {'pivot', 'shell'}:
            return ''
        return text[text.find('(') + 1:-1].strip().lower()

    def _pivot_source_name_candidates(value: Any) -> set[str]:
        text = str(value or '').strip().lower()
        if not text:
            return set()
        names: set[str] = set()

        def _add(raw: str) -> None:
            candidate = str(raw or '').strip().lower()
            if not candidate:
                return
            names.add(candidate)
            base = candidate.split(' @ ', 1)[0].strip() if ' @ ' in candidate else candidate
            if base and base != candidate:
                names.add(base)
            if base.isdigit():
                names.add(f'docker-{base}')
            if base.startswith('docker-'):
                suffix = base.split('docker-', 1)[1].strip()
                if suffix.isdigit():
                    names.add(suffix)

        _add(text)
        return {name for name in names if name}

    def _pivot_fact_source_in_chain(value: Any) -> bool:
        subject = _pivot_fact_subject(value)
        if not subject:
            return True
        source_names = _pivot_source_name_candidates(subject)
        return any(source_name in _chain_all_ids for source_name in source_names)

    def _rule_source_in_chain(rule: dict[str, Any], source_id: str) -> bool:
        source_name = str(rule.get('source_name') or '').strip()
        source_names = _pivot_source_name_candidates(source_id) | _pivot_source_name_candidates(source_name)
        return any(source_name in _chain_all_ids for source_name in source_names)

    def _rule_source_requires(rule: dict[str, Any], requires: list[str], source_id: str) -> list[str]:
        produces = set(_flow_split_top_level_list(rule.get('produces')))
        matched = [fact for fact in requires if fact in produces]
        if matched:
            return matched
        source_names = _pivot_source_name_candidates(source_id) | _pivot_source_name_candidates(rule.get('source_name'))
        matched = [fact for fact in requires if _pivot_fact_subject(fact) in source_names]
        if matched:
            return matched
        synthetic_requires = [fact for fact in requires if _pivot_fact_subject(fact)]
        return synthetic_requires or list(requires)

    def _remove_assignment_values(target: dict[str, Any], key: str, values: list[str]) -> None:
        remove = {str(value or '').strip() for value in (values or []) if str(value or '').strip()}
        if not remove or not isinstance(target.get(key), list):
            return
        target[key] = [
            item for item in (target.get(key) or [])
            if str(item or '').strip() not in remove
        ]

    def _remove_absent_pivot_facts(target: dict[str, Any], key: str) -> None:
        if not isinstance(target.get(key), list):
            return
        target[key] = [
            item for item in (target.get(key) or [])
            if not (_pivot_fact_subject(item) and not _pivot_fact_source_in_chain(item))
        ]

    def _remove_self_pivot_facts(target: dict[str, Any], key: str, current_names: set[str]) -> None:
        if not isinstance(target.get(key), list) or not current_names:
            return
        target[key] = [
            item for item in (target.get(key) or [])
            if not (_pivot_fact_subject(item) and (_pivot_source_name_candidates(_pivot_fact_subject(item)) & current_names))
        ]

    def _pivot_provider_priority(value: Any) -> int:
        provider = _flow_pivot_requested_provider(value)
        return {
            'vulnerability': 0,
            'flag-node-generator': 1,
            'ssh-fallback': 2,
            'manual': 3,
            'random': 4,
            'auto': 4,
        }.get(provider, 5)

    chain_index_by_id: dict[str, int] = {}
    for index, node in enumerate(chain_nodes or []):
        if not isinstance(node, dict):
            continue
        node_id_for_index = _flow_pivot_node_id(node)
        if node_id_for_index:
            chain_index_by_id.setdefault(node_id_for_index, index)

    cyclic_pivot_requires_by_target: dict[str, set[str]] = {}
    try:
        pair_rules: dict[tuple[str, str], list[dict[str, Any]]] = {}
        for rule in rules or []:
            if not isinstance(rule, dict):
                continue
            source_id = str(rule.get('source_id') or '').strip()
            target_id = str(rule.get('target_id') or '').strip()
            if not source_id or not target_id or source_id == target_id:
                continue
            pair_key = tuple(sorted((source_id, target_id)))
            pair_rules.setdefault(pair_key, []).append(rule)
        for (_left_id, _right_id), related_rules in pair_rules.items():
            directions = {
                (str(rule.get('source_id') or '').strip(), str(rule.get('target_id') or '').strip())
                for rule in related_rules
                if isinstance(rule, dict)
            }
            if (_left_id, _right_id) not in directions or (_right_id, _left_id) not in directions:
                continue
            source_priority: dict[str, int] = {}
            for rule in related_rules:
                source_id = str(rule.get('source_id') or '').strip()
                if not source_id:
                    continue
                priority = _pivot_provider_priority(rule.get('provider'))
                source_priority[source_id] = min(source_priority.get(source_id, priority), priority)
            if not source_priority:
                continue
            bootstrap_id = min(
                source_priority,
                key=lambda node_id: (
                    source_priority.get(node_id, 5),
                    chain_index_by_id.get(node_id, 10**9),
                    node_id,
                ),
            )
            for rule in related_rules:
                target_id = str(rule.get('target_id') or '').strip()
                source_id = str(rule.get('source_id') or '').strip()
                if target_id != bootstrap_id or source_id == bootstrap_id:
                    continue
                requires_to_prune = _flow_split_top_level_list(rule.get('target_requires'))
                if requires_to_prune:
                    cyclic_pivot_requires_by_target.setdefault(target_id, set()).update(requires_to_prune)
    except Exception:
        cyclic_pivot_requires_by_target = {}

    out: list[dict[str, Any]] = []
    for index, assignment in enumerate(flag_assignments):
        if not isinstance(assignment, dict):
            out.append(assignment)
            continue
        a2 = dict(assignment)
        node_id = str(a2.get('node_id') or '').strip()
        if not node_id and index < len(chain_nodes):
            node_id = _flow_pivot_node_id(chain_nodes[index])
            if node_id:
                a2['node_id'] = node_id
        node = (node_by_id.get(node_id) or node_by_id.get(node_id.lower())) if node_id else None
        node_name = _flow_pivot_node_name(node) if isinstance(node, dict) else node_id
        current_names: set[str] = set()
        current_names |= _flow_pivot_aliases_for_node(node if isinstance(node, dict) else None)
        current_names |= _flow_pivot_aliases_for_assignment(a2)
        current_names |= _pivot_source_name_candidates(node_id)
        current_names |= _pivot_source_name_candidates(node_name)
        pivot_entries: list[dict[str, Any]] = [entry for entry in (a2.get('pivot') or []) if isinstance(entry, dict)] if isinstance(a2.get('pivot'), list) else []
        # Collect target-side hint parts so all pivot sources for this node are
        # consolidated into a single hint instead of one hint per source rule.
        _pivot_target_hint_parts: list[tuple[str, list[str], str]] = []  # (source_name, requires, port_text)

        for rule in rules:
            source_id = str(rule.get('source_id') or '').strip()
            target_id = str(rule.get('target_id') or '').strip()
            if node_id and source_id and node_id == source_id:
                produces = _flow_split_top_level_list(rule.get('produces'))
                _flow_append_unique_values(a2, 'produces', produces)
                _flow_append_unique_values(a2, 'outputs', produces)
                source_targets = str(rule.get('target_name') or rule.get('target_id') or '').strip()
                provider_label = str(rule.get('provider_label') or _flow_pivot_provider_label(rule.get('provider')))
                hint = (
                    f"Pivot source: establish access on {node_name or source_id} "
                    f"using {provider_label} to unlock pivot-only target {source_targets}. "
                    f"Produces: {', '.join(produces)}."
                )
                _flow_add_assignment_hint(a2, hint)
                pivot_entries.append({
                    'role': 'source',
                    'provider': rule.get('provider'),
                    'provider_label': provider_label,
                    'source': rule.get('source_name') or source_id,
                    'target': rule.get('target_name') or target_id,
                    'produces': produces,
                    'requires': [],
                })
            if node_id and target_id and node_id == target_id:
                requires = _flow_split_top_level_list(rule.get('target_requires'))
                source_requires = _rule_source_requires(rule, requires, source_id)
                cyclic_pruned_requires = sorted(
                    set(source_requires) & set(cyclic_pivot_requires_by_target.get(target_id) or set())
                )
                # Only treat the pivot fact as a hard generator dependency when the
                # pivot source node is also present in this chain.  If it is absent
                # the fact will never be produced and would permanently invalidate
                # the chain order check, blocking all flag execution.
                _source_in_chain = _rule_source_in_chain(rule, source_id)
                if cyclic_pruned_requires:
                    _remove_assignment_values(a2, 'requires', cyclic_pruned_requires)
                    _remove_assignment_values(a2, 'inputs', cyclic_pruned_requires)
                elif _source_in_chain:
                    _flow_append_unique_values(a2, 'requires', source_requires)
                    _flow_append_unique_values(a2, 'inputs', source_requires)
                else:
                    _remove_assignment_values(a2, 'requires', source_requires)
                    _remove_assignment_values(a2, 'inputs', source_requires)
                provider_label = str(rule.get('provider_label') or _flow_pivot_provider_label(rule.get('provider')))
                source_name = str(rule.get('source_name') or rule.get('source_id') or '').strip()
                ports = _flow_split_top_level_list(rule.get('target_ports'))
                port_text = f" Ports: {', '.join(ports)}." if ports else ''
                # Defer hint emission - collect parts and consolidate below.
                if not cyclic_pruned_requires:
                    _pivot_target_hint_parts.append((source_name, list(source_requires), port_text))
                pivot_entries.append({
                    'role': 'target',
                    'provider': rule.get('provider'),
                    'provider_label': provider_label,
                    'source': source_name,
                    'target': rule.get('target_name') or target_id,
                    'requires': [fact for fact in source_requires if fact not in set(cyclic_pruned_requires)],
                    'produces': [],
                    'target_ports': ports,
                    'target_protocols': _flow_split_top_level_list(rule.get('target_protocols')),
                    'exposure': rule.get('exposure') or 'pivot-only',
                })

        # Emit a single consolidated "Pivot required" hint for this assignment.
        if _pivot_target_hint_parts:
            if len(_pivot_target_hint_parts) == 1:
                s_name, s_requires, s_port_text = _pivot_target_hint_parts[0]
                _fact_label = 'Required fact' if len(s_requires) == 1 else 'Required facts'
                _flow_add_assignment_hint(
                    a2,
                    f"Pivot required: reach {node_name or node_id} through {s_name} "
                    f"after the pivot source is solved. {_fact_label}: {', '.join(s_requires)}.{s_port_text}",
                )
            else:
                _all_sources = ', '.join(p[0] for p in _pivot_target_hint_parts if p[0])
                _all_facts: list[str] = []
                _seen_facts: set[str] = set()
                for _, _reqs, _ in _pivot_target_hint_parts:
                    for _f in _reqs:
                        if _f not in _seen_facts:
                            _seen_facts.add(_f)
                            _all_facts.append(_f)
                _fact_label = 'Required fact' if len(_all_facts) == 1 else 'Required facts'
                _flow_add_assignment_hint(
                    a2,
                    f"Pivot required: reach {node_name or node_id} through {_all_sources} "
                    f"after the pivot sources are solved. {_fact_label}: {', '.join(_all_facts)}.",
                )

        _remove_absent_pivot_facts(a2, 'requires')
        _remove_absent_pivot_facts(a2, 'inputs')
        _remove_self_pivot_facts(a2, 'requires', current_names)
        _remove_self_pivot_facts(a2, 'inputs', current_names)

        if pivot_entries:
            deduped: list[dict[str, Any]] = []
            seen: set[str] = set()
            for entry in pivot_entries:
                key = json.dumps(entry, sort_keys=True, default=str)
                if key in seen:
                    continue
                seen.add(key)
                deduped.append(entry)
            a2['pivot'] = deduped
            a2['pivot_summary'] = [
                f"{entry.get('role')}: {entry.get('source')} -> {entry.get('target')}"
                for entry in deduped
                if entry.get('source') or entry.get('target')
            ]
            a2['pivot_inputs'] = sorted(set(_flow_split_top_level_list(a2.get('requires'))) & {fact for rule in rules for fact in _flow_split_top_level_list(rule.get('target_requires'))})
            a2['pivot_outputs'] = sorted(set(_flow_split_top_level_list(a2.get('produces'))) & {fact for rule in rules for fact in _flow_split_top_level_list(rule.get('produces'))})
        out.append(a2)
    return out


def _flow_normalize_dependency_level(raw: Any) -> int:
    try:
        level = int(raw)
    except Exception:
        level = 3
    return max(1, min(5, level))

def _flow_normalize_fact_override(raw: Any) -> dict[str, list[str]] | None:
    if not isinstance(raw, dict):
        return None
    arts = raw.get('artifacts') if isinstance(raw.get('artifacts'), list) else []
    fields = raw.get('fields') if isinstance(raw.get('fields'), list) else []
    def _is_flag_fact(name: str) -> bool:
        s = str(name or '').strip()
        if not s:
            return False
        if s.lower() == 'flag(flag_id)' or s == 'Flag':
            return True
        return s.startswith('Flag(') or s.startswith('flag(')

    out_artifacts = [
        str(x or '').strip()
        for x in (arts or [])
        if str(x or '').strip()
    ]
    out_fields = [
        str(x or '').strip()
        for x in (fields or [])
        if str(x or '').strip()
    ]
    if not out_artifacts and not out_fields:
        return None
    return {
        'artifacts': out_artifacts,
        'fields': out_fields,
    }


def _flow_generator_seed(*, base_seed: Any, scenario_norm: str, node_id: str, gen_id: str, occurrence_idx: int = 0) -> str:
    """Build the deterministic generator seed for Flow.

    NOTE: This seed intentionally includes an occurrence index so a Flow chain may repeat the
    same (node_id, generator_id) without producing an *exact* duplicate configuration.
    """
    return _flow_generator_seed_impl(
        base_seed=base_seed,
        scenario_norm=scenario_norm,
        node_id=node_id,
        gen_id=gen_id,
        occurrence_idx=occurrence_idx,
    )



def _flow_strip_runtime_sensitive_fields(flag_assignments: list[dict[str, Any]]) -> list[dict[str, Any]]:
    """Return a copy of assignments safe to persist in preview-plan metadata.

    NOTE: As of the "flags are required outputs" contract, realized flag strings are part
    of the sequencing contract and are allowed to persist so the UI can display them.
    """
    if not isinstance(flag_assignments, list):
        return flag_assignments
    out: list[dict[str, Any]] = []
    for a in (flag_assignments or []):
        if not isinstance(a, dict):
            continue
        a2 = dict(a)
        a2.pop('runtime_flags', None)
        a2.pop('runtime_outputs', None)
        # Keep resolved inputs/outputs so the Flow UI can restore values after refresh.
        # Effective generator config may include secrets and should not be persisted.
        a2.pop('config', None)
        out.append(a2)
    return out


def _flow_first_hints_from_assignments(flag_assignments: list[dict[str, Any]] | Any) -> list[str]:
    """Return participant-facing hints for Flow assignments that can start immediately."""
    if not isinstance(flag_assignments, list) or not flag_assignments:
        return []

    out: list[str] = []

    def _add_many(values: Any) -> None:
        if isinstance(values, str):
            candidates = [values]
        elif isinstance(values, (list, tuple, set)):
            candidates = list(values)
        else:
            candidates = []
        for item in candidates:
            text = str(item or '').strip()
            if text and text not in out:
                out.append(text)

    try:
        start_positions = _flow_parallel_start_assignment_indexes(
            flag_assignments,
            gen_defs_by_id=_flow_enabled_generator_defs_by_id(),
        )
    except Exception:
        start_positions = {0}
    for index in sorted(start_positions or {0}):
        if index < 0 or index >= len(flag_assignments):
            continue
        assignment = flag_assignments[index]
        if not isinstance(assignment, dict):
            continue
        levels = assignment.get('hint_levels') if isinstance(assignment.get('hint_levels'), dict) else {}
        if isinstance(levels, dict):
            _add_many(levels.get('low'))
        _add_many(assignment.get('chain_supplied_input_hints'))
    if not out:
        first = flag_assignments[0]
        if not isinstance(first, dict):
            return []
        _add_many(first.get('hints'))
    if not out:
        first = flag_assignments[0]
        if not isinstance(first, dict):
            return []
        _add_many(first.get('hint'))
    return out


def _flow_enrich_saved_flag_assignments(
    flag_assignments: list[dict[str, Any]],
    chain_nodes: list[dict[str, Any]],
    *,
    scenario_label: str,
) -> list[dict[str, Any]]:
    """Best-effort enrichment for persisted Flow assignments.

    Older preview plans may persist `flag_assignments` that predate newer UI fields
    (e.g., `description_hints`) or contain hints that still include ids.

    We keep the chosen generator per node, but refresh:
    - `description_hints` from current enabled catalogs
    - `hint_templates`/`hint_template` from current enabled catalogs
    - rendered `hints`/`hint` for the current chain order
    - `next_node_id`/`next_node_name`
    """
    if not isinstance(flag_assignments, list) or not isinstance(chain_nodes, list):
        return flag_assignments

    # Map ids -> names for THIS/NEXT substitution.
    id_to_name: dict[str, str] = {}
    id_to_ip: dict[str, str] = {}
    chain_ids: list[str] = []
    vuln_names_by_id: dict[str, list[str]] = {}
    vuln_field_seen_by_id: set[str] = set()
    resolved_ip_by_id: dict[str, str] = {}
    try:
        for fa in (flag_assignments or []):
            if not isinstance(fa, dict):
                continue
            nid = str(fa.get('node_id') or '').strip()
            if not nid:
                continue
            ri = fa.get('resolved_inputs') if isinstance(fa.get('resolved_inputs'), dict) else None
            if not isinstance(ri, dict):
                continue
            for key in ('Knowledge(ip)', 'target_ip', 'host_ip', 'ip4', 'ipv4', 'ip'):
                val = ri.get(key)
                if val is None:
                    continue
                ip_val = _first_valid_ipv4(val)
                if ip_val:
                    resolved_ip_by_id[nid] = ip_val
                    break
    except Exception:
        resolved_ip_by_id = {}
    for n in (chain_nodes or []):
        if not isinstance(n, dict):
            continue
        nid = str(n.get('id') or '').strip()
        if not nid:
            continue
        chain_ids.append(nid)
        nm = str(n.get('name') or '').strip()
        id_to_name[nid] = nm or nid
        try:
            node_ip_val = _first_valid_ipv4(n.get('ip4') or n.get('ipv4') or n.get('ip') or '')
            ip_val = node_ip_val or resolved_ip_by_id.get(nid)
            if ip_val:
                id_to_ip[nid] = ip_val
        except Exception:
            pass
        try:
            raw = n.get('vulnerabilities')
            names: list[str] = []
            if isinstance(raw, list):
                vuln_field_seen_by_id.add(nid)
                for v in raw:
                    if isinstance(v, str):
                        s = v.strip()
                        if s:
                            names.append(s)
                        continue
                    if isinstance(v, dict):
                        for key in ('name', 'title', 'id', 'vuln', 'cve', 'cve_id', 'slug'):
                            val = v.get(key)
                            if isinstance(val, str) and val.strip():
                                names.append(val.strip())
                                break
            if names:
                uniq = []
                seen = set()
                for nm in names:
                    if nm and nm not in seen:
                        seen.add(nm)
                        uniq.append(nm)
                vuln_names_by_id[nid] = uniq
        except Exception:
            pass

    # Build a by-id view of currently enabled generators.
    by_id: dict[str, dict[str, Any]] = {}
    try:
        gens, _ = _flag_generators_from_enabled_sources()
        for g in (gens or []):
            if not isinstance(g, dict):
                continue
            gid = str(g.get('id') or '').strip()
            if gid and gid not in by_id:
                by_id[gid] = g
    except Exception:
        pass
    try:
        node_gens, _ = _flag_node_generators_from_enabled_sources()
        for g in (node_gens or []):
            if not isinstance(g, dict):
                continue
            gid = str(g.get('id') or '').strip()
            if gid and gid not in by_id:
                by_id[gid] = g
    except Exception:
        pass

    try:
        plugins_by_id = _flow_enabled_plugin_contracts_by_id()
    except Exception:
        plugins_by_id = {}

    def _refresh_assignment_io_metadata(assignment: dict[str, Any], gen_def: dict[str, Any] | None) -> None:
        if not isinstance(assignment, dict) or not isinstance(gen_def, dict):
            return

        input_defs = list(gen_def.get('inputs') or []) if isinstance(gen_def.get('inputs'), list) else []
        output_defs = list(gen_def.get('outputs') or []) if isinstance(gen_def.get('outputs'), list) else []

        input_fields_all = sorted([
            str(item.get('name') or '').strip()
            for item in input_defs
            if isinstance(item, dict) and str(item.get('name') or '').strip()
        ])
        input_fields_required = sorted([
            str(item.get('name') or '').strip()
            for item in input_defs
            if isinstance(item, dict) and str(item.get('name') or '').strip() and item.get('required') is not False
        ])
        input_fields_optional = sorted([name for name in input_fields_all if name and name not in set(input_fields_required)])
        output_fields = sorted([
            str(item.get('name') or '').strip()
            for item in output_defs
            if isinstance(item, dict) and str(item.get('name') or '').strip()
        ])

        requires_artifacts: list[str] = []
        produces_artifacts: list[str] = []
        try:
            gen_id = str(gen_def.get('id') or '').strip()
            plugin = plugins_by_id.get(gen_id)
            if isinstance(plugin, dict):
                req = plugin.get('requires')
                if isinstance(req, list):
                    requires_artifacts = sorted([str(item).strip() for item in req if str(item).strip()])
                prod = plugin.get('produces')
                if isinstance(prod, list):
                    produces_artifacts = sorted([
                        str(item.get('artifact') or '').strip()
                        for item in prod
                        if isinstance(item, dict) and str(item.get('artifact') or '').strip()
                    ])
        except Exception:
            requires_artifacts = []
            produces_artifacts = []

        try:
            optional_field_set = set(input_fields_optional)
            requires_effective = sorted([item for item in requires_artifacts if item and item not in optional_field_set])
        except Exception:
            requires_effective = list(requires_artifacts or [])

        inputs_effective = sorted(set(requires_effective) | set(input_fields_required))
        output_fields = sorted(set(output_fields) | set(produces_artifacts))
        outputs_effective = sorted(set(produces_artifacts) | set(output_fields))

        assignment['input_defs'] = input_defs
        assignment['output_defs'] = output_defs
        assignment['input_fields'] = input_fields_all
        assignment['input_fields_required'] = input_fields_required
        assignment['input_fields_optional'] = input_fields_optional
        assignment['output_fields'] = output_fields
        assignment['requires'] = requires_effective
        assignment['produces'] = produces_artifacts
        assignment['inputs'] = inputs_effective
        assignment['outputs'] = outputs_effective

    out: list[dict[str, Any]] = []

    def _default_vuln_injects_for_node(node_id: str, assignment: dict[str, Any]) -> list[str]:
        try:
            existing_vulns = assignment.get('vulnerabilities') if isinstance(assignment.get('vulnerabilities'), list) else []
            if any(str(v or '').strip() for v in (existing_vulns or [])):
                return ['flag.txt -> /tmp']
        except Exception:
            pass
        try:
            if str(node_id or '') in vuln_names_by_id:
                return ['flag.txt -> /tmp']
        except Exception:
            pass
        return []

    def _merge_vuln_injects(existing: Any, catalog_injects: list[str], fallback: list[str]) -> list[str]:
        current = [str(x or '').strip() for x in (existing or [])] if isinstance(existing, list) else []
        current = [x for x in current if x]
        explicit_catalog = [str(x or '').strip() for x in (catalog_injects or []) if str(x or '').strip()]
        fallback_tokens = {str(x or '').strip() for x in (fallback or []) if str(x or '').strip()}

        if explicit_catalog:
            current = [item for item in current if item not in fallback_tokens]
            if not current:
                current = list(explicit_catalog)

        if not current and fallback:
            current = [str(x or '').strip() for x in fallback if str(x or '').strip()]

        out: list[str] = []
        seen: set[str] = set()
        for item in current:
            if item in seen:
                continue
            seen.add(item)
            out.append(item)
        return out

    for i, a in enumerate(flag_assignments or []):
        if not isinstance(a, dict):
            continue
        a2 = dict(a)
        this_id = str(a2.get('node_id') or '').strip() or (chain_ids[i] if i < len(chain_ids) else '')
        next_id = chain_ids[i + 1] if (i + 1) < len(chain_ids) else ''
        a2['node_id'] = this_id
        a2['next_node_id'] = str(next_id)
        a2['next_node_name'] = str(id_to_name.get(str(next_id)) or '')
        try:
            existing_vulns = a2.get('vulnerabilities')
            has_existing = isinstance(existing_vulns, list) and any(str(x or '').strip() for x in existing_vulns)
        except Exception:
            has_existing = False
        if not has_existing:
            try:
                a2['vulnerabilities'] = list(vuln_names_by_id.get(str(this_id), []) or [])
            except Exception:
                pass
        else:
            try:
                if str(this_id) in vuln_field_seen_by_id:
                    a2['vulnerabilities'] = list(vuln_names_by_id.get(str(this_id), []) or [])
            except Exception:
                pass

        gen_id = str(a2.get('id') or '').strip()
        gen_def = by_id.get(gen_id) if gen_id else None

        try:
            _refresh_assignment_io_metadata(a2, gen_def)
        except Exception:
            pass

        try:
            a2 = _flow_apply_first_step_chain_supplied_inputs(
                a2,
                gen_def,
                scenario_label=scenario_label,
                position=i,
                supply_on_start=(i in start_positions),
            )
        except Exception:
            pass

        # Backfill source label for older persisted assignments.
        # Historically this was often the generic string "manifest"; now we prefer
        # the containing pack/bundle label (or "repo") from the current catalog.
        try:
            existing_src = str(a2.get('flag_generator') or '').strip()
        except Exception:
            existing_src = ''
        try:
            catalog_src = str((gen_def or {}).get('_source_name') or '').strip() if isinstance(gen_def, dict) else ''
        except Exception:
            catalog_src = ''
        if catalog_src and (not existing_src or existing_src.lower() == 'manifest'):
            a2['flag_generator'] = catalog_src

        # Backfill inject_files for older persisted assignments.
        try:
            existing_injects = a2.get('inject_files')
            catalog_injects: list[str] = []
            if isinstance(gen_def, dict):
                inj = gen_def.get('inject_files')
                if isinstance(inj, list):
                    catalog_injects = [str(x or '').strip() for x in inj if str(x or '').strip()]
            fallback = _default_vuln_injects_for_node(str(this_id), a2)
            merged_injects = _merge_vuln_injects(existing_injects, catalog_injects, fallback)
            if merged_injects:
                a2['inject_files'] = merged_injects
        except Exception:
            pass

        try:
            if isinstance(gen_def, dict) and not _normalize_inject_candidate_paths(a2.get('inject_candidate_paths')):
                candidates = _normalize_inject_candidate_paths(gen_def.get('inject_candidate_paths'))
                if candidates:
                    a2['inject_candidate_paths'] = list(candidates)
        except Exception:
            pass

        # Ensure generator description exists (if the catalog provides it).
        try:
            existing_desc = str(a2.get('description') or '').strip()
        except Exception:
            existing_desc = ''
        if (not existing_desc) and isinstance(gen_def, dict):
            try:
                a2['description'] = str(gen_def.get('description') or '')
            except Exception:
                pass

        # Ensure description hints exist (if the catalog provides them).
        try:
            existing = a2.get('description_hints')
            if not (isinstance(existing, list) and any(str(x or '').strip() for x in existing)):
                dh = (gen_def or {}).get('description_hints') if isinstance(gen_def, dict) else None
                if isinstance(dh, list):
                    a2['description_hints'] = [str(x or '').strip() for x in dh if str(x or '').strip()]
        except Exception:
            pass

        # Input/output descriptors are refreshed from the current catalog above.

        # Ensure access_instructions exist (if the catalog provides them).
        # These guide participants on how to interact with generated artifacts.
        try:
            existing_access = a2.get('access_instructions')
            if not (isinstance(existing_access, dict) and existing_access.get('steps')):
                ai = (gen_def or {}).get('access_instructions') if isinstance(gen_def, dict) else None
                if isinstance(ai, dict) and ai.get('steps'):
                    a2['access_instructions'] = dict(ai)
        except Exception:
            pass

        def _apply_ip_to_hint_text(s: str) -> str:
            try:
                if not s:
                    return s
                out_s = str(s)
                ipv4_pat = r"(?:\d{1,3}\.){3}\d{1,3}"
                entries = sorted(
                    list((id_to_name or {}).items()),
                    key=lambda item: len(str(item[1] or '')),
                    reverse=True,
                )
                for nid_key, nm_val in entries:
                    name_val = str(nm_val or '').strip()
                    ip_val = str(id_to_ip.get(nid_key) or '').strip()
                    if not name_val or not ip_val or name_val not in out_s:
                        continue
                    escaped_name = re.escape(name_val)
                    stale_at = rf"{escaped_name}\s*@\s*{ipv4_pat}"
                    if re.search(stale_at, out_s):
                        out_s = re.sub(stale_at, f"{name_val} @ {ip_val}", out_s)
                        continue
                    stale_paren = rf"{escaped_name}\s*\(\s*{ipv4_pat}\s*\)"
                    if re.search(stale_paren, out_s):
                        out_s = re.sub(stale_paren, f"{name_val} @ {ip_val}", out_s)
                        continue
                    if not _flow_text_contains_ipv4(out_s, ip_val):
                        out_s = out_s.replace(name_val, f"{name_val} @ {ip_val}")
                return _flow_strip_ids_from_hint(out_s)
            except Exception:
                return s

        def _apply_ip_to_hint_levels(levels: Any) -> dict[str, list[str]]:
            out_levels: dict[str, list[str]] = {level: [] for level in _FLOW_HINT_LEVELS}
            if not isinstance(levels, dict):
                return out_levels
            for level in _FLOW_HINT_LEVELS:
                raw_values = levels.get(level)
                if isinstance(raw_values, str):
                    raw_iter = [raw_values]
                elif isinstance(raw_values, (list, tuple, set)):
                    raw_iter = list(raw_values)
                else:
                    raw_iter = []
                for raw_value in raw_iter:
                    text = _apply_ip_to_hint_text(str(raw_value or '').strip())
                    if text and text not in out_levels[level]:
                        out_levels[level].append(text)
            return out_levels

        # If hint overrides exist, treat them as authoritative.
        try:
            if 'hint_overrides' in a2:
                if a2.get('hint_overrides') is None:
                    a2.pop('hint_overrides', None)
                elif isinstance(a2.get('hint_overrides'), list):
                    ovr = [str(x or '').strip() for x in (a2.get('hint_overrides') or [])]
                    ovr = [x for x in ovr if x]
                    ovr = [_apply_ip_to_hint_text(x) for x in ovr]
                    ovr = [x for x in ovr if x]
                    a2['hint_overrides'] = ovr
                    a2['hints'] = ovr
                    a2['hint'] = ovr[0] if ovr else ''
                    a2['hint_levels'] = {'low': list(ovr), 'medium': [], 'high': []}
        except Exception:
            pass

        # User-authored hint overrides are authoritative. Keep next-node linkage
        # metadata fresh, but do not re-render template hints over custom text.
        try:
            if isinstance(a2.get('hint_overrides'), list):
                out.append(a2)
                continue
        except Exception:
            pass

        # Normalize optional persisted flag override.
        try:
            if 'flag_override' in a2:
                if a2.get('flag_override') is None:
                    a2.pop('flag_override', None)
                elif isinstance(a2.get('flag_override'), str):
                    s = str(a2.get('flag_override') or '').strip()
                    if s:
                        a2['flag_override'] = s
                    else:
                        a2.pop('flag_override', None)
                else:
                    a2.pop('flag_override', None)
        except Exception:
            pass

        # Normalize optional persisted output overrides (dict of output_key -> value).
        try:
            if 'output_overrides' in a2:
                if a2.get('output_overrides') is None:
                    a2.pop('output_overrides', None)
                elif isinstance(a2.get('output_overrides'), dict):
                    cleaned: dict[str, Any] = {}
                    for k, v in (a2.get('output_overrides') or {}).items():
                        kk = str(k or '').strip()
                        if not kk:
                            continue
                        cleaned[kk] = v
                    if cleaned:
                        a2['output_overrides'] = cleaned
                    else:
                        a2.pop('output_overrides', None)
                else:
                    a2.pop('output_overrides', None)
        except Exception:
            pass

        # Normalize optional persisted inject-files override (list of paths).
        try:
            if 'inject_files_override' in a2:
                if a2.get('inject_files_override') is None:
                    a2.pop('inject_files_override', None)
                elif isinstance(a2.get('inject_files_override'), list):
                    cleaned = [str(x or '').strip() for x in (a2.get('inject_files_override') or [])]
                    cleaned = [x for x in cleaned if x]
                    a2['inject_files_override'] = cleaned
                    # Mirror into inject_files so the UI/runner sees the effective list.
                    a2['inject_files'] = cleaned
                else:
                    a2.pop('inject_files_override', None)
        except Exception:
            pass

        # Prefer rendering from templates using the current chain/IP map so hints stay
        # consistent after topology/IP changes. Fall back to persisted hint text only
        # when no template source is available.
        has_hints = False
        try:
            if isinstance(a2.get('hints'), list) and any(str(x or '').strip() for x in (a2.get('hints') or [])):
                has_hints = True
            elif str(a2.get('hint') or '').strip():
                has_hints = True
        except Exception:
            has_hints = False

        hint_templates_effective: list[str] = []
        try:
            if isinstance(a2.get('hint_templates'), list):
                hint_templates_effective = [str(x or '').strip() for x in (a2.get('hint_templates') or []) if str(x or '').strip()]
        except Exception:
            hint_templates_effective = []
        try:
            if not hint_templates_effective:
                single_tpl = str(a2.get('hint_template') or '').strip()
                if single_tpl:
                    hint_templates_effective = [single_tpl]
        except Exception:
            pass
        try:
            if not hint_templates_effective and isinstance(gen_def, dict):
                hint_templates_effective = _flow_hint_templates_from_generator(gen_def)
        except Exception:
            pass

        try:
            applied_rendered_levels = False
            if isinstance(a2.get('hint_level_templates'), dict):
                level_templates = a2.get('hint_level_templates')
                rendered_levels = _flow_render_hint_level_templates(
                    level_templates,
                    scenario_label=scenario_label,
                    id_to_name=id_to_name,
                    id_to_ip=id_to_ip,
                    this_id=str(this_id),
                    next_id=str(next_id),
                )
                if any(rendered_levels.get(level) for level in _FLOW_HINT_LEVELS):
                    a2['hint_levels'] = rendered_levels
                    applied_rendered_levels = True
            elif isinstance(gen_def, dict):
                level_templates = _flow_hint_level_templates_from_generator(gen_def)
                rendered_levels = _flow_render_hint_level_templates(
                    level_templates,
                    scenario_label=scenario_label,
                    id_to_name=id_to_name,
                    id_to_ip=id_to_ip,
                    this_id=str(this_id),
                    next_id=str(next_id),
                )
                if any(rendered_levels.get(level) for level in _FLOW_HINT_LEVELS):
                    a2['hint_level_templates'] = level_templates
                    a2['hint_levels'] = rendered_levels
                    applied_rendered_levels = True
            if (not applied_rendered_levels) and isinstance(a2.get('hint_levels'), dict):
                a2['hint_levels'] = _apply_ip_to_hint_levels(a2.get('hint_levels'))
        except Exception:
            pass

        if hint_templates_effective:
            try:
                hint_tpl = hint_templates_effective[0] if hint_templates_effective else 'Next: {{NEXT_NODE_NAME}} @ {{NEXT_NODE_IP}}'
                rendered = [
                    _flow_render_hint_template(
                        t,
                        scenario_label=scenario_label,
                        id_to_name=id_to_name,
                        id_to_ip=id_to_ip,
                        this_id=str(this_id),
                        next_id=str(next_id),
                    )
                    for t in (hint_templates_effective or [hint_tpl])
                ]
                rendered = [str(x or '').strip() for x in rendered if str(x or '').strip()]
                if rendered:
                    a2['hint_templates'] = hint_templates_effective
                    a2['hint_template'] = str(hint_tpl or '')
                    a2['hints'] = rendered
                    a2['hint'] = rendered[0]
                    out.append(a2)
                    continue
            except Exception:
                pass

        if has_hints:
            try:
                if isinstance(a2.get('hints'), list) and a2.get('hints'):
                    raw = [str(x or '') for x in (a2.get('hints') or [])]
                    # Only mutate if the text actually contains ids/placeholders.
                    if any(('(id=' in s.lower()) or ('{{NEXT_NODE_ID}}' in s) or ('{{THIS_NODE_ID}}' in s) for s in raw):
                        a2['hints'] = [_flow_strip_ids_from_hint(s) for s in raw]
                        a2['hints'] = [x for x in (a2.get('hints') or []) if str(x).strip()]
                        if a2['hints']:
                            a2['hint'] = a2['hints'][0]
                    try:
                        a2['hints'] = [_apply_ip_to_hint_text(s) for s in (a2.get('hints') or [])]
                        if a2.get('hints'):
                            a2['hint'] = a2['hints'][0]
                    except Exception:
                        pass
                elif a2.get('hint'):
                    s = str(a2.get('hint') or '')
                    if ('(id=' in s.lower()) or ('{{NEXT_NODE_ID}}' in s) or ('{{THIS_NODE_ID}}' in s):
                        a2['hint'] = _flow_strip_ids_from_hint(s)
                    try:
                        a2['hint'] = _apply_ip_to_hint_text(str(a2.get('hint') or ''))
                    except Exception:
                        pass
            except Exception:
                pass
        elif isinstance(gen_def, dict):
            hint_tpl = 'Next: {{NEXT_NODE_NAME}} @ {{NEXT_NODE_IP}}'
            a2['hint_templates'] = [hint_tpl]
            a2['hint_template'] = hint_tpl
            rendered = [
                _flow_render_hint_template(
                    hint_tpl,
                    scenario_label=scenario_label,
                    id_to_name=id_to_name,
                    id_to_ip=id_to_ip,
                    this_id=str(this_id),
                    next_id=str(next_id),
                )
            ]
            a2['hints'] = rendered
            a2['hint'] = rendered[0] if rendered else _flow_render_hint_template(
                hint_tpl,
                scenario_label=scenario_label,
                id_to_name=id_to_name,
                id_to_ip=id_to_ip,
                this_id=str(this_id),
                next_id=str(next_id),
            )

        out.append(a2)
    try:
        return _flow_apply_pivot_context_to_assignments(
            out,
            chain_nodes,
            preview=None,
            pivot_context={},
            scenario_label=scenario_label,
        )
    except Exception:
        return out


def _infer_flow_artifacts_dir_from_assignment(assignment: dict[str, Any], *, max_dirs: int = 60) -> dict[str, str]:
    """Infer artifacts/run/mount dirs from existing assignment data.

    Returns a dict with any of: artifacts_dir, run_dir, outputs_manifest, inject_source_dir.
    """
    if not isinstance(assignment, dict):
        return {}

    rel_candidates: list[str] = []
    for key in ('resolved_outputs',):
        ro = assignment.get(key)
        if isinstance(ro, dict):
            for v in ro.values():
                if isinstance(v, str) and v.strip():
                    rel_candidates.append(v.strip())
    detail_list = assignment.get('inject_files_detail') if isinstance(assignment.get('inject_files_detail'), list) else []
    for item in detail_list:
        if not isinstance(item, dict):
            continue
        raw = str(item.get('resolved') or '').strip()
        if raw:
            rel_candidates.append(raw)

    def _to_rel(raw: str) -> str:
        s = str(raw or '').replace('\\', '/').strip()
        if not s:
            return ''
        if '/artifacts/' in s:
            return s.split('/artifacts/', 1)[1].lstrip('/')
        if '/flow_artifacts/' in s:
            return s.split('/flow_artifacts/', 1)[1].lstrip('/')
        if s.startswith('artifacts/'):
            return s
        if s.startswith('/tmp/'):
            s = s[len('/tmp/'):]
        if s.startswith('/'):
            s = s[1:]
        return s

    rels: list[str] = []
    for raw in rel_candidates:
        rel = _to_rel(raw)
        if rel and rel not in rels:
            rels.append(rel)

    if not rels:
        return {}

    outputs_root = _outputs_dir()
    base_dirs = [
        os.path.join('/tmp/vulns', 'flag_generators_runs'),
        os.path.join('/tmp/vulns', 'flag_node_generators_runs'),
        os.path.join(outputs_root, 'flag_generators_runs'),
        os.path.join(outputs_root, 'flag_node_generators_runs'),
        os.path.join(outputs_root, 'vulns', 'flag_generators_runs'),
        os.path.join(outputs_root, 'vulns', 'flag_node_generators_runs'),
    ]
    run_dirs: list[str] = []
    for base in base_dirs:
        if not os.path.isdir(base):
            continue
        try:
            for entry in os.scandir(base):
                if entry.is_dir():
                    run_dirs.append(entry.path)
        except Exception:
            continue
    run_dirs.sort(key=lambda p: os.path.getmtime(p) if os.path.exists(p) else 0, reverse=True)
    if max_dirs and len(run_dirs) > max_dirs:
        run_dirs = run_dirs[:max_dirs]

    def _exists_in_run(run_dir: str, rel: str) -> bool:
        rel_clean = rel.lstrip('/')
        if rel_clean.startswith('artifacts/'):
            rel_clean = rel_clean[len('artifacts/'):]
        for candidate in (
            os.path.join(run_dir, rel),
            os.path.join(run_dir, 'artifacts', rel_clean),
            os.path.join(run_dir, 'injected', rel_clean),
        ):
            if os.path.exists(candidate):
                return True
        return False

    for rd in run_dirs:
        try:
            if any(_exists_in_run(rd, rel) for rel in rels):
                inject_source_dir = ''
                if os.path.isdir(os.path.join(rd, 'injected')):
                    inject_source_dir = os.path.join(rd, 'injected')
                elif os.path.isdir(os.path.join(rd, 'artifacts')):
                    inject_source_dir = os.path.join(rd, 'artifacts')
                else:
                    inject_source_dir = rd
                out = {
                    'artifacts_dir': rd,
                    'run_dir': rd,
                    'inject_source_dir': inject_source_dir,
                }
                manifest = os.path.join(rd, 'outputs.json')
                if os.path.exists(manifest):
                    out['outputs_manifest'] = manifest
                return out
        except Exception:
            continue
    return {}


def _webui_log_path() -> str:
    try:
        port = str(os.environ.get('CORETG_PORT') or '').strip() or '9090'
    except Exception:
        port = '9090'
    try:
        logs_dir = os.path.abspath(os.path.join(_outputs_dir(), 'logs'))
    except Exception:
        logs_dir = os.path.abspath(os.path.join(os.getcwd(), 'outputs', 'logs'))
    return os.path.join(logs_dir, f'webui-{port}.log')


try:
    from webapp.routes import webui_logs as _webui_logs_routes

    _webui_logs_routes.register(
        app,
        current_user_getter=lambda: _current_user(),
        normalize_role_value=lambda role: _normalize_role_value(role),
        webui_log_path_getter=lambda: _webui_log_path(),
    )
except Exception:
    try:
        app.logger.exception('Failed to register webui_logs routes.')
    except Exception:
        pass


def _enrich_flow_state_with_artifacts(flow_state: dict[str, Any]) -> dict[str, Any]:
    if not isinstance(flow_state, dict):
        return flow_state
    assigns = flow_state.get('flag_assignments') if isinstance(flow_state.get('flag_assignments'), list) else []
    if not assigns:
        return flow_state
    changed = False
    enriched: list[dict[str, Any]] = []
    for a in assigns:
        if not isinstance(a, dict):
            continue
        a2 = dict(a)
        try:
            injects = a2.get('inject_files') if isinstance(a2.get('inject_files'), list) else None
            if injects:
                fixed = []
                for raw in injects:
                    s = str(raw or '').strip()
                    if s.startswith('/tmp/tmp/'):
                        s = '/tmp/' + s[len('/tmp/tmp/') :]
                    fixed.append(s)
                a2['inject_files'] = fixed
                changed = True
        except Exception:
            pass
        try:
            detail = a2.get('inject_files_detail') if isinstance(a2.get('inject_files_detail'), list) else None
            if detail:
                fixed_detail = []
                for item in detail:
                    if not isinstance(item, dict):
                        fixed_detail.append(item)
                        continue
                    item2 = dict(item)
                    path = str(item2.get('path') or '').strip()
                    if path.startswith('/tmp/tmp/'):
                        path = '/tmp/' + path[len('/tmp/tmp/') :]
                        item2['path'] = path
                    fixed_detail.append(item2)
                a2['inject_files_detail'] = fixed_detail
                changed = True
        except Exception:
            pass
        try:
            ro = a2.get('resolved_outputs') if isinstance(a2.get('resolved_outputs'), dict) else None
            if not ro:
                detail = a2.get('resolved_outputs_detail') if isinstance(a2.get('resolved_outputs_detail'), list) else None
                if detail:
                    ro_map: dict[str, Any] = {}
                    for item in detail:
                        if not isinstance(item, dict):
                            continue
                        field = str(item.get('field') or '').strip()
                        if not field:
                            continue
                        val = item.get('resolved')
                        if val is not None and field not in ro_map:
                            ro_map[field] = val
                    if ro_map:
                        a2['resolved_outputs'] = ro_map
                        changed = True
        except Exception:
            pass
        try:
            ro = a2.get('resolved_outputs') if isinstance(a2.get('resolved_outputs'), dict) else None
            if not ro:
                manifest_path = str(a2.get('outputs_manifest') or '').strip()
                if manifest_path and os.path.exists(manifest_path):
                    with open(manifest_path, 'r', encoding='utf-8') as mf:
                        m = json.load(mf) or {}
                    outs = m.get('outputs') if isinstance(m, dict) else None
                    if isinstance(outs, dict) and outs:
                        a2['resolved_outputs'] = outs
                        changed = True
        except Exception:
            pass
        needs = not any(a2.get(k) for k in ('artifacts_dir', 'run_dir', 'outputs_manifest', 'inject_source_dir'))
        if needs:
            inferred = _infer_flow_artifacts_dir_from_assignment(a2)
            if inferred:
                a2.update(inferred)
                changed = True
        # Resolve relative paths in inject_files_detail and resolved_outputs to absolute paths.
        # This ensures docker-compose generation gets full paths when loading from saved XML.
        try:
            art_dir = str(a2.get('inject_source_dir') or a2.get('artifacts_dir') or a2.get('run_dir') or '').strip()
            if art_dir and os.path.isabs(art_dir):
                # Resolve relative paths in inject_files_detail.resolved
                detail = a2.get('inject_files_detail') if isinstance(a2.get('inject_files_detail'), list) else None
                if detail:
                    fixed_detail = []
                    for item in detail:
                        if not isinstance(item, dict):
                            fixed_detail.append(item)
                            continue
                        item2 = dict(item)
                        resolved = str(item2.get('resolved') or '').strip()
                        if resolved and not os.path.isabs(resolved):
                            rel_resolved = resolved.lstrip('/').replace('\\', '/')
                            try:
                                if os.path.basename(os.path.normpath(art_dir)) == 'artifacts':
                                    while rel_resolved.startswith('artifacts/'):
                                        rel_resolved = rel_resolved[len('artifacts/'):]
                            except Exception:
                                pass
                            # Resolve relative path to absolute using artifacts_dir
                            # 1. Try literal join
                            full_path = os.path.join(art_dir, rel_resolved)
                            # 2. Try outputs/ subdirectory
                            if not os.path.exists(full_path):
                                cand = os.path.join(art_dir, 'outputs', rel_resolved)
                                if os.path.exists(cand):
                                    full_path = cand
                            # 3. Try without 'artifacts/' prefix if it exists
                            if not os.path.exists(full_path):
                                if resolved.startswith('artifacts/'):
                                    alt_path = os.path.join(art_dir, resolved[len('artifacts/'):])
                                    if os.path.exists(alt_path):
                                        full_path = alt_path
                                    else:
                                        alt_path = os.path.join(art_dir, 'outputs', resolved[len('artifacts/'):])
                                        if os.path.exists(alt_path):
                                            full_path = alt_path
                            item2['resolved'] = full_path
                            changed = True
                        fixed_detail.append(item2)
                    a2['inject_files_detail'] = fixed_detail
                # Resolve relative paths in resolved_outputs values
                ro = a2.get('resolved_outputs') if isinstance(a2.get('resolved_outputs'), dict) else None
                if ro:
                    fixed_ro = {}
                    for k, v in ro.items():
                        if isinstance(v, str) and v.strip() and not os.path.isabs(v):
                            rel_v = v.lstrip('/').replace('\\', '/')
                            try:
                                if os.path.basename(os.path.normpath(art_dir)) == 'artifacts':
                                    while rel_v.startswith('artifacts/'):
                                        rel_v = rel_v[len('artifacts/'):]
                            except Exception:
                                pass
                            # Check if this looks like a file path (contains slash or file extension)
                            if '/' in v or ('.' in v and not v.startswith('{')):
                                # Try to find the file in art_dir or art_dir/outputs
                                flat_v = os.path.basename(v)
                                full_path = os.path.join(art_dir, rel_v)
                                if not os.path.exists(full_path):
                                    cand = os.path.join(art_dir, 'outputs', rel_v)
                                    if os.path.exists(cand):
                                        full_path = cand
                                if not os.path.exists(full_path):
                                    # Try flattened fallback in outputs/
                                    cand = os.path.join(art_dir, 'outputs', flat_v)
                                    if os.path.exists(cand):
                                        full_path = cand
                                if not os.path.exists(full_path):
                                    # Try flattened fallback in root
                                    cand = os.path.join(art_dir, flat_v)
                                    if os.path.exists(cand):
                                        full_path = cand
                                fixed_ro[k] = full_path
                                changed = True
                            else:
                                fixed_ro[k] = v
                        else:
                            fixed_ro[k] = v
                    a2['resolved_outputs'] = fixed_ro

                # Normalize resolved_paths payload so UI gets absolute inject source
                # paths immediately (without requiring a refresh/revalidate cycle).
                resolved_paths = a2.get('resolved_paths') if isinstance(a2.get('resolved_paths'), dict) else None
                if resolved_paths:
                    rp2 = dict(resolved_paths)

                    def _is_symbolic_inject_token(raw_value: Any) -> bool:
                        s = str(raw_value or '').strip()
                        if not s:
                            return False
                        if '/' in s or '\\' in s:
                            return False
                        try:
                            return bool(re.match(r'^[A-Za-z_][A-Za-z0-9_]*\(.+\)$', s))
                        except Exception:
                            return False

                    def _extract_symbolic_token_from_path(raw_value: Any) -> str:
                        s = str(raw_value or '').strip().replace('\\', '/')
                        if not s:
                            return ''
                        base = os.path.basename(s.rstrip('/')) if s.startswith('/') else s
                        return base if _is_symbolic_inject_token(base) else ''

                    def _resolved_output_for_token(token: str) -> str:
                        if not token:
                            return ''
                        ro = a2.get('resolved_outputs') if isinstance(a2.get('resolved_outputs'), dict) else None
                        if not isinstance(ro, dict):
                            return ''
                        val = ro.get(token)
                        if isinstance(val, str) and val.strip():
                            return val.strip()
                        token_lower = token.lower()
                        for k, v in ro.items():
                            if str(k or '').strip().lower() == token_lower and isinstance(v, str) and v.strip():
                                return v.strip()
                        return ''

                    def _norm_flow_path(raw_path: Any) -> str:
                        s = str(raw_path or '').strip()
                        if not s:
                            return ''
                        s = s.replace('\\', '/')
                        token = _extract_symbolic_token_from_path(s)
                        if token:
                            resolved_token = _resolved_output_for_token(token)
                            if resolved_token:
                                s = str(resolved_token).strip().replace('\\', '/')
                            else:
                                return ''
                        if s.startswith('/tmp/vulns/'):
                            return s
                        if s.startswith('/outputs/') or s.startswith('/exports/') or s.startswith('/inputs/'):
                            return s
                        if os.path.isabs(s):
                            base = os.path.basename(s.rstrip('/'))
                            if base and art_dir:
                                candidate = os.path.join(art_dir, base)
                                if os.path.exists(candidate):
                                    return candidate
                            return s
                        if art_dir:
                            rel = s.lstrip('/')
                            candidate = os.path.join(art_dir, rel)
                            if os.path.exists(candidate):
                                return candidate
                            base = os.path.basename(rel)
                            if base:
                                candidate2 = os.path.join(art_dir, base)
                                if os.path.exists(candidate2):
                                    return candidate2
                        return s

                    try:
                        art_info = rp2.get('artifacts_dir') if isinstance(rp2.get('artifacts_dir'), dict) else None
                        if art_info is not None:
                            cur = str(art_info.get('path') or '').strip()
                            nxt = _norm_flow_path(cur)
                            if nxt and nxt != cur:
                                art2 = dict(art_info)
                                art2['path'] = nxt
                                rp2['artifacts_dir'] = art2
                                changed = True
                    except Exception:
                        pass

                    try:
                        inj_info = rp2.get('inject_source_dir') if isinstance(rp2.get('inject_source_dir'), dict) else None
                        if inj_info is not None:
                            cur = str(inj_info.get('path') or '').strip()
                            nxt = _norm_flow_path(cur)
                            if nxt and nxt != cur:
                                i2 = dict(inj_info)
                                i2['path'] = nxt
                                rp2['inject_source_dir'] = i2
                                changed = True
                    except Exception:
                        pass

                    inject_entries = rp2.get('inject_sources') if isinstance(rp2.get('inject_sources'), list) else None
                    if inject_entries is not None:
                        next_entries: list[dict[str, Any]] = []
                        inject_changed = False
                        for entry in inject_entries:
                            if not isinstance(entry, dict):
                                continue
                            e2 = dict(entry)
                            cur = str(e2.get('path') or '').strip()
                            nxt = _norm_flow_path(cur)
                            if not nxt:
                                inject_changed = True
                                continue
                            if nxt != cur:
                                e2['path'] = nxt
                                inject_changed = True
                            next_entries.append(e2)
                        if inject_changed:
                            rp2['inject_sources'] = next_entries
                            changed = True

                    if rp2 != resolved_paths:
                        a2['resolved_paths'] = rp2
                        changed = True
        except Exception:
            pass
        enriched.append(a2)
    if changed:
        flow_state = dict(flow_state)
        flow_state['flag_assignments'] = enriched
    return flow_state



def _flow_parse_bool(value: Any, *, default: bool = False) -> bool:
    """Parse a truthy/falsey value commonly used in query args/JSON."""
    if value is None:
        return default
    try:
        if isinstance(value, bool):
            return bool(value)
        s = str(value).strip().lower()
    except Exception:
        return default
    if s in ('1', 'true', 'yes', 'y', 'on'):
        return True
    if s in ('0', 'false', 'no', 'n', 'off'):
        return False
    return default


def _flow_extract_node_authoring_doc(node: dict[str, Any]) -> dict[str, Any] | None:
    if not isinstance(node, dict):
        return None
    meta = node.get('metadata') if isinstance(node.get('metadata'), dict) else {}
    candidates: list[Any] = []
    for key in ('node_authoring', 'node_schema', 'node_spec', 'node_definition', 'authoring'):
        if key in node:
            candidates.append(node.get(key))
        if isinstance(meta, dict) and key in meta:
            candidates.append(meta.get(key))
    for raw in candidates:
        if raw is None:
            continue
        if isinstance(raw, dict):
            return raw
        if isinstance(raw, str):
            try:
                import yaml  # type: ignore
                doc = yaml.safe_load(raw)
            except Exception:
                doc = None
            if isinstance(doc, dict):
                return doc
    return None


def _flow_validate_chain_nodes_against_node_schema(
    chain_nodes: list[dict[str, Any]],
    *,
    scenario_label: str,
) -> list[str]:
    schema = _load_node_schema_validation()
    if not isinstance(schema, dict):
        return []
    try:
        from scenarioforge.sequencer.schemas import validate_against_schema
    except Exception:
        return []
    errors: list[str] = []
    for node in (chain_nodes or []):
        if not isinstance(node, dict):
            continue
        doc = _flow_extract_node_authoring_doc(node)
        if not isinstance(doc, dict):
            continue
        ok, errs = validate_against_schema(doc, schema)
        if not ok:
            node_id = str(node.get('id') or node.get('node_id') or node.get('name') or '').strip()
            prefix = f"{node_id}: " if node_id else ''
            for err in errs:
                errors.append(f"{prefix}node authoring invalid: {err}")
    if errors:
        errors.insert(0, f"node authoring schema validation failed for scenario '{scenario_label}'")
    return errors


def _flow_validate_chain_order_by_requires_produces(
    chain_nodes: list[dict[str, Any]],
    flag_assignments: list[dict[str, Any]],
    *,
    scenario_label: str,
    plugins_by_id_override: dict[str, dict[str, Any]] | None = None,
) -> tuple[bool, list[str]]:
    """Validate that the given chain order is solvable by requires/produces.

    This is a strict, linear check in the *current* order:
    - Each step's effective requires must be satisfied by synthesized inputs or prior produces.
    - Effective requires/produces are derived from v3 plugin contracts, plus assignment-declared
      inputs/outputs (best-effort) to support coarse catalogs.

    Returns: (ok, errors)
    """
    errors: list[str] = []
    if not isinstance(chain_nodes, list) or not chain_nodes:
        return False, ['missing chain nodes']
    if not isinstance(flag_assignments, list) or not flag_assignments:
        try:
            chain_count = len(chain_nodes or []) if isinstance(chain_nodes, list) else 0
        except Exception:
            chain_count = 0
        try:
            vuln_nodes = len([n for n in (chain_nodes or []) if isinstance(n, dict) and _flow_node_is_vuln(n)])
        except Exception:
            vuln_nodes = 0
        try:
            docker_nodes = len([n for n in (chain_nodes or []) if isinstance(n, dict) and _flow_node_is_docker_role(n)])
        except Exception:
            docker_nodes = 0
        try:
            gens_enabled, _ = _flag_generators_from_enabled_sources()
        except Exception:
            gens_enabled = []
        try:
            node_gens_enabled, _ = _flag_node_generators_from_enabled_sources()
        except Exception:
            node_gens_enabled = []
        try:
            eligible_flag_gens = len([g for g in (gens_enabled or []) if isinstance(g, dict)])
        except Exception:
            eligible_flag_gens = 0
        try:
            eligible_node_gens = len([g for g in (node_gens_enabled or []) if isinstance(g, dict)])
        except Exception:
            eligible_node_gens = 0
        return False, [
            'missing flag assignments',
            f"assignments=0 chain_nodes={chain_count}",
            f"chain_vuln_nodes={vuln_nodes}",
            f"chain_docker_nodes={docker_nodes}",
            f"eligible_flag_generators={eligible_flag_gens}",
            f"eligible_flag_node_generators={eligible_node_gens}",
        ]

    chain_ids: list[str] = [
        str(n.get('id') or '').strip()
        for n in chain_nodes
        if isinstance(n, dict) and str(n.get('id') or '').strip()
    ]
    if not chain_ids:
        return False, ['empty chain']

    node_schema_errors = _flow_validate_chain_nodes_against_node_schema(
        chain_nodes,
        scenario_label=scenario_label,
    )
    if node_schema_errors:
        errors.extend(node_schema_errors)

    assign_by_node: dict[str, dict[str, Any]] = {}
    for a in flag_assignments:
        if not isinstance(a, dict):
            continue
        nid = str(a.get('node_id') or '').strip()
        if nid:
            assign_by_node[nid] = a

    # If assignments are positionally aligned but missing node_id fields, map by position.
    try:
        if any(cid not in assign_by_node for cid in chain_ids):
            if len(flag_assignments) == len(chain_ids):
                for i, cid in enumerate(chain_ids):
                    if cid in assign_by_node:
                        continue
                    a = flag_assignments[i]
                    if isinstance(a, dict):
                        assign_by_node[cid] = a
    except Exception:
        pass

    missing_assignments = [cid for cid in chain_ids if cid not in assign_by_node]
    if missing_assignments:
        return False, [
            'missing assignment for at least one chain node',
            f"missing_assignment_nodes={','.join(missing_assignments)}",
        ]

    if isinstance(plugins_by_id_override, dict) and plugins_by_id_override:
        plugins_by_id = plugins_by_id_override
    else:
        plugins_by_id = _flow_enabled_plugin_contracts_by_id()

    node_by_id: dict[str, dict[str, Any]] = {}
    for node in chain_nodes:
        if not isinstance(node, dict):
            continue
        nid = str(node.get('id') or '').strip()
        if nid:
            node_by_id[nid] = node

    # Best-effort: load enabled generator definitions so we can infer optional
    # input fields even if the assignment payload doesn't include them.
    gen_defs_by_id: dict[str, dict[str, Any]] = _flow_enabled_generator_defs_by_id()

    available: set[str] = set(_flow_synthesized_inputs())
    try:
        ordered_assignments = [assign_by_node.get(cid) or {} for cid in chain_ids]
        start_positions = _flow_parallel_start_assignment_indexes(ordered_assignments, gen_defs_by_id=gen_defs_by_id)
        for start_index in sorted(start_positions):
            if start_index < 0 or start_index >= len(ordered_assignments):
                continue
            start_assignment = ordered_assignments[start_index]
            start_plugin_id = str(start_assignment.get('id') or start_assignment.get('generator_id') or '').strip()
            supplied = start_assignment.get('chain_supplied_inputs') if isinstance(start_assignment.get('chain_supplied_inputs'), list) else []
            available |= {str(x).strip() for x in (supplied or []) if str(x).strip()}
            if start_plugin_id:
                start_gen = gen_defs_by_id.get(start_plugin_id)
                available |= set(_flow_first_step_chain_supplied_input_names(start_gen if isinstance(start_gen, dict) else start_assignment))
    except Exception:
        pass

    for cid in chain_ids:
        a = assign_by_node.get(cid) or {}
        plugin_id = str(a.get('id') or '').strip()
        if not plugin_id:
            errors.append(f"{cid}: missing generator id")
            continue

        plugin = plugins_by_id.get(plugin_id)
        if not isinstance(plugin, dict):
            errors.append(f"{cid}: unknown plugin '{plugin_id}'")
            continue

        inferred_requires = {str(x).strip() for x in (a.get('inputs') or []) if str(x).strip()}
        inferred_produces = {str(x).strip() for x in (a.get('outputs') or []) if str(x).strip()}

        # Optional dependency tokens (do not block ordering). Prefer the assignment
        # field when present; fall back to the generator catalog schema.
        opt_set: set[str] = set()
        try:
            opt_fields = a.get('input_fields_optional') or []
            if isinstance(opt_fields, list):
                opt_set |= {str(x).strip() for x in opt_fields if str(x).strip()}
        except Exception:
            pass
        if not opt_set:
            try:
                gen_def = gen_defs_by_id.get(plugin_id)
                inputs = (gen_def or {}).get('inputs') if isinstance(gen_def, dict) else None
                if isinstance(inputs, list):
                    for inp in inputs:
                        if not isinstance(inp, dict):
                            continue
                        if inp.get('required') is False:
                            nm = str(inp.get('name') or '').strip()
                            if nm:
                                opt_set.add(nm)
            except Exception:
                pass

        base_requires = {str(x).strip() for x in (plugin.get('requires') or []) if str(x).strip()} if isinstance(plugin.get('requires'), list) else set()
        if opt_set:
            base_requires = {r for r in base_requires if r not in opt_set}
            inferred_requires = {r for r in inferred_requires if r not in opt_set}

        requires = set(_flow_prune_unavailable_or_self_pivot_facts(
            sorted(base_requires | inferred_requires),
            chain_nodes,
            current_node=node_by_id.get(cid),
            current_assignment=a,
        ))

        base_prod: set[str] = set()
        try:
            for p in (plugin.get('produces') or []):
                if not isinstance(p, dict):
                    continue
                art = str(p.get('artifact') or '').strip()
                if art:
                    base_prod.add(art)
        except Exception:
            base_prod = set()
        produces = base_prod | inferred_produces

        missing = sorted(list({r for r in requires if r not in available}))
        if missing:
            errors.append(f"{cid}: requires {missing} before they are produced")

        available |= produces

    if errors:
        # Include minimal context; callers may surface this in API error details.
        return False, errors
    return True, []


def _flow_enabled_plugin_contracts_by_id() -> dict[str, dict[str, Any]]:
    """Return generator plugin contracts indexed by plugin_id.

    Strict: contracts are derived from per-generator YAML manifests.
    """
    plugins_by_id: dict[str, dict[str, Any]] = {}

    # Important: Flow sequencing must NOT consider disabled generators.
    # We filter plugin contracts to installed+enabled generators only.
    try:
        gens, fg_plugins, _errs = _flag_generators_from_manifests(kind='flag-generator')
        allowed: set[str] = set()
        for g in (gens or []):
            if not isinstance(g, dict):
                continue
            if not _is_installed_generator_view(g):
                continue
            gid = str(g.get('id') or '').strip()
            if not gid:
                continue
            if _is_installed_generator_disabled(kind='flag-generator', generator_id=gid):
                continue
            allowed.add(gid)
        for k, v in (fg_plugins or {}).items():
            if isinstance(k, str) and k in allowed and isinstance(v, dict):
                plugins_by_id[k] = v
    except Exception:
        pass

    try:
        gens2, ng_plugins, _errs2 = _flag_generators_from_manifests(kind='flag-node-generator')
        allowed2: set[str] = set()
        for g in (gens2 or []):
            if not isinstance(g, dict):
                continue
            if not _is_installed_generator_view(g):
                continue
            gid = str(g.get('id') or '').strip()
            if not gid:
                continue
            if _is_installed_generator_disabled(kind='flag-node-generator', generator_id=gid):
                continue
            allowed2.add(gid)
        for k, v in (ng_plugins or {}).items():
            if isinstance(k, str) and k in allowed2 and k not in plugins_by_id and isinstance(v, dict):
                plugins_by_id[k] = v
    except Exception:
        pass

    return plugins_by_id


def _flow_reorder_chain_by_generator_dag(
    chain_nodes: list[dict[str, Any]],
    flag_assignments: list[dict[str, Any]],
    *,
    scenario_label: str,
    dependency_level: int | None = None,
    plugins_by_id_override: dict[str, dict[str, Any]] | None = None,
    return_debug: bool = False,
    flow_progress: Any | None = None,
) -> tuple[list[dict[str, Any]], list[dict[str, Any]], dict[str, Any] | None]:
    """Best-effort: reorder the chain using generator artifact dependencies.

    This does not change generator selection; it only reorders the existing
    chain nodes + assignments so that inputs are satisfied by some producer.

    If the DAG cannot be built, returns inputs unchanged.
    """
    def _progress(message: str) -> None:
        if flow_progress is None:
            return
        try:
            flow_progress(f'DAG: {message}')
        except Exception:
            pass

    try:
        _progress(f'start nodes={len(chain_nodes or [])} assignments={len(flag_assignments or [])} dependency_level={_flow_normalize_dependency_level(dependency_level)}')
        if not isinstance(chain_nodes, list) or not chain_nodes:
            _progress('skipped: missing chain nodes')
            return chain_nodes, flag_assignments, None
        if not isinstance(flag_assignments, list) or not flag_assignments:
            _progress('skipped: missing flag assignments')
            return chain_nodes, flag_assignments, None

        _progress('loading sequencer DAG helpers')
        from scenarioforge.sequencer.dag import build_dag
        from scenarioforge.sequencer.chain import validate_chain_doc, validate_linear_chain
        _progress('sequencer DAG helpers loaded')

        node_by_id: dict[str, dict[str, Any]] = {}
        for n in chain_nodes:
            if not isinstance(n, dict):
                continue
            nid = str(n.get('id') or '').strip()
            if nid:
                node_by_id[nid] = n

        assign_by_node: dict[str, dict[str, Any]] = {}
        for a in flag_assignments:
            if not isinstance(a, dict):
                continue
            nid = str(a.get('node_id') or '').strip()
            if nid:
                assign_by_node[nid] = a

        # Only reorder when we have a 1:1 mapping.
        chain_ids = [str(n.get('id') or '').strip() for n in chain_nodes if isinstance(n, dict) and str(n.get('id') or '').strip()]
        if not chain_ids:
            _progress('skipped: chain has no ids')
            return chain_nodes, flag_assignments, None
        if any(cid not in assign_by_node for cid in chain_ids):
            _progress('skipped: chain and assignments are not 1:1')
            return chain_nodes, flag_assignments, None

        _progress(f'indexed chain ids={",".join(chain_ids)}')

        gen_defs_by_id_for_reorder: dict[str, dict[str, Any]] = {}
        try:
            _progress('loading enabled generator definitions')
            gen_defs_by_id_for_reorder = _flow_enabled_generator_defs_by_id()
            _progress(f'loaded generator definitions count={len(gen_defs_by_id_for_reorder or {})}')
        except Exception as exc:
            gen_defs_by_id_for_reorder = {}
            _progress(f'generator definition load failed: {type(exc).__name__}: {exc}')

        plugins_by_id: dict[str, dict[str, Any]] = {}
        if isinstance(plugins_by_id_override, dict) and plugins_by_id_override:
            plugins_by_id = plugins_by_id_override
            _progress(f'using provided plugin contracts count={len(plugins_by_id)}')
        else:
            try:
                _progress('loading enabled plugin contracts')
                plugins_by_id = _flow_enabled_plugin_contracts_by_id()
                _progress(f'loaded plugin contracts count={len(plugins_by_id or {})}')
            except Exception as exc:
                plugins_by_id = {}
                _progress(f'plugin contract load failed: {type(exc).__name__}: {exc}')

        initial_artifacts = set(_flow_synthesized_inputs())
        try:
            gen_defs_by_id_for_initial = gen_defs_by_id_for_reorder
            ordered_for_initial = [assign_by_node.get(cid) or {} for cid in chain_ids]
            start_positions_for_initial = _flow_parallel_start_assignment_indexes(
                ordered_for_initial,
                gen_defs_by_id=gen_defs_by_id_for_initial,
            )
            for start_index in sorted(start_positions_for_initial):
                if start_index < 0 or start_index >= len(ordered_for_initial):
                    continue
                start_assignment_for_initial = ordered_for_initial[start_index]
                if not isinstance(start_assignment_for_initial, dict):
                    continue
                initial_artifacts |= {
                    str(x).strip()
                    for x in (start_assignment_for_initial.get('chain_supplied_inputs') or [])
                    if str(x).strip()
                }
                gen_id = str(start_assignment_for_initial.get('id') or start_assignment_for_initial.get('generator_id') or '').strip()
                gen_def = gen_defs_by_id_for_initial.get(gen_id) if gen_id else None
                initial_artifacts |= set(_flow_first_step_chain_supplied_input_names(gen_def if isinstance(gen_def, dict) else start_assignment_for_initial))
        except Exception:
            pass
            _progress(f'initial artifacts ready count={len(initial_artifacts)}')

        def _assignment_fact_list(assignment: dict[str, Any], keys: tuple[str, ...]) -> set[str]:
            facts: set[str] = set()
            if not isinstance(assignment, dict):
                return facts
            for key in keys:
                raw = assignment.get(key)
                if not isinstance(raw, list):
                    continue
                for item in raw:
                    if isinstance(item, dict):
                        for nested_key in ('artifact', 'name', 'field'):
                            nested_val = str(item.get(nested_key) or '').strip()
                            if nested_val:
                                facts.add(nested_val)
                                break
                        continue
                    val = str(item or '').strip()
                    if val:
                        facts.add(val)
            return facts

        def _assignment_requires(assignment: dict[str, Any]) -> set[str]:
            requires = _assignment_fact_list(
                assignment,
                ('requires', 'input_fields_required', 'inputs'),
            ) - initial_artifacts
            try:
                explicit_supplied = {
                    str(x or '').strip()
                    for x in (assignment.get('chain_supplied_inputs') or [])
                    if str(x or '').strip()
                } if isinstance(assignment.get('chain_supplied_inputs'), list) else set()
                requires -= explicit_supplied
            except Exception:
                pass
            return requires

        def _assignment_produces(assignment: dict[str, Any]) -> set[str]:
            return _assignment_fact_list(
                assignment,
                ('produces', 'output_fields', 'outputs'),
            )

        def _adjacent_dependency_count(assignments: list[dict[str, Any]]) -> int:
            count = 0
            for idx in range(1, len(assignments or [])):
                prev_assignment = assignments[idx - 1] if idx - 1 < len(assignments) else {}
                cur_assignment = assignments[idx] if idx < len(assignments) else {}
                if _assignment_produces(prev_assignment) & _assignment_requires(cur_assignment):
                    count += 1
            return count

        def _refresh_next_fields(
            ordered_nodes: list[dict[str, Any]],
            ordered_assignments: list[dict[str, Any]],
        ) -> tuple[list[dict[str, Any]], list[dict[str, Any]]]:
            id_to_name: dict[str, str] = {}
            for node in ordered_nodes:
                try:
                    node_id = str(node.get('id') or '').strip()
                    node_name = str(node.get('name') or '').strip()
                    if node_id:
                        id_to_name[node_id] = node_name or node_id
                except Exception:
                    continue

            def _render_hint(tpl: str, *, this_id: str, next_id: str) -> str:
                try:
                    text = str(tpl or '').strip() or 'Next: {{NEXT_NODE_NAME}}'
                    next_id_val = str(next_id or '').strip()
                    next_name_val = (id_to_name.get(next_id_val) or '').strip() if next_id_val else ''
                    if not next_id_val:
                        return "You've completed this sequence of challenges!"
                    if not next_name_val:
                        next_name_val = next_id_val
                    repl = {
                        '{{SCENARIO}}': str(scenario_label or ''),
                        '{{THIS_NODE_ID}}': this_id,
                        '{{THIS_NODE_NAME}}': id_to_name.get(this_id) or this_id,
                        '{{NEXT_NODE_ID}}': next_id_val,
                        '{{NEXT_NODE_NAME}}': next_name_val,
                    }
                    for key, value in repl.items():
                        text = text.replace(key, str(value))
                    return _flow_strip_ids_from_hint(text)
                except Exception:
                    return ''

            try:
                start_positions = _flow_parallel_start_assignment_indexes(
                    ordered_assignments,
                    gen_defs_by_id=gen_defs_by_id_for_reorder,
                )
            except Exception:
                start_positions = {0} if ordered_assignments else set()

            for idx, assignment in enumerate(ordered_assignments):
                try:
                    this_id = str(assignment.get('node_id') or '').strip()
                    next_id = ''
                    if (idx + 1) < len(ordered_nodes):
                        next_id = str((ordered_nodes[idx + 1] or {}).get('id') or '').strip()
                    hint_templates: list[str] = []
                    try:
                        ht = assignment.get('hint_templates')
                        if isinstance(ht, list) and ht:
                            hint_templates = [str(x or '').strip() for x in ht if str(x or '').strip()]
                    except Exception:
                        hint_templates = []
                    tpl = str(assignment.get('hint_template') or '').strip() or (hint_templates[0] if hint_templates else 'Next: {{NEXT_NODE_NAME}}')
                    assignment['next_node_id'] = str(next_id)
                    assignment['next_node_name'] = str(id_to_name.get(str(next_id)) or '')
                    rendered = [_render_hint(t, this_id=this_id, next_id=str(next_id)) for t in (hint_templates or [tpl])]
                    pivot_hints = [
                        str(x or '').strip()
                        for x in (assignment.get('pivot_hints') or [])
                        if str(x or '').strip()
                    ] if isinstance(assignment.get('pivot_hints'), list) else []
                    rendered = [str(x or '').strip() for x in (rendered or []) if str(x or '').strip()]
                    for pivot_hint in pivot_hints:
                        if pivot_hint not in rendered:
                            rendered.append(pivot_hint)
                    assignment['hint'] = rendered[0] if rendered else _render_hint(tpl, this_id=this_id, next_id=str(next_id))
                    assignment['hints'] = rendered
                    if pivot_hints:
                        levels = assignment.get('hint_levels') if isinstance(assignment.get('hint_levels'), dict) else {}
                        levels = dict(levels or {})
                        low_values = [str(x or '').strip() for x in (levels.get('low') or []) if str(x or '').strip()] if isinstance(levels.get('low'), list) else []
                        for pivot_hint in pivot_hints:
                            if pivot_hint not in low_values:
                                low_values.append(pivot_hint)
                        levels['low'] = low_values
                        assignment['hint_levels'] = levels
                    try:
                        _flow_apply_first_step_chain_supplied_inputs(
                            assignment,
                            assignment,
                            scenario_label=scenario_label,
                            position=idx,
                            supply_on_start=(idx in start_positions),
                        )
                    except Exception:
                        pass
                except Exception:
                    continue
            return ordered_nodes, ordered_assignments

        def _high_dependency_greedy_order() -> tuple[list[dict[str, Any]], list[dict[str, Any]], dict[str, Any] | None] | None:
            _progress('high-dependency greedy ordering start')
            pairs: list[tuple[int, dict[str, Any], dict[str, Any]]] = []
            for idx, node_id in enumerate(chain_ids):
                node = node_by_id.get(node_id)
                assignment = assign_by_node.get(node_id)
                if not isinstance(node, dict) or not isinstance(assignment, dict):
                    _progress(f'high-dependency greedy skipped: missing node or assignment for {node_id}')
                    return None
                pairs.append((idx, node, assignment))
            if len(pairs) != len(chain_ids):
                _progress('high-dependency greedy skipped: incomplete pair list')
                return None
            remaining = list(pairs)
            ordered: list[tuple[int, dict[str, Any], dict[str, Any]]] = []
            known = set(initial_artifacts)
            chain_produced: set[str] = set()
            previous_produced: set[str] = set()

            while remaining:
                future_required: set[str] = set()
                for _idx, _node, assignment in remaining:
                    future_required |= _assignment_requires(assignment)
                eligible = [item for item in remaining if _assignment_requires(item[2]).issubset(known)]
                pool = eligible or list(remaining)
                _progress(f'high-dependency greedy step={len(ordered) + 1}/{len(pairs)} eligible={len(eligible)} remaining={len(remaining)}')

                def _score(item: tuple[int, dict[str, Any], dict[str, Any]]) -> tuple[int, int]:
                    original_index, _node, assignment = item
                    requires = _assignment_requires(assignment)
                    produces = _assignment_produces(assignment)
                    score = 0
                    if ordered:
                        score += 1000 * len(requires & previous_produced)
                        score += 250 * len(requires & chain_produced)
                    else:
                        score += 200 * len(produces & future_required)
                    score += 50 * len((produces - known) & future_required)
                    score += 5 * len(produces - known)
                    return score, -original_index

                chosen = max(pool, key=_score)
                remaining.remove(chosen)
                ordered.append(chosen)
                produced = _assignment_produces(chosen[2])
                known |= produced
                chain_produced |= produced
                previous_produced = set(produced)

            ordered_nodes = [node for _idx, node, _assignment in ordered]
            ordered_assignments = [assignment for _idx, _node, assignment in ordered]
            before_adjacent = _adjacent_dependency_count(flag_assignments)
            after_adjacent = _adjacent_dependency_count(ordered_assignments)
            current_valid = False
            try:
                _progress('validating current order before accepting greedy result')
                current_valid, _errors = _flow_validate_chain_order_by_requires_produces(
                    chain_nodes,
                    flag_assignments,
                    scenario_label=scenario_label,
                    plugins_by_id_override=plugins_by_id,
                )
                _progress(f'current order validation valid={bool(current_valid)} errors={len(_errors or [])}')
            except Exception:
                current_valid = False
            if after_adjacent <= before_adjacent and current_valid:
                debug: dict[str, Any] | None = None
                if return_debug:
                    debug = {
                        'ok': True,
                        'strategy': 'high_dependency_preserve',
                        'before_adjacent_dependencies': before_adjacent,
                        'after_adjacent_dependencies': before_adjacent,
                        'order': [str((node or {}).get('id') or '') for node in chain_nodes],
                    }
                refreshed_nodes, refreshed_assignments = _refresh_next_fields(chain_nodes, flag_assignments)
                _progress('high-dependency greedy preserved current order')
                _progress('DAG reorder complete strategy=high_dependency_preserve')
                return refreshed_nodes, refreshed_assignments, debug
            try:
                _progress('validating greedy candidate order')
                valid, _errors = _flow_validate_chain_order_by_requires_produces(
                    ordered_nodes,
                    ordered_assignments,
                    scenario_label=scenario_label,
                    plugins_by_id_override=plugins_by_id,
                )
                if not valid:
                    _progress(f'high-dependency greedy candidate invalid errors={len(_errors or [])}')
                    return None
                _progress('high-dependency greedy candidate valid')
            except Exception:
                pass
            debug: dict[str, Any] | None = None
            if return_debug:
                _greedy_edges: list[dict[str, Any]] = []
                for _gi, (_, _gni, _gai) in enumerate(ordered):
                    _src = str((_gai or {}).get('node_id') or (_gni or {}).get('id') or '')
                    _prod = _assignment_produces(_gai)
                    for _gj, (_, _gnj, _gaj) in enumerate(ordered):
                        if _gj <= _gi:
                            continue
                        _dst = str((_gaj or {}).get('node_id') or (_gnj or {}).get('id') or '')
                        _req = _assignment_requires(_gaj)
                        for _art in sorted(_prod & _req):
                            _greedy_edges.append({'src': _src, 'dst': _dst, 'artifact': _art})
                debug = {
                    'ok': True,
                    'strategy': 'high_dependency_greedy',
                    'before_adjacent_dependencies': before_adjacent,
                    'after_adjacent_dependencies': after_adjacent,
                    'order': [str((node or {}).get('id') or '') for node in ordered_nodes],
                    'edges': _greedy_edges,
                }
            refreshed_nodes, refreshed_assignments = _refresh_next_fields(ordered_nodes, ordered_assignments)
            _progress(f'high-dependency greedy selected order={",".join([str((node or {}).get("id") or "") for node in ordered_nodes])}')
            _progress('DAG reorder complete strategy=high_dependency_greedy')
            return refreshed_nodes, refreshed_assignments, debug

        try:
            if _flow_normalize_dependency_level(dependency_level) >= 5:
                _progress('trying high-dependency greedy reorder')
                greedy_result = _high_dependency_greedy_order()
                if greedy_result is not None:
                    return greedy_result
                _progress('high-dependency greedy did not produce an order')
        except Exception:
            pass

        try:
            _progress('checking current chain order before DAG build')
            current_valid, _current_errors = _flow_validate_chain_order_by_requires_produces(
                chain_nodes,
                flag_assignments,
                scenario_label=scenario_label,
                plugins_by_id_override=plugins_by_id,
            )
            _progress(f'current chain order valid={bool(current_valid)} errors={len(_current_errors or [])}')
            if not current_valid:
                _progress('trying greedy reorder for invalid current chain')
                greedy_result = _high_dependency_greedy_order()
                if greedy_result is not None:
                    return greedy_result
                _progress('greedy reorder for invalid current chain did not produce an order')
        except Exception:
            pass

        # Build a real sequencer chain instance (YAML-shape) from the current Flow chain.
        #
        # Important: some catalogs may omit requires/produces details or keep them coarse.
        # For Flow ordering we also incorporate the assignment-derived inputs/outputs as
        # additional requires/produces to avoid a no-op DAG.
        chain_doc: dict[str, Any] = {
            'ctf': {
                'id': str(scenario_label or '').strip() or 'flow',
                'version': 'flow',
                'difficulty': 'unknown',
                'description': 'Generated from Flow Sequencing assignments',
            },
            'challenges': [],
        }

        effective_plugins_by_id: dict[str, dict[str, Any]] = dict(plugins_by_id or {})
        challenges: list[dict[str, Any]] = []
        _progress(f'building DAG chain document challenges={len(chain_ids)}')
        for index, cid in enumerate(chain_ids, 1):
            a = assign_by_node.get(cid) or {}
            plugin_id = str(a.get('id') or '').strip()
            if not plugin_id:
                _progress(f'skipped DAG build: missing plugin id for node {cid}')
                return chain_nodes, flag_assignments, None
            plugin = plugins_by_id.get(plugin_id)
            if not isinstance(plugin, dict):
                # Without the plugin contract we can't build a correct artifact DAG.
                _progress(f'skipped DAG build: missing plugin contract {plugin_id}')
                return chain_nodes, flag_assignments, None

            inferred_requires = [str(x).strip() for x in (a.get('inputs') or []) if str(x).strip()]
            inferred_produces = [str(x).strip() for x in (a.get('outputs') or []) if str(x).strip()]

            # Build an "effective" plugin contract for DAG purposes.
            try:
                eff = dict(plugin)
            except Exception:
                eff = plugin

            try:
                base_req = [str(x).strip() for x in (eff.get('requires') or []) if str(x).strip()] if isinstance(eff, dict) else []
            except Exception:
                base_req = []
            eff_requires = sorted(list({*base_req, *inferred_requires}))
            if isinstance(eff, dict):
                eff['requires'] = eff_requires

            base_prod_set: set[str] = set()
            try:
                for p in (eff.get('produces') or []) if isinstance(eff, dict) else []:
                    if not isinstance(p, dict):
                        continue
                    art = str(p.get('artifact') or '').strip()
                    if art:
                        base_prod_set.add(art)
            except Exception:
                base_prod_set = set()
            eff_prod_set = {*(base_prod_set), *(set(inferred_produces))}
            if isinstance(eff, dict):
                eff['produces'] = [{'artifact': x} for x in sorted(list(eff_prod_set))]

            effective_plugins_by_id[plugin_id] = eff

            kind = str(plugin.get('plugin_type') or a.get('type') or 'flag-generator').strip() or 'flag-generator'
            requires_list: list[dict[str, str]] = []
            try:
                for art in (eff.get('requires') or []):
                    a2 = str(art or '').strip()
                    if a2:
                        requires_list.append({'artifact': a2})
            except Exception:
                requires_list = []

            ch = {
                'challenge_id': cid,
                'kind': kind,
                'plugin': plugin_id,
                'requires': requires_list,
            }
            chain_doc['challenges'].append(ch)

            # Also build the challenge instances for build_dag.
            challenges.append(ch)
            _progress(f'DAG chain document challenge={index}/{len(chain_ids)} node={cid} plugin={plugin_id}')

        _progress('validating DAG chain document')
        chain_ok, chain_errors, chain_norm = validate_chain_doc(chain_doc)
        _progress(f'DAG chain document validation ok={bool(chain_ok)} errors={len(chain_errors or [])}')

        _progress('building sequencer DAG')
        dag, errors = build_dag(challenges, plugins_by_id=effective_plugins_by_id, initial_artifacts=sorted(list(initial_artifacts)))
        _progress(f'sequencer DAG build complete ok={bool(dag is not None)} errors={len(errors or [])}')
        debug: dict[str, Any] | None = None
        if return_debug:
            try:
                debug = {
                    'ok': bool(dag is not None),
                    'errors': list(errors or []),
                    'initial_artifacts': sorted(list(initial_artifacts)),
                    'chain_ok': bool(chain_ok),
                    'chain_errors': list(chain_errors or []),
                }
                if dag is not None:
                    debug['order'] = list(dag.order)
                    debug['edges'] = [
                        {'src': e.src, 'dst': e.dst, 'artifact': e.artifact}
                        for e in (dag.edges or ())
                    ]
            except Exception:
                debug = None
        if dag is None:
            _progress('DAG build returned no order; keeping current chain')
            return chain_nodes, flag_assignments, debug

        order = [str(x) for x in (dag.order or ()) if str(x).strip()]
        if not order:
            _progress('DAG order empty; keeping current chain')
            return chain_nodes, flag_assignments, debug
        if set(order) != set(chain_ids):
            _progress('DAG order did not match chain ids; keeping current chain')
            return chain_nodes, flag_assignments, debug

        # Reorder nodes + assignments.
        new_chain_nodes = [node_by_id[cid] for cid in order if cid in node_by_id]
        new_assignments = [assign_by_node[cid] for cid in order if cid in assign_by_node]
        if len(new_chain_nodes) != len(chain_nodes) or len(new_assignments) != len(flag_assignments):
            _progress('DAG ordered result length mismatch; keeping current chain')
            return chain_nodes, flag_assignments, debug

        # Optional: validate that the new order is linearly solvable by the chain spec.
        # This uses only instance produces/requires; since we keep instance.requires empty,
        # this is expected to succeed (and is primarily a sanity check).
        if debug is not None:
            try:
                reordered_doc = dict(chain_norm or {})
                reordered_doc['challenges'] = [
                    next((c for c in (chain_norm.get('challenges') or []) if isinstance(c, dict) and str(c.get('challenge_id') or '') == cid), None)
                    for cid in order
                ]
                reordered_doc['challenges'] = [c for c in reordered_doc['challenges'] if isinstance(c, dict)]
                lin_ok, lin_errors = validate_linear_chain(reordered_doc, initial_artifacts=sorted(list(initial_artifacts)))
                debug['linear_ok'] = bool(lin_ok)
                debug['linear_errors'] = list(lin_errors or [])
            except Exception:
                pass

        # Update NEXT placeholders in hints for the new order.
        id_to_name: dict[str, str] = {}
        for n in new_chain_nodes:
            try:
                nid = str(n.get('id') or '').strip()
                nm = str(n.get('name') or '').strip()
                if nid:
                    id_to_name[nid] = nm or nid
            except Exception:
                continue

        def _render_hint(tpl: str, *, this_id: str, next_id: str) -> str:
            try:
                text = str(tpl or '').strip() or 'Next: {{NEXT_NODE_NAME}}'
                next_id_val = str(next_id or '').strip()
                next_name_val = (id_to_name.get(next_id_val) or '').strip() if next_id_val else ''
                if not next_id_val:
                    return "You've completed this sequence of challenges!"
                if not next_name_val:
                    next_name_val = next_id_val
                repl = {
                    '{{SCENARIO}}': str(scenario_label or ''),
                    '{{THIS_NODE_ID}}': this_id,
                    '{{THIS_NODE_NAME}}': id_to_name.get(this_id) or this_id,
                    '{{NEXT_NODE_ID}}': next_id_val,
                    '{{NEXT_NODE_NAME}}': next_name_val,
                }
                for k, v in repl.items():
                    text = text.replace(k, str(v))
                return _flow_strip_ids_from_hint(text)
            except Exception:
                return ''

        try:
            dag_start_positions = _flow_parallel_start_assignment_indexes(
                new_assignments,
                gen_defs_by_id=gen_defs_by_id_for_reorder,
            )
        except Exception:
            dag_start_positions = {0} if new_assignments else set()

        _progress(f'refreshing NEXT fields for DAG order={",".join(order)}')
        for i, a in enumerate(new_assignments):
            try:
                this_id = str(a.get('node_id') or '').strip()
                next_id = order[i + 1] if (i + 1) < len(order) else ''
                hint_templates: list[str] = []
                try:
                    ht = a.get('hint_templates')
                    if isinstance(ht, list) and ht:
                        hint_templates = [str(x or '').strip() for x in ht if str(x or '').strip()]
                except Exception:
                    hint_templates = []
                tpl = str(a.get('hint_template') or '').strip() or (hint_templates[0] if hint_templates else 'Next: {{NEXT_NODE_NAME}}')
                a['next_node_id'] = str(next_id)
                a['next_node_name'] = str(id_to_name.get(str(next_id)) or '')
                rendered = [_render_hint(t, this_id=this_id, next_id=str(next_id)) for t in (hint_templates or [tpl])]
                a['hint'] = rendered[0] if rendered else _render_hint(tpl, this_id=this_id, next_id=str(next_id))
                a['hints'] = rendered
                _flow_apply_first_step_chain_supplied_inputs(
                    a,
                    a,
                    scenario_label=scenario_label,
                    position=i,
                    supply_on_start=(i in dag_start_positions),
                )
            except Exception:
                continue

        _progress('DAG reorder complete')
        return new_chain_nodes, new_assignments, debug
    except BaseException as exc:
        if isinstance(exc, KeyboardInterrupt):
            raise
        _progress(f'failed: {type(exc).__name__}: {exc}')
        try:
            app.logger.exception('Flow DAG reorder failed; returning original chain.')
        except Exception:
            pass
        return chain_nodes, flag_assignments, None


