def _normalize_scenario_section_semantics(scenario_payload: Any) -> Dict[str, Any]:
    scenario = copy.deepcopy(scenario_payload) if isinstance(scenario_payload, dict) else {}
    sections = scenario.get('sections') if isinstance(scenario.get('sections'), dict) else None
    if not isinstance(sections, dict):
        return scenario

    node_section = sections.get('Node Information') if isinstance(sections.get('Node Information'), dict) else None
    routing_section = sections.get('Routing') if isinstance(sections.get('Routing'), dict) else None
    node_items = list(node_section.get('items') or []) if isinstance(node_section, dict) and isinstance(node_section.get('items'), list) else []
    routing_items = list(routing_section.get('items') or []) if isinstance(routing_section, dict) and isinstance(routing_section.get('items'), list) else []

    def _apply_count_defaults(item: Dict[str, Any]) -> None:
        if item.get('v_count') in (None, '') and item.get('count') not in (None, ''):
            item['v_count'] = item.get('count')
        if item.get('v_count') not in (None, '') and not str(item.get('v_metric') or '').strip():
            item['v_metric'] = 'Count'
        if str(item.get('v_metric') or '').strip() == 'Count' and item.get('v_count') in (None, '', 0):
            item['v_count'] = 1
        if item.get('factor') in (None, ''):
            item['factor'] = 1.0

    next_node_items: list[Any] = []
    moved_any = False
    for raw_item in node_items:
        if not isinstance(raw_item, dict):
            next_node_items.append(raw_item)
            continue
        item = copy.deepcopy(raw_item)
        raw_selected = str(item.get('selected') or '').strip()
        normalized_node = _normalize_node_information_role(raw_selected)
        if normalized_node:
            item['selected'] = normalized_node
            _apply_count_defaults(item)
            next_node_items.append(item)
            continue

        normalized_routing = _normalize_routing_item_selection(raw_selected)
        if normalized_routing:
            item['selected'] = normalized_routing
            _apply_count_defaults(item)
            routing_items.append(item)
            moved_any = True
            continue

        next_node_items.append(item)

    if node_items or isinstance(node_section, dict):
        if not isinstance(node_section, dict):
            node_section = {'items': []}
        node_section['items'] = next_node_items
        sections['Node Information'] = node_section

    if moved_any and not isinstance(routing_section, dict):
        routing_section = {'density': 0.0, 'items': []}
    if moved_any and routing_section.get('density') in (None, ''):
        routing_section['density'] = 0.0
    if moved_any:
        routing_section['items'] = routing_items
        sections['Routing'] = routing_section

    for raw_item in routing_items:
        if not isinstance(raw_item, dict):
            continue
        raw_selected = raw_item.get('selected')
        normalized_selected = _normalize_routing_item_selection(raw_selected)
        if normalized_selected:
            raw_item['selected'] = normalized_selected
        _apply_count_defaults(raw_item)

    service_section = sections.get('Services') if isinstance(sections.get('Services'), dict) else None
    service_items = service_section.get('items') if isinstance(service_section, dict) and isinstance(service_section.get('items'), list) else []
    for raw_item in service_items:
        if not isinstance(raw_item, dict):
            continue
        raw_selected = raw_item.get('selected')
        normalized_selected = _normalize_service_item_selection(raw_selected)
        if normalized_selected:
            raw_item['selected'] = normalized_selected
        _apply_count_defaults(raw_item)

    traffic_section = sections.get('Traffic') if isinstance(sections.get('Traffic'), dict) else None
    traffic_items = traffic_section.get('items') if isinstance(traffic_section, dict) and isinstance(traffic_section.get('items'), list) else []
    for raw_item in traffic_items:
        if not isinstance(raw_item, dict):
            continue
        raw_selected = raw_item.get('selected')
        normalized_selected = _normalize_traffic_item_selection(raw_selected)
        if normalized_selected:
            raw_item['selected'] = normalized_selected
        raw_pattern = raw_item.get('pattern')
        normalized_pattern = _normalize_traffic_pattern_value(raw_pattern)
        if normalized_pattern:
            raw_item['pattern'] = normalized_pattern
        raw_content_type = raw_item.get('content_type')
        normalized_content_type = _normalize_traffic_content_type_value(raw_content_type)
        if normalized_content_type:
            raw_item['content_type'] = normalized_content_type
        _apply_count_defaults(raw_item)

    segmentation_section = sections.get('Segmentation') if isinstance(sections.get('Segmentation'), dict) else None
    segmentation_items = segmentation_section.get('items') if isinstance(segmentation_section, dict) and isinstance(segmentation_section.get('items'), list) else []
    for raw_item in segmentation_items:
        if not isinstance(raw_item, dict):
            continue
        raw_selected = raw_item.get('selected')
        normalized_selected = _normalize_segmentation_item_selection(raw_selected)
        if normalized_selected and normalized_selected != 'CUSTOM':
            raw_item['selected'] = normalized_selected
        if _coerce_bool(raw_item.get('pivot_enabled')):
            raw_item['pivot_enabled'] = True
            provider = str(raw_item.get('pivot_provider') or raw_item.get('access_provider') or 'random').strip().lower().replace('_', '-')
            provider_aliases = {
                'auto': 'random',
                'none': 'random',
                'manual': 'random',
                'ssh': 'ssh-fallback',
                'ssh-server': 'ssh-fallback',
                'fallback-ssh': 'ssh-fallback',
                'flag-node': 'flag-node-generator',
                'flag-nodegen': 'flag-node-generator',
                'vuln': 'vulnerability',
            }
            raw_item['pivot_provider'] = provider_aliases.get(provider, provider or 'random')
        _apply_count_defaults(raw_item)

    if not isinstance(node_section, dict):
        node_section = {'items': []}

    scenario['sections'] = sections
    scenario = _canonicalize_specific_vulnerability_items(scenario, strict=False)
    if isinstance(scenario.get('plan_preview'), dict):
        scenario['plan_preview'] = _canonicalize_plan_preview_vulnerability_names(
            scenario.get('plan_preview'),
            scenario_payload=scenario,
        )
    scenario, docker_capacity_repair = _ensure_vulnerability_docker_capacity(scenario)
    if docker_capacity_repair.get('added_docker_hosts'):
        scenario['docker_capacity_repair'] = docker_capacity_repair
    return scenario


def _deterministic_random_fraction(seed_text: Any) -> float:
    base = hashlib.sha256(str(seed_text or '').encode('utf-8')).digest()
    digest = hashlib.sha256(base + (0).to_bytes(8, byteorder='little', signed=False)).digest()
    value = int.from_bytes(digest[:8], byteorder='big', signed=False)
    return value / 18446744073709551616


def _deterministic_pick(options: List[Any], seed_text: Any) -> Any:
    if not options:
        return None
    if len(options) == 1:
        return options[0]
    idx = int(_deterministic_random_fraction(seed_text) * len(options)) % len(options)
    return options[idx]


def _coerce_numeric_placeholder(value: Any, *, default: float, minimum: float | None = None, maximum: float | None = None) -> float:
    text = str(value or '').strip()
    if text.lower() == 'random':
        numeric = default
    else:
        try:
            numeric = float(text) if text else default
        except Exception:
            numeric = default
    if minimum is not None and numeric < minimum:
        numeric = minimum
    if maximum is not None and numeric > maximum:
        numeric = maximum
    return numeric


def _random_reroll_salt(item: Any, key: str) -> str:
    if not isinstance(item, dict):
        return ''
    bag = item.get('_random_reroll')
    if not isinstance(bag, dict):
        return ''
    value = bag.get(str(key or 'selected'))
    return f'|{value}' if value not in (None, '') else ''


def _concretize_traffic_numeric_placeholder(value: Any, *, options: List[float], seed_text: Any, default: float, minimum: float | None = None, maximum: float | None = None) -> float:
    text = str(value or '').strip()
    if not text or text.lower() == 'random':
        picked = _deterministic_pick(options, seed_text)
        numeric = float(picked if picked is not None else default)
    else:
        numeric = _coerce_numeric_placeholder(value, default=default, minimum=minimum, maximum=maximum)
    if minimum is not None and numeric < minimum:
        numeric = minimum
    if maximum is not None and numeric > maximum:
        numeric = maximum
    return numeric


def _load_backend_vuln_catalog_items(*, selectable_only: bool = True) -> List[Dict[str, Any]]:
    try:
        state = _load_vuln_catalogs_state()
        entry = _get_active_vuln_catalog_entry(state)
    except Exception:
        entry = None

    if isinstance(entry, dict):
        try:
            catalog_id = str(entry.get('id') or '').strip()
            norm_items = _normalize_vuln_catalog_items(entry)
            out: List[Dict[str, Any]] = []
            for item in norm_items:
                if not isinstance(item, dict):
                    continue
                eligible = _vuln_catalog_item_is_selectable(item)
                if selectable_only and not eligible:
                    continue
                try:
                    abs_compose = _vuln_catalog_item_abs_compose_path(catalog_id=catalog_id, item=item)
                except Exception:
                    continue
                out.append({
                    'Name': _vuln_catalog_item_display_name(item),
                    'Path': os.path.abspath(abs_compose),
                    'Type': 'docker-compose',
                    'Vector': '',
                    'Startup': '',
                    'CVE': '',
                    'Description': '',
                    'References': '',
                    'id': str(item.get('id') or '').strip(),
                    'validated_ok': bool(item.get('validated_ok')) if item.get('validated_ok') is not None else None,
                    'validated_at': str(item.get('validated_at') or '').strip() or None,
                    'eligible_for_selection': eligible,
                })
            return out
        except Exception:
            if selectable_only:
                return []

    try:
        from scenarioforge.utils.vuln_process import load_vuln_catalog
        if selectable_only:
            return []
        items = load_vuln_catalog(_get_repo_root()) or []
        return [item for item in items if isinstance(item, dict)]
    except Exception:
        return []


def _canonicalize_specific_vulnerability_items(
    scenario_payload: Any,
    *,
    strict: bool = False,
) -> Dict[str, Any]:
    scenario = copy.deepcopy(scenario_payload) if isinstance(scenario_payload, dict) else {}
    sections = scenario.get('sections') if isinstance(scenario.get('sections'), dict) else None
    if not isinstance(sections, dict):
        return scenario

    vuln_section = sections.get('Vulnerabilities') if isinstance(sections.get('Vulnerabilities'), dict) else None
    items = vuln_section.get('items') if isinstance(vuln_section, dict) and isinstance(vuln_section.get('items'), list) else None
    if not isinstance(items, list):
        return scenario

    catalog_items = _load_backend_vuln_catalog_items()
    if strict:
        requested_targets = 0
        for item in items:
            if not isinstance(item, dict):
                continue
            selected = str(item.get('selected') or '').strip()
            if not selected:
                continue
            count_raw = item.get('v_count') if item.get('v_count') not in (None, '') else item.get('count')
            try:
                count_value = int(count_raw)
            except Exception:
                try:
                    count_value = int(float(count_raw))
                except Exception:
                    count_value = 1
            requested_targets += max(1, count_value)
        eligible_count = len(catalog_items)
        if requested_targets > eligible_count:
            vuln_label = 'vulnerability is' if eligible_count == 1 else 'vulnerabilities are'
            target_label = 'target is' if requested_targets == 1 else 'targets are'
            raise ValueError(
                f'Only {eligible_count} validated/tested {vuln_label} currently eligible in the Vulnerability Catalog, '
                f'but {requested_targets} vulnerability {target_label} required. Validate more vulnerabilities or reduce the requested vulnerability count.'
            )
    from scenarioforge.utils.vuln_process import resolve_vulnerability_catalog_entry

    for item in items:
        if not isinstance(item, dict):
            continue
        selected = str(item.get('selected') or '').strip().lower()
        if selected != 'specific':
            continue
        resolved = resolve_vulnerability_catalog_entry(
            catalog_items,
            v_name=str(item.get('v_name') or ''),
            v_path=str(item.get('v_path') or item.get('path') or ''),
        )
        if resolved:
            item['v_name'] = resolved['name']
            current_path = str(item.get('v_path') or item.get('path') or '').strip()
            item['v_path'] = current_path or resolved['path']
            continue
        if strict:
            raise ValueError('Specific vulnerability must match an enabled catalog entry by v_path or v_name')

    return scenario


def _specific_vulnerability_name_map(scenario_payload: Any) -> Dict[str, str]:
    original = copy.deepcopy(scenario_payload) if isinstance(scenario_payload, dict) else {}
    canonical = _canonicalize_specific_vulnerability_items(original, strict=False)
    original_sections = original.get('sections') if isinstance(original.get('sections'), dict) else {}
    canonical_sections = canonical.get('sections') if isinstance(canonical.get('sections'), dict) else {}
    original_items = ((original_sections.get('Vulnerabilities') or {}).get('items') or []) if isinstance(original_sections, dict) else []
    canonical_items = ((canonical_sections.get('Vulnerabilities') or {}).get('items') or []) if isinstance(canonical_sections, dict) else []
    mapping: Dict[str, str] = {}
    for original_item, canonical_item in zip(original_items, canonical_items):
        if not isinstance(original_item, dict) or not isinstance(canonical_item, dict):
            continue
        if str(original_item.get('selected') or '').strip().lower() != 'specific':
            continue
        source_name = str(original_item.get('v_name') or '').strip()
        target_name = str(canonical_item.get('v_name') or '').strip()
        if source_name and target_name:
            mapping[source_name] = target_name
        target_path = str(canonical_item.get('v_path') or '').strip()
        if target_name:
            mapping[target_name] = target_name
            short_name = target_name.split('/', 1)[0].strip()
            if short_name:
                mapping[short_name] = target_name
        if target_path:
            try:
                path_parts = [part for part in target_path.replace('\\', '/').split('/') if part]
                if len(path_parts) >= 2:
                    path_alias = path_parts[-2].strip()
                    if path_alias:
                        mapping[path_alias] = target_name or mapping.get(path_alias, path_alias)
            except Exception:
                pass
    return mapping


def _canonicalize_plan_preview_vulnerability_names(plan_preview: Any, *, scenario_payload: Any) -> Any:
    if not isinstance(plan_preview, dict):
        return plan_preview

    name_map = _specific_vulnerability_name_map(scenario_payload)
    if not name_map:
        return plan_preview

    payload = copy.deepcopy(plan_preview)
    full_preview = payload.get('full_preview') if isinstance(payload.get('full_preview'), dict) else None
    if not isinstance(full_preview, dict):
        return payload

    def _rename_list(values: Any) -> Any:
        if not isinstance(values, list):
            return values
        return [name_map.get(str(value or '').strip(), str(value or '').strip()) for value in values if str(value or '').strip()]

    for group_name in ('hosts', 'routers', 'switches'):
        nodes = full_preview.get(group_name)
        if not isinstance(nodes, list):
            continue
        for node in nodes:
            if not isinstance(node, dict):
                continue
            if isinstance(node.get('vulnerabilities'), list):
                node['vulnerabilities'] = _rename_list(node.get('vulnerabilities'))

    for field_name in ('vulnerabilities_preview', 'vulnerabilities_by_node'):
        raw_map = full_preview.get(field_name)
        if not isinstance(raw_map, dict):
            continue
        next_map: Dict[Any, Any] = {}
        for key, value in raw_map.items():
            next_map[key] = _rename_list(value)
        full_preview[field_name] = next_map

    raw_plan = full_preview.get('vulnerabilities_plan')
    if isinstance(raw_plan, dict):
        next_plan: Dict[str, int] = {}
        for key, value in raw_plan.items():
            next_key = name_map.get(str(key or '').strip(), str(key or '').strip())
            if not next_key:
                continue
            try:
                next_value = int(value) if value is not None else 0
            except Exception:
                try:
                    next_value = int(float(value))
                except Exception:
                    next_value = 0
            next_plan[next_key] = next_plan.get(next_key, 0) + next_value
        full_preview['vulnerabilities_plan'] = next_plan

    payload['full_preview'] = full_preview
    return payload


def _concretize_preview_placeholders(scenario_payload: Any, *, seed: Any = None) -> Dict[str, Any]:
    scenario = _normalize_scenario_section_semantics(scenario_payload)
    sections = scenario.get('sections') if isinstance(scenario.get('sections'), dict) else None
    if not isinstance(sections, dict):
        return scenario

    seed_value = seed
    try:
        seed_int = int(seed_value)
        if seed_int <= 0:
            seed_int = 1
    except Exception:
        seed_int = 1
    scenario_name = str(scenario.get('name') or '').strip() or 'Scenario'

    vuln_catalog_items = _load_backend_vuln_catalog_items()
    target_sections = ['Node Information', 'Routing', 'Services', 'Traffic', 'Vulnerabilities', 'Segmentation']
    for section_name in target_sections:
        sec = sections.get(section_name) if isinstance(sections.get(section_name), dict) else None
        if not isinstance(sec, dict):
            continue
        items = sec.get('items') if isinstance(sec.get('items'), list) else []
        next_items: list[dict[str, Any]] = []
        if section_name == 'Vulnerabilities':
            for index, raw_item in enumerate(items):
                if not isinstance(raw_item, dict):
                    continue
                item = copy.deepcopy(raw_item)
                raw_selected = str(item.get('selected') or '').strip()
                normalized_selected = raw_selected.lower()
                is_random_selected = (not raw_selected) or normalized_selected == 'random'
                if is_random_selected and vuln_catalog_items:
                    chosen = _deterministic_pick(
                        vuln_catalog_items,
                        f'{seed_int}|{scenario_name}|{section_name}|{index}|v_name|save-xml',
                    )
                    picked_name = str((chosen or {}).get('Name') or (chosen or {}).get('name') or '').strip()
                    picked_path = str((chosen or {}).get('Path') or (chosen or {}).get('path') or '').strip()
                    picked_desc = str((chosen or {}).get('Description') or (chosen or {}).get('description') or '').strip()
                    if picked_name:
                        item['selected'] = 'Specific'
                        item['v_name'] = picked_name
                        if picked_path:
                            item['v_path'] = picked_path
                        if picked_desc:
                            item['v_desc'] = picked_desc
                        if str(item.get('v_metric') or '').strip() in {'', 'Weight'}:
                            item['v_metric'] = 'Count'
                        if item.get('v_count') in (None, '', 0):
                            item['v_count'] = 1
                next_items.append(item)
            sec['items'] = next_items
            sections[section_name] = sec
            continue

        options = list(_RANDOM_OPTIONS_BY_SECTION.get(section_name) or [])
        if section_name in {'Traffic', 'Segmentation'}:
            options = [option for option in options if option != 'CUSTOM']
        for index, raw_item in enumerate(items):
            if not isinstance(raw_item, dict):
                continue
            item = copy.deepcopy(raw_item)

            if section_name == 'Routing':
                raw_selected = item.get('selected')
                if raw_selected in (None, ''):
                    raw_selected = item.get('protocol')
                normalized_selected = _normalize_routing_item_selection(raw_selected)
                if normalized_selected:
                    item['selected'] = normalized_selected

                if item.get('v_count') not in (None, '') and not str(item.get('v_metric') or '').strip():
                    item['v_metric'] = 'Count'
                if str(item.get('v_metric') or '').strip() == 'Count' and item.get('v_count') in (None, '', 0):
                    item['v_count'] = 1
                if item.get('factor') in (None, ''):
                    item['factor'] = 1.0

                for mode_key in ('r2r_mode', 'r2s_mode'):
                    raw_mode = str(item.get(mode_key) or '').strip()
                    if not raw_mode or raw_mode.lower() == 'random':
                        chosen_mode = _deterministic_pick(
                            _ROUTING_EDGE_MODE_OPTIONS,
                            f'{seed_int}|{scenario_name}|Routing|{index}|{mode_key}|save-xml',
                        )
                        item[mode_key] = str(chosen_mode or 'Uniform')

                r2r_mode = str(item.get('r2r_mode') or '').strip()
                if r2r_mode == 'Exact':
                    try:
                        r2r_edges = int(item.get('r2r_edges') or 0)
                    except Exception:
                        r2r_edges = 0
                    if r2r_edges <= 0:
                        item['r2r_edges'] = int(_deterministic_pick([2, 3, 4], f'{seed_int}|{scenario_name}|Routing|{index}|r2r_edges|save-xml') or 2)
                else:
                    item.pop('r2r_edges', None)

                r2s_mode = str(item.get('r2s_mode') or '').strip()
                if r2s_mode == 'Exact':
                    try:
                        r2s_edges = int(item.get('r2s_edges') or 0)
                    except Exception:
                        r2s_edges = 0
                    if r2s_edges <= 0:
                        item['r2s_edges'] = int(_deterministic_pick([1, 2, 3], f'{seed_int}|{scenario_name}|Routing|{index}|r2s_edges|save-xml') or 1)
                else:
                    item.pop('r2s_edges', None)

                if r2s_mode == 'NonUniform':
                    try:
                        r2s_hosts_min = int(item.get('r2s_hosts_min') or 0)
                    except Exception:
                        r2s_hosts_min = 0
                    try:
                        r2s_hosts_max = int(item.get('r2s_hosts_max') or 0)
                    except Exception:
                        r2s_hosts_max = 0
                    if r2s_hosts_min <= 0:
                        r2s_hosts_min = 1
                    if r2s_hosts_max <= 0:
                        r2s_hosts_max = 4
                    if r2s_hosts_min > r2s_hosts_max:
                        r2s_hosts_min, r2s_hosts_max = r2s_hosts_max, r2s_hosts_min
                    item['r2s_hosts_min'] = r2s_hosts_min
                    item['r2s_hosts_max'] = r2s_hosts_max

            raw_selected = str(item.get('selected') or '').strip()
            if (not raw_selected or raw_selected.lower() == 'random') and options:
                pick = _deterministic_pick(
                    options,
                    f'{seed_int}|{scenario_name}|{section_name}|{index}|selected|save-xml',
                )
                if pick is not None:
                    item['selected'] = str(pick)

            if section_name == 'Traffic':
                raw_ct = str(item.get('content_type') or '').strip()
                if not raw_ct or raw_ct.lower() == 'random':
                    pick_ct = _deterministic_pick(
                        _TRAFFIC_CONTENT_TYPE_OPTIONS,
                        f'{seed_int}|{scenario_name}|{section_name}|{index}|content_type|save-xml',
                    )
                    if pick_ct is not None:
                        item['content_type'] = str(pick_ct)

                ct_now = str(item.get('content_type') or '').strip()
                raw_pattern = str(item.get('pattern') or '').strip()
                if raw_pattern.lower() == 'bursty':
                    item['pattern'] = 'burst'
                    raw_pattern = 'burst'
                if ct_now and ct_now.lower() != 'random' and (not raw_pattern or raw_pattern.lower() == 'random'):
                    pick_pattern = _deterministic_pick(
                        _TRAFFIC_PATTERN_OPTIONS,
                        f'{seed_int}|{scenario_name}|{section_name}|{index}|pattern|save-xml',
                    )
                    if pick_pattern is not None:
                        item['pattern'] = str(pick_pattern)

                item['rate_kbps'] = _concretize_traffic_numeric_placeholder(
                    item.get('rate_kbps'),
                    options=_TRAFFIC_RATE_OPTIONS,
                    seed_text=f'{seed_int}|{scenario_name}|{section_name}|{index}|rate_kbps{_random_reroll_salt(item, "rate_kbps")}|save-xml',
                    default=_TRAFFIC_NUMERIC_DEFAULTS['rate_kbps'],
                    minimum=0.0,
                )
                item['period_s'] = _concretize_traffic_numeric_placeholder(
                    item.get('period_s'),
                    options=_TRAFFIC_PERIOD_OPTIONS,
                    seed_text=f'{seed_int}|{scenario_name}|{section_name}|{index}|period_s{_random_reroll_salt(item, "period_s")}|save-xml',
                    default=_TRAFFIC_NUMERIC_DEFAULTS['period_s'],
                    minimum=0.0,
                )
                item['jitter_pct'] = _concretize_traffic_numeric_placeholder(
                    item.get('jitter_pct'),
                    options=_TRAFFIC_JITTER_OPTIONS,
                    seed_text=f'{seed_int}|{scenario_name}|{section_name}|{index}|jitter_pct{_random_reroll_salt(item, "jitter_pct")}|save-xml',
                    default=_TRAFFIC_NUMERIC_DEFAULTS['jitter_pct'],
                    minimum=0.0,
                    maximum=100.0,
                )

            next_items.append(item)

        sec['items'] = next_items
        sections[section_name] = sec

    try:
        ni = sections.get('Node Information') if isinstance(sections.get('Node Information'), dict) else None
        ni_items = ni.get('items') if isinstance(ni, dict) and isinstance(ni.get('items'), list) else []
        density_count = 0
        try:
            density_count = int(str(scenario.get('density_count') or '').strip() or '0')
        except Exception:
            density_count = 0
        count_rows = [
            it for it in ni_items
            if isinstance(it, dict) and str(it.get('v_metric') or '').strip().lower() == 'count'
        ]
        count_sum = 0
        for item in count_rows:
            try:
                count_sum += max(0, int(item.get('v_count') or 0))
            except Exception:
                pass
        weight_rows = [
            it for it in ni_items
            if isinstance(it, dict) and str(it.get('v_metric') or 'Weight').strip().lower() != 'count'
        ]
        has_usable_weight = any(
            (float(str(it.get('factor') or 'nan')) > 0) if str(it.get('factor') or '').strip() else True
            for it in weight_rows if isinstance(it, dict)
        ) if weight_rows else False
        planned_from_weight = density_count if (density_count > 0 and has_usable_weight) else 0
        routing_items = sections.get('Routing', {}).get('items') if isinstance(sections.get('Routing'), dict) else []
        has_routing_items = any(isinstance(it, dict) for it in routing_items) if isinstance(routing_items, list) else False
        if count_sum + planned_from_weight <= 0 and not has_routing_items:
            if not isinstance(ni, dict):
                ni = {'items': []}
            if not isinstance(ni.get('items'), list):
                ni['items'] = []
            ni['items'].append({'selected': 'PC', 'v_metric': 'Count', 'v_count': 10, 'factor': 1.0})
            sections['Node Information'] = ni
    except Exception:
        pass

    scenario['sections'] = sections
    return scenario


def _concretize_scenarios_for_save(scenarios_payload: Any, *, seed: Any = None) -> list[Any]:
    if not isinstance(scenarios_payload, list):
        return []

    try:
        seed_int = int(seed)
        if seed_int <= 0:
            seed_int = 1
    except Exception:
        seed_int = 1

    concretized: list[Any] = []
    for scenario in scenarios_payload:
        if not isinstance(scenario, dict):
            concretized.append(scenario)
            continue
        try:
            next_scenario = copy.deepcopy(scenario)
            scenario_name = str(next_scenario.get('name') or '').strip() or 'Scenario'
            sections = next_scenario.get('sections') if isinstance(next_scenario.get('sections'), dict) else None
            if isinstance(sections, dict):
                routing_section = sections.get('Routing') if isinstance(sections.get('Routing'), dict) else None
                routing_items = routing_section.get('items') if isinstance(routing_section, dict) and isinstance(routing_section.get('items'), list) else None
                if isinstance(routing_items, list):
                    next_items: list[Any] = []
                    for index, raw_item in enumerate(routing_items):
                        if not isinstance(raw_item, dict):
                            next_items.append(raw_item)
                            continue

                        item = copy.deepcopy(raw_item)
                        raw_selected = str(item.get('selected') or '').strip()
                        if not raw_selected or raw_selected.lower() == 'random':
                            selected = _deterministic_pick(
                                _ROUTING_RANDOM_PROTOCOL_DEFAULTS,
                                f'{seed_int}|{scenario_name}|Routing|{index}|selected|save-xml',
                            )
                            item['selected'] = str(selected or 'OSPFv2')

                        for mode_key in ('r2r_mode', 'r2s_mode'):
                            raw_mode = str(item.get(mode_key) or '').strip()
                            if not raw_mode or raw_mode.lower() == 'random':
                                chosen_mode = _deterministic_pick(
                                    _ROUTING_EDGE_MODE_OPTIONS,
                                    f'{seed_int}|{scenario_name}|Routing|{index}|{mode_key}|save-xml',
                                )
                                item[mode_key] = str(chosen_mode or 'Uniform')

                        r2r_mode = str(item.get('r2r_mode') or '').strip()
                        if r2r_mode == 'Exact':
                            try:
                                r2r_edges = int(item.get('r2r_edges') or 0)
                            except Exception:
                                r2r_edges = 0
                            if r2r_edges <= 0:
                                item['r2r_edges'] = int(_deterministic_pick([2, 3, 4], f'{seed_int}|{scenario_name}|Routing|{index}|r2r_edges|save-xml') or 2)
                        else:
                            item.pop('r2r_edges', None)

                        r2s_mode = str(item.get('r2s_mode') or '').strip()
                        if r2s_mode == 'Exact':
                            try:
                                r2s_edges = int(item.get('r2s_edges') or 0)
                            except Exception:
                                r2s_edges = 0
                            if r2s_edges <= 0:
                                item['r2s_edges'] = int(_deterministic_pick([1, 2, 3], f'{seed_int}|{scenario_name}|Routing|{index}|r2s_edges|save-xml') or 1)

                        if r2s_mode == 'NonUniform':
                            try:
                                r2s_hosts_min = int(item.get('r2s_hosts_min') or 0)
                            except Exception:
                                r2s_hosts_min = 0
                            try:
                                r2s_hosts_max = int(item.get('r2s_hosts_max') or 0)
                            except Exception:
                                r2s_hosts_max = 0
                            if r2s_hosts_min <= 0:
                                r2s_hosts_min = 1
                            if r2s_hosts_max <= 0:
                                r2s_hosts_max = 4
                            if r2s_hosts_min > r2s_hosts_max:
                                r2s_hosts_min, r2s_hosts_max = r2s_hosts_max, r2s_hosts_min
                            item['r2s_hosts_min'] = r2s_hosts_min
                            item['r2s_hosts_max'] = r2s_hosts_max

                        next_items.append(item)

                    routing_section['items'] = next_items
                    sections['Routing'] = routing_section
                    next_scenario['sections'] = sections

                segmentation_section = sections.get('Segmentation') if isinstance(sections.get('Segmentation'), dict) else None
                segmentation_items = segmentation_section.get('items') if isinstance(segmentation_section, dict) and isinstance(segmentation_section.get('items'), list) else None
                if isinstance(segmentation_items, list):
                    next_items = []
                    for index, raw_item in enumerate(segmentation_items):
                        if not isinstance(raw_item, dict):
                            next_items.append(raw_item)
                            continue

                        item = copy.deepcopy(raw_item)
                        if _coerce_bool(item.get('pivot_enabled')):
                            provider = str(item.get('pivot_provider') or item.get('access_provider') or 'random').strip().lower().replace('_', '-')
                            provider_aliases = {
                                'auto': 'random',
                                'none': 'random',
                                'manual': 'random',
                                'ssh': 'ssh-fallback',
                                'ssh-server': 'ssh-fallback',
                                'fallback-ssh': 'ssh-fallback',
                                'flag-node': 'flag-node-generator',
                                'flagnode': 'flag-node-generator',
                                'flag-nodegen': 'flag-node-generator',
                                'vuln': 'vulnerability',
                            }
                            provider = provider_aliases.get(provider, provider or 'random')
                            if provider == 'random':
                                provider = str(_deterministic_pick(
                                    _PIVOT_PROVIDER_OPTIONS,
                                    f'{seed_int}|{scenario_name}|Segmentation|{index}|pivot_provider{_random_reroll_salt(item, "pivot_provider")}|save-xml',
                                ) or 'ssh-fallback')
                            if provider in _PIVOT_PROVIDER_OPTIONS:
                                item['pivot_provider'] = provider
                        next_items.append(item)

                    segmentation_section['items'] = next_items
                    sections['Segmentation'] = segmentation_section
                    next_scenario['sections'] = sections

            concretized.append(next_scenario)
        except Exception:
            concretized.append(copy.deepcopy(scenario))
    return concretized


def _default_scenarios_payload_for_names(names: Iterable[Any] | None) -> Dict[str, Any]:
    scenario_names: list[str] = []
    for entry in names or []:
        try:
            text = str(entry or '').strip()
        except Exception:
            text = ''
        if text:
            scenario_names.append(text)
    if not scenario_names:
        scenario_names = ["Scenario 1"]

    return {
        "scenarios": [_default_scenario_payload(name) for name in scenario_names],
        "result_path": None,
        "core": _default_core_dict(),
        "host_interfaces": _enumerate_host_interfaces(),
    }


def _empty_scenarios_payload() -> Dict[str, Any]:
    return {
        "scenarios": [],
        "result_path": None,
        "core": _default_core_dict(),
        "host_interfaces": _enumerate_host_interfaces(),
    }


def _filter_scenarios_by_norms(
    scenarios: Iterable[Any],
    allowed_norms: set[str],
) -> List[Dict[str, Any]]:
    filtered: List[Dict[str, Any]] = []
    if not allowed_norms:
        return filtered
    allowed_keys = {key for key in (_scenario_match_key(v) for v in allowed_norms) if key}
    if not allowed_keys:
        return filtered
    for scen in scenarios or []:
        if not isinstance(scen, dict):
            continue
        if _scenario_match_key(scen.get('name')) in allowed_keys:
            filtered.append(scen)
    return filtered


def _collect_scenario_norms(scenarios: Iterable[Any]) -> set[str]:
    norms: set[str] = set()
    for scen in scenarios or []:
        if not isinstance(scen, dict):
            continue
        norm = _normalize_scenario_label(scen.get('name'))
        if norm:
            norms.add(norm)
    return norms


def _order_scenarios_by_catalog_names(
    scenarios: Iterable[Any],
    catalog_names: Iterable[Any] | None,
) -> List[Dict[str, Any]]:
    ordered: List[Dict[str, Any]] = []
    for scen in scenarios or []:
        if isinstance(scen, dict):
            ordered.append(scen)
    if not ordered:
        return ordered

    rank_by_norm: Dict[str, int] = {}
    next_rank = 0
    for display in catalog_names or []:
        norm = _normalize_scenario_label(display)
        if not norm or norm in rank_by_norm:
            continue
        rank_by_norm[norm] = next_rank
        next_rank += 1

    indexed = list(enumerate(ordered))
    indexed.sort(
        key=lambda pair: (
            rank_by_norm.get(_normalize_scenario_label(pair[1].get('name')), float('inf')),
            _scenario_display_sort_key(pair[1].get('name')),
            pair[0],
        )
    )
    return [item for _idx, item in indexed]


def _prepare_payload_for_index(payload: Optional[Dict[str, Any]], *, user: Optional[dict] = None) -> Dict[str, Any]:
    """Normalize payload data before rendering the index page."""
    if not isinstance(payload, dict):
        payload = {}
    else:
        payload = dict(payload)

    had_explicit_scenarios_list = isinstance(payload.get('scenarios'), list)

    try:
        force_empty = _scenario_catalog_force_empty()
        payload['scenario_catalog_force_empty'] = bool(force_empty)
        if force_empty:
            payload['scenario_catalog_names'] = []
            payload['scenario_catalog_empty'] = True
        else:
            scenario_names_live, _scenario_paths_live, _scenario_url_hints_live = _scenario_catalog_for_user(None, user=user)
            payload['scenario_catalog_names'] = _sort_scenario_display_names(scenario_names_live)
            payload['scenario_catalog_empty'] = not bool(scenario_names_live)
    except Exception:
        payload['scenario_catalog_names'] = []
        payload['scenario_catalog_empty'] = True
        payload['scenario_catalog_force_empty'] = False

    project_hint_raw = payload.get('project_key_hint') if isinstance(payload.get('project_key_hint'), str) else None
    project_hint = project_hint_raw.strip() if isinstance(project_hint_raw, str) else None
    scenario_hint_raw = payload.get('scenario_query') if isinstance(payload.get('scenario_query'), str) else None
    scenario_hint = scenario_hint_raw.strip() if isinstance(scenario_hint_raw, str) else None
    allowed_norms = _builder_allowed_norms(user)
    builder_assignment_order: Optional[list[str]] = None
    if allowed_norms is not None:
        builder_assignment_order = _assigned_scenarios_for_user(user)

    defaults = _default_scenarios_payload()

    # --- Core connection defaults ---
    core_meta = _normalize_core_config(payload.get('core'), include_password=True)
    core_defaults = defaults['core']
    if not core_meta.get('host'):
        core_meta['host'] = core_defaults.get('host')
    if not core_meta.get('port'):
        core_meta['port'] = core_defaults.get('port')
    # Ensure ssh_host defaults to current host to simplify UI when enabling later
    if not core_meta.get('ssh_host'):
        core_meta['ssh_host'] = core_meta.get('host') or core_defaults.get('host')
    if not core_meta.get('ssh_port'):
        core_meta['ssh_port'] = 22
    payload['core'] = core_meta

    # --- Scenarios ---
    scenarios_raw = payload.get('scenarios')
    if not isinstance(scenarios_raw, list):
        # For actual restricted roles (builder/participant), an empty assignment list
        # should result in an empty scenario list ("all or none" visibility).
        scenarios_raw = defaults['scenarios'] if allowed_norms is None else []
    # For restricted roles, always build scenarios from catalog + assignments so
    # Scenarios/CORE/Reports are consistent (including ordering).
    if allowed_norms is not None and allowed_norms:
        seeded = _builder_catalog_seed_scenarios(allowed_norms, builder_assignment_order, user=user)
        if seeded:
            scenarios_raw = seeded

    required_sections = {
        'Node Information': {'density': None, 'total_nodes': None},
        'Routing': {'density': 0.5},
        'Services': {'density': 0.5},
        'Traffic': {'density': 0.5},
        'Vulnerabilities': {'density': 0.5, 'flag_type': 'text'},
        'Segmentation': {'density': 0.5},
        'HITL': {},
    }

    normalized_scenarios: List[Dict[str, Any]] = []
    for idx, scen in enumerate(scenarios_raw, start=1):
        if not isinstance(scen, dict):
            continue
        scen_norm = dict(scen)
        scen_norm['name'] = scen_norm.get('name') or f"Scenario {idx}"

        base_meta = scen_norm.get('base')
        if not isinstance(base_meta, dict):
            base_meta = {}
        base_meta = dict(base_meta)
        filepath = base_meta.get('filepath')
        if not isinstance(filepath, str):
            filepath = '' if filepath is None else str(filepath)
        base_meta['filepath'] = filepath
        if filepath and not base_meta.get('display_name'):
            base_meta['display_name'] = os.path.basename(filepath)
        scen_norm['base'] = base_meta

        if 'density_count' not in scen_norm:
            scen_norm['density_count'] = 10

        sections_meta = scen_norm.get('sections')
        if not isinstance(sections_meta, dict):
            sections_meta = {}
        sections_out: Dict[str, Any] = {}
        for section_name, defaults_map in required_sections.items():
            sec_val = sections_meta.get(section_name)
            if isinstance(sec_val, dict):
                sec_norm = dict(sec_val)
            else:
                sec_norm = {}
            items = sec_norm.get('items')
            if isinstance(items, list):
                sec_norm['items'] = [item for item in items if isinstance(item, dict)]
            else:
                sec_norm['items'] = []
            for key, val in defaults_map.items():
                sec_norm.setdefault(key, val)
            sections_out[section_name] = sec_norm
        for extra_name, extra_val in sections_meta.items():
            if extra_name == 'Events':
                continue
            if extra_name not in sections_out:
                sections_out[extra_name] = extra_val
        scen_norm['sections'] = sections_out

        hitl_meta = scen_norm.get('hitl')
        if isinstance(hitl_meta, dict):
            hitl_norm = dict(hitl_meta)
        else:
            hitl_norm = {}
        hitl_norm['enabled'] = bool(hitl_norm.get('enabled'))
        interfaces_raw = hitl_norm.get('interfaces')
        interfaces_norm: List[Dict[str, Any]] = []
        if isinstance(interfaces_raw, list):
            for iface in interfaces_raw:
                if not isinstance(iface, dict):
                    continue
                iface_norm = dict(iface)
                name = iface_norm.get('name')
                if not isinstance(name, str):
                    name = '' if name is None else str(name)
                name = name.strip()
                if not name:
                    continue
                iface_norm['name'] = name
                iface_norm['attachment'] = _normalize_hitl_attachment(iface_norm.get('attachment'))
                for addr_key in ('ipv4', 'ipv6'):
                    vals = iface_norm.get(addr_key)
                    if isinstance(vals, list):
                        iface_norm[addr_key] = [str(v).strip() for v in vals if v is not None and str(v).strip()]
                interfaces_norm.append(iface_norm)
        hitl_norm['interfaces'] = interfaces_norm
        hitl_norm['core'] = _extract_optional_core_config(hitl_norm.get('core'), include_password=True)

        prox_raw = hitl_norm.get('proxmox') if isinstance(hitl_norm.get('proxmox'), dict) else {}
        prox_norm: Dict[str, Any] = {}
        for key in ('url', 'port', 'verify_ssl', 'secret_id', 'validated', 'last_validated_at', 'stored_at', 'last_message', 'remember_credentials', 'inventory'):
            if key in prox_raw:
                prox_norm[key] = prox_raw.get(key)
        if isinstance(prox_norm.get('url'), str):
            prox_norm['url'] = prox_norm['url'].strip()
        if isinstance(prox_norm.get('secret_id'), str):
            prox_norm['secret_id'] = prox_norm['secret_id'].strip() or None
        if 'port' in prox_norm:
            try:
                prox_norm['port'] = int(prox_norm.get('port'))
            except Exception:
                prox_norm.pop('port', None)
        if 'verify_ssl' in prox_norm:
            prox_norm['verify_ssl'] = _coerce_bool(prox_norm.get('verify_ssl'))
        if 'validated' in prox_norm:
            prox_norm['validated'] = _coerce_bool(prox_norm.get('validated'))
        if 'remember_credentials' in prox_norm:
            prox_norm['remember_credentials'] = _coerce_bool(prox_norm.get('remember_credentials'))
        for ts_key in ('last_validated_at', 'stored_at'):
            if ts_key in prox_norm and not isinstance(prox_norm.get(ts_key), str):
                prox_norm[ts_key] = None
        if prox_norm:
            hitl_norm['proxmox'] = prox_norm

        scen_norm['hitl'] = hitl_norm

        ai_generator_meta = _sanitize_ai_generator_state(scen_norm.get('ai_generator'))
        if ai_generator_meta:
            scen_norm['ai_generator'] = ai_generator_meta
        else:
            scen_norm.pop('ai_generator', None)

        normalized_scenarios.append(scen_norm)

    # Only synthesize a default scenario when the caller omitted scenarios entirely.
    if not normalized_scenarios and allowed_norms is None and not had_explicit_scenarios_list:
        normalized_scenarios = defaults['scenarios']

    # If the UI is in builder mode (even for admin users previewing builder view),
    # merge admin-managed HITL validation hints into scenarios so builder cannot
    # appear "unassigned" when admin has already selected a CORE VM.
    try:
        view_mode = getattr(g, 'ui_view_mode', None)
    except Exception:
        view_mode = None
    if not isinstance(view_mode, str) or not view_mode.strip():
        try:
            role_hint = (user.get('role') if isinstance(user, dict) else None) or 'admin'
            view_mode = _default_ui_view_mode_for_role(role_hint)
        except Exception:
            view_mode = 'admin'
    if view_mode != 'participant':
        try:
            hitl_validation_hints = _load_scenario_hitl_validation_from_disk()
            builder_hitl_fallback = _select_builder_hitl_fallback(hitl_validation_hints)
            hitl_config_hints = _load_scenario_hitl_config_from_disk()
            builder_hitl_config_fallback = _select_builder_hitl_fallback(hitl_config_hints) if hitl_config_hints else None
            try:
                _, _, participant_urls_by_norm = _load_scenario_catalog_from_disk()
            except Exception:
                participant_urls_by_norm = {}
        except Exception:
            hitl_validation_hints = {}
            builder_hitl_fallback = None
            hitl_config_hints = {}
            builder_hitl_config_fallback = None
            participant_urls_by_norm = {}

        for scen in normalized_scenarios:
            if not isinstance(scen, dict):
                continue
            norm = _normalize_scenario_label(scen.get('name'))
            validation_hint = hitl_validation_hints.get(norm) if (norm and isinstance(hitl_validation_hints, dict)) else None
            effective_hint = validation_hint if isinstance(validation_hint, dict) and validation_hint else builder_hitl_fallback
            config_hint = hitl_config_hints.get(norm) if (norm and isinstance(hitl_config_hints, dict)) else None
            effective_cfg = config_hint if isinstance(config_hint, dict) and config_hint else builder_hitl_config_fallback
            if not (isinstance(effective_hint, dict) and effective_hint) and not (isinstance(effective_cfg, dict) and effective_cfg):
                continue

            effective_hint_dict: Dict[str, Any] = effective_hint if isinstance(effective_hint, dict) else {}

            hitl_meta = scen.get('hitl') if isinstance(scen.get('hitl'), dict) else {}
            hitl_meta = dict(hitl_meta)

            # Merge participant URL hints (non-secret) so builder view shows Step 5 as configured.
            try:
                participant_hint = participant_urls_by_norm.get(norm) if (norm and isinstance(participant_urls_by_norm, dict)) else ''
                if participant_hint:
                    for k in ('participant_proxmox_url', 'participant_ui_url', 'participant_url', 'participant'):
                        if k not in hitl_meta or hitl_meta.get(k) in (None, ''):
                            hitl_meta[k] = participant_hint
            except Exception:
                pass

            prox_hint = effective_hint_dict.get('proxmox') if isinstance(effective_hint_dict.get('proxmox'), dict) else None
            if isinstance(prox_hint, dict) and prox_hint:
                prox_state = hitl_meta.get('proxmox') if isinstance(hitl_meta.get('proxmox'), dict) else {}
                prox_state = dict(prox_state)
                for k, v in prox_hint.items():
                    if k not in prox_state or prox_state.get(k) in (None, '', False):
                        prox_state[k] = v
                hitl_meta['proxmox'] = prox_state

            core_hint = effective_hint_dict.get('core') if isinstance(effective_hint_dict.get('core'), dict) else None
            if isinstance(core_hint, dict) and core_hint:
                core_state = hitl_meta.get('core') if isinstance(hitl_meta.get('core'), dict) else {}
                core_state = dict(core_state)
                for k, v in core_hint.items():
                    if k not in core_state or core_state.get(k) in (None, '', False):
                        core_state[k] = v
                hitl_meta['core'] = core_state

            # Apply HITL configuration hints (enabled/interfaces/mappings)
            if isinstance(effective_cfg, dict) and effective_cfg:
                try:
                    participant_cfg = _normalize_participant_proxmox_url(effective_cfg.get('participant_proxmox_url'))
                    if participant_cfg:
                        for k in ('participant_proxmox_url', 'participant_ui_url', 'participant_url', 'participant'):
                            if k not in hitl_meta or hitl_meta.get(k) in (None, ''):
                                hitl_meta[k] = participant_cfg
                except Exception:
                    pass
                if 'enabled' in effective_cfg:
                    hitl_meta['enabled'] = bool(effective_cfg.get('enabled'))
                if isinstance(effective_cfg.get('interfaces'), list):
                    hitl_meta['interfaces'] = effective_cfg.get('interfaces')
                cfg_prox = effective_cfg.get('proxmox') if isinstance(effective_cfg.get('proxmox'), dict) else None
                if isinstance(cfg_prox, dict) and cfg_prox:
                    prox_state = hitl_meta.get('proxmox') if isinstance(hitl_meta.get('proxmox'), dict) else {}
                    prox_state = dict(prox_state)
                    for k, v in cfg_prox.items():
                        if k not in prox_state or prox_state.get(k) in (None, '', False):
                            prox_state[k] = v
                    hitl_meta['proxmox'] = prox_state
                cfg_core = effective_cfg.get('core') if isinstance(effective_cfg.get('core'), dict) else None
                if isinstance(cfg_core, dict) and cfg_core:
                    core_state = hitl_meta.get('core') if isinstance(hitl_meta.get('core'), dict) else {}
                    core_state = dict(core_state)
                    for k, v in cfg_core.items():
                        if k not in core_state or core_state.get(k) in (None, '', False):
                            core_state[k] = v
                    hitl_meta['core'] = core_state

            scen['hitl'] = hitl_meta
    if allowed_norms is not None:
        # If there are assignments, filter to them.
        if allowed_norms:
            normalized_scenarios = _filter_scenarios_by_norms(normalized_scenarios, allowed_norms)
        else:
            normalized_scenarios = []
        # Always mark as restricted when allowed_norms is not None.
        payload['builder_restricted_scenarios'] = True
        payload['builder_assigned_scenarios'] = sorted(allowed_norms)
        payload['builder_no_assignments'] = not bool(allowed_norms)
    else:
        payload.pop('builder_restricted_scenarios', None)
        payload.pop('builder_assigned_scenarios', None)
        payload.pop('builder_no_assignments', None)
        payload.pop('builder_assigned_scenarios', None)
        payload.pop('builder_no_assignments', None)

    # Keep Scenarios-page lists consistent across tabs: if active XML hydration
    # produced only a subset of scenarios, append catalog-backed stubs for any
    # missing scenario names so VM/Access + Topology show the same list as
    # Flag Sequencing + Preview.
    try:
        if allowed_norms is None:
            catalog_names = payload.get('scenario_catalog_names') if isinstance(payload.get('scenario_catalog_names'), list) else []
            existing_norms = _collect_scenario_norms(normalized_scenarios)
            for display_name in catalog_names:
                norm = _normalize_scenario_label(display_name)
                if not norm or norm in existing_norms:
                    continue
                normalized_scenarios.append(_default_scenario_payload(display_name))
                existing_norms.add(norm)
    except Exception:
        pass

    try:
        normalized_scenarios = _order_scenarios_by_catalog_names(
            normalized_scenarios,
            payload.get('scenario_catalog_names') if isinstance(payload.get('scenario_catalog_names'), list) else [],
        )
    except Exception:
        pass

    payload['scenarios'] = normalized_scenarios

    # --- Base upload metadata ---
    base_upload = payload.get('base_upload')
    if isinstance(base_upload, dict):
        base_norm = dict(base_upload)
        path = base_norm.get('path')
        if isinstance(path, str):
            base_norm['path'] = path
            base_norm.setdefault('display_name', os.path.basename(path) if path else '')
        else:
            base_norm['path'] = ''
        if 'valid' in base_norm:
            base_norm['valid'] = bool(base_norm['valid'])
        payload['base_upload'] = base_norm

    # --- Host interfaces ---
    host_ifaces = payload.get('host_interfaces')
    if not isinstance(host_ifaces, list):
        host_ifaces = []
    sanitized_ifaces: List[Dict[str, Any]] = []
    adaptor_names: set[str] = set()
    for iface in host_ifaces:
        if not isinstance(iface, dict):
            continue
        entry = dict(iface)
        name = entry.get('name')
        if isinstance(name, str):
            name = name.strip()
        elif name is not None:
            name = str(name)
        else:
            name = ''
        entry['name'] = name
        if name:
            adaptor_names.add(name)
        for arr_key in ('ipv4', 'ipv6', 'flags'):
            vals = entry.get(arr_key)
            if isinstance(vals, list):
                entry[arr_key] = [v for v in vals if v not in (None, '')]
        sanitized_ifaces.append(entry)
    payload['host_interfaces'] = sanitized_ifaces
    payload['hitl_adaptors'] = sorted(adaptor_names)

    payload.setdefault('result_path', defaults['result_path'])

    try:
        scen_names_for_catalog = [scen.get('name') for scen in normalized_scenarios if isinstance(scen, dict)]
        # Build a per-scenario participant URL hint map. Include explicit empty values
        # so we can clear stale catalog hints when a user removes a URL in the editor.
        participant_hints: Dict[str, Any] = {}
        for scen in normalized_scenarios:
            if not isinstance(scen, dict):
                continue
            name = scen.get('name')
            norm = _normalize_scenario_label(name)
            if not norm:
                continue
            hitl_meta = scen.get('hitl') if isinstance(scen.get('hitl'), dict) else None
            participant_url_value = ''
            if hitl_meta:
                for key in ('participant_proxmox_url', 'participant_ui_url', 'participant_url', 'participant'):
                    candidate = hitl_meta.get(key)
                    normalized = _normalize_participant_proxmox_url(candidate)
                    if normalized:
                        participant_url_value = normalized
                        break
            participant_hints[norm] = participant_url_value or ''

        if allowed_norms is None:
            result_path = payload.get('result_path') if isinstance(payload.get('result_path'), str) else None
            should_persist = bool(result_path)
            if not should_persist:
                try:
                    should_persist = not os.path.exists(_scenario_catalog_file())
                except Exception:
                    should_persist = False
            if should_persist:
                _persist_scenario_catalog(scen_names_for_catalog, result_path, participant_urls=participant_hints)
            else:
                if participant_hints:
                    _merge_participant_urls_into_scenario_catalog(participant_hints)
        else:
            if participant_hints:
                _merge_participant_urls_into_scenario_catalog(participant_hints)
    except Exception:
        pass

    if project_hint:
        payload['project_key_hint'] = project_hint
    elif payload.get('result_path') and not payload.get('project_key_hint'):
        payload['project_key_hint'] = payload['result_path']
    if scenario_hint:
        payload['scenario_query'] = scenario_hint

    return payload


def _merge_catalog_scenario_stubs_into_payload(payload: Optional[Dict[str, Any]]) -> Dict[str, Any]:
    """Ensure payload.scenarios contains catalog-named scenario stubs for missing entries."""
    if not isinstance(payload, dict):
        return payload if isinstance(payload, dict) else {}

    try:
        scenarios = payload.get('scenarios') if isinstance(payload.get('scenarios'), list) else []
        catalog_names = payload.get('scenario_catalog_names') if isinstance(payload.get('scenario_catalog_names'), list) else []
        deleted_match_keys = _scenario_catalog_deleted_match_keys()
        if payload.get('_filter_deleted_scenarios') is True:
            scenarios = [
                scenario
                for scenario in scenarios
                if not (
                    isinstance(scenario, dict)
                    and _scenario_match_key(scenario.get('name')) in deleted_match_keys
                )
            ]
        catalog_names = [name for name in catalog_names if _scenario_match_key(name) not in deleted_match_keys]
        catalog_names = _sort_scenario_display_names(catalog_names)
        payload['scenario_catalog_names'] = catalog_names
        existing_norms = _collect_scenario_norms(scenarios)
        for display_name in catalog_names:
            norm = _normalize_scenario_label(display_name)
            if not norm or norm in existing_norms:
                continue
            scenarios.append(_default_scenario_payload(display_name))
            existing_norms.add(norm)
        try:
            scenarios = _order_scenarios_by_catalog_names(scenarios, catalog_names)
        except Exception:
            pass
        payload['scenarios'] = scenarios
    except Exception:
        pass
    return payload


