def _find_latest_session_xml(base_dir: str, stem: str | None = None) -> str | None:
    """Best-effort helper to locate the newest session XML written previously.

    If `stem` is provided, prefer files beginning with that stem; otherwise
    return the most recent .xml file under the directory.
    """
    try:
        if not base_dir or not os.path.isdir(base_dir):
            return None
        candidates: list[tuple[float, str]] = []
        for name in os.listdir(base_dir):
            if not name.lower().endswith('.xml'):
                continue
            if stem:
                prefix = f"{stem}-"
                if not name.startswith(prefix):
                    continue
            path = os.path.join(base_dir, name)
            try:
                st = os.stat(path)
                candidates.append((st.st_mtime, path))
            except Exception:
                continue
        if not candidates and stem:
            return _find_latest_session_xml(base_dir, stem=None)
        if not candidates:
            return None
        candidates.sort(key=lambda item: item[0], reverse=True)
        return candidates[0][1]
    except Exception:
        return None


def _expected_from_plan_preview(scenario_xml_path: str, scenario_label: Optional[str]) -> Dict[int, Dict[str, Any]]:
    expected: Dict[int, Dict[str, Any]] = {}
    if not scenario_xml_path or not os.path.exists(scenario_xml_path):
        return expected
    payload = _load_plan_preview_from_xml(scenario_xml_path, scenario_label)
    if not isinstance(payload, dict):
        return expected
    full = payload.get('full_preview') if isinstance(payload.get('full_preview'), dict) else payload
    if not isinstance(full, dict):
        return expected
    services_preview = full.get('services_preview') if isinstance(full.get('services_preview'), dict) else {}

    def _add_node(entry: dict, role: str | None = None) -> None:
        try:
            nid = entry.get('node_id') if isinstance(entry, dict) else None
            if nid is None:
                nid = entry.get('id') if isinstance(entry, dict) else None
            nid_int = int(nid)
        except Exception:
            return
        name = str(entry.get('name') or '').strip() if isinstance(entry, dict) else ''
        ip4 = str(entry.get('ip4') or '').strip() if isinstance(entry, dict) else ''
        expected.setdefault(nid_int, {'name': name, 'ip4': ip4, 'role': role, 'services': None})

    for r in (full.get('routers') or []):
        if isinstance(r, dict):
            _add_node(r, role='router')
    for h in (full.get('hosts') or []):
        if isinstance(h, dict):
            _add_node(h, role=str(h.get('role') or 'host').strip().lower())
    for sid, svcs in (services_preview or {}).items():
        try:
            nid_int = int(str(sid).strip())
        except Exception:
            continue
        if not isinstance(svcs, list):
            continue
        entry = expected.setdefault(nid_int, {'name': '', 'ip4': '', 'role': None, 'services': None})
        entry['services'] = list({str(s).strip() for s in svcs if str(s).strip()})
    return expected


def _append_session_scenario_discrepancies(
    report_path: Optional[str],
    scenario_xml_path: Optional[str],
    session_xml_path: Optional[str],
    scenario_label: Optional[str] = None,
) -> None:
    if not report_path or not os.path.exists(report_path):
        return
    if not scenario_xml_path or not session_xml_path:
        return
    try:
        with open(report_path, 'r', encoding='utf-8', errors='ignore') as rf:
            existing = rf.read()
        if '## Scenario/Session Discrepancies' in existing:
            return
    except Exception:
        existing = None

    expected = _expected_from_plan_preview(scenario_xml_path, scenario_label)
    actual = _parse_session_xml_for_compare(session_xml_path)

    lines: List[str] = []
    lines.append('\n## Scenario/Session Discrepancies')
    if not expected:
        lines.append('PlanPreview missing in scenario XML; comparison skipped.')
        _append_report_lines(report_path, lines)
        return
    if not actual:
        lines.append('Session XML missing or unreadable; comparison skipped.')
        _append_report_lines(report_path, lines)
        return

    expected_ids = set(expected.keys())
    actual_ids = set(actual.keys())
    missing_nodes = sorted(expected_ids - actual_ids)
    extra_nodes = sorted(actual_ids - expected_ids)

    mismatch_rows: List[str] = []
    for nid in sorted(expected_ids & actual_ids):
        exp = expected.get(nid) or {}
        act = actual.get(nid) or {}
        exp_name = (exp.get('name') or '').strip()
        act_name = (act.get('name') or '').strip()
        exp_ip = (exp.get('ip4') or '').strip()
        act_ips = sorted(list(act.get('ips') or []))
        exp_services = exp.get('services')
        act_services = sorted(list(act.get('services') or []))

        name_mismatch = exp_name and act_name and exp_name != act_name
        ip_mismatch = bool(exp_ip) and (exp_ip not in act_ips)
        svc_missing: List[str] = []
        svc_extra: List[str] = []
        if isinstance(exp_services, list):
            exp_set = set(exp_services)
            act_set = set(act_services)
            svc_missing = sorted(list(exp_set - act_set))
            svc_extra = sorted(list(act_set - exp_set))

        if name_mismatch or ip_mismatch or svc_missing or svc_extra:
            mismatch_rows.append(
                f"| {nid} | {exp_name or 'n/a'} | {act_name or 'n/a'} | {exp_ip or 'n/a'} | {', '.join(act_ips) or 'n/a'} | {', '.join(svc_missing) or '—'} | {', '.join(svc_extra) or '—'} |"
            )

    if not missing_nodes and not extra_nodes and not mismatch_rows:
        lines.append('No discrepancies detected.')
        _append_report_lines(report_path, lines)
        return

    if missing_nodes:
        lines.append(f"- Missing nodes in session XML: {', '.join(str(n) for n in missing_nodes)}")
    if extra_nodes:
        lines.append(f"- Extra nodes in session XML: {', '.join(str(n) for n in extra_nodes)}")
    if mismatch_rows:
        lines.append('')
        lines.append('| Node ID | Expected Name | Actual Name | Expected IP | Actual IPs | Missing Services | Extra Services |')
        lines.append('| ---: | --- | --- | --- | --- | --- | --- |')
        lines.extend(mismatch_rows)
    _append_report_lines(report_path, lines)


def _append_report_lines(report_path: str, lines: List[str]) -> None:
    try:
        with open(report_path, 'a', encoding='utf-8') as wf:
            wf.write('\n'.join(lines).rstrip() + '\n')
    except Exception:
        pass


def _persist_execute_validation_artifacts(
    report_path: Optional[str],
    summary_path: Optional[str],
    validation: Optional[dict],
) -> None:
    if not isinstance(validation, dict) or not validation:
        return

    def _count(key: str) -> int:
        try:
            v = validation.get(key)
            return len(v) if isinstance(v, list) else 0
        except Exception:
            return 0

    status_ok = bool(validation.get('ok'))
    counts = {
        'validation_missing_nodes': _count('missing_nodes'),
        'validation_extra_nodes': _count('extra_nodes'),
        'validation_docker_missing': _count('docker_missing'),
        'validation_docker_not_running': _count('docker_not_running'),
        'validation_injects_missing': _count('injects_missing'),
        'validation_generator_outputs_missing': _count('generator_outputs_missing'),
        'validation_generator_injects_missing': _count('generator_injects_missing'),
    }

    if report_path and os.path.exists(report_path):
        try:
            existing = ''
            with open(report_path, 'r', encoding='utf-8', errors='ignore') as rf:
                existing = rf.read()
            if '## Execute Validation Summary' not in existing:
                lines: List[str] = []
                lines.append('')
                lines.append('## Execute Validation Summary')
                lines.append(f"- Status: {'passed' if status_ok else 'issues detected'}")
                lines.append(f"- Missing nodes: {counts['validation_missing_nodes']}")
                lines.append(f"- Unexpected nodes: {counts['validation_extra_nodes']}")
                lines.append(f"- Missing docker containers: {counts['validation_docker_missing']}")
                lines.append(f"- Docker not running: {counts['validation_docker_not_running']}")
                lines.append(f"- Missing injects: {counts['validation_injects_missing']}")
                lines.append(f"- Missing generator outputs: {counts['validation_generator_outputs_missing']}")
                lines.append(f"- Missing generator inject sources: {counts['validation_generator_injects_missing']}")
                _append_report_lines(report_path, lines)
        except Exception:
            pass


def _build_execute_error_logs(
    *,
    run_id: str,
    validation: Dict[str, Any],
    main_log_path: Optional[str] = None,
) -> List[Dict[str, str]]:
    if not isinstance(validation, dict):
        return []
    run_norm = str(run_id or '').strip() or 'unknown'
    out_dir = os.path.join(_outputs_dir(), 'logs', 'execute-errors', run_norm)
    try:
        os.makedirs(out_dir, exist_ok=True)
    except Exception:
        return []

    categories: List[tuple[str, str, str]] = [
        ('missing_nodes', 'Missing nodes', 'missing_nodes.log'),
        ('extra_nodes', 'Unexpected nodes', 'extra_nodes.log'),
        ('missing_docker_nodes', 'Missing docker nodes', 'missing_docker_nodes.log'),
        ('extra_docker_nodes', 'Unexpected docker nodes', 'extra_docker_nodes.log'),
        ('docker_missing', 'Missing docker containers', 'docker_missing.log'),
        ('docker_not_running', 'Docker not running', 'docker_not_running.log'),
        ('injects_missing', 'Missing injects/sources', 'injects_missing.log'),
        ('generator_outputs_missing', 'Missing generator outputs', 'generator_outputs_missing.log'),
        ('generator_injects_missing', 'Missing generator inject sources', 'generator_injects_missing.log'),
    ]

    logs: List[Dict[str, str]] = []
    now = _local_timestamp_display()
    has_issue = not bool(validation.get('ok'))

    def _filter_string_details_for_items(details: Any, item_values: Any) -> list[Any]:
        if not isinstance(details, list) or not details:
            return []
        if not isinstance(item_values, list) or not item_values:
            return []
        item_names = [str(item or '').strip() for item in item_values if str(item or '').strip()]
        if not item_names:
            return []
        filtered: list[Any] = []
        for detail in details:
            text = str(detail or '').strip()
            if any(text.startswith(f"{name}:") for name in item_names):
                filtered.append(detail)
        return filtered

    for key, label, fname in categories:
        items = validation.get(key)
        if not isinstance(items, list) or not items:
            continue
        has_issue = True
        path = os.path.join(out_dir, fname)
        payload = {
            'run_id': run_norm,
            'generated_at': now,
            'category': key,
            'label': label,
            'count': len(items),
            'items': items,
        }
        if key == 'docker_not_running':
            details = validation.get('docker_not_running_details')
            if isinstance(details, list) and details:
                payload['details'] = details
        if key == 'injects_missing':
            details = validation.get('injects_detail')
            if isinstance(details, list) and details:
                payload['details'] = _filter_string_details_for_items(details, items) or details
        if key in {'generator_outputs_missing', 'generator_injects_missing'}:
            details = validation.get('generator_validation_detail')
            if isinstance(details, list) and details:
                payload['details'] = details
        try:
            with open(path, 'w', encoding='utf-8') as wf:
                wf.write(json.dumps(payload, indent=2, sort_keys=True, default=str))
                wf.write('\n')
        except Exception:
            continue
        logs.append({'key': key, 'label': label, 'path': path})

    val_error = str(validation.get('error') or '').strip()
    if val_error:
        has_issue = True
        path = os.path.join(out_dir, 'validation_error.log')
        payload = {
            'run_id': run_norm,
            'generated_at': now,
            'label': 'Validation error',
            'error': val_error,
        }
        try:
            with open(path, 'w', encoding='utf-8') as wf:
                wf.write(json.dumps(payload, indent=2, sort_keys=True, default=str))
                wf.write('\n')
            logs.append({'key': 'validation_error', 'label': 'Validation error', 'path': path})
        except Exception:
            pass

    if has_issue and main_log_path and os.path.exists(main_log_path):
        path = os.path.join(out_dir, 'run_output.log')
        try:
            with open(main_log_path, 'r', encoding='utf-8', errors='ignore') as rf:
                content = rf.read()
            with open(path, 'w', encoding='utf-8') as wf:
                wf.write(content)
            logs.append({'key': 'run_output', 'label': 'Full run output', 'path': path})
        except Exception:
            pass

    return logs

    if summary_path and os.path.exists(summary_path):
        try:
            with open(summary_path, 'r', encoding='utf-8') as sf:
                payload = json.load(sf)
            if not isinstance(payload, dict):
                return
            payload['validation_summary'] = validation
            counts_obj = payload.get('counts') if isinstance(payload.get('counts'), dict) else {}
            counts_obj['validation_ok'] = status_ok
            counts_obj.update(counts)
            payload['counts'] = counts_obj
            meta = payload.get('metadata') if isinstance(payload.get('metadata'), dict) else {}
            meta['execute_validation_summary'] = validation
            payload['metadata'] = meta
            with open(summary_path, 'w', encoding='utf-8') as sf:
                json.dump(payload, sf, indent=2, sort_keys=True, default=str)
        except Exception:
            pass

def _attach_base_upload(payload: Dict[str, Any]):
    """Ensure payload['base_upload'] is present if first scenario has a base filepath referencing an existing file.
    Performs validation to set valid flag. Does nothing if already present.
    """
    try:
        if payload.get('base_upload'):
            return
        scen_list = payload.get('scenarios') or []
        if not scen_list:
            return
        base_path = scen_list[0].get('base', {}).get('filepath') or ''
        if not base_path or not os.path.exists(base_path):
            return
        ok, _errs = _validate_core_xml(base_path)
        display_name = os.path.basename(base_path)
        payload['base_upload'] = {
            'path': base_path,
            'valid': bool(ok),
            'display_name': display_name,
        }
        try:
            scen_list[0].setdefault('base', {})['display_name'] = display_name
        except Exception:
            pass
    except Exception:
        pass


def _parse_scenarios_xml(path):
    data = {"scenarios": []}
    tree = ET.parse(path)
    root = tree.getroot()
    if root.tag != "Scenarios":
        # Fallback: if file is a single ScenarioEditor, wrap
        if root.tag == "ScenarioEditor":
            scen = _parse_scenario_editor(root)
            scen["name"] = os.path.splitext(os.path.basename(path))[0]
            scen = _canonicalize_specific_vulnerability_items(scen, strict=False)
            if isinstance(scen.get('plan_preview'), dict):
                scen['plan_preview'] = _canonicalize_plan_preview_vulnerability_names(
                    scen.get('plan_preview'),
                    scenario_payload=scen,
                )
            data["scenarios"].append(scen)
            return data
        raise ValueError("Root element must be <Scenarios> or <ScenarioEditor>")
    core_el = root.find('CoreConnection')
    if core_el is not None:
        core_meta = _extract_optional_core_config(dict(core_el.attrib), include_password=True)
        data['core'] = core_meta if isinstance(core_meta, dict) else _normalize_core_config({}, include_password=True)
    else:
        data['core'] = _default_core_dict()

    for scen_el in root.findall("Scenario"):
        scen = {"name": scen_el.get("name", "Scenario")}
        # Capture scenario-level density_count attribute if present
        dc_attr = scen_el.get('density_count')
        if dc_attr is not None and dc_attr != '':
            try:
                scen['density_count'] = int(dc_attr)
            except Exception:
                pass
        total_nodes_attr = scen_el.get('scenario_total_nodes')
        if total_nodes_attr not in (None, ''):
            try:
                scen['scenario_total_nodes'] = int(total_nodes_attr)
            except Exception:
                scen['scenario_total_nodes'] = total_nodes_attr
        base_nodes_attr = scen_el.get('base_nodes')
        if base_nodes_attr not in (None, ''):
            try:
                scen['base_nodes'] = int(base_nodes_attr)
            except Exception:
                scen['base_nodes'] = base_nodes_attr
        try:
            min_en_attr = str(scen_el.get('density_count_min_enabled') or '').strip().lower()
            if min_en_attr in ('1', 'true', 'yes', 'on'):
                scen['density_count_min_enabled'] = True
                min_attr = scen_el.get('density_count_min')
                if min_attr not in (None, ''):
                    scen['density_count_min'] = int(min_attr)
        except Exception:
            pass
        try:
            max_en_attr = str(scen_el.get('density_count_max_enabled') or '').strip().lower()
            if max_en_attr in ('1', 'true', 'yes', 'on'):
                scen['density_count_max_enabled'] = True
                max_attr = scen_el.get('density_count_max')
                if max_attr not in (None, ''):
                    scen['density_count_max'] = int(max_attr)
        except Exception:
            pass
        se = scen_el.find("ScenarioEditor")
        if se is None:
            continue
        scen.update(_parse_scenario_editor(se))
        scen = _canonicalize_specific_vulnerability_items(scen, strict=False)
        if isinstance(scen.get('plan_preview'), dict):
            scen['plan_preview'] = _canonicalize_plan_preview_vulnerability_names(
                scen.get('plan_preview'),
                scenario_payload=scen,
            )
        # If scenario-level density_count was absent but Node Information section provided one, keep existing.
        data["scenarios"].append(scen)
    return data


def _core_config_from_xml_path(
    xml_path: str | None,
    scenario_norm: str,
    *,
    include_password: bool = True,
) -> Dict[str, Any] | None:
    if not xml_path:
        return None
    try:
        xml_abs = os.path.abspath(xml_path)
    except Exception:
        return None
    if not os.path.exists(xml_abs):
        return None
    try:
        payload = _parse_scenarios_xml(xml_abs)
    except Exception:
        return None

    scenario_core: Dict[str, Any] | None = None
    scen_list = payload.get('scenarios') if isinstance(payload, dict) else None
    if isinstance(scen_list, list):
        for sc in scen_list:
            if not isinstance(sc, dict):
                continue
            nm = str(sc.get('name') or '').strip()
            if scenario_norm and _normalize_scenario_label(nm) != scenario_norm:
                continue
            hitl = sc.get('hitl') if isinstance(sc.get('hitl'), dict) else None
            if isinstance(hitl, dict) and isinstance(hitl.get('core'), dict):
                scenario_core = hitl.get('core')
            if scenario_norm:
                break
            if scenario_core:
                break

    global_core: Dict[str, Any] | None = None
    try:
        tree = ET.parse(xml_abs)
        root = tree.getroot()
        core_el = root.find('CoreConnection')
        if core_el is not None:
            global_core = _extract_optional_core_config(dict(core_el.attrib), include_password=include_password)
    except Exception:
        global_core = None

    if not scenario_core and not global_core:
        return None
    return _merge_core_configs(global_core, scenario_core, include_password=include_password)


def _flow_state_from_latest_xml(scenario_norm: str) -> dict[str, Any] | None:
    try:
        scen_norm = _normalize_scenario_label(scenario_norm)
        if not scen_norm:
            return None
        xml_path = _latest_xml_path_for_scenario(scen_norm)
        if not xml_path:
            return None
        parsed = _parse_scenarios_xml(xml_path)
        scen_list = parsed.get('scenarios') if isinstance(parsed, dict) else None
        if not isinstance(scen_list, list):
            return None
        for sc in scen_list:
            if not isinstance(sc, dict):
                continue
            nm = str(sc.get('name') or '').strip()
            if _normalize_scenario_label(nm) != scen_norm:
                continue
            fs = sc.get('flow_state')
            if not isinstance(fs, dict):
                return None
            normalized = _canonicalize_flow_state_paths(fs, xml_path=xml_path)
            normalized = _flow_state_scrub_disallowed_duplicates(normalized)
            return _refresh_loaded_flow_state_assignments(normalized, scenario_label=nm or scenario_norm)
        return None
    except Exception:
        return None


def _flow_state_from_xml_path(xml_path: str, scenario_label: str | None) -> dict[str, Any] | None:
    try:
        if not xml_path:
            return None
        xml_abs = _abs_path_or_original(xml_path)
        if not os.path.exists(xml_abs):
            return None
        parsed = _parse_scenarios_xml(xml_abs)
        scen_list = parsed.get('scenarios') if isinstance(parsed, dict) else None
        if not isinstance(scen_list, list):
            return None
        target_norm = _normalize_scenario_label(scenario_label or '') if scenario_label else ''
        if target_norm:
            for sc in scen_list:
                if not isinstance(sc, dict):
                    continue
                nm = str(sc.get('name') or '').strip()
                if _normalize_scenario_label(nm) != target_norm:
                    continue
                fs = sc.get('flow_state')
                if not isinstance(fs, dict):
                    return None
                normalized = _canonicalize_flow_state_paths(fs, xml_path=xml_abs)
                normalized = _flow_state_scrub_disallowed_duplicates(normalized)
                return _refresh_loaded_flow_state_assignments(normalized, scenario_label=nm or scenario_label)
            return None
        # No scenario specified: return the first flow_state found.
        for sc in scen_list:
            if not isinstance(sc, dict):
                continue
            fs = sc.get('flow_state')
            if isinstance(fs, dict):
                normalized = _canonicalize_flow_state_paths(fs, xml_path=xml_abs)
                normalized = _flow_state_scrub_disallowed_duplicates(normalized)
                nm = str(sc.get('name') or '').strip()
                return _refresh_loaded_flow_state_assignments(normalized, scenario_label=nm or scenario_label)
        return None
    except Exception:
        return None


def _latest_xml_path_for_scenario(scenario_norm: str) -> str | None:
    try:
        scen_norm = _normalize_scenario_label(scenario_norm)
        if not scen_norm:
            return None
        current_user = _current_user()
        scenario_names, scenario_paths, _scenario_url_hints = _scenario_catalog_for_user(None, user=current_user)
        path_candidates = None
        if scenario_names and isinstance(scenario_paths, dict):
            path_candidates = scenario_paths.get(scen_norm) or scenario_paths.get(_resolve_scenario_display(scen_norm, scenario_names, scen_norm)) or None
        filtered = None
        if isinstance(path_candidates, (list, tuple, set)):
            filtered = [p for p in path_candidates if not _is_autosave_xml_path(str(p or ''))]
        preferred = _select_single_scenario_path(filtered or path_candidates, scen_norm)
        # Only return a single-scenario XML. Avoid aggregate files.
        if preferred:
            return preferred

        # Run history fallback: some entries can have valid XML paths even when
        # scenario catalog metadata is stale or incomplete.
        try:
            history = _load_run_history()
            filtered_hist = _filter_history_by_scenario(history, scen_norm)
            filtered_hist.sort(key=lambda e: _parse_iso_ts(e.get('timestamp') if isinstance(e, dict) else None), reverse=True)
            for entry in filtered_hist:
                if not isinstance(entry, dict):
                    continue
                for key in ('single_scenario_xml_path', 'scenario_xml_path', 'preview_plan_path', 'xml_path'):
                    cand = _existing_xml_path_or_none(entry.get(key))
                    if not cand or _is_autosave_xml_path(cand):
                        continue
                    try:
                        scen_names = _scenario_names_from_xml(cand)
                    except Exception:
                        scen_names = []
                    # Do not accept candidates that do not encode scenario names
                    # (e.g., session XML); that can cause cross-scenario preview drift.
                    if not scen_names:
                        continue
                    if not any(_normalize_scenario_label(nm) == scen_norm for nm in scen_names):
                        continue
                    return cand
        except Exception:
            pass

        # Fallback: scan outputs/scenarios-* for per-scenario XML files and pick newest
        # match by scenario label + mtime. This covers cases where catalog/history mapping
        # is stale or missing for scenario-only API calls.
        try:
            out_dir = _outputs_dir()
            if not out_dir or not os.path.isdir(out_dir):
                return None
            best_path = None
            best_mtime = -1.0
            for dirname in os.listdir(out_dir):
                if not str(dirname).startswith('scenarios-'):
                    continue
                base = os.path.join(out_dir, dirname)
                if not os.path.isdir(base):
                    continue
                try:
                    names = os.listdir(base)
                except Exception:
                    continue
                for fn in names:
                    if not str(fn).lower().endswith('.xml'):
                        continue
                    cand = os.path.join(base, fn)
                    if _is_autosave_xml_path(cand):
                        continue
                    scen_names = _scenario_names_from_xml(cand)
                    matched = False
                    if isinstance(scen_names, list) and scen_names:
                        for nm in scen_names:
                            if _normalize_scenario_label(nm) == scen_norm:
                                matched = True
                                break
                    if not matched:
                        continue
                    try:
                        mtime = float(os.path.getmtime(cand))
                    except Exception:
                        mtime = 0.0
                    if mtime >= best_mtime:
                        best_mtime = mtime
                        best_path = cand
            return best_path
        except Exception:
            return None
    except Exception:
        return None


def _resolve_preexecute_xml_path(xml_path: Any, scenario_name: Any) -> str:
    """Prefer the latest saved scenario XML during preview/plan/execute flows."""
    try:
        scenario_norm = _normalize_scenario_label(scenario_name or '')
    except Exception:
        scenario_norm = str(scenario_name or '').strip().lower()
    if scenario_norm:
        try:
            latest_xml = _existing_xml_path_or_none(_latest_xml_path_for_scenario(scenario_norm) or '')
        except Exception:
            latest_xml = None
        if latest_xml:
            return latest_xml
    try:
        resolved = _abs_path_or_original(xml_path)
    except Exception:
        resolved = str(xml_path or '').strip()
    return str(resolved or '').strip()


def _is_autosave_xml_path(path_value: str) -> bool:
    try:
        if not path_value:
            return True
        norm = str(path_value).replace('\\', '/').lower()
        if '/outputs/autosave/' in norm or norm.endswith('/outputs/autosave'):
            return True
        base = os.path.basename(norm)
        return base.startswith('autosave-')
    except Exception:
        return True


def _xml_trace_snapshot(xml_path: str | None, scenario_label: str | None = None) -> dict[str, Any]:
    out: dict[str, Any] = {
        'xml_path': str(xml_path or ''),
        'exists': False,
        'mtime': 0.0,
        'size': 0,
        'sha12': '',
        'flow_chain_len': None,
        'flow_enabled': None,
        'flow_updated_at': None,
    }
    try:
        path = _abs_path_or_original(str(xml_path or '').strip())
    except Exception:
        path = ''
    if not path:
        return out
    out['xml_path'] = path
    try:
        if not os.path.exists(path):
            return out
        out['exists'] = True
        out['mtime'] = float(os.path.getmtime(path))
        out['size'] = int(os.path.getsize(path))
        h = hashlib.sha256()
        with open(path, 'rb') as fh:
            while True:
                chunk = fh.read(65536)
                if not chunk:
                    break
                h.update(chunk)
        out['sha12'] = h.hexdigest()[:12]
    except Exception:
        pass
    try:
        fs = _flow_state_from_xml_path(path, scenario_label)
        if isinstance(fs, dict):
            chain_ids = fs.get('chain_ids') if isinstance(fs.get('chain_ids'), list) else []
            out['flow_chain_len'] = len(chain_ids)
            if 'flow_enabled' in fs:
                out['flow_enabled'] = _coerce_bool(fs.get('flow_enabled'))
            out['flow_updated_at'] = fs.get('updated_at')
    except Exception:
        pass
    return out


try:
    from webapp.routes import scenario_latest as _scenario_latest_routes

    _scenario_latest_routes.register(
        app,
        normalize_scenario_label=lambda value: _normalize_scenario_label(value),
        latest_xml_path_for_scenario=lambda scenario_name: _latest_xml_path_for_scenario(scenario_name),
        abs_path_or_original=lambda value: _abs_path_or_original(value),
        parse_scenarios_xml=lambda path: _parse_scenarios_xml(path),
        merge_hitl_hints_into_scenario_state=lambda state, scenario_norm: _merge_hitl_hints_into_scenario_state(state, scenario_norm),
        logger=app.logger,
    )
except Exception:
    try:
        app.logger.exception('Failed to register scenario_latest routes.')
    except Exception:
        pass


def _update_flow_state_in_xml(xml_path: str, scenario_label: str | None, flow_state: dict[str, Any]) -> tuple[bool, str]:
    """Update (or create) FlagSequencing/FlowState within a scenarios XML file."""
    xml_path = _abs_path_or_original(xml_path)
    if not xml_path or not os.path.exists(xml_path):
        return False, 'xml_path not found'
    if not isinstance(flow_state, dict) or not flow_state:
        return False, 'flow_state empty'
    # Backfill inject_files from current generator catalogs before persisting.
    flow_state = _backfill_flow_state_inject_files_from_catalog(flow_state)
    flow_state = _canonicalize_flow_state_paths(flow_state, xml_path=xml_path)
    flow_state = _refresh_loaded_flow_state_assignments(flow_state, scenario_label=scenario_label) or flow_state
    if _flow_state_has_disallowed_duplicate_nodes(flow_state):
        return False, 'Flow chain reuses nodes while duplicates are disabled. Regenerate or explicitly enable duplicates.'
    try:
        tree = ET.parse(xml_path)
        root = tree.getroot()
    except Exception as e:
        return False, f'failed to parse xml: {e}'

    scenario_norm = _normalize_scenario_label(scenario_label or '')
    se_target = None

    try:
        if root.tag == 'ScenarioEditor':
            se_target = root
        elif root.tag == 'Scenario':
            se_target = root.find('ScenarioEditor')
            if se_target is None:
                se_target = ET.SubElement(root, 'ScenarioEditor')
        elif root.tag == 'Scenarios':
            for scen_el in root.findall('Scenario'):
                nm = str(scen_el.get('name') or '').strip()
                if scenario_norm and _normalize_scenario_label(nm) != scenario_norm:
                    continue
                se_target = scen_el.find('ScenarioEditor')
                if se_target is None:
                    se_target = ET.SubElement(scen_el, 'ScenarioEditor')
                if se_target is not None:
                    break
    except Exception:
        se_target = None

    if se_target is None:
        return False, 'ScenarioEditor not found'

    try:
        fs_el = se_target.find('FlagSequencing')
        if fs_el is None:
            fs_el = ET.SubElement(se_target, 'FlagSequencing')
        # Clear existing FlowState children.
        for child in list(fs_el):
            if child.tag == 'FlowState':
                fs_el.remove(child)
        st_el = ET.SubElement(fs_el, 'FlowState')
        st_el.text = json.dumps(flow_state, separators=(',', ':'), ensure_ascii=False)
        _write_xml_tree_atomic(tree, xml_path)
        return True, 'ok'
    except Exception as e:
        return False, f'failed to update xml: {e}'


def _write_xml_tree_atomic(tree: ET.ElementTree, xml_path: str) -> None:
    """Persist XML by writing a sibling temp file and replacing the target.

    This avoids opening the existing XML for in-place write, which can fail when
    the file itself is read-only or owned by another user even though the parent
    directory is writable. XML containing an SSH password is restricted to the
    owning user.
    """
    xml_path = _abs_path_or_original(xml_path)
    if not xml_path:
        raise ValueError('xml_path not found')
    target_dir = os.path.dirname(xml_path) or '.'
    original_mode: int | None = None
    try:
        original_mode = os.stat(xml_path).st_mode & 0o777
    except Exception:
        original_mode = None

    has_embedded_password = any(
        element.tag == 'CoreConnection'
        and bool(str(element.get('ssh_password') or '').strip())
        for element in tree.getroot().iter()
    )
    target_mode = 0o600 if has_embedded_password else original_mode

    tmp_fd, tmp_path = tempfile.mkstemp(prefix='.coretg-xml-', suffix='.tmp', dir=target_dir)
    os.close(tmp_fd)
    try:
        tree.write(tmp_path, encoding='utf-8', xml_declaration=True)
        if target_mode is not None:
            try:
                os.chmod(tmp_path, target_mode)
            except Exception:
                pass
        os.replace(tmp_path, xml_path)
    except Exception:
        try:
            if os.path.exists(tmp_path):
                os.remove(tmp_path)
        except Exception:
            pass
        raise


def _core_config_xml_attributes(core_cfg: Dict[str, Any]) -> Dict[str, str]:
    """Serialize the complete CORE connection into the authoritative XML."""
    public_cfg = (
        _extract_optional_core_config(core_cfg, include_password=True)
        or _normalize_core_config(core_cfg, include_password=True)
        or {}
    )
    attrs: Dict[str, str] = {}
    host = public_cfg.get('grpc_host') or public_cfg.get('host') or ''
    port = public_cfg.get('grpc_port') if public_cfg.get('grpc_port') not in (None, '') else public_cfg.get('port')
    attrs['host'] = str(host)
    attrs['port'] = str(port or '')
    attrs['ssh_enabled'] = 'true' if _coerce_bool(public_cfg.get('ssh_enabled')) else 'false'
    attrs['ssh_host'] = str(public_cfg.get('ssh_host') or host or '')
    attrs['ssh_port'] = str(public_cfg.get('ssh_port') or '')
    attrs['ssh_username'] = str(public_cfg.get('ssh_username') or '')
    if public_cfg.get('ssh_password') not in (None, ''):
        attrs['ssh_password'] = str(public_cfg.get('ssh_password') or '')

    skipped = {
        'host',
        'port',
        'grpc_host',
        'grpc_port',
        'ssh_enabled',
        'ssh_host',
        'ssh_port',
        'ssh_username',
        'ssh_password',
        'ssh',
    }
    for key, value in public_cfg.items():
        if key in skipped or value in (None, ''):
            continue
        if isinstance(value, bool):
            attrs[str(key)] = 'true' if value else 'false'
        elif isinstance(value, (dict, list, tuple)):
            attrs[str(key)] = json.dumps(value, separators=(',', ':'), sort_keys=True)
        else:
            attrs[str(key)] = str(value)
    return attrs


def _update_core_config_in_xml(
    xml_path: str,
    scenario_label: str | None,
    core_cfg: Dict[str, Any],
) -> tuple[bool, str]:
    """Make the selected CORE connection part of the authoritative scenario XML."""
    xml_path = _abs_path_or_original(xml_path)
    if not xml_path or not os.path.exists(xml_path):
        return False, 'xml_path not found'
    if not isinstance(core_cfg, dict) or not core_cfg:
        return False, 'core config empty'
    try:
        tree = ET.parse(xml_path)
        root = tree.getroot()
    except Exception as exc:
        return False, f'failed to parse xml: {exc}'

    attrs = _core_config_xml_attributes(core_cfg)
    scenario_norm = _normalize_scenario_label(scenario_label or '')
    scenario_el = None
    editor_el = None

    try:
        if root.tag == 'Scenarios':
            global_core = root.find('CoreConnection')
            if global_core is None:
                global_core = ET.Element('CoreConnection')
                root.insert(0, global_core)
            global_core.attrib.clear()
            global_core.attrib.update(attrs)

            for candidate in root.findall('Scenario'):
                name = str(candidate.get('name') or '').strip()
                if scenario_norm and _normalize_scenario_label(name) != scenario_norm:
                    continue
                scenario_el = candidate
                break
            if scenario_el is None and not scenario_norm:
                scenario_el = root.find('Scenario')
            if scenario_el is not None:
                editor_el = scenario_el.find('ScenarioEditor')
                if editor_el is None:
                    editor_el = ET.SubElement(scenario_el, 'ScenarioEditor')
        elif root.tag == 'Scenario':
            scenario_el = root
            editor_el = root.find('ScenarioEditor')
            if editor_el is None:
                editor_el = ET.SubElement(root, 'ScenarioEditor')
        elif root.tag == 'ScenarioEditor':
            editor_el = root
    except Exception as exc:
        return False, f'failed to locate scenario: {exc}'

    if editor_el is None:
        return False, 'ScenarioEditor not found'

    try:
        hitl_el = editor_el.find('HardwareInLoop')
        if hitl_el is None:
            hitl_el = ET.SubElement(editor_el, 'HardwareInLoop')
            hitl_el.set('enabled', 'false')
        scenario_core = hitl_el.find('CoreConnection')
        if scenario_core is None:
            scenario_core = ET.SubElement(hitl_el, 'CoreConnection')
        scenario_core.attrib.clear()
        scenario_core.attrib.update(attrs)
        _write_xml_tree_atomic(tree, xml_path)
        return True, 'ok'
    except Exception as exc:
        return False, f'failed to update core config in xml: {exc}'


def _read_flow_state_from_xml_path(xml_path: str, scenario_label: str | None) -> dict[str, Any] | None:
    """Best-effort read of FlowState from scenario XML.

    Keep this aligned with the canonical reader used elsewhere so execute-time XML
    refreshes preserve path canonicalization and backfilled inject metadata before
    remote upload.
    """
    return _flow_state_from_xml_path(xml_path, scenario_label)


def _canonicalize_payload_flow_from_xml(
    payload: dict[str, Any] | None,
    *,
    xml_path: str,
    scenario_label: str | None,
) -> tuple[dict[str, Any], dict[str, Any] | None]:
    """Force payload metadata.flow to mirror XML FlowState (single source of truth).

    Returns (metadata_dict, flow_state_dict_or_none).
    """
    meta: dict[str, Any] = {}
    if isinstance(payload, dict) and isinstance(payload.get('metadata'), dict):
        try:
            meta = dict(payload.get('metadata') or {})
        except Exception:
            meta = {}

    flow_state = _flow_state_from_xml_path(xml_path, scenario_label)
    if isinstance(flow_state, dict):
        try:
            meta['flow'] = dict(flow_state)
        except Exception:
            meta['flow'] = flow_state
    else:
        try:
            if 'flow' in meta:
                meta.pop('flow', None)
        except Exception:
            pass

    if isinstance(payload, dict):
        payload['metadata'] = meta
    return meta, (flow_state if isinstance(flow_state, dict) else None)


def _flow_payload_has_pivoting_plan(payload: Any) -> bool:
    if not isinstance(payload, dict):
        return False
    for source in _flow_pivot_context_sources(payload, payload.get('full_preview') if isinstance(payload.get('full_preview'), dict) else None):
        if not isinstance(source, dict):
            continue
        for key in ('pivoting', 'pivoting_plan'):
            candidate = source.get(key) if isinstance(source.get(key), dict) else None
            if isinstance(candidate, dict):
                if candidate.get('rules') or candidate.get('raw_items_serialized') or candidate.get('items_count'):
                    return True
        if source.get('rules') or source.get('raw_items_serialized') or source.get('items_count'):
            return True
        breakdowns = source.get('breakdowns') if isinstance(source.get('breakdowns'), dict) else None
        pivoting = breakdowns.get('pivoting') if isinstance(breakdowns, dict) and isinstance(breakdowns.get('pivoting'), dict) else None
        if isinstance(pivoting, dict) and (pivoting.get('rules') or pivoting.get('raw_items_serialized') or pivoting.get('items_count')):
            return True
    return False


def _flow_attach_pivoting_plan_from_xml(
    payload: dict[str, Any] | None,
    *,
    xml_path: str,
    scenario_label: str | None,
) -> bool:
    if not isinstance(payload, dict):
        return False
    if _flow_payload_has_pivoting_plan(payload):
        return False
    try:
        xml_abs = os.path.abspath(str(xml_path or '').strip())
    except Exception:
        xml_abs = ''
    if not xml_abs or not os.path.exists(xml_abs):
        return False
    try:
        from scenarioforge.planning.orchestrator import compute_full_plan
        seed = None
        try:
            full = payload.get('full_preview') if isinstance(payload.get('full_preview'), dict) else {}
            meta = payload.get('metadata') if isinstance(payload.get('metadata'), dict) else {}
            seed_raw = full.get('seed') if isinstance(full, dict) else None
            if seed_raw is None and isinstance(meta, dict):
                seed_raw = meta.get('seed')
            if seed_raw is not None:
                seed = int(seed_raw)
        except Exception:
            seed = None
        plan = compute_full_plan(xml_abs, scenario=scenario_label, seed=seed, include_breakdowns=True)
    except Exception:
        return False
    pivoting_plan = None
    try:
        if isinstance(plan.get('pivoting_plan'), dict):
            pivoting_plan = plan.get('pivoting_plan')
        if not isinstance(pivoting_plan, dict):
            breakdowns = plan.get('breakdowns') if isinstance(plan.get('breakdowns'), dict) else {}
            candidate = breakdowns.get('pivoting') if isinstance(breakdowns.get('pivoting'), dict) else None
            if isinstance(candidate, dict):
                pivoting_plan = candidate
    except Exception:
        pivoting_plan = None
    if not isinstance(pivoting_plan, dict):
        return False
    if not (pivoting_plan.get('rules') or pivoting_plan.get('raw_items_serialized') or pivoting_plan.get('items_count')):
        return False
    full_preview = payload.get('full_preview') if isinstance(payload.get('full_preview'), dict) else None
    if not isinstance(full_preview, dict):
        full_preview = {}
        payload['full_preview'] = full_preview
    full_preview['pivoting_plan'] = pivoting_plan
    try:
        meta = payload.get('metadata') if isinstance(payload.get('metadata'), dict) else {}
        meta = dict(meta or {})
        meta['pivoting_plan_attached_from_xml'] = True
        payload['metadata'] = meta
    except Exception:
        pass
    return True

    scenario_norm = _normalize_scenario_label(scenario_label or '')
    scen_el = None
    try:
        scenarios = root.findall('.//Scenario')
        if scenario_norm:
            for sc in scenarios:
                nm = str(sc.get('name') or '').strip()
                if _normalize_scenario_label(nm) == scenario_norm:
                    scen_el = sc
                    break
        if scen_el is None and scenarios:
            scen_el = scenarios[0]
    except Exception:
        scen_el = None

    if scen_el is None:
        return None
    try:
        flow_el = scen_el.find('.//FlagSequencing/FlowState')
        raw = (flow_el.text or '').strip() if flow_el is not None else ''
        if not raw:
            return None
        data = json.loads(raw)
        return data if isinstance(data, dict) else None
    except Exception:
        return None


def _clear_flow_state_in_xml(xml_path: str, scenario_label: str | None) -> tuple[bool, str]:
    """Remove FlagSequencing/FlowState from a scenarios XML file (best-effort)."""
    if not xml_path or not os.path.exists(xml_path):
        return False, 'xml_path not found'
    try:
        tree = ET.parse(xml_path)
        root = tree.getroot()
    except Exception as e:
        return False, f'failed to parse xml: {e}'

    scenario_norm = _normalize_scenario_label(scenario_label or '')
    se_target = None
    try:
        if root.tag == 'ScenarioEditor':
            se_target = root
        elif root.tag == 'Scenario':
            se_target = root.find('ScenarioEditor')
        elif root.tag == 'Scenarios':
            for scen_el in root.findall('Scenario'):
                nm = str(scen_el.get('name') or '').strip()
                if scenario_norm and _normalize_scenario_label(nm) != scenario_norm:
                    continue
                se_target = scen_el.find('ScenarioEditor')
                if se_target is not None:
                    break
    except Exception:
        se_target = None

    if se_target is None:
        return False, 'ScenarioEditor not found'

    try:
        fs_el = se_target.find('FlagSequencing')
        if fs_el is None:
            return True, 'ok'
        removed = False
        for child in list(fs_el):
            if child.tag == 'FlowState':
                fs_el.remove(child)
                removed = True
        if removed:
            _write_xml_tree_atomic(tree, xml_path)
        return True, 'ok'
    except Exception as e:
        return False, f'failed to update xml: {e}'


def _clear_plan_preview_flow_metadata_in_xml(xml_path: str, scenario_label: str | None) -> tuple[bool, str]:
    """Remove metadata.flow from ScenarioEditor/PlanPreview payload in XML."""
    xml_path = _abs_path_or_original(xml_path)
    if not xml_path or not os.path.exists(xml_path):
        return False, 'xml_path not found'
    payload = _load_plan_preview_from_xml(xml_path, scenario_label)
    if not isinstance(payload, dict):
        return True, 'ok'
    try:
        meta = payload.get('metadata') if isinstance(payload.get('metadata'), dict) else {}
        if isinstance(meta, dict) and ('flow' in meta):
            meta = dict(meta)
            meta.pop('flow', None)
            payload = dict(payload)
            payload['metadata'] = meta
            return _update_plan_preview_in_xml(xml_path, scenario_label, payload)
        return True, 'ok'
    except Exception as e:
        return False, f'failed to clear plan flow metadata: {e}'


def _update_plan_preview_in_xml(
    xml_path: str,
    scenario_label: str | None,
    plan_payload: dict[str, Any],
) -> tuple[bool, str]:
    """Update (or create) ScenarioEditor/PlanPreview within a scenarios XML file."""
    xml_path = _abs_path_or_original(xml_path)
    if not xml_path or not os.path.exists(xml_path):
        return False, 'xml_path not found'
    if not isinstance(plan_payload, dict) or not plan_payload:
        return False, 'plan payload empty'
    plan_payload = _canonicalize_plan_payload_paths(plan_payload, xml_path=xml_path)
    try:
        tree = ET.parse(xml_path)
        root = tree.getroot()
    except Exception as e:
        return False, f'failed to parse xml: {e}'

    scenario_norm = _normalize_scenario_label(scenario_label or '')
    se_target = None
    try:
        if root.tag == 'ScenarioEditor':
            se_target = root
        elif root.tag == 'Scenarios':
            for scen_el in root.findall('Scenario'):
                nm = str(scen_el.get('name') or '').strip()
                if scenario_norm and _normalize_scenario_label(nm) != scenario_norm:
                    continue
                se_target = scen_el.find('ScenarioEditor')
                if se_target is not None:
                    break
    except Exception:
        se_target = None

    if se_target is None:
        return False, 'ScenarioEditor not found'

    try:
        plan_el = se_target.find('PlanPreview')
        if plan_el is None:
            plan_el = ET.SubElement(se_target, 'PlanPreview')
        plan_el.text = json.dumps(plan_payload, separators=(',', ':'), ensure_ascii=False)
        _write_xml_tree_atomic(tree, xml_path)
        return True, 'ok'
    except Exception as e:
        return False, f'failed to update xml: {e}'


def _load_plan_preview_from_xml(xml_path: str, scenario_label: str | None) -> dict[str, Any] | None:
    """Load embedded PlanPreview JSON payload from a scenarios XML file."""
    xml_path = _abs_path_or_original(xml_path)
    if not xml_path or not os.path.exists(xml_path):
        return None
    try:
        tree = ET.parse(xml_path)
        root = tree.getroot()
    except Exception:
        return None

    scenario_norm = _normalize_scenario_label(scenario_label or '')
    se_target = None
    try:
        if root.tag == 'ScenarioEditor':
            se_target = root
        elif root.tag == 'Scenarios':
            for scen_el in root.findall('Scenario'):
                nm = str(scen_el.get('name') or '').strip()
                if scenario_norm and _normalize_scenario_label(nm) != scenario_norm:
                    continue
                se_target = scen_el.find('ScenarioEditor')
                if se_target is not None:
                    break
    except Exception:
        se_target = None

    if se_target is None:
        return None
    try:
        plan_el = se_target.find('PlanPreview')
        raw = (plan_el.text or '').strip() if plan_el is not None else ''
        if not raw:
            return None
        payload = json.loads(raw)
        if isinstance(payload, dict):
            payload = _canonicalize_plan_payload_paths(payload, xml_path=xml_path)
            try:
                parsed = _parse_scenarios_xml(xml_path)
                scenarios = parsed.get('scenarios') if isinstance(parsed, dict) else None
                selected = None
                if isinstance(scenarios, list):
                    target_norm = _normalize_scenario_label(scenario_label or '') if scenario_label else ''
                    for scenario_payload in scenarios:
                        if not isinstance(scenario_payload, dict):
                            continue
                        if target_norm:
                            name = str(scenario_payload.get('name') or '').strip()
                            if _normalize_scenario_label(name) != target_norm:
                                continue
                        selected = scenario_payload
                        break
                if isinstance(selected, dict):
                    payload = _canonicalize_plan_preview_vulnerability_names(payload, scenario_payload=selected)
            except Exception:
                pass
            return payload
        return None
    except Exception:
        return None


def _load_preview_payload_from_path(path: str, scenario_label: str | None = None) -> dict[str, Any] | None:
    """Load a preview payload from embedded XML PlanPreview only.

    Recompute is handled by explicit routes/actions (Generate and Preview page load).
    """

    try:
        ap = _existing_xml_path_or_none(path)
        if not ap:
            return None
        payload = _load_plan_preview_payload_from_path(ap, scenario_label)
        preview_source = 'embedded'

        if not isinstance(payload, dict):
            return None
        try:
            meta = payload.get('metadata') if isinstance(payload.get('metadata'), dict) else {}
            if not isinstance(meta, dict):
                meta = {}
            meta['preview_source'] = preview_source
            payload['metadata'] = meta
            xml_hint = _abs_path_or_original(meta.get('xml_path') or '')
            if not xml_hint:
                xml_hint = ap
            return _canonicalize_plan_payload_paths(payload, xml_path=xml_hint or None)
        except Exception:
            return payload
    except Exception:
        return None
    return None


def _parse_scenario_editor(se):
    scen = {"base": {"filepath": ""}, "sections": {}, "notes": ""}
    # If parent <Scenario> carries scenario-level density_count attribute, capture it.
    try:
        parent = se.getparent()  # lxml style (if ever switched) - fallback below
    except Exception:
        parent = None
    # ElementTree doesn't support getparent; instead inspect tail by traversing immediate children of root in caller.
    # Simplest: look for density_count on any ancestor via attrib access on 'se' .attrib is only local, so rely on caller to have set scen_el attrib earlier.
    # We can recover by walking up using a cheap hack: se._parent if present (cpython impl detail) else ignore.
    try:
        scen_el = getattr(se, 'attrib', None)
    except Exception:
        scen_el = None
    # Instead of fragile parent access, during parsing of root we can read attribute directly from the sibling Scenario element (handled in outer loop); emulate by checking se.get('density_count') first.
    # For backward compatibility, allow density_count on Scenario or Node Information section.
    # We'll set scen['density_count'] here only if Scenario element attribute is available; Node Information section handled later.
    # Outer loop already hands us 'se'; its parent was processed to create scen dict. We'll modify outer function to inject attribute before calling this if needed.
    # Simpler: just check if 'density_count' exists on any ancestor by scanning se.iterfind('..') unsupported; fallback: pass.
    pass
    base = se.find("BaseScenario")
    if base is not None:
        scen["base"]["filepath"] = base.get("filepath", "")
    hitl_el = se.find("HardwareInLoop")
    hitl_info: Dict[str, Any] = {"enabled": False, "interfaces": [], "core": None, "proxmox": None}
    if hitl_el is not None:
        enabled_raw = (hitl_el.get("enabled") or "").strip().lower()
        hitl_info["enabled"] = enabled_raw in ("1", "true", "yes", "on")
        bridge_validated_raw = (hitl_el.get("bridge_validated") or "").strip().lower()
        if bridge_validated_raw in ("1", "true", "yes", "on"):
            hitl_info["bridge_validated"] = True
        bridge_validated_at_raw = (hitl_el.get("bridge_validated_at") or "").strip()
        if bridge_validated_at_raw:
            hitl_info["bridge_validated_at"] = bridge_validated_at_raw
        participant_attr = (
            hitl_el.get('participant_proxmox_url')
            or hitl_el.get('participant_url')
            or hitl_el.get('participant')
        )
        if participant_attr not in (None, ''):
            participant_clean = str(participant_attr).strip()
            if participant_clean:
                hitl_info['participant_proxmox_url'] = participant_clean
        interfaces: List[Dict[str, Any]] = []
        for iface_el in hitl_el.findall("Interface"):
            name = (iface_el.get("name") or "").strip()
            if not name:
                continue
            entry: Dict[str, Any] = {"name": name}
            alias = (iface_el.get("alias") or iface_el.get("display") or iface_el.get("description") or "").strip()
            if alias:
                entry["alias"] = alias
            mac_attr = iface_el.get("mac")
            if mac_attr:
                entry["mac"] = mac_attr
            core_bridge_attr = (iface_el.get("core_bridge") or "").strip()
            if core_bridge_attr:
                entry["core_bridge"] = core_bridge_attr
            attachment_attr = iface_el.get("attachment") or iface_el.get("attach")
            entry["attachment"] = _normalize_hitl_attachment(attachment_attr)
            ipv4_attr = iface_el.get("ipv4") or iface_el.get("ipv4_addresses")
            if ipv4_attr:
                entry["ipv4"] = [p.strip() for p in ipv4_attr.split(',') if p.strip()]
            ipv6_attr = iface_el.get("ipv6") or iface_el.get("ipv6_addresses")
            if ipv6_attr:
                entry["ipv6"] = [p.strip() for p in ipv6_attr.split(',') if p.strip()]

            prox_target = {
                "node": (iface_el.get("pve_node") or "").strip(),
                "vmid": (iface_el.get("pve_vmid") or "").strip(),
                "interface_id": (iface_el.get("pve_interface_id") or "").strip(),
                "macaddr": (iface_el.get("pve_macaddr") or "").strip(),
                "bridge": (iface_el.get("pve_bridge") or "").strip(),
                "model": (iface_el.get("pve_model") or "").strip(),
                "vm_name": (iface_el.get("pve_vm_name") or "").strip(),
                "label": (iface_el.get("pve_label") or "").strip(),
            }
            if any(v for v in prox_target.values()):
                entry["proxmox_target"] = prox_target

            external_vm = {
                "vm_key": (iface_el.get("ext_vm_key") or "").strip(),
                "vm_node": (iface_el.get("ext_vm_node") or "").strip(),
                "vm_name": (iface_el.get("ext_vm_name") or "").strip(),
                "vmid": (iface_el.get("ext_vmid") or "").strip(),
                "status": (iface_el.get("ext_status") or "").strip(),
                "interface_id": (iface_el.get("ext_interface_id") or "").strip(),
                "interface_bridge": (iface_el.get("ext_interface_bridge") or "").strip(),
                "interface_mac": (iface_el.get("ext_interface_mac") or "").strip(),
                "interface_model": (iface_el.get("ext_interface_model") or "").strip(),
            }
            if any(v for v in external_vm.values()):
                entry["external_vm"] = external_vm
            interfaces.append(entry)
        hitl_info["interfaces"] = interfaces
        core_el = hitl_el.find("CoreConnection")
        if core_el is not None:
            core_cfg = _extract_optional_core_config(dict(core_el.attrib), include_password=True)
            if core_cfg:
                if "validated" in core_cfg:
                    core_cfg["validated"] = _coerce_bool(core_cfg.get("validated"))
                if isinstance(core_cfg.get("core_secret_id"), str):
                    core_cfg["core_secret_id"] = core_cfg["core_secret_id"].strip() or None
                hitl_info["core"] = core_cfg
        prox_el = hitl_el.find("ProxmoxConnection")
        if prox_el is not None:
            prox_cfg: Dict[str, Any] = {}
            for key in ("url", "port", "verify_ssl", "secret_id", "validated", "last_validated_at", "stored_at", "username", "remember_credentials", "last_message"):
                if key in prox_el.attrib:
                    prox_cfg[key] = prox_el.get(key)
            if isinstance(prox_cfg.get("secret_id"), str):
                prox_cfg["secret_id"] = prox_cfg["secret_id"].strip() or None
            if isinstance(prox_cfg.get("username"), str):
                prox_cfg["username"] = prox_cfg["username"].strip() or None
            if isinstance(prox_cfg.get("port"), str):
                try:
                    prox_cfg["port"] = int(str(prox_cfg["port"]).strip())
                except Exception:
                    pass
            if "verify_ssl" in prox_cfg:
                v = str(prox_cfg.get("verify_ssl") or "").strip().lower()
                prox_cfg["verify_ssl"] = v in ("1", "true", "yes", "on")
            if "validated" in prox_cfg:
                v = str(prox_cfg.get("validated") or "").strip().lower()
                prox_cfg["validated"] = v in ("1", "true", "yes", "on")
            if "remember_credentials" in prox_cfg:
                v = str(prox_cfg.get("remember_credentials") or "").strip().lower()
                prox_cfg["remember_credentials"] = v in ("1", "true", "yes", "on")
            if prox_cfg:
                hitl_info["proxmox"] = prox_cfg
    scen["hitl"] = hitl_info

    # AI Generator state for provider config + draft prompt/generation metadata.
    try:
        ai_el = se.find("AIGenerator")
        if ai_el is not None and ai_el.text:
            raw_ai = ai_el.text
            try:
                parsed_ai = json.loads(raw_ai)
                sanitized_ai = _sanitize_ai_generator_state(parsed_ai)
                if isinstance(sanitized_ai, dict):
                    scen["ai_generator"] = sanitized_ai
            except Exception:
                scen["ai_generator"] = {"raw": str(raw_ai)}
    except Exception:
        pass

    # Flag Sequencing flow state (resolved values, chain selections).
    try:
        fs_el = se.find("FlagSequencing")
        if fs_el is not None:
            flow_el = fs_el.find("FlowState")
            raw = None
            if flow_el is not None and flow_el.text:
                raw = flow_el.text
            elif fs_el.text:
                raw = fs_el.text
            if raw:
                try:
                    scen["flow_state"] = json.loads(raw)
                except Exception:
                    scen["flow_state"] = {"raw": str(raw)}
    except Exception:
        pass
    # Plan preview payload (full preview + plan/breakdowns metadata) for UI round-trip.
    try:
        plan_el = se.find("PlanPreview")
        if plan_el is not None and plan_el.text:
            raw_plan = plan_el.text
            try:
                scen["plan_preview"] = json.loads(raw_plan)
            except Exception:
                scen["plan_preview"] = {"raw": str(raw_plan)}
    except Exception:
        pass
    # Sections
    for sec in se.findall("section"):
        name = sec.get("name", "")
        if not name:
            continue
        entry = {"density": None, "total_nodes": None, "items": []}
        try:
            min_en_attr = str(sec.get('node_count_min_enabled') or '').strip().lower()
            if min_en_attr in ('1', 'true', 'yes', 'on'):
                entry['node_count_min_enabled'] = True
                min_attr = sec.get('node_count_min')
                if min_attr not in (None, ''):
                    entry['node_count_min'] = int(min_attr)
        except Exception:
            pass
        try:
            max_en_attr = str(sec.get('node_count_max_enabled') or '').strip().lower()
            if max_en_attr in ('1', 'true', 'yes', 'on'):
                entry['node_count_max_enabled'] = True
                max_attr = sec.get('node_count_max')
                if max_attr not in (None, ''):
                    entry['node_count_max'] = int(max_attr)
        except Exception:
            pass
        if name == "Node Information":
            tn = sec.get("total_nodes")
            if tn is not None:
                try:
                    entry["total_nodes"] = int(tn)
                except Exception:
                    entry["total_nodes"] = 1
        else:
            dens = sec.get("density")
            entry["density"] = float(dens) if dens is not None else 0.5
        if name == "Vulnerabilities":
            entry["flag_type"] = (sec.get("flag_type") or "text").strip() or "text"
        for item in sec.findall("item"):
            d = {
                "selected": item.get("selected", "Random"),
                "factor": float(item.get("factor", "1.0")),
            }
            if name == "Routing":
                em = item.get('r2r_mode')
                if em is not None:
                    # Store under new key r2r_mode; keep legacy key for UI components still referencing it
                    d['r2r_mode'] = em
                ev = item.get('r2r_edges') or item.get('edges')
                if ev is not None and ev.strip() != '':
                    try:
                        d['r2r_edges'] = int(ev)
                    except Exception:
                        pass
                r2s_m = item.get('r2s_mode')
                if r2s_m is not None:
                    d['r2s_mode'] = r2s_m
                r2s_ev = item.get('r2s_edges')
                if r2s_ev is not None and r2s_ev.strip() != '':
                    try:
                        d['r2s_edges'] = int(r2s_ev)
                    except Exception:
                        pass
                # New per-item hosts-per-switch bounds
                hmin_attr = item.get('r2s_hosts_min')
                hmax_attr = item.get('r2s_hosts_max')
                try:
                    if hmin_attr is not None and hmin_attr.strip() != '':
                        d['r2s_hosts_min'] = int(hmin_attr)
                except Exception:
                    pass
                try:
                    if hmax_attr is not None and hmax_attr.strip() != '':
                        d['r2s_hosts_max'] = int(hmax_attr)
                except Exception:
                    pass
            if name == "Traffic":
                d.update({
                    "pattern": item.get("pattern", "continuous"),
                    "rate_kbps": float(item.get("rate_kbps", "64.0")),
                    "period_s": float(item.get("period_s", "1.0")),
                    "jitter_pct": float(item.get("jitter_pct", "10.0")),
                    "content_type": (item.get("content_type") or "Random"),
                })
            if name == "Vulnerabilities":
                # Extra attributes for Vulnerabilities section
                sel = (d.get("selected") or "").strip()
                if sel == "Specific":
                    d["v_name"] = item.get("v_name", "")
                    d["v_path"] = item.get("v_path", "")
                    # Default count to 1 if missing/invalid
                    try:
                        d["v_count"] = int(item.get("v_count", "1"))
                    except Exception:
                        d["v_count"] = 1
                # Persist metric choice if present (Weight or Count)
                vm = item.get("v_metric")
                if vm:
                    d["v_metric"] = vm
            # Generic metric/count for all sections (including Vulnerabilities)
            try:
                vm_generic = item.get("v_metric")
                if vm_generic and vm_generic in ("Weight", "Count"):
                    d["v_metric"] = vm_generic
                vc_generic = item.get("v_count")
                if vc_generic is not None:
                    try:
                        d["v_count"] = int(vc_generic)
                    except Exception:
                        d["v_count"] = 1
            except Exception:
                pass
            if name == "Segmentation":
                pivot_enabled_raw = (item.get("pivot_enabled") or item.get("pivot_required") or item.get("pivot") or "").strip().lower()
                if pivot_enabled_raw in ("1", "true", "yes", "on", "pivot", "pivot-only", "required"):
                    d["pivot_enabled"] = True
                for xml_attr, state_key in (
                    ("pivot_provider", "pivot_provider"),
                    ("access_provider", "pivot_provider"),
                    ("provider", "pivot_provider"),
                    ("pivot_node", "pivot_node"),
                    ("pivot_role", "pivot_role"),
                    ("target_node", "target_node"),
                    ("target_role", "target_role"),
                    ("target_ports", "target_ports"),
                    ("target_protocols", "target_protocols"),
                    ("target_exposure", "target_exposure"),
                    ("exposure", "target_exposure"),
                    ("source_scope", "source_scope"),
                    ("requires", "requires"),
                    ("produces", "produces"),
                ):
                    val = item.get(xml_attr)
                    if val is not None and str(val).strip() != "" and state_key not in d:
                        parsed_val = str(val).strip()
                        if state_key == "pivot_provider" and parsed_val.lower().replace("_", "-") in {"auto", "none", "manual"}:
                            parsed_val = "random"
                        d[state_key] = parsed_val
            entry["items"].append(d)
        scen["sections"][name] = entry
        # Capture scenario-level density_count if present on Scenario element once
        if 'density_count' not in scen and se is not None:
            # Attempt to access parent <Scenario> by scanning for attribute on sec's ancestors is not directly supported.
            # Instead, rely on convention: during writing we place density_count on <Scenario>. So parse root manually here.
            try:
                # Walk up by brute force: find the nearest ancestor named 'Scenario'
                # We don't have parent links; reconstruct by searching from current element root.
                root = sec
                while getattr(root, 'tag', None) and root.tag != 'Scenario':
                    # ElementTree lacks parent pointer; break to avoid infinite loop
                    break
            except Exception:
                root = None
        # Fallback: if Node Information section carries density_count/base_nodes and scenario-level missing, propagate to scen.
        if name == 'Node Information' and 'density_count' not in scen:
            dc_attr = sec.get('density_count') or sec.get('base_nodes') or sec.get('total_nodes')
            if dc_attr:
                try:
                    scen['density_count'] = int(dc_attr)
                except Exception:
                    pass
    # Notes
    notes_sec = None
    for sec in se.findall("section"):
        if sec.get("name") == "Notes":
            notes_sec = sec; break
    if notes_sec is not None:
        notes_el = notes_sec.find("notes")
        if notes_el is not None and notes_el.text:
            scen["notes"] = notes_el.text
    return scen


def _build_scenarios_xml(data_dict: dict) -> ET.ElementTree:
    root = ET.Element("Scenarios")
    core_cfg = _extract_optional_core_config(data_dict.get('core'), include_password=True) or _normalize_core_config(data_dict.get('core'), include_password=True)
    core_el = ET.SubElement(root, 'CoreConnection')
    core_host = core_cfg.get('grpc_host') or core_cfg.get('host') or ''
    core_port = core_cfg.get('grpc_port') if core_cfg.get('grpc_port') not in (None, '') else core_cfg.get('port')
    core_el.set('host', str(core_host))
    core_el.set('port', str(core_port or ''))
    core_el.set('ssh_enabled', 'true' if core_cfg.get('ssh_enabled') else 'false')
    core_el.set('ssh_host', str(core_cfg.get('ssh_host') or core_host or ''))
    core_el.set('ssh_port', str(core_cfg.get('ssh_port') or ''))
    core_el.set('ssh_username', str(core_cfg.get('ssh_username') or ''))
    if core_cfg.get('ssh_password') not in (None, ''):
        core_el.set('ssh_password', str(core_cfg.get('ssh_password') or ''))
    for extra_key, extra_val in core_cfg.items():
        if extra_key in {'host', 'port', 'grpc_host', 'grpc_port', 'ssh_enabled', 'ssh_host', 'ssh_port', 'ssh_username', 'ssh_password', 'ssh'}:
            continue
        try:
            if extra_val not in (None, ''):
                core_el.set(str(extra_key), str(extra_val))
        except Exception:
            continue
    for idx, scen in enumerate(data_dict.get("scenarios", [])):
        scen = _normalize_scenario_section_semantics(scen)
        scen_el = ET.SubElement(root, "Scenario")
        scen_name = _sanitize_scenario_name_strict((scen or {}).get("name"), f"NewScenario{idx + 1}")
        scen_el.set("name", scen_name)
        # Persist scenario-level density_count (Count for Density) so parser priority can pick it up on reload.
        try:
            if 'density_count' in scen and scen.get('density_count') is not None:
                scen_el.set('density_count', str(int(scen.get('density_count'))))
        except Exception:
            pass
        try:
            if bool(scen.get('density_count_min_enabled')):
                scen_el.set('density_count_min_enabled', 'true')
                v = scen.get('density_count_min')
                if v is not None and str(v).strip() != '':
                    scen_el.set('density_count_min', str(int(v)))
        except Exception:
            pass
        try:
            if bool(scen.get('density_count_max_enabled')):
                scen_el.set('density_count_max_enabled', 'true')
                v = scen.get('density_count_max')
                if v is not None and str(v).strip() != '':
                    scen_el.set('density_count_max', str(int(v)))
        except Exception:
            pass
        se = ET.SubElement(scen_el, "ScenarioEditor")
        base = ET.SubElement(se, "BaseScenario")
        base.set("filepath", scen.get("base", {}).get("filepath", ""))

        hitl = scen.get("hitl") or {}
        raw_ifaces = hitl.get("interfaces") if isinstance(hitl, dict) else None
        normalized_ifaces: List[Dict[str, Any]] = []
        if isinstance(raw_ifaces, list):
            for entry in raw_ifaces:
                if not entry:
                    continue
                if isinstance(entry, str):
                    normalized_ifaces.append({"name": entry})
                    continue
                if not isinstance(entry, dict):
                    continue
                name = entry.get("name") or entry.get("interface") or entry.get("iface")
                if not name:
                    continue
                clean: Dict[str, Any] = {"name": str(name)}
                for key in ("alias", "display", "description"):
                    val = entry.get(key)
                    if isinstance(val, str) and val.strip():
                        clean["alias"] = val.strip()
                        break
                mac_val = entry.get("mac")
                if isinstance(mac_val, str) and mac_val.strip():
                    clean["mac"] = mac_val.strip()
                core_bridge_val = entry.get("core_bridge")
                if isinstance(core_bridge_val, str) and core_bridge_val.strip():
                    clean["core_bridge"] = core_bridge_val.strip()
                clean["attachment"] = _normalize_hitl_attachment(entry.get("attachment"))
                for attr_key in ("ipv4", "ipv6"):
                    val = entry.get(attr_key)
                    if isinstance(val, str):
                        items = [p.strip() for p in val.split(',') if p.strip()]
                        if items:
                            clean[attr_key] = items
                    elif isinstance(val, (list, tuple, set)):
                        items = [str(p).strip() for p in val if str(p).strip()]
                        if items:
                            clean[attr_key] = items

                prox_target_raw = entry.get("proxmox_target") if isinstance(entry.get("proxmox_target"), dict) else None
                if isinstance(prox_target_raw, dict):
                    prox_target_clean: Dict[str, Any] = {}
                    for src, dst in (
                        ("node", "node"),
                        ("vmid", "vmid"),
                        ("interface_id", "interface_id"),
                        ("macaddr", "macaddr"),
                        ("bridge", "bridge"),
                        ("model", "model"),
                        ("vm_name", "vm_name"),
                        ("label", "label"),
                    ):
                        val = prox_target_raw.get(src)
                        if val in (None, ""):
                            continue
                        sval = str(val).strip()
                        if sval:
                            prox_target_clean[dst] = sval
                    if prox_target_clean:
                        clean["proxmox_target"] = prox_target_clean

                external_vm_raw = entry.get("external_vm") if isinstance(entry.get("external_vm"), dict) else None
                if isinstance(external_vm_raw, dict):
                    external_vm_clean: Dict[str, Any] = {}
                    for src, dst in (
                        ("vm_key", "vm_key"),
                        ("vm_node", "vm_node"),
                        ("vm_name", "vm_name"),
                        ("vmid", "vmid"),
                        ("status", "status"),
                        ("interface_id", "interface_id"),
                        ("interface_bridge", "interface_bridge"),
                        ("interface_mac", "interface_mac"),
                        ("interface_model", "interface_model"),
                    ):
                        val = external_vm_raw.get(src)
                        if val in (None, ""):
                            continue
                        sval = str(val).strip()
                        if sval:
                            external_vm_clean[dst] = sval
                    if external_vm_clean:
                        clean["external_vm"] = external_vm_clean
                normalized_ifaces.append(clean)
        for iface in normalized_ifaces:
            if "attachment" not in iface:
                iface["attachment"] = _DEFAULT_HITL_ATTACHMENT

        participant_url_raw = hitl.get("participant_proxmox_url") if isinstance(hitl, dict) else None
        if participant_url_raw not in (None, ''):
            try:
                participant_url = str(participant_url_raw).strip()
            except Exception:
                participant_url = ''
        else:
            participant_url = ''

        if hitl and (_coerce_bool(hitl.get("enabled")) or normalized_ifaces or hitl.get("core") or hitl.get("proxmox") or participant_url):
            hitl_el = ET.SubElement(se, "HardwareInLoop")
            hitl_el.set("enabled", "true" if _coerce_bool(hitl.get("enabled")) else "false")
            if _coerce_bool(hitl.get("bridge_validated")):
                hitl_el.set("bridge_validated", "true")
                bridge_validated_at = str(hitl.get("bridge_validated_at") or "").strip()
                if bridge_validated_at:
                    hitl_el.set("bridge_validated_at", bridge_validated_at)
            if participant_url:
                hitl_el.set('participant_proxmox_url', participant_url)
            hitl_core_cfg = _extract_optional_core_config(hitl.get("core"), include_password=True)
            if hitl_core_cfg:
                hitl_core_el = ET.SubElement(hitl_el, "CoreConnection")
                hitl_core_host = hitl_core_cfg.get("grpc_host") or hitl_core_cfg.get("host") or ""
                hitl_core_port = hitl_core_cfg.get("grpc_port") if hitl_core_cfg.get("grpc_port") not in (None, "") else hitl_core_cfg.get("port")
                hitl_core_el.set("host", str(hitl_core_host))
                hitl_core_el.set("port", str(hitl_core_port or ""))
                hitl_core_el.set("ssh_enabled", "true" if hitl_core_cfg.get("ssh_enabled") else "false")
                hitl_core_el.set("ssh_host", str(hitl_core_cfg.get("ssh_host") or hitl_core_host or ""))
                hitl_core_el.set("ssh_port", str(hitl_core_cfg.get("ssh_port") or ""))
                hitl_core_el.set("ssh_username", str(hitl_core_cfg.get("ssh_username") or ""))
                if hitl_core_cfg.get('ssh_password') not in (None, ''):
                    hitl_core_el.set('ssh_password', str(hitl_core_cfg.get('ssh_password') or ''))
                for extra_key, extra_val in hitl_core_cfg.items():
                    if extra_key in {"host", "port", "grpc_host", "grpc_port", "ssh_enabled", "ssh_host", "ssh_port", "ssh_username", "ssh_password", "ssh"}:
                        continue
                    try:
                        hitl_core_el.set(str(extra_key), str(extra_val))
                    except Exception:
                        continue
            prox_raw = hitl.get("proxmox") if isinstance(hitl, dict) else None
            if isinstance(prox_raw, dict):
                prox_clean: Dict[str, Any] = {}
                for key in ("url", "port", "verify_ssl", "secret_id", "validated", "last_validated_at", "stored_at", "username", "remember_credentials", "last_message"):
                    if key in prox_raw:
                        prox_clean[key] = prox_raw.get(key)
                if isinstance(prox_clean.get("secret_id"), str):
                    prox_clean["secret_id"] = prox_clean["secret_id"].strip() or None
                if isinstance(prox_clean.get("username"), str):
                    prox_clean["username"] = prox_clean["username"].strip() or None
                if prox_clean:
                    prox_el = ET.SubElement(hitl_el, "ProxmoxConnection")
                    for key, value in prox_clean.items():
                        if value in (None, ""):
                            continue
                        if isinstance(value, bool):
                            prox_el.set(str(key), "true" if value else "false")
                        else:
                            prox_el.set(str(key), str(value))
            for iface in normalized_ifaces:
                name = iface.get("name")
                if not name:
                    continue
                iface_el = ET.SubElement(hitl_el, "Interface")
                iface_el.set("name", str(name))
                alias = iface.get("alias")
                if alias:
                    iface_el.set("alias", str(alias))
                if iface.get("mac"):
                    iface_el.set("mac", str(iface["mac"]))
                if iface.get("core_bridge"):
                    iface_el.set("core_bridge", str(iface["core_bridge"]))
                attachment = _normalize_hitl_attachment(iface.get("attachment"))
                if attachment:
                    iface_el.set("attachment", attachment)
                ipv4_vals = iface.get("ipv4")
                if isinstance(ipv4_vals, (list, tuple, set)):
                    joined = ",".join(str(p) for p in ipv4_vals if p)
                    if joined:
                        iface_el.set("ipv4", joined)
                ipv6_vals = iface.get("ipv6")
                if isinstance(ipv6_vals, (list, tuple, set)):
                    joined6 = ",".join(str(p) for p in ipv6_vals if p)
                    if joined6:
                        iface_el.set("ipv6", joined6)

                prox_target = iface.get("proxmox_target") if isinstance(iface.get("proxmox_target"), dict) else None
                if isinstance(prox_target, dict):
                    attr_map = {
                        "node": "pve_node",
                        "vmid": "pve_vmid",
                        "interface_id": "pve_interface_id",
                        "macaddr": "pve_macaddr",
                        "bridge": "pve_bridge",
                        "model": "pve_model",
                        "vm_name": "pve_vm_name",
                        "label": "pve_label",
                    }
                    for src_key, xml_attr in attr_map.items():
                        val = prox_target.get(src_key)
                        if val in (None, ""):
                            continue
                        iface_el.set(xml_attr, str(val))

                external_vm = iface.get("external_vm") if isinstance(iface.get("external_vm"), dict) else None
                if isinstance(external_vm, dict):
                    attr_map = {
                        "vm_key": "ext_vm_key",
                        "vm_node": "ext_vm_node",
                        "vm_name": "ext_vm_name",
                        "vmid": "ext_vmid",
                        "status": "ext_status",
                        "interface_id": "ext_interface_id",
                        "interface_bridge": "ext_interface_bridge",
                        "interface_mac": "ext_interface_mac",
                        "interface_model": "ext_interface_model",
                    }
                    for src_key, xml_attr in attr_map.items():
                        val = external_vm.get(src_key)
                        if val in (None, ""):
                            continue
                        iface_el.set(xml_attr, str(val))

        try:
            ai_generator = _sanitize_ai_generator_state(scen.get('ai_generator'))
            if isinstance(ai_generator, dict) and ai_generator:
                ai_el = ET.SubElement(se, "AIGenerator")
                ai_el.text = json.dumps(ai_generator, separators=(',', ':'), ensure_ascii=False)
        except Exception:
            pass

        # Flag Sequencing flow state (resolved values, chain selections).
        try:
            flow_state = scen.get('flow_state')
            if isinstance(flow_state, dict) and flow_state:
                fs_el = ET.SubElement(se, "FlagSequencing")
                st_el = ET.SubElement(fs_el, "FlowState")
                st_el.text = json.dumps(flow_state, separators=(',', ':'), ensure_ascii=False)
        except Exception:
            pass

        # Plan preview payload (full preview + plan/breakdowns metadata) for UI round-trip.
        try:
            plan_preview = scen.get('plan_preview') or scen.get('planPreview')
            if isinstance(plan_preview, dict) and plan_preview:
                pp_el = ET.SubElement(se, "PlanPreview")
                pp_el.text = json.dumps(plan_preview, separators=(',', ':'), ensure_ascii=False)
        except Exception:
            pass

        order = [
            "Node Information", "Routing", "Services", "Traffic",
            "Vulnerabilities", "Segmentation", "Notes"
        ]
        combined_host_pool: int | None = None
        scenario_host_additive = 0
        scenario_routing_total = 0
        scenario_vuln_total = 0

        for name in order:
            if name == "Notes":
                sec_el = ET.SubElement(se, "section", name="Notes")
                ne = ET.SubElement(sec_el, "notes")
                ne.text = scen.get("notes", "") or ""
                continue
            sec = scen.get("sections", {}).get(name)
            if not sec:
                continue
            sec_el = ET.SubElement(se, "section", name=name)
            items_list = sec.get("items", []) or []
            if name == "Vulnerabilities":
                sec_el.set("flag_type", str(sec.get("flag_type") or "text"))
            weight_rows = [it for it in items_list if (it.get('v_metric') or (it.get('selected')=='Specific' and name=='Vulnerabilities') or 'Weight') == 'Weight']
            count_rows = [it for it in items_list if (it.get('v_metric') == 'Count') or (name == 'Vulnerabilities' and it.get('selected') == 'Specific')]
            weight_sum = sum(float(it.get('factor', 0) or 0) for it in weight_rows) if weight_rows else 0.0

            if name == "Node Information":
                # Determine if an explicit density_count was provided (scenario-level or legacy section field).
                explicit_density_raw = None
                scen_level_dc = scen.get('density_count')
                if scen_level_dc is not None:
                    explicit_density_raw = scen_level_dc
                else:
                    for legacy_key in ('density_count', 'total_nodes', 'base_nodes'):
                        if sec.get(legacy_key) not in (None, ""):
                            explicit_density_raw = sec.get(legacy_key)
                            break
                density_count: int | None = None
                if explicit_density_raw is not None:
                    try:
                        density_count = max(0, int(explicit_density_raw))
                    except Exception:
                        density_count = 0
                # additive Count rows always additive even if base omitted
                additive_nodes = sum(int(it.get('v_count') or 0) for it in count_rows)
                # For derived counts we only have a combined host pool if explicit density_count provided
                combined_nodes = (density_count or 0) + additive_nodes
                norm_sum = 0.0
                if weight_rows:
                    raw_sum = sum(float(it.get('factor') or 0) for it in weight_rows)
                    if raw_sum > 0:
                        for it in weight_rows:
                            try:
                                it['factor'] = float(it.get('factor') or 0) / raw_sum
                            except Exception:
                                it['factor'] = 0.0
                        norm_sum = 1.0
                    else:
                        weight_rows[0]['factor'] = 1.0
                        for it in weight_rows[1:]:
                            it['factor'] = 0.0
                        norm_sum = 1.0
                # Only persist base-related fields if an explicit density_count was supplied. Otherwise omit so parser can apply default.
                if density_count is not None:
                    sec_el.set("density_count", str(density_count))
                    sec_el.set("base_nodes", str(density_count))
                sec_el.set("additive_nodes", str(additive_nodes))
                if density_count is not None:
                    sec_el.set("combined_nodes", str(combined_nodes))
                sec_el.set("weight_rows", str(len(weight_rows)))
                sec_el.set("count_rows", str(len(count_rows)))
                sec_el.set("weight_sum", f"{weight_sum:.3f}")
                sec_el.set("normalized_weight_sum", f"{norm_sum:.3f}")
                combined_host_pool = combined_nodes if density_count is not None else None
                scenario_host_additive += combined_nodes if density_count is not None else additive_nodes
            else:
                dens = sec.get("density")
                if dens is not None:
                    try:
                        sec_el.set("density", f"{float(dens):.3f}")
                    except Exception:
                        sec_el.set("density", str(dens))
                if name in ("Routing", "Vulnerabilities"):
                    base_pool = combined_host_pool if isinstance(combined_host_pool, int) else None
                    explicit = sum(int(it.get('v_count') or 0) for it in count_rows)
                    derived = 0
                    try:
                        dens_val = float(dens or 0)
                    except Exception:
                        dens_val = 0.0
                    if weight_rows and base_pool and base_pool > 0:
                        if name == 'Routing':
                            if dens_val >= 1:
                                derived = int(round(dens_val))
                            elif dens_val > 0:
                                derived = int(round(base_pool * dens_val))
                        else:  # Vulnerabilities
                            if dens_val > 0:
                                dens_clip = min(1.0, dens_val)
                                derived = int(round(base_pool * dens_clip))
                    total_planned = explicit + derived
                    sec_el.set("explicit_count", str(explicit))
                    sec_el.set("derived_count", str(derived))
                    sec_el.set("total_planned", str(total_planned))
                    sec_el.set("weight_rows", str(len(weight_rows)))
                    sec_el.set("count_rows", str(len(count_rows)))
                    sec_el.set("weight_sum", f"{weight_sum:.3f}")
                    if name == 'Routing':
                        scenario_routing_total += total_planned
                    else:
                        scenario_vuln_total += total_planned
                elif name in ("Services", "Traffic", "Segmentation"):
                    explicit = sum(int(it.get('v_count') or 0) for it in count_rows)
                    sec_el.set("explicit_count", str(explicit))
                    sec_el.set("weight_rows", str(len(weight_rows)))
                    sec_el.set("count_rows", str(len(count_rows)))
                    sec_el.set("weight_sum", f"{weight_sum:.3f}")

            try:
                if bool(sec.get('node_count_min_enabled')):
                    sec_el.set('node_count_min_enabled', 'true')
                    min_val = sec.get('node_count_min')
                    if min_val is not None and str(min_val).strip() != '':
                        sec_el.set('node_count_min', str(int(min_val)))
            except Exception:
                pass
            try:
                if bool(sec.get('node_count_max_enabled')):
                    sec_el.set('node_count_max_enabled', 'true')
                    max_val = sec.get('node_count_max')
                    if max_val is not None and str(max_val).strip() != '':
                        sec_el.set('node_count_max', str(int(max_val)))
            except Exception:
                pass

            for item in items_list:
                it = ET.SubElement(sec_el, "item")
                sel_for_xml = str(item.get('selected', 'Random'))
                it.set("selected", sel_for_xml)
                try:
                    it.set("factor", f"{float(item.get('factor', 1.0)):.3f}")
                except Exception:
                    it.set("factor", "0.000")
                if name == 'Routing':
                    em = (item.get('r2r_mode') or '').strip()
                    r2s_mode = (item.get('r2s_mode') or '').strip()
                    if em:
                        it.set('r2r_mode', em)
                    if r2s_mode:
                        it.set('r2s_mode', r2s_mode)
                    # Persist edge budget hints when provided (including Uniform/NonUniform / aggregate modes)
                    try:
                        ev_raw = item.get('r2r_edges') or item.get('edges')
                        if em == 'Exact' and ev_raw is not None and str(ev_raw).strip() != '':
                            ev = int(ev_raw)
                            if ev > 0:  # only meaningful positive degrees
                                it.set('r2r_edges', str(ev))
                    except Exception:
                        pass
                    try:
                        r2s_raw = item.get('r2s_edges')
                        if r2s_raw is not None and str(r2s_raw).strip() != '':
                            ev2 = int(r2s_raw)
                            if ev2 >= 0:
                                it.set('r2s_edges', str(ev2))
                    except Exception:
                        pass
                    # Persist per-item host grouping bounds if provided (non-empty and >=0)
                    try:
                        hmin_raw = item.get('r2s_hosts_min')
                        if hmin_raw not in (None, ''):
                            hmin_val = int(hmin_raw)
                            if hmin_val >= 0:
                                it.set('r2s_hosts_min', str(hmin_val))
                    except Exception:
                        pass
                    try:
                        hmax_raw = item.get('r2s_hosts_max')
                        if hmax_raw not in (None, ''):
                            hmax_val = int(hmax_raw)
                            if hmax_val >= 0:
                                it.set('r2s_hosts_max', str(hmax_val))
                    except Exception:
                        pass
                    # If still absent, write explicit defaults (UI defaults 1 and 4) for deterministic round-trip
                    if 'r2s_hosts_min' not in it.attrib:
                        it.set('r2s_hosts_min', '1')
                    if 'r2s_hosts_max' not in it.attrib:
                        it.set('r2s_hosts_max', '4')
                if name == 'Traffic':
                    it.set('pattern', str(item.get('pattern', 'continuous')))
                    it.set('rate_kbps', f"{float(item.get('rate_kbps', 64.0)):.1f}")
                    it.set('period_s', f"{float(item.get('period_s', 1.0)):.1f}")
                    it.set('jitter_pct', f"{float(item.get('jitter_pct', 10.0)):.1f}")
                    ct = (item.get('content_type') or '').strip()
                    if ct:
                        it.set('content_type', ct)
                if name == 'Vulnerabilities':
                    sel = sel_for_xml
                    if sel == 'Specific':
                        vn = item.get('v_name')
                        vp = item.get('v_path')
                        if vn:
                            it.set('v_name', str(vn))
                        if vp:
                            it.set('v_path', str(vp))
                if name == 'Segmentation':
                    if _coerce_bool(item.get('pivot_enabled')):
                        it.set('pivot_enabled', 'true')
                        for state_key, xml_attr in (
                            ('pivot_provider', 'pivot_provider'),
                            ('requires', 'requires'),
                            ('produces', 'produces'),
                        ):
                            val = item.get(state_key)
                            if val is not None and str(val).strip() != '':
                                it.set(xml_attr, str(val).strip())
                vm_any = item.get('v_metric')
                if vm_any:
                    it.set('v_metric', str(vm_any))
                if (item.get('v_metric') == 'Count') or (name == 'Vulnerabilities' and str(item.get('selected', '')) == 'Specific'):
                    vc_any = item.get('v_count')
                    try:
                        if vc_any is not None:
                            it.set('v_count', str(int(vc_any)))
                    except Exception:
                        pass

        # Final scenario-level aggregate
        try:
            total_nodes = scenario_host_additive + scenario_routing_total + scenario_vuln_total
            scen_el.set('scenario_total_nodes', str(total_nodes))
            scen_el.set('base_nodes', '0')
        except Exception:
            pass

    return ET.ElementTree(root)


def _validate_core_xml(xml_path: str):
    """Validate the scenario XML against the CORE XML XSD. Returns (ok, errors_text)."""
    try:
        # Derive project root relative to this file (../) then the validation directory
        here = os.path.abspath(os.path.dirname(__file__))
        repo_root = os.path.abspath(os.path.join(here, '..'))
        xsd_path = os.path.join(repo_root, 'schemas', 'xml', 'corexml_codebased.xsd')
        # Fallback: if not found, try relative to current working directory (for unusual run contexts)
        if not os.path.exists(xsd_path):
            alt = os.path.abspath(os.path.join(os.getcwd(), 'schemas', 'xml', 'corexml_codebased.xsd'))
            if os.path.exists(alt):
                xsd_path = alt
        if not os.path.exists(xsd_path):
            return False, f"Schema not found: {xsd_path}"
        with open(xsd_path, 'rb') as f:
            schema_doc = LET.parse(f)
        schema = LET.XMLSchema(schema_doc)
        # Read original XML; if it contains any <container> elements (session export artifacts),
        # strip them prior to validation so that user-provided or auto-exported session XML can
        # still be validated against the scenario schema. This addresses UI errors like:
        #   Element 'container': This element is not expected.
        # We purposefully do NOT mutate the source file on disk; sanitization is in-memory.
        try:
            raw_tree = LET.parse(xml_path)
            root = raw_tree.getroot()
            # Collect and remove any elements whose local-name is 'container'
            containers = root.xpath('.//*[local-name()="container"]')
            if containers:
                for el in containers:
                    parent = el.getparent()
                    if parent is not None:
                        parent.remove(el)
                # Validate sanitized tree
                try:
                    schema.assertValid(root)
                    return True, ''
                except LET.DocumentInvalid as e:
                    # Fall through to structured error collection below
                    err_log = e.error_log
                    lines = [f"{er.level_name} L{er.line}:C{er.column} - {er.message}" for er in err_log]
                    return False, "\n".join(lines) or str(e)
            else:
                # No <container>; validate normally using parser bound to schema for speed
                parser = LET.XMLParser(schema=schema)
                LET.parse(xml_path, parser)
                return True, ''
        except LET.XMLSyntaxError as e:  # low-level parse error before schema phase
            lines = []
            for err in e.error_log:
                lines.append(f"{err.level_name} L{err.line}:C{err.column} - {err.message}")
            return False, "\n".join(lines) or str(e)
    except LET.XMLSyntaxError as e:
        lines = []
        for err in e.error_log:
            lines.append(f"{err.level_name} L{err.line}:C{err.column} - {err.message}")
        return False, "\n".join(lines) or str(e)
    except Exception as e:
        return False, str(e)


def _analyze_core_xml(xml_path: str) -> Dict[str, Any]:
    """Extract a topology summary from a CORE session/scenario XML."""
    info: Dict[str, Any] = {}
    try:
        tree = LET.parse(xml_path)
        root = tree.getroot()

        def attrs(el, *names):
            return {n: el.get(n) for n in names if el.get(n) is not None}

        def local(tag: str) -> str:
            if not tag:
                return ''
            if '}' in tag:
                return tag.split('}', 1)[1]
            return tag

        def iter_by_local(el, lname: str):
            lname = lname.lower()
            for e in el.iter():
                if local(getattr(e, 'tag', '')).lower() == lname:
                    yield e

        # Combine device/node representations (session exports sometimes use <node>)
        candidates = list(iter_by_local(root, 'device')) + list(iter_by_local(root, 'node'))
        devices: list[Any] = []
        seen_ids: set[str] = set()
        for cand in candidates:
            ident = cand.get('id') or cand.get('name')
            key = str(ident).strip() if ident is not None else ''
            if key and key in seen_ids:
                continue
            if key:
                seen_ids.add(key)
            devices.append(cand)

        networks = list(iter_by_local(root, 'network'))
        links = list(iter_by_local(root, 'link'))
        services = list(iter_by_local(root, 'service'))

        routing_edge_policies: list[dict] = []
        try:
            for sec in root.findall('.//section'):
                if (sec.get('name') or '').strip() != 'Routing':
                    continue
                for item in sec.findall('./item'):
                    r2r_edges = item.get('r2r_edges') or item.get('edges')
                    r2s_edges = item.get('r2s_edges')
                    if any([item.get('r2r_mode'), r2r_edges, item.get('r2s_mode'), r2s_edges]):
                        routing_edge_policies.append({
                            'r2r_mode': item.get('r2r_mode') or '',
                            'r2r_edges': int(r2r_edges) if (r2r_edges and r2r_edges.isdigit()) else None,
                            'r2s_mode': item.get('r2s_mode') or '',
                            'r2s_edges': int(r2s_edges) if (r2s_edges and r2s_edges.isdigit()) else None,
                            'protocol': item.get('selected') or '',
                        })
        except Exception:
            routing_edge_policies = []

        interface_store: Dict[str, Dict[str, Dict[str, Any]]] = defaultdict(dict)

        def record_interface(node_ref: Any, iface_el: Any) -> None:
            node_key = str(node_ref or '').strip()
            if not node_key or iface_el is None:
                return
            try:
                attrs_iface = dict(getattr(iface_el, 'attrib', {}) or {})
            except Exception:
                attrs_iface = {}
            name_raw = (attrs_iface.get('name') or attrs_iface.get('id') or '').strip()
            if not name_raw:
                name_el = iface_el.find('./name') if hasattr(iface_el, 'find') else None
                if name_el is not None and getattr(name_el, 'text', None):
                    name_raw = name_el.text.strip()
            mac = (attrs_iface.get('mac') or '').strip()
            if not mac and hasattr(iface_el, 'find'):
                mac_el = iface_el.find('./mac')
                if mac_el is not None and getattr(mac_el, 'text', None):
                    mac = mac_el.text.strip()
            ip4 = (attrs_iface.get('ip4') or attrs_iface.get('ipv4') or '').strip()
            ip4_mask = (attrs_iface.get('ip4_mask') or attrs_iface.get('ipv4_mask') or '').strip()
            ip6 = (attrs_iface.get('ip6') or attrs_iface.get('ipv6') or '').strip()
            ip6_mask = (attrs_iface.get('ip6_mask') or attrs_iface.get('ipv6_mask') or '').strip()
            try:
                for addr in iface_el.findall('.//addr'):
                    addr_type = (addr.get('type') or addr.get('family') or '').lower()
                    addr_val = (addr.get('address') or addr.get('ip') or (addr.text or '')).strip()
                    mask_val = (addr.get('mask') or addr.get('prefix') or addr.get('netmask') or '').strip()
                    if not addr_val:
                        continue
                    if '6' in addr_type:
                        if not ip6:
                            ip6 = addr_val
                        if not ip6_mask:
                            ip6_mask = mask_val
                    else:
                        if not ip4:
                            ip4 = addr_val
                        if not ip4_mask:
                            ip4_mask = mask_val
                for addr in iface_el.findall('.//address'):
                    addr_val = (addr.get('value') or addr.get('address') or (addr.text or '')).strip()
                    mask_val = (addr.get('mask') or addr.get('prefix') or '').strip()
                    addr_type = (addr.get('type') or '').lower()
                    if not addr_val:
                        continue
                    if '6' in addr_type:
                        if not ip6:
                            ip6 = addr_val
                        if not ip6_mask:
                            ip6_mask = mask_val
                    else:
                        if not ip4:
                            ip4 = addr_val
                        if not ip4_mask:
                            ip4_mask = mask_val
            except Exception:
                pass
            if not any([name_raw, mac, ip4, ip6]):
                return
            stable_key = '|'.join([
                name_raw.lower(),
                ip4,
                ip6,
            ])
            existing = interface_store[node_key].get(stable_key)
            if existing:
                if mac and not existing.get('mac'):
                    existing['mac'] = mac
                if ip4_mask and not existing.get('ipv4_mask'):
                    existing['ipv4_mask'] = ip4_mask
                if ip6_mask and not existing.get('ipv6_mask'):
                    existing['ipv6_mask'] = ip6_mask
                if name_raw and not existing.get('name'):
                    existing['name'] = name_raw
                return
            interface_store[node_key][stable_key] = {
                'name': name_raw or None,
                'mac': mac or None,
                'ipv4': ip4 or None,
                'ipv4_mask': ip4_mask or None,
                'ipv6': ip6 or None,
                'ipv6_mask': ip6_mask or None,
            }

        id_to_name: Dict[str, str] = {}
        id_to_type: Dict[str, str] = {}
        id_to_services: Dict[str, list] = {}

        def coerce_device_id(raw_id: Any, fallback_index: int) -> str:
            value = str(raw_id).strip() if raw_id is not None else ''
            if value:
                return value
            return f"device_{fallback_index}"

        for idx, dev in enumerate(devices, start=1):
            did = coerce_device_id(dev.get('id') or dev.get('name'), idx)
            name_val = (dev.get('name') or '').strip()
            if not name_val and hasattr(dev, 'find'):
                name_el = dev.find('./name')
                if name_el is not None and getattr(name_el, 'text', None):
                    name_val = name_el.text.strip()
            type_val = (dev.get('type') or '').strip()
            if not type_val and hasattr(dev, 'find'):
                type_el = dev.find('./type') or dev.find('./model') or dev.find('./icon')
                if type_el is not None and getattr(type_el, 'text', None):
                    type_val = type_el.text.strip()
            id_to_name[did] = name_val or did
            id_to_type[did] = type_val or ''

            services_found: set[str] = set()
            try:
                for svc in dev.findall('./services/service'):
                    nm = (svc.get('name') or (svc.text or '')).strip()
                    if nm:
                        services_found.add(nm)
                for svc in dev.findall('./service'):
                    nm = (svc.get('name') or (svc.text or '')).strip()
                    if nm:
                        services_found.add(nm)
            except Exception:
                pass
            id_to_services[did] = sorted(services_found)

            try:
                for iface in dev.findall('.//interface'):
                    record_interface(did, iface)
                for iface in dev.findall('.//iface'):
                    record_interface(did, iface)
            except Exception:
                pass

        adj: Dict[str, set[str]] = defaultdict(set)

        def normalize_ref(value: Any) -> str:
            return str(value).strip() if value is not None else ''

        for link in links:
            n1 = normalize_ref(link.get('node1') or link.get('node1_id'))
            n2 = normalize_ref(link.get('node2') or link.get('node2_id'))
            if not n1 or not n2:
                try:
                    if not n1 and hasattr(link, 'find'):
                        iface1 = link.find('.//iface1')
                        if iface1 is not None:
                            n1 = normalize_ref(iface1.get('node') or iface1.get('device') or iface1.get('node_id'))
                    if not n2 and hasattr(link, 'find'):
                        iface2 = link.find('.//iface2')
                        if iface2 is not None:
                            n2 = normalize_ref(iface2.get('node') or iface2.get('device') or iface2.get('node_id'))
                except Exception:
                    pass
            if n1 and n2:
                adj[n1].add(n2)
                adj[n2].add(n1)
            try:
                for child in list(link):
                    tag = local(getattr(child, 'tag', '')).lower()
                    target = None
                    if tag in ('iface1', 'interface1'):
                        target = n1
                    elif tag in ('iface2', 'interface2'):
                        target = n2
                    elif tag in ('iface', 'interface'):
                        target = normalize_ref(child.get('node') or child.get('node_id') or child.get('device')) or n2
                    if target:
                        record_interface(target, child)
            except Exception:
                continue

        nodes: list[dict] = []
        for idx, dev in enumerate(devices, start=1):
            did = coerce_device_id(dev.get('id') or dev.get('name'), idx)
            raw_ifaces = interface_store.get(did, {})
            iface_entries = []
            for entry in raw_ifaces.values():
                cleaned = {k: v for k, v in entry.items() if v not in (None, '')}
                if cleaned:
                    iface_entries.append(cleaned)
            iface_entries.sort(key=lambda e: ((e.get('name') or '').lower(), e.get('ipv4') or '', e.get('ipv6') or ''))
            nodes.append({
                'id': did,
                'name': id_to_name.get(did, did),
                'type': id_to_type.get(did, ''),
                'services': id_to_services.get(did, []),
                'linked_nodes': [],
                'interfaces': iface_entries,
            })

        switches = [n for n in nodes if (n.get('type') or '').lower() == 'switch']
        extra_switch_nodes: list[dict] = []
        extra_hitl_network_nodes: list[dict] = []
        hitl_network_markers = ('rj45', 'rj-45', 'hitl', 'tap', 'bridge', 'ethernet', 'physical')
        try:
            for net in networks:
                ntype = (net.get('type') or '').lower()
                is_switch_candidate = 'switch' in ntype
                is_hitl_candidate = any(marker in ntype for marker in hitl_network_markers)
                if not is_switch_candidate and not is_hitl_candidate:
                    continue
                sw_id = normalize_ref(net.get('id') or net.get('name'))
                if not sw_id:
                    continue
                sw_name = (net.get('name') or sw_id).strip() or sw_id
                if is_switch_candidate and any(sw_id == sw.get('id') or sw_name == sw.get('name') for sw in switches):
                    continue
                if is_hitl_candidate and any(sw_id == n.get('id') or sw_name == n.get('name') for n in nodes):
                    continue
                raw_ifaces = interface_store.get(sw_id, {})
                iface_entries = []
                for entry in raw_ifaces.values():
                    cleaned = {k: v for k, v in entry.items() if v not in (None, '')}
                    if cleaned:
                        iface_entries.append(cleaned)
                iface_entries.sort(key=lambda e: ((e.get('name') or '').lower(), e.get('ipv4') or '', e.get('ipv6') or ''))
                if is_switch_candidate:
                    extra_switch = {
                        'id': sw_id,
                        'name': sw_name,
                        'type': 'switch',
                        'services': [],
                        'linked_nodes': [],
                        'interfaces': iface_entries,
                    }
                    switches.append(extra_switch)
                    extra_switch_nodes.append(extra_switch)
                    id_to_name.setdefault(sw_id, sw_name)
                    id_to_type.setdefault(sw_id, 'switch')
                elif is_hitl_candidate:
                    extra_hitl = {
                        'id': sw_id,
                        'name': sw_name,
                        'type': net.get('type') or 'rj45',
                        'services': [],
                        'linked_nodes': [],
                        'interfaces': iface_entries,
                    }
                    extra_hitl_network_nodes.append(extra_hitl)
                    id_to_name.setdefault(sw_id, sw_name)
                    id_to_type.setdefault(sw_id, extra_hitl['type'].lower())
        except Exception:
            pass

        valid_ids: set[str] = {n['id'] for n in nodes}
        valid_ids.update(sw['id'] for sw in extra_switch_nodes)
        valid_ids.update(hitl['id'] for hitl in extra_hitl_network_nodes)
        adj_clean: Dict[str, set[str]] = {}
        for nid, neighbors in adj.items():
            if nid not in valid_ids:
                continue
            adj_clean[nid] = {nbr for nbr in neighbors if nbr in valid_ids}
        for sw in extra_switch_nodes:
            adj_clean.setdefault(sw['id'], set())
        for hitl in extra_hitl_network_nodes:
            adj_clean.setdefault(hitl['id'], set())

        def _prune_neighbors(node_id: str, node_type: str) -> None:
            if node_type in ('router', 'switch'):
                return
            current_neighbors = sorted(adj_clean.get(node_id, set()), key=lambda vid: id_to_name.get(vid, vid).lower())
            routers = [vid for vid in current_neighbors if (id_to_type.get(vid, '').lower() == 'router')]
            switches_local = [vid for vid in current_neighbors if (id_to_type.get(vid, '').lower() == 'switch')]

            def _trim_group(group: list[str]) -> None:
                if len(group) <= 1:
                    return
                keep = group[0]
                for extra in group[1:]:
                    adj_clean.get(node_id, set()).discard(extra)
                    if extra in adj_clean:
                        adj_clean[extra].discard(node_id)

            _trim_group(routers)
            _trim_group(switches_local)

        for node in nodes:
            _prune_neighbors(node['id'], (node.get('type') or '').lower())
        for sw in extra_switch_nodes:
            _prune_neighbors(sw['id'], (sw.get('type') or '').lower())
        for hitl in extra_hitl_network_nodes:
            _prune_neighbors(hitl['id'], (hitl.get('type') or '').lower())

        def _neighbor_names(node_id: str) -> list[str]:
            neighbors = sorted(adj_clean.get(node_id, set()), key=lambda vid: id_to_name.get(vid, vid).lower())
            return [id_to_name.get(vid, vid) for vid in neighbors]

        filtered_nodes: list[dict] = []
        important_types = {'router', 'switch', 'rj45', 'rj-45', 'tap', 'bridge'}
        for node in nodes:
            nid = node['id']
            linked = adj_clean.get(nid, set())
            node_type = (node.get('type') or '').lower()
            if linked or (node.get('interfaces') and len(node.get('interfaces')) > 0) or node_type in important_types:
                node['linked_nodes'] = _neighbor_names(nid)
                filtered_nodes.append(node)
        nodes = filtered_nodes

        filtered_extra_switch_nodes: list[dict] = []
        for sw in extra_switch_nodes:
            nid = sw['id']
            linked = adj_clean.get(nid, set())
            if linked:
                sw['linked_nodes'] = _neighbor_names(nid)
                filtered_extra_switch_nodes.append(sw)
        extra_switch_nodes = filtered_extra_switch_nodes

        filtered_extra_hitl_nodes: list[dict] = []
        for hitl in extra_hitl_network_nodes:
            nid = hitl['id']
            linked = adj_clean.get(nid, set())
            if linked:
                hitl['linked_nodes'] = _neighbor_names(nid)
                filtered_extra_hitl_nodes.append(hitl)
        extra_hitl_network_nodes = filtered_extra_hitl_nodes

        valid_ids = {n['id'] for n in nodes}
        valid_ids.update(sw['id'] for sw in extra_switch_nodes)
        valid_ids.update(hitl['id'] for hitl in extra_hitl_network_nodes)
        adj_clean = {nid: {nbr for nbr in neighbors if nbr in valid_ids} for nid, neighbors in adj_clean.items() if nid in valid_ids}

        switches = [n for n in nodes if (n.get('type') or '').lower() == 'switch']
        hitl_markers = ('rj45', 'hitl', 'tap', 'bridge', 'ethernet', 'rj-45')

        def _is_hitl_node(node: dict) -> bool:
            node_type = (node.get('type') or '').lower()
            if node_type and any(marker in node_type for marker in hitl_markers):
                return True
            for svc in node.get('services') or []:
                svc_name = (svc or '').lower()
                if any(marker in svc_name for marker in hitl_markers):
                    return True
            node_name = (node.get('name') or '').lower()
            if node_name and any(marker in node_name for marker in ('rj45', 'hitl')):
                return True
            return False

        hitl_nodes: list[dict] = []
        for node in nodes:
            if _is_hitl_node(node):
                node['is_hitl'] = True
                hitl_nodes.append(node)
        for hitl in extra_hitl_network_nodes:
            hitl['is_hitl'] = True
            hitl_nodes.append(hitl)

        link_details: list[dict] = []
        seen_pairs: set[tuple[str, str]] = set()
        for src, neighbors in adj_clean.items():
            for dst in neighbors:
                if src == dst or dst not in valid_ids:
                    continue
                ordered = tuple(sorted((src, dst)))
                if ordered in seen_pairs:
                    continue
                seen_pairs.add(ordered)
                link_details.append({
                    'node1': ordered[0],
                    'node2': ordered[1],
                    'node1_name': id_to_name.get(ordered[0], ordered[0]),
                    'node2_name': id_to_name.get(ordered[1], ordered[1]),
                })

        info.update({
            'nodes_count': len(nodes),
            'networks_count': len(networks),
            'links_count': len(link_details),
            'services_count': len(services),
            'nodes': nodes,
            'switches_count': len(switches) + len(extra_switch_nodes),
            'switches_device_count': len(switches),
            'switches': [sw['name'] for sw in switches] + [sw['name'] for sw in extra_switch_nodes],
            'switch_nodes': extra_switch_nodes,
            'hitl_network_nodes': extra_hitl_network_nodes,
            'hitl_nodes': hitl_nodes,
            'hitl_nodes_count': len(hitl_nodes),
            'links_detail': link_details,
            'routing_edges_policies': routing_edge_policies,
        })
        info['devices'] = [attrs(d, 'id', 'name', 'type', 'class', 'image') for d in devices[:50]]
        info['networks'] = [attrs(n, 'id', 'name', 'type', 'model', 'mobility') for n in networks[:50]]
        info['links_sample'] = len(link_details)

        try:
            st = os.stat(xml_path)
            info['file_size_bytes'] = st.st_size
        except Exception:
            pass

        try:
            router_ids = [normalize_ref(dev.get('id')) for dev in devices if (dev.get('type') or '').lower().find('router') >= 0]
            degs = {rid: len(adj_clean.get(rid, set())) for rid in router_ids if rid}
            if degs:
                vals = list(degs.values())
                info['router_degree_stats'] = {
                    'min': min(vals),
                    'max': max(vals),
                    'avg': round(sum(vals) / len(vals), 2),
                    'per_router': degs,
                }
        except Exception:
            pass

        return info
    except Exception as e:
        return {'error': str(e)}


def _summarize_planner_scenarios(xml_path: str) -> Dict[str, Any]:
    """Create a lightweight summary for Scenario Editor bundles (root <Scenarios>)."""
    summary: Dict[str, Any] = {'__planner_bundle': True, 'scenarios': [], 'scenarios_count': 0}
    try:
        payload = _parse_scenarios_xml(xml_path)
    except Exception as exc:
        summary['error'] = str(exc)
        return summary
    scen_list = payload.get('scenarios') or []
    for scen in scen_list:
        if not isinstance(scen, dict):
            continue
        sections_meta = scen.get('sections') if isinstance(scen.get('sections'), dict) else {}
        sections_summary: List[Dict[str, Any]] = []
        for sec_name, sec_val in sections_meta.items():
            if not isinstance(sec_val, dict):
                continue
            sections_summary.append({
                'name': sec_name,
                'item_count': len(sec_val.get('items') or []),
                'density': sec_val.get('density'),
                'total_nodes': sec_val.get('total_nodes'),
            })
        summary['scenarios'].append({
            'name': scen.get('name') or 'Scenario',
            'density_count': scen.get('density_count'),
            'scenario_total_nodes': scen.get('scenario_total_nodes'),
            'base_nodes': scen.get('base_nodes'),
            'hitl_enabled': bool(((scen.get('hitl') or {}).get('enabled'))),
            'base_file': ((scen.get('base') or {}).get('filepath') or ''),
            'sections': sections_summary,
        })
    summary['scenarios_count'] = len(summary['scenarios'])
    core_meta = payload.get('core') if isinstance(payload.get('core'), dict) else None
    if core_meta:
        summary['core'] = core_meta
    return summary


try:
    from webapp.routes import xml_editor_io as _xml_editor_io_routes

    _xml_editor_io_routes.register(
        app,
        current_user_getter=lambda: _current_user(),
        allowed_file_func=lambda filename: allowed_file(filename),
        parse_scenarios_xml=lambda path: _parse_scenarios_xml(path),
        default_core_dict=lambda: _default_core_dict(),
        attach_base_upload=lambda payload, *args, **kwargs: _attach_base_upload(payload, *args, **kwargs),
        hydrate_base_upload_from_disk=lambda payload, *args, **kwargs: _hydrate_base_upload_from_disk(payload, *args, **kwargs),
        enumerate_host_interfaces=lambda: _enumerate_host_interfaces(),
        save_base_upload_state=lambda payload, user=None: _save_base_upload_state(payload, user=user),
        prepare_payload_for_index=lambda *args, **kwargs: _prepare_payload_for_index(*args, **kwargs),
        persist_editor_state_snapshot=lambda *args, **kwargs: _persist_editor_state_snapshot(*args, **kwargs),
        load_editor_state_snapshot=lambda user=None: _load_editor_state_snapshot(user=user),
        normalize_core_config=lambda *args, **kwargs: _normalize_core_config(*args, **kwargs),
        normalize_scenario_names_strict=lambda *args, **kwargs: _normalize_scenario_names_strict(*args, **kwargs),
        local_timestamp_safe=lambda: _local_timestamp_safe(),
        outputs_dir=lambda: _outputs_dir(),
        sanitize_scenario_name_strict=lambda *args, **kwargs: _sanitize_scenario_name_strict(*args, **kwargs),
        build_scenarios_xml=lambda payload: _build_scenarios_xml(payload),
        persist_scenario_catalog=lambda *args, **kwargs: _persist_scenario_catalog(*args, **kwargs),
        ui_build_id=_WEBUI_BUILD_ID,
        logger=app.logger,
    )
except Exception:
    try:
        app.logger.exception('Failed to register xml_editor_io routes.')
    except Exception:
        pass


def load_xml():
    user = _current_user()
    file = request.files.get('scenarios_xml')
    if not file or file.filename == '':
        flash('No file selected.')
        return redirect(url_for('index'))
    if not allowed_file(file.filename):
        flash('Invalid file type. Only XML allowed.')
        return redirect(url_for('index'))
    filename = secure_filename(file.filename)
    filepath = os.path.join(app.config['UPLOAD_FOLDER'], filename)
    os.makedirs(app.config['UPLOAD_FOLDER'], exist_ok=True)
    file.save(filepath)
    try:
        payload = _parse_scenarios_xml(filepath)
        # add default CORE connection parameters
        if "core" not in payload:
            payload["core"] = _default_core_dict()
        payload["result_path"] = filepath
        _attach_base_upload(payload)
        _hydrate_base_upload_from_disk(payload)
        payload['host_interfaces'] = _enumerate_host_interfaces()
        if payload.get('base_upload'):
            _save_base_upload_state(payload['base_upload'])
        xml_text = ""
        try:
            with open(filepath, 'r', encoding='utf-8', errors='ignore') as f:
                xml_text = f.read()
        except Exception:
            xml_text = ""
        payload = _prepare_payload_for_index(payload, user=user)
        snapshot_source = dict(payload)
        snapshot_source['active_index'] = 0
        snapshot_source['project_key_hint'] = payload.get('result_path')
        _persist_editor_state_snapshot(snapshot_source, user=user)
        snapshot = _load_editor_state_snapshot(user)
        if snapshot:
            payload['editor_snapshot'] = snapshot
        return render_template('index.html', payload=payload, logs="", xml_preview=xml_text, ui_build_id=_WEBUI_BUILD_ID)
    except Exception as e:
        flash(f'Failed to parse XML: {e}')
        return redirect(url_for('index'))


def save_xml():
    data_str = request.form.get('scenarios_json')
    if not data_str:
        flash('No data received.')
        return redirect(url_for('index'))
    user = _current_user()
    try:
        data = json.loads(data_str)
    except Exception as e:
        flash(f'Invalid JSON: {e}')
        return redirect(url_for('index'))
    try:
        active_index = None
        try:
            active_index = int(data.get('active_index')) if 'active_index' in data else None
        except Exception:
            active_index = None
        core_meta = None
        try:
            core_str = request.form.get('core_json')
            if core_str:
                core_meta = json.loads(core_str)
        except Exception:
            core_meta = None
        client_project_hint = (request.form.get('project_key_hint') or '').strip()
        client_scenario_query = (request.form.get('scenario_query') or '').strip()
        normalized_core = _normalize_core_config(core_meta, include_password=True) if core_meta else None
        # Enforce strict alphanumeric-only scenario names with deterministic uniquification.
        try:
            scenarios_list = data.get('scenarios') or []
            if isinstance(scenarios_list, list):
                _normalize_scenario_names_strict(scenarios_list)
                scenarios_list = _concretize_scenarios_for_save(scenarios_list, seed=data.get('seed'))
                data['scenarios'] = scenarios_list
        except Exception:
            pass
        scenario_count = len(data.get('scenarios') or []) if isinstance(data.get('scenarios'), list) else 0
        scenario_names_desc = []
        try:
            scenario_names_desc = [str((sc or {}).get('name') or '').strip() for sc in (data.get('scenarios') or []) if isinstance(sc, dict)]
        except Exception:
            scenario_names_desc = []
        username = (user or {}).get('username') if isinstance(user, dict) else None
        try:
            app.logger.info(
                '[save_xml] user=%s scen_count=%s active_index=%s project_hint=%s scenario_query=%s names=%s',
                username or 'anonymous',
                scenario_count,
                active_index if active_index is not None else 'none',
                client_project_hint or '<none>',
                client_scenario_query or '<none>',
                ', '.join(name for name in scenario_names_desc if name) or '<unnamed>'
            )
        except Exception:
            pass
        scenarios_list = data.get('scenarios') if isinstance(data.get('scenarios'), list) else []
        ts = _local_timestamp_safe()
        out_dir = os.path.join(_outputs_dir(), f'scenarios-{ts}')
        os.makedirs(out_dir, exist_ok=True)
        try:
            legacy_bundle = os.path.join(out_dir, 'scenarios.xml')
            if os.path.exists(legacy_bundle):
                os.remove(legacy_bundle)
        except Exception:
            pass
        scenario_paths_map: dict[str, str] = {}
        active_out_path = None
        if scenarios_list:
            for idx, scen in enumerate(scenarios_list):
                if not isinstance(scen, dict):
                    continue
                raw_name = (scen.get('name') or '').strip()
                display_name = _sanitize_scenario_name_strict(raw_name, f"NewScenario{idx + 1}")
                stem = secure_filename(display_name).strip('_-.') or f"Scenario_{idx + 1}"
                out_path = os.path.join(out_dir, f"{stem}.xml")
                # Ensure unique filename in this save directory.
                if os.path.exists(out_path):
                    suffix = 2
                    base = stem
                    while os.path.exists(out_path):
                        stem = f"{base}-{suffix}"
                        out_path = os.path.join(out_dir, f"{stem}.xml")
                        suffix += 1
                try:
                    tree = _build_scenarios_xml({ 'scenarios': [scen], 'core': normalized_core })
                    from lxml import etree as LET  # type: ignore
                    raw = ET.tostring(tree.getroot(), encoding='utf-8')
                    lroot = LET.fromstring(raw)
                    pretty = LET.tostring(lroot, pretty_print=True, xml_declaration=True, encoding='utf-8')
                    with open(out_path, 'wb') as f:
                        f.write(pretty)
                except Exception:
                    try:
                        tree = _build_scenarios_xml({ 'scenarios': [scen], 'core': normalized_core })
                        tree.write(out_path, encoding='utf-8', xml_declaration=True)
                    except Exception:
                        continue
                scenario_paths_map[display_name] = out_path
                if active_index is not None and active_index == idx:
                    active_out_path = out_path
            if active_out_path is None and scenario_paths_map:
                # Default to first scenario when active_index is missing/invalid.
                active_out_path = next(iter(scenario_paths_map.values()))
        else:
            out_path = None
        out_path = active_out_path
        try:
            if scenario_paths_map:
                app.logger.info('[save_xml] wrote %s scenario xml files under %s', len(scenario_paths_map), out_dir)
            else:
                app.logger.info('[save_xml] persisted empty scenario state with no xml output')
        except Exception:
            pass
        # Read back XML content for preview
        xml_text = ""
        if out_path:
            try:
                with open(out_path, 'r', encoding='utf-8', errors='ignore') as f:
                    xml_text = f.read()
            except Exception:
                xml_text = ""
        try:
            names_for_catalog = [name for name in scenario_names_desc if isinstance(name, str) and name.strip()]
            if names_for_catalog:
                _persist_scenario_catalog(names_for_catalog, source_path=scenario_paths_map or out_path)
        except Exception:
            pass
        if out_path:
            flash(f'Scenarios saved (per-scenario). Active XML: {os.path.basename(out_path)}')
        else:
            flash('Empty scenario state saved.')
        payload = {
            'scenarios': data.get('scenarios', []),
            'result_path': out_path,
            'core': _normalize_core_config(normalized_core or {}, include_password=False) if normalized_core else _default_core_dict(),
        }
        payload['host_interfaces'] = _enumerate_host_interfaces()
        _attach_base_upload(payload)
        _hydrate_base_upload_from_disk(payload)
        if payload.get('base_upload'):
            _save_base_upload_state(payload['base_upload'])
        payload = _prepare_payload_for_index(payload, user=user)
        if client_project_hint:
            payload['project_key_hint'] = client_project_hint
        if client_scenario_query:
            payload['scenario_query'] = client_scenario_query
        snapshot_source = dict(payload)
        try:
            snapshot_source['scenarios'] = copy.deepcopy(data.get('scenarios') or [])
        except Exception:
            snapshot_source['scenarios'] = data.get('scenarios') or []
        snapshot_source['active_index'] = active_index
        if client_project_hint:
            snapshot_source['project_key_hint'] = client_project_hint
        elif payload.get('project_key_hint'):
            snapshot_source['project_key_hint'] = payload.get('project_key_hint')
        else:
            snapshot_source['project_key_hint'] = payload.get('result_path')
        if client_scenario_query:
            snapshot_source['scenario_query'] = client_scenario_query
        elif payload.get('scenario_query'):
            snapshot_source['scenario_query'] = payload.get('scenario_query')
        _persist_editor_state_snapshot(snapshot_source, user=user)
        snapshot = _load_editor_state_snapshot(user)
        if snapshot:
            payload['editor_snapshot'] = snapshot
        try:
            app.logger.info('[save_xml] success user=%s xml=%s scen_count=%s', username or 'anonymous', out_path, scenario_count)
        except Exception:
            pass
        return render_template('index.html', payload=payload, logs="", xml_preview=xml_text, ui_build_id=_WEBUI_BUILD_ID)
    except Exception as e:
        flash(f'Failed to save XML: {e}')
        return redirect(url_for('index'))


def save_xml_api():
    try:
        user = _current_user()
        data = request.get_json(silent=True) or {}
        scenarios = data.get('scenarios')
        core_meta = data.get('core')
        normalized_core = _normalize_core_config(core_meta, include_password=True) if isinstance(core_meta, (dict, list)) or core_meta else None
        raw_project_hint = data.get('project_key_hint') if isinstance(data, dict) else None
        project_key_hint = raw_project_hint.strip() if isinstance(raw_project_hint, str) else ''
        raw_scenario_query = data.get('scenario_query') if isinstance(data, dict) else None
        scenario_query_hint = raw_scenario_query.strip() if isinstance(raw_scenario_query, str) else ''
        active_index = None
        try:
            active_index = int(data.get('active_index')) if 'active_index' in data else None
        except Exception:
            active_index = None
        if not isinstance(scenarios, list):
            return jsonify({ 'ok': False, 'error': 'Invalid payload (scenarios list required)' }), 400
        # Enforce strict alphanumeric-only scenario names with deterministic uniquification.
        try:
            _normalize_scenario_names_strict(scenarios)
            scenarios = _concretize_scenarios_for_save(scenarios, seed=data.get('seed'))
        except Exception:
            pass
        scenario_names: list[str] = []
        try:
            scenario_names = [str((s or {}).get('name') or '').strip() for s in scenarios if isinstance(s, dict)]
        except Exception:
            scenario_names = []
        username = (user or {}).get('username') if isinstance(user, dict) else None
        try:
            app.logger.info(
                '[save_xml_api] user=%s scen_count=%s active_index=%s project_hint=%s scenario_query=%s names=%s',
                username or 'anonymous',
                len(scenarios),
                active_index if active_index is not None else 'none',
                project_key_hint or '<none>',
                scenario_query_hint or '<none>',
                ', '.join(name for name in scenario_names if name) or '<unnamed>'
            )
        except Exception:
            pass
        autosave = False

        def _has_meaningful_value(value: Any) -> bool:
            if value is None:
                return False
            if isinstance(value, str):
                return bool(value.strip())
            if isinstance(value, bool):
                return value is True
            if isinstance(value, (int, float)):
                return True
            if isinstance(value, list):
                return len(value) > 0
            if isinstance(value, dict):
                return any(_has_meaningful_value(v) for v in value.values())
            return False

        def _has_meaningful_hitl(scenario_payload: Any) -> bool:
            if not isinstance(scenario_payload, dict):
                return False
            hitl = scenario_payload.get('hitl') if isinstance(scenario_payload.get('hitl'), dict) else None
            if not isinstance(hitl, dict):
                return False
            return _has_meaningful_value(hitl)

        def _merge_verified_hitl_fields(existing_hitl: Any, incoming_hitl: Any) -> Any:
            """Merge existing verified HITL fields into incoming payload without clobbering user edits.

            This protects readiness-critical fields (validated + secret identifiers + vm_key)
            during autosave/partial saves where the client may send a reduced HITL object.
            """
            if not isinstance(existing_hitl, dict):
                return incoming_hitl
            if not isinstance(incoming_hitl, dict):
                return copy.deepcopy(existing_hitl)

            merged_hitl = copy.deepcopy(incoming_hitl)
            existing = copy.deepcopy(existing_hitl)

            # Preserve overall bridge validation marker when incoming omitted it.
            try:
                if (_coerce_bool(existing.get('bridge_validated')) or existing.get('bridge_validated_at')) and not _coerce_bool(merged_hitl.get('bridge_validated')):
                    merged_hitl['bridge_validated'] = True
                    if (not merged_hitl.get('bridge_validated_at')) and existing.get('bridge_validated_at'):
                        merged_hitl['bridge_validated_at'] = existing.get('bridge_validated_at')
            except Exception:
                pass

            # Proxmox readiness guard.
            existing_prox = existing.get('proxmox') if isinstance(existing.get('proxmox'), dict) else {}
            incoming_prox = merged_hitl.get('proxmox') if isinstance(merged_hitl.get('proxmox'), dict) else {}
            incoming_prox = dict(incoming_prox)
            try:
                existing_secret = str(existing_prox.get('secret_id') or '').strip()
                existing_validated = _coerce_bool(existing_prox.get('validated'))
                incoming_secret = str(incoming_prox.get('secret_id') or '').strip()
                incoming_validated = _coerce_bool(incoming_prox.get('validated'))
                if existing_validated and existing_secret and (not incoming_validated or not incoming_secret):
                    incoming_prox['secret_id'] = existing_secret
                    incoming_prox['validated'] = True
                    if (not incoming_prox.get('last_validated_at')) and existing_prox.get('last_validated_at'):
                        incoming_prox['last_validated_at'] = existing_prox.get('last_validated_at')
                # Fill missing connection metadata from existing state.
                for key in ('url', 'port', 'verify_ssl', 'stored_at', 'last_message'):
                    if key not in incoming_prox or incoming_prox.get(key) in (None, ''):
                        if existing_prox.get(key) not in (None, ''):
                            incoming_prox[key] = existing_prox.get(key)
            except Exception:
                pass
            if incoming_prox:
                merged_hitl['proxmox'] = incoming_prox

            # CORE readiness guard.
            existing_core = existing.get('core') if isinstance(existing.get('core'), dict) else {}
            incoming_core = merged_hitl.get('core') if isinstance(merged_hitl.get('core'), dict) else {}
            incoming_core = dict(incoming_core)
            try:
                existing_core_secret = str(existing_core.get('core_secret_id') or '').strip()
                existing_vm_key = str(existing_core.get('vm_key') or '').strip()
                existing_validated = _coerce_bool(existing_core.get('validated'))
                incoming_core_secret = str(incoming_core.get('core_secret_id') or '').strip()
                incoming_vm_key = str(incoming_core.get('vm_key') or '').strip()
                incoming_validated = _coerce_bool(incoming_core.get('validated'))
                if existing_validated and existing_core_secret and existing_vm_key and (
                    (not incoming_validated) or (not incoming_core_secret) or (not incoming_vm_key)
                ):
                    incoming_core['core_secret_id'] = existing_core_secret
                    incoming_core['vm_key'] = existing_vm_key
                    incoming_core['validated'] = True
                    if (not incoming_core.get('last_validated_at')) and existing_core.get('last_validated_at'):
                        incoming_core['last_validated_at'] = existing_core.get('last_validated_at')
                for key in ('vm_name', 'vm_node', 'vmid', 'grpc_host', 'grpc_port', 'ssh_host', 'ssh_port', 'stored_at', 'last_tested_at', 'last_tested_status', 'last_tested_message', 'last_tested_host', 'last_tested_port', 'internal_bridge', 'internal_bridge_owner'):
                    if key not in incoming_core or incoming_core.get(key) in (None, ''):
                        if existing_core.get(key) not in (None, ''):
                            incoming_core[key] = existing_core.get(key)
            except Exception:
                pass
            if incoming_core:
                merged_hitl['core'] = incoming_core

            return merged_hitl

        existing_hitl_by_norm: dict[str, dict[str, Any]] = {}
        try:
            for scen in scenarios if isinstance(scenarios, list) else []:
                if not isinstance(scen, dict):
                    continue
                nm = str((scen.get('name') or '')).strip()
                norm = _normalize_scenario_label(nm)
                if not norm or norm in existing_hitl_by_norm:
                    continue
                xml_existing = _latest_xml_path_for_scenario(norm)
                if not xml_existing:
                    continue
                parsed_existing = _parse_scenarios_xml(xml_existing)
                existing_list = parsed_existing.get('scenarios') if isinstance(parsed_existing, dict) else None
                if not isinstance(existing_list, list):
                    continue
                for existing_scen in existing_list:
                    if not isinstance(existing_scen, dict):
                        continue
                    ex_name = str(existing_scen.get('name') or '').strip()
                    if _normalize_scenario_label(ex_name) != norm:
                        continue
                    ex_hitl = existing_scen.get('hitl') if isinstance(existing_scen.get('hitl'), dict) else None
                    if isinstance(ex_hitl, dict) and _has_meaningful_value(ex_hitl):
                        existing_hitl_by_norm[norm] = copy.deepcopy(ex_hitl)
                    break
        except Exception:
            existing_hitl_by_norm = {}

        ts = _local_timestamp_safe()
        out_dir = os.path.join(_outputs_dir(), f'scenarios-{ts}')
        os.makedirs(out_dir, exist_ok=True)
        try:
            legacy_bundle = os.path.join(out_dir, 'scenarios.xml')
            if os.path.exists(legacy_bundle):
                os.remove(legacy_bundle)
        except Exception:
            pass
        scenario_paths_map: dict[str, str] = {}
        scenario_paths_by_index: list[str | None] = []
        active_out_path = None
        if scenarios:
            for idx, scen in enumerate(scenarios):
                if not isinstance(scen, dict):
                    scenario_paths_by_index.append(None)
                    continue
                raw_name = (scen.get('name') or '').strip()
                display_name = _sanitize_scenario_name_strict(raw_name, f"NewScenario{idx + 1}")
                stem_raw = display_name
                stem = secure_filename(stem_raw).strip('_-.') or f"NewScenario{idx + 1}"
                out_path = os.path.join(out_dir, f"{stem}.xml")
                if os.path.exists(out_path):
                    suffix = 2
                    base = stem
                    while os.path.exists(out_path):
                        stem = f"{base}-{suffix}"
                        out_path = os.path.join(out_dir, f"{stem}.xml")
                        suffix += 1
                try:
                    scen_to_write = scen
                    try:
                        norm = _normalize_scenario_label(display_name)
                        existing_hitl = existing_hitl_by_norm.get(norm)
                        if isinstance(existing_hitl, dict):
                            scen_to_write = dict(scen)
                            incoming_hitl = scen.get('hitl') if isinstance(scen, dict) else None
                            if not _has_meaningful_hitl(scen):
                                scen_to_write['hitl'] = copy.deepcopy(existing_hitl)
                                try:
                                    app.logger.info('[save_xml_api] preserved hitl for scenario=%s from existing XML', display_name)
                                except Exception:
                                    pass
                            else:
                                scen_to_write['hitl'] = _merge_verified_hitl_fields(existing_hitl, incoming_hitl)
                                try:
                                    app.logger.info('[save_xml_api] merged verified hitl fields for scenario=%s', display_name)
                                except Exception:
                                    pass
                    except Exception:
                        scen_to_write = scen

                    tree = _build_scenarios_xml({ 'scenarios': [scen_to_write], 'core': normalized_core })
                    raw = ET.tostring(tree.getroot(), encoding='utf-8')
                    lroot = LET.fromstring(raw)
                    pretty = LET.tostring(lroot, pretty_print=True, xml_declaration=True, encoding='utf-8')
                    with open(out_path, 'wb') as f:
                        f.write(pretty)
                except Exception:
                    try:
                        tree = _build_scenarios_xml({ 'scenarios': [scen_to_write], 'core': normalized_core })
                        tree.write(out_path, encoding='utf-8', xml_declaration=True)
                    except Exception:
                        continue
                # Defensive: ensure each file contains exactly one <Scenario>.
                try:
                    parsed = ET.parse(out_path)
                    root = parsed.getroot()
                    scenario_count = len(root.findall('Scenario'))
                    if scenario_count != 1:
                        tree = _build_scenarios_xml({ 'scenarios': [scen], 'core': normalized_core })
                        tree.write(out_path, encoding='utf-8', xml_declaration=True)
                except Exception:
                    pass
                scenario_paths_map[display_name] = out_path
                scenario_paths_by_index.append(out_path)
                if active_index is not None and active_index == idx:
                    active_out_path = out_path
            if active_out_path is None and scenario_paths_map:
                active_out_path = next(iter(scenario_paths_map.values()))
        else:
            active_out_path = None
        out_path = active_out_path
        try:
            if scenario_paths_map:
                app.logger.info('[save_xml_api] wrote %s scenario xml files under %s', len(scenario_paths_map), out_dir)
            else:
                app.logger.info('[save_xml_api] persisted empty scenario state with no xml output')
        except Exception:
            pass
        resp_core = _normalize_core_config(normalized_core or core_meta or {}, include_password=False) if (normalized_core or core_meta) else _default_core_dict()
        snapshot_source = {
            'scenarios': scenarios,
            'core': resp_core,
            'result_path': out_path,
            'active_index': active_index,
            'project_key_hint': project_key_hint or out_path,
        }
        try:
            snapshot_source['saved_xml_paths_by_index'] = scenario_paths_by_index
        except Exception:
            pass
        if scenario_query_hint:
            snapshot_source['scenario_query'] = scenario_query_hint
        try:
            if active_index is not None and 0 <= active_index < len(scenarios):
                active_name = str((scenarios[active_index] or {}).get('name') or '').strip()
                if active_name:
                    snapshot_source['result_path_scenario'] = active_name
        except Exception:
            pass
        _persist_editor_state_snapshot(snapshot_source, user=user)
        try:
            app.logger.info('[save_xml_api] success user=%s xml=%s scen_count=%s', username or 'anonymous', out_path, len(scenarios))
        except Exception:
            pass
        try:
            names_for_catalog = [name for name in scenario_names if isinstance(name, str) and name.strip()]
            if names_for_catalog:
                _persist_scenario_catalog(names_for_catalog, source_path=scenario_paths_map or out_path)
        except Exception:
            pass
        response_payload = { 'ok': True, 'result_path': out_path, 'core': resp_core }
        if scenario_paths_map:
            response_payload['scenario_paths'] = scenario_paths_map
        response_payload['scenario_paths_by_index'] = scenario_paths_by_index
        if active_index is not None and 0 <= active_index < len(scenarios):
            try:
                active_name = str((scenarios[active_index] or {}).get('name') or '').strip()
            except Exception:
                active_name = ''
            if active_name:
                response_payload['active_scenario'] = active_name
        return jsonify(response_payload)
    except Exception as e:
        try:
            app.logger.exception("[save_xml_api] failed: %s", e)
        except Exception:
            pass
        return jsonify({ 'ok': False, 'error': str(e) }), 500


def render_xml_api():
    """Render scenario XML for preview without persisting to disk."""
    try:
        data = request.get_json(silent=True) or {}
        scenarios = data.get('scenarios')
        core_meta = data.get('core')
        normalized_core = _normalize_core_config(core_meta, include_password=True) if isinstance(core_meta, (dict, list)) or core_meta else None
        if not isinstance(scenarios, list):
            return jsonify({ 'ok': False, 'error': 'Invalid payload (scenarios list required)' }), 400
        tree = _build_scenarios_xml({ 'scenarios': scenarios, 'core': normalized_core })
        # Pretty print when possible
        try:
            raw = ET.tostring(tree.getroot(), encoding='utf-8')
            lroot = LET.fromstring(raw)
            pretty = LET.tostring(lroot, pretty_print=True, xml_declaration=True, encoding='utf-8')
            return Response(pretty, mimetype='application/xml')
        except Exception:
            out = ET.tostring(tree.getroot(), encoding='utf-8', xml_declaration=True)
            return Response(out, mimetype='application/xml')
    except Exception as e:
        try:
            app.logger.exception('[render_xml_api] failed: %s', e)
        except Exception:
            pass
        return jsonify({ 'ok': False, 'error': str(e) }), 500


