def _close_async_run_tunnel(meta: Dict[str, Any]) -> None:
    tunnel = meta.pop('ssh_tunnel', None)
    if tunnel:
        try:
            tunnel.close()
        except Exception:
            pass


def _append_async_run_log_line(meta: Dict[str, Any] | None, line: str) -> None:
    if not meta:
        return
    lp = meta.get('log_path')
    if not lp:
        return
    try:
        with open(lp, 'a', encoding='utf-8', buffering=1) as _f:
            _f.write(line.rstrip('\n') + "\n")
    except Exception:
        pass


def _session_docker_nodes_from_xml(session_xml_path: str) -> List[str]:
    names: List[str] = []
    if not session_xml_path or not os.path.exists(session_xml_path):
        return names
    try:
        import xml.etree.ElementTree as _ET
        app.logger.info(f"_session_docker_nodes_from_xml parsing {session_xml_path}")
        root = _ET.parse(session_xml_path).getroot()
    except Exception:
        return names
    candidates = []
    try:
        candidates.extend(root.findall('.//node'))
    except Exception:
        pass
    try:
        candidates.extend(root.findall('.//device'))
    except Exception:
        pass
    for node in candidates:
        try:
            ntype = (node.get('type') or node.get('model') or '').strip().lower()
            nclass = (node.get('class') or '').strip().lower()
            compose = (node.get('compose') or '').strip()
            compose_name = (node.get('compose_name') or '').strip()
        except Exception:
            ntype = ''
            nclass = ''
            compose = ''
            compose_name = ''
        is_docker = False
        if ntype in ('docker', 'docker-compose', 'docker_node', 'docker-node') or 'docker' in ntype:
            is_docker = True
        if nclass and 'docker' in nclass:
            is_docker = True
        if compose or compose_name:
            is_docker = True
        if not is_docker:
            continue
        nm = (node.get('name') or node.findtext('name') or '').strip()
        if nm:
            names.append(nm)
    # Deduplicate while preserving order
    seen: set[str] = set()
    out: List[str] = []
    for n in names:
        if n in seen:
            continue
        seen.add(n)
        out.append(n)
    app.logger.info(f"_session_docker_nodes_from_xml found {len(out)} nodes: {out}")
    return out


def _remote_docker_injects_status_script(
    *,
    containers: List[str],
    sudo_password: str | None = None,
    inject_dirs: List[str] | None = None,
    expected_by_node: Dict[str, List[str]] | None = None,
    max_find: int = 200,
) -> str:
    containers_literal = json.dumps([str(x) for x in (containers or [])])
    sudo_password_literal = json.dumps(str(sudo_password) if sudo_password else "")
    max_find_literal = json.dumps(int(max_find))
    inject_dirs_literal = json.dumps([str(d) for d in (inject_dirs or [])])
    expected_by_node_literal = json.dumps(expected_by_node or {})
    return (
        r"""
import json, shlex, subprocess, time

null = None
true = True
false = False

CONTAINERS = __CONTAINERS_LITERAL__
SUDO_PASSWORD = __SUDO_PASSWORD_LITERAL__
MAX_FIND = __MAX_FIND_LITERAL__
INJECT_DIRS = __INJECT_DIRS_LITERAL__
EXPECTED_BY_NODE = __EXPECTED_BY_NODE_LITERAL__


def _run(cmd, timeout=30):
    try:
        p = subprocess.run(['sudo', '-n'] + list(cmd), stdout=subprocess.PIPE, stderr=subprocess.STDOUT, text=True, timeout=timeout)
        if p.returncode == 0:
            return p
        if SUDO_PASSWORD:
            return subprocess.run(
                ['sudo', '-S', '-k', '-p', ''] + list(cmd),
                input=str(SUDO_PASSWORD) + "\n",
                stdout=subprocess.PIPE,
                stderr=subprocess.STDOUT,
                text=True,
                timeout=timeout,
            )
        return p
    except Exception as e:
        return subprocess.CompletedProcess(cmd, 127, stdout=str(e))


def _inspect_state(container_name, attempts=4, delay_s=1.0):
    last_out = ''
    total_attempts = max(1, int(attempts or 1))
    for idx in range(total_attempts):
        p = _run(['docker', 'inspect', '--format', '{{json .State}}', container_name], timeout=20)
        out = str(p.stdout or '').strip()
        if p.returncode == 0 and out:
            try:
                st = json.loads(out)
            except Exception:
                st = {}
            if not isinstance(st, dict):
                st = {}
            status = str(st.get('Status') or '').strip()
            status_norm = status.lower()
            restarting = bool(st.get('Restarting') is True or status_norm == 'restarting')
            running = bool((st.get('Running') is True or status_norm == 'running') and not restarting)
            exit_code = st.get('ExitCode')
            state_error = str(st.get('Error') or '').strip()
            if restarting and idx < total_attempts - 1:
                last_out = out
                try:
                    time.sleep(float(delay_s or 1.0))
                except Exception:
                    pass
                continue
            return {
                'exists': True,
                'running': running,
                'status': status,
                'exit_code': exit_code,
                'error': state_error,
                'inspect_error': '',
            }
        if out:
            last_out = out
        if idx < total_attempts - 1:
            try:
                time.sleep(float(delay_s or 1.0))
            except Exception:
                pass
    return {
        'exists': False,
        'running': False,
        'status': '',
        'exit_code': None,
        'error': '',
        'inspect_error': last_out,
    }


def _expected_paths_for(container_name):
    if not isinstance(EXPECTED_BY_NODE, dict):
        return []
    raw = EXPECTED_BY_NODE.get(container_name)
    if not isinstance(raw, list):
        return []
    out = []
    seen = set()
    for item in raw:
        path = str(item or '').strip()
        if not path or path in seen:
            continue
        seen.add(path)
        out.append(path)
    return out


def _check_expected_paths(container_name, paths):
    present = []
    missing = []
    debug = []
    for path in paths or []:
        qpath = shlex.quote(str(path or '').strip())
        if not qpath:
            continue
        p = _run(['docker', 'exec', container_name, 'sh', '-c', f'test -e {qpath}'], timeout=15)
        if p.returncode == 0:
            present.append(str(path))
        else:
            out = str(p.stdout or '').strip()
            if out:
                debug.append(out)
            missing.append(str(path))
    return present, missing, debug


def _debug_mentions_restarting(values):
    for value in values or []:
        text = str(value or '').lower()
        if ' is restarting' in text or 'container is restarting' in text:
            return True
    return False


def main():
    items = []
    for c in CONTAINERS:
        c = str(c or '').strip()
        if not c:
            continue
        exists = False
        running = False
        state_status = ''
        state_exit_code = None
        state_error = ''
        inspect_error = ''
        try:
            st = _inspect_state(c, attempts=4, delay_s=1.0)
            exists = bool(st.get('exists'))
            running = bool(st.get('running'))
            state_status = str(st.get('status') or '').strip()
            state_exit_code = st.get('exit_code')
            state_error = str(st.get('error') or '').strip()
            inspect_error = str(st.get('inspect_error') or '').strip()
        except Exception:
            exists = False
            running = False
        inject_count = 0
        inject_samples = []
        inject_dirs_found = []
        expected_present = []
        expected_missing = []
        debug_logs = []
        if exists and running:
            for d in INJECT_DIRS:
                if not d:
                    continue
                shell = (
                    'set -e; '
                    'mesg n >/dev/null 2>&1 || true; '
                    f"if [ -d {d} ]; then "
                    f"find {d} -maxdepth 4 -type f -print 2>/dev/null | head -n {MAX_FIND}; "
                    f"fi; "
                )
                p2 = _run(['docker', 'exec', c, 'sh', '-c', shell], timeout=25)
                out = (p2.stdout or '').strip()
                if p2.returncode == 0 and out:
                    lines = [ln.strip() for ln in out.splitlines() if str(ln).strip().startswith('/')]
                    if lines:
                        inject_dirs_found.append(d)
                        inject_samples = (inject_samples + lines)[:5]
                        inject_count += len(lines)
                    elif out:
                        first = str(out.splitlines()[0]).strip()
                        if first:
                            debug_logs.append(first)
                else:
                    if d:
                        shell_dbg = (
                            'set -e; '
                            'mesg n >/dev/null 2>&1 || true; '
                            f"if [ -d {d} ]; then ls -la {d} 2>&1 | head -n 10; else echo 'MISSING_DIR:{d}'; fi; "
                        )
                        p3 = _run(['docker', 'exec', c, 'sh', '-c', shell_dbg], timeout=20)
                        dbg = (p3.stdout or '').strip()
                        if dbg:
                            debug_logs.append(dbg)
            expected_paths = _expected_paths_for(c)
            if expected_paths:
                expected_present, expected_missing, expected_debug = _check_expected_paths(c, expected_paths)
                debug_logs.extend(expected_debug)
            if _debug_mentions_restarting(debug_logs):
                retry_state = _inspect_state(c, attempts=8, delay_s=1.0)
                exists = bool(retry_state.get('exists'))
                running = False
                state_status = str(retry_state.get('status') or 'restarting').strip() or 'restarting'
                state_exit_code = retry_state.get('exit_code')
                state_error = str(retry_state.get('error') or '').strip()
                inspect_error = str(retry_state.get('inspect_error') or inspect_error).strip()
        items.append({
            'container': c,
            'exists': exists,
            'running': running,
            'state_status': state_status,
            'state_exit_code': state_exit_code,
            'state_error': state_error,
            'inspect_error': inspect_error,
            'inject_count': inject_count,
            'inject_samples': inject_samples,
            'inject_dirs_found': inject_dirs_found,
            'expected_present': expected_present,
            'expected_missing': expected_missing,
            'debug_logs': debug_logs,
        })
    print(json.dumps({'ok': True, 'items': items}))


if __name__ == '__main__':
    main()
"""
    ).replace('__CONTAINERS_LITERAL__', containers_literal) \
     .replace('__SUDO_PASSWORD_LITERAL__', sudo_password_literal) \
     .replace('__MAX_FIND_LITERAL__', max_find_literal) \
    .replace('__INJECT_DIRS_LITERAL__', inject_dirs_literal) \
    .replace('__EXPECTED_BY_NODE_LITERAL__', expected_by_node_literal)


def _remote_flow_artifacts_validation_script(
    assignments: List[Dict[str, Any]],
    scenario_label: str = '',
    sudo_password: str | None = None,
) -> str:
    assignments_literal = json.dumps(assignments or [])
    scenario_label_literal = json.dumps(str(scenario_label or ''))
    sudo_password_literal = json.dumps(str(sudo_password) if sudo_password else '')
    return (
        r"""
import json, os, glob, subprocess, shlex, re

null = None
true = True
false = False

ASSIGNMENTS = __ASSIGNMENTS_LITERAL__
SCENARIO_LABEL = __SCENARIO_LABEL_LITERAL__
SUDO_PASSWORD = __SUDO_PASSWORD_LITERAL__


def _run_docker(cmd, timeout=20, capture=True):
    stdout = subprocess.PIPE if capture else subprocess.DEVNULL
    stderr = subprocess.STDOUT if capture else subprocess.DEVNULL
    try:
        p = subprocess.run(['sudo', '-n', 'docker'] + list(cmd), stdout=stdout, stderr=stderr, text=True, timeout=timeout)
        if p.returncode == 0:
            return p
        if SUDO_PASSWORD:
            return subprocess.run(
                ['sudo', '-S', '-k', '-p', '', 'docker'] + list(cmd),
                input=str(SUDO_PASSWORD) + "\n",
                stdout=stdout,
                stderr=stderr,
                text=True,
                timeout=timeout,
            )
        return p
    except Exception as e:
        class _P:
            returncode = 1
            stdout = str(e)
        return _P()


def _docker_names() -> tuple[set[str], str]:
    p = _run_docker(['ps', '-a', '--format', '{{.Names}}'], timeout=20, capture=True)
    if getattr(p, 'returncode', 1) != 0:
        return set(), str(getattr(p, 'stdout', '') or '').strip()
    out = set()
    for ln in str(getattr(p, 'stdout', '') or '').splitlines():
        s = str(ln or '').strip()
        if s:
            out.add(s)
    return out, ''


def _container_path_exists(container_name: str, container_path: str) -> tuple[bool, str]:
    if not container_name or not container_path or not str(container_path).startswith('/'):
        return False, 'invalid_container_path'
    cmd = f"test -e {shlex.quote(str(container_path))}"
    p = _run_docker(['exec', container_name, '/usr/local/coretg/bin/busybox', 'sh', '-lc', cmd], timeout=20, capture=True)
    if getattr(p, 'returncode', 1) == 0:
        return True, ''
    p2 = _run_docker(['exec', container_name, 'sh', '-lc', cmd], timeout=20, capture=True)
    if getattr(p2, 'returncode', 1) == 0:
        return True, ''
    p3 = _run_docker(['exec', container_name, '/bin/sh', '-lc', cmd], timeout=20, capture=True)
    if getattr(p3, 'returncode', 1) == 0:
        return True, ''
    p4 = _run_docker(['exec', container_name, 'ls', '-ld', str(container_path)], timeout=20, capture=True)
    if getattr(p4, 'returncode', 1) == 0:
        return True, ''
    return False, str(
        getattr(p4, 'stdout', '')
        or getattr(p3, 'stdout', '')
        or getattr(p2, 'stdout', '')
        or getattr(p, 'stdout', '')
        or ''
    ).strip()


def _safe_exists(p: str) -> bool:
    try:
        return bool(p and os.path.exists(p))
    except Exception:
        return False


def _looks_like_path(key, val) -> bool:
    try:
        if not isinstance(val, str):
            return False
        v = val.strip()
        if not v:
            return False
        k = str(key or '').lower()
        if 'path' in k or 'file' in k:
            return True
        if 'directory' in k or 'dir' in k:
            return True
        if v.startswith('/') or v.startswith('artifacts/'):
            return True
        if '/' in v:
            return True
        return False
    except Exception:
        return False


def _skip_output_path_check(key, val) -> bool:
    try:
        k = str(key or '').strip().lower()
        v = str(val or '').strip()
        if k.startswith('directory('):
            return True
        if k.startswith('endpoint('):
            return True
        if k.startswith(('credential(', 'exposedsecret(', 'flagdelivery(', 'hostname(', 'portforward(', 'token(', 'version(')):
            return True
        if not v:
            return False
        if v in ('/exports', '/outputs', '/inputs'):
            return True
        return False
    except Exception:
        return False


def _find_latest_run_dir(scenario_tag, node_name):
    try:
        base = '/tmp/vulns/flag_node_generators_runs'
        if not os.path.isdir(base):
            return None
        # Pattern: cli-{scenario}-{node}-*
        # We need to be careful about safe names.
        # But we can try globbing.
        pat = f"{base}/cli-*{scenario_tag}*{node_name}*"
        cands = glob.glob(pat)
        if not cands:
            return None
        # Sort by modification time
        cands.sort(key=os.path.getmtime, reverse=True)
        return cands[0]
    except Exception:
        return None


def _find_output_path_suffix(base_dir: str, rel_value: str) -> str:
    try:
        root = str(base_dir or '').strip()
        rel = str(rel_value or '').replace('\\', '/').strip().lstrip('/')
        if rel.startswith('outputs/'):
            rel = rel.split('outputs/', 1)[1].lstrip('/')
        if not root or not rel or not os.path.isdir(root):
            return ''
        basename = os.path.basename(rel)
        visited = 0
        for current_dir, _dirnames, filenames in os.walk(root):
            for filename in filenames:
                visited += 1
                if visited > 5000:
                    return ''
                candidate = os.path.join(current_dir, filename)
                try:
                    rel_candidate = os.path.relpath(candidate, root).replace('\\', '/')
                except Exception:
                    rel_candidate = filename
                if rel_candidate == rel or rel_candidate.endswith('/' + rel):
                    return candidate
                if basename and filename == basename and '/' not in rel:
                    return candidate
    except Exception:
        return ''
    return ''


def _resolve_output_path(val: str, run_dir: str, artifacts_dir: str, scenario_tag: str = '', node_name: str = '') -> str:
    v = str(val or '').strip()
    if not v:
        return ''
    
    # Dynamic discovery override if run_dir/artifacts_dir seem missing/stale
    # and we have enough info to guess.
    use_v = v
    if (not run_dir or not os.path.exists(run_dir)) and scenario_tag and node_name:
        found = _find_latest_run_dir(scenario_tag, node_name)
        if found:
            run_dir = found

    def _map_container_mount_path(abs_path: str) -> str:
        p = str(abs_path or '').strip()
        if not p or not os.path.isabs(p):
            return p
        base = run_dir or artifacts_dir or ''
        if not base:
            return p
        for mount_prefix in ('/outputs', '/exports'):
            if p == mount_prefix:
                return base
            if p.startswith(mount_prefix + '/'):
                suffix = p[len(mount_prefix):].lstrip('/')
                return os.path.join(base, suffix) if suffix else base
        return p
    
    if os.path.isabs(v):
        return _map_container_mount_path(v)

    rel = v.lstrip('/')
    candidates = []
    if artifacts_dir:
        if v.startswith('artifacts/'):
            candidates.append(os.path.join(artifacts_dir, v.split('artifacts/', 1)[1].lstrip('/')))
        else:
            candidates.append(os.path.join(artifacts_dir, rel))
    if run_dir:
        candidates.append(os.path.join(run_dir, rel))
        if not v.startswith('artifacts/'):
            candidates.append(os.path.join(run_dir, 'artifacts', rel))
            candidates.append(os.path.join(run_dir, 'outputs', rel))
            candidates.append(os.path.join(run_dir, 'outputs', 'artifacts', rel))

    seen = set()
    uniq_candidates = []
    for c in candidates:
        if not c:
            continue
        if c in seen:
            continue
        seen.add(c)
        uniq_candidates.append(c)

    for c in uniq_candidates:
        if _safe_exists(c):
            return c
    for root in (artifacts_dir, run_dir):
        found = _find_output_path_suffix(root, rel)
        if found:
            return found
    if uniq_candidates:
        return uniq_candidates[0]
    return v


def _normalize_inject_src_for_copy(raw_src: str, source_dir: str) -> str:
    def _normalize_rel_artifacts(rel_src: str, base_dir: str) -> str:
        out = str(rel_src or '').replace('\\', '/').strip()
        if out.startswith('./'):
            out = out[2:]
        out = out.lstrip('/')
        try:
            if base_dir and os.path.basename(os.path.normpath(base_dir)) == 'artifacts':
                while out.startswith('artifacts/'):
                    out = out[len('artifacts/'):]
        except Exception:
            pass
        return out

    src = str(raw_src or '').strip()
    if not src:
        return ''
    if src == '/tmp/flag.txt':
        return src
    if not os.path.isabs(src):
        return _normalize_rel_artifacts(src, source_dir)
    try:
        if source_dir:
            src_abs = os.path.abspath(src)
            base_abs = os.path.abspath(source_dir)
            if os.path.commonpath([src_abs, base_abs]) == base_abs:
                return _normalize_rel_artifacts(os.path.relpath(src_abs, base_abs), source_dir)
    except Exception:
        pass
    for marker in ('/artifacts/', '/flow_artifacts/'):
        if marker in src:
            return _normalize_rel_artifacts(src.split(marker, 1)[1], source_dir)
    return src


def _normalize_inject_spec_for_copy(raw: str, source_dir: str) -> str:
    text = str(raw or '').strip()
    if not text:
        return ''
    sep = '->' if '->' in text else '=>' if '=>' in text else ''
    if sep:
        left, _right = text.split(sep, 1)
        src_norm = _normalize_inject_src_for_copy(left.strip(), source_dir)
        return src_norm
    return _normalize_inject_src_for_copy(text, source_dir)


def _inject_files_for_copy_from_detail(detail_list, source_dir: str) -> list[str]:
    if not isinstance(detail_list, list):
        return []
    out = []
    for entry in detail_list:
        if not isinstance(entry, dict):
            continue
        resolved = str(entry.get('resolved') or '').strip()
        path = str(entry.get('path') or '').strip()
        if not path:
            continue
        dest_dir = os.path.dirname(path) if path.startswith('/') else ''
        if dest_dir == '/' and path.startswith('/'):
            dest_dir = path.rstrip('/') or '/'
        if not dest_dir or dest_dir == '/':
            continue
        src_norm = _normalize_inject_src_for_copy(resolved, source_dir)
        if not src_norm:
            continue
        out.append(src_norm)
    return out


def main():
    docker_names, docker_err = _docker_names()
    items = []
    for a in (ASSIGNMENTS or []):
        if not isinstance(a, dict):
            continue
        node_id = str(a.get('node_id') or '')
        node_name = str(a.get('node_name') or a.get('node_id') or '').strip()
        gen_id = str(a.get('id') or a.get('generator_id') or '')
        gen_name = str(a.get('generator_name') or a.get('name') or '')
        gen_type = str(a.get('generator_type') or a.get('type') or '')
        run_dir = str(a.get('run_dir') or a.get('artifacts_dir') or '')
        artifacts_dir = str(a.get('inject_source_dir') or a.get('artifacts_dir') or '')
        outputs_manifest = str(a.get('outputs_manifest') or '')
        outputs_missing = []
        outputs_checked = []
        outputs_resolved = {}
        flag_delivery_mode = 'unknown'
        flag_file_path = ''
        manifest_expected = bool(outputs_manifest)
        manifest_exists = _safe_exists(outputs_manifest)
        outs = None
        if manifest_expected and not manifest_exists:
            manifest_txt = str(outputs_manifest or '').strip().replace('\\', '/')
            if (
                manifest_txt.startswith('/tmp/')
                or manifest_txt.startswith('/exports/')
                or manifest_txt.startswith('/outputs/')
                or manifest_txt.startswith('/inputs/')
            ):
                outputs_missing.append(f"missing manifest: {outputs_manifest}")
        if manifest_exists:
            try:
                with open(outputs_manifest, 'r', encoding='utf-8') as f:
                    m = json.load(f) or {}
                outs = m.get('outputs') if isinstance(m, dict) else None
            except Exception:
                outs = None
        if manifest_exists and not (isinstance(outs, dict) and outs):
            outputs_missing.append(f"empty manifest: {outputs_manifest}")
        if isinstance(outs, dict):
            try:
                mode_raw = str(outs.get('FlagDelivery(mode)') or '').strip().lower()
                if mode_raw in ('file', 'embedded', 'none', 'unknown'):
                    flag_delivery_mode = mode_raw
            except Exception:
                pass
            try:
                ff_raw = str(outs.get('FlagFile(path)') or '').strip()
                if ff_raw:
                    flag_file_path = _resolve_output_path(ff_raw, run_dir, artifacts_dir)
            except Exception:
                pass
            # Derive scenario tag from label if possible
            st = ''
            try:
                if SCENARIO_LABEL:
                    st = ''.join([c for c in SCENARIO_LABEL if c.isalnum() or c in ('-', '_')])[:40]
            except Exception:
                pass

            for k, v in outs.items():
                if _skip_output_path_check(k, v):
                    continue
                if not _looks_like_path(k, v):
                    continue
                p = _resolve_output_path(str(v), run_dir, artifacts_dir, scenario_tag=st, node_name=node_id)
                if not p:
                    continue
                # normalized key for matching
                k_norm = str(k).strip()
                outputs_resolved[k_norm] = p
                outputs_checked.append(p)
                if not _safe_exists(p):
                    outputs_missing.append(p)

            # Hard rule: flag-node-generators must provide docker-compose.yml/.yaml via File(path).
            try:
                gen_type_l = str(gen_type or '').strip().lower()
                if gen_type_l == 'flag-node-generator':
                    compose_val = str(
                        outs.get('File(path)')
                        or outs.get('file')
                        or outs.get('File')
                        or ''
                    ).strip()
                    if not compose_val:
                        outputs_missing.append('missing required output File(path) for flag-node-generator')
                    else:
                        compose_base = os.path.basename(compose_val).strip().lower()
                        if compose_base not in ('docker-compose.yml', 'docker-compose.yaml'):
                            outputs_missing.append(f'invalid File(path) for flag-node-generator: {compose_val}')
            except Exception:
                pass

        source_dir = artifacts_dir or run_dir
        inject_sources = _inject_files_for_copy_from_detail(a.get('inject_files_detail'), source_dir)
        legacy_tmp_flag_spec = False
        inj = a.get('inject_files') if isinstance(a.get('inject_files'), list) else []
        for raw in inj:
            text_raw = str(raw or '').strip()
            if not text_raw:
                continue
            sep_raw = '->' if '->' in text_raw else '=>' if '=>' in text_raw else ''
            left_raw = text_raw.split(sep_raw, 1)[0].strip() if sep_raw else text_raw
            right_raw = text_raw.split(sep_raw, 1)[1].strip() if sep_raw else ''
            left_base = os.path.basename(left_raw.rstrip('/')) if left_raw else ''
            if left_raw == '/tmp/flag.txt':
                legacy_tmp_flag_spec = True
                break
            if left_base == 'flag.txt' and (not right_raw or right_raw == '/tmp'):
                legacy_tmp_flag_spec = True
                break
        if not inject_sources:
            for raw in inj:
                src_norm = _normalize_inject_spec_for_copy(raw, source_dir)
                if src_norm:
                    inject_sources.append(src_norm)

        # Prefer generation-time resolved inject sources when available.
        # This avoids stale/ambiguous inject_files normalization artifacts.
        try:
            resolved_paths = a.get('resolved_paths') if isinstance(a.get('resolved_paths'), dict) else {}
            resolved_items = resolved_paths.get('inject_sources') if isinstance(resolved_paths, dict) else []
            resolved_inject_sources = []
            if isinstance(resolved_items, list):
                for item in resolved_items:
                    if not isinstance(item, dict):
                        continue
                    src_path = str(item.get('path') or '').strip()
                    if src_path:
                        resolved_inject_sources.append(src_path)
            if resolved_inject_sources:
                inject_sources = resolved_inject_sources
        except Exception:
            pass

        # De-dupe while preserving order.
        try:
            _seen_inject = set()
            _uniq_inject = []
            for _src in inject_sources:
                _key = str(_src or '').strip()
                if not _key or _key in _seen_inject:
                    continue
                _seen_inject.add(_key)
                _uniq_inject.append(_key)
            inject_sources = _uniq_inject
        except Exception:
            pass

        inject_missing = []
        inject_checked = []
        container_dest_paths = []
        for raw in inj:
            txt = str(raw or '').strip()
            if not txt:
                continue
            sep = '->' if '->' in txt else '=>' if '=>' in txt else ''
            if not sep:
                continue
            _left, right = txt.split(sep, 1)
            dst_txt = str(right or '').strip()
            if dst_txt.startswith('/'):
                container_dest_paths.append(dst_txt)

        # De-dupe container destination paths while preserving order.
        seen_container_paths = set()
        uniq_container_paths = []
        for pth in container_dest_paths:
            k = str(pth or '').strip()
            if not k or k in seen_container_paths:
                continue
            seen_container_paths.add(k)
            uniq_container_paths.append(k)
        container_dest_paths = uniq_container_paths

        for src in inject_sources:
            src_txt = str(src or '').strip()
            if not src_txt:
                continue
            if flag_delivery_mode == 'embedded' and os.path.basename(src_txt.rstrip('/')) == 'flag.txt':
                continue
            # Legacy fallback inside containers; not a host-side source path.
            if str(gen_type or '').strip().lower() == 'flag-generator' and src_txt == '/tmp/flag.txt':
                continue
            if str(gen_type or '').strip().lower() == 'flag-generator' and legacy_tmp_flag_spec:
                if os.path.basename(src_txt.rstrip('/')) == 'flag.txt' and '/artifacts/' not in src_txt.replace('\\', '/'):
                    continue
            if (not os.path.isabs(src_txt)) and (not source_dir):
                # Relative inject source cannot be validated without a known base directory.
                continue
            if os.path.isabs(src_txt):
                p = src_txt
            elif source_dir:
                p = os.path.join(source_dir, src_txt.lstrip('/'))
            else:
                p = src_txt
            inject_checked.append(p)
            if not _safe_exists(p):
                inject_missing.append(p)

        if flag_delivery_mode == 'file' and flag_file_path:
            inject_checked.append(flag_file_path)
            if not _safe_exists(flag_file_path):
                inject_missing.append(flag_file_path)

        container_checked = []
        container_missing = []
        container_check_error = ''
        target_container = ''
        try:
            inferred_from_run_dir = ''
            try:
                rd_norm = str(run_dir or '').strip().replace('\\', '/')
                if rd_norm:
                    m = re.search(r'(docker-\d+)(?:/)?$', rd_norm)
                    if m:
                        inferred_from_run_dir = str(m.group(1) or '').strip()
            except Exception:
                inferred_from_run_dir = ''

            if node_name and node_name in docker_names:
                target_container = node_name
            elif inferred_from_run_dir and inferred_from_run_dir in docker_names:
                target_container = inferred_from_run_dir
            elif node_id and node_id in docker_names:
                target_container = node_id
            elif node_id and node_id.isdigit() and f"docker-{node_id}" in docker_names:
                target_container = f"docker-{node_id}"
            if container_dest_paths and not target_container:
                msg = 'container_not_found'
                if docker_err:
                    msg = f"container_not_found ({docker_err})"
                for dst in container_dest_paths:
                    container_missing.append(f"{msg}: {dst}")
            elif target_container:
                for dst in container_dest_paths:
                    container_checked.append(dst)
                    ok, err = _container_path_exists(target_container, dst)
                    if not ok:
                        if err:
                            container_missing.append(f"{dst} ({err})")
                        else:
                            container_missing.append(dst)
        except Exception as exc:
            container_check_error = str(exc)

        items.append({
            'node_id': node_id,
            'node_name': node_name,
            'generator_id': gen_id,
            'generator_name': gen_name,
            'generator_type': gen_type,
            'container_name': target_container,
            'container_check_error': container_check_error,
            'container_checked': container_checked,
            'container_missing': container_missing,
            'flag_delivery_mode': flag_delivery_mode,
            'flag_file_path': flag_file_path,
            'run_dir': run_dir,
            'artifacts_dir': artifacts_dir,
            'outputs_manifest': outputs_manifest,
            'outputs_manifest_exists': bool(manifest_exists),
            'outputs_checked': outputs_checked,
            'outputs_resolved': outputs_resolved,
            'outputs_missing': outputs_missing,
            'inject_checked': inject_checked,
            'inject_missing': inject_missing,
        })

    print(json.dumps({'ok': True, 'items': items}))


if __name__ == '__main__':
    main()
"""
    ).replace('__ASSIGNMENTS_LITERAL__', assignments_literal) \
     .replace('__SCENARIO_LABEL_LITERAL__', scenario_label_literal) \
     .replace('__SUDO_PASSWORD_LITERAL__', sudo_password_literal)


def _remote_vuln_assignments_script(assignments_path: str = '/tmp/vulns/compose_assignments.json') -> str:
    assignments_literal = json.dumps(str(assignments_path))
    return (
        r"""
import json, os

ASSIGNMENTS_PATH = __ASSIGNMENTS_PATH_LITERAL__

def main():
    if not ASSIGNMENTS_PATH or not os.path.exists(ASSIGNMENTS_PATH):
        print(json.dumps({'ok': False, 'error': 'missing compose_assignments', 'nodes': []}))
        return
    try:
        with open(ASSIGNMENTS_PATH, 'r', encoding='utf-8') as f:
            payload = json.load(f)
    except Exception as exc:
        print(json.dumps({'ok': False, 'error': f'read_failed: {exc}', 'nodes': []}))
        return
    assignments = payload.get('assignments') if isinstance(payload, dict) else None
    nodes = []
    if isinstance(assignments, dict):
        nodes = [str(k) for k in assignments.keys() if str(k).strip()]
    print(json.dumps({'ok': True, 'nodes': nodes}))

if __name__ == '__main__':
    main()
"""
    ).replace('__ASSIGNMENTS_PATH_LITERAL__', assignments_literal)


def _validate_session_nodes_and_injects(
    *,
    scenario_xml_path: str | None,
    session_xml_path: str | None,
    core_cfg: Dict[str, Any] | None,
    preview_plan_path: str | None = None,
    scenario_label: str | None = None,
    flow_enabled: bool = True,
) -> Dict[str, Any]:
    flow_enabled = bool(flow_enabled)
    summary: Dict[str, Any] = {
        'ok': True,
        'missing_nodes': [],
        'extra_nodes': [],
        'missing_node_ids': [],
        'extra_node_ids': [],
        'expected_nodes': [],
        'actual_nodes': [],
        'actual_nodes_detail': [],
        'docker_nodes': [],
        'expected_docker_nodes': [],
        'missing_docker_nodes': [],
        'extra_docker_nodes': [],
        'expected_vuln_nodes': [],
        'missing_vuln_nodes': [],
        'actual_vuln_nodes': [],
        'docker_missing': [],
        'docker_not_running': [],
        'docker_not_running_details': [],
        'docker_start_pending': [],
        'docker_running': [],
        'injects_missing': [],
        'injects_detail': [],
        'inject_dirs_expected': [],
        'inject_nodes_expected': [],
        'inject_files_expected_by_node': {},
        'generator_outputs_missing': [],
        'generator_injects_missing': [],
        'generator_validation_detail': [],
        'flow_live_paths_checked': 0,
        'flow_live_paths_missing_count': 0,
        'flow_live_paths_missing': [],
        'flow_live_paths_detail': [],
    }

    def _is_mount_root_path(path_value: Any) -> bool:
        try:
            p = str(path_value or '').strip().replace('\\', '/')
        except Exception:
            return False
        if not p:
            return False
        return p in {'/exports', '/outputs', '/inputs'}

    def _looks_like_optional_flag_path(path_value: Any) -> bool:
        try:
            p = str(path_value or '').strip().replace('\\', '/').rstrip('/')
        except Exception:
            return False
        if not p:
            return False
        return p.endswith('/flag.txt')

    def _sanitize_expected_inject_paths(paths: Any) -> List[str]:
        if not isinstance(paths, list):
            return []
        out: List[str] = []
        seen: set[str] = set()
        for raw in paths:
            p = str(raw or '').strip()
            if not p:
                continue
            if _is_mount_root_path(p):
                continue
            if _looks_like_optional_flag_path(p):
                continue
            if p in seen:
                continue
            seen.add(p)
            out.append(p)
        return out

    def _inject_dirs_from_expected_by_node(expected_by_node: Any) -> List[str]:
        if not isinstance(expected_by_node, dict):
            return []
        seen_dirs: set[str] = set()
        out_dirs: List[str] = []
        for paths in expected_by_node.values():
            if not isinstance(paths, list):
                continue
            for raw_path in paths:
                p = str(raw_path or '').strip()
                if not p or p == '/':
                    continue
                if p.endswith('/'):
                    p = p.rstrip('/') or '/'
                if not p or p == '/':
                    continue
                try:
                    d = os.path.dirname(p)
                except Exception:
                    d = ''
                if d == '/' and p.startswith('/'):
                    d = p
                d = str(d or p).strip()
                if not d or d == '/' or d in seen_dirs:
                    continue
                seen_dirs.add(d)
                out_dirs.append(d)
        return out_dirs

    def _is_local_host_path(path_value: Any) -> bool:
        try:
            p = str(path_value or '').strip().replace('\\', '/')
        except Exception:
            return False
        if not p:
            return False
        return p.startswith('/Users/') or p.startswith('/home/')

    def _keep_generator_output_missing(raw_value: Any) -> bool:
        text = str(raw_value or '').strip()
        if not text:
            return False
        low = text.lower()
        if low.startswith('missing manifest:'):
            try:
                manifest_path = text.split(':', 1)[1].strip()
            except Exception:
                manifest_path = ''
            if not manifest_path:
                return False
            if _is_local_host_path(manifest_path):
                return False
        return True

    def _keep_generator_inject_missing(raw_value: Any) -> bool:
        text = str(raw_value or '').strip()
        if not text:
            return False
        if _is_local_host_path(text):
            return False
        if (not text.startswith('/')) and ('/' not in text):
            return False
        return True

    def _docker_probe_mentions_restarting(values: Any) -> bool:
        if not isinstance(values, list):
            return False
        for value in values:
            text = str(value or '').lower()
            if ' is restarting' in text or 'container is restarting' in text:
                return True
        return False

    def _collect_flow_live_path_diagnostics() -> None:
        if not flow_enabled:
            return
        try:
            flow_state = _flow_state_from_xml_path(scenario_xml_path or '', scenario_label)
            assignments = flow_state.get('flag_assignments') if isinstance(flow_state, dict) else None
            if not isinstance(assignments, list) or not assignments:
                return
            details: List[Dict[str, Any]] = []
            missing_lines: List[str] = []
            checked = 0
            missing_count = 0

            def _record(
                *,
                node_id: str,
                generator_id: str,
                path_type: str,
                path_value: str,
                is_remote: bool,
            ) -> None:
                nonlocal checked, missing_count
                p = str(path_value or '').strip()
                if not p:
                    return
                checked += 1
                exists_local = bool(os.path.exists(p))
                missing_local = (not is_remote) and (not exists_local)
                if missing_local:
                    missing_count += 1
                details.append({
                    'node_id': node_id,
                    'generator_id': generator_id,
                    'path_type': path_type,
                    'path': p,
                    'exists_local': bool(exists_local),
                    'is_remote': bool(is_remote),
                    'missing_local': bool(missing_local),
                })
                if missing_local:
                    label = f"{node_id or generator_id or 'assignment'} {path_type}: {p}"
                    missing_lines.append(label)

            for fa in assignments:
                if not isinstance(fa, dict):
                    continue
                node_id = str(fa.get('node_id') or '').strip()
                generator_id = str(fa.get('id') or fa.get('generator_id') or '').strip()
                resolved = fa.get('resolved_paths') if isinstance(fa.get('resolved_paths'), dict) else None
                live = fa.get('live_paths') if isinstance(fa.get('live_paths'), dict) else None
                paths = resolved if isinstance(resolved, dict) else live
                if not isinstance(paths, dict):
                    continue

                def _is_remote_path(path_value: str, explicit_flag: Any) -> bool:
                    if explicit_flag is True:
                        return True
                    if explicit_flag is False:
                        return False
                    p = str(path_value or '').strip().replace('\\', '/')
                    if not p:
                        return False
                    for pref in ('/tmp/vulns', '/exports', '/outputs', '/inputs'):
                        if p == pref or p.startswith(pref + '/'):
                            return True
                    return False

                for key in ('artifacts_dir', 'inject_source_dir'):
                    info = paths.get(key)
                    if not isinstance(info, dict):
                        continue
                    p_val = str(info.get('path') or '').strip()
                    _record(
                        node_id=node_id,
                        generator_id=generator_id,
                        path_type=key,
                        path_value=p_val,
                        is_remote=_is_remote_path(p_val, info.get('is_remote')),
                    )

                inject_sources = paths.get('inject_sources') if isinstance(paths.get('inject_sources'), list) else []
                for src in inject_sources:
                    if not isinstance(src, dict):
                        continue
                    p_val = str(src.get('path') or '').strip()
                    _record(
                        node_id=node_id,
                        generator_id=generator_id,
                        path_type='inject_source',
                        path_value=p_val,
                        is_remote=_is_remote_path(p_val, src.get('is_remote')),
                    )

            summary['flow_live_paths_checked'] = int(checked)
            summary['flow_live_paths_missing_count'] = int(missing_count)
            summary['flow_live_paths_detail'] = details
            summary['flow_live_paths_missing'] = missing_lines
        except Exception:
            pass

    _collect_flow_live_path_diagnostics()
    if not scenario_xml_path or not session_xml_path:
        summary['ok'] = False
        summary['error'] = 'missing scenario or session xml'
        if scenario_xml_path and os.path.exists(scenario_xml_path):
            try:
                expected = _expected_from_plan_preview(scenario_xml_path, scenario_label)
                expected_ids = sorted(expected.keys())
                expected_names: List[str] = []
                for nid in expected_ids:
                    exp = expected.get(nid) or {}
                    nm = str(exp.get('name') or '').strip()
                    expected_names.append(nm or f"node-{nid}")
                summary['expected_nodes'] = expected_names
                summary['missing_node_ids'] = expected_ids
                summary['missing_nodes'] = list(expected_names)
            except Exception:
                pass
            try:
                expected_docker_nodes, expected_vuln_nodes = _extract_expected_docker_and_vuln_nodes_from_plan_xml(
                    scenario_xml_path,
                    scenario_label,
                )
                summary['expected_docker_nodes'] = expected_docker_nodes
                summary['missing_docker_nodes'] = list(expected_docker_nodes)
                summary['expected_vuln_nodes'] = expected_vuln_nodes
                summary['missing_vuln_nodes'] = list(expected_vuln_nodes)
            except Exception:
                pass
            try:
                flow_inject_specs = _extract_inject_specs_from_flow_state(scenario_xml_path, scenario_label)
                inject_expected_by_node = _extract_inject_expected_by_node(scenario_xml_path, scenario_label)
                if flow_enabled:
                    if flow_inject_specs:
                        flow_payload = {'inject_files': flow_inject_specs}
                        expected_inject_dirs = _extract_inject_dirs_from_payload(flow_payload)
                        expected_inject_files = _extract_inject_files_from_payload(flow_payload)
                    else:
                        expected_inject_dirs = _extract_inject_dirs_from_plan_xml(scenario_xml_path, scenario_label)
                        expected_inject_files = _extract_inject_files_from_plan_xml(scenario_xml_path, scenario_label)
                    if isinstance(inject_expected_by_node, dict) and inject_expected_by_node:
                        flat_expected: List[str] = []
                        seen_expected: set[str] = set()
                        for paths in inject_expected_by_node.values():
                            if not isinstance(paths, list):
                                continue
                            for path in paths:
                                p = str(path or '').strip()
                                if not p or p in seen_expected:
                                    continue
                                seen_expected.add(p)
                                flat_expected.append(p)
                        if flat_expected:
                            expected_inject_files = flat_expected
                            expected_inject_dirs = _inject_dirs_from_expected_by_node(inject_expected_by_node) or expected_inject_dirs
                else:
                    inject_expected_by_node = {}
                    expected_inject_dirs = []
                    expected_inject_files = []
                summary['inject_dirs_expected'] = expected_inject_dirs
                summary['inject_files_expected'] = expected_inject_files
                summary['inject_files_expected_by_node'] = inject_expected_by_node
                if isinstance(inject_expected_by_node, dict) and inject_expected_by_node:
                    summary['inject_nodes_expected'] = sorted([str(k) for k in inject_expected_by_node.keys() if str(k).strip()])
            except Exception:
                pass
        return summary

    try:
        expected = _expected_from_plan_preview(scenario_xml_path, scenario_label)
        actual = _parse_session_xml_for_compare(session_xml_path)
        expected_ids = set(expected.keys())
        actual_ids = set(actual.keys())
        missing_ids = sorted(expected_ids - actual_ids)
        extra_ids = sorted(actual_ids - expected_ids)
        summary['missing_node_ids'] = missing_ids
        summary['extra_node_ids'] = extra_ids
        missing_names = []
        for nid in missing_ids:
            exp = expected.get(nid) or {}
            nm = (exp.get('name') or '').strip()
            missing_names.append(nm or f"node-{nid}")
        extra_names = []
        for nid in extra_ids:
            act = actual.get(nid) or {}
            nm = (act.get('name') or '').strip()
            extra_names.append(nm or f"node-{nid}")
        summary['missing_nodes'] = missing_names
        summary['extra_nodes'] = extra_names
        try:
            expected_names = []
            for nid in sorted(expected_ids):
                exp = expected.get(nid) or {}
                nm = (exp.get('name') or '').strip()
                expected_names.append(nm or f"node-{nid}")
            actual_names = []
            actual_detail = []
            for nid in sorted(actual_ids):
                act = actual.get(nid) or {}
                nm = (act.get('name') or '').strip()
                ntype = (act.get('type') or '').strip()
                label = nm or f"node-{nid}"
                actual_names.append(label)
                if ntype:
                    actual_detail.append(f"{label} ({ntype})")
                else:
                    actual_detail.append(f"{label} (unknown)")
            summary['expected_nodes'] = expected_names
            summary['actual_nodes'] = actual_names
            summary['actual_nodes_detail'] = actual_detail
        except Exception:
            pass
    except Exception:
        pass

    if flow_enabled:
        flow_inject_specs = _extract_inject_specs_from_flow_state(scenario_xml_path, scenario_label)
        inject_expected_by_node = _extract_inject_expected_by_node(scenario_xml_path, scenario_label)
        if isinstance(inject_expected_by_node, dict) and inject_expected_by_node:
            cleaned_expected_by_node: Dict[str, List[str]] = {}
            for node_name, paths in inject_expected_by_node.items():
                clean_paths = _sanitize_expected_inject_paths(paths)
                if clean_paths:
                    cleaned_expected_by_node[str(node_name)] = clean_paths
            inject_expected_by_node = cleaned_expected_by_node
        if flow_inject_specs:
            flow_payload = {'inject_files': flow_inject_specs}
            expected_inject_dirs = _extract_inject_dirs_from_payload(flow_payload)
            expected_inject_files = _extract_inject_files_from_payload(flow_payload)
        else:
            expected_inject_dirs = _extract_inject_dirs_from_plan_xml(scenario_xml_path, scenario_label)
            expected_inject_files = _extract_inject_files_from_plan_xml(scenario_xml_path, scenario_label)
        expected_inject_dirs = [
            str(d) for d in (expected_inject_dirs or [])
            if str(d or '').strip() and not _is_mount_root_path(d)
        ]
        expected_inject_files = _sanitize_expected_inject_paths(expected_inject_files)
        if isinstance(inject_expected_by_node, dict) and inject_expected_by_node:
            flat_expected: List[str] = []
            seen_expected: set[str] = set()
            for paths in inject_expected_by_node.values():
                if not isinstance(paths, list):
                    continue
                for path in paths:
                    p = str(path or '').strip()
                    if not p or p in seen_expected:
                        continue
                    seen_expected.add(p)
                    flat_expected.append(p)
            if flat_expected:
                expected_inject_files = flat_expected
                expected_inject_dirs = _inject_dirs_from_expected_by_node(inject_expected_by_node) or expected_inject_dirs
    else:
        flow_inject_specs = []
        inject_expected_by_node = {}
        expected_inject_dirs = []
        expected_inject_files = []
    if preview_plan_path and not flow_inject_specs:
        try:
            payload = _load_plan_preview_payload_from_path(preview_plan_path, scenario_label)
            extra_dirs = _extract_inject_dirs_from_payload(payload) if isinstance(payload, dict) else []
            if extra_dirs:
                seen_dirs = set(expected_inject_dirs)
                for d in extra_dirs:
                    if d in seen_dirs:
                        continue
                    seen_dirs.add(d)
                    expected_inject_dirs.append(d)
        except Exception:
            pass
        try:
            payload = _load_plan_preview_payload_from_path(preview_plan_path, scenario_label)
            extra_files = _extract_inject_files_from_payload(payload) if isinstance(payload, dict) else []
            if extra_files:
                seen_files = set(expected_inject_files)
                for f in extra_files:
                    if f in seen_files:
                        continue
                    seen_files.add(f)
                    expected_inject_files.append(f)
        except Exception:
            pass
    summary['inject_dirs_expected'] = expected_inject_dirs
    summary['inject_files_expected'] = expected_inject_files
    summary['inject_files_expected_by_node'] = inject_expected_by_node

    expected_docker_nodes, expected_vuln_nodes = _extract_expected_docker_and_vuln_nodes_from_plan_xml(
        scenario_xml_path,
        scenario_label,
    )
    summary['expected_docker_nodes'] = expected_docker_nodes
    summary['expected_vuln_nodes'] = expected_vuln_nodes

    docker_nodes = _session_docker_nodes_from_xml(session_xml_path)
    summary['docker_nodes'] = docker_nodes
    inject_node_ids = _extract_inject_node_ids_from_flow_state(scenario_xml_path, scenario_label) if flow_enabled else set()
    inject_node_names: List[str] = []
    container_expected_missing_nodes: set[str] = set()
    if inject_node_ids:
        try:
            expected = _expected_from_plan_preview(scenario_xml_path, scenario_label)
            for nid in sorted(inject_node_ids):
                exp = expected.get(nid) or {}
                nm = str(exp.get('name') or '').strip()
                if nm:
                    inject_node_names.append(nm)
        except Exception:
            inject_node_names = []
    summary['inject_nodes_expected'] = inject_node_names
    actual_vuln_nodes: List[str] = []
    if docker_nodes and isinstance(core_cfg, dict):
        try:
            payload = _run_remote_python_json(
                core_cfg,
                _remote_vuln_assignments_script(),
                logger=app.logger,
                label='docker.compose.assignments',
                timeout=45.0,
            )
            nodes_raw = payload.get('nodes') if isinstance(payload, dict) else None
            if isinstance(nodes_raw, list):
                node_set = {str(n).strip() for n in nodes_raw if str(n).strip()}
                if node_set:
                    actual_vuln_nodes = [n for n in docker_nodes if n in node_set]
                    summary['actual_vuln_nodes'] = actual_vuln_nodes
        except Exception:
            pass
    if expected_docker_nodes:
        exp_set = set(expected_docker_nodes)
        act_set = set(docker_nodes)
        summary['missing_docker_nodes'] = sorted(exp_set - act_set)
        summary['extra_docker_nodes'] = sorted(act_set - exp_set)
    if expected_vuln_nodes:
        exp_vuln = set(expected_vuln_nodes)
        if actual_vuln_nodes:
            act_set = set(actual_vuln_nodes)
        else:
            act_set = set(docker_nodes)
            summary['actual_vuln_nodes'] = sorted(exp_vuln & act_set)
        summary['missing_vuln_nodes'] = sorted(exp_vuln - act_set)
    if docker_nodes and isinstance(core_cfg, dict):
        containers_for_injects = docker_nodes
        if inject_node_names:
            containers_for_injects = [n for n in docker_nodes if n in set(inject_node_names)]
        def _is_transient_missing_inspect_error(text: Any) -> bool:
            try:
                s = str(text or '').strip().lower()
            except Exception:
                return False
            if not s:
                return False
            return (
                ('no such container' in s)
                or ('no such object' in s)
                or ('not found' in s and 'docker' in s)
            )
        def _safe_inject_dir(path: str) -> str | None:
            p = str(path or '').strip()
            if not p or p == '/':
                return None
            if p.endswith('/'):
                p = p.rstrip('/') or '/'
            if not p or p == '/':
                return None
            try:
                d = os.path.dirname(p)
            except Exception:
                d = ''
            if d == '/' and p.startswith('/'):
                # Single-segment absolute path like /tmp should be its own dir.
                return p
            return d or p

        def _second_chance_container_state(name: str) -> Dict[str, Any] | None:
            try:
                payload2 = _run_remote_python_json(
                    core_cfg,
                    _remote_docker_injects_status_script(
                        containers=[name],
                        sudo_password=core_cfg.get('ssh_password'),
                        inject_dirs=inject_dirs,
                        expected_by_node={name: inject_expected_by_node.get(name) or []},
                        max_find=50,
                    ),
                    logger=app.logger,
                    label='docker.exec.injects_status.recheck',
                    timeout=45.0,
                )
                items2 = payload2.get('items') if isinstance(payload2, dict) else None
                if isinstance(items2, list) and items2 and isinstance(items2[0], dict):
                    return items2[0]
            except Exception:
                return None
            return None

        if inject_expected_by_node:
            inject_dirs = sorted({d for paths in inject_expected_by_node.values() for p in paths if p.startswith('/') for d in (_safe_inject_dir(p),) if d})
        else:
            inject_dirs = expected_inject_dirs if (expected_inject_dirs and not flow_enabled) else None
        try:
            payload = _run_remote_python_json(
                core_cfg,
                _remote_docker_injects_status_script(
                    containers=containers_for_injects,
                    sudo_password=core_cfg.get('ssh_password'),
                    inject_dirs=inject_dirs,
                    expected_by_node=inject_expected_by_node if isinstance(inject_expected_by_node, dict) else {},
                ),
                logger=app.logger,
                label='docker.exec.injects_status',
                timeout=120.0,
            )
            items = payload.get('items') if isinstance(payload, dict) else None
            if isinstance(items, list):
                for it in items:
                    if not isinstance(it, dict):
                        continue
                    name = str(it.get('container') or '').strip()
                    if not name:
                        continue
                    probe_logs = it.get('debug_logs') if isinstance(it.get('debug_logs'), list) else []
                    if _docker_probe_mentions_restarting(probe_logs):
                        it = dict(it)
                        it['running'] = False
                        it['state_status'] = 'restarting'
                    if not it.get('exists'):
                        inspect_err = str(it.get('inspect_error') or '').strip()
                        if _is_transient_missing_inspect_error(inspect_err):
                            summary['docker_start_pending'].append(name)
                            if inspect_err:
                                summary['injects_detail'].append(f"{name}: startup pending (inspect transient: {inspect_err})")
                            else:
                                summary['injects_detail'].append(f"{name}: startup pending (inspect transient)")
                        else:
                            summary['docker_missing'].append(name)
                            if inspect_err:
                                summary['injects_detail'].append(f"{name}: missing ({inspect_err})")
                            else:
                                summary['injects_detail'].append(f"{name}: missing")
                        continue
                    if not it.get('running'):
                        status_text = str(it.get('state_status') or '').strip()
                        exit_code = it.get('state_exit_code')
                        try:
                            exit_code_int = int(exit_code) if exit_code is not None and str(exit_code).strip() != '' else None
                        except Exception:
                            exit_code_int = None
                        err_text = str(it.get('state_error') or '').strip()
                        status_norm = status_text.lower()
                        startup_pending = bool(status_norm in {'created', 'restarting'} and (exit_code_int in (None, 0)) and not err_text)
                        if not startup_pending:
                            it2 = _second_chance_container_state(name)
                            if isinstance(it2, dict):
                                if bool(it2.get('running')):
                                    summary['docker_running'].append(name)
                                    summary['injects_detail'].append(f"{name}: startup recovered after recheck")
                                    continue
                                status2 = str(it2.get('state_status') or '').strip().lower()
                                exit2 = it2.get('state_exit_code')
                                err2 = str(it2.get('state_error') or '').strip()
                                try:
                                    exit2_int = int(exit2) if exit2 is not None and str(exit2).strip() != '' else None
                                except Exception:
                                    exit2_int = None
                                if status2 in {'created', 'restarting'}:
                                    startup_pending = True
                                elif status2 == 'exited' and (exit2_int in (0, 1, 137, 143)) and (not err2):
                                    startup_pending = True
                        if startup_pending:
                            summary['docker_start_pending'].append(name)
                            summary['injects_detail'].append(f"{name}: startup pending ({status_norm or 'created'})")
                        else:
                            summary['docker_not_running'].append(name)
                            nr_detail: Dict[str, Any] = {'container': name}
                            if status_text:
                                nr_detail['status'] = status_text
                            if exit_code is not None:
                                nr_detail['exit_code'] = exit_code
                            if err_text:
                                nr_detail['error'] = err_text
                            summary['docker_not_running_details'].append(nr_detail)
                            reason_bits: List[str] = []
                            if status_text:
                                reason_bits.append(status_text)
                            if exit_code is not None:
                                reason_bits.append(f"exit={exit_code}")
                            if err_text:
                                reason_bits.append(err_text)
                            reason = f" ({'; '.join(reason_bits)})" if reason_bits else ''
                            summary['injects_detail'].append(f"{name}: not running{reason}")
                    else:
                        summary['docker_running'].append(name)
                    try:
                        is_running = bool(it.get('running'))
                        samples = it.get('inject_samples') if isinstance(it.get('inject_samples'), list) else []
                        inject_count = int(it.get('inject_count') or 0)
                        inject_dirs_found = it.get('inject_dirs_found') if isinstance(it.get('inject_dirs_found'), list) else []
                        expected_missing = it.get('expected_missing') if isinstance(it.get('expected_missing'), list) else []
                        debug_logs = it.get('debug_logs') if isinstance(it.get('debug_logs'), list) else []
                        expected_paths = []
                        if inject_expected_by_node:
                            expected_paths = inject_expected_by_node.get(name) or []
                        if expected_missing:
                            container_expected_missing_nodes.add(name)
                        if is_running and (expected_inject_dirs or inject_count > 0 or samples):
                            if inject_dirs_found:
                                dirs_text = ', '.join(str(d) for d in inject_dirs_found)
                            elif expected_inject_dirs:
                                dirs_text = ', '.join(str(d) for d in expected_inject_dirs)
                            else:
                                dirs_text = ''
                            detail = f"{name}: {inject_count} file(s)"
                            if dirs_text:
                                detail += f" in {dirs_text}"
                            if samples:
                                detail += f" (e.g., {', '.join(str(s) for s in samples)})"
                            if expected_paths:
                                exp_preview = ', '.join(str(p) for p in expected_paths[:3])
                                more = f" (+{len(expected_paths)-3} more)" if len(expected_paths) > 3 else ''
                                detail += f"; expected {exp_preview}{more}"
                            if expected_missing:
                                missing_preview = ', '.join(str(p) for p in expected_missing[:3])
                                more_missing = f" (+{len(expected_missing)-3} more)" if len(expected_missing) > 3 else ''
                                detail += f"; missing expected {missing_preview}{more_missing}"
                            if debug_logs:
                                dbg = ' | '.join(str(x) for x in debug_logs[:2])
                                detail += f"; debug: {dbg}"
                            summary['injects_detail'].append(detail)
                    except Exception:
                        pass
                    expected_for_node = expected_paths if isinstance(expected_paths, list) else []
                    should_require_injects = bool(expected_for_node) if inject_expected_by_node else bool(inject_dirs)
                    exact_expected_missing = it.get('expected_missing') if isinstance(it.get('expected_missing'), list) else []
                    if should_require_injects and bool(it.get('running')) and (int(it.get('inject_count') or 0) <= 0 or bool(exact_expected_missing)):
                        if name not in summary['injects_missing']:
                            summary['injects_missing'].append(name)
        except Exception as exc:
            summary['ok'] = False
            summary['error'] = f'failed docker injects validation: {exc}'

    # Validate Flow generator outputs/inject sources on the CORE VM (remote).
    gen_validation_error: str | None = None
    assignments_list: List[Dict[str, Any]] | None = None
    try:
        flow_state = _flow_state_from_xml_path(scenario_xml_path or '', scenario_label)
        assignments = flow_state.get('flag_assignments') if isinstance(flow_state, dict) else None
        if isinstance(assignments, list) and assignments:
            assignments_list = [a for a in assignments if isinstance(a, dict)]
        if isinstance(assignments_list, list) and assignments_list and isinstance(core_cfg, dict):
            assignment_node_names: Dict[str, str] = {}
            try:
                for node in _flow_state_chain_nodes(flow_state):
                    if not isinstance(node, dict):
                        continue
                    node_id = str(node.get('id') or node.get('node_id') or '').strip()
                    node_name = str(node.get('name') or '').strip()
                    if node_id and node_name and node_id not in assignment_node_names:
                        assignment_node_names[node_id] = node_name
            except Exception:
                assignment_node_names = {}
            check_items: List[Dict[str, Any]] = []
            for fa in assignments_list:
                node_id = str(fa.get('node_id') or '').strip()
                node_name = str(fa.get('node_name') or '').strip() or assignment_node_names.get(node_id) or ''
                check_items.append({
                    'node_id': node_id,
                    'node_name': node_name,
                    'generator_id': fa.get('id') or fa.get('generator_id'),
                    'generator_name': fa.get('name'),
                    'generator_type': fa.get('type') or fa.get('generator_type'),
                    'run_dir': fa.get('run_dir') or fa.get('artifacts_dir'),
                    'artifacts_dir': fa.get('artifacts_dir'),
                    'inject_source_dir': fa.get('inject_source_dir'),
                    'outputs_manifest': fa.get('outputs_manifest'),
                    'inject_files_detail': fa.get('inject_files_detail'),
                    'inject_files': fa.get('inject_files'),
                    'resolved_paths': fa.get('resolved_paths'),
                })
            try:
                payload = _run_remote_python_json(
                    core_cfg,
                    _remote_flow_artifacts_validation_script(
                        check_items,
                        scenario_label=scenario_label,
                        sudo_password=core_cfg.get('ssh_password'),
                    ),
                    logger=app.logger,
                    label='flow.artifacts.validate',
                    timeout=60.0,
                )
                items = payload.get('items') if isinstance(payload, dict) else None
                if isinstance(items, list):
                    for it in items:
                        if not isinstance(it, dict):
                            continue
                        node_id = str(it.get('node_id') or '').strip()
                        gen_id = str(it.get('generator_id') or '').strip()
                        miss_out_raw = it.get('outputs_missing') if isinstance(it.get('outputs_missing'), list) else []
                        miss_inj_raw = it.get('inject_missing') if isinstance(it.get('inject_missing'), list) else []
                        miss_out = [p for p in miss_out_raw if _keep_generator_output_missing(p)]
                        miss_inj = [p for p in miss_inj_raw if _keep_generator_inject_missing(p)]
                        if miss_out:
                            for p in miss_out:
                                summary['generator_outputs_missing'].append(f"{node_id or gen_id}: {p}")
                        if miss_inj:
                            for p in miss_inj:
                                summary['generator_injects_missing'].append(f"{node_id or gen_id}: {p}")
                        it_clean = dict(it)
                        it_clean['outputs_missing'] = miss_out
                        it_clean['inject_missing'] = miss_inj
                        summary['generator_validation_detail'].append(it_clean)
                else:
                    gen_validation_error = 'no generator validation items returned'
            except Exception as exc:
                gen_validation_error = f"generator validation failed: {exc}"
        elif isinstance(assignments_list, list) and assignments_list and not isinstance(core_cfg, dict):
            gen_validation_error = 'generator validation skipped (no core config)'
    except Exception as exc:
        gen_validation_error = f"generator validation exception: {exc}"

    def _looks_like_path_local(val: Any) -> bool:
        try:
            s = str(val or '').strip()
        except Exception:
            return False
        if not s:
            return False
        return '/' in s or s.startswith('artifacts/') or s.startswith('flow_artifacts/')

    def _resolve_output_path_local(val: str, run_dir: str, artifacts_dir: str) -> str:
        v = str(val or '').strip()
        if not v:
            return ''
        if os.path.isabs(v):
            return v
        rel = v.lstrip('/')
        candidates: List[str] = []
        if artifacts_dir:
            if v.startswith('artifacts/'):
                candidates.append(os.path.join(artifacts_dir, v.split('artifacts/', 1)[1].lstrip('/')))
            else:
                candidates.append(os.path.join(artifacts_dir, rel))
        if run_dir:
            candidates.append(os.path.join(run_dir, rel))
            if not v.startswith('artifacts/'):
                candidates.append(os.path.join(run_dir, 'artifacts', rel))
                candidates.append(os.path.join(run_dir, 'outputs', rel))
                candidates.append(os.path.join(run_dir, 'outputs', 'artifacts', rel))

        seen: set[str] = set()
        uniq_candidates: List[str] = []
        for c in candidates:
            if not c or c in seen:
                continue
            seen.add(c)
            uniq_candidates.append(c)

        for c in uniq_candidates:
            if os.path.exists(c):
                return c
        if uniq_candidates:
            return uniq_candidates[0]
        return v

    def _normalize_inject_source_local(raw: str, run_dir: str, artifacts_dir: str) -> str:
        text = str(raw or '').strip()
        if not text:
            return ''
        for sep in ('->', '=>'):
            if sep in text:
                text = text.split(sep, 1)[0].strip()
                break
        if not text:
            return ''
        if os.path.isabs(text):
            for marker in ('/artifacts/', '/flow_artifacts/'):
                if marker in text:
                    rel = text.split(marker, 1)[1].lstrip('/')
                    base = artifacts_dir or run_dir
                    return os.path.join(base, rel) if base else text
            return text
        if text.startswith('artifacts/'):
            base = artifacts_dir or run_dir
            return os.path.join(base, text.split('artifacts/', 1)[1].lstrip('/')) if base else text
        base = artifacts_dir or run_dir
        return os.path.join(base, text.lstrip('/')) if base else text

    if flow_enabled and isinstance(assignments_list, list) and assignments_list and not summary['generator_validation_detail']:
        for fa in assignments_list:
            run_dir = str(fa.get('run_dir') or fa.get('artifacts_dir') or '')
            artifacts_dir = str(fa.get('inject_source_dir') or fa.get('artifacts_dir') or '')
            outputs_checked: List[str] = []
            inject_checked: List[str] = []
            flag_delivery_mode = 'unknown'
            flag_file_path = ''
            try:
                resolved_detail = fa.get('resolved_outputs_detail') if isinstance(fa.get('resolved_outputs_detail'), list) else []
                for item in resolved_detail:
                    if not isinstance(item, dict):
                        continue
                    val = item.get('resolved') or item.get('path')
                    if _looks_like_path_local(val):
                        p = _resolve_output_path_local(str(val), run_dir, artifacts_dir)
                        if p:
                            outputs_checked.append(p)
            except Exception:
                pass
            try:
                resolved_outputs = fa.get('resolved_outputs') if isinstance(fa.get('resolved_outputs'), dict) else None
                if isinstance(resolved_outputs, dict):
                    mode_raw = str(resolved_outputs.get('FlagDelivery(mode)') or '').strip().lower()
                    if mode_raw in {'file', 'embedded', 'none', 'unknown'}:
                        flag_delivery_mode = mode_raw
                    ff_raw = str(resolved_outputs.get('FlagFile(path)') or '').strip()
                    if ff_raw:
                        ff_resolved = _resolve_output_path_local(ff_raw, run_dir, artifacts_dir)
                        flag_file_path = ff_resolved or ff_raw
                    for v in resolved_outputs.values():
                        if _looks_like_path_local(v):
                            p = _resolve_output_path_local(str(v), run_dir, artifacts_dir)
                            if p:
                                outputs_checked.append(p)
            except Exception:
                pass
            try:
                inject_detail = fa.get('inject_files_detail') if isinstance(fa.get('inject_files_detail'), list) else []
                for item in inject_detail:
                    if not isinstance(item, dict):
                        continue
                    src = item.get('resolved') or item.get('path')
                    p = _normalize_inject_source_local(str(src), run_dir, artifacts_dir)
                    if p:
                        inject_checked.append(p)
            except Exception:
                pass
            try:
                inject_files = fa.get('inject_files') if isinstance(fa.get('inject_files'), list) else []
                for raw in inject_files:
                    p = _normalize_inject_source_local(str(raw), run_dir, artifacts_dir)
                    if p:
                        inject_checked.append(p)
            except Exception:
                pass
            if flag_delivery_mode == 'embedded':
                inject_checked = [p for p in inject_checked if os.path.basename(str(p).rstrip('/')) != 'flag.txt']
            if flag_delivery_mode == 'file' and flag_file_path:
                inject_checked.append(flag_file_path)
            summary['generator_validation_detail'].append({
                'node_id': fa.get('node_id'),
                'generator_id': fa.get('id') or fa.get('generator_id'),
                'generator_name': fa.get('name'),
                'generator_type': fa.get('type') or fa.get('generator_type'),
                'flag_delivery_mode': flag_delivery_mode,
                'flag_file_path': flag_file_path,
                'run_dir': run_dir,
                'artifacts_dir': artifacts_dir,
                'outputs_manifest': fa.get('outputs_manifest'),
                'outputs_checked': sorted(set(outputs_checked)),
                'outputs_missing': [],
                'inject_checked': sorted(set(inject_checked)),
                'inject_missing': [],
                'validation_error': gen_validation_error,
            })
        if gen_validation_error:
            summary['generator_outputs_missing'].append(f"generator validation error: {gen_validation_error}")

    # If generator validation for a node is clean, do not fail solely on the
    # generic container-side /flow_injects probe for that same node.
    try:
        clean_inject_nodes: set[str] = set()
        for it in (summary.get('generator_validation_detail') or []):
            if not isinstance(it, dict):
                continue
            inject_missing = it.get('inject_missing') if isinstance(it.get('inject_missing'), list) else []
            outputs_missing = it.get('outputs_missing') if isinstance(it.get('outputs_missing'), list) else []
            if inject_missing or outputs_missing:
                continue
            container_name = str(it.get('container_name') or '').strip()
            node_name = str(it.get('node_name') or '').strip()
            node_id = str(it.get('node_id') or '').strip()
            for cand in (container_name, node_name, node_id):
                c = str(cand or '').strip()
                if c:
                    clean_inject_nodes.add(c)
            if node_id.isdigit():
                clean_inject_nodes.add(f"docker-{node_id}")

        if clean_inject_nodes:
            injects_missing = summary.get('injects_missing') if isinstance(summary.get('injects_missing'), list) else []
            summary['injects_missing'] = [
                n for n in injects_missing
                if str(n or '').strip() not in clean_inject_nodes
                or str(n or '').strip() in container_expected_missing_nodes
            ]
    except Exception:
        pass

    if (
        summary['missing_nodes']
        or summary['docker_missing']
        or summary['docker_not_running']
        or summary['injects_missing']
        or summary['missing_docker_nodes']
        or summary['extra_docker_nodes']
        or summary['missing_vuln_nodes']
        or summary['generator_outputs_missing']
        or summary['generator_injects_missing']
        or int(summary.get('flow_live_paths_missing_count') or 0) > 0
    ):
        summary['ok'] = False
    return summary


def _maybe_copy_flow_artifacts_into_containers(meta: Dict[str, Any] | None, *, stage: str, log_prefix: str = '[remote] ') -> None:
    if not meta:
        return
    if not meta.get('remote'):
        return
    if meta.get('flow_artifacts_copied'):
        return
    if _coerce_bool(meta.get('skip_flow_artifact_container_copy')):
        meta['flow_artifacts_copied'] = True
        return
    cfg = meta.get('core_cfg')
    if not isinstance(cfg, dict):
        return

    try:
        _log_remote_vulns_inventory(meta, stage=f'before_copy.{stage}', log_prefix=log_prefix)
    except Exception:
        pass

    _append_async_run_log_line(meta, f"{log_prefix}=== docker.copy_flow_artifacts({stage}) ===")
    try:
        payload = _run_remote_python_json(
            cfg,
            _remote_copy_flow_artifacts_into_containers_script(cfg.get('ssh_password')),
            logger=app.logger,
            label=f'docker.copy_flow_artifacts({stage})',
            timeout=180.0,
        )
        if isinstance(payload, dict):
            meta['flow_artifact_copy_summary'] = payload
        try:
            if isinstance(payload, dict) and payload.get('error'):
                _append_async_run_log_line(meta, f"{log_prefix}docker.copy_flow_artifacts({stage}) error={payload.get('error')}")
            if isinstance(payload, dict) and 'assignments_count' in payload:
                _append_async_run_log_line(
                    meta,
                    f"{log_prefix}docker.copy_flow_artifacts({stage}) assignments={payload.get('assignments_count')} keys={payload.get('assignments_keys')}",
                )
            if isinstance(payload, dict) and 'candidate_count' in payload:
                _append_async_run_log_line(
                    meta,
                    f"{log_prefix}docker.copy_flow_artifacts({stage}) candidates={payload.get('candidate_count')} keys={payload.get('candidate_keys')}",
                )
        except Exception:
            pass
        items = payload.get('items') if isinstance(payload, dict) else None
        payload_error = str(payload.get('error') or '').strip() if isinstance(payload, dict) else ''
        copied_total = len(items or []) if isinstance(items, list) else 0
        copied_ok = (
            sum(1 for it in (items or []) if isinstance(it, dict) and it.get('ok'))
            if isinstance(items, list)
            else 0
        )

        def _first_copy_failure_detail() -> str:
            def _is_warning_detail(value: str) -> bool:
                text = str(value or '').strip().lower()
                return text.startswith('warning:') or ': warning:' in text

            if not isinstance(items, list):
                return ''
            warning_fallback = ''
            for it in items:
                if not isinstance(it, dict) or it.get('ok'):
                    continue
                direct = str(it.get('error') or '').strip()
                if direct:
                    if _is_warning_detail(direct):
                        warning_fallback = warning_fallback or direct
                    else:
                        return _summarize_for_log(direct)
                errs = it.get('errors') if isinstance(it.get('errors'), list) else []
                for raw in errs:
                    detail = str(raw or '').strip()
                    if not detail:
                        continue
                    if _is_warning_detail(detail):
                        warning_fallback = warning_fallback or detail
                        continue
                    return _summarize_for_log(detail)
                attempts = it.get('copy_attempts') if isinstance(it.get('copy_attempts'), list) else []
                for attempt in reversed(attempts):
                    if not isinstance(attempt, dict) or attempt.get('ok'):
                        continue
                    attempt_errors = attempt.get('errors') if isinstance(attempt.get('errors'), list) else []
                    for raw in attempt_errors:
                        detail = str(raw or '').strip()
                        if not detail:
                            continue
                        if _is_warning_detail(detail):
                            warning_fallback = warning_fallback or detail
                            continue
                        return _summarize_for_log(detail)
                cmd_outs = it.get('command_outputs') if isinstance(it.get('command_outputs'), list) else []
                for entry in reversed(cmd_outs):
                    if not isinstance(entry, dict):
                        continue
                    try:
                        rc = int(entry.get('rc') or 0)
                    except Exception:
                        rc = 0
                    if rc == 0:
                        continue
                    out = str(entry.get('out') or '').strip()
                    dest_path = str(entry.get('dest') or '').strip()
                    copy_dest = str(entry.get('copy_dest') or '').strip()
                    parts = []
                    if dest_path:
                        parts.append(f'dest={dest_path}')
                    if copy_dest and copy_dest != dest_path:
                        parts.append(f'copy_dest={copy_dest}')
                    if out:
                        parts.append(out)
                    if parts:
                        return _summarize_for_log('; '.join(parts))
            return _summarize_for_log(warning_fallback) if warning_fallback else ''

        _append_async_run_log_line(
            meta,
            f"{log_prefix}docker.copy_flow_artifacts({stage}) complete ok={int(copied_ok)} total={int(copied_total)}",
        )
        if isinstance(items, list) and items:
            for it in items[:25]:
                if not isinstance(it, dict):
                    continue
                node = it.get('node')
                ok = bool(it.get('ok'))
                src = it.get('src')
                dest = it.get('dest')
                targets = it.get('targets')
                err = it.get('error') or ''
                errs = it.get('errors') or []
                commands = it.get('commands') or []
                cmd_outs = it.get('command_outputs') if isinstance(it.get('command_outputs'), list) else []
                err_tail = ''
                try:
                    if err:
                        err_tail = str(err)
                    elif isinstance(errs, list) and errs:
                        err_tail = _summarize_for_log(str(errs[0]))
                except Exception:
                    err_tail = ''
                target_desc = None
                try:
                    if isinstance(targets, list) and targets:
                        target_desc = ','.join(str(x) for x in targets[:3])
                except Exception:
                    target_desc = None
                detail = f"node={node} ok={ok} src={src} dest={dest}"
                if target_desc:
                    detail += f" targets={target_desc}"
                if err_tail:
                    detail += f" error={err_tail}"
                _append_async_run_log_line(meta, f"{log_prefix}{detail}")
                try:
                    if isinstance(commands, list):
                        for cmd in commands[:8]:
                            cmd_str = str(cmd or '').strip()
                            if cmd_str:
                                _append_async_run_log_line(meta, f"{log_prefix}cmd: {cmd_str}")
                    if cmd_outs:
                        for entry in cmd_outs[:8]:
                            if not isinstance(entry, dict):
                                continue
                            tgt = str(entry.get('target') or '').strip()
                            rc = entry.get('rc')
                            out = str(entry.get('out') or '').strip()
                            _append_async_run_log_line(meta, f"{log_prefix}cmd: docker cp target={tgt or 'unknown'} rc={rc}")
                            if out:
                                for line in out.splitlines()[:10]:
                                    _append_async_run_log_line(meta, f"{log_prefix}cmd: {line}")
                except Exception:
                    pass

        # Verify: list /flow_artifacts inside target container(s) so logs prove the copy worked.
        try:
            import re as _re

            def _is_hex_container_id(text: str) -> bool:
                # docker short ids are 12 hex chars; full ids are 64.
                try:
                    return bool(_re.fullmatch(r"[0-9a-f]{12,64}", str(text or '').strip().lower()))
                except Exception:
                    return False

            # Prioritize verifying nodes that actually had a Flow artifacts src (these are the
            # ones where we expect /flow_artifacts and /flow_injects to contain files).
            # Also prefer real hex container IDs over aliases like the node name.
            preferred: List[str] = []
            fallback: List[str] = []
            if isinstance(items, list):
                # 1) Items with `src` (flow artifacts) first
                for it in items:
                    if not isinstance(it, dict) or not it.get('ok'):
                        continue
                    src = str(it.get('src') or '').strip()
                    if not src:
                        continue
                    targets = it.get('targets')
                    if isinstance(targets, list):
                        for t in targets:
                            name = str(t or '').strip()
                            if not name:
                                continue
                            (preferred if _is_hex_container_id(name) else fallback).append(name)
                # 2) Remaining items (no src)
                for it in items:
                    if not isinstance(it, dict) or not it.get('ok'):
                        continue
                    src = str(it.get('src') or '').strip()
                    if src:
                        continue
                    targets = it.get('targets')
                    if isinstance(targets, list):
                        for t in targets:
                            name = str(t or '').strip()
                            if not name:
                                continue
                            (preferred if _is_hex_container_id(name) else fallback).append(name)

            seen: set[str] = set()
            uniq: List[str] = []
            for t in (preferred + fallback):
                if t in seen:
                    continue
                seen.add(t)
                uniq.append(t)
                if len(uniq) >= 10:
                    break

            if uniq:
                _append_async_run_log_line(meta, f"{log_prefix}=== docker.exec.verify_flow_artifacts({stage}) ===")
                verify_payload = _run_remote_python_json(
                    cfg,
                    _remote_docker_exec_flow_artifacts_listing_script(
                        containers=uniq,
                        sudo_password=cfg.get('ssh_password'),
                        max_find=200,
                    ),
                    logger=app.logger,
                    label=f'docker.exec.verify_flow_artifacts({stage})',
                    timeout=90.0,
                )
                vitems = verify_payload.get('items') if isinstance(verify_payload, dict) else None
                if isinstance(vitems, list):
                    for vit in vitems[:5]:
                        if not isinstance(vit, dict):
                            continue
                        container = vit.get('container')
                        ok2 = bool(vit.get('ok'))
                        rc2 = vit.get('rc')
                        out2 = vit.get('output') or ''
                        _append_async_run_log_line(meta, f"{log_prefix}docker.exec.verify container={container} ok={ok2} rc={rc2}")
                        for line in str(out2).splitlines()[:60]:
                            _append_async_run_log_line(meta, f"{log_prefix}{line}")


                _append_async_run_log_line(meta, f"{log_prefix}=== docker.exec.listener_snapshot({stage}) ===")
                listener_payload = _run_remote_python_json(
                    cfg,
                    _remote_docker_exec_listener_snapshot_script(
                        containers=uniq,
                        sudo_password=cfg.get('ssh_password'),
                    ),
                    logger=app.logger,
                    label=f'docker.exec.listener_snapshot({stage})',
                    timeout=90.0,
                )
                litems = listener_payload.get('items') if isinstance(listener_payload, dict) else None
                if isinstance(litems, list):
                    for lit in litems[:5]:
                        if not isinstance(lit, dict):
                            continue
                        container = lit.get('container')
                        ok3 = bool(lit.get('ok'))
                        rc3 = lit.get('rc')
                        tcp_rows = int(lit.get('tcp_rows') or 0)
                        tcp6_rows = int(lit.get('tcp6_rows') or 0)
                        udp_rows = int(lit.get('udp_rows') or 0)
                        udp6_rows = int(lit.get('udp6_rows') or 0)
                        _append_async_run_log_line(
                            meta,
                            f"{log_prefix}docker.exec.listeners container={container} ok={ok3} rc={rc3} "
                            f"tcp={tcp_rows} tcp6={tcp6_rows} udp={udp_rows} udp6={udp6_rows}",
                        )
                        out3 = lit.get('output') or ''
                        missing_ss = False
                        for line in str(out3).splitlines()[:80]:
                            _append_async_run_log_line(meta, f"{log_prefix}{line}")
                            try:
                                ll = str(line or '').strip().lower()
                                if 'ss:' in ll and 'not found' in ll:
                                    missing_ss = True
                            except Exception:
                                pass
                        if missing_ss:
                            _append_async_run_log_line(
                                meta,
                                f"{log_prefix}WARNING: 'ss' command is not available inside this container. "
                                "This is not fatal; listener snapshot falls back to /proc/net (tcp/tcp6/udp/udp6) counts for diagnostics.",
                            )
        except Exception as exc_verify:
            _append_async_run_log_line(meta, f"{log_prefix}docker.exec.verify_flow_artifacts({stage}) failed: {exc_verify}")
        copy_required = _coerce_bool(meta.get('flow_copy_required'))
        copy_complete = bool(
            not payload_error
            and copied_ok == copied_total
            and (copied_total > 0 or not copy_required)
        )
        if copy_complete:
            meta['flow_artifacts_copied'] = True
        else:
            if copy_required and copied_total <= 0 and not payload_error:
                meta['flow_artifact_copy_error'] = 'no Flow artifact copy targets were found'
            elif payload_error:
                meta['flow_artifact_copy_error'] = payload_error
            elif copied_ok != copied_total:
                detail = _first_copy_failure_detail()
                message = f'only {int(copied_ok)} of {int(copied_total)} Flow artifact copy targets succeeded'
                if detail:
                    message += f'; first_error={detail}'
                meta['flow_artifact_copy_error'] = message
            _append_async_run_log_line(
                meta,
                f"{log_prefix}docker.copy_flow_artifacts({stage}) pending retry ok={int(copied_ok)} total={int(copied_total)}",
            )
    except Exception as exc:
        meta['flow_artifact_copy_error'] = str(exc)
        _append_async_run_log_line(meta, f"{log_prefix}docker.copy_flow_artifacts({stage}) failed: {exc}")


def _remote_vulns_inventory_script(base_dir: str | None) -> str:
    base_dir_literal = json.dumps(str(base_dir) if base_dir else '')
    return (
        r"""
import glob, json, os

BASE_DIR = __BASE_DIR_LITERAL__


def _safe_exists(p: str) -> bool:
    try:
        return bool(p) and os.path.exists(p)
    except Exception:
        return False


def _first_existing(paths):
    for p in paths:
        if not p:
            continue
        if _safe_exists(p):
            return p
    return None


def _list_dirs(pattern: str, limit: int = 10):
    out = []
    try:
        for p in sorted(glob.glob(pattern)):
            try:
                if os.path.isdir(p):
                    out.append(p)
            except Exception:
                continue
            if len(out) >= limit:
                break
    except Exception:
        return []
    return out


def _count_files_under(path: str, limit: int = 2000) -> int:
    count = 0
    try:
        for _, _, files in os.walk(path):
            count += len(files or [])
            if count >= limit:
                return limit
    except Exception:
        return -1
    return count


def main():
    base = BASE_DIR or os.environ.get('CORE_REMOTE_BASE_DIR') or '/tmp/scenarioforge'
    base = os.path.abspath(base)
    candidates = {
        'base_dir': base,
        'tmp_vulns': '/tmp/vulns',
        'base_vulns': os.path.join(base, 'vulns'),
        'base_outputs_vulns': os.path.join(base, 'outputs', 'vulns'),
    }

    assignments_candidates = [
        os.path.join(base, 'vulns', 'compose_assignments.json'),
        os.path.join(base, 'outputs', 'vulns', 'compose_assignments.json'),
        os.path.join(base, 'compose_assignments.json'),
        '/tmp/vulns/compose_assignments.json',
    ]
    assignments_path = _first_existing(assignments_candidates)

    run_dirs = []
    for root in (candidates.get('tmp_vulns'), candidates.get('base_vulns'), candidates.get('base_outputs_vulns')):
        if not root:
            continue
        run_dirs.extend(_list_dirs(os.path.join(root, 'flag_generators_runs', '*'), limit=10))
        run_dirs.extend(_list_dirs(os.path.join(root, 'flag_node_generators_runs', '*'), limit=10))

    run_dir_summaries = []
    for p in run_dirs[:10]:
        run_dir_summaries.append({
            'path': p,
            'files': _count_files_under(p, limit=2000),
        })

    payload = {
        'ok': True,
        'base_dir': base,
        'paths': {k: {'path': v, 'exists': _safe_exists(v)} for k, v in candidates.items()},
        'compose_assignments': {
            'candidates': assignments_candidates,
            'found': assignments_path,
            'found_exists': bool(assignments_path and _safe_exists(assignments_path)),
        },
        'run_dirs': run_dir_summaries,
    }
    print(json.dumps(payload))


if __name__ == '__main__':
    main()
"""
    ).replace('__BASE_DIR_LITERAL__', base_dir_literal)


def _log_remote_vulns_inventory(meta: Dict[str, Any] | None, *, stage: str, log_prefix: str = '[remote] ') -> None:
    if not meta or not meta.get('remote'):
        return
    cfg = meta.get('core_cfg')
    if not isinstance(cfg, dict):
        return
    base_dir = meta.get('remote_base_dir') or (meta.get('remote_context') or {}).get('base_dir')

    _append_async_run_log_line(meta, f"{log_prefix}=== remote.vulns_inventory({stage}) ===")
    try:
        payload = _run_remote_python_json(
            cfg,
            _remote_vulns_inventory_script(str(base_dir) if base_dir else None),
            logger=app.logger,
            label=f'remote.vulns_inventory({stage})',
            timeout=60.0,
        )
    except Exception as exc:
        _append_async_run_log_line(meta, f"{log_prefix}remote.vulns_inventory({stage}) failed: {exc}")
        return

    try:
        base = payload.get('base_dir') if isinstance(payload, dict) else None
        if base:
            _append_async_run_log_line(meta, f"{log_prefix}CORE_REMOTE_BASE_DIR={base}")
    except Exception:
        pass
    try:
        paths = payload.get('paths') if isinstance(payload, dict) else None
        if isinstance(paths, dict):
            for key in ('tmp_vulns', 'base_vulns', 'base_outputs_vulns'):
                entry = paths.get(key)
                if isinstance(entry, dict):
                    _append_async_run_log_line(
                        meta,
                        f"{log_prefix}{key} path={entry.get('path')} exists={bool(entry.get('exists'))}",
                    )
    except Exception:
        pass
    try:
        ca = payload.get('compose_assignments') if isinstance(payload, dict) else None
        if isinstance(ca, dict):
            _append_async_run_log_line(
                meta,
                f"{log_prefix}compose_assignments found={ca.get('found')} exists={bool(ca.get('found_exists'))}",
            )
    except Exception:
        pass
    try:
        runs = payload.get('run_dirs') if isinstance(payload, dict) else None
        if isinstance(runs, list) and runs:
            _append_async_run_log_line(meta, f"{log_prefix}run_dirs found={len(runs)} (showing up to 10)")
            for it in runs[:10]:
                if not isinstance(it, dict):
                    continue
                _append_async_run_log_line(meta, f"{log_prefix}run_dir path={it.get('path')} files={it.get('files')}")
        else:
            _append_async_run_log_line(meta, f"{log_prefix}run_dirs found=0")
    except Exception:
        pass


def _log_remote_vulns_inventory_to_handle(
    *,
    core_cfg: Dict[str, Any],
    log_handle: Any,
    stage: str,
    base_dir: str | None = None,
    log_prefix: str = '[remote] ',
) -> None:
    """Write the same inventory info as _log_remote_vulns_inventory, but without requiring RUNS meta.

    This is useful for early-run diagnostics before RUNS[run_id] is populated, or
    in failure paths where we never reach the postrun copy stage.
    """
    try:
        log_handle.write(f"{log_prefix}=== remote.vulns_inventory({stage}) ===\n")
    except Exception:
        return

    try:
        payload = _run_remote_python_json(
            core_cfg,
            _remote_vulns_inventory_script(str(base_dir) if base_dir else None),
            logger=app.logger,
            label=f'remote.vulns_inventory({stage})',
            timeout=60.0,
        )
    except Exception as exc:
        try:
            log_handle.write(f"{log_prefix}remote.vulns_inventory({stage}) failed: {exc}\n")
        except Exception:
            pass
        return

    def _w(line: str) -> None:
        try:
            log_handle.write(line.rstrip('\n') + "\n")
        except Exception:
            pass

    try:
        base = payload.get('base_dir') if isinstance(payload, dict) else None
        if base:
            _w(f"{log_prefix}CORE_REMOTE_BASE_DIR={base}")
    except Exception:
        pass
    try:
        paths = payload.get('paths') if isinstance(payload, dict) else None
        if isinstance(paths, dict):
            for key in ('tmp_vulns', 'base_vulns', 'base_outputs_vulns'):
                entry = paths.get(key)
                if isinstance(entry, dict):
                    _w(f"{log_prefix}{key} path={entry.get('path')} exists={bool(entry.get('exists'))}")
    except Exception:
        pass
    try:
        ca = payload.get('compose_assignments') if isinstance(payload, dict) else None
        if isinstance(ca, dict):
            _w(f"{log_prefix}compose_assignments found={ca.get('found')} exists={bool(ca.get('found_exists'))}")
    except Exception:
        pass
    try:
        runs = payload.get('run_dirs') if isinstance(payload, dict) else None
        if isinstance(runs, list) and runs:
            _w(f"{log_prefix}run_dirs found={len(runs)} (showing up to 10)")
            for it in runs[:10]:
                if not isinstance(it, dict):
                    continue
                _w(f"{log_prefix}run_dir path={it.get('path')} files={it.get('files')}")
        else:
            _w(f"{log_prefix}run_dirs found=0")
    except Exception:
        pass


def _remote_docker_exec_flow_artifacts_listing_script(
    *,
    containers: List[str],
    sudo_password: str | None = None,
    max_find: int = 200,
) -> str:
    containers_literal = json.dumps([str(x) for x in (containers or [])])
    sudo_password_literal = json.dumps(str(sudo_password) if sudo_password else "")
    max_find_literal = json.dumps(int(max_find))
    return (
        r"""
import json, subprocess

CONTAINERS = __CONTAINERS_LITERAL__
SUDO_PASSWORD = __SUDO_PASSWORD_LITERAL__
MAX_FIND = __MAX_FIND_LITERAL__


def _run(cmd, timeout=25):
    try:
        p = subprocess.run(['sudo', '-n'] + list(cmd), stdout=subprocess.PIPE, stderr=subprocess.STDOUT, text=True, timeout=timeout)
        if p.returncode == 0:
            return p
        if SUDO_PASSWORD:
            return subprocess.run(
                ['sudo', '-S', '-k', '-p', ''] + list(cmd),
                input=str(SUDO_PASSWORD) + "\n",
                stdout=subprocess.PIPE,
                stderr=subprocess.STDOUT,
                text=True,
                timeout=timeout,
            )
        return p
    except Exception as e:
        return subprocess.CompletedProcess(cmd, 127, stdout=str(e))


def main():
    items = []
    for c in CONTAINERS:
        c = str(c or '').strip()
        if not c:
            continue
        shell = (
            'set -e; '
            'echo "--- ls -la /flow_artifacts ---"; '
            'ls -la /flow_artifacts 2>&1 || true; '
            'echo "--- find /flow_artifacts (files) ---"; '
            f"find /flow_artifacts -maxdepth 3 -type f -print 2>/dev/null | head -n {MAX_FIND} || true; "
            'echo "--- ls -la /flow_injects ---"; '
            'ls -la /flow_injects 2>&1 || true; '
            'echo "--- find /flow_injects (files) ---"; '
            f"find /flow_injects -maxdepth 3 -type f -print 2>/dev/null | head -n {MAX_FIND} || true; "
        )
        p = _run(['docker', 'exec', c, 'sh', '-c', shell], timeout=25)
        items.append({'container': c, 'ok': p.returncode == 0, 'rc': int(p.returncode), 'output': (p.stdout or '')})
    print(json.dumps({'ok': True, 'items': items}))


if __name__ == '__main__':
    main()
"""
    ).replace('__CONTAINERS_LITERAL__', containers_literal) \
     .replace('__SUDO_PASSWORD_LITERAL__', sudo_password_literal) \
     .replace('__MAX_FIND_LITERAL__', max_find_literal)


def _run_cli_background_task(run_id: str, job_spec: dict[str, Any]) -> None:
    run_id_local = run_id
    seed = job_spec.get('seed')
    xml_path = job_spec.get('xml_path')
    session_xml_str = job_spec.get('session_xml_str')
    preview_plan_path = job_spec.get('preview_plan_path')
    core_override = job_spec.get('core_override')
    scenario_core_override = job_spec.get('scenario_core_override')
    scenario_name_hint = job_spec.get('scenario_name_hint')
    scenario_index_hint = job_spec.get('scenario_index_hint')
    flow_enabled = job_spec.get('flow_enabled')
    # Repo sync is always enabled for remote (SSH) execution.
    update_remote_repo = True
    adv_fix_docker_daemon = job_spec.get('adv_fix_docker_daemon')
    adv_run_core_cleanup = job_spec.get('adv_run_core_cleanup')
    adv_deep_cleanup_after_run = job_spec.get('adv_deep_cleanup_after_run')
    adv_check_core_version = False
    adv_restart_core_daemon = job_spec.get('adv_restart_core_daemon')
    adv_start_core_daemon = job_spec.get('adv_start_core_daemon')
    adv_auto_kill_sessions = job_spec.get('adv_auto_kill_sessions')
    docker_remove_conflicts = job_spec.get('docker_remove_conflicts')
    docker_cleanup_before_run = job_spec.get('docker_cleanup_before_run')
    docker_remove_all_containers = job_spec.get('docker_remove_all_containers')
    if _webui_running_in_docker() and (adv_fix_docker_daemon or docker_cleanup_before_run or docker_remove_all_containers):
        adv_fix_docker_daemon = False
        docker_cleanup_before_run = False
        docker_remove_all_containers = False
        try:
            app.logger.warning('[async] Background run %s: forced docker repair/cleanup toggles off (web UI in Docker)', run_id)
        except Exception:
            pass

    # Ensure FlowState inject_files are backfilled into the XML before uploading/running.
    try:
        if isinstance(xml_path, str) and xml_path.strip() and os.path.exists(str(xml_path)):
            fs = _read_flow_state_from_xml_path(str(xml_path), scenario_name_hint)
            if isinstance(fs, dict) and fs:
                _update_flow_state_in_xml(str(xml_path), scenario_name_hint, fs)
    except Exception:
        pass

    overwrite_existing_images = job_spec.get('overwrite_existing_images')
    # Always use full artifacts mode; injected-only uploads are no longer supported.
    upload_only_injected_artifacts = False
    scenarios_inline = job_spec.get('scenarios_inline')
    scenario_for_plan = job_spec.get('scenario_for_plan')
    test_docker_node_id = str(job_spec.get('test_docker_node_id') or '').strip()
    test_docker_node_name = str(job_spec.get('test_docker_node_name') or '').strip()
    test_scenario_tag = str(job_spec.get('test_scenario_tag') or '').strip()
    skip_flow_artifact_container_copy = _coerce_bool(job_spec.get('skip_flow_artifact_container_copy'))
    
    out_dir = os.path.dirname(xml_path) if xml_path else _outputs_dir()
    default_log_path = os.path.join(out_dir, f'cli-{run_id}.log')
    meta_for_log = RUNS.get(run_id_local)
    existing_log_path = meta_for_log.get('log_path') if isinstance(meta_for_log, dict) else None
    if isinstance(existing_log_path, str) and existing_log_path.strip():
        log_path = existing_log_path.strip()
        open_mode = 'a'
    else:
        log_path = default_log_path
        open_mode = 'w'

    try:
        log_f = open(log_path, open_mode, encoding='utf-8', buffering=1)
    except Exception:
        log_f = open(log_path, open_mode, encoding='utf-8')

    try:
        if isinstance(meta_for_log, dict):
            meta_for_log['log_path'] = log_path
            if test_docker_node_id:
                meta_for_log['test_docker_node_id'] = test_docker_node_id
            if test_docker_node_name:
                meta_for_log['test_docker_node_name'] = test_docker_node_name
            if test_scenario_tag:
                meta_for_log['test_scenario_tag'] = test_scenario_tag
            if skip_flow_artifact_container_copy:
                meta_for_log['skip_flow_artifact_container_copy'] = True
    except Exception:
        pass
    
    try:
        app.logger.debug("[async] Opened CLI log (line-buffered) at %s", log_path)
    except Exception:
        pass
    app.logger.info("[async] Starting CLI background task; log: %s", log_path)

    # Helper function to signal failure and exit
    def _fail_run(
        error_msg: str,
        detail: str = None,
        code: int = 1,
        extra: Optional[Dict[str, Any]] = None,
    ):
        try:
            log_f.write(f"[async error] {error_msg}\n")
            if detail:
                log_f.write(f"[async detail] {detail}\n")
        except Exception:
            pass
        try:
            log_f.close()
        except Exception:
            pass
        meta = RUNS.get(run_id)
        if meta:
            meta['done'] = True
            meta['returncode'] = code # Non-zero to indicate failure
            meta['error'] = str(error_msg or '').strip()
            if detail:
                meta['error_detail'] = str(detail)
            if isinstance(extra, dict) and extra:
                try:
                    meta.update(extra)
                except Exception:
                    pass

    # Preflight: fail fast on unsafe shell command patterns in flow compose outputs
    # before any CORE daemon interaction.
    try:
        if isinstance(xml_path, str) and xml_path.strip() and os.path.exists(str(xml_path)):
            pre_ok, pre_err, pre_meta = _flow_compose_shell_safety_preflight(str(xml_path), scenario_name_hint)
            if not pre_ok:
                try:
                    log_f.write(f"[preflight] flow compose shell safety failed: {pre_err}\n")
                except Exception:
                    pass
                _fail_run(
                    str(pre_err or 'Flow compose shell safety preflight failed.'),
                    detail='Generator-produced compose command uses shell-expansion patterns unsafe for CORE compose printf rendering.',
                    code=1,
                    extra={'preflight_compose': pre_meta},
                )
                return
    except Exception as exc:
        try:
            log_f.write(f"[preflight] WARN flow compose shell safety check failed unexpectedly: {exc}\n")
        except Exception:
            pass
    
    try:
        payload_for_core = _parse_scenarios_xml(xml_path)
    except Exception:
        payload_for_core = None

    scenario_payload = None
    if payload_for_core:
        scen_list = payload_for_core.get('scenarios') or []
        if isinstance(scen_list, list) and scen_list:
            if scenario_name_hint:
                for scen_entry in scen_list:
                    if not isinstance(scen_entry, dict):
                        continue
                    if str(scen_entry.get('name') or '').strip() == str(scenario_name_hint).strip():
                        scenario_payload = scen_entry
                        break
            if scenario_payload is None and scenario_index_hint is not None:
                if 0 <= scenario_index_hint < len(scen_list):
                    candidate = scen_list[scenario_index_hint]
                    if isinstance(candidate, dict):
                        scenario_payload = candidate
            if scenario_payload is None:
                for scen_entry in scen_list:
                    if isinstance(scen_entry, dict):
                        scenario_payload = scen_entry
                        break
    scenario_core_saved = None
    if scenario_payload and isinstance(scenario_payload.get('hitl'), dict):
        scenario_core_saved = scenario_payload['hitl'].get('core')
    global_core_saved = payload_for_core.get('core') if (payload_for_core and isinstance(payload_for_core.get('core'), dict)) else None
    scenario_core_public = None
    candidate_scenario_core = scenario_core_override if isinstance(scenario_core_override, dict) else None
    if not candidate_scenario_core and isinstance(scenario_core_saved, dict):
        candidate_scenario_core = scenario_core_saved
    if candidate_scenario_core:
        scenario_core_public = _scrub_scenario_core_config(candidate_scenario_core)
    core_cfg = _merge_core_configs(
        global_core_saved,
        scenario_core_saved,
        core_override if isinstance(core_override, dict) else None,
        scenario_core_override if isinstance(scenario_core_override, dict) else None,
        include_password=True,
    )
    core_cfg = _prefer_explicit_or_ssh_core_host(
        core_cfg,
        global_core_saved,
        scenario_core_saved,
        core_override if isinstance(core_override, dict) else None,
        scenario_core_override if isinstance(scenario_core_override, dict) else None,
    )
    # Flag Sequencing (flow.html) invokes via JSON without sending core config.
    scenario_for_secret = None
    try:
        request_provided_core = bool(
            (isinstance(core_override, dict) and core_override)
            or (isinstance(scenario_core_override, dict) and scenario_core_override)
        )
        history = _load_run_history()
        try:
            scenario_for_secret = _normalize_scenario_label(str(scenario_name_hint or '').strip())
        except Exception:
            scenario_for_secret = None
        if not scenario_for_secret:
            try:
                if isinstance(scenario_payload, dict) and isinstance(scenario_payload.get('name'), str):
                    scenario_for_secret = _normalize_scenario_label(str(scenario_payload.get('name') or '').strip())
            except Exception:
                scenario_for_secret = None

        selected_cfg = None
        if scenario_for_secret:
            selected_cfg = _select_core_config_for_page(scenario_for_secret, history, include_password=True)

        # The XML/request identifies the target. Saved page state may only
        # provide credentials for that same target.
        if selected_cfg:
            core_cfg = _fill_matching_core_credentials(core_cfg, selected_cfg)
    except Exception:
        pass
    core_cfg = _prefer_explicit_or_ssh_core_host(
        core_cfg,
        global_core_saved,
        scenario_core_saved,
        core_override if isinstance(core_override, dict) else None,
        scenario_core_override if isinstance(scenario_core_override, dict) else None,
    )
    try:
        if scenario_for_secret and str(core_cfg.get('core_secret_id') or '').strip():
            core_cfg = _apply_core_secret_to_config(core_cfg, scenario_for_secret)
    except Exception:
        pass
    try:
        core_cfg = _require_core_ssh_credentials(core_cfg)
    except _SSHTunnelError as exc:
        _fail_run(str(exc))
        return

    # Persist remote execution context into RUNS metadata so postrun steps
    # (docker copy into /flow_artifacts and /flow_injects) have access to SSH creds.
    try:
        meta = RUNS.get(run_id_local)
        if isinstance(meta, dict):
            meta['core_cfg'] = dict(core_cfg) if isinstance(core_cfg, dict) else core_cfg
            meta['adv_deep_cleanup_after_run'] = bool(_coerce_bool(adv_deep_cleanup_after_run))
            try:
                meta['remote'] = bool(_coerce_bool(core_cfg.get('ssh_enabled')))
            except Exception:
                meta['remote'] = True
            meta.setdefault('remote_base_dir', '/tmp/scenarioforge')
    except Exception:
        pass

    preferred_cli_venv = _sanitize_venv_bin_path(core_cfg.get('venv_bin'))
    venv_is_explicit = _venv_is_explicit(core_cfg, preferred_cli_venv)
    if preferred_cli_venv and venv_is_explicit:
        venv_error = None
        remote_venv_allowed = bool(core_cfg.get('ssh_enabled'))
        if not os.path.isabs(preferred_cli_venv):
            venv_error = f"Preferred CORE venv bin must be an absolute path: {preferred_cli_venv}"
        elif os.path.isdir(preferred_cli_venv):
            if not _find_python_in_venv_bin(preferred_cli_venv):
                expected = ', '.join(PYTHON_EXECUTABLE_NAMES)
                venv_error = (
                    f"Preferred CORE venv bin {preferred_cli_venv} does not contain a python interpreter "
                    f"(expected one of {expected})."
                )
        elif not remote_venv_allowed:
            venv_error = f"Preferred CORE venv bin not found: {preferred_cli_venv}"
        else:
            try:
                app.logger.info(
                    "[async] Preferred CORE venv bin %s not present locally; assuming remote path",
                    preferred_cli_venv,
                )
            except Exception:
                pass
            try:
                log_f.write(
                    f"[remote] Preferred CORE venv bin {preferred_cli_venv} not present locally; assuming remote path\n"
                )
            except Exception:
                pass
        if venv_error:
            try:
                app.logger.warning("[async] %s", venv_error)
            except Exception:
                pass
            _fail_run(venv_error)
            return

    if bool(core_cfg.get('ssh_enabled')) and update_remote_repo:
        try:
            log_f.write("[remote] Repo sync starting (always enabled for remote execution)\n")
        except Exception:
            pass
        try:
            repo_sync = _push_repo_to_remote(
                core_cfg,
                logger=app.logger,
                upload_only_injected_artifacts=False,
                log_handle=log_f,
            )
        except Exception as exc:
            detail_text = f"{type(exc).__name__}: {str(exc) or repr(exc)}"
            _fail_run(f"Repo upload failed: {detail_text}", detail=repr(exc), code=1)
            return
        else:
            repo_path = repo_sync.get('repo_path') if isinstance(repo_sync, dict) else None
            try:
                detail = f" ({repo_path})" if repo_path else ''
                log_f.write(f"[remote] Repo upload complete{detail}\n")
            except Exception:
                pass
            # Verify installed vuln catalogs arrived on the CORE VM when present locally.
            try:
                local_catalog_root = _installed_vuln_catalogs_root()
                local_has_catalogs = False
                if os.path.isdir(local_catalog_root):
                    try:
                        for _entry in os.scandir(local_catalog_root):
                            local_has_catalogs = True
                            break
                    except Exception:
                        local_has_catalogs = True
                if local_has_catalogs and repo_path and core_cfg.get('ssh_enabled'):
                    client = None
                    try:
                        client = _open_ssh_client(core_cfg)
                        remote_catalog_root = _remote_path_join(repo_path, 'outputs', 'installed_vuln_catalogs')
                        check_cmd = (
                            f"if [ -d {shlex.quote(remote_catalog_root)} ] && "
                            f"[ \"$(ls -A {shlex.quote(remote_catalog_root)} 2>/dev/null)\" ]; then "
                            f"echo OK; else echo MISSING; fi"
                        )
                        _rc, out_text, _err_text = _exec_ssh_command(client, check_cmd, timeout=30.0, check=False)
                        if 'OK' not in (out_text or ''):
                            try:
                                log_f.write(
                                    "[remote] ERROR: outputs/installed_vuln_catalogs missing after repo upload. "
                                    "Compose-based vulnerabilities may fail to resolve.\n"
                                )
                            except Exception:
                                pass
                            _fail_run("Repo upload missing outputs/installed_vuln_catalogs on CORE VM.", code=1)
                            return
                        else:
                            try:
                                log_f.write("[remote] Verified outputs/installed_vuln_catalogs on CORE VM\n")
                            except Exception:
                                pass
                    except Exception as exc:
                        try:
                            log_f.write(f"[remote] WARN: failed to verify installed catalogs: {exc}\n")
                        except Exception:
                            pass
                    finally:
                        try:
                            if client is not None:
                                client.close()
                        except Exception:
                            pass
            except Exception:
                pass
    # Note: for local execution, repo sync is not applicable.

    # Remote preflight: some flow compose paths are remote-only (/tmp/vulns/...).
    # Scan those files on the CORE VM before invoking CLI/CORE startup.
    try:
        if isinstance(xml_path, str) and xml_path.strip() and os.path.exists(str(xml_path)):
            remote_pre_ok, remote_pre_err, remote_pre_meta = _flow_compose_shell_safety_preflight_remote(
                core_cfg,
                str(xml_path),
                scenario_name_hint,
            )
            if not remote_pre_ok:
                try:
                    log_f.write(f"[preflight] remote flow compose shell safety failed: {remote_pre_err}\n")
                except Exception:
                    pass
                _fail_run(
                    str(remote_pre_err or 'Remote flow compose shell safety preflight failed.'),
                    detail='Generator-produced compose command uses shell-expansion patterns unsafe for CORE compose printf rendering.',
                    code=1,
                    extra={'preflight_compose_remote': remote_pre_meta},
                )
                return
    except Exception as exc:
        try:
            log_f.write(f"[preflight] WARN remote flow compose shell safety check failed unexpectedly: {exc}\n")
        except Exception:
            pass

    core_host = _remote_core_target_host(core_cfg, default='127.0.0.1')
    try:
        core_port = int(core_cfg.get('port', 50051))
    except Exception:
        core_port = 50051
    remote_desc = f"{core_host}:{core_port}"

    def _collect_blocking_sessions() -> list[dict]:
        blocking: list[dict] = []
        try:
            sessions = _list_active_core_sessions(core_host, core_port, core_cfg, errors=[], meta={})
        except Exception as exc:
            try:
                app.logger.warning('[async] Failed to enumerate existing CORE sessions: %s', exc)
            except Exception:
                pass
            sessions = []
        for entry in sessions:
            state_raw = str(entry.get('state') or '').strip().lower()
            if state_raw in {'shutdown'}:
                continue
            blocking.append(entry)
        return blocking

    app.logger.info("[async] CORE remote=%s (ssh_enabled=%s)", remote_desc, core_cfg.get('ssh_enabled'))
    pre_saved = None
    # Establish SSH tunnel so CLI subprocess can reach CORE
    conn_host = core_host
    conn_port = core_port
    ssh_tunnel = None
    try:
        tunnel = _SshTunnel(
            ssh_host=str(core_cfg.get('ssh_host') or core_host),
            ssh_port=int(core_cfg.get('ssh_port') or 22),
            username=str(core_cfg.get('ssh_username') or ''),
            password=(core_cfg.get('ssh_password') or None),
            remote_host=str(core_host),
            remote_port=int(core_port),
        )
        conn_host, conn_port = tunnel.start()
        ssh_tunnel = tunnel
        app.logger.info(
            "[async] SSH tunnel active: %s -> %s",
            f"{conn_host}:{conn_port}",
            remote_desc,
        )
        try:
            log_f.write(f"[remote] SSH tunnel active: {conn_host}:{conn_port} -> {remote_desc}\n")
            _write_sse_marker(
                log_f,
                'phase',
                {
                    'stage': 'ssh.tunnel',
                    'kind': 'tunnel',
                    'local': f"{conn_host}:{conn_port}",
                    'remote': remote_desc,
                },
            )
        except Exception:
            pass
    except _SSHTunnelError as exc:
        try:
            ssh_host = str(core_cfg.get('ssh_host') or core_host)
            ssh_port = int(core_cfg.get('ssh_port') or 22)
            ssh_user = str(core_cfg.get('ssh_username') or '')

            app.logger.warning(
                "[async] SSH tunnel setup failed: %s. Context: ssh=%s:%s user=%s target=%s:%s",
                exc, ssh_host, ssh_port, ssh_user, core_host, core_port
            )
        except Exception:
            pass
        if ssh_tunnel:
            try:
                ssh_tunnel.close()
            except Exception:
                pass
        _fail_run(f"SSH tunnel failed: {exc}", code=1)
        return
    except Exception as exc:
        try:
            app.logger.exception("[async] Unexpected SSH tunnel failure: %s", exc)
        except Exception:
            pass
        if ssh_tunnel:
            try:
                ssh_tunnel.close()
            except Exception:
                pass
        _fail_run("Failed to establish SSH tunnel", code=1)
        return

    # Capture scenario names from the editor XML now (CORE post XML will not be parsable by our scenarios parser)
    scen_names = _scenario_names_from_xml(xml_path)
    resolved_scenario_name = None
    try:
        resolved_scenario_name = str(scenario_name_hint or '').strip() or None
    except Exception:
        resolved_scenario_name = None
    if not resolved_scenario_name:
        try:
            if isinstance(scenario_payload, dict):
                resolved_scenario_name = str(scenario_payload.get('name') or '').strip() or None
        except Exception:
            resolved_scenario_name = None
    if not resolved_scenario_name:
        try:
            if isinstance(scen_names, list) and scen_names:
                resolved_scenario_name = str(scen_names[0] or '').strip() or None
        except Exception:
            resolved_scenario_name = None
    try:
        meta = RUNS.get(run_id_local)
        if isinstance(meta, dict):
            meta['scenario_name'] = resolved_scenario_name
            meta['scenario_names'] = list(scen_names or []) if isinstance(scen_names, list) else []
            meta['core_cfg'] = core_cfg
            meta['adv_deep_cleanup_after_run'] = bool(_coerce_bool(adv_deep_cleanup_after_run))
            if isinstance(scenario_core_public, dict):
                meta['scenario_core'] = scenario_core_public
    except Exception:
        pass
    log_prefix = "[remote] "
    remote_client = None
    remote_ctx = None
    remote_python = None

    def _purge_remote_run_dir() -> None:
        if not remote_ctx:
            return
        run_dir = remote_ctx.get('run_dir') if isinstance(remote_ctx, dict) else None
        if not run_dir or not remote_client:
            return
        try:
            _remote_remove_path(remote_client, run_dir)
        except Exception:
            pass

    try:
        remote_client = _open_ssh_client(core_cfg)
    except Exception as exc:
        try:
            log_f.write(f"{log_prefix}Failed to open SSH session for CLI: {exc}\n")
        except Exception:
            pass
        if ssh_tunnel:
            try:
                ssh_tunnel.close()
            except Exception:
                pass
        _fail_run(f"Failed to open SSH session for CLI: {exc}", code=1)
        return

    def _sanitize_remote_compose_templates() -> None:
        script = textwrap.dedent(
            r"""
            python3 - <<'PY'
            import glob, json, re

            changed = []
            for path in sorted(glob.glob('/tmp/vulns/docker-compose-*.yml')):
                try:
                    with open(path, 'r', encoding='utf-8', errors='ignore') as f:
                        txt = f.read()
                    safe_re = re.compile(r'\$\{\s*([\"\'])\$\{[^}]*\}\1\s*\}')
                    stash = {}

                    def _stash(m):
                        key = f"__CORETG_SAFE_MAKO_EXPR_{len(stash)}__"
                        stash[key] = m.group(0)
                        return key

                    fixed = safe_re.sub(_stash, txt)

                    def _wrap(m):
                        expr = (m.group(1) or '')
                        if not expr:
                            return m.group(0)
                        return '${"${' + expr + '}"}'

                    fixed = re.sub(r'\\+\$\{([^}]*)\}', _wrap, fixed)
                    fixed = re.sub(r'\$\$\{([^}]*)\}', _wrap, fixed)
                    fixed = safe_re.sub(_stash, fixed)
                    fixed = re.sub(r'(?<!\$)\$\{([^}]*)\}', _wrap, fixed)
                    for key, original in stash.items():
                        fixed = fixed.replace(key, original)
                    if fixed != txt:
                        with open(path, 'w', encoding='utf-8') as f:
                            f.write(fixed)
                        changed.append(path)
                except Exception:
                    continue
            print(json.dumps({'changed': changed, 'count': len(changed)}))
            PY
            """
        ).strip()
        try:
            code, out_text, err_text = _exec_ssh_command(remote_client, script, timeout=45.0)
        except Exception as exc:
            try:
                log_f.write(f"{log_prefix}WARN: pre-run remote compose sanitize failed: {exc}\n")
            except Exception:
                pass
            return
        if code != 0:
            try:
                log_f.write(
                    f"{log_prefix}WARN: pre-run remote compose sanitize exited {code}; stderr={_summarize_for_log((err_text or '').strip())}\n"
                )
            except Exception:
                pass
            return
        try:
            payload = json.loads((out_text or '').strip() or '{}')
        except Exception:
            payload = {}
        try:
            log_f.write(
                f"{log_prefix}pre-run remote compose sanitize changed={int(payload.get('count') or 0)}\n"
            )
        except Exception:
            pass
    auto_start_allowed = _coerce_bool(core_cfg.get('auto_start_daemon')) or bool(adv_restart_core_daemon)
    try:
        log_f.write(f"{log_prefix}core-daemon auto-start allowed: {auto_start_allowed}\n")
    except Exception:
        pass

    def _exec_sudo(
        cmd: str,
        *,
        timeout: float = 30.0,
        stage: str = 'sudo',
    ) -> tuple[int, str, str]:
        sudo_password = core_cfg.get('ssh_password')
        # Wrap in `timeout` to avoid hanging indefinitely.
        wrapped = _build_remote_sudo_shell_command(cmd, timeout=timeout)
        if sudo_password:
            sudo_cmd = f"sudo -S -p '' {wrapped}"
        else:
            sudo_cmd = f"sudo -n {wrapped}"
        stdin = stdout = stderr = None
        try:
            stdin, stdout, stderr = remote_client.exec_command(sudo_cmd, timeout=timeout + 5.0, get_pty=True)
            if sudo_password:
                try:
                    stdin.write(str(sudo_password) + '\n')
                    stdin.flush()
                except Exception:
                    pass
            stdout_data = stdout.read()
            stderr_data = stderr.read()
            try:
                exit_code = stdout.channel.recv_exit_status() if hasattr(stdout, 'channel') else 0
            except Exception:
                exit_code = 0
            out_text = stdout_data.decode('utf-8', 'ignore') if isinstance(stdout_data, bytes) else str(stdout_data or '')
            err_text = stderr_data.decode('utf-8', 'ignore') if isinstance(stderr_data, bytes) else str(stderr_data or '')
            try:
                log_f.write(
                    f"{log_prefix}{stage}: {sudo_cmd} -> exit={exit_code} stdout={_summarize_for_log(out_text.strip())} stderr={_summarize_for_log(err_text.strip())}\n"
                )
            except Exception:
                pass
            return exit_code, out_text, err_text
        finally:
            _close_ssh_command_streams(stdin, stdout, stderr)

    def _check_core_version() -> tuple[bool, str]:
        # Some deployments do not support --version; use -h for a portable probe.
        exit_code, out_text, err_text = _exec_sudo("core-daemon -h", stage='version_check')
        merged = f"{out_text}\n{err_text}".strip()
        if exit_code == 0 or "usage:" in merged.lower() or "core-daemon" in merged.lower():
            return True, "detected"
        return False, ""

    def _maybe_fix_docker_daemon() -> None:
        if not adv_fix_docker_daemon:
            return
        try:
            log_f.write(f"{log_prefix}Attempting to unmask/enable docker service...\n")
        except Exception:
            pass
        _exec_sudo("systemctl unmask docker", stage='docker_fix')
        _exec_sudo("systemctl enable docker", stage='docker_fix')
        _exec_sudo("systemctl restart docker", stage='docker_fix')
        try:
            log_f.write(f"{log_prefix}Docker service restart command sent.\n")
        except Exception:
            pass

    def _maybe_restart_core_daemon() -> None:
        if not adv_restart_core_daemon:
            return
        try:
            log_f.write(f"{log_prefix}Restarting core-daemon service...\n")
        except Exception:
            pass
        _exec_sudo("systemctl restart core-daemon", stage='core_restart')
    def _maybe_kill_active_sessions() -> None:
        if not adv_auto_kill_sessions:
            try:
                log_f.write(f"{log_prefix}Auto-kill sessions toggle is OFF; skipping active session termination.\n")
            except Exception:
                pass
            return
        to_kill = _collect_blocking_sessions()
        if not to_kill:
            try:
                log_f.write(f"{log_prefix}No active CORE sessions found to auto-kill.\n")
            except Exception:
                pass
            return
        supports_stop = False
        try:
            _, out_h, err_h = _exec_sudo("core-daemon -h", stage='kill_session_capability')
            help_text = f"{out_h}\n{err_h}".lower()
            supports_stop = ('--stop' in help_text)
        except Exception:
            supports_stop = False
        try:
            log_f.write(f"{log_prefix}Auto-killing {len(to_kill)} active session(s)...\n")
        except Exception:
            pass
        for s in to_kill:
            sid = s.get('id')
            if not sid:
                continue
            try:
                exit_code = 1
                if supports_stop:
                    # Try graceful stop first when supported by this core-daemon build.
                    exit_code, _, _ = _exec_sudo(f"core-daemon --stop {sid}", stage='kill_session')
                if exit_code != 0:
                    _exec_sudo("core-cleanup", stage='core_cleanup')
                    # core-cleanup is destructive; restart daemon to clear in-memory session state
                    _exec_sudo("systemctl restart core-daemon", stage='core_restart_after_cleanup')
                    time.sleep(2.0)
            except Exception as exc:
                try:
                    log_f.write(f"{log_prefix}ERROR: clean session {sid} failed: {exc}\n")
                except Exception:
                    pass
        # Wait a bit
        try:
            time.sleep(2.0)
        except Exception:
            pass

    def _maybe_core_cleanup() -> None:
        _remote_docker_remove_all_containers_script = (
            "sh -c '"
            "ids=$(docker ps -a --format '\"'\"'{{.ID}} {{.Names}}'\"'\"' | "
            "grep -vE '\"'\"' core-daemon$| registry:2$'\"'\"' | awk '\"'\"'{print $1}'\"'\"'); "
            "if [ -n \"$ids\" ]; then "
            "imgs=$(docker inspect -f '\"'\"'{{.Image}}'\"'\"' $ids 2>/dev/null | sort -u); "
            "echo \"$ids\" | xargs -r docker rm -f; "
            "if [ -n \"$imgs\" ]; then echo \"$imgs\" | xargs -r docker rmi -f || true; fi; "
            "fi'"
        )
        _remote_docker_cleanup_script = r"""
        docker container prune -f
        docker image prune -f
        docker network prune -f
        docker volume prune -f
        find /tmp/vulns -maxdepth 1 \( -name 'docker-compose-*.yml' -o -name 'docker-compose-*.orig.yml' -o -name 'compose_assignments.json' -o -name 'docker-wrap-*' \) -exec rm -rf {} + 2>/dev/null || true
        """

        _remote_docker_remove_generator_images_shell = r"""
        docker images --format '{{.Repository}}:{{.Tag}}' | grep -E '^coretg-gen-[^:]+:' | xargs -r docker rmi -f
        """

        _remote_docker_remove_wrapper_images_script = r"""
        docker images --format '{{.Repository}}:{{.Tag}}' | grep '_wrapper' | xargs -r docker rmi -f
        """

        if adv_run_core_cleanup:
            try:
                log_f.write(f"{log_prefix}Running advanced CORE cleanup (core-cleanup + stale dirs)...\n")
            except Exception:
                pass
            cleanup_exit, cleanup_out, cleanup_err = _exec_sudo("core-cleanup", stage='core_cleanup')
            if cleanup_exit != 0:
                try:
                    log_f.write(
                        f"{log_prefix}WARN: core-cleanup exited {cleanup_exit}; continuing with stale-dir cleanup. stderr={_summarize_for_log((cleanup_err or '').strip())} stdout={_summarize_for_log((cleanup_out or '').strip())}\n"
                    )
                except Exception:
                    pass
            else:
                try:
                    log_f.write(f"{log_prefix}core-cleanup completed successfully.\n")
                except Exception:
                    pass
            _exec_sudo("find /var/lib/core -name '*.conf' -mtime +1 -delete", stage='cleanup')
            _exec_sudo("find /tmp -name 'pycore.*' -mtime +1 -delete", stage='cleanup')
            try:
                log_f.write(f"{log_prefix}Cleanup commands sent.\n")
            except Exception:
                pass
        
        if docker_remove_conflicts or docker_cleanup_before_run or docker_remove_all_containers:
            try:
                log_f.write(f"{log_prefix}Running Docker cleanup tasks...\n")
            except Exception:
                pass
            
            if docker_remove_all_containers:
                _exec_sudo(_remote_docker_remove_all_containers_script, stage='docker_nuke')
                try:
                    log_f.write(f"{log_prefix}Removed all non-essential containers.\n")
                except Exception:
                    pass
            elif docker_remove_conflicts:
                # Remove containers that start with the scenario safe name
                # We need the scenario name. We have `scen_names`.
                # If multiple scenarios, we might need to iterate.
                # But here we just want to execute.
                # In original code:
                # It iterates over `scen_names` (implied from xml_path parsing)
                pass

            if docker_cleanup_before_run:
                _exec_sudo(_remote_docker_cleanup_script, stage='docker_prune')
                try:
                    log_f.write(f"{log_prefix}Pruned docker system and unused volumes.\n")
                except Exception:
                    pass
                
                # Also remove old generator images to prevent stale cache issues
                try:
                    gen_exit, gen_out, gen_err = _exec_sudo(
                        _remote_docker_remove_generator_images_shell,
                        stage='docker_gen_cleanup',
                    )
                    if gen_exit == 0:
                        log_f.write(f"{log_prefix}Cleaned up old generator images.\n")
                    else:
                        log_f.write(
                            f"{log_prefix}Generator image cleanup skipped or failed: "
                            f"exit={gen_exit} stdout={_summarize_for_log((gen_out or '').strip())} "
                            f"stderr={_summarize_for_log((gen_err or '').strip())}\n"
                        )
                except Exception as gen_cleanup_exc:
                    try:
                        log_f.write(f"{log_prefix}Generator image cleanup skipped or failed: {str(gen_cleanup_exc)[:200]}\n")
                    except Exception:
                        pass

        # Handle overwrite existing images
        if overwrite_existing_images:
            try:
                log_f.write(f"{log_prefix}Checking for existing wrapper images to overwrite...\n")
            except Exception:
                pass
            _exec_sudo(_remote_docker_remove_wrapper_images_script, stage='docker_rmi')
            try:
                 log_f.write(f"{log_prefix}Removed existing wrapper images.\n")
            except Exception:
                 pass

    # Now execute the sequence
    try:
        log_f.write(
            f"{log_prefix}Toggle state: "
            f"adv_fix_docker_daemon={bool(adv_fix_docker_daemon)} "
            f"adv_run_core_cleanup={bool(adv_run_core_cleanup)} "
            f"adv_check_core_version={bool(adv_check_core_version)} "
            f"adv_restart_core_daemon={bool(adv_restart_core_daemon)} "
            f"adv_start_core_daemon={bool(adv_start_core_daemon)} "
            f"adv_auto_kill_sessions={bool(adv_auto_kill_sessions)} "
            f"docker_remove_conflicts={bool(docker_remove_conflicts)} "
            f"docker_cleanup_before_run={bool(docker_cleanup_before_run)} "
            f"docker_remove_all_containers={bool(docker_remove_all_containers)} "
            f"overwrite_existing_images={bool(overwrite_existing_images)} "
            f"upload_only_injected_artifacts={bool(upload_only_injected_artifacts)}\n"
        )
    except Exception:
        pass
    _maybe_fix_docker_daemon()
    _maybe_core_cleanup()

    # CORE Daemon checks
    daemon_ok, ver = _check_core_version()
    if not daemon_ok:
        try:
             log_f.write(f"{log_prefix}WARN: core-daemon check failed. Attempting restart...\n")
        except Exception:
             pass
        _maybe_restart_core_daemon()
        time.sleep(2.0)
        daemon_ok, ver = _check_core_version()
        if not daemon_ok:
             try:
                 log_f.write(f"{log_prefix}ERROR: core-daemon is not responding or not installed.\n")
             except Exception:
                 pass
             _fail_run("Remote core-daemon not reachable.", code=1)
             return
    
    try:
        log_f.write(f"{log_prefix}CORE version active: {ver}\n")
    except Exception:
         pass

    # Ensure daemon is ready (session check)
    try:
        log_f.write(f"{log_prefix}Verifying core-daemon process state...\n")
    except Exception:
        pass

    try:
        _ensure_remote_core_daemon_ready(
            client=remote_client,
            core_cfg=core_cfg,
            auto_start_allowed=auto_start_allowed,
            sudo_password=core_cfg.get('ssh_password'),
            prefer_managed_service=True,
            logger=app.logger,
            log_handle=log_f,
            log_prefix=log_prefix
        )
    except CoreDaemonConflictError as exc:
        try:
             log_f.write(f"{log_prefix}ERROR: Failed to ensure core-daemon is ready: {exc}\n")
        except Exception:
             pass
        _fail_run(
            f"Failed to ensure core-daemon is ready: {exc}",
            code=1,
            extra={
                'daemon_conflict': True,
                'daemon_pids': list(getattr(exc, 'pids', []) or []),
                'can_stop_daemons': bool(core_cfg.get('ssh_password')),
                'error_code': 'core_daemon_conflict',
            },
        )
        return
    except Exception as exc:
        try:
             log_f.write(f"{log_prefix}ERROR: Failed to ensure core-daemon is ready: {exc}\n")
        except Exception:
             pass
        _fail_run(f"Failed to ensure core-daemon is ready: {exc}", code=1)
        return

    try:
        required_custom_services = set(_local_custom_service_names() or ["DockerDefaultRoute", "CoreTGPrereqs"])
        # Keep Execute on the repository's current service implementations.
        # CORE imports custom service classes in core-daemon, so merely syncing the
        # repo is not enough; updated modules must be installed and the daemon restarted.
        install_custom_services_on_execute = bool(
            core_cfg.get('install_custom_services', False)
            or core_cfg.get('ssh_password')
        )
        discovered = _remote_core_service_names(remote_client, core_cfg=core_cfg, require_custom_services_dir=True)
        missing = sorted([name for name in required_custom_services if name not in discovered])
        if install_custom_services_on_execute:
            try:
                if missing:
                    log_f.write(f"{log_prefix}Missing custom services on CORE VM ({', '.join(missing)}); installing now...\n")
                else:
                    log_f.write(f"{log_prefix}Ensuring custom services are installed on CORE VM...\n")
            except Exception:
                pass
            install_meta = _install_custom_services_to_core_vm(
                remote_client,
                sudo_password=core_cfg.get('ssh_password'),
                logger=app.logger,
                core_cfg=core_cfg,
            )
            try:
                targets = install_meta.get('services_dirs') or []
                if targets:
                    log_f.write(f"{log_prefix}Custom services install targets: {', '.join([str(t) for t in targets])}\n")
                conf_targets = install_meta.get('core_conf_custom_services_dirs') or []
                if conf_targets:
                    log_f.write(f"{log_prefix}core.conf custom_services dirs: {', '.join([str(t) for t in conf_targets])}\n")
                else:
                    log_f.write(f"{log_prefix}core.conf custom_services dirs: none found\n")
                conf_readable = install_meta.get('core_conf_readable')
                conf_path = str(install_meta.get('core_conf_path') or '').strip()
                if conf_path:
                    log_f.write(f"{log_prefix}core.conf path used: {conf_path}\n")
                else:
                    log_f.write(f"{log_prefix}core.conf path used: not found\n")
                if conf_readable is True:
                    log_f.write(f"{log_prefix}core.conf readable: yes\n")
                elif conf_readable is False:
                    log_f.write(f"{log_prefix}core.conf readable: no\n")
                else:
                    log_f.write(f"{log_prefix}core.conf readable: unknown\n")
                conf_lines = install_meta.get('core_conf_custom_services_lines') or []
                if conf_lines:
                    log_f.write(f"{log_prefix}core.conf matching entries: {' | '.join([str(x) for x in conf_lines])}\n")
                else:
                    log_f.write(f"{log_prefix}core.conf matching entries: none found\n")
            except Exception:
                pass
            discovered = _remote_core_service_names(remote_client, core_cfg=core_cfg, require_custom_services_dir=True)
            missing = sorted([name for name in required_custom_services if name not in discovered])
        if missing:
            _fail_run(
                f"Required custom CORE service(s) missing on remote host: {', '.join(missing)}. "
                "Use the Execute preflight prompt to install them, or open CORE Connection, enable "
                "'Install custom services', then re-run Execute.",
                code=1,
                extra={'error_code': 'missing_custom_services', 'missing_services': missing},
            )
            return
    except Exception as exc:
        _fail_run(
            "Failed validating/installing custom services on remote CORE host: "
            f"{exc}. Open CORE Connection and enable "
            "'Install custom services', then re-run Execute.",
            code=1,
            extra={'error_code': 'custom_services_install_failed'},
        )
        return

    try:
        required_builtin_services = _required_builtin_core_services_for_xml_input(
            xml_path,
            session_xml_str,
            scenario_name=scenario_name_hint,
        )
        if required_builtin_services:
            discovered_builtin_services = _remote_core_service_names(
                remote_client,
                core_cfg=core_cfg,
                require_custom_services_dir=False,
            )
            missing_builtin_services = sorted(
                name for name in required_builtin_services if name not in discovered_builtin_services
            )
            if missing_builtin_services:
                try:
                    log_f.write(
                        f"{log_prefix}Missing built-in CORE services on CORE VM ({', '.join(missing_builtin_services)}).\n"
                    )
                except Exception:
                    pass
                _fail_run(
                    f"Required built-in CORE service(s) missing on remote host: {', '.join(missing_builtin_services)}. "
                    "This usually means the CORE VM install is incomplete or core-daemon did not load its default services. "
                    "If you also saw '/etc/core/logging.conf does not exist', repair the CORE daemon config on the VM and restart core-daemon before re-running Execute.",
                    code=1,
                    extra={
                        'error_code': 'missing_builtin_services',
                        'missing_services': missing_builtin_services,
                        'required_services': sorted(required_builtin_services),
                    },
                )
                return
    except Exception as exc:
        try:
            log_f.write(f"{log_prefix}WARN: built-in CORE service preflight skipped: {exc}\n")
        except Exception:
            pass

    _sanitize_remote_compose_templates()

    try:
        log_f.write(f"{log_prefix}Cleaning up active sessions...\n")
    except Exception:
        pass

    _maybe_kill_active_sessions()

    # Final check for blocking sessions
    blocking = _collect_blocking_sessions()
    if blocking:
         if adv_auto_kill_sessions:
             msg = f"Blocking sessions active: {[s.get('id') for s in blocking]}. Auto-kill was enabled but did not clear all sessions."
         else:
             msg = f"Blocking sessions active: {[s.get('id') for s in blocking]}. Auto-kill was not enabled."
         try:
             log_f.write(f"{log_prefix}ERROR: {msg}\n")
         except Exception:
             pass
         _fail_run(msg, code=1, extra={'error_code': 'active_sessions_blocking'})
         return

    if _stale_core_veth_cleanup_enabled():
        try:
            log_f.write(f"{log_prefix}Cleaning stale CORE host veth interfaces (best-effort)...\n")
        except Exception:
            pass
        try:
            cleanup_cmd = _stale_core_veth_cleanup_command()
            rc, out_text, err_text = _exec_sudo(cleanup_cmd, timeout=25.0, stage='stale_veth_cleanup')
            if rc != 0:
                try:
                    log_f.write(
                        f"{log_prefix}WARN: stale veth cleanup exited {rc}; continuing. "
                        f"stdout={_summarize_for_log((out_text or '').strip())} "
                        f"stderr={_summarize_for_log((err_text or '').strip())}\n"
                    )
                except Exception:
                    pass
        except Exception as exc:
            try:
                log_f.write(f"{log_prefix}WARN: stale veth cleanup failed: {exc}; continuing.\n")
            except Exception:
                pass
    else:
        try:
            log_f.write(f"{log_prefix}Stale CORE host veth cleanup is disabled by env.\n")
        except Exception:
            pass

    # Prepare remote context and uploads
    import tempfile
    tmp_xml = None
    try:
        if not xml_path and session_xml_str:
            with tempfile.NamedTemporaryFile('w', delete=False, suffix='.xml', encoding='utf-8') as tf:
                tf.write(session_xml_str)
                tmp_xml = tf.name
            xml_path = tmp_xml

        if not xml_path:
             _fail_run("No XML path or content provided for execution", code=1)
             return

        try:
            log_f.write(f"{log_prefix}Preparing remote workspace and uploads...\n")
        except Exception:
            pass

        last_prepare_exc: Optional[Exception] = None
        for prepare_attempt in range(2):
            try:
                remote_ctx = _prepare_remote_cli_context(
                     client=remote_client,
                     run_id=run_id_local,
                     xml_path=xml_path,
                     preview_plan_path=preview_plan_path,
                     log_handle=log_f,
                     upload_only_injected_artifacts=upload_only_injected_artifacts,
                     core_cfg=core_cfg,
                )
                last_prepare_exc = None
                break
            except Exception as exc:
                last_prepare_exc = exc
                should_retry = prepare_attempt == 0 and _is_transient_remote_prepare_error(exc)
                if not should_retry:
                    raise
                try:
                    log_f.write(f"{log_prefix}Transient remote prep error ({exc}); reconnecting SSH and retrying once...\n")
                except Exception:
                    pass
                try:
                    if remote_client:
                        remote_client.close()
                except Exception:
                    pass
                remote_client = _open_ssh_client(core_cfg)
        if last_prepare_exc is not None and remote_ctx is None:
            raise last_prepare_exc
    except Exception as exc:
        if tmp_xml and os.path.exists(tmp_xml):
            try: os.remove(tmp_xml)
            except Exception: pass
        if str(exc).strip() == FLOW_REMOTE_ARTIFACTS_MISSING_MESSAGE:
            _fail_run(FLOW_REMOTE_ARTIFACTS_MISSING_MESSAGE, code=1)
        else:
            _fail_run(f"Failed to prepare remote CLI context: {exc}", code=1)
        return
    
    if tmp_xml and os.path.exists(tmp_xml):
        try: os.remove(tmp_xml)
        except Exception: pass

    # Build CLI command
    try:
        remote_python = _select_remote_python_interpreter(remote_client, core_cfg)
        
        cli_args = [
            remote_python,
            '-u',
            '-m',
            'scenarioforge.cli',
            'execute',
            '--xml',
            remote_ctx['xml_path'],
            '--host',
            core_host,
            '--port',
            str(core_port),
        ]
        try:
            cli_verbose = str(os.getenv('CORETG_WEBAPP_CLI_VERBOSE') or '').strip().lower() in ('1', 'true', 'yes', 'y', 'on')
        except Exception:
            cli_verbose = False
        try:
            if (not cli_verbose) and str(os.getenv('WEBAPP_LOG_LEVEL') or '').strip().upper() == 'DEBUG':
                cli_verbose = True
        except Exception:
            pass
        if cli_verbose:
            cli_args.append('--verbose')
        if docker_remove_conflicts:
            cli_args.append('--docker-remove-conflicts')
        if seed is not None:
            cli_args.extend(['--seed', str(seed)])
        
        # Determine active scenario name if not hinted
        active_scen = scenario_name_hint
        if not active_scen:
            # Try to get from remote_ctx? No, we parsed it earlier?
            # We don't have local elementtree strict check here.
            # But the CLI handles it.
            pass
        
        if active_scen:
            cli_args.extend(['--scenario', active_scen])
        
        if remote_ctx.get('preview_plan_path'):
            cli_args.extend(['--preview-plan', remote_ctx['preview_plan_path']])

        core_start_timeout_s = _webui_remote_core_start_timeout_s()
        docker_wait_s = _webui_remote_docker_wait_s()
        if core_start_timeout_s is not None:
            cli_args.extend(['--start-timeout-s', _format_runtime_timeout_arg(core_start_timeout_s)])
        if docker_wait_s is not None:
            cli_args.extend(['--docker-wait-s', _format_runtime_timeout_arg(docker_wait_s)])
        
        cli_cmd = ' '.join(shlex.quote(arg) for arg in cli_args)
        work_dir = remote_ctx['repo_dir']
        
        venv_bin_remote = str(core_cfg.get('venv_bin') or '').strip()
        activate_prefix = ''
        if venv_bin_remote:
            activate_path = posixpath.join(venv_bin_remote.rstrip('/'), 'activate')
            activate_prefix = f". {shlex.quote(activate_path)} >/dev/null 2>&1 || true; "
        
        # For remote SSH runs, default to sudo-backed docker and strict pull.
        # This ensures the CLI can preflight (pull/build) images *before* CORE's
        # core-daemon tries to start docker nodes.
        docker_env_parts: list[str] = []
        docker_use_sudo = core_cfg.get('docker_use_sudo')
        docker_strict_pull = core_cfg.get('docker_strict_pull')
        docker_build_pull = core_cfg.get('docker_build_pull')

        if docker_use_sudo is None:
            docker_use_sudo = True
        if docker_strict_pull is None:
            docker_strict_pull = True
        if docker_build_pull is None:
            docker_build_pull = False

        if _coerce_bool(docker_use_sudo):
            docker_env_parts.append('CORETG_DOCKER_USE_SUDO=1')
        if _coerce_bool(docker_strict_pull):
            docker_env_parts.append('CORETG_DOCKER_STRICT_PULL=1')

        # Explicitly set build-pull to override any remote VM environment defaults.
        # `docker build --pull` can trigger registry metadata fetches even when cached.
        docker_env_parts.append('CORETG_DOCKER_BUILD_PULL=1' if _coerce_bool(docker_build_pull) else 'CORETG_DOCKER_BUILD_PULL=0')

        # CORE docker nodes expect to be able to address the container by node name.
        # Inject `container_name: <node>` into generated compose by default.
        docker_env_parts.append('CORETG_COMPOSE_SET_CONTAINER_NAME=1')

        if core_cfg.get('ssh_password') and _coerce_bool(docker_use_sudo):
            docker_env_parts.append('CORETG_DOCKER_SUDO_PASSWORD_STDIN=1')
        
        docker_env_prefix = (' '.join(docker_env_parts) + ' ') if docker_env_parts else ''
        flow_env_parts: list[str] = [
            'CORETG_FLOW_ARTIFACTS_MODE=copy',
            'CORETG_CLI_REMOTE_DELEGATED=1',
        ]
        if remote_ctx.get('base_dir'):
             flow_env_parts.append(f"CORE_REMOTE_BASE_DIR={shlex.quote(str(remote_ctx.get('base_dir')))}")
        
        flow_env_prefix = (' '.join(flow_env_parts) + ' ') if flow_env_parts else ''
        
        # Define scenario_tag (was missing)
        scenario_tag = 'scenario'
        try:
            out_dir_for_tag = os.path.dirname(xml_path) if xml_path else ''
            upload_base = os.path.basename(out_dir_for_tag) if out_dir_for_tag else ''
            parts = []
            if upload_base:
                parts.append(upload_base)
            if scenario_name_hint:
                parts.append(scenario_name_hint)
            
            # _safe_name is defined at module level (even if later in file), so valid at runtime
            candidate = '-'.join(parts) if parts else (scenario_name_hint or 'scenario')
            scenario_tag = _safe_name(candidate)
        except Exception:
            pass
        try:
            meta_tag = RUNS.get(run_id_local)
            if isinstance(meta_tag, dict):
                meta_tag['scenario_tag'] = scenario_tag
        except Exception:
            pass

        remote_command = (
            f"{activate_prefix}cd {shlex.quote(work_dir)} && "
            f"CORETG_SCENARIO_TAG={shlex.quote(scenario_tag)} {flow_env_prefix}{docker_env_prefix}PYTHONUNBUFFERED=1 {cli_cmd}"
        )

        try:
             log_f.write(f"{log_prefix}Starting CLI execution...\n")
             log_f.write(f"{log_prefix}Command: {cli_cmd}\n")
        except Exception:
             pass

    except Exception as exc:
        _fail_run(f"Failed to construct CLI command: {exc}", code=1)
        return

    # Execute SSH command
    exit_code = -1
    try:
        # Use get_pty=True to merge stdout/stderr and ensure unbuffered output
        stdin, stdout, stderr = remote_client.exec_command(remote_command, get_pty=True, timeout=None)
        
        # Pass sudo password to stdin if requested
        if 'CORETG_DOCKER_SUDO_PASSWORD_STDIN=1' in docker_env_parts:
            try:
                stdin.write(str(core_cfg.get('ssh_password')) + '\n')
                stdin.flush()
            except Exception:
                pass
        
        try:
            stdin.close()
        except Exception:
            pass
        
        _relay_remote_channel_to_log(
            stdout.channel,
            log_f,
            redact_tokens=[str(core_cfg.get('ssh_password') or '')],
        )
        
        exit_code = stdout.channel.recv_exit_status()
        _close_ssh_command_streams(None, stdout, stderr)
        
    except Exception as exc:
        _fail_run(f"SSH command execution failed: {exc}", code=1)
        try:
            remote_client.close()
        except:
            pass
        return

    # Finalize run
    try:
        final_status = "completed" if exit_code == 0 else "failed"
        log_f.write(f"\n{log_prefix}Process finished with exit code {exit_code}\n")
        
        RUNS[run_id_local]['status'] = final_status
        RUNS[run_id_local]['returncode'] = exit_code

        # IMPORTANT: perform postrun Flow artifact copy immediately on completion.
        # Relying on /run_status polling is fragile (RUNS is in-memory and can be lost
        # on webapp restart). This step populates /flow_artifacts and /flow_injects
        # inside vuln containers when CORETG_FLOW_ARTIFACTS_MODE=copy.
        try:
            _maybe_copy_flow_artifacts_into_containers(RUNS.get(run_id_local), stage='postrun')
        except Exception as exc:
            try:
                log_f.write(f"{log_prefix}docker.copy_flow_artifacts(postrun) failed: {exc}\n")
            except Exception:
                pass

        RUNS[run_id_local]['done'] = True
        
        # Do not append run history here. Canonical history persistence happens in
        # run_status once report/summary/session artifacts and validation are resolved.

    except Exception:
        pass
    finally:
        try:
            log_f.close()
        except:
            pass
        try:
            remote_client.close()
        except:
            pass
        # Close tunnel if it was tracked (we didn't track it explicitly in this scope, 
        # but _open_ssh_client might have attached it to client? 
        # Actually _open_ssh_client returns a client. The tunnel is managed globally or by client?)
        # In api_run_cli_async, it tracks ssh_tunnel separately.
        # Here we don't have access to the tunnel object unless we returned it from _open_ssh_client or passed it.
        # But if the client is closed, the tunnel (if part of transport) should close?
        # If it's a separate process/thread, it might linger.
        # However, for this refactor, letting Paramiko handle it is likely fine.






