# ---------------- Flag Catalog / Generator Packs -----------------


def _require_builder_or_admin() -> None:
    user = _current_user()
    if not user or not _is_admin_view_role(user.get('role')):
        abort(403)


def _split_lines(value: Any) -> list[str]:
    if value is None:
        return []
    if isinstance(value, list):
        out: list[str] = []
        for v in value:
            if v is None:
                continue
            s = str(v).strip()
            if s:
                out.append(s)
        return out
    text = str(value)
    return [s.strip() for s in text.splitlines() if s.strip()]


def _split_artifact_list(value: Any) -> list[str]:
    """Coerce an artifact list.

    Accepts:
      - list[str]
      - list[dict] with {'artifact': '...'}
      - newline-delimited str
    """
    if value is None:
        return []
    if isinstance(value, list):
        out: list[str] = []
        for item in value:
            if item is None:
                continue
            if isinstance(item, dict):
                s = str(item.get('artifact') or '').strip()
            else:
                s = str(item).strip()
            if s:
                out.append(s)
        return out
    return _split_lines(value)


def _normalize_inject_candidate_paths(value: Any) -> list[str]:
    if value is None:
        return []
    if isinstance(value, list):
        raw_items = value
    else:
        raw_items = re.split(r'[\n,]+', str(value or ''))

    normalized: list[str] = []
    seen: set[str] = set()
    for item in raw_items:
        candidate = str(item or '').strip().rstrip('/')
        if candidate == '':
            continue
        if not candidate.startswith('/'):
            continue
        parts = [part for part in candidate.split('/') if part]
        if any(part == '..' for part in parts):
            continue
        candidate = candidate or '/'
        if candidate not in seen:
            seen.add(candidate)
            normalized.append(candidate)
    return normalized


def _normalize_access_instructions(value: Any) -> dict[str, Any]:
    if isinstance(value, str) and value.strip():
        try:
            parsed = json.loads(value)
        except Exception:
            parsed = None
        value = parsed
    if not isinstance(value, dict):
        return {}
    steps = value.get('steps')
    if not isinstance(steps, list) or not steps:
        return {}
    normalized_steps: list[dict[str, Any]] = []
    for index, item in enumerate(steps, start=1):
        if not isinstance(item, dict):
            continue
        instructions = str(item.get('instructions') or '').strip()
        title = str(item.get('title') or '').strip()
        if not instructions and not title:
            continue
        record: dict[str, Any] = {
            'step': item.get('step') if item.get('step') is not None else index,
            'title': title or f'Step {index}',
            'instructions': instructions,
        }
        vars_value = item.get('vars')
        if isinstance(vars_value, dict) and vars_value:
            record['vars'] = {str(key): str(val) for key, val in vars_value.items() if str(key or '').strip()}
        normalized_steps.append(record)
    if not normalized_steps:
        return {}
    title = str(value.get('title') or '').strip() or 'Access Instructions'
    return {'title': title, 'steps': normalized_steps}


def _normalize_scaffold_hint_levels(value: Any) -> dict[str, list[str]]:
    if isinstance(value, str) and value.strip():
        try:
            parsed = json.loads(value)
        except Exception:
            parsed = None
        value = parsed
    if not isinstance(value, dict):
        return {}
    normalized: dict[str, list[str]] = {}
    for level in ('low', 'medium', 'high'):
        entries = _split_lines(value.get(level))
        if entries:
            normalized[level] = entries
    return normalized


def _default_scaffold_hint_levels(produces: list[str]) -> dict[str, list[str]]:
    artifacts = [str(item or '').strip() for item in (produces or []) if str(item or '').strip()]

    def _compact(value: str) -> str:
        return re.sub(r'\s+', '', str(value or '')).lower()

    priority = (
        'File(path)',
        'Credential(user,password)',
        'Credential(user, password)',
        'Credential(user)',
        'Token(service)',
        'APIKey(service)',
        'PortForward(host,port)',
        'PortForward(host, port)',
        'Endpoint(path)',
        'Knowledge(value)',
    )
    by_compact = {_compact(item): item for item in artifacts}
    chosen = ''
    for wanted in priority:
        chosen = by_compact.get(_compact(wanted), '')
        if chosen:
            break
    if not chosen:
        chosen = next((item for item in artifacts if _compact(item) != _compact('Flag(flag_id)')), '')

    if chosen:
        medium = f"Artifact or service: {{{{OUTPUT.{chosen}}}}}"
    else:
        medium = 'Inspect the target service or generated artifact for the next clue.'

    return {
        'low': ['Target: {{NEXT_NODE_IP}}'],
        'medium': [medium],
        'high': ['Use the access instructions and README.md for the complete workflow.'],
    }


def _ensure_scaffold_hint_levels(value: Any, produces: list[str]) -> dict[str, list[str]]:
    normalized = _normalize_scaffold_hint_levels(value)
    defaults = _default_scaffold_hint_levels(produces)
    for level in ('low', 'medium', 'high'):
        if not normalized.get(level):
            normalized[level] = list(defaults.get(level) or [])
    return normalized


def _manifest_yaml_block(value: Any) -> str:
    try:
        import yaml  # type: ignore

        text = yaml.safe_dump(value, sort_keys=False, allow_unicode=True, default_flow_style=False).rstrip()
    except Exception:
        text = json.dumps(value, indent=2)
    return textwrap.indent(text, '  ')


def _normalize_requires_with_optional(payload: dict[str, Any]) -> tuple[list[str], list[str]]:
    """Return (required_requires, optional_requires)."""
    req_items = payload.get('requires')
    if req_items is None:
        optional_set = {x for x in _split_artifact_list(payload.get('optional_requires')) if x}
        return [], sorted(optional_set)

    if isinstance(req_items, list) and all(isinstance(x, dict) for x in req_items):
        required: list[str] = []
        optional: list[str] = []
        for item in req_items:
            art = str(item.get('artifact') or '').strip()
            if not art:
                continue
            is_opt = _coerce_bool(item.get('optional'), False)
            if is_opt:
                optional.append(art)
            else:
                required.append(art)
        required_set = {x for x in required if x}
        optional_set = {x for x in optional if x and x not in required_set}
        return sorted(required_set), sorted(optional_set)

    raise ValueError('requires must be a list of {artifact, optional} objects')


def _normalize_plugin_type(raw: Any) -> str:
    value = (str(raw or '')).strip()
    if value not in {'flag-generator', 'flag-node-generator'}:
        return 'flag-generator'
    return value


def _sanitize_id(raw: Any) -> str:
    value = (str(raw or '')).strip()
    value = re.sub(r'[^a-zA-Z0-9_.\-]+', '_', value)
    value = re.sub(r'_+', '_', value).strip('_')
    return value


def _sanitize_folder(raw: Any) -> str:
    value = (str(raw or '')).strip()
    value = value.replace('\\', '/').strip('/')
    value = re.sub(r'[^a-zA-Z0-9_\-/\.]+', '_', value)
    value = value.split('/', 1)[0]
    value = value.strip().strip('.')
    value = re.sub(r'_+', '_', value)
    return value


def _inputs_schema_from_flags(flags: dict[str, Any], *, plugin_type: str) -> dict[str, Any]:
    inputs: dict[str, Any] = {}

    def _add(name: str, *, sensitive: bool = False, required: bool = True) -> None:
        inputs[name] = {'type': 'string', 'required': bool(required)}
        if sensitive:
            inputs[name]['sensitive'] = True

    if flags.get('seed'):
        _add('seed', required=True)
    if flags.get('secret') and plugin_type == 'flag-generator':
        _add('secret', sensitive=True, required=True)
    if flags.get('node_name') and plugin_type == 'flag-node-generator':
        _add('node_name', required=True)
    if flags.get('flag_prefix'):
        _add('flag_prefix', required=False)
    return inputs


def _normalize_runtime_inputs(raw_inputs: Any, *, plugin_type: str) -> list[dict[str, Any]]:
    if isinstance(raw_inputs, list):
        normalized: list[dict[str, Any]] = []
        seen_names: set[str] = set()
        for item in raw_inputs:
            if not isinstance(item, dict):
                continue
            name = str(item.get('name') or '').strip()
            if not name or name in seen_names:
                continue
            seen_names.add(name)
            record: dict[str, Any] = {
                'name': name,
                'type': str(item.get('type') or 'string').strip() or 'string',
                'required': bool(item.get('required', True)),
            }
            if item.get('sensitive') is True:
                record['sensitive'] = True
            if _flow_truthy_flag(item.get('flow_supply_when_first')):
                record['flow_supply_when_first'] = True
            normalized.append(record)
        return normalized

    flags = raw_inputs if isinstance(raw_inputs, dict) else {}
    inputs_schema = _inputs_schema_from_flags(flags, plugin_type=plugin_type)
    normalized = []
    for name, meta in (inputs_schema or {}).items():
        nm = str(name or '').strip()
        if not nm:
            continue
        record: dict[str, Any] = {
            'name': nm,
            'type': str((meta or {}).get('type') or 'string').strip() or 'string',
            'required': bool((meta or {}).get('required', True)),
        }
        if (meta or {}).get('sensitive') is True:
            record['sensitive'] = True
        if _flow_truthy_flag((meta or {}).get('flow_supply_when_first')):
            record['flow_supply_when_first'] = True
        normalized.append(record)
    return normalized


def _build_generator_scaffold(payload: dict[str, Any]) -> tuple[dict[str, str], str, str]:
    plugin_type = _normalize_plugin_type(payload.get('plugin_type'))
    plugin_id = _sanitize_id(payload.get('plugin_id'))
    if not plugin_id:
        raise ValueError('plugin_id is required')

    folder_name = _sanitize_folder(payload.get('folder_name'))
    if not folder_name:
        folder_name = f"py_{plugin_id}"
    if folder_name.startswith('py__'):
        folder_name = folder_name.replace('py__', 'py_', 1)
    if folder_name == 'py_':
        folder_name = f"py_{plugin_id}"

    display_name = str(payload.get('name') or '').strip() or plugin_id
    description = str(payload.get('description') or '').strip() or f"Generator {plugin_id}"

    requires, optional_requires = _normalize_requires_with_optional(payload)
    produces = _split_artifact_list(payload.get('produces'))
    hint_levels = _normalize_scaffold_hint_levels(payload.get('hint_levels'))
    inject_files_raw = payload.get('inject_files')
    inject_files = []
    if isinstance(inject_files_raw, list):
        for x in inject_files_raw:
            s = str(x or '').strip()
            if s:
                inject_files.append(s)
    inject_candidate_paths = _normalize_inject_candidate_paths(payload.get('inject_candidate_paths'))
    access_instructions = _normalize_access_instructions(payload.get('access_instructions'))

    if 'Flag(flag_id)' not in produces and 'flag' not in produces:
        produces = ['Flag(flag_id)'] + produces
    if plugin_type == 'flag-node-generator' and 'File(path)' not in produces:
        produces.append('File(path)')
    hint_levels = _ensure_scaffold_hint_levels(hint_levels, produces)

    runtime_inputs_raw = payload.get('runtime_inputs')
    if runtime_inputs_raw is None:
        runtime_inputs_raw = payload.get('inputs')
    inputs_manifest = _normalize_runtime_inputs(runtime_inputs_raw, plugin_type=plugin_type)

    manifest_yaml = (
        "manifest_version: 1\n"
        f"id: {plugin_id}\n"
        f"kind: {plugin_type}\n"
        f"name: {display_name}\n"
        f"description: {description}\n"
        "version: 1.0\n"
        "\n"
        "runtime:\n"
        "  type: docker-compose\n"
        "  compose_file: docker-compose.yml\n"
        "  service: generator\n"
    )
    if inputs_manifest:
        manifest_yaml += "\ninputs:\n"
        for inp in inputs_manifest:
            try:
                nm = str(inp.get('name') or '').strip()
                if not nm:
                    continue
                manifest_yaml += f"  - name: {nm}\n"
                tp = str(inp.get('type') or 'string').strip() or 'string'
                manifest_yaml += f"    type: {tp}\n"
                if 'required' in inp:
                    manifest_yaml += f"    required: {'true' if bool(inp.get('required')) else 'false'}\n"
                if inp.get('sensitive') is True:
                    manifest_yaml += "    sensitive: true\n"
                if inp.get('flow_supply_when_first') is True:
                    manifest_yaml += "    flow_supply_when_first: true\n"
            except Exception:
                continue

    # Artifacts for Flow chaining.
    manifest_yaml += "\nartifacts:\n"
    manifest_yaml += "  requires:\n"
    for a in (requires or []):
        s = str(a or '').strip()
        if s:
            manifest_yaml += f"    - {s}\n"

    if optional_requires:
        manifest_yaml += "  optional_requires:\n"
        for a in (optional_requires or []):
            s = str(a or '').strip()
            if s:
                manifest_yaml += f"    - {s}\n"

    manifest_yaml += "  produces:\n"
    for a in (produces or []):
        s = str(a or '').strip()
        if s:
            manifest_yaml += f"    - {s}\n"

    # Hints
    if hint_levels:
        manifest_yaml += "\nhint_levels:\n"
        for level in ('low', 'medium', 'high'):
            values = hint_levels.get(level) or []
            if not values:
                continue
            manifest_yaml += f"  {level}:\n"
            for value in values:
                manifest_yaml += f"    - {json.dumps(str(value))}\n"

    # Injected artifacts allowlist for safe mounting.
    if inject_files:
        manifest_yaml += "\ninjects:\n"
        for x in inject_files:
            s = str(x or '').strip()
            if s:
                manifest_yaml += f"  - {s}\n"

    if inject_candidate_paths:
        manifest_yaml += "\ninject_candidate_paths:\n"
        for candidate_path in inject_candidate_paths:
            manifest_yaml += f"  - {candidate_path}\n"

    if access_instructions:
        manifest_yaml += "\naccess_instructions:\n"
        manifest_yaml += _manifest_yaml_block(access_instructions) + "\n"

    # Fixed env vars.
    gen_env = payload.get('env')
    if isinstance(gen_env, dict) and gen_env:
        manifest_yaml += "\nenv:\n"
        for k, v in gen_env.items():
            kk = str(k or '').strip()
            if not kk:
                continue
            vv = str(v if v is not None else '')
            vv2 = vv.replace('"', '\\"')
            manifest_yaml += f"  {kk}: \"{vv2}\"\n"

    base_dir = 'flag_generators' if plugin_type == 'flag-generator' else 'flag_node_generators'
    folder_path = f"{base_dir}/{folder_name}"

    compose_yaml = (
        "services:\n"
        "  generator:\n"
        "    image: python:3.12-slim\n"
        "    working_dir: /app\n"
        "    command: [\"python\", \"/app/generator.py\"]\n"
        "    environment:\n"
        "      INPUTS_DIR: ${INPUTS_DIR}\n"
        "      OUTPUTS_DIR: ${OUTPUTS_DIR}\n"
        "    volumes:\n"
        "      - ./generator.py:/app/generator.py:ro\n"
        "      - ${INPUTS_DIR}:/inputs:ro\n"
        "      - ${OUTPUTS_DIR}:/outputs\n"
    )

    compose_override = str(payload.get('compose_text') or '').strip('\n')
    if compose_override.strip():
        compose_yaml = compose_override + ("\n" if not compose_override.endswith("\n") else "")

    if plugin_type == 'flag-generator':
        generator_py = f"""import hashlib
import json
from pathlib import Path


def _read_config() -> dict:
    try:
        return json.loads(Path('/inputs/config.json').read_text('utf-8'))
    except Exception:
        return {{}}


def _flag(seed: str, secret: str, flag_prefix: str = 'FLAG') -> str:
    digest = hashlib.sha256(f"{{seed}}|{{secret}}|flag".encode('utf-8', 'replace')).hexdigest()[:24]
    prefix = (flag_prefix or 'FLAG').strip() or 'FLAG'
    return f"{{prefix}}{{{{{{digest}}}}}}"


def main() -> None:
    cfg = _read_config()
    seed = str(cfg.get('seed') or '').strip()
    secret = str(cfg.get('secret') or '').strip()
    flag_prefix = str(cfg.get('flag_prefix') or 'FLAG').strip() or 'FLAG'

    if not seed:
        raise SystemExit('Missing seed in /inputs/config.json')
    if not secret:
        raise SystemExit('Missing secret in /inputs/config.json')

    # TODO: implement your generator logic and add additional outputs.
    flag_value = _flag(seed, secret, flag_prefix)

    out_dir = Path('/outputs')
    out_dir.mkdir(parents=True, exist_ok=True)

    outputs = {{
        'generator_id': {json.dumps(plugin_id)},
        'outputs': {{
            'Flag(flag_id)': flag_value,
        }},
    }}

    (out_dir / 'outputs.json').write_text(json.dumps(outputs, indent=2) + '\n', encoding='utf-8')
    # Prefer hint_levels in the manifest/catalog for Flow participant hints.


if __name__ == '__main__':
    main()
"""
    else:
        generator_py = f"""import hashlib
import json
from pathlib import Path


def _read_config() -> dict:
    try:
        return json.loads(Path('/inputs/config.json').read_text('utf-8'))
    except Exception:
        return {{}}


def _flag(seed: str, node_name: str, flag_prefix: str = 'FLAG') -> str:
    digest = hashlib.sha256(f"{{seed}}|{{node_name}}|flag".encode('utf-8', 'replace')).hexdigest()[:16]
    prefix = (flag_prefix or 'FLAG').strip() or 'FLAG'
    return f"{{prefix}}{{{{{{digest}}}}}}"


def main() -> None:
    cfg = _read_config()
    seed = str(cfg.get('seed') or '').strip()
    node_name = str(cfg.get('node_name') or '').strip()
    flag_prefix = str(cfg.get('flag_prefix') or 'FLAG').strip() or 'FLAG'

    if not seed:
        raise SystemExit('Missing seed in /inputs/config.json')
    if not node_name:
        raise SystemExit('Missing node_name in /inputs/config.json')

    # TODO: implement your per-node compose generation.
    flag_value = _flag(seed, node_name, flag_prefix)
    compose_text = (
        "services:\n"
        "  node:\n"
        "    image: alpine:3.19\n"
        "    command: [\\"sh\\", \\"-lc\\", \\"echo \\\\\"$FLAG\\\\\" > /flag.txt && tail -f /dev/null\\"]\n"
        "    environment:\n"
        f"      FLAG: {{json.dumps(flag_value)}}\n"
    )

    out_dir = Path('/outputs')
    out_dir.mkdir(parents=True, exist_ok=True)
    (out_dir / 'docker-compose.yml').write_text(compose_text, encoding='utf-8')

    outputs = {{
        'generator_id': {json.dumps(plugin_id)},
        'outputs': {{
            'File(path)': 'docker-compose.yml',
            'Flag(flag_id)': flag_value,
        }},
    }}
    (out_dir / 'outputs.json').write_text(json.dumps(outputs, indent=2) + '\n', encoding='utf-8')


if __name__ == '__main__':
    main()
"""

    generator_override = str(payload.get('generator_py_text') or payload.get('generator_text') or '').strip('\n')
    if generator_override.strip():
        generator_py = generator_override + ("\n" if not generator_override.endswith("\n") else "")

    readme_override = str(payload.get('readme_text') or '')
    if readme_override and not readme_override.endswith('\n'):
        readme_override = readme_override + '\n'

    scaffold_files: dict[str, str] = {
        f"{folder_path}/docker-compose.yml": compose_yaml,
        f"{folder_path}/generator.py": generator_py,
        f"{folder_path}/README.md": readme_override or f"# {display_name}\n\nTODO: describe this generator.\n\n- plugin_id: `{plugin_id}`\n- type: `{plugin_type}`\n",
        f"{folder_path}/manifest.yaml": manifest_yaml,
    }

    return scaffold_files, manifest_yaml, folder_path


def _validate_builder_scaffold_runtime_contract(scaffold_files: dict[str, str]) -> list[str]:
    manifest_path = ''
    manifest_text = ''
    generator_path = ''
    generator_text = ''
    for rel_path, content in (scaffold_files or {}).items():
        path_text = str(rel_path or '').strip()
        if not path_text:
            continue
        if not manifest_path and path_text.endswith(('/manifest.yaml', '/manifest.yml')):
            manifest_path = path_text
            manifest_text = str(content or '')
        elif not generator_path and path_text.endswith('/generator.py'):
            generator_path = path_text
            generator_text = str(content or '')

    if not manifest_path or not generator_path:
        return []

    declared_inputs: set[str] = set()
    manifest_doc: dict[str, Any] = {}
    try:
        import yaml  # type: ignore

        manifest_doc = yaml.safe_load(manifest_text) or {}
        if not isinstance(manifest_doc, dict):
            manifest_doc = {}
        manifest_inputs = manifest_doc.get('inputs')
        if isinstance(manifest_inputs, list):
            for item in manifest_inputs:
                if not isinstance(item, dict):
                    continue
                input_name = str(item.get('name') or '').strip()
                if input_name:
                    declared_inputs.add(input_name)
    except Exception:
        return []

    required_config_inputs: set[str] = set()
    missing_config_pattern = re.compile(r"Missing\s+([A-Za-z0-9_.-]+)\s+in\s+/inputs/config\.json", re.IGNORECASE)
    try:
        parsed = ast.parse(generator_text)
    except Exception:
        parsed = None
    if parsed is not None:
        for node in ast.walk(parsed):
            if not isinstance(node, ast.Call):
                continue
            if not isinstance(node.func, ast.Name) or node.func.id != 'SystemExit':
                continue
            if not node.args:
                continue
            first_arg = node.args[0]
            if not isinstance(first_arg, ast.Constant) or not isinstance(first_arg.value, str):
                continue
            match = missing_config_pattern.search(first_arg.value)
            if match:
                required_config_inputs.add(match.group(1))
    for match in missing_config_pattern.finditer(generator_text):
        required_config_inputs.add(match.group(1))

    errors: list[str] = []

    missing_from_manifest = sorted(required_config_inputs - declared_inputs)
    if missing_from_manifest:
        joined = ', '.join(missing_from_manifest)
        errors.append(
            'Generated scaffold is inconsistent: '
            f'{generator_path} requires runtime input(s) {joined} via /inputs/config.json, '
            f'but {manifest_path} does not declare them under inputs.'
        )

    levels = manifest_doc.get('hint_levels') if isinstance(manifest_doc, dict) else None
    missing_hint_levels: list[str] = []
    for level in ('low', 'medium', 'high'):
        values = (levels or {}).get(level) if isinstance(levels, dict) else None
        if not isinstance(values, list) or not any(str(item or '').strip() for item in values):
            missing_hint_levels.append(level)
    if missing_hint_levels:
        errors.append(
            'Generated scaffold is inconsistent: '
            f'{manifest_path} must define hint_levels.low, hint_levels.medium, and hint_levels.high '
            'with at least one non-empty hint each.'
        )

    return errors


