def _installed_generators_root() -> str:
    """Root directory for installed generator packs.

    Defaults to ./outputs/installed_generators under repo root.
    Overridable via CORETG_INSTALLED_GENERATORS_DIR for tests/dev.
    """
    env = str(os.environ.get('CORETG_INSTALLED_GENERATORS_DIR') or '').strip()
    if env:
        root = os.path.abspath(os.path.expanduser(env))
    else:
        try:
            repo_root = _get_repo_root()
        except Exception:
            repo_root = os.getcwd()
        root = os.path.join(repo_root, 'outputs', 'installed_generators')
    os.makedirs(root, exist_ok=True)
    return root


def _installed_generator_packs_state_path() -> str:
    return os.path.join(_installed_generators_root(), '_packs_state.json')


def _load_installed_generator_packs_state() -> dict:
    path = _installed_generator_packs_state_path()
    try:
        if not os.path.exists(path):
            state = {'packs': []}
            tmp = path + '.tmp'
            with open(tmp, 'w', encoding='utf-8') as fh:
                json.dump(state, fh, indent=2)
            os.replace(tmp, path)
            return state
        with open(path, 'r', encoding='utf-8') as fh:
            state = json.load(fh)
        if not isinstance(state, dict):
            return {'packs': []}
        if not isinstance(state.get('packs'), list):
            state['packs'] = []
        return state
    except Exception:
        return {'packs': []}


def _save_installed_generator_packs_state(state: dict) -> None:
    path = _installed_generator_packs_state_path()
    try:
        tmp = path + '.tmp'
        with open(tmp, 'w', encoding='utf-8') as fh:
            json.dump(state if isinstance(state, dict) else {'packs': []}, fh, indent=2)
        os.replace(tmp, path)
    except Exception:
        pass


def _snapshot_test_log_copy(*, source_log_path: str, subdir: str, file_stem: str) -> tuple[str | None, str | None]:
    src = str(source_log_path or '').strip()
    if not src or not os.path.isfile(src):
        return None, None

    safe_stem = re.sub(r'[^A-Za-z0-9_.-]+', '-', str(file_stem or '').strip()).strip('-') or 'test-log'
    dest_dir = os.path.join(_outputs_dir(), subdir)
    os.makedirs(dest_dir, exist_ok=True)
    filename = f'{safe_stem}-{_local_timestamp_safe()}.log'
    dest_path = os.path.join(dest_dir, filename)

    try:
        shutil.copy2(src, dest_path)
    except Exception:
        try:
            with open(src, 'r', encoding='utf-8', errors='ignore') as src_handle, open(dest_path, 'w', encoding='utf-8') as dest_handle:
                dest_handle.write(src_handle.read())
        except Exception:
            return None, None

    return dest_path, filename


def _normalize_installed_source_path(p: str) -> str:
    return str(p or '').replace('\\', '/').strip().lower()


def _is_installed_generator_view(gen: dict) -> bool:
    """Best-effort check that a generator came from outputs/installed_generators."""
    try:
        src = ''
        if isinstance(gen.get('source'), dict):
            src = str(gen.get('source', {}).get('path') or '')
        norm = _normalize_installed_source_path(src)
        if 'outputs/installed_generators' in norm:
            return True

        mp = str(gen.get('_source_path') or '').strip()
        if mp:
            # Check if it's under outputs/installed_generators
            installed_root = os.path.abspath(_installed_generators_root())
            abs_mp = os.path.abspath(mp)
            try:
                if os.path.commonpath([installed_root, abs_mp]) == installed_root:
                    return True
            except Exception:
                pass
    except Exception:
        return False
    return False


def _build_installed_disable_maps() -> tuple[dict[str, dict[str, Any]], dict[tuple[str, str], dict[str, Any]]]:
    """Return (pack_by_id, gen_by_kind_id) maps from the installed packs state."""
    state = _load_installed_generator_packs_state()
    packs = state.get('packs') if isinstance(state, dict) else None
    if not isinstance(packs, list):
        packs = []

    pack_by_id: dict[str, dict[str, Any]] = {}
    gen_by_kind_id: dict[tuple[str, str], dict[str, Any]] = {}

    for p in packs:
        if not isinstance(p, dict):
            continue
        pid = str(p.get('id') or '').strip()
        if not pid:
            continue
        pack_uninstalled = bool(p.get('uninstalled') is True)
        pack_disabled = bool(p.get('disabled') is True or pack_uninstalled)
        pack_label = str(p.get('label') or '').strip() or pid
        pack_by_id[pid] = {
            'id': pid,
            'label': pack_label,
            'disabled': pack_disabled,
            'uninstalled': pack_uninstalled,
            'origin': str(p.get('origin') or '').strip(),
        }
        for it in (p.get('installed') or []):
            if not isinstance(it, dict):
                continue
            gid = str(it.get('id') or '').strip()
            kind = str(it.get('kind') or '').strip()
            if not gid or not kind:
                continue
            item_uninstalled = bool(it.get('uninstalled') is True)
            item_disabled = bool(it.get('disabled') is True or item_uninstalled)
            info_obj = {
                'pack_id': pid,
                'pack_label': pack_label,
                'pack_disabled': pack_disabled,
                'pack_uninstalled': pack_uninstalled,
                'uninstalled': pack_uninstalled or item_uninstalled,
                'disabled': pack_disabled or item_disabled or item_uninstalled,
                'item_disabled': item_disabled,
                'item_uninstalled': item_uninstalled,
                'validated_ok': bool(it.get('validated_ok')) if it.get('validated_ok') is not None else None,
                'validated_incomplete': bool(it.get('validated_incomplete') is True),
                'validated_at': str(it.get('validated_at') or '').strip() or None,
                'last_test_log_path': str(it.get('last_test_log_path') or '').strip() or None,
                'last_test_log_filename': str(it.get('last_test_log_filename') or '').strip() or None,
                'disabled_due_to_missing_files': bool(it.get('disabled_due_to_missing_files') is True),
            }

            # Back-compat: generator packs may use numeric ids in the packs state,
            # but Flow/UI operate on stable `source_generator_id`. If we can
            # resolve a source id from the installed pack marker, map both.
            gen_by_kind_id[(kind, gid)] = info_obj
            try:
                pack_path = str(it.get('path') or '').strip()
                if pack_path:
                    marker_path = os.path.join(pack_path, '.coretg_pack.json')
                    if os.path.exists(marker_path) and os.path.isfile(marker_path):
                        with open(marker_path, 'r', encoding='utf-8') as fh:
                            marker = json.load(fh)
                        if isinstance(marker, dict):
                            src_id = str(marker.get('source_generator_id') or '').strip()
                            if src_id:
                                gen_by_kind_id.setdefault((kind, src_id), info_obj)
            except Exception:
                pass

    return pack_by_id, gen_by_kind_id


def _annotate_disabled_state(generators: list[dict], *, kind: str) -> list[dict]:
    """Annotate generator views with _disabled/_pack_* fields using pack state."""
    _pack_by_id, gen_by_kind_id = _build_installed_disable_maps()
    out: list[dict] = []
    for g in (generators or []):
        if not isinstance(g, dict):
            continue
        gid = str(g.get('id') or '').strip()
        info = gen_by_kind_id.get((kind, gid)) if gid else None
        g['_installed'] = True
        if info:
            g['_pack_id'] = info.get('pack_id')
            g['_pack_label'] = info.get('pack_label')
            g['_pack_disabled'] = bool(info.get('pack_disabled'))
            g['_pack_uninstalled'] = bool(info.get('pack_uninstalled'))
            g['_disabled'] = bool(info.get('disabled'))
            g['_item_disabled'] = bool(info.get('item_disabled'))
            g['_disabled_due_to_missing_files'] = bool(info.get('disabled_due_to_missing_files'))
            g['_item_uninstalled'] = bool(info.get('item_uninstalled'))
            g['_uninstalled'] = bool(info.get('uninstalled'))
            g['_validated_ok'] = info.get('validated_ok')
            g['_validated_incomplete'] = bool(info.get('validated_incomplete') is True)
            g['_validated_at'] = info.get('validated_at')
            g['_last_test_log_path'] = info.get('last_test_log_path')
            g['_last_test_log_filename'] = info.get('last_test_log_filename')
        else:
            g['_disabled'] = False
            g['_disabled_due_to_missing_files'] = False
            g['_uninstalled'] = False
            g['_validated_ok'] = None
            g['_validated_incomplete'] = False
            g['_validated_at'] = None
            g['_last_test_log_path'] = None
            g['_last_test_log_filename'] = None
        out.append(g)
    return out


def _is_installed_generator_disabled(*, kind: str, generator_id: str) -> bool:
    gid = str(generator_id or '').strip()
    if not gid:
        return False
    _pack_by_id, gen_by_kind_id = _build_installed_disable_maps()
    info = gen_by_kind_id.get((str(kind or '').strip(), gid))
    return bool(info and info.get('disabled') is True)


def _installed_generator_state_item_matches(*, item: dict[str, Any], kind: str, generator_id: str) -> bool:
    if not isinstance(item, dict):
        return False
    item_kind = str(item.get('kind') or '').strip().lower().replace('_', '-')
    target_kind = str(kind or '').strip().lower().replace('_', '-')
    if item_kind != target_kind:
        return False

    gid = str(generator_id or '').strip()
    if not gid:
        return False
    if str(item.get('id') or '').strip() == gid:
        return True

    try:
        pack_path = str(item.get('path') or '').strip()
        if not pack_path:
            return False
        marker_path = os.path.join(pack_path, '.coretg_pack.json')
        if not os.path.isfile(marker_path):
            return False
        with open(marker_path, 'r', encoding='utf-8') as fh:
            marker = json.load(fh)
        if not isinstance(marker, dict):
            return False
        return str(marker.get('source_generator_id') or '').strip() == gid
    except Exception:
        return False


def _set_generator_validation_state(
    *,
    kind: str,
    generator_id: str,
    validated_ok: bool | None,
    validated_incomplete: bool = False,
    log_path: str | None = None,
    log_filename: str | None = None,
) -> tuple[bool, str]:
    gid = str(generator_id or '').strip()
    if not gid:
        return False, 'Missing generator id'

    k = str(kind or '').strip().lower().replace('_', '-')
    if k not in ('flag-generator', 'flag-node-generator'):
        return False, f'Invalid kind: {kind}'

    state = _load_installed_generator_packs_state()
    packs = state.get('packs') if isinstance(state, dict) else None
    if not isinstance(packs, list):
        packs = []

    for pack in packs:
        if not isinstance(pack, dict):
            continue
        items = pack.get('installed')
        if not isinstance(items, list):
            continue
        for item in items:
            if not _installed_generator_state_item_matches(item=item, kind=k, generator_id=gid):
                continue
            if validated_ok is None:
                item['validated_ok'] = None
            else:
                item['validated_ok'] = bool(validated_ok)
            item['validated_incomplete'] = bool(validated_incomplete)
            item['validated_at'] = _local_timestamp_display()
            if isinstance(log_path, str) and log_path.strip():
                item['last_test_log_path'] = str(log_path).strip()
            if isinstance(log_filename, str) and log_filename.strip():
                item['last_test_log_filename'] = str(log_filename).strip()
            state['packs'] = packs
            _save_installed_generator_packs_state(state)
            if validated_ok is None:
                status_label = 'incomplete'
            else:
                status_label = 'success' if bool(validated_ok) else 'fail'
            return True, f'Updated {k} {gid} as {status_label}'

    return False, 'Installed generator not found'


def _persist_generator_test_result(
    *,
    kind: str,
    generator_id: str,
    generator_name: str,
    validated_ok: bool | None,
    validated_incomplete: bool = False,
    source_log_path: str | None = None,
) -> tuple[bool, str]:
    safe_name = re.sub(r'[^A-Za-z0-9_.-]+', '-', str(generator_name or generator_id or '').strip()).strip('-') or str(generator_id or 'generator')
    subdir = 'catalog-test-logs/flag_node_generators' if str(kind or '').strip().lower().replace('_', '-') == 'flag-node-generator' else 'catalog-test-logs/flag_generators'
    copied_log_path = None
    copied_log_name = None
    if isinstance(source_log_path, str) and source_log_path.strip():
        copied_log_path, copied_log_name = _snapshot_test_log_copy(
            source_log_path=source_log_path,
            subdir=subdir,
            file_stem=f'{safe_name}-{generator_id}',
        )
    return _set_generator_validation_state(
        kind=kind,
        generator_id=generator_id,
        validated_ok=validated_ok,
        validated_incomplete=validated_incomplete,
        log_path=copied_log_path,
        log_filename=copied_log_name,
    )


def _is_safe_remote_zip_url(url: str) -> tuple[bool, str]:
    """Basic SSRF guard: only allow http(s) and block private/reserved IPs."""
    try:
        from urllib.parse import urlparse
        import ipaddress
        import socket

        u = str(url or '').strip()
        if not u:
            return False, 'Missing URL'
        parsed = urlparse(u)
        if parsed.scheme not in ('http', 'https'):
            return False, 'Only http(s) URLs are allowed'
        host = parsed.hostname
        if not host:
            return False, 'Invalid URL host'
        if host.lower() in ('localhost',):
            return False, 'Blocked host'

        infos = socket.getaddrinfo(host, None)
        ips: set[str] = set()
        for info in infos:
            try:
                ips.add(str(info[4][0]))
            except Exception:
                continue
        if not ips:
            return False, 'Could not resolve host'
        for ip_s in ips:
            try:
                ip = ipaddress.ip_address(ip_s)
            except Exception:
                return False, f'Invalid resolved IP: {ip_s}'
            if (
                ip.is_loopback
                or ip.is_private
                or ip.is_link_local
                or ip.is_multicast
                or ip.is_reserved
                or ip.is_unspecified
            ):
                return False, f'Blocked IP: {ip}'
        return True, ''
    except Exception:
        # Fail closed.
        return False, 'URL validation failed'


def _download_zip_from_url(url: str, *, max_bytes: int = 50_000_000) -> bytes:
    ok, reason = _is_safe_remote_zip_url(url)
    if not ok:
        raise ValueError(reason)

    u = str(url or '').strip()
    try:
        import requests  # type: ignore

        resp = requests.get(u, stream=True, timeout=20)
        resp.raise_for_status()
        buf = bytearray()
        for chunk in resp.iter_content(chunk_size=1024 * 64):
            if not chunk:
                continue
            buf.extend(chunk)
            if len(buf) > max_bytes:
                raise ValueError('Download too large')
        return bytes(buf)
    except Exception:
        # Fallback to urllib
        from urllib.request import urlopen

        with urlopen(u, timeout=20) as r:  # nosec - guarded by _is_safe_remote_zip_url
            buf = r.read(max_bytes + 1)
        if len(buf) > max_bytes:
            raise ValueError('Download too large')
        return buf


# ---------------- Vulnerability Catalog Packs -----------------


def _installed_vuln_catalogs_root() -> str:
    return os.path.join(_outputs_dir(), 'installed_vuln_catalogs')


def _vuln_catalogs_state_path() -> str:
    return os.path.join(_installed_vuln_catalogs_root(), '_catalogs_state.json')


def _load_vuln_catalogs_state() -> dict:
    try:
        p = _vuln_catalogs_state_path()
        if not os.path.exists(p):
            return {'catalogs': [], 'active_id': ''}
        with open(p, 'r', encoding='utf-8') as f:
            obj = json.load(f)
        if not isinstance(obj, dict):
            return {'catalogs': [], 'active_id': ''}
        obj.setdefault('catalogs', [])
        obj.setdefault('active_id', '')
        return obj
    except Exception:
        return {'catalogs': [], 'active_id': ''}


def _write_vuln_catalogs_state(state: dict) -> None:
    os.makedirs(_installed_vuln_catalogs_root(), exist_ok=True)
    p = _vuln_catalogs_state_path()
    tmp = p + '.tmp'
    with open(tmp, 'w', encoding='utf-8') as f:
        json.dump(state, f, indent=2, sort_keys=True)
    os.replace(tmp, p)


def _vuln_catalog_pack_dir(catalog_id: str) -> str:
    return os.path.join(_installed_vuln_catalogs_root(), str(catalog_id))


def _vuln_catalog_pack_zip_path(catalog_id: str) -> str:
    return os.path.join(_vuln_catalog_pack_dir(catalog_id), 'catalog.zip')


def _vuln_catalog_pack_content_dir(catalog_id: str) -> str:
    return os.path.join(_vuln_catalog_pack_dir(catalog_id), 'content')


def _active_vuln_catalog_label() -> str:
    """Return the active vulnerability catalog pack label (best-effort)."""
    try:
        state = _load_vuln_catalogs_state()
        active_id = str(state.get('active_id') or '').strip() if isinstance(state, dict) else ''
        catalogs = state.get('catalogs') if isinstance(state, dict) else None
        if not active_id or not isinstance(catalogs, list):
            return ''
        for c in catalogs:
            if not isinstance(c, dict):
                continue
            cid = str(c.get('id') or '').strip()
            if cid != active_id:
                continue
            label = str(c.get('label') or c.get('name') or '').strip()
            return label or cid
    except Exception:
        return ''
    return ''


def _safe_path_under(base_dir: str, subpath: str) -> str:
    """Resolve a user-provided subpath under base_dir safely."""
    base_abs = os.path.abspath(base_dir)
    rel = str(subpath or '').replace('\\', '/').strip()
    rel = rel.lstrip('/')
    parts = [p for p in rel.split('/') if p not in ('', '.')]
    if any(p == '..' for p in parts):
        raise ValueError('Invalid path')
    out = os.path.abspath(os.path.join(base_abs, *parts))
    if out == base_abs:
        return out
    if not out.startswith(base_abs + os.sep):
        raise ValueError('Path escaped base directory')
    return out


def _pick_vuln_csv_from_zip(zf: zipfile.ZipFile) -> str | None:
    names = [n for n in (zf.namelist() or []) if isinstance(n, str)]
    preferred = [n for n in names if n.lower().endswith('/vuln_list_w_url.csv') or n.lower() == 'vuln_list_w_url.csv']
    if preferred:
        preferred.sort(key=lambda s: (s.count('/'), len(s)))
        return preferred[0]
    alt = [n for n in names if n.lower().endswith('/vuln_list.csv') or n.lower() == 'vuln_list.csv']
    if alt:
        alt.sort(key=lambda s: (s.count('/'), len(s)))
        return alt[0]
    return None


def _install_vuln_catalog_zip_file_single(*, zip_file_path: str, label: str, origin: str) -> dict:
    os.makedirs(_installed_vuln_catalogs_root(), exist_ok=True)
    catalog_id = _local_timestamp_safe() + '-' + secrets.token_hex(3)
    pack_dir = _vuln_catalog_pack_dir(catalog_id)
    os.makedirs(pack_dir, exist_ok=True)

    zip_path = _vuln_catalog_pack_zip_path(catalog_id)
    shutil.copyfile(str(zip_file_path), zip_path)

    csv_rel_paths: list[str] = []
    compose_items: list[dict[str, Any]] = []
    try:
        # Extract the entire ZIP directory tree so compose directories (and their
        # support files) are preserved.
        content_dir = _vuln_catalog_pack_content_dir(catalog_id)
        _safe_extract_zip_to_dir(zip_path, content_dir)
        try:
            from scenarioforge.compose_dependencies import missing_dependency_paths, scan_compose_dependencies
        except Exception:
            missing_dependency_paths = None  # type: ignore
            scan_compose_dependencies = None  # type: ignore

        # Discover all directories containing docker-compose.yml (required).
        compose_paths: list[tuple[str, str]] = []
        for dirpath, _dirnames, filenames in os.walk(content_dir):
            if '__MACOSX' in dirpath:
                continue
            if not filenames:
                continue
            if 'docker-compose.yml' not in filenames:
                continue
            compose_path = os.path.join(dirpath, 'docker-compose.yml')
            if not os.path.isfile(compose_path):
                continue
            rel_dir = os.path.relpath(dirpath, content_dir).replace('\\', '/')
            name = rel_dir if rel_dir not in ('.', '') else 'root'
            compose_paths.append((name, compose_path))

        if not compose_paths:
            raise ValueError('ZIP must contain at least one directory with docker-compose.yml')

        # Build item metadata (stable numeric id; UI name uses the parent folder name).
        norm_label = str(label or '').strip()
        for idx, (rel_name, compose_path) in enumerate(sorted(compose_paths, key=lambda t: t[0]), start=1):
            rel_dir = rel_name
            # Display name should include the parent folder when nested: <parent>/<leaf>.
            if rel_dir in ('', '.', 'root'):
                display_name = 'root'
            else:
                parts = [p for p in str(rel_dir).replace('\\', '/').split('/') if p]
                if len(parts) >= 2:
                    display_name = f"{parts[-2]}/{parts[-1]}"
                else:
                    display_name = parts[-1] if parts else 'root'
            compose_rel = os.path.relpath(compose_path, content_dir).replace('\\', '/')
            dir_rel = os.path.relpath(os.path.dirname(compose_path), content_dir).replace('\\', '/')
            compose_dependency_summary: dict[str, Any] = {}
            if scan_compose_dependencies is not None and missing_dependency_paths is not None:
                try:
                    compose_dependency_summary = scan_compose_dependencies(compose_path)
                except Exception:
                    compose_dependency_summary = {}
            required_files = compose_dependency_summary.get('requires') or []
            missing_required_files = missing_dependency_paths(compose_dependency_summary) if missing_dependency_paths is not None else []
            auto_disabled = bool(missing_required_files)
            compose_items.append({
                'id': idx,
                'name': display_name,
                'rel_dir': rel_dir,
                'dir_rel': dir_rel,
                'compose_rel': compose_rel,
                # Keep repo-relative paths for convenience / compatibility.
                'compose_path': os.path.relpath(compose_path, _get_repo_root()).replace('\\', '/'),
                'dir': os.path.relpath(os.path.dirname(compose_path), _get_repo_root()).replace('\\', '/'),
                'from_source': norm_label,
                'disabled': auto_disabled,
                'disabled_due_to_missing_files': auto_disabled,
                'required_files': required_files,
                'missing_required_files': missing_required_files,
                'compose_dependency_warning': str(compose_dependency_summary.get('warning') or '').strip(),
            })

        # Generate a catalog CSV from discovered compose directories.
        out_path = os.path.join(pack_dir, 'vuln_list_w_url.csv')
        with open(out_path, 'w', newline='', encoding='utf-8') as f:
            w = csv.writer(f)
            w.writerow(['Name', 'Path', 'Type', 'Vector', 'Startup', 'CVE', 'Description', 'References'])
            for it in compose_items:
                if bool(it.get('disabled', False)):
                    continue
                abs_compose = os.path.abspath(os.path.join(content_dir, str(it.get('compose_rel') or 'docker-compose.yml')))
                w.writerow([str(it.get('name') or ''), abs_compose, 'docker-compose', '', '', '', '', ''])

        # Validate generated CSV is parseable and non-empty.
        try:
            from scenarioforge.utils.vuln_process import _read_csv as _read_vuln_csv
            enabled_compose_items = [it for it in compose_items if not bool(it.get('disabled', False))]
            if enabled_compose_items and not _read_vuln_csv(out_path):
                raise ValueError('Generated catalog CSV parsed as empty')
        except Exception as exc:
            raise ValueError(f'Invalid vulnerability catalog CSV: {exc}')

        csv_rel_paths = [os.path.relpath(out_path, _get_repo_root())]
    except Exception:
        shutil.rmtree(pack_dir, ignore_errors=True)
        raise

    entry = {
        'id': catalog_id,
        'label': str(label or '').strip() or catalog_id,
        'from_source': str(label or '').strip() or catalog_id,
        'origin': str(origin or '').strip(),
        'installed_at': _local_timestamp_display(),
        'csv_paths': csv_rel_paths,
        'content_dir': os.path.relpath(_vuln_catalog_pack_content_dir(catalog_id), _get_repo_root()).replace('\\', '/'),
        'compose_items': compose_items,
        'compose_count': len(compose_items),
        'missing_required_file_count': sum(
            len(item.get('missing_required_files') or [])
            for item in compose_items
            if isinstance(item, dict)
        ),
    }

    state = _load_vuln_catalogs_state()
    catalogs = state.get('catalogs')
    if not isinstance(catalogs, list):
        catalogs = []
    catalogs.append(entry)
    state['catalogs'] = catalogs
    if not str(state.get('active_id') or '').strip():
        state['active_id'] = catalog_id
    _write_vuln_catalogs_state(state)
    return entry


def _install_vuln_catalog_zip_file(*, zip_file_path: str, label: str, origin: str) -> dict:
    """Install a vulnerability catalog ZIP or an export_all bundle of catalog ZIPs."""
    nested_archives: list[str] = []
    catalog_manifest_by_archive: dict[str, dict[str, Any]] = {}

    try:
        with zipfile.ZipFile(zip_file_path, 'r') as archive:
            names = [str(name or '').replace('\\', '/') for name in archive.namelist()]
            has_compose = any(name == 'docker-compose.yml' or name.endswith('/docker-compose.yml') for name in names)
            manifest_name = next((name for name in names if name == 'catalogs.json' or name.endswith('/catalogs.json')), '')
            nested_all = [
                name for name in names
                if name and not name.endswith('/') and name.lower().endswith('.zip') and not name.startswith('__MACOSX/')
            ]
            nested_archives = [name for name in nested_all if name.startswith('catalogs/')]
            if not nested_archives:
                nested_archives = nested_all

            if manifest_name:
                try:
                    manifest_doc = json.loads(archive.read(manifest_name).decode('utf-8', errors='ignore') or '{}')
                    catalogs = manifest_doc.get('catalogs') if isinstance(manifest_doc, dict) else []
                    if isinstance(catalogs, list):
                        for item in catalogs:
                            if not isinstance(item, dict):
                                continue
                            archive_name = str(item.get('archive') or '').replace('\\', '/').strip()
                            if archive_name:
                                catalog_manifest_by_archive[archive_name] = item
                except Exception:
                    catalog_manifest_by_archive = {}

            # A normal vulnerability pack may contain helper ZIP files. Treat it
            # as a bundle only when it has the export-all manifest or no compose
            # files of its own.
            if nested_archives and (manifest_name or not has_compose):
                installed_entries: list[dict[str, Any]] = []
                failures: list[str] = []
                for inner_name in sorted(set(nested_archives)):
                    try:
                        inner_bytes = archive.read(inner_name)
                    except Exception as exc:
                        failures.append(f'{inner_name}: read failed ({exc})')
                        continue

                    manifest_item = catalog_manifest_by_archive.get(inner_name) or {}
                    inner_label = str(manifest_item.get('label') or '').strip()
                    if not inner_label:
                        inner_label = secure_filename(os.path.basename(inner_name)) or 'vuln-catalog.zip'
                    fd, inner_tmp = tempfile.mkstemp(
                        prefix='coretg_vuln_catalog_bundle_',
                        suffix='-' + (secure_filename(os.path.basename(inner_name)) or 'catalog.zip'),
                    )
                    os.close(fd)
                    try:
                        with open(inner_tmp, 'wb') as handle:
                            handle.write(inner_bytes)
                        installed_entries.append(_install_vuln_catalog_zip_file_single(
                            zip_file_path=inner_tmp,
                            label=inner_label,
                            origin=origin,
                        ))
                    except Exception as exc:
                        failures.append(f'{inner_name}: {exc}')
                    finally:
                        try:
                            os.remove(inner_tmp)
                        except Exception:
                            pass

                if not installed_entries:
                    detail = f': {failures[0]}' if failures else ''
                    raise ValueError(f'No vulnerability catalog packs could be installed from bundle{detail}')

                return {
                    'id': str(installed_entries[0].get('id') or ''),
                    'label': str(label or '').strip() or 'vulnerability_catalog.zip',
                    'origin': str(origin or '').strip(),
                    'bundle_count': len(installed_entries),
                    'installed_catalog_ids': [str(item.get('id') or '') for item in installed_entries if str(item.get('id') or '')],
                    'bundle_failures': failures,
                }
    except zipfile.BadZipFile:
        pass

    return _install_vuln_catalog_zip_file_single(zip_file_path=zip_file_path, label=label, origin=origin)


def _install_vuln_catalog_zip_bytes(*, zip_bytes: bytes, label: str, origin: str) -> dict:
    tmp_path = ''
    try:
        with tempfile.NamedTemporaryFile(prefix='vuln-catalog-', suffix='.zip', delete=False) as tmp:
            tmp.write(zip_bytes or b'')
            tmp_path = tmp.name
        return _install_vuln_catalog_zip_file(zip_file_path=tmp_path, label=label, origin=origin)
    finally:
        if tmp_path:
            try:
                os.remove(tmp_path)
            except Exception:
                pass


