def _core_like_compose_template_preflight(path: str) -> tuple[bool, str | None, dict[str, Any]]:
    """Best-effort emulate CORE's compose template parsing behavior.

    CORE treats compose files as templates (Mako). This preflight catches template
    expression errors early for the vuln catalog Test button flow.
    """
    meta: dict[str, Any] = {}
    try:
        text = Path(path).read_text(encoding='utf-8', errors='ignore')
    except Exception as exc:
        return False, f'Unable to read prepared docker-compose file: {exc}', meta

    # Ignore already-safe wrappers like `${"${VAR:-x}"}` while scanning.
    scan_text = re.sub(
        r'\$\{\s*([\"\'])\$\{[^}]*\}\1\s*\}',
        lambda m: ' ' * len(m.group(0)),
        text,
    )

    raw_exprs: list[tuple[str, int]] = []
    for m in re.finditer(r'(?<!\\)\$\{([^}]*)\}', scan_text):
        expr = (m.group(1) or '').strip()
        line_no = text.count('\n', 0, m.start()) + 1
        raw_exprs.append((expr, line_no))
    if raw_exprs:
        meta['raw_template_expr_count'] = len(raw_exprs)

    syntax_errors: list[str] = []
    for expr, line_no in raw_exprs[:8]:
        try:
            ast.parse(expr, mode='eval')
        except SyntaxError:
            syntax_errors.append(f'line {line_no}: ${{{expr}}}')
        except Exception:
            # Non-syntax parse failures are still suspicious but less deterministic.
            syntax_errors.append(f'line {line_no}: ${{{expr}}}')
    if syntax_errors:
        return (
            False,
            'Compose template contains unescaped `${...}` expression(s) that fail CORE-style parsing: '
            + '; '.join(syntax_errors[:3]),
            meta,
        )

    try:
        from mako.template import Template as _MakoTemplate  # type: ignore
        from mako import exceptions as _mako_exceptions  # type: ignore

        meta['template_engine'] = 'mako'
        try:
            _MakoTemplate(text).render()
        except Exception as exc:
            detail = ''
            try:
                detail = str(_mako_exceptions.text_error_template().render()).strip()
            except Exception:
                detail = str(exc)
            detail = detail.replace('\n', ' | ')
            if len(detail) > 700:
                detail = detail[:700] + '...'
            return False, f'CORE-like template render check failed: {detail}', meta
    except Exception:
        meta['template_engine'] = 'ast-fallback'

    return True, None, meta


def _scan_compose_shell_command_safety(path: str) -> tuple[bool, list[dict[str, Any]]]:
    """Return (ok, issues) for shell-command fragments unsafe for CORE printf rendering."""
    issues: list[dict[str, Any]] = []
    try:
        text = Path(path).read_text(encoding='utf-8', errors='ignore')
    except Exception:
        return True, issues

    try:
        import yaml  # type: ignore

        doc = yaml.safe_load(text)
    except Exception:
        return True, issues
    services = doc.get('services') if isinstance(doc, dict) else None
    if not isinstance(services, dict):
        return True, issues

    for svc_name, svc in services.items():
        if not isinstance(svc, dict):
            continue
        cmd = svc.get('command')
        cmd_text = ''
        if isinstance(cmd, str):
            cmd_text = cmd
        elif isinstance(cmd, list):
            try:
                parts = [str(x) for x in cmd]
            except Exception:
                parts = []
            if len(parts) >= 3 and parts[0] in {'sh', 'bash'} and parts[1] in {'-c', '-lc'}:
                cmd_text = parts[2]
            elif parts:
                cmd_text = ' '.join(parts)
        if not cmd_text:
            continue

        low = cmd_text.lower()
        markers: list[str] = []
        if 'rpcbind_pid' in low and ('$!' in cmd_text or '$$' in cmd_text or '$rpcbind_pid' in low):
            markers.append('rpcbind_pid_dollar_expansion')
        if 'trap' in low and '$$' in cmd_text:
            markers.append('trap_double_dollar')
        if '$$!' in cmd_text or '$$rpcbind_pid' in low:
            markers.append('double_dollar_pid_pattern')
        if markers:
            issues.append({
                'service': str(svc_name or ''),
                'path': str(path),
                'markers': markers,
                'command_preview': cmd_text[:300],
            })

    return (len(issues) == 0), issues


def _autofix_legacy_nfs_compose_shell_pattern(path: str) -> bool:
    """Best-effort rewrite for legacy nfs_sensitive_file compose command patterns."""
    import re
    try:
        text = Path(path).read_text(encoding='utf-8', errors='ignore')
    except Exception:
        return False

    original = text
    safe_cmd = (
        'rpcbind -w -f & '
        'ganesha.nfsd -F -L STDOUT -f /etc/ganesha/ganesha.conf || sleep infinity'
    )

    # Legacy command that used PID shell-expansion and trap patterns that CORE
    # compose printf rendering can mangle. Use regex to match two variants:
    # 1. Full error handling: { echo "[coretg]..." >&2; sleep infinity; }
    # 2. Simple: || sleep infinity
    
    # Pattern for full error handling variant
    pattern_full = re.compile(
        r'rpcbind\s+-w\s+-f\s+&\s+RPCBIND_PID=\$\$!;\s*trap\s+kill\s+\$\$RPCBIND_PID\s+2>/dev/null\s+\|\|\s+true\s+EXIT;\s*'
        r'ganesha\.nfsd\s+-F\s+-L\s+STDOUT\s+-f\s+/etc/ganesha/ganesha\.conf\s+\|\|\s*'
        r'{\s*echo\s+[\\"]?\[coretg\]\s+ganesha\s+failed;\s+keeping\s+container\s+alive[\\"]?\s+>&2;\s*sleep\s+infinity;\s*}',
        re.DOTALL
    )
    text = pattern_full.sub(safe_cmd, text)
    
    # Pattern for simple variant (without error handling block)
    pattern_simple = re.compile(
        r'rpcbind\s+-w\s+-f\s+&\s+RPCBIND_PID=\$\$!;\s*trap\s+kill\s+\$\$RPCBIND_PID\s+2>/dev/null\s+\|\|\s+true\s+EXIT;\s*'
        r'ganesha\.nfsd\s+-F\s+-L\s+STDOUT\s+-f\s+/etc/ganesha/ganesha\.conf\s+\|\|\s+sleep\s+infinity',
        re.DOTALL
    )
    text = pattern_simple.sub(safe_cmd, text)

    if text == original:
        return False
    try:
        Path(path).write_text(text, encoding='utf-8')
    except Exception:
        return False
    return True




def _flow_compose_candidate_records(xml_path: str, scenario_label: str | None) -> list[dict[str, Any]]:
    """Collect compose path candidates from flow flag-node-generator assignments."""
    records: list[dict[str, Any]] = []
    try:
        flow_state = _flow_state_from_xml_path(xml_path, scenario_label)
    except Exception:
        flow_state = None
    assignments = flow_state.get('flag_assignments') if isinstance(flow_state, dict) else None
    if not isinstance(assignments, list) or not assignments:
        return records

    for fa in assignments:
        if not isinstance(fa, dict):
            continue
        gen_type = str(fa.get('type') or fa.get('generator_type') or '').strip().lower()
        if gen_type != 'flag-node-generator':
            continue

        run_dir = str(fa.get('run_dir') or fa.get('artifacts_dir') or '').strip()
        artifacts_dir = str(fa.get('inject_source_dir') or fa.get('artifacts_dir') or '').strip()
        outputs_manifest = str(fa.get('outputs_manifest') or '').strip()
        resolved_outputs = fa.get('resolved_outputs') if isinstance(fa.get('resolved_outputs'), dict) else {}

        compose_hints: list[str] = []
        try:
            hint = str((resolved_outputs or {}).get('File(path)') or '').strip()
            if hint:
                compose_hints.append(hint)
        except Exception:
            pass
        if outputs_manifest and os.path.isfile(outputs_manifest):
            try:
                payload = json.loads(Path(outputs_manifest).read_text(encoding='utf-8', errors='ignore') or '{}')
                outs = payload.get('outputs') if isinstance(payload, dict) else None
                if isinstance(outs, dict):
                    hint2 = str(outs.get('File(path)') or '').strip()
                    if hint2:
                        compose_hints.append(hint2)
            except Exception:
                pass

        compose_candidates: set[str] = set()
        for compose_hint in compose_hints:
            if not compose_hint:
                continue
            if os.path.isabs(compose_hint):
                compose_candidates.add(compose_hint)
            else:
                rel = compose_hint.lstrip('/')
                for base in (run_dir, artifacts_dir, os.path.dirname(outputs_manifest) if outputs_manifest else ''):
                    if base:
                        compose_candidates.add(os.path.join(base, rel))
                base_name = os.path.basename(compose_hint)
                if run_dir and base_name:
                    compose_candidates.add(os.path.join(run_dir, base_name))

        # Mirror topology builder fallbacks used at runtime for node generators.
        for base in (run_dir, artifacts_dir, os.path.dirname(outputs_manifest) if outputs_manifest else ''):
            if not base:
                continue
            compose_candidates.add(os.path.join(base, 'docker-compose.yml'))
            compose_candidates.add(os.path.join(base, 'outputs', 'docker-compose.yml'))

        for cand in compose_candidates:
            raw = str(cand or '').strip()
            if not raw:
                continue
            try:
                norm = os.path.abspath(raw)
            except Exception:
                norm = raw
            records.append({
                'path': norm,
                'node_id': str(fa.get('node_id') or ''),
                'generator_id': str(fa.get('id') or fa.get('generator_id') or ''),
            })

    return records


def _flow_compose_shell_safety_preflight(xml_path: str, scenario_label: str | None) -> tuple[bool, str | None, dict[str, Any]]:
    """Check flow assignments for generator compose files with unsafe shell command patterns."""
    meta: dict[str, Any] = {'checked': 0, 'issues': [], 'candidate_count': 0, 'missing_local_paths': [], 'autofixed_paths': []}
    try:
        records = _flow_compose_candidate_records(xml_path, scenario_label)
    except Exception as exc:
        return True, None, {'checked': 0, 'issues': [], 'warning': f'compose candidate discovery unavailable: {exc}'}
    if not records:
        return True, None, meta
    meta['candidate_count'] = len(records)

    checked_paths: set[str] = set()
    for rec in records:
        abs_cand = str(rec.get('path') or '').strip()
        if not abs_cand or abs_cand in checked_paths:
            continue
        checked_paths.add(abs_cand)
        if not os.path.isfile(abs_cand):
            missing = meta.get('missing_local_paths')
            if isinstance(missing, list) and len(missing) < 20:
                missing.append(abs_cand)
            continue

        meta['checked'] = int(meta.get('checked') or 0) + 1
        ok, issues = _scan_compose_shell_command_safety(abs_cand)
        if (not ok) and issues:
            rec_gen = str(rec.get('generator_id') or '').strip().lower()
            if rec_gen == 'nfs_sensitive_file' and _autofix_legacy_nfs_compose_shell_pattern(abs_cand):
                ok, issues = _scan_compose_shell_command_safety(abs_cand)
                if ok:
                    fixed = meta.get('autofixed_paths')
                    if isinstance(fixed, list):
                        fixed.append(abs_cand)
        if not ok and issues:
            for issue in issues:
                issue_rec = dict(issue)
                issue_rec['node_id'] = str(rec.get('node_id') or '')
                issue_rec['generator_id'] = str(rec.get('generator_id') or '')
                meta['issues'].append(issue_rec)

    if meta['issues']:
        first = meta['issues'][0]
        node = str(first.get('node_id') or '?')
        gen = str(first.get('generator_id') or '?')
        path = str(first.get('path') or '?')
        return False, (
            f"Flow compose preflight blocked unsafe shell command pattern for node {node} "
            f"generator {gen} at {path}. Re-generate or reinstall the generator pack."
        ), meta

    return True, None, meta


def _flow_compose_shell_safety_preflight_remote(core_cfg: dict[str, Any], xml_path: str, scenario_label: str | None) -> tuple[bool, str | None, dict[str, Any]]:
    """Run remote compose safety scan for flow node-generator compose paths over SSH."""
    meta: dict[str, Any] = {'checked': 0, 'issues': [], 'autofixed_remote_paths': []}
    if not isinstance(core_cfg, dict) or not _coerce_bool(core_cfg.get('ssh_enabled')):
        return True, None, meta

    records = _flow_compose_candidate_records(xml_path, scenario_label)
    if not records:
        return True, None, meta

    path_to_rec: dict[str, dict[str, Any]] = {}
    remote_entries: list[dict[str, str]] = []
    seen: set[str] = set()
    for rec in records:
        p = str(rec.get('path') or '').strip()
        if not p or p in seen:
            continue
        seen.add(p)
        path_to_rec[p] = rec
        if os.path.isabs(p):
            remote_entries.append({
                'path': p,
                'generator_id': str(rec.get('generator_id') or ''),
            })
    if not remote_entries:
        return True, None, meta

    script = textwrap.dedent(
        r"""
        python3 - <<'PY' __CORETG_PATHS_JSON__
import json
import os
import sys

raw = sys.argv[1] if len(sys.argv) > 1 else '[]'
try:
    entries = json.loads(raw)
except Exception:
    entries = []

issues = []
checked = 0
autofixed = []
for entry in entries:
    if isinstance(entry, dict):
        p = str(entry.get('path') or '').strip()
        gen = str(entry.get('generator_id') or '').strip().lower()
    else:
        p = str(entry or '').strip()
        gen = ''
    if not p or not os.path.isfile(p):
        continue
    checked += 1
    try:
        text = open(p, 'r', encoding='utf-8', errors='ignore').read()
    except Exception:
        continue

    if gen == 'nfs_sensitive_file':
        import re
        safe_cmd = (
            'rpcbind -w -f & '
            'ganesha.nfsd -F -L STDOUT -f /etc/ganesha/ganesha.conf || sleep infinity'
        )
        # Handle both full and simple command variants
        pattern_full = re.compile(
            r'rpcbind\s+-w\s+-f\s+&\s+RPCBIND_PID=\$\$!;\s*trap\s+kill\s+\$\$RPCBIND_PID\s+2>/dev/null\s+\|\|\s+true\s+EXIT;\s*'
            r'ganesha\.nfsd\s+-F\s+-L\s+STDOUT\s+-f\s+/etc/ganesha/ganesha\.conf\s+\|\|\s*'
            r'{\s*echo\s+[\\"]?\[coretg\]\s+ganesha\s+failed;\s+keeping\s+container\s+alive[\\"]?\s+>&2;\s*sleep\s+infinity;\s*}',
            re.DOTALL
        )
        updated = pattern_full.sub(safe_cmd, text)
        
        if updated == text:
            # Try simpler variant
            pattern_simple = re.compile(
                r'rpcbind\s+-w\s+-f\s+&\s+RPCBIND_PID=\$\$!;\s*trap\s+kill\s+\$\$RPCBIND_PID\s+2>/dev/null\s+\|\|\s+true\s+EXIT;\s*'
                r'ganesha\.nfsd\s+-F\s+-L\s+STDOUT\s+-f\s+/etc/ganesha/ganesha\.conf\s+\|\|\s+sleep\s+infinity',
                re.DOTALL
            )
            updated = pattern_simple.sub(safe_cmd, text)
        
        if updated != text:
            try:
                with open(p, 'w', encoding='utf-8') as fh:
                    fh.write(updated)
                text = updated
                autofixed.append(p)
            except Exception:
                pass

    low = text.lower()
    markers = []
    if 'rpcbind_pid' in low and ('$!' in text or '$$' in text or '$rpcbind_pid' in low):
        markers.append('rpcbind_pid_dollar_expansion')
    if 'trap' in low and '$$' in text:
        markers.append('trap_double_dollar')
    if '$$!' in text or '$$rpcbind_pid' in low:
        markers.append('double_dollar_pid_pattern')
    if markers:
        issues.append({'path': p, 'markers': markers, 'command_preview': text[:300]})

print(json.dumps({'checked': checked, 'issues': issues, 'autofixed_paths': autofixed}))
PY
        """
    ).replace('__CORETG_PATHS_JSON__', shlex.quote(json.dumps(remote_entries))).strip()

    client = None
    try:
        client = _open_ssh_client(core_cfg)
        rc, out, err = _exec_ssh_command(client, f"bash -lc {shlex.quote(script)}", timeout=60.0)
    except Exception as exc:
        return False, f'Remote flow compose safety preflight failed: {exc}', {'checked': 0, 'issues': [], 'warning': str(exc)}
    finally:
        try:
            if client:
                client.close()
        except Exception:
            pass

    if rc != 0:
        detail = str(err or out or '').strip() or f'command exited {rc}'
        return False, f'Remote flow compose safety preflight command failed: {detail}', {'checked': 0, 'issues': []}

    payload: dict[str, Any] = {}
    try:
        payload = json.loads(str(out or '').strip() or '{}')
    except Exception:
        payload = {}
    if isinstance(payload.get('checked'), int):
        meta['checked'] = int(payload.get('checked') or 0)
    if isinstance(payload.get('autofixed_paths'), list):
        meta['autofixed_remote_paths'] = [str(x) for x in payload.get('autofixed_paths') if str(x).strip()]
    issues = payload.get('issues') if isinstance(payload.get('issues'), list) else []
    for issue in issues:
        if not isinstance(issue, dict):
            continue
        issue_path = str(issue.get('path') or '').strip()
        mapped = path_to_rec.get(issue_path) if issue_path else None
        rec = dict(issue)
        if isinstance(mapped, dict):
            rec['node_id'] = str(mapped.get('node_id') or '')
            rec['generator_id'] = str(mapped.get('generator_id') or '')
        meta['issues'].append(rec)

    if meta['issues']:
        first = meta['issues'][0]
        node = str(first.get('node_id') or '?')
        gen = str(first.get('generator_id') or '?')
        path = str(first.get('path') or '?')
        return False, (
            f"Flow compose preflight blocked unsafe shell command pattern for node {node} "
            f"generator {gen} at {path}. Re-generate or reinstall the generator pack."
        ), meta

    return True, None, meta


def _core_vm_compose_template_preflight(ssh_client: Any, remote_compose_path: str) -> tuple[bool, str | None, dict[str, Any]]:
    """Run a CORE-like compose template preflight on the CORE VM itself."""
    meta: dict[str, Any] = {}
    remote_path = str(remote_compose_path or '').strip()
    if not remote_path:
        return False, 'Missing remote compose path for CORE VM preflight', meta

    path_q = shlex.quote(remote_path)
    script = textwrap.dedent(
        r"""
        python3 - <<'PY' __CORETG_PATH__
import ast, json, re, sys

meta = {}
path = sys.argv[1] if len(sys.argv) > 1 else ''
if not path:
    print(json.dumps({'ok': False, 'error': 'missing compose path', 'meta': meta}))
    raise SystemExit(0)
try:
    with open(path, 'r', encoding='utf-8', errors='ignore') as f:
        text = f.read()
except Exception as exc:
    print(json.dumps({'ok': False, 'error': f'unable to read compose: {exc}', 'meta': meta}))
    raise SystemExit(0)

scan_text = re.sub(r'\$\{\s*([\"\'])\$\{[^}]*\}\1\s*\}', lambda m: ' ' * len(m.group(0)), text)
raw_exprs = []
for m in re.finditer(r'(?<!\\)\$\{([^}]*)\}', scan_text):
    expr = (m.group(1) or '').strip()
    line_no = text.count('\n', 0, m.start()) + 1
    raw_exprs.append((expr, line_no))
if raw_exprs:
    meta['raw_template_expr_count'] = len(raw_exprs)

syntax_errors = []
for expr, line_no in raw_exprs[:8]:
    try:
        ast.parse(expr, mode='eval')
    except Exception:
        syntax_errors.append(f'line {line_no}: ${{{expr}}}')
if syntax_errors:
    print(json.dumps({'ok': False, 'error': 'Compose template contains unescaped `${...}` expression(s): ' + '; '.join(syntax_errors[:3]), 'meta': meta}))
    raise SystemExit(0)

try:
    from mako.template import Template as _MakoTemplate  # type: ignore
    meta['template_engine'] = 'mako'
    _MakoTemplate(text).render()
except ImportError:
    meta['template_engine'] = 'ast-fallback'
except Exception as exc:
    detail = str(exc).replace('\n', ' | ')
    if len(detail) > 700:
        detail = detail[:700] + '...'
    print(json.dumps({'ok': False, 'error': 'CORE-VM template render check failed: ' + detail, 'meta': meta}))
    raise SystemExit(0)

print(json.dumps({'ok': True, 'meta': meta}))
PY
    """
    ).replace('__CORETG_PATH__', path_q).strip()

    cmd = f"bash -lc {shlex.quote(script)}"
    try:
        rc, out, err = _exec_ssh_command(ssh_client, cmd, timeout=30.0)
    except Exception as exc:
        return False, f'CORE VM template preflight transport failed: {exc}', meta
    if rc != 0:
        detail = str(err or out or '').strip() or f'command exited {rc}'
        return False, f'CORE VM template preflight command failed: {detail}', meta

    payload: dict[str, Any] = {}
    out_text = str(out or '').strip()
    if out_text:
        try:
            payload = json.loads(out_text)
        except Exception:
            return False, f'CORE VM template preflight returned non-JSON output: {out_text[:300]}', meta
    if not isinstance(payload, dict):
        payload = {}
    pm = payload.get('meta')
    if isinstance(pm, dict):
        meta.update(pm)
    if payload.get('ok') is False:
        return False, str(payload.get('error') or 'CORE VM compose template preflight failed'), meta
    return True, None, meta


def _core_vm_render_compose_template(ssh_client: Any, remote_compose_path: str) -> tuple[bool, str | None, str | None, dict[str, Any]]:
    """Render compose template on CORE VM and return a runtime compose path.

    Returns: (ok, rendered_path, error, meta)
    """
    meta: dict[str, Any] = {}
    remote_path = str(remote_compose_path or '').strip()
    if not remote_path:
        return False, None, 'Missing remote compose path for CORE VM render', meta

    path_q = shlex.quote(remote_path)
    script = textwrap.dedent(
        r"""
        python3 - <<'PY' __CORETG_PATH__
import json, os, re, sys

src = sys.argv[1] if len(sys.argv) > 1 else ''
if not src:
    print(json.dumps({'ok': False, 'error': 'missing source path'}))
    raise SystemExit(0)

try:
    with open(src, 'r', encoding='utf-8', errors='ignore') as f:
        text = f.read()
except Exception as exc:
    print(json.dumps({'ok': False, 'error': f'unable to read source compose: {exc}'}))
    raise SystemExit(0)

engine = 'wrapper-fallback'
rendered = text
try:
    from mako.template import Template as _MakoTemplate  # type: ignore
    rendered = _MakoTemplate(text).render()
    engine = 'mako'
except ImportError:
    # Fallback: collapse `${"${...}"}` wrappers emitted by sanitizer.
    prev = None
    cur = rendered
    pat = re.compile(r'\$\{\s*[\"\']\s*(\$\{[^}]*\})\s*[\"\']\s*\}')
    while prev != cur:
        prev = cur
        cur = pat.sub(r'\1', cur)
    rendered = cur
except Exception as exc:
    print(json.dumps({'ok': False, 'error': f'mako render failed: {exc}'}))
    raise SystemExit(0)

out_path = src + '.runtime.yml'
try:
    with open(out_path, 'w', encoding='utf-8') as f:
        f.write(rendered)
except Exception as exc:
    print(json.dumps({'ok': False, 'error': f'unable to write rendered compose: {exc}'}))
    raise SystemExit(0)

print(json.dumps({'ok': True, 'path': out_path, 'meta': {'engine': engine}}))
PY
        """
    ).replace('__CORETG_PATH__', path_q).strip()

    cmd = f"bash -lc {shlex.quote(script)}"
    try:
        rc, out, err = _exec_ssh_command(ssh_client, cmd, timeout=30.0)
    except Exception as exc:
        return False, None, f'CORE VM compose render transport failed: {exc}', meta
    if rc != 0:
        detail = str(err or out or '').strip() or f'command exited {rc}'
        return False, None, f'CORE VM compose render command failed: {detail}', meta

    payload: dict[str, Any] = {}
    out_text = str(out or '').strip()
    if out_text:
        try:
            payload = json.loads(out_text)
        except Exception:
            return False, None, f'CORE VM compose render returned non-JSON output: {out_text[:300]}', meta
    if not isinstance(payload, dict):
        payload = {}
    pm = payload.get('meta')
    if isinstance(pm, dict):
        meta.update(pm)
    if payload.get('ok') is False:
        return False, None, str(payload.get('error') or 'CORE VM compose render failed'), meta
    out_path = str(payload.get('path') or '').strip()
    if not out_path:
        return False, None, 'CORE VM compose render did not return output path', meta
    return True, out_path, None, meta


