def _stop_vuln_test_meta(meta: dict, user_ok: bool | None):
    execute_like_real = bool(meta.get('execute_like_real'))
    compose_path = meta.get('remote_compose_path')
    remote_run_dir = meta.get('remote_run_dir')
    local_run_dir = str(meta.get('run_dir') or '').strip()
    cleanup_generated_artifacts = True
    try:
        if 'cleanup_generated_artifacts' in meta:
            cleanup_generated_artifacts = _coerce_bool(meta.get('cleanup_generated_artifacts'))
    except Exception:
        cleanup_generated_artifacts = True
    project_name = meta.get('project_name')
    log_path = meta.get('log_path')
    core_cfg = meta.get('core_cfg') if isinstance(meta.get('core_cfg'), dict) else None

    def _response(payload: dict, status_code: int = 200):
        try:
            from flask import has_app_context

            if has_app_context():
                return jsonify(payload), status_code
        except Exception:
            pass
        if status_code == 200:
            return payload
        return payload, status_code

    if not core_cfg and not execute_like_real:
        return _response({'ok': False, 'error': 'Missing CORE VM credentials'}, 400)

    try:
        if log_path:
            with open(log_path, 'a', encoding='utf-8') as log_f:
                log_f.write("[stop] User requested stop\n")
    except Exception:
        pass

    if not execute_like_real:
        try:
            channel = meta.get('ssh_channel')
            if channel is not None and hasattr(channel, 'close'):
                try:
                    channel.close()
                except Exception:
                    pass
        except Exception:
            pass

    try:
        if isinstance(meta, dict):
            meta['cleanup_started'] = True
            meta['cleanup_done'] = False
    except Exception:
        pass

    def _cleanup_remote() -> None:
        _client = None
        try:
            if not execute_like_real:
                _client = _open_ssh_client(core_cfg)
                if log_path:
                    with open(log_path, 'a', encoding='utf-8') as log_f:
                        log_f.write('[cleanup] docker compose down -v --remove-orphans --rmi all\n')
                pw = ''
                try:
                    pw = str(core_cfg.get('ssh_password') or '')
                except Exception:
                    pw = ''
                down_cmd = (
                    f"cd {shlex.quote(remote_run_dir or '/tmp')} && "
                    f"COMPOSE_PROJECT_NAME={shlex.quote(project_name or '')} sudo -S -p '' -k "
                    f"docker compose -f {shlex.quote(compose_path or '')} down -v --remove-orphans --rmi all"
                )
                cmd = f"bash -lc {shlex.quote(down_cmd)}"
                channel = _client.get_transport().open_session() if _client.get_transport() else None
                if channel is not None:
                    try:
                        channel.get_pty()
                    except Exception:
                        pass
                    channel.exec_command(cmd)
                    try:
                        if pw:
                            channel.send(pw + "\n")
                    except Exception:
                        pass
                    try:
                        with open(log_path, 'a', encoding='utf-8') as log_f:
                            _relay_remote_channel_to_log(channel, log_f, redact_tokens=[pw])
                    except Exception:
                        pass
        except Exception:
            pass
        try:
            _cleanup_remote_test_runtime(meta)
        except Exception:
            pass
        if cleanup_generated_artifacts:
            try:
                if _client and remote_run_dir:
                    _remote_remove_path(_client, remote_run_dir)
            except Exception:
                pass
            try:
                if local_run_dir and os.path.isdir(local_run_dir):
                    shutil.rmtree(local_run_dir, ignore_errors=True)
            except Exception:
                pass
        try:
            if _client:
                _client.close()
        except Exception:
            pass
        try:
            if isinstance(meta, dict):
                meta['cleanup_done'] = True
        except Exception:
            pass

    try:
        threading.Thread(target=_cleanup_remote, daemon=True).start()
    except Exception:
        _cleanup_remote()

    # Persist validation status on the item.
    try:
        state = _load_vuln_catalogs_state()
        cid = str(meta.get('catalog_id') or '').strip()
        item_id = int(meta.get('item_id') or 0)
        item_name = str(meta.get('item_name') or meta.get('test_docker_node_name') or f'item-{item_id}').strip()
        copied_log_path = None
        copied_log_name = None
        if isinstance(log_path, str) and log_path.strip():
            copied_log_path, copied_log_name = _snapshot_test_log_copy(
                source_log_path=log_path,
                subdir='catalog-test-logs/vuln_catalog',
                file_stem=f'{cid}-{item_id}-{item_name}',
            )
        catalogs = [c for c in (state.get('catalogs') or []) if isinstance(c, dict)]
        for c in catalogs:
            if str(c.get('id') or '').strip() != cid:
                continue
            items = _normalize_vuln_catalog_items(c)
            updated = False
            for it in items:
                if int(it.get('id') or 0) == item_id:
                    if user_ok is None:
                        it['validated_incomplete'] = True
                        it['validated_ok'] = None
                    else:
                        it['validated_incomplete'] = False
                        it['validated_ok'] = bool(user_ok)
                    it['validated_at'] = _local_timestamp_display()
                    if copied_log_path:
                        it['last_test_log_path'] = copied_log_path
                    if copied_log_name:
                        it['last_test_log_filename'] = copied_log_name
                    updated = True
                    break
            if updated:
                c['compose_items'] = items
                c['csv_paths'] = _write_vuln_catalog_csv_from_items(catalog_id=cid, items=items)
                state['catalogs'] = catalogs
                _write_vuln_catalogs_state(state)
            break
    except Exception:
        pass

    try:
        if isinstance(meta, dict):
            meta['done'] = True
            meta['returncode'] = meta.get('returncode') or 0
    except Exception:
        pass
    return _response({'ok': True})





def _zip_entry_is_symlink(info) -> bool:
    try:
        # ZipInfo.external_attr: upper 16 bits are unix mode if created on unix.
        import stat

        mode = (int(getattr(info, 'external_attr', 0)) >> 16) & 0o170000
        return mode == stat.S_IFLNK
    except Exception:
        return False


def _safe_extract_zip_to_dir(zip_path: str, dest_dir: str) -> None:
    import zipfile

    os.makedirs(dest_dir, exist_ok=True)
    with zipfile.ZipFile(zip_path, 'r') as z:
        for info in z.infolist():
            name = str(info.filename or '')
            if not name:
                continue
            if name.startswith('/') or name.startswith('\\'):
                raise ValueError('Zip contains absolute paths')
            parts = [p for p in name.replace('\\', '/').split('/') if p not in ('', '.')]
            if any(p == '..' for p in parts):
                raise ValueError('Zip contains parent directory traversal')
            if _zip_entry_is_symlink(info):
                raise ValueError('Zip contains symlinks (not allowed)')
            out_path = os.path.abspath(os.path.join(dest_dir, *parts))
            if not out_path.startswith(os.path.abspath(dest_dir) + os.sep):
                raise ValueError('Zip extraction escaped destination')
            if name.endswith('/'):
                os.makedirs(out_path, exist_ok=True)
                continue
            os.makedirs(os.path.dirname(out_path), exist_ok=True)
            with z.open(info, 'r') as src, open(out_path, 'wb') as dst:
                dst.write(src.read())


def _validate_generator_pack_tree(extracted_dir: str) -> tuple[bool, str, list[dict[str, Any]], list[dict[str, Any]]]:
    """Validate generator pack contents.

    Returns (ok, note, items) where items are generator dirs to install.
    Validation includes:
      - manifest.yaml syntax and required fields
      - docker-compose.yml yaml syntax + referenced service exists
      - python file syntax checks via ast.parse
    """
    try:
        from pathlib import Path
        import ast
        import yaml  # type: ignore
    except Exception as exc:
        return False, f'Missing validator dependency: {exc}', [], []

    try:
        from scenarioforge.sequencer.facts import parse_fact_ref
    except Exception:
        parse_fact_ref = None  # type: ignore

    try:
        from scenarioforge.compose_dependencies import missing_dependency_paths, scan_compose_dependencies
    except Exception:
        missing_dependency_paths = None  # type: ignore
        scan_compose_dependencies = None  # type: ignore

    root = Path(extracted_dir)
    if not root.exists() or not root.is_dir():
        return False, 'Empty pack', [], []

    # Find all manifest files.
    manifests: list[Path] = []
    for p in root.rglob('manifest.yaml'):
        if '__MACOSX' in str(p):
            continue
        manifests.append(p)
    for p in root.rglob('manifest.yml'):
        if '__MACOSX' in str(p):
            continue
        manifests.append(p)
    # De-dupe
    manifests = sorted({m.resolve() for m in manifests})
    if not manifests:
        return False, 'No manifest.yaml found in zip', [], []

    items: list[dict[str, Any]] = []
    errors: list[str] = []
    warnings: list[dict[str, Any]] = []

    canonical_types = {
        'string', 'int', 'float', 'number', 'boolean', 'json', 'file', 'string_list', 'file_list'
    }

    fact_pattern = re.compile(r'^[A-Za-z_][A-Za-z0-9_]*\s*\([^\n]*\)$')

    def _normalize_artifact_entry(item: Any) -> str:
        if isinstance(item, dict):
            return str(item.get('artifact') or item.get('name') or '').strip()
        return str(item or '').strip()

    def _validate_artifact_list(section: str, items: Any, *, manifest_path: Path) -> None:
        if items is None:
            return
        if not isinstance(items, list):
            errors.append(f'{manifest_path}: artifacts.{section} must be a list')
            return
        for idx, item in enumerate(items):
            art = _normalize_artifact_entry(item)
            if not art:
                errors.append(f'{manifest_path}: artifacts.{section}[{idx}] is empty')
                continue
            if parse_fact_ref is not None:
                try:
                    parse_fact_ref(art)
                except Exception:
                    errors.append(f'{manifest_path}: artifacts.{section}[{idx}] must be fact-style (e.g., File(path))')
            else:
                if not fact_pattern.match(art):
                    errors.append(f'{manifest_path}: artifacts.{section}[{idx}] must be fact-style (e.g., File(path))')

    def _normalize_input_type_for_warning(type_value: Any) -> tuple[str, bool]:
        """Return (canonical_type, used_fallback).

        used_fallback=True means we could not map the provided type (or it was missing)
        and defaulted to "string".
        """
        try:
            t0 = str(type_value or '').strip().lower()
        except Exception:
            t0 = ''
        if not t0:
            return 'string', True

        t = t0
        is_list = False
        try:
            is_list = ('list' in t) or t.endswith('[]')
        except Exception:
            is_list = False

        if t in canonical_types:
            return t, False

        # Common aliases.
        if t in {'text', 'str'}:
            return 'string', False
        if t in {'integer'}:
            return 'int', False
        if t in {'double'}:
            return 'float', False
        if t in {'bool'}:
            return 'boolean', False
        if t in {'object', 'dict', 'map'}:
            return 'json', False
        if t in {'filepath', 'file_path', 'path', 'pathname'}:
            return 'file', False
        if t in {'strings'}:
            return 'string_list', False
        if t in {'files'}:
            return 'file_list', False
        if is_list and ('file' in t or 'path' in t):
            return 'file_list', False
        if is_list and ('string' in t or 'text' in t or 'str' in t):
            return 'string_list', False
        if t.endswith('[]'):
            return 'string_list', False

        return 'string', True

    def _resolve_manifest_runtime_dir(manifest_dir: Any, source_path_value: Any) -> Any:
        raw = str(source_path_value or '').replace('\\', '/').strip()
        if not raw:
            return manifest_dir
        parts = [part for part in raw.split('/') if part not in ('', '.')]
        if any(part == '..' for part in parts):
            return manifest_dir
        try:
            if os.path.isabs(raw):
                candidate = Path(raw).resolve()
            else:
                candidate = (root / Path(*parts)).resolve()
            if candidate.exists() and candidate.is_dir() and os.path.commonpath([str(root.resolve()), str(candidate)]) == str(root.resolve()):
                return candidate
        except Exception:
            pass
        return manifest_dir

    for mp in manifests:
        try:
            doc = yaml.safe_load(mp.read_text('utf-8', errors='ignore'))
        except Exception as exc:
            errors.append(f'{mp}: invalid yaml: {exc}')
            continue
        if not isinstance(doc, dict):
            errors.append(f'{mp}: manifest must be a mapping')
            continue
        mv = int(doc.get('manifest_version') or 0)
        if mv != 1:
            errors.append(f'{mp}: manifest_version must be 1')
            continue
        manifest_id = str(doc.get('id') or '').strip()
        source_id = manifest_id

        # If this generator was exported from an installed pack, it may carry a
        # marker with the original stable source id. Prefer that over the
        # (numeric) installed manifest id so export/import roundtrips preserve ids.
        try:
            marker_path = mp.parent / '.coretg_pack.json'
            if marker_path.exists() and marker_path.is_file():
                marker = json.loads(marker_path.read_text('utf-8', errors='ignore') or '{}')
                if isinstance(marker, dict):
                    marker_source_id = str(marker.get('source_generator_id') or '').strip()
                    if marker_source_id and len(marker_source_id) <= 256:
                        source_id = marker_source_id
        except Exception:
            pass

        # Allow packs to omit ids; we will assign numeric ids on install.
        gen_id = source_id
        if not gen_id:
            try:
                import uuid

                gen_id = f"gen-{uuid.uuid4().hex[:10]}"
            except Exception:
                gen_id = 'gen-unknown'
        kind = str(doc.get('kind') or '').strip()
        if kind not in ('flag-generator', 'flag-node-generator'):
            errors.append(f'{mp}: kind must be flag-generator or flag-node-generator')
            continue

        # Enforce fact-style artifact keys in manifests.
        try:
            artifacts = doc.get('artifacts') if isinstance(doc.get('artifacts'), dict) else None
            if artifacts:
                _validate_artifact_list('requires', artifacts.get('requires'), manifest_path=mp)
                _validate_artifact_list('optional_requires', artifacts.get('optional_requires'), manifest_path=mp)
                _validate_artifact_list('produces', artifacts.get('produces'), manifest_path=mp)
        except Exception:
            pass

        # Warn on missing/unknown input types (they will fall back to string at runtime).
        try:
            raw_inputs = doc.get('inputs')
            if isinstance(raw_inputs, list):
                for idx, inp in enumerate(raw_inputs):
                    if not isinstance(inp, dict):
                        continue
                    nm = str(inp.get('name') or '').strip()
                    if not nm:
                        continue
                    raw_t = inp.get('type')
                    normalized, used_fallback = _normalize_input_type_for_warning(raw_t)
                    if raw_t is None:
                        warnings.append({
                            'manifest_path': str(mp),
                            'input_name': nm,
                            'raw_type': None,
                            'normalized_type': normalized,
                            'warning': 'inputs[].type is missing; defaulting to string',
                        })
                    elif used_fallback:
                        warnings.append({
                            'manifest_path': str(mp),
                            'input_name': nm,
                            'raw_type': str(raw_t),
                            'normalized_type': normalized,
                            'warning': f'Unknown input type "{raw_t}"; defaulting to string',
                        })
        except Exception:
            pass

        gen_dir = mp.parent
        source_path_value = doc.get('source_path') or (doc.get('source', {}).get('path') if isinstance(doc.get('source'), dict) else '')
        runtime_dir = _resolve_manifest_runtime_dir(gen_dir, source_path_value)
        runtime = doc.get('runtime') if isinstance(doc.get('runtime'), dict) else {}
        runtime_type = str(runtime.get('type') or 'docker-compose').strip().lower()
        compose_dependency_summary: dict[str, Any] = {}
        if runtime_type in ('docker-compose', 'compose'):
            compose_file = str(runtime.get('compose_file') or runtime.get('file') or 'docker-compose.yml')
            compose_service = str(runtime.get('service') or 'generator')
            compose_path = (runtime_dir / compose_file).resolve()
            if not compose_path.exists() or not compose_path.is_file():
                errors.append(f'{mp}: missing compose file: {compose_file}')
                continue
            try:
                compose_doc = yaml.safe_load(compose_path.read_text('utf-8', errors='ignore'))
            except Exception as exc:
                errors.append(f'{compose_path}: invalid yaml: {exc}')
                continue
            if not isinstance(compose_doc, dict):
                errors.append(f'{compose_path}: compose must be a mapping')
                continue
            services = compose_doc.get('services')
            if not isinstance(services, dict) or not services:
                errors.append(f'{compose_path}: compose missing services')
                continue
            if compose_service not in services:
                errors.append(f'{compose_path}: missing service "{compose_service}"')
                continue
            if scan_compose_dependencies is not None and missing_dependency_paths is not None:
                try:
                    compose_dependency_summary = scan_compose_dependencies(compose_path)
                    for missing_path in missing_dependency_paths(compose_dependency_summary):
                        warnings.append({
                            'manifest_path': str(mp),
                            'compose_path': str(compose_path),
                            'dependency_path': missing_path,
                            'warning': f'Missing compose dependency "{missing_path}"; create it before running this generator.',
                        })
                except Exception:
                    compose_dependency_summary = {}

        # Basic Python syntax check for any .py file in the generator dir.
        try:
            for py in gen_dir.rglob('*.py'):
                if py.is_file():
                    ast.parse(py.read_text('utf-8', errors='ignore'))
        except Exception as exc:
            errors.append(f'{mp}: python syntax error: {exc}')
            continue

        items.append({
            'id': gen_id,
            'kind': kind,
            'path': str(gen_dir),
            'runtime_source_path': str(runtime_dir) if str(runtime_dir) != str(gen_dir) else '',
            'source_id': source_id,
            'manifest_id': manifest_id,
            'manifest_path': str(mp),
            'compose_dependencies': compose_dependency_summary,
        })

    if errors:
        # Show first few errors.
        return False, '; '.join(errors[:4]) + (f' (+{len(errors)-4} more)' if len(errors) > 4 else ''), [], warnings
    return True, f'Validated {len(items)} generator(s)', items, warnings


def _compute_next_numeric_generator_id(*, repo_root: str) -> int:
    """Return the next numeric generator id across installed packs.

    Generator packs use numeric ids for uniqueness, but manifest discovery may
    remap ids to stable source ids for UI/Flow. To avoid collisions, derive the
    numeric max from installed pack markers.
    """
    max_numeric = 0
    try:
        root = _installed_generators_root()
        for dirpath, _dirnames, filenames in os.walk(root):
            if '.coretg_pack.json' not in filenames:
                continue
            marker_path = os.path.join(dirpath, '.coretg_pack.json')
            try:
                with open(marker_path, 'r', encoding='utf-8') as fh:
                    marker = json.load(fh)
                if not isinstance(marker, dict):
                    continue
                gid = str(marker.get('generator_id') or '').strip()
                if gid.isdigit():
                    max_numeric = max(max_numeric, int(gid))
            except Exception:
                continue
    except Exception:
        max_numeric = 0

    return max_numeric + 1


def _install_generator_pack_payload(
    *,
    zip_path: str,
    pack_id: str,
    safe_label: str,
    pack_origin: str,
    next_numeric: int,
) -> tuple[bool, str, list[dict[str, Any]], int, list[dict[str, Any]]]:
    """Install a pack zip payload and return installed items.

    This does not write to the packs state file; callers decide how to record grouping.
    """
    import shutil
    import tempfile
    from pathlib import Path

    try:
        import yaml  # type: ignore
    except Exception as exc:
        return False, f'Pack install requires PyYAML: {exc}', [], next_numeric, []

    root = _installed_generators_root()
    tmp_dir = tempfile.mkdtemp(prefix='coretg_pack_')
    try:
        _safe_extract_zip_to_dir(zip_path, tmp_dir)
        ok, note, items, warnings = _validate_generator_pack_tree(tmp_dir)
        if not ok:
            return False, note, [], next_numeric, warnings

        installed: list[dict[str, Any]] = []
        for it in items:
            kind = str(it.get('kind') or '')
            src_dir = str(it.get('path') or '')
            runtime_src_dir = str(it.get('runtime_source_path') or '')
            source_gid = str(it.get('source_id') or it.get('id') or '')
            assigned_gid = str(next_numeric)
            next_numeric += 1

            if kind == 'flag-node-generator':
                dest_base = os.path.join(root, 'flag_node_generators')
            else:
                dest_base = os.path.join(root, 'flag_generators')
            os.makedirs(dest_base, exist_ok=True)

            dir_name = secure_filename(f"p_{pack_id}__{assigned_gid}") or f"p_{pack_id}__generator"
            dest_dir = os.path.join(dest_base, dir_name)
            suffix = 2
            while os.path.exists(dest_dir):
                dest_dir = os.path.join(dest_base, f"{dir_name}_{suffix}")
                suffix += 1

            src_abs = os.path.abspath(src_dir)
            runtime_src_abs = os.path.abspath(runtime_src_dir) if runtime_src_dir else ''
            if runtime_src_abs and runtime_src_abs != src_abs and os.path.isdir(runtime_src_abs):
                shutil.copytree(runtime_src_abs, dest_dir)
                shutil.copytree(src_abs, dest_dir, dirs_exist_ok=True)
            else:
                shutil.copytree(src_abs, dest_dir)

            # Rewrite installed manifest id and avoid overriding installed source path.
            try:
                manifest_path = None
                for nm in ('manifest.yaml', 'manifest.yml'):
                    p = os.path.join(dest_dir, nm)
                    if os.path.exists(p) and os.path.isfile(p):
                        manifest_path = p
                        break
                if manifest_path is None:
                    for rp in Path(dest_dir).rglob('manifest.yaml'):
                        if '__MACOSX' in str(rp):
                            continue
                        manifest_path = str(rp)
                        break
                if manifest_path is None:
                    for rp in Path(dest_dir).rglob('manifest.yml'):
                        if '__MACOSX' in str(rp):
                            continue
                        manifest_path = str(rp)
                        break

                if manifest_path:
                    doc = yaml.safe_load(Path(manifest_path).read_text('utf-8', errors='ignore'))
                    if isinstance(doc, dict):
                        doc['id'] = assigned_gid
                        doc.pop('source_path', None)
                        if isinstance(doc.get('source'), dict):
                            doc.pop('source', None)
                        Path(manifest_path).write_text(yaml.safe_dump(doc, sort_keys=False), encoding='utf-8')
            except Exception:
                pass

            # Marker for debugging/traceability.
            try:
                marker = {
                    'pack_id': pack_id,
                    'pack_label': safe_label,
                    'origin': pack_origin,
                    'installed_at': _local_timestamp_display(),
                    'generator_id': assigned_gid,
                    'kind': kind,
                    'source_generator_id': source_gid,
                }
                with open(os.path.join(dest_dir, '.coretg_pack.json'), 'w', encoding='utf-8') as fh:
                    json.dump(marker, fh, indent=2)
            except Exception:
                pass

            installed_item: dict[str, Any] = {'id': assigned_gid, 'kind': kind, 'path': dest_dir}
            compose_dependency_summary = it.get('compose_dependencies') if isinstance(it.get('compose_dependencies'), dict) else {}
            required_files = compose_dependency_summary.get('requires') if isinstance(compose_dependency_summary, dict) else []
            if isinstance(required_files, list):
                installed_item['required_files'] = required_files
                installed_item['missing_required_files'] = [
                    str(entry.get('path') or '').strip()
                    for entry in required_files
                    if isinstance(entry, dict)
                    and entry.get('required') is not False
                    and entry.get('exists') is False
                    and str(entry.get('path') or '').strip()
                ]
                if installed_item['missing_required_files']:
                    installed_item['disabled'] = True
                    installed_item['disabled_due_to_missing_files'] = True
            if isinstance(compose_dependency_summary, dict) and compose_dependency_summary.get('warning'):
                installed_item['compose_dependency_warning'] = str(compose_dependency_summary.get('warning') or '').strip()
            installed.append(installed_item)

        return True, note, installed, next_numeric, warnings
    finally:
        try:
            shutil.rmtree(tmp_dir, ignore_errors=True)
        except Exception:
            pass


def _install_generator_pack(*, zip_path: str, pack_label: str, pack_origin: str) -> tuple[bool, str]:
    try:
        try:
            repo_root = _get_repo_root()
        except Exception:
            repo_root = os.getcwd()

        safe_label = secure_filename(pack_label or 'pack') or 'pack'
        pack_id = _local_timestamp_safe() + '-' + uuid.uuid4().hex[:6]
        next_numeric = _compute_next_numeric_generator_id(repo_root=repo_root)

        ok, note, installed, _next, warnings = _install_generator_pack_payload(
            zip_path=zip_path,
            pack_id=pack_id,
            safe_label=safe_label,
            pack_origin=pack_origin,
            next_numeric=next_numeric,
        )
        if not ok:
            return False, note

        state = _load_installed_generator_packs_state()
        state.setdefault('packs', [])
        state['packs'].append({
            'id': pack_id,
            'label': safe_label,
            'origin': pack_origin,
            'note': note,
            'warnings': warnings,
            'installed_at': _local_timestamp_display(),
            'installed': installed,
        })
        _save_installed_generator_packs_state(state)
        warn_note = ''
        try:
            if isinstance(warnings, list) and warnings:
                warn_note = f" (warnings: {len(warnings)})"
        except Exception:
            warn_note = ''
        return True, f"Installed {len(installed)} generator(s) from {safe_label}" + warn_note
    except ValueError as ve:
        return False, str(ve)
    except Exception as exc:
        return False, str(exc)


def _read_generator_pack_zip_metadata(zip_path: str) -> dict[str, Any]:
    try:
        import zipfile

        with zipfile.ZipFile(zip_path, 'r') as archive:
            if 'pack.json' not in archive.namelist():
                return {}
            raw = archive.read('pack.json').decode('utf-8', errors='ignore')
        data = json.loads(raw or '{}')
        return data if isinstance(data, dict) else {}
    except Exception:
        return {}


def _install_generator_pack_or_bundle(*, zip_path: str, pack_label: str, pack_origin: str) -> tuple[bool, str]:
    """Install either a single generator-pack ZIP, or a bundle ZIP produced by export_all.

    A bundle is a ZIP that contains one or more nested pack ZIPs. By convention,
    export_all writes them under packs/*.zip, but we also accept nested *.zip files
    anywhere in the archive.
    """
    import tempfile
    import zipfile

    try:
        with zipfile.ZipFile(zip_path, 'r') as z:
            names = [str(n or '') for n in z.namelist()]

            normalized_names = [n.replace('\\', '/') for n in names]
            has_manifest = any(n.endswith('/manifest.yaml') or n.endswith('/manifest.yml') for n in normalized_names)
            nested_all = [
                n for n in normalized_names
                if n and (not n.endswith('/')) and n.lower().endswith('.zip') and (not n.startswith('__MACOSX/'))
            ]
            # Prefer the export_all convention, but accept bundles created by users too.
            nested = [n for n in nested_all if n.startswith('packs/')]
            if not nested:
                nested = nested_all

            looks_like_vuln_catalog_bundle = (
                any(n == 'catalogs.json' or n.endswith('/catalogs.json') for n in normalized_names)
                or any(n.startswith('catalogs/') and n.lower().endswith('.zip') for n in normalized_names)
            )
            if (not has_manifest) and looks_like_vuln_catalog_bundle:
                return False, 'This looks like a Vulnerability Catalog export. Upload it from the Vulnerability Catalog page.'

            if (not has_manifest) and nested:
                # Bundle import: install each nested pack as its own saved pack
                # row so catalog categories survive export/import round trips.
                bundle_label = secure_filename(pack_label or 'bundle') or 'bundle'
                try:
                    repo_root = _get_repo_root()
                except Exception:
                    repo_root = os.getcwd()
                next_numeric = _compute_next_numeric_generator_id(repo_root=repo_root)

                successes = 0
                failures: list[str] = []
                rows_to_append: list[dict[str, Any]] = []
                warnings_total = 0

                for inner_name in sorted(set(nested)):
                    try:
                        inner_bytes = z.read(inner_name)
                    except Exception as exc:
                        failures.append(f'{inner_name}: read failed ({exc})')
                        continue

                    fd, inner_tmp = tempfile.mkstemp(prefix='coretg_pack_bundle_', suffix='-' + os.path.basename(inner_name))
                    os.close(fd)
                    try:
                        with open(inner_tmp, 'wb') as fh:
                            fh.write(inner_bytes)

                        source_meta = _read_generator_pack_zip_metadata(inner_tmp)
                        inner_label_raw = str(source_meta.get('label') or '').strip()
                        if not inner_label_raw:
                            inner_label_raw = os.path.splitext(os.path.basename(inner_name))[0]
                        safe_inner_label = secure_filename(inner_label_raw or bundle_label) or bundle_label
                        inner_origin = str(source_meta.get('origin') or pack_origin or 'upload').strip() or 'upload'
                        inner_pack_id = _local_timestamp_safe() + '-' + uuid.uuid4().hex[:6]

                        ok_inner, note_inner, installed_inner, next_numeric, warnings_inner = _install_generator_pack_payload(
                            zip_path=inner_tmp,
                            pack_id=inner_pack_id,
                            safe_label=safe_inner_label,
                            pack_origin=inner_origin,
                            next_numeric=next_numeric,
                        )
                        if ok_inner:
                            if isinstance(warnings_inner, list) and warnings_inner:
                                warnings_total += len(warnings_inner)
                            rows_to_append.append({
                                'id': inner_pack_id,
                                'label': safe_inner_label,
                                'origin': inner_origin,
                                'note': note_inner,
                                'warnings': warnings_inner,
                                'installed_at': _local_timestamp_display(),
                                'installed': installed_inner,
                                'source_pack_id': str(source_meta.get('id') or '').strip(),
                                'source_pack_label': str(source_meta.get('label') or '').strip(),
                                'source_pack_origin': str(source_meta.get('origin') or '').strip(),
                                'bundle_label': bundle_label,
                                'bundle_origin': pack_origin,
                                'bundle_archive': inner_name,
                            })
                            successes += 1
                        else:
                            failures.append(f'{inner_name}: {note_inner}')
                    finally:
                        try:
                            os.remove(inner_tmp)
                        except Exception:
                            pass

                # Record one combined bundle pack state row only when at least
                # one nested pack installed successfully.
                if rows_to_append:
                    try:
                        state = _load_installed_generator_packs_state()
                        state.setdefault('packs', [])
                        state['packs'].extend(rows_to_append)
                        _save_installed_generator_packs_state(state)
                    except Exception:
                        pass

                warn_note = f" (warnings: {warnings_total})" if warnings_total else ''
                if failures:
                    return successes > 0, f'Imported {successes} pack(s) from bundle as separate categories from {bundle_label}{warn_note}; {failures[0]}'
                return True, f'Imported {successes} pack(s) from bundle as separate categories from {bundle_label}{warn_note}'

    except Exception as exc:
        return False, f'Invalid zip: {exc}'

    return _install_generator_pack(zip_path=zip_path, pack_label=pack_label, pack_origin=pack_origin)


def _flag_catalog_packs_for_export() -> list[dict[str, Any]]:
    """Return visible Flag Catalog pack rows.

    Installed packs are the normal source of truth. Repo-local generator folders
    are still recognized as an optional developer workflow when present.
    """
    state = _load_installed_generator_packs_state()
    packs = state.get('packs') if isinstance(state, dict) else []
    if not isinstance(packs, list):
        packs = []
    result = [pack for pack in packs if isinstance(pack, dict)]
    changed = False

    def _repo_local_pack_key(kind: str, manifest_path: str, source_path: str) -> tuple[str, str, str, str] | None:
        kind_norm = str(kind or '').strip().lower().replace('_', '-')
        base_dir = 'flag_node_generators' if kind_norm == 'flag-node-generator' else 'flag_generators'
        for raw in (str(manifest_path or ''), str(source_path or '')):
            normalized = raw.replace('\\', '/').strip()
            if not normalized or 'outputs/installed_generators' in normalized:
                continue
            marker = f'/{base_dir}/'
            idx = normalized.find(marker)
            if idx >= 0:
                tail = normalized[idx + len(marker):].strip('/')
            elif normalized.startswith(base_dir + '/'):
                tail = normalized[len(base_dir) + 1:].strip('/')
            else:
                continue
            if not tail:
                continue
            pack = tail.split('/', 1)[0].strip()
            if not pack or pack.startswith('_'):
                continue
            pack_id = f'repo-local:{base_dir}:{pack}'
            origin = f'{base_dir}/{pack}'
            pack_path = origin
            if idx >= 0:
                pack_path = normalized[:idx + len(marker)] + pack
            return pack_id, pack, origin, pack_path
        return None

    def _pretty_pack_label(pack: str) -> str:
        parts = [part for part in str(pack or '').replace('-', '_').split('_') if part]
        if not parts:
            return 'Repo Local'
        acronyms = {'dns', 'ftp', 'http', 'https', 'imap', 'ldap', 'mqtt', 'nfs', 'smb', 'smtp', 'ssh'}
        return ' '.join(part.upper() if part.lower() in acronyms else part.capitalize() for part in parts)

    def _merge_repo_local_item_state(existing: dict[str, Any], repo_pack: dict[str, Any]) -> bool:
        preserved_keys = {
            'disabled',
            'uninstalled',
            'uninstalled_at',
            'validated_ok',
            'validated_incomplete',
            'validated_at',
            'last_test_log_path',
            'last_test_log_filename',
        }
        existing_items = existing.get('installed') if isinstance(existing.get('installed'), list) else []
        preserved_by_key: dict[tuple[str, str], dict[str, Any]] = {}
        for old_item in existing_items:
            if not isinstance(old_item, dict):
                continue
            key = (str(old_item.get('kind') or '').strip(), str(old_item.get('id') or '').strip())
            if key[0] and key[1]:
                preserved_by_key[key] = old_item

        changed = False
        merged_items: list[dict[str, Any]] = []
        for new_item in repo_pack.get('installed') or []:
            if not isinstance(new_item, dict):
                continue
            item = dict(new_item)
            key = (str(item.get('kind') or '').strip(), str(item.get('id') or '').strip())
            old_item = preserved_by_key.get(key)
            if isinstance(old_item, dict):
                for preserved_key in preserved_keys:
                    if preserved_key in old_item and item.get(preserved_key) != old_item.get(preserved_key):
                        item[preserved_key] = old_item.get(preserved_key)
            merged_items.append(item)

        if existing.get('installed') != merged_items:
            existing['installed'] = merged_items
            changed = True
        return changed

    repo_packs: dict[str, dict[str, Any]] = {}
    loaders = [
        ('flag-generator', _flag_generators_from_all_installed_sources),
        ('flag-node-generator', _flag_node_generators_from_all_installed_sources),
    ]
    for kind, loader in loaders:
        try:
            generators, _errors = loader()
        except Exception:
            continue
        for generator in (generators or []):
            if not isinstance(generator, dict):
                continue
            gid = str(generator.get('id') or '').strip()
            if not gid:
                continue
            source = generator.get('source') if isinstance(generator.get('source'), dict) else {}
            key = _repo_local_pack_key(kind, str(generator.get('_source_path') or ''), str(source.get('path') or ''))
            if key is None:
                continue
            pack_id, pack_name, origin, pack_path = key
            pack = repo_packs.setdefault(pack_id, {
                'id': pack_id,
                'label': _pretty_pack_label(pack_name),
                'origin': origin,
                'installed_at': 'repo-local',
                'installed': [],
                'disabled': False,
                'repo_local': True,
            })
            pack['installed'].append({
                'id': gid,
                'kind': kind,
                'path': pack_path,
                'manifest_path': str(generator.get('_source_path') or ''),
                'repo_local': True,
            })

    kept: list[dict[str, Any]] = []
    for pack in result:
        pack_id = str(pack.get('id') or '').strip()
        if pack.get('repo_local') is True and pack.get('uninstalled') is not True and pack_id not in repo_packs:
            changed = True
            continue
        kept.append(pack)
    result = kept
    existing_by_id = {str(pack.get('id') or '').strip(): pack for pack in result if isinstance(pack, dict)}
    for pack_id in sorted(repo_packs):
        existing = existing_by_id.get(pack_id)
        if isinstance(existing, dict):
            if existing.get('uninstalled') is True:
                continue
            repo_pack = repo_packs[pack_id]
            for key in ('label', 'origin', 'installed_at', 'installed', 'repo_local'):
                if key == 'installed':
                    if _merge_repo_local_item_state(existing, repo_pack):
                        changed = True
                    continue
                if existing.get(key) != repo_pack.get(key):
                    existing[key] = repo_pack.get(key)
                    changed = True
            continue
        result.append(repo_packs[pack_id])
        changed = True

    if changed:
        state['packs'] = result
        _save_installed_generator_packs_state(state)
    return [pack for pack in result if isinstance(pack, dict) and pack.get('uninstalled') is not True]


