def _pack_to_zip_bytes(pack: dict) -> bytes:
    """Build a ZIP archive for a single installed pack."""
    import io
    import zipfile

    mem = io.BytesIO()
    installed = pack.get('installed') if isinstance(pack, dict) else []
    with zipfile.ZipFile(mem, 'w', zipfile.ZIP_DEFLATED) as z:
        # Pack metadata
        try:
            meta = json.dumps(pack, indent=2)
        except Exception:
            meta = '{}'
        z.writestr('pack.json', meta + '\n')

        seen_sources: set[str] = set()
        for it in (installed or []):
            if not isinstance(it, dict):
                continue
            if it.get('uninstalled') is True:
                continue
            kind = str(it.get('kind') or '').strip()
            src = str(it.get('path') or '').strip()
            if src and not os.path.isabs(src):
                try:
                    src = os.path.join(_get_repo_root(), src)
                except Exception:
                    src = os.path.abspath(src)
            if not src or not os.path.exists(src):
                continue
            abs_src = os.path.abspath(src)
            if abs_src in seen_sources:
                continue
            seen_sources.add(abs_src)

            base = 'flag_generators'
            if kind == 'flag-node-generator':
                base = 'flag_node_generators'

            root_name = os.path.basename(src.rstrip('/')) or 'generator'
            if os.path.isdir(src):
                for dirpath, _dirnames, filenames in os.walk(src):
                    for fn in filenames:
                        abs_p = os.path.join(dirpath, fn)
                        rel_p = os.path.relpath(abs_p, src)
                        arc = '/'.join([base, root_name, rel_p.replace('\\', '/')])
                        try:
                            z.write(abs_p, arcname=arc)
                        except Exception:
                            continue
            else:
                arc = '/'.join([base, root_name])
                try:
                    z.write(src, arcname=arc)
                except Exception:
                    pass

    mem.seek(0)
    return mem.read()


def _delete_installed_generator(*, kind: str, generator_id: str) -> tuple[bool, str]:
    """Delete a single installed generator directory by manifest id.

    Safety: only deletes directories under outputs/installed_generators.
    """
    import shutil
    from pathlib import Path

    try:
        import yaml  # type: ignore
    except Exception as exc:
        return False, f'PyYAML required: {exc}'

    gid = str(generator_id or '').strip()
    if not gid:
        return False, 'Missing generator_id'

    k = str(kind or '').strip().lower().replace('_', '-')
    if k not in ('flag-generator', 'flag-node-generator'):
        return False, f'Invalid kind: {kind}'

    installed_root = os.path.abspath(_installed_generators_root())
    state = _load_installed_generator_packs_state()
    packs = state.get('packs') if isinstance(state, dict) else None
    if not isinstance(packs, list):
        packs = []

    state_target_item: dict[str, Any] | None = None
    state_target_pack: dict[str, Any] | None = None
    state_target_path = ''
    for pack in packs:
        if not isinstance(pack, dict):
            continue
        installed_items = pack.get('installed') if isinstance(pack.get('installed'), list) else []
        for item in installed_items:
            if not isinstance(item, dict):
                continue
            if not _installed_generator_state_item_matches(item=item, kind=k, generator_id=gid):
                continue
            state_target_pack = pack
            state_target_item = item
            state_target_path = str(item.get('path') or '').strip()
            break
        if state_target_item is not None:
            break

    if state_target_item is not None:
        abs_state_path = os.path.abspath(state_target_path) if state_target_path else ''
        is_repo_local = bool(state_target_item.get('repo_local') is True or (state_target_pack or {}).get('repo_local') is True)
        try:
            is_under_installed_root = bool(abs_state_path and os.path.commonpath([installed_root, abs_state_path]) == installed_root)
        except Exception:
            is_under_installed_root = False
        if is_repo_local or not is_under_installed_root:
            state_target_item['disabled'] = True
            state_target_item['uninstalled'] = True
            state_target_item['uninstalled_at'] = _local_timestamp_display()
            if state_target_pack is not None:
                active_items = [
                    item for item in (state_target_pack.get('installed') or [])
                    if isinstance(item, dict) and item.get('uninstalled') is not True
                ]
                if not active_items:
                    state_target_pack['disabled'] = True
                    state_target_pack['uninstalled'] = True
                    state_target_pack['uninstalled_at'] = _local_timestamp_display()
            state['packs'] = packs
            _save_installed_generator_packs_state(state)
            return True, f'Uninstalled repo-local {k} {gid} (workspace files remain)'

    base = os.path.join(installed_root, 'flag_node_generators' if k == 'flag-node-generator' else 'flag_generators')
    if not os.path.isdir(base):
        return False, 'No installed generators directory'

    target_dir: str | None = None
    if state_target_path:
        try:
            abs_state_path = os.path.abspath(state_target_path)
            if os.path.isdir(abs_state_path) and os.path.commonpath([installed_root, abs_state_path]) == installed_root:
                target_dir = abs_state_path
        except Exception:
            target_dir = None

    for child in sorted(Path(base).iterdir()):
        if target_dir:
            break
        if not child.is_dir():
            continue
        manifest_path = None
        for nm in ('manifest.yaml', 'manifest.yml'):
            p = child / nm
            if p.exists() and p.is_file():
                manifest_path = p
                break
        if manifest_path is None:
            continue
        try:
            doc = yaml.safe_load(manifest_path.read_text('utf-8', errors='ignore'))
        except Exception:
            continue
        if not isinstance(doc, dict):
            continue
        mid = str(doc.get('id') or '').strip()
        if mid == gid:
            target_dir = str(child)
            break
        marker_path = child / '.coretg_pack.json'
        if marker_path.exists() and marker_path.is_file():
            try:
                marker = json.loads(marker_path.read_text('utf-8', errors='ignore') or '{}')
            except Exception:
                marker = None
            if isinstance(marker, dict) and str(marker.get('source_generator_id') or '').strip() == gid:
                target_dir = str(child)
                break

    if not target_dir:
        return False, f'Installed generator not found: {gid}'

    abs_target = os.path.abspath(target_dir)
    try:
        if os.path.commonpath([installed_root, abs_target]) != installed_root:
            return False, f'Refused to delete outside installed root: {abs_target}'
    except Exception:
        return False, f'Refused to delete path: {abs_target}'

    try:
        shutil.rmtree(abs_target, ignore_errors=False)
    except Exception as exc:
        return False, f'Failed deleting {abs_target}: {exc}'

    # Update pack state: remove references to this generator.
    try:
        state = _load_installed_generator_packs_state()
        packs = state.get('packs') or []
        if not isinstance(packs, list):
            packs = []
        kept_packs = []
        removed_refs = 0
        for p in packs:
            if not isinstance(p, dict):
                continue
            installed = p.get('installed') or []
            if not isinstance(installed, list):
                installed = []
            new_installed = []
            for it in installed:
                if not isinstance(it, dict):
                    continue
                it_path = str(it.get('path') or '').strip()
                if _installed_generator_state_item_matches(item=it, kind=k, generator_id=gid):
                    removed_refs += 1
                    continue
                if it_path and os.path.abspath(it_path) == abs_target:
                    removed_refs += 1
                    continue
                new_installed.append(it)

            if new_installed:
                p2 = dict(p)
                p2['installed'] = new_installed
                kept_packs.append(p2)
            else:
                # Drop pack row if no installed generators remain.
                continue
        state['packs'] = kept_packs
        _save_installed_generator_packs_state(state)
    except Exception:
        removed_refs = 0

    note = f'Deleted installed {k} {gid}'
    if removed_refs:
        note += f' (updated {removed_refs} pack reference(s))'
    return True, note





def _flag_generators_runs_dir() -> str:
    d = os.path.join(_outputs_dir(), 'flag_generators_runs')
    os.makedirs(d, exist_ok=True)
    return d


def _flaggen_run_dir_for_id(run_id: str) -> str:
    """Resolve a local flag generator run directory for a run_id.

    This allows artifact browsing/downloading even if the webapp restarted and
    the in-memory RUNS registry was lost.
    """
    rid = (run_id or '').strip()
    # Basic sanitization: avoid path traversal.
    rid = rid.replace('..', '').replace('\\', '/').strip('/').strip()
    return os.path.join(_flag_generators_runs_dir(), rid)


def _flag_node_generators_runs_dir() -> str:
    d = os.path.join(_outputs_dir(), 'flag_node_generators_runs')
    os.makedirs(d, exist_ok=True)
    return d


def _flagnodegen_run_dir_for_id(run_id: str) -> str:
    rid = (run_id or '').strip()
    rid = rid.replace('..', '').replace('\\', '/').strip('/').strip()
    return os.path.join(_flag_node_generators_runs_dir(), rid)


def _parse_flag_test_core_cfg_from_form(form: Any) -> Dict[str, Any] | None:
    raw = str((form or {}).get('core') or '').strip()
    if not raw:
        return None
    try:
        payload = json.loads(raw)
    except Exception as exc:
        raise RuntimeError(f'Invalid core payload: {exc}') from exc
    if not isinstance(payload, dict):
        raise RuntimeError('Invalid core payload: expected object')
    core_cfg = _merge_core_configs(payload, include_password=True)
    runtime_mode = _webui_runtime_mode()
    core_cfg = _prefer_explicit_or_ssh_core_host(core_cfg, payload)
    if not core_cfg.get('host'):
        if runtime_mode == 'vm':
            core_cfg['host'] = core_cfg.get('ssh_host') or '127.0.0.1'
        else:
            core_cfg['host'] = '127.0.0.1'
    if not core_cfg.get('port'):
        core_cfg['port'] = CORE_PORT
    return _require_core_ssh_credentials(core_cfg)

def _load_saved_flag_generators_test_core_cfg() -> Dict[str, Any] | None:
    hint_path = os.path.join(_outputs_dir(), 'flag_generators_test_core_hint.json')
    try:
        if not os.path.exists(hint_path):
            return None
        with open(hint_path, 'r', encoding='utf-8') as fh:
            hint = json.load(fh)
    except Exception:
        return None
    if not isinstance(hint, dict):
        return None
    secret_id = str(hint.get('core_secret_id') or '').strip()
    if not secret_id:
        return None
    record = _load_core_credentials(secret_id)
    if not isinstance(record, dict):
        return None
    core_cfg = {
        'host': record.get('grpc_host') or record.get('host') or record.get('ssh_host') or '127.0.0.1',
        'port': int(record.get('grpc_port') or record.get('port') or CORE_PORT),
        'ssh_host': record.get('ssh_host') or record.get('host') or '127.0.0.1',
        'ssh_port': int(record.get('ssh_port') or 22),
        'ssh_username': record.get('ssh_username') or '',
        'ssh_password': record.get('ssh_password_plain') or record.get('password_plain') or '',
        'ssh_enabled': True,
        'venv_bin': record.get('venv_bin') or DEFAULT_CORE_VENV_BIN,
        'core_secret_id': record.get('identifier') or secret_id,
    }
    try:
        return _require_core_ssh_credentials(core_cfg)
    except Exception:
        return None


def _ensure_core_vm_idle_for_test(core_cfg: Dict[str, Any]) -> None:
    errors: list[str] = []
    host = str(core_cfg.get('host') or '127.0.0.1')
    port = int(core_cfg.get('port') or CORE_PORT)
    sessions = _list_active_core_sessions(host, port, core_cfg, errors=errors, meta={})
    if errors:
        raise RuntimeError(f'Unable to verify CORE sessions: {errors[0]}')
    if sessions:
        raise RuntimeError('CORE VM has active session(s). Stop running scenario before testing.')

def _run_remote_builder_scaffold_test(
    *,
    scaffold_files: Dict[str, str],
    plugin_kind: str,
    plugin_id: str,
    config: Dict[str, Any],
) -> Dict[str, Any]:
    core_cfg = _load_saved_flag_generators_test_core_cfg()
    if not isinstance(core_cfg, dict):
        raise RuntimeError('Saved CORE VM generator-test credentials not found. Save generator test CORE credentials first.')
    _ensure_core_vm_idle_for_test(core_cfg)

    run_id = _local_timestamp_safe() + '-' + uuid.uuid4().hex[:10]
    temp_root = tempfile.mkdtemp(prefix='generator-builder-remote-', dir=_outputs_dir())
    staged_repo = os.path.join(temp_root, 'repo')
    local_run_dir = os.path.join(temp_root, 'run')
    os.makedirs(staged_repo, exist_ok=True)
    os.makedirs(local_run_dir, exist_ok=True)

    def _collect_local_output_files(run_dir: str) -> List[Dict[str, Any]]:
        files: List[Dict[str, Any]] = []
        if not os.path.isdir(run_dir):
            return files
        for root, _dirs, filenames in os.walk(run_dir):
            for filename in filenames:
                abs_path = os.path.join(root, filename)
                rel_path = os.path.relpath(abs_path, run_dir).replace('\\', '/')
                try:
                    size = os.path.getsize(abs_path)
                except Exception:
                    size = None
                text_content = None
                if size is not None and size <= 65536:
                    try:
                        with open(abs_path, 'r', encoding='utf-8') as handle:
                            text_content = handle.read()
                    except Exception:
                        text_content = None
                files.append({'path': rel_path, 'name': filename, 'size': size, 'text': text_content})
        files.sort(key=lambda entry: str(entry.get('path') or ''))
        return files

    for rel_path, content in scaffold_files.items():
        abs_path = os.path.join(staged_repo, rel_path)
        os.makedirs(os.path.dirname(abs_path), exist_ok=True)
        with open(abs_path, 'w', encoding='utf-8') as handle:
            handle.write(content)

    ssh_client = None
    sftp = None
    remote_env_path = ''
    remote_repo_dir = ''
    remote_run_dir = ''
    try:
        _push_repo_to_remote(
            core_cfg,
            logger=app.logger,
            include_repo_paths=[
                'scripts/run_flag_generator.py',
                'scenarioforge',
                'flag_generators',
                'flag_node_generators',
                'outputs/installed_generators/flag_generators',
                'outputs/installed_generators/flag_node_generators',
            ],
        )
        ssh_client = _open_ssh_client(core_cfg)
        sftp = ssh_client.open_sftp()
        remote_static_repo = _remote_static_repo_dir(sftp)
        remote_repo_dir = _remote_path_join('/tmp/tests', f'flag-builder-repo-{run_id}')
        remote_run_dir = _remote_path_join('/tmp/tests', f'flag-builder-run-{run_id}')
        _remote_remove_path(ssh_client, remote_repo_dir)
        _remote_remove_path(ssh_client, remote_run_dir)
        _exec_ssh_command(
            ssh_client,
            f"mkdir -p {shlex.quote(posixpath.dirname(remote_repo_dir) or '/tmp/tests')} && cp -R {shlex.quote(remote_static_repo)} {shlex.quote(remote_repo_dir)}",
            timeout=300.0,
            check=True,
        )
        _remote_mkdirs(ssh_client, remote_run_dir)
        _remote_mkdirs(ssh_client, _remote_path_join(remote_run_dir, 'inputs'))

        for rel_path in scaffold_files.keys():
            local_path = os.path.join(staged_repo, rel_path)
            remote_path = _remote_path_join(remote_repo_dir, rel_path.replace('\\', '/'))
            _remote_mkdirs(ssh_client, posixpath.dirname(remote_path) or remote_repo_dir)
            sftp.put(local_path, remote_path)

        sudo_pw = str(core_cfg.get('ssh_password') or '')

        def _sh_single_quote(val: str) -> str:
            return "'" + (val or '').replace("'", "'\\''") + "'"

        remote_env_path = _remote_path_join(remote_run_dir, '.coretg_env.sh')
        env_lines = [
            '#!/usr/bin/env bash',
            'set -euo pipefail',
            'export CORETG_DOCKER_USE_SUDO=1',
            'export CORETG_DOCKER_HOST_NETWORK=1',
            f"export CORETG_DOCKER_SUDO_PASSWORD={_sh_single_quote(sudo_pw)}",
        ]
        with sftp.open(remote_env_path, 'w') as fh:
            fh.write('\n'.join(env_lines) + '\n')
        _exec_ssh_command(ssh_client, f"chmod 600 {shlex.quote(remote_env_path)}")

        python_exec = _select_remote_python_interpreter(ssh_client, core_cfg)
        config_payload = json.dumps(config, ensure_ascii=False)
        remote_runner_path = _remote_path_join(remote_repo_dir, 'scripts', 'run_flag_generator.py')
        prefix = f"set -a && source {shlex.quote(remote_env_path)} && set +a && " if remote_env_path else ''
        cmd_inner = (
            f"{prefix}cd {shlex.quote(remote_repo_dir)} && "
            f"{shlex.quote(python_exec)} {shlex.quote(remote_runner_path)} "
            f"--kind {shlex.quote(plugin_kind)} "
            f"--generator-id {shlex.quote(plugin_id)} "
            f"--out-dir {shlex.quote(remote_run_dir)} "
            f"--config {shlex.quote(config_payload)} "
            f"--repo-root {shlex.quote(remote_repo_dir)}"
        )
        returncode, stdout, stderr = _exec_ssh_command(
            ssh_client,
            f"bash -lc {shlex.quote(cmd_inner)}",
            timeout=300.0,
            check=False,
        )
        _download_remote_tree(sftp, remote_run_dir, local_run_dir)
        return {
            'ok': returncode == 0,
            'returncode': returncode,
            'stdout': stdout,
            'stderr': stderr,
            'files': _collect_local_output_files(local_run_dir),
        }
    finally:
        try:
            if ssh_client and remote_env_path:
                _remote_remove_path(ssh_client, remote_env_path)
        except Exception:
            pass
        try:
            if ssh_client and remote_run_dir:
                _remote_remove_path(ssh_client, remote_run_dir)
        except Exception:
            pass
        try:
            if ssh_client and remote_repo_dir:
                _remote_remove_path(ssh_client, remote_repo_dir)
        except Exception:
            pass
        try:
            if sftp:
                sftp.close()
        except Exception:
            pass
        try:
            if ssh_client:
                ssh_client.close()
        except Exception:
            pass
        try:
            shutil.rmtree(temp_root, ignore_errors=True)
        except Exception:
            pass

def _start_remote_builder_scaffold_test_process(
    *,
    run_id: str,
    run_dir: str,
    log_handle: Any,
    scaffold_files: Dict[str, str],
    plugin_kind: str,
    plugin_id: str,
    cfg: Dict[str, Any],
    core_cfg: Dict[str, Any],
) -> Dict[str, Any]:
    ssh_client = _open_ssh_client(core_cfg)
    sftp = ssh_client.open_sftp()
    remote_static_repo = _remote_static_repo_dir(sftp)
    remote_repo_dir = _remote_path_join('/tmp/tests', f'flag-builder-repo-{run_id}')
    remote_run_dir = _remote_path_join('/tmp/tests', f'flag-builder-run-{run_id}')

    try:
        _push_repo_to_remote(
            core_cfg,
            logger=app.logger,
            include_repo_paths=[
                'scripts/run_flag_generator.py',
                'scenarioforge',
                'flag_generators',
                'flag_node_generators',
                'outputs/installed_generators/flag_generators',
                'outputs/installed_generators/flag_node_generators',
            ],
            log_handle=log_handle,
        )
    except Exception:
        try:
            sftp.close()
        except Exception:
            pass
        sftp = ssh_client.open_sftp()
        remote_static_repo = _remote_static_repo_dir(sftp)

    _remote_remove_path(ssh_client, remote_repo_dir)
    _remote_remove_path(ssh_client, remote_run_dir)
    _exec_ssh_command(
        ssh_client,
        f"mkdir -p {shlex.quote(posixpath.dirname(remote_repo_dir) or '/tmp/tests')} && cp -R {shlex.quote(remote_static_repo)} {shlex.quote(remote_repo_dir)}",
        timeout=300.0,
        check=True,
    )
    _remote_mkdirs(ssh_client, remote_run_dir)
    _remote_mkdirs(ssh_client, _remote_path_join(remote_run_dir, 'inputs'))

    local_staging_dir = tempfile.mkdtemp(prefix='generator-builder-stage-', dir=_outputs_dir())
    try:
        for rel_path, content in scaffold_files.items():
            local_path = os.path.join(local_staging_dir, rel_path)
            os.makedirs(os.path.dirname(local_path), exist_ok=True)
            with open(local_path, 'w', encoding='utf-8') as handle:
                handle.write(content)
            remote_path = _remote_path_join(remote_repo_dir, rel_path.replace('\\', '/'))
            _remote_mkdirs(ssh_client, posixpath.dirname(remote_path) or remote_repo_dir)
            sftp.put(local_path, remote_path)

        local_inputs_dir = os.path.join(run_dir, 'inputs')
        if os.path.isdir(local_inputs_dir):
            for root, dirs, files in os.walk(local_inputs_dir):
                rel = os.path.relpath(root, local_inputs_dir)
                rel = '' if rel == '.' else rel
                remote_root = _remote_path_join(remote_run_dir, 'inputs', rel) if rel else _remote_path_join(remote_run_dir, 'inputs')
                _remote_mkdirs(ssh_client, remote_root)
                for directory_name in dirs:
                    _remote_mkdirs(ssh_client, _remote_path_join(remote_root, directory_name))
                for filename in files:
                    local_file = os.path.join(root, filename)
                    remote_file = _remote_path_join(remote_root, filename)
                    if os.path.isfile(local_file):
                        sftp.put(local_file, remote_file)
    finally:
        try:
            shutil.rmtree(local_staging_dir, ignore_errors=True)
        except Exception:
            pass

    try:
        sudo_pw = str(core_cfg.get('ssh_password') or '')
    except Exception:
        sudo_pw = ''
    remote_env_path = _remote_path_join(remote_run_dir, '.coretg_env.sh')
    try:
        def _sh_single_quote(val: str) -> str:
            return "'" + (val or '').replace("'", "'\\''") + "'"

        env_lines = [
            '#!/usr/bin/env bash',
            'set -euo pipefail',
            'export CORETG_DOCKER_USE_SUDO=1',
            'export CORETG_DOCKER_HOST_NETWORK=1',
            f"export CORETG_DOCKER_SUDO_PASSWORD={_sh_single_quote(sudo_pw)}",
        ]
        with sftp.open(remote_env_path, 'w') as fh:
            fh.write('\n'.join(env_lines) + '\n')
        _exec_ssh_command(ssh_client, f"chmod 600 {shlex.quote(remote_env_path)}")
    except Exception:
        remote_env_path = ''

    python_exec = _select_remote_python_interpreter(ssh_client, core_cfg)
    config_payload = json.dumps(cfg, ensure_ascii=False)
    remote_runner_path = _remote_path_join(remote_repo_dir, 'scripts', 'run_flag_generator.py')
    prefix = f"set -a && source {shlex.quote(remote_env_path)} && set +a && " if remote_env_path else ''
    cmd_inner = (
        f"{prefix}cd {shlex.quote(remote_repo_dir)} && "
        f"{shlex.quote(python_exec)} {shlex.quote(remote_runner_path)} "
        f"--kind {shlex.quote(plugin_kind)} "
        f"--generator-id {shlex.quote(plugin_id)} "
        f"--out-dir {shlex.quote(remote_run_dir)} "
        f"--config {shlex.quote(config_payload)} "
        f"--repo-root {shlex.quote(remote_repo_dir)}"
    )
    cmd = f"bash -lc {shlex.quote(cmd_inner)}"

    channel = ssh_client.get_transport().open_session() if ssh_client.get_transport() else None
    if channel is None:
        raise RuntimeError('SSH channel unavailable')
    try:
        channel.get_pty()
    except Exception:
        pass
    channel.exec_command(cmd)
    relay_thread = threading.Thread(
        target=_relay_remote_channel_to_log,
        args=(channel, log_handle),
        kwargs={'redact_tokens': [sudo_pw] if sudo_pw else []},
        daemon=True,
    )
    relay_thread.start()
    try:
        sftp.close()
    except Exception:
        pass
    return {
        'ssh_client': ssh_client,
        'ssh_channel': channel,
        'ssh_log_thread': relay_thread,
        'remote_run_dir': remote_run_dir,
        'remote_repo_dir': remote_repo_dir,
        'remote_env_path': remote_env_path,
    }
try:
    from webapp.routes import core_test_prepare as _core_test_prepare_routes

    _core_test_prepare_routes.register(
        app,
        backend_module=sys.modules[__name__],
    )
except Exception:
    try:
        app.logger.exception('Failed to register core_test_prepare routes.')
    except Exception:
        pass


def _download_remote_tree(sftp: Any, remote_root: str, local_root: str, *, skip_names: Optional[set[str]] = None) -> int:
    copied = 0
    skips = skip_names or set()
    os.makedirs(local_root, exist_ok=True)
    for entry in sftp.listdir_attr(remote_root):
        name = str(getattr(entry, 'filename', '') or '').strip()
        if not name or name in {'.', '..'} or name in skips:
            continue
        remote_path = _remote_path_join(remote_root, name)
        local_path = os.path.join(local_root, name)
        mode = int(getattr(entry, 'st_mode', 0) or 0)
        if stat.S_ISDIR(mode):
            copied += _download_remote_tree(sftp, remote_path, local_path, skip_names=skip_names)
            continue
        os.makedirs(os.path.dirname(local_path), exist_ok=True)
        sftp.get(remote_path, local_path)
        copied += 1
    return copied


def _sync_remote_flag_test_outputs(meta: Dict[str, Any]) -> None:
    if not isinstance(meta, dict) or not meta.get('remote'):
        return
    core_cfg = meta.get('core_cfg') if isinstance(meta.get('core_cfg'), dict) else None
    remote_run_dir = str(meta.get('remote_run_dir') or '').strip()
    run_dir = str(meta.get('run_dir') or '').strip()
    if not core_cfg or not remote_run_dir or not run_dir:
        return
    client = None
    sftp = None
    copied = 0
    try:
        client = _open_ssh_client(core_cfg)
        sftp = client.open_sftp()
        copied = _download_remote_tree(sftp, remote_run_dir, run_dir)
        meta['remote_outputs_synced'] = True
    except Exception as exc:
        try:
            app.logger.warning('[flag_test] remote output sync failed: %s', exc)
        except Exception:
            pass
        return
    finally:
        try:
            if sftp:
                sftp.close()
        except Exception:
            pass
        try:
            if client:
                client.close()
        except Exception:
            pass
    try:
        lp = str(meta.get('log_path') or '').strip()
        if lp:
            with open(lp, 'a', encoding='utf-8') as log_f:
                log_f.write(f"[remote] synced outputs: {copied} file(s)\n")
    except Exception:
        pass


def _start_remote_flag_test_process(
    *,
    run_id: str,
    run_dir: str,
    log_handle: Any,
    kind: str,
    generator_id: str,
    cfg: Dict[str, Any],
    run_remote_builder_test=lambda *args, **kwargs: _run_remote_builder_scaffold_test(*args, **kwargs),
    core_cfg: Dict[str, Any],
) -> Dict[str, Any]:
    ssh_client = _open_ssh_client(core_cfg)
    sftp = ssh_client.open_sftp()
    remote_repo_dir = _remote_static_repo_dir(sftp)
    remote_runner_path = _remote_path_join(remote_repo_dir, 'scripts', 'run_flag_generator.py')

    # Resolve selected generator early so we can sync its source path to the
    # remote static repo before execution.
    try:
        if str(kind or '').strip() == 'flag-generator':
            selected_gen = _find_enabled_generator_by_id(generator_id)
        else:
            selected_gen = _find_enabled_node_generator_by_id(generator_id)
    except Exception:
        selected_gen = None

    # Best-effort: keep remote static repo runner in sync with local.
    # This avoids confusing drift when the webapp changes behavior (e.g., sudo prompt suppression).
    try:
        local_repo_root = _get_repo_root()
        local_runner = os.path.join(local_repo_root, 'scripts', 'run_flag_generator.py')
        if os.path.isfile(local_runner):
            sftp.put(local_runner, remote_runner_path)
    except Exception:
        pass

    # Always refresh the remote static repo with required runtime paths. This
    # keeps remote tests in sync with newly added local generators.
    include_repo_paths: list[str] = [
        'scripts/run_flag_generator.py',
        'scenarioforge',
        'flag_generators',
        'flag_node_generators',
        'outputs/installed_generators/flag_generators',
        'outputs/installed_generators/flag_node_generators',
    ]
    try:
        src_path_raw = str(
            (selected_gen or {}).get('_source_path')
            or ((selected_gen or {}).get('source') or {}).get('path')
            or ''
        ).strip()
        if src_path_raw:
            repo_root_abs = os.path.abspath(_get_repo_root())
            src_abs = os.path.abspath(src_path_raw) if os.path.isabs(src_path_raw) else os.path.abspath(os.path.join(repo_root_abs, src_path_raw))
            if os.path.commonpath([repo_root_abs, src_abs]) == repo_root_abs:
                rel = os.path.relpath(src_abs, repo_root_abs).replace('\\', '/')
                if rel:
                    include_repo_paths.append(rel)
    except Exception:
        pass
    include_repo_paths = list(dict.fromkeys([p for p in include_repo_paths if isinstance(p, str) and p.strip()]))
    try:
        _push_repo_to_remote(
            core_cfg,
            logger=app.logger,
            upload_only_injected_artifacts=False,
            include_repo_paths=include_repo_paths,
            log_handle=log_handle,
        )
        try:
            sftp.close()
        except Exception:
            pass
        sftp = ssh_client.open_sftp()
        remote_repo_dir = _remote_static_repo_dir(sftp)
        remote_runner_path = _remote_path_join(remote_repo_dir, 'scripts', 'run_flag_generator.py')
    except Exception:
        pass

    try:
        sftp.stat(remote_runner_path)
    except Exception as first_missing_exc:
        try:
            if log_handle:
                log_handle.write('[remote] runner missing on CORE VM; bootstrapping remote repo snapshot...\n')
                log_handle.flush()
        except Exception:
            pass

        include_repo_paths: list[str] = [
            'scripts/run_flag_generator.py',
            'scenarioforge',
            'flag_generators',
            'flag_node_generators',
            'outputs/installed_generators/flag_generators',
            'outputs/installed_generators/flag_node_generators',
        ]

        try:
            src_path_raw = str(
                (selected_gen or {}).get('_source_path')
                or ((selected_gen or {}).get('source') or {}).get('path')
                or ''
            ).strip()
            if src_path_raw:
                repo_root_abs = os.path.abspath(_get_repo_root())
                src_abs = os.path.abspath(src_path_raw) if os.path.isabs(src_path_raw) else os.path.abspath(os.path.join(repo_root_abs, src_path_raw))
                if os.path.commonpath([repo_root_abs, src_abs]) == repo_root_abs:
                    rel = os.path.relpath(src_abs, repo_root_abs).replace('\\', '/')
                    if rel:
                        include_repo_paths.append(rel)
        except Exception:
            pass

        include_repo_paths = list(dict.fromkeys([p for p in include_repo_paths if isinstance(p, str) and p.strip()]))

        try:
            _push_repo_to_remote(
                core_cfg,
                logger=app.logger,
                upload_only_injected_artifacts=False,
                include_repo_paths=include_repo_paths,
                log_handle=log_handle,
            )
        except Exception as push_exc:
            raise RuntimeError(
                f'Remote runtime bootstrap failed while preparing {remote_runner_path}: {push_exc}'
            ) from first_missing_exc

        try:
            sftp.close()
        except Exception:
            pass
        sftp = ssh_client.open_sftp()
        remote_repo_dir = _remote_static_repo_dir(sftp)
        remote_runner_path = _remote_path_join(remote_repo_dir, 'scripts', 'run_flag_generator.py')
        sftp.stat(remote_runner_path)

    remote_run_dir = _remote_path_join('/tmp/tests', f'flag-test-{run_id}')
    _remote_mkdirs(ssh_client, remote_run_dir)
    _remote_mkdirs(ssh_client, _remote_path_join(remote_run_dir, 'inputs'))

    # Provide sudo password to the generator runner without exposing it in the process list.
    # Do NOT rely on SSH AcceptEnv; instead, write a private env file and source it.
    try:
        sudo_pw = str(core_cfg.get('ssh_password') or '')
    except Exception:
        sudo_pw = ''
    remote_env_path = _remote_path_join(remote_run_dir, '.coretg_env.sh')
    try:
        def _sh_single_quote(val: str) -> str:
            # Safely embed arbitrary string into single-quoted shell literal.
            return "'" + (val or '').replace("'", "'\\''") + "'"

        env_lines = [
            '#!/usr/bin/env bash',
            'set -euo pipefail',
            'export CORETG_DOCKER_USE_SUDO=1',
            'export CORETG_DOCKER_HOST_NETWORK=1',
            f"export CORETG_DOCKER_SUDO_PASSWORD={_sh_single_quote(sudo_pw)}",
        ]
        with sftp.open(remote_env_path, 'w') as fh:
            fh.write('\n'.join(env_lines) + '\n')
        _exec_ssh_command(ssh_client, f"chmod 600 {shlex.quote(remote_env_path)}")
    except Exception:
        # Best-effort only; if this fails, docker may still fail with permission denied.
        remote_env_path = ''

    local_inputs_dir = os.path.join(run_dir, 'inputs')
    if os.path.isdir(local_inputs_dir):
        for root, dirs, files in os.walk(local_inputs_dir):
            rel = os.path.relpath(root, local_inputs_dir)
            rel = '' if rel == '.' else rel
            remote_root = _remote_path_join(remote_run_dir, 'inputs', rel) if rel else _remote_path_join(remote_run_dir, 'inputs')
            _remote_mkdirs(ssh_client, remote_root)
            for dn in dirs:
                _remote_mkdirs(ssh_client, _remote_path_join(remote_root, dn))
            for fn in files:
                lp = os.path.join(root, fn)
                rp = _remote_path_join(remote_root, fn)
                if os.path.isfile(lp):
                    sftp.put(lp, rp)

    python_exec = _select_remote_python_interpreter(ssh_client, core_cfg)
    config_payload = json.dumps(cfg, ensure_ascii=False)
    prefix = ''
    if remote_env_path:
        prefix = f"set -a && source {shlex.quote(remote_env_path)} && set +a && "

    cmd_inner = (
        f"{prefix}cd {shlex.quote(remote_repo_dir)} && "
        f"{shlex.quote(python_exec)} {shlex.quote(remote_runner_path)} "
        f"--kind {shlex.quote(kind)} "
        f"--generator-id {shlex.quote(generator_id)} "
        f"--out-dir {shlex.quote(remote_run_dir)} "
        f"--config {shlex.quote(config_payload)} "
        f"--repo-root {shlex.quote(remote_repo_dir)}"
    )
    cmd = f"bash -lc {shlex.quote(cmd_inner)}"

    channel = ssh_client.get_transport().open_session() if ssh_client.get_transport() else None
    if channel is None:
        raise RuntimeError('SSH channel unavailable')
    try:
        channel.get_pty()
    except Exception:
        pass

    pw = sudo_pw
    channel.exec_command(cmd)
    relay_thread = threading.Thread(
        target=_relay_remote_channel_to_log,
        args=(channel, log_handle),
        kwargs={'redact_tokens': [pw] if pw else []},
        daemon=True,
    )
    relay_thread.start()
    try:
        sftp.close()
    except Exception:
        pass
    return {
        'ssh_client': ssh_client,
        'ssh_channel': channel,
        'ssh_log_thread': relay_thread,
        'remote_run_dir': remote_run_dir,
        'remote_repo_dir': remote_repo_dir,
        'remote_env_path': remote_env_path,
    }


def _purge_remote_flag_test_dir(meta: Dict[str, Any]) -> None:
    if not isinstance(meta, dict) or not meta.get('remote'):
        return
    core_cfg = meta.get('core_cfg') if isinstance(meta.get('core_cfg'), dict) else None
    remote_run_dir = str(meta.get('remote_run_dir') or '').strip()
    if not core_cfg or not remote_run_dir:
        return
    client = None
    try:
        client = _open_ssh_client(core_cfg)
        _remote_remove_path(client, remote_run_dir)
    except Exception:
        return
    finally:
        try:
            if client:
                client.close()
        except Exception:
            pass


def _find_enabled_node_generator_by_id(generator_id: str) -> Optional[dict]:
    gid = (generator_id or '').strip()
    if not gid:
        return None
    try:
        generators, _errors = _flag_node_generators_from_enabled_sources()
    except Exception:
        return None
    for g in generators:
        try:
            if str(g.get('id') or '').strip() == gid:
                return g
        except Exception:
            continue
    return None


def _find_enabled_generator_by_id(generator_id: str) -> Optional[dict]:
    gid = (generator_id or '').strip()
    if not gid:
        return None
    try:
        generators, _errors = _flag_generators_from_enabled_sources()
    except Exception:
        return None
    for g in generators:
        try:
            if str(g.get('id') or '').strip() == gid:
                return g
        except Exception:
            continue
    return None


def _flaggen_build_ephemeral_execute_job(meta: dict[str, Any], *, run_id: str) -> tuple[dict[str, Any] | None, str | None]:
    run_dir = str((meta or {}).get('run_dir') or '').strip()
    generator_id = str((meta or {}).get('generator_id') or '').strip()
    if not run_dir or not os.path.isdir(run_dir):
        return None, 'flag generator run_dir missing'
    if not generator_id:
        return None, 'flag generator id missing'

    manifest_path = os.path.join(run_dir, 'outputs.json')
    outputs: dict[str, Any] = {}
    if os.path.isfile(manifest_path):
        try:
            payload = json.loads(Path(manifest_path).read_text(encoding='utf-8'))
            outs = payload.get('outputs') if isinstance(payload, dict) else None
            if isinstance(outs, dict):
                outputs = dict(outs)
        except Exception:
            outputs = {}

    scenario_name = f"flaggen-test-{str(run_id or '').replace('/', '-')[:24]}"
    xml_path = os.path.abspath(os.path.join(run_dir, 'ephemeral_execute.xml'))
    xml_text = f"""<Scenarios>
  <Scenario name='{scenario_name}'>
    <ScenarioEditor>
      <section name='Node Information'>
        <item selected='Docker' v_metric='Count' v_count='1'/>
      </section>
    </ScenarioEditor>
  </Scenario>
</Scenarios>"""
    Path(xml_path).write_text(xml_text, encoding='utf-8')

    try:
        _planner_persist_flow_plan(xml_path=xml_path, scenario=scenario_name, seed=None, persist_plan_file=False)
    except Exception as exc:
        return None, f'failed to build ephemeral preview plan: {exc}'

    payload = _load_preview_payload_from_path(xml_path, scenario_name)
    full_preview = payload.get('full_preview') if isinstance(payload, dict) else None
    if not isinstance(full_preview, dict):
        return None, 'ephemeral preview payload missing full_preview'
    hosts = full_preview.get('hosts') if isinstance(full_preview.get('hosts'), list) else []
    docker_nodes = [
        h for h in hosts
        if isinstance(h, dict) and str(h.get('role') or '').strip().lower() == 'docker' and str(h.get('node_id') or '').strip()
    ]
    if not docker_nodes:
        return None, 'ephemeral scenario missing docker node'
    docker_node_id = str((docker_nodes[0] or {}).get('node_id') or '').strip()
    if not docker_node_id:
        return None, 'ephemeral docker node id missing'
    docker_node_name = str((docker_nodes[0] or {}).get('name') or '').strip()
    if not docker_node_name and docker_node_id.isdigit():
        docker_node_name = f"docker-{docker_node_id}"

    resolved_outputs = dict(outputs)
    flag_value = str(
        resolved_outputs.get('Flag(flag_id)')
        or resolved_outputs.get('flag')
        or ''
    ).strip()

    inject_files: list[str] = []
    seen_injects: set[str] = set()
    for val in resolved_outputs.values():
        if not isinstance(val, str):
            continue
        raw = val.strip()
        if not raw:
            continue
        abs_path = raw if os.path.isabs(raw) else os.path.abspath(os.path.join(run_dir, raw.lstrip('/')))
        if not os.path.exists(abs_path):
            continue
        if abs_path in seen_injects:
            continue
        seen_injects.add(abs_path)
        inject_files.append(abs_path)

    assignment: dict[str, Any] = {
        'node_id': docker_node_id,
        'id': generator_id,
        'name': str((meta or {}).get('generator_name') or generator_id),
        'type': 'flag-generator',
        'generator_catalog': 'flag_generators',
        'run_dir': run_dir,
        'artifacts_dir': run_dir,
        'outputs_manifest': manifest_path if os.path.isfile(manifest_path) else '',
        'resolved_outputs': resolved_outputs,
        'inject_files': inject_files,
    }
    if flag_value:
        assignment['flag_value'] = flag_value

    flow_state = {
        'scenario': scenario_name,
        'length': 1,
        'chain': [{'id': docker_node_id, 'name': str((docker_nodes[0] or {}).get('name') or docker_node_id)}],
        'flag_assignments': [assignment],
        'flow_enabled': True,
    }
    ok, msg = _update_flow_state_in_xml(xml_path, scenario_name, flow_state)
    if not ok:
        return None, f'failed to save ephemeral flow state: {msg}'

    core_cfg = (meta or {}).get('core_cfg') if isinstance((meta or {}).get('core_cfg'), dict) else None
    if not isinstance(core_cfg, dict):
        return None, 'missing core config for ephemeral execute'

    job_spec: dict[str, Any] = {
        'seed': None,
        'xml_path': xml_path,
        'preview_plan_path': xml_path,
        'core_override': dict(core_cfg),
        'scenario_core_override': None,
        'scenario_name_hint': scenario_name,
        'scenario_index_hint': 0,
        'update_remote_repo': True,
        'adv_fix_docker_daemon': False,
        'adv_run_core_cleanup': True,
        'adv_deep_cleanup_after_run': True,
        'adv_check_core_version': False,
        'adv_restart_core_daemon': False,
        'adv_start_core_daemon': False,
        'adv_auto_kill_sessions': False,
        'docker_remove_conflicts': False,
        'docker_cleanup_before_run': True,
        'docker_remove_all_containers': False,
        'overwrite_existing_images': True,
        'upload_only_injected_artifacts': False,
        'scenarios_inline': None,
        'flow_enabled': True,
        'scenario_for_plan': scenario_name,
        'test_docker_node_id': docker_node_id,
        'test_docker_node_name': docker_node_name,
        'test_scenario_tag': scenario_name,
        'skip_flow_artifact_container_copy': True,
    }
    return job_spec, None


def _flaggen_run_ephemeral_execute(run_id_local: str) -> None:
    meta = RUNS.get(run_id_local)
    if not isinstance(meta, dict):
        return
    job_spec, err = _flaggen_build_ephemeral_execute_job(meta, run_id=run_id_local)
    if not isinstance(job_spec, dict):
        meta['done'] = True
        meta['returncode'] = 1
        meta['status'] = 'failed'
        meta['error'] = str(err or 'failed to prepare ephemeral execute run')
        return
    meta['test_docker_node_id'] = str(job_spec.get('test_docker_node_id') or '').strip()
    meta['test_docker_node_name'] = str(job_spec.get('test_docker_node_name') or '').strip()
    meta['test_scenario_tag'] = str(job_spec.get('test_scenario_tag') or '').strip()
    meta['xml_path'] = str(job_spec.get('xml_path') or '').strip()
    meta['preview_plan_path'] = str(job_spec.get('preview_plan_path') or '').strip()
    meta['scenario_name'] = str(job_spec.get('scenario_name_hint') or job_spec.get('scenario_for_plan') or '').strip()
    meta['flow_enabled'] = bool(job_spec.get('flow_enabled'))
    meta['done'] = False
    meta['returncode'] = None
    meta['status'] = 'executing'
    _run_cli_background_task(run_id_local, job_spec)


def _flagnodegen_build_ephemeral_execute_job(meta: dict[str, Any], *, run_id: str) -> tuple[dict[str, Any] | None, str | None]:
    run_dir = str((meta or {}).get('run_dir') or '').strip()
    generator_id = str((meta or {}).get('generator_id') or '').strip()
    if not run_dir or not os.path.isdir(run_dir):
        return None, 'flag node generator run_dir missing'
    if not generator_id:
        return None, 'flag node generator id missing'

    manifest_path = os.path.join(run_dir, 'outputs.json')
    outputs: dict[str, Any] = {}
    if os.path.isfile(manifest_path):
        try:
            payload = json.loads(Path(manifest_path).read_text(encoding='utf-8'))
            outs = payload.get('outputs') if isinstance(payload, dict) else None
            if isinstance(outs, dict):
                outputs = dict(outs)
        except Exception:
            outputs = {}

    scenario_name = f"flagnodegen-test-{str(run_id or '').replace('/', '-')[:24]}"
    xml_path = os.path.abspath(os.path.join(run_dir, 'ephemeral_execute.xml'))
    xml_text = f"""<Scenarios>
  <Scenario name='{scenario_name}'>
    <ScenarioEditor>
      <section name='Node Information'>
        <item selected='Docker' v_metric='Count' v_count='1'/>
      </section>
    </ScenarioEditor>
  </Scenario>
</Scenarios>"""
    Path(xml_path).write_text(xml_text, encoding='utf-8')

    try:
        _planner_persist_flow_plan(xml_path=xml_path, scenario=scenario_name, seed=None, persist_plan_file=False)
    except Exception as exc:
        return None, f'failed to build ephemeral preview plan: {exc}'

    payload = _load_preview_payload_from_path(xml_path, scenario_name)
    full_preview = payload.get('full_preview') if isinstance(payload, dict) else None
    if not isinstance(full_preview, dict):
        return None, 'ephemeral preview payload missing full_preview'
    hosts = full_preview.get('hosts') if isinstance(full_preview.get('hosts'), list) else []
    docker_nodes = [
        h for h in hosts
        if isinstance(h, dict) and str(h.get('role') or '').strip().lower() == 'docker' and str(h.get('node_id') or '').strip()
    ]
    if not docker_nodes:
        return None, 'ephemeral scenario missing docker node'
    docker_node_id = str((docker_nodes[0] or {}).get('node_id') or '').strip()
    if not docker_node_id:
        return None, 'ephemeral docker node id missing'
    docker_node_name = str((docker_nodes[0] or {}).get('name') or '').strip()
    if not docker_node_name and docker_node_id.isdigit():
        docker_node_name = f"docker-{docker_node_id}"

    resolved_outputs = dict(outputs)
    flag_value = str(
        resolved_outputs.get('Flag(flag_id)')
        or resolved_outputs.get('flag')
        or ''
    ).strip()

    inject_files: list[str] = []
    seen_injects: set[str] = set()
    for val in resolved_outputs.values():
        if not isinstance(val, str):
            continue
        raw = val.strip()
        if not raw:
            continue
        abs_path = raw if os.path.isabs(raw) else os.path.abspath(os.path.join(run_dir, raw.lstrip('/')))
        if not os.path.exists(abs_path):
            continue
        if abs_path in seen_injects:
            continue
        seen_injects.add(abs_path)
        inject_files.append(abs_path)

    assignment: dict[str, Any] = {
        'node_id': docker_node_id,
        'id': generator_id,
        'name': str((meta or {}).get('generator_name') or generator_id),
        'type': 'flag-node-generator',
        'generator_catalog': 'flag_node_generators',
        'run_dir': run_dir,
        'artifacts_dir': run_dir,
        'outputs_manifest': manifest_path if os.path.isfile(manifest_path) else '',
        'resolved_outputs': resolved_outputs,
        'inject_files': inject_files,
    }
    if flag_value:
        assignment['flag_value'] = flag_value

    flow_state = {
        'scenario': scenario_name,
        'length': 1,
        'chain': [{'id': docker_node_id, 'name': str((docker_nodes[0] or {}).get('name') or docker_node_id)}],
        'flag_assignments': [assignment],
        'flow_enabled': True,
    }
    ok, msg = _update_flow_state_in_xml(xml_path, scenario_name, flow_state)
    if not ok:
        return None, f'failed to save ephemeral flow state: {msg}'

    core_cfg = (meta or {}).get('core_cfg') if isinstance((meta or {}).get('core_cfg'), dict) else None
    if not isinstance(core_cfg, dict):
        return None, 'missing core config for ephemeral execute'

    job_spec: dict[str, Any] = {
        'seed': None,
        'xml_path': xml_path,
        'preview_plan_path': xml_path,
        'core_override': dict(core_cfg),
        'scenario_core_override': None,
        'scenario_name_hint': scenario_name,
        'scenario_index_hint': 0,
        'update_remote_repo': True,
        'adv_fix_docker_daemon': False,
        'adv_run_core_cleanup': True,
        'adv_deep_cleanup_after_run': True,
        'adv_check_core_version': False,
        'adv_restart_core_daemon': False,
        'adv_start_core_daemon': False,
        'adv_auto_kill_sessions': False,
        'docker_remove_conflicts': False,
        'docker_cleanup_before_run': True,
        'docker_remove_all_containers': False,
        'overwrite_existing_images': True,
        'upload_only_injected_artifacts': False,
        'scenarios_inline': None,
        'flow_enabled': True,
        'scenario_for_plan': scenario_name,
        'test_docker_node_id': docker_node_id,
        'test_docker_node_name': docker_node_name,
        'test_scenario_tag': scenario_name,
        'skip_flow_artifact_container_copy': True,
    }
    return job_spec, None


def _flagnodegen_run_ephemeral_execute(run_id_local: str) -> None:
    meta = RUNS.get(run_id_local)
    if not isinstance(meta, dict):
        return
    job_spec, err = _flagnodegen_build_ephemeral_execute_job(meta, run_id=run_id_local)
    if not isinstance(job_spec, dict):
        meta['done'] = True
        meta['returncode'] = 1
        meta['status'] = 'failed'
        meta['error'] = str(err or 'failed to prepare ephemeral execute run')
        return
    meta['test_docker_node_id'] = str(job_spec.get('test_docker_node_id') or '').strip()
    meta['test_docker_node_name'] = str(job_spec.get('test_docker_node_name') or '').strip()
    meta['test_scenario_tag'] = str(job_spec.get('test_scenario_tag') or '').strip()
    meta['xml_path'] = str(job_spec.get('xml_path') or '').strip()
    meta['preview_plan_path'] = str(job_spec.get('preview_plan_path') or '').strip()
    meta['scenario_name'] = str(job_spec.get('scenario_name_hint') or job_spec.get('scenario_for_plan') or '').strip()
    meta['flow_enabled'] = bool(job_spec.get('flow_enabled'))
    meta['done'] = False
    meta['returncode'] = None
    meta['status'] = 'executing'
    _run_cli_background_task(run_id_local, job_spec)


def _vuln_test_build_ephemeral_execute_job(
    *,
    run_dir: str,
    run_id: str,
    core_cfg: dict[str, Any],
    item_id: int,
    item_name: str,
    compose_path: str,
) -> tuple[dict[str, Any] | None, str | None]:
    run_dir_abs = os.path.abspath(str(run_dir or '').strip()) if str(run_dir or '').strip() else ''
    if not run_dir_abs:
        return None, 'vuln test run_dir missing'
    try:
        os.makedirs(run_dir_abs, exist_ok=True)
    except Exception as exc:
        return None, f'failed to create vuln test run_dir: {exc}'

    compose_abs = os.path.abspath(str(compose_path or '').strip()) if str(compose_path or '').strip() else ''
    if not compose_abs or not os.path.isfile(compose_abs):
        return None, 'vuln test compose path missing'

    scenario_name = f"vuln-test-{str(item_id or 0)}-{str(run_id or '').replace('/', '-')[:16]}"
    xml_path = os.path.abspath(os.path.join(run_dir_abs, 'ephemeral_execute.xml'))

    def _xml_attr(value: str) -> str:
        try:
            return (
                str(value or '')
                .replace('&', '&amp;')
                .replace("'", '&apos;')
                .replace('"', '&quot;')
                .replace('<', '&lt;')
                .replace('>', '&gt;')
            )
        except Exception:
            return ''

    item_name_xml = _xml_attr(str(item_name or f'vuln-{item_id}'))
    compose_xml = _xml_attr(compose_abs)
    scenario_xml = _xml_attr(scenario_name)

    xml_text = f"""<Scenarios>
  <Scenario name='{scenario_xml}'>
    <ScenarioEditor>
      <section name='Node Information'>
        <item selected='Docker' v_metric='Count' v_count='1'/>
      </section>
      <section name='Vulnerabilities' density='0.0'>
        <item selected='Specific' v_metric='Count' v_count='1' v_name='{item_name_xml}' v_path='{compose_xml}'/>
      </section>
    </ScenarioEditor>
  </Scenario>
</Scenarios>"""

    try:
        Path(xml_path).write_text(xml_text, encoding='utf-8')
    except Exception as exc:
        return None, f'failed to write vuln test XML: {exc}'

    try:
        _planner_persist_flow_plan(xml_path=xml_path, scenario=scenario_name, seed=None, persist_plan_file=False)
    except Exception as exc:
        return None, f'failed to build vuln test preview plan: {exc}'

    docker_node_id = ''
    docker_node_name = ''
    try:
        payload = _load_preview_payload_from_path(xml_path, scenario_name)
        full_preview = payload.get('full_preview') if isinstance(payload, dict) else None
        hosts = full_preview.get('hosts') if isinstance(full_preview, dict) and isinstance(full_preview.get('hosts'), list) else []
        for host in hosts:
            if not isinstance(host, dict):
                continue
            role = str(host.get('role') or '').strip().lower()
            node_id = str(host.get('node_id') or '').strip()
            if role == 'docker' and node_id:
                docker_node_id = node_id
                docker_node_name = str(host.get('name') or '').strip()
                break
    except Exception:
        docker_node_id = ''
        docker_node_name = ''
    if not docker_node_name and docker_node_id.isdigit():
        docker_node_name = f"docker-{docker_node_id}"

    if not isinstance(core_cfg, dict):
        return None, 'missing core config for vuln test execute'

    job_spec: dict[str, Any] = {
        'seed': None,
        'xml_path': xml_path,
        'preview_plan_path': xml_path,
        'core_override': dict(core_cfg),
        'scenario_core_override': None,
        'scenario_name_hint': scenario_name,
        'scenario_index_hint': 0,
        'update_remote_repo': True,
        'adv_fix_docker_daemon': False,
        'adv_run_core_cleanup': True,
        'adv_deep_cleanup_after_run': True,
        'adv_check_core_version': False,
        'adv_restart_core_daemon': False,
        'adv_start_core_daemon': False,
        'adv_auto_kill_sessions': False,
        'docker_remove_conflicts': False,
        'docker_cleanup_before_run': True,
        'docker_remove_all_containers': False,
        'overwrite_existing_images': True,
        'upload_only_injected_artifacts': False,
        'scenarios_inline': None,
        'flow_enabled': False,
        'scenario_for_plan': scenario_name,
        'test_docker_node_id': docker_node_id,
        'test_docker_node_name': docker_node_name,
        'test_scenario_tag': scenario_name,
        'skip_flow_artifact_container_copy': True,
    }
    return job_spec, None


